const T09 = {"name":"综合其它","key":"09_其它","count":746,"data":[{"id":5,"author":"张闻捷; 黄妍颖","title":"工艺的复古——陈侯午三器铭文制法新探","abstract":"关于商周铜器铭文的制法，学界长期以来有模作法和范作法的争论，在范作法中，直接用泥条堆塑文字的工艺日益受到关注和重视。本文以陈侯午三器铭文为研究对象，分析其中所见的泥条法铸造特征，揭示出陈侯午三器铭文应均使用泥条法制作而成。由此表明，泥条法作为一种可行的青铜器铭文铸造方法，在春秋战国时期仍被使用，反映出这一时期特定器物在工艺上的复古倾向。","categories":["09_其它"],"year":2026,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2026.01.006","pages":"14-28, 159","volume":""},{"id":22,"author":"赫俊红","title":"陈介祺的毛公鼎考释稿及其传古治史观","abstract":"陈介祺作为金石收藏大家，他的诸多研究成果尤其是手稿一直未能刊布。近年，笔者有幸对陈介祺手稿及拓本进行了较全面的整理和研究，本文试以他不同时段所作的毛公鼎释文和考释稿为例，探究他记录古器、考释金文的写作方式和特点，以及蕴含其中的一些传古治史观念。","categories":["09_其它"],"year":2025,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKeGf2aeKyCD_k3qcLtlN_egRwjdGUnqX9SXeeHnfxEohYQhy3MGLaD_9OdlJkHjZKNnprZzcgHvRZj-GOhc5X5pgjh_SMMvbRWJAj8mFL_DF8AH5G9L0cuaA_2m9vgEv-swI-ZXc8MwPUcm5yPbYUZw2o0hLZPRPFZq1ZmkdVpOg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"58-59, 63, 67, 70-83","volume":""},{"id":39,"author":"陆明君","title":"陈介祺与晚清金石学体系的建构","abstract":"金石学至晚清而鼎盛，形成了较完备的学科体系，陈介祺作为晚清最具代表性的金石学家，贡献多方，而于晚清金石学体系的建构厥功至钜。主要体现在：多有发现与开创之功，拓宽了金石学领域；鉴藏风气的引领与范式的确立；以传古为志及对金石传拓的考究与探索，促进了拓本的广泛流通；其与金石家的书函频繁往来，形成了学术网络与交流范式，并提升了学科品质。","categories":["09_其它"],"year":2025,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKx91bOiFILvPj-FlvOrhENhCsSlcSxzbe8jwg-ElEEM9ckQu67n0P1Q8B7SN4mnS-VOmKRhGv1Uuk3D9gLFLt4MMnoE3-yC2pJ8Jbe27dbHDJoB9TDtPnFrzvm-8GBbTIkDKhBdvzdIVZBsXpazPcrX7OJtwijXd59QEFPezeA6NTUUpecRzPD&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46173","volume":""},{"id":40,"author":"刘志基","title":"《簠斋吉金录》中的商周金文分时段特征字形例说","abstract":"将商周金文字形分时段特征的整理结果与《簠斋吉金录》收字加以比对，分系统匹配、偏旁匹配和部分匹配三种情况呈现比对结果。以定量分析的方式，揭示商周金文不同时段的“唯一型”“主流型”“仅见型”特征构形，为金文书法创作提供参考材料。","categories":["09_其它"],"year":2025,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJvMLtjeLUKLJv4NIxFb7f2e55GeuGpKrRVRXkTHRUwVEEaxbeOq5Kv7uMt6jXLSzMS-RGEi5ETtHzMBbVVvm2ZtzgP7IDibRbG5_Lt6FPztlJkfm5fIsnAAFNFmoNZb67P4KpTtPFpezQA7TH-2KTjn1uChXLo89iRoHm8yQ-J2I9YRjyoXbOn&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-101, 209-210","volume":""},{"id":61,"author":"李保江; 李荣有","title":"证经补史：近古金石学著录乐钟及其功能考述","abstract":"近古金石学是古代历史上考察青铜乐器的重要领域，较早始于北宋欧阳修，后迄于清末端方。现基于金石学著述典籍中有关乐钟实物的图文资料，辨析所录镈钟、甬钟和钮钟等类型，及相关乐钟编组、所属时代等问题。在此期间发现，金石学者在记载乐钟形制时表现出趋于统一的著录格式，及对部分乐钟的考证与王朝制礼作乐的特殊语境相关联，进而由乐钟的形制变化观照到音响声律等本体特征。而明清学者如朱载堉、陈梦雷等在稽考乐钟律制与样式和编撰类书图籍时，辑录和征引了金石学领域的大量乐钟成果，有利于补正经学传统长期影响下有关青铜礼乐器物的臆说误识，发挥其独特的历史功能。","categories":["09_其它"],"year":2025,"publication":"北方音乐","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK9aYOmn8O83h8loYONWKL2g0WpR6Gk8euWjyU-CtQSnZqhsfkSIUlbBFI34zy8SblGuL4sIOZlyMGiXhEEqFflel2UIcHkc9OpqNBiuzq4LZGpwYw-IaKKnDdO2hhvRQjO4g-14iSCGnkSeXzqyRMc_vxKdAvMiVm942n08Nc4pqlnNQDUtw-s&amp;uniplatform=NZKPT&amp;language=CHS","pages":"84-94","volume":""},{"id":65,"author":"任哨奇","title":"“安州六器”再考——以新见《安州古器图》佚文为中心","abstract":"“安州六器”为北宋重和时出土于安州孝感的周初铜器，《金石录》《宣和博古图》等宋代金石典籍皆有著录，但其中一件圆鼎因文献记载模糊而争论不定，郭沫若、王国维、马衡、岑仲勉、唐兰、容庚、陈梦家等学者都曾撰文讨论。笔者于《永乐大典》卷一一九五六“鼎”字册发现所引翟耆年《籀史》记录“安州六器”铭文与出土过程，不见于今本《籀史》,当属《籀史》失传之卷下《安州古器图》佚文。其中明确记录了“安州六器”争论未定之圆鼎铭文与《宣和博古图》“周父己鼎”、《钟鼎款识》著录“周癸亥父己鬲鼎”铭文相近。经考，《安州古器图》当为北宋末期关于“安州六器”出土的一手记录，《宣和博古图》之所以未将“周父己鼎”归为“安州六器”,或因编撰者对内府藏器出土信息的含糊遗失。","categories":["09_其它"],"year":2025,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKPicmegqVCSJqTamra1y4_B6KD6_mLJHJPEbMtbOtX0_ZqwyzEuLGP_QOHlyc4lkn3lkHIOgP17YAnZf3Ver3e0Z3Eio9RRzma5dAip_dTYYgn37ZPKZJDI6etc1fVf0AMwxWxeeNIoolu_tCxU6wOEofxBOrFBLGLCcRP59ymdMtkbgN5KW7S&amp;uniplatform=NZKPT&amp;language=CHS","pages":"27-33, 170","volume":""},{"id":77,"author":"洪晨娜","title":"吴大澂书札八通考释","abstract":"吴大澂，字清卿，江苏吴县人。同治七年（1868）进士，授翰林编修，官至河道总督。近见吴大澂写给吴承潞、潘祖荫的八通书札，不见于已经出版的《吴大澂书信四种》《吴大澂手札》，书札内容既涉及仕途迁升背后的政治运作，东北边防屯垦、领土交涉等政情民生，又多与金石有关。吴大澂身在仕途，仍热衷于金石拓印，颇有创见。书札内容较为丰富，故先作释文，再略作考证。书札中的残缺之字，概以“□”形表示。","categories":["09_其它"],"year":2025,"publication":"艺术工作","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIViw_WuzQucGAkO5MQKdTSeB59NE5QYMAbT1rqN7-4fCQAA9c-z_ayhmuI_FrH3AH7Y4CKbFzN_hSOor0PNaCN99WqnqixmfHlG2vOGRZKDo1XRop5SLQk34jsZCvzKopDTze4z4pnLtXzpwkUOMnG37f-FS1fNeLwWF_UFCYKyBcie0qS3eqd&amp;uniplatform=NZKPT&amp;language=CHS","pages":"92-95","volume":""},{"id":79,"author":"宋松","title":"大盂鼎铭文拓本再研究","abstract":"大盂鼎是西周早期青铜重器，具有较高的历史、艺术和文物价值。本文公开了烟台市博物馆收藏的两种大盂鼎清代旧拓，介绍拓本上的题跋、钤印及相关人物之间的关系。结合前人研究成果并对比各类铭文拓本，列举18处文字变化，梳理出鼎铭的4次剔洗过程，将拓本由早及晚地划分为“戎”字未剔本、“王”字未剔本、“王”字已剔本、“祀”字已剔本和“三”字已剔本等5种版本。参考纪年材料及文献著录，对5种版本的年代进行了判定。","categories":["09_其它","08_金文著录"],"year":2025,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJAHU8BamxFHkZ1fyI284ZZ51AkDR9dDjhFKgvJJcikH2SYdPytefSRJ-KY2hZZ_ftbS2rvjOTMiJ6mKMmcBG28utKCXXOGJBu4SzakqkoYhL40RsMYKSQceJdsLGyhfIYQf7_kkLf3WWZAFKl2_sw2IHlM-MZad0enLr9W8c-Bnzs7ydlMf-bj&amp;uniplatform=NZKPT&amp;language=CHS","pages":"119-140","volume":""},{"id":85,"author":"张薇","title":"接受与批判：金石图录的外译与欧洲中国青铜器研究方法的嬗变（1838—1910）","abstract":"19世纪上半叶，得益于西方汉学家对《宣和博古图》等金石图录的翻译与研究，中国古代青铜器的相关知识逐渐传至欧洲。依托于对中国金石图录的翻译与阅读，汉学家们对当时欧洲公共与私人收藏的明清仿古铜器展开了一系列的鉴藏与研究活动。20世纪初期，商周青铜器的大量出土及其考古研究，不仅让欧洲汉学界形成了青铜器具有“雕塑”艺术特征的认识观，而且也进一步促使欧洲学者对中国传统金石学研究方法进行批判性反思，并由此进一步形成以出土青铜器本体的器型与纹样为考察对象的西方考古学与艺术史研究视角。","categories":["09_其它"],"year":2025,"publication":"民族艺术","link":"https://link.cnki.net/doi/10.16564/j.cnki.1003-2568.2025.03.011","pages":"113-128","volume":""},{"id":91,"author":"王一凡; 关砚文","title":"新见《逋盂新考》修改手稿与尚未面世的《两周金文辞大系考释续编》——兼谈黄盛璋与郭沫若先生之交谊","abstract":"北京宣南书局新见《逋盂新考》修改手稿一封,标题被修改为《逋盂所见西周女君与政治》。应是黄盛璋先生在原文于《人文杂志》正式发表后,拆出修改的文章。手稿3张6页,并附纸2处增补。除对个别字、词的修改外,增修内容还涉及西周时期历史地理问题、小臣逋鼎的时代、西周铜器中女君的权力与政治关系等问题。再查黄盛璋先生与郭沫若先生信件往来、回忆文章与相关文献,该修改手稿应是未曾面世的《两周金文辞大系考释续编》中的一篇,是黄盛璋先生秉承郭沫若先生嘱托,对“新出与未收的铜器”所“作补录或续编”。","categories":["09_其它"],"year":2025,"publication":"郭沫若研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI3HxUYCEvn4LpN4xUbLu0Xfm00k-yjMcbDNZIQwRPYHlDm2JHtol5qd67Y4LSJTMINCUyPsCiLBbFfnoiQA7JtyI8gyGmETUtQQAgm5LNgxhmQ6R76Nps8igRdAJIkzQcQ3WPBwkPQwRHcfPtQuoKE5pjD5a2xR2AEWF1tapIRsg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"228-237","volume":""},{"id":96,"author":"李金晏","title":"读《春秋金文全编》札记","abstract":"《春秋金文全编》是新近出版的一部单收春秋金文字形的文字编著作。与旧有同类文字编著作相比,该书有许多创新和贡献之处。然限于人力、资源等因素,该书也存在部分疏漏,因而在使用时需要稍加注意。结合当前的研究成果,本文对《春秋金文全编》做了部分校订工作,以期学界能更好地使用这部工具书。","categories":["09_其它","08_金文著录"],"year":2025,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL-cg5BE-mjxsXnFSexy3EMSsZmE4chmGIuctYdyYpZZQ_DzxYmbn_7_Mt4s6TW1fzcE6imrMt-wpaJlYxFdD1LVyL5xkUpUscJCKWjsr5rj-MdBfwUeST0Ufjg5YYCYaakpSwLAe7UhqJeByG6QZtNWCZjEYyR1kuF9d_QoqZ38w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"35-40","volume":""},{"id":101,"author":"陈鹏宇","title":"散氏盘的流传、入贡和再发现","abstract":"本文考证了散氏盘的流传、入贡及再发现的细节，兼及阮元所仿二器流传的情况，认为散氏盘在康熙年间出土于陕西凤翔，经歙县籍的扬州盐商程梦州、徐景京及徐士业父子、洪肇松递藏。清嘉庆十二年（1807），两淮盐政额勒布从洪家购得，进贡入宫。嘉庆十三年（1808），散氏盘开始陈设于养心殿东暖阁，清道光三年（1823）被收入内务府库房。1924年2月至3月间，随着对内务府库房的清点，散氏盘再次被发现。1925年故宫博物院成立后，马衡主导了散氏盘的影印和传拓。","categories":["09_其它"],"year":2025,"publication":"西泠艺丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIIBeXjSEkp3t92OHyQob6oDPGOmYl8-Y8hbCDCgLvQG8dELYxy7cPe-bo3UO_H7YF25DIIJ9GMUoE-1K0bKZAVXHH8hWW-9O4rgQDTLu7oj19ipR_0LOvQ9GDcIP6NsVBjv1h3X6b2s5LTyHtjNzjs0XItYTwQOpkEqpkpaT4-Sfum-iqcwcz6&amp;uniplatform=NZKPT&amp;language=CHS","pages":"17-27","volume":""},{"id":105,"author":"刘源","title":"以古人视角探索甲骨金文史料中的殷商文明","abstract":"商代史研究是中国古代史研究的重要组成部分，对于深入揭示中华文明演进历程，探究中华传统文化的渊源流变等具有重要意义。随着考古新材料的涌现及学科交叉理论方法不断更新，商代史研究成果蔚为大观。为进一步构建新时代商代史研究学科体系、学术体系与话语体系，推动商代史研究向纵深发展，本刊特邀数位学者，从多维视角透视商代历史文化，以期给相关研究带来启示。","categories":["09_其它"],"year":2025,"publication":"中国史研究动态","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJeKKtmgL6Ycqp7LWZwOcAku6KnARy63lu-AbjDFOJkrl12CnhObtH5YT7LLXRXtKNEWfcStYRvHibI_W6nG-o0c5GlWEz_bCFDUArPGxxUwufsECxa6wXqRTJ-kG-FKfqy1wTnwnSNPPlJp4o9lYKVEUHirnLcFjROVd6a-XH7G9PCfm7C5EaJ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"32-38","volume":""},{"id":118,"author":"郝导华; 刘延常; 王龙","title":"试论滕州大韩墓地的性质","abstract":"2017至2020年，大韩墓地共发掘东周墓葬198座，车马坑2座。其中中型贵族墓48座、小型平民墓150座。通过该墓地文化因素分析、青铜器铭文考证及该地墓葬与薛国故城墓葬和东江墓葬的比较，大韩墓地在春秋晚期（或至战国前期）应属郳国。同时，该墓地的中型贵族墓葬又包含越国、楚国等其他诸侯国的文化因素成分。","categories":["09_其它"],"year":2025,"publication":"海岱考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIsEEoFQLy545mPH9HKtQz8Z62tfRATzlAZOy1spi77pPjNtAhwELiZPtNdToBj6e68AQoX9BkPSOsHwDkxQggPgyM7VF7PDW1n96bLoWxxnDuPYbpVfCCYy-FspuTCdpmlPpDzf5UPN3S39lBoVdraxYHLXeU9N6reaK7mcIz9KpIo72BaZjpA&amp;uniplatform=NZKPT&amp;language=CHS","pages":"155-162","volume":""},{"id":124,"author":"刘江; 张俊成","title":"楚国金文字体研究","abstract":"金文字體的研究,目前沒有受到學界的充分重視,但確有著重要的意義和價值。不僅能對銅器的分期和斷代提供重要的參考,還可以豐富金文的研究内容、方法和理論,從而對青銅器及金文的綜合研究提供幫助。本文 主要由四部分構成:第一部分是是對楚國金文字形的研究。基於金文“字形變化”這一客觀特徵,從單字結構、筆劃演變的角度出發,重點選取楚國金文中出現頻率較高、字形有清晰變化特徵及結構較爲複雜的單字,運用類型學的方法,進行型式分析,總結歸納出楚國金文字形的演變規律。通過統計,將器銘中出現100次以上的單字列爲高頻單字,共有41個高頻單字,但是能夠平均分佈於楚國各個時期並且字形變化的時代特徵較明顯的單字僅有18個,將這18個高頻單字按照單字出現的頻次進行分級,可劃分爲四個級別:一級高頻單字,僅有“之”一字;二級高頻單字,有“曾”“乍”“子”“王”“用”“其”六字;三級高頻單字,有“吉”“爲”“永”“自”“月”“隹","categories":["09_其它","08_金文著录"],"year":2025,"publication":"697","link":"","pages":"","volume":""},{"id":127,"author":"郭媛媛; 崎川隆","title":"梅原末治《日本搜储支那古铜精华》译注及相关问题研究","abstract":"梅原末治《日本搜储支那古铜精华》为海外收藏我国古代青铜器及其铭文材料的重要著录书之一,该书1959到1964年分六册出版,收录梅原末治上世纪20-30年代搜集调查的五百余件日本所藏商周到唐代的中国青铜器材料,其中近半数为商周有铭材料。书中提供清晰的器物照片和铭文拓影,并对每件器物进行说明,包括器物的时代、尺寸、来源及作者的解说等。这些器物大多仍然流散在海外,对这些材料的研究主要依靠各著录书,故书中提供的基本信息对研究起着关键作用。另外,书中部分有铭器物为《殷周金文集成(修订增补本)》、《商周青铜器铭文曁图像集成》等常见资料汇编未著录,具有很高的学术价值。由于语言不通,印数很少等原因,国内学者对此书的了解较少。基于此,该研究主要包括两个方面,其一,对《日精华》中所有的文字介绍部分进行译注、校订;其二,对所收材料的著录、流传情况进行调查,并对部分铭文材料进行初步研究。旨在充分挖掘《日精华》的学","categories":["09_其它","08_金文著录"],"year":2025,"publication":"709","link":"","pages":"","volume":""},{"id":138,"author":"刘志基","title":"古文字字符集与古文字工具书的编纂——以《古文字构形类纂·金文卷》为例","abstract":"字符集的缺位是数字时代古文字工具书编纂转型升级的最大障碍。要排除这一障碍，需将古文字工具书编纂与古文字字符集研制融为一体。古文字字符集的研制既要遵循通用国际标准，也需以服务于古文字研究与应用为准则。工具书编纂中应全面发挥字符集的数字处理功能，并以此功能引领工具书编纂格局的创新。古文字字符集加持下编纂的古文字工具书，可以为古文字研究应用提供新的资料库，给出古文字进入国际标准的字符集编码方案，并为古文字智能工具的开发提供“数据”支持。","categories":["09_其它","08_金文著录"],"year":2025,"publication":"辞书研究","link":"https://link.cnki.net/doi/10.16134/j.cnki.cn31-1997/g2.2025.03.004","pages":"1-14, 125","volume":""},{"id":139,"author":"李一诺; 王克震","title":"金属器皿铭文的形式特征研究","abstract":"金属器皿铭文是指以金属器皿为载体的铭文,自先秦时代青铜器表面开始出现文字至现今金属器皿表面的文字在形式特征方面出现了巨大变化。本文以断代研究思路出发,详解了自商代到现代的铭文在内在含义及功能用途等方面出现的变化及其不同时代在形式特征方面的特点,列举了金属器皿铭文在器皿空间位置分布的三种基本类型并分析影响其行款方式的因素所在,铭文的变化尤其是在铭文起始阶段的重大突破与铭文的制作技艺发展是密切相关的,而制作技艺的发展演进不仅体现着古代工匠的智慧与创新,更昭示着金属工艺的多样性衍变和金属材质自身的无限潜力以及彰显了艺术与技术完美融合,并且金属器皿铭文因其材质的独特性,表现出了别样的书法艺术风貌、鲜明的装饰美学观念与审美倾向及青铜器代表的重要历史文化价值,这是金属材质迥异于其他材质的独到之处。文章 通过对古代、近代及现代金属器皿铭文在形式特征方面的解读与分析,结合现代艺术设计作品,对现今金属艺术设","categories":["09_其它"],"year":2025,"publication":"770","link":"","pages":"","volume":""},{"id":140,"author":"李厚岑; 刘玉涛","title":"山东龙口丁氏家族青铜器收藏鉴赏","abstract":"山东龙口丁氏家族是我国近代赫赫有名的收藏世家，其藏品中青铜器数量繁多、品类丰富且价值连城，堪称瑰宝。这些青铜器不仅彰显了我国古代青铜器艺术的卓越成就，更映射出丁氏家族深厚的文化底蕴与对传统文化的炽热挚爱。本文聚焦丁氏家族所藏青铜器，从造型艺术、纹饰特点、铭文价值、文化意义等维度展开鉴赏与剖析，旨在深入探讨其在我国青铜器收藏史上的显赫地位，揭示其背后蕴含的丰富文化内涵与历史价值。","categories":["09_其它"],"year":2025,"publication":"文物鉴定与鉴赏","link":"https://link.cnki.net/doi/10.20005/j.cnki.issn.1674-8697.2025.09.003","pages":"13-16","volume":""},{"id":144,"author":"何景成","title":"周代文字区域化特征的形成与融合发展","abstract":"汉字的形体和风格在周代经历了很大的变化，而使用汉字的地域和族群也在不断扩大。西周早期的文字，传承了商代晚期的风格。从西周中期开始，汉字笔画逐渐摆脱早期粗细不均及含有团块、波磔的现象，朝线条化和平直化方向发展，最后演进出规整匀称的篆体，成为秦代统一文字的标准字体。在西周时期，文字资料主要集中于王畿地区。周边诸侯国的文字风格与演变进程，基本与王畿地区保持一致。到了春秋时期，诸侯国文字资料成为主体。汉字在广大地域经过长期的传播发展，形成了以主要诸侯国为核心的区域性文字，如秦系、晋系、齐系、燕系、楚系文字等，各系文字特点鲜明又交流融合。汉字在中华大地不同族群间传播使用，对中华文明的传承和发展起到基础性作用。","categories":["09_其它"],"year":2025,"publication":"中国高校社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLjETsOgDNyKCLUJt08ZAYdeCkX0QFUziIDtT-SIdu417pwtiGD2NBDklGU2twO8yUTAOT60UHvGkbJ_3rUC69lvttGMSacA_vQHeCqPc6YDHIbnSyw1sZhHxkXA5Bs3BoGLg3SSFD4usu0nAsWwCEUYiLxpxmuDlgCpTORhH_RiwWEx_RXczuv&amp;uniplatform=NZKPT&amp;language=CHS","pages":"101-111, 159-160","volume":""},{"id":145,"author":"孙嘉鸿; 韩天雍","title":"王懿荣交游与金石鉴藏研究","abstract":"本文从生平、交游、鉴藏等多方面研究王懿荣的金石鉴藏活动及理念。第一部分即第一章,以晚清金石学家王懿荣为核心,通过家世考证揭示其家族自明初迁居山东福山以来,以科举仕宦与金石学传统交织的学术基因如何孕育其发现甲骨文之开创性成就,进而探讨其在金石鉴藏、士人精神与甲骨学研究中的历史定位,为理解晚清学术转型与士人命运提供新视角。第二部分即第二到第四章,分别探究了王懿荣与京师、齐鲁和江南三大金石文化圈的交游情况。其中王懿荣与京城金石文化圈的交游,王懿荣与潘祖荫的交游以及为潘祖荫金石鉴藏与著述的付出使其跻身京师金石文化圈的核心圈层,而与吴大澂以金石志趣义结金兰,两人更是成为继潘祖荫和陈介祺之后最为出色的金石鉴藏家,王瓘则在王懿荣的金石交游中为王懿荣代笔篆书。第三章是王懿荣与齐鲁金石文化圈的交游,同为山东人,王懿荣以自己的金石鉴藏功底与好学的态度成为陈介祺在京的联络人,陈氏也将所有金石鉴藏的技法和治学理念","categories":["09_其它"],"year":2025,"publication":"800","link":"","pages":"","volume":""},{"id":148,"author":"林隽如; 马军霞; 李永平","title":"商周青铜卣铭文整理与研究","abstract":"青铜卣是商周时期重要的盛酒器,主要流行于商代后期至西周中期,西周中期以后基本不见。商周青铜卣分布范围甚广,出土墓葬规格较高。目前收集到的有铭青铜卣包括传世的449件和出土的174件。本文聚焦商周时期有铭青铜卣,通过对考古出土与传世器物的系统整理,结合铭文内容与文献记载,重点分析铭文所载的族属、国别、战争、婚姻等史实,探讨青铜卣在先秦社会中的历史价值,揭示器物背后隐藏的社会组织形态与文明演进过程。在确 立研究角度与方法后,需对有铭青铜卣的分布状况及其铭文类型形成基础认识。因此,本文首先通过考古与文献证据,梳理其地域分布特征及铭文分类体系,为后续的深入探讨奠定基础。首先从器物分布与铭文类型切入。考古出土的青铜卣多集中于商周核心统治区,铭文内容可分为作器者、族属、国别、朝聘、战争、婚姻六类。其次 深入分析铭文内容。以铭文中的族徽为线索,梳理出“举”“倗”“戈”等多个氏族。通过比对商周金文与甲骨文","categories":["09_其它"],"year":2025,"publication":"812","link":"","pages":"","volume":""},{"id":150,"author":"李箫; 井中伟","title":"海岱地区周代青铜兵器研究","abstract":"海岱地区西接中原,东临大海,北通燕赵,南连江淮,是古代文明交流与融合的重要区域。周代特别是东周时期,战争频发,各国竞相发展军事,铸造兵器。研究海岱地区周代青铜兵器,不仅能够理清铜兵的发展演变,对探讨战争方式的转变、古国间的政治外交以及地区间的文化交流皆具有重要意义。本文在全面梳理海岱地区周代青铜兵器材料的基础上,综合运用考古类型学分析、考古情境分析、文化因素分析、统计分析等方法,对铜兵的类型式演变、时空分布特征、组合形式、铜兵题铭以及文化交流等问题进行研究。海岱 地区周代青铜兵器可分为近战性长兵:戈、矛、戟、殳、铍,近战性短兵:剑、刀,远射性兵器:弓、弩、镞,防护性兵器:甲、胄。根据铜兵类型演变规律及兵器组合变化,可将海岱地区周代青铜兵器的发展演变划分为四个阶段:西周早期至西周晚期早段、西周晚期晚段至春秋中期、春秋晚期至战国中期早段、战国中期晚段至战国晚期,建立起相关铜兵的分期与编年序列。","categories":["09_其它"],"year":2025,"publication":"820","link":"","pages":"","volume":""},{"id":155,"author":"李春桃","title":"商周金文中刮磨、加刻现象研究","abstract":"目次一金文刮磨、加刻现象的分类二刮磨、加刻金文的内容研究三刮磨、加刻现象与青铜器流转商周时期的青铜器由于战争、迁徙、赏赐、赠送等多种原因，在制作后可能辗转流传至他人手中，这种现象在古书中常有记载。器主发生变更后，有时器物上原有铭文会被刮磨，或者加刻新的铭文。讨论这种刮磨、加刻现象，对于研究青铜器的先后归属、时代国别、铭文释读等均有重要意义，同时也可借此梳理青铜器的流转方式等问题。","categories":["09_其它"],"year":2025,"publication":"考古学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLUa2Q-KtPnMS_LuxYongzBaNYjRJbDcSzC23l2IgnVWKeGthuHko0mazbZk_DAGvSQ964n6zRK4HwbsA-QjfEesW1a6aescIVnnF6E_WFF5tYlESIaEnyR16MJIN0hwbhIEtxP_G62AyFKwnd426PJxj54x19nwVRm_7hoOtKQ12bwJ9uXqfb0&amp;uniplatform=NZKPT&amp;language=CHS","pages":"199-230, 293-294","volume":""},{"id":156,"author":"栗军芬","title":"比干墓铜盘铭的发现与流传考述","abstract":"比干墓铜盘铭历来被认为是与殷商时期比干相关的一篇青铜器铭文，铜盘出土于唐代。历代学者对铜盘及铭文众说纷纭，甚至传为孔子所书，流传过程也扑朔迷离。本文以翔实的历史文献，考证了唐开元四年铜盘发现的经过及当时判定为比干墓铜盘的依据，指出其论据不足，铜盘并非出自比干墓，并对宋以来流传过程中的种种歧说作了梳理和辨证。","categories":["09_其它"],"year":2025,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLTeW5hqHXvvri6iMrGdakD_T2jWX3GBitPV2uKzA_O0Y-vyYQlKkpQ16AZZCcdcK6Sn8BsFViSct2V6FQuokeSstf-RAWd0Pypnrib1tKRZ3gV0gpXYZBzsUnk-QfTxkzHRwDp8APVtRSEBvTHD_sQfuNPtJxISzg8X7cTRHxYawEVU84vml1M&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-74","volume":""},{"id":157,"author":"李霏","title":"友朋致徐同柏手札八通考释","abstract":"上海图书馆藏《从古堂款识学》稿本之末裱有友朋致徐同柏的多通信札[1]，今择其中八通加以考释。徐同柏（1775—1854），原名大椿，字寿臧，号籀庄，浙江海盐人，贡生。室名讽籀书窠、从古堂。徐同柏从舅氏张廷济（1768—1848）问学，又得同邑毕星海（1740—1801）指授，精研六书、篆籀，多识古文奇字。著有《从古堂款识学》（以下简称《从古》）十六卷[2]、《清仪阁古印考释》等。此八通手札内容侧重古器款识考释或拓本搜辑,大致分为两类：一是书信人寄赠吉金拓本，或托寻拓本；一是拓请考释审定，或请徐氏亲笔手书考释文字。札中提及的器物款识，多数被收录于《从古》并附考释。","categories":["09_其它"],"year":2025,"publication":"艺术工作","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKsILE4hzUeE5bq7QXzU2A5aUYGOVj8PfB-uRautzKSO78gBJPCOSUczFEPEmUC-ewpyWERQsk-q42e3m8lRI0XsRYATtxTBrGDaVc3jdkPVy73fdbFwLXewfDgiHcAwCqEy2N_gaRF_dl1X0z2eXx4Y5h7eNPUvDu7Y0u-yYd3aewTMV1xmMS_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"96-100","volume":""},{"id":163,"author":"崎川隆","title":"銘文重合辨僞法的理論和實踐","abstract":"一、前言近年來,隨着考古發掘工作的全面開展,科學出土商周青銅器銘文材料的數量日益增多。但就目前的情況而言,“傳世品”或“非考古出土”金文材料的所占比例仍然達到全部材料的一半以上。而且,通過盜掘、私挖等非法、非科學手段出土,後來被轉賣到國内外古物市場的材料也在不斷地增加。因此,若要將那些“非考古出土”材料當做學術研究資料使用,爲了確保研究的科學性,對其進行以辨僞爲主的史料批判工作是十分必要的。","categories":["09_其它"],"year":2025,"publication":"出土文献与古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK6eX0wQvRbp91hS5lZVtH_Pubm31QTj3NtMtxbwhIKVlquTRN2_gN_oX6yBUh3EIGj3XY6ZeEak9UXlKtMWeo8yS4k8XaL3lb0MZWmunNKw2h8r2o9oTunV8kwNkWcLT5PT7CihVJGnF1rGm7QyA-nq0uiiVrPSR9qhSkl2A44wg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"332-349","volume":""},{"id":173,"author":"郭玉海","title":"北宋至民国间青铜器传拓考论","abstract":"北宋开始的青铜器铭文传拓，促进了金石学与传拓技艺的发展；清代乾嘉金石学家广泛参与拓片制作，进一步使金石学与传拓技艺密切结合，相互成就。到晚清时期，明确、系统的青铜器铭文传拓操作规则得以确立，职业手工艺人的出现，更为此后的青铜器拓片制作注入了蓬勃生机。青铜器铭文传拓，俨然成为相关专业研究人员和出版工作者所固有的民族文化信仰，代表着他们对金石学传统的执着与珍视……","categories":["09_其它"],"year":2025,"publication":"紫禁城","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK9wfp5wqrBhUJXlK-OTVMlaVgAig50z0B2c3bP70TUkF_qJUXgYizBDMePboMkTzgLHHtGynRA2qB6fIInm9i2YdQVjsp2sg-X5uEETS_VdlPYIpg6-z4pvqpHe0oYxXN0H8av7tf-XnS-XVoFfxKUcFgJs2VP5If3SGLkw1mBjlsOfltX2yBI&amp;uniplatform=NZKPT&amp;language=CHS","pages":"122-133","volume":""},{"id":174,"author":"李伟敏","title":"周肇祥辑《吉金文字拓本》初考","abstract":"周肇祥是活跃于民国初年的文物收藏鉴赏家、书画家，但目前有关周肇祥金石收藏的资料公布及研究较少。北京市考古研究院藏周肇祥辑《吉金文字拓本》是周氏收藏的吉金文字拓本集，共计三册，收录古器物或其局部铭刻文字拓片161张，所涉古器物种类颇多。本文对拓本所涉器物、印章及部分清末民初金石名家等加以介绍，并对相关问题进行探讨，以期揭示周肇祥在民国初年的金石收藏和研究情况。","categories":["09_其它"],"year":2025,"publication":"收藏家","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIlTQjzm5rJZINX0jr8ExEzgaep5YBCctzFUfEVTEM8I525iwrKqlRLwwOzBNTskmQG-WclFOEKFzWyrau2NIDyNlbJbjgIN2RvEA5O2dYIot-1YhmkKI40o1j9-P3ZG3chS1aKfRFD6zUeIYfHf69q1vHK1VAvIXLmtl65TlOa9jCFLxvP1yFk&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-74","volume":""},{"id":175,"author":"迟杨; 福斯托·准奇利亚","title":"知识驱动的古文字字形识别与语义跟踪研究","abstract":"甲骨文、金文等中国古文字来自遥远的先秦时代,与现代汉字存在明显差异,书写也尚未统一,通常具有多种异体字形。至今仍有大量的古文字尚未被破译,在古文字考释的过程中,专家需要对历史上所有相近的字形进行比较研究,归纳文字演变的规律,从而对未知字形对应的汉字进行推理。但是历史上存在过数以万计的字形,它们的字形、字音、字义知识由非结构化的图像、文本数据所描述,这些数据分散在不同的历史典籍和平台中,难以被关联和检索,古文字研究高度依赖于专家的经验、记忆与推理能力。针对以上问题,本文的目标是利用人工智能(Artificial Intelligence,AI)方法,构建链接汉字的知识图谱,为古文字专家提供知识关联与检索服务;基于知识图谱,量化古文字字形相似度,为专家推荐字形相似的古文字;更进一步,预测未知字形所属的文字标签,启发专家进行考释研究;最后生成汉字字义的历时变化可视化分析。本研究对于古文字这一“冷","categories":["09_其它"],"year":2025,"publication":"946","link":"","pages":"","volume":""},{"id":177,"author":"刘志基","title":"殷商至西周汉字偏旁划一性演变再研究","abstract":"基于合理抽样前提下的穷尽量化调查，就汉字偏旁划一性演变趋向问题进行特定断代范围的再研究后，认为在殷商西周时段，偏旁演变的主要趋向是与“划一性”相反的“分化性”演变。导致这一现象的原因，首先是该时段“偏旁化”是文字构形演变的主流；其次是西周文字相对殷商文字的地域分歧扩大；三是文字构形的成熟性演变缺乏自觉性的内动力。","categories":["09_其它"],"year":2025,"publication":"语言科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKF-EMPtMSVMJt-BuoHYYlLqmRJOFW9X12Scf7ZNWqbEERoyg5cUGbo6mMta3O7jrDrdjbMV3CrlDN8lK4O4jFaH4LCJOiGPq2IJRQXnrCYJWslVTzcfSFGtv0ofNwhMocFOC3PsE8uipsLgkfHJrMGx2r-qi9EFdRTJDbmRgDkjVD17dqR32ks&amp;uniplatform=NZKPT&amp;language=CHS","pages":"206-224","volume":"24"},{"id":182,"author":"吴毅强","title":"陕西历史博物馆藏函皇父鼎盘拓本题跋研究","abstract":"对陕西历史博物馆藏郭沫若、马衡、于右任等所作函皇父鼎、盘全形拓本题跋(简称全形本)进行整理研究，并与郭沫若已发表的《函皇父器杂识》(简称杂识本)进行对比，明确了杂识本的漏字、人物信息不准确等问题，尤其是确定了其写作背景和时间。据全形本可知，此跋是郭沫若应于右任之约而作。同时对题跋涉及的相关历史问题，诸如函皇父的族姓、身份，及其与琱妘的关系进行了综合梳理。明确函皇父与《诗经·十月之交》的“皇父”非一人，琱(女员)亦非周王之妻，函皇父与琱(女员)的关系仍有待进一步研究。此外还揭示于右任、马衡、郭沫若对该组器物铭文的学术观点，如郭沫若的观点是对王国维观点的继承与阐发，为进一步了解彼此之间的学术交往提供佐证。","categories":["09_其它"],"year":2025,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2025.01.003","pages":"19-26","volume":"45"},{"id":204,"author":"秦晓华","title":"训诂与阐释：商周铜器铭文研究的视角与佐证","abstract":"“训诂阐释学”是一个重要的方法论，对文献研究具有指导意义。当前学者多从传世文献的角度出发，探讨“训诂阐释学”的理论及方法。本文以商周铜器铭文为研究对象，探讨将“训诂阐释学”与商周铜器铭文结合的可能性与必要性。将“训诂阐释学”运用于铜器铭文研究，可以更新铜器铭文的研究方法，挖掘铜器铭文的研究价值，进一步揭示古代社会的风俗习惯、政治制度、宗教信仰等多方面的信息，对于了解和研究中国古代历史文化具有重要意义。","categories":["09_其它"],"year":2025,"publication":"学术研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK1HSf0IpRgUBYTGSFrvCC52sQ-jVzOYotUMKD4G27LZmWzzMY3rsf-f7gslPPBx4y2Ru5cmWy3LiQZEGtqYpGPklrpsWjkQmDkqB6G3b6Ex4yGbUCuuYuoPMLfPD9RzC41O4x36-vsXesE2FMh-EspvJ03_9Q4YUQ7ELOiphN0Iou4hzMch6uT&amp;uniplatform=NZKPT&amp;language=CHS","pages":"24-31","volume":""},{"id":207,"author":"李琦","title":"从清代金文题跋看几件虢叔旅钟的流传与著录","abstract":"清代的金文书籍收录七件真铭虢叔旅钟，现有五件存世。学界在著录该组虢叔旅钟的递藏信息时偶有遗漏，而清代金文题跋材料则为补充该组器物的流传信息提供了重要参考。根据相关题跋，阮元藏钟可补充司马亶等三位藏家；张廷济藏钟可补充吴鼒等六位藏家；伊秉绶藏钟可补充瞿世瑛一位藏家；一件下落不明的虢叔钟则可补充陈敏常一位藏家。另外，清代金文题跋等材料中还有两件伪铭虢叔旅钟值得关注，一件现藏美国弗利尔美术馆，另一件则下落不明。","categories":["09_其它"],"year":2025,"publication":"文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJJj-IBTZma5d_kVjwH_VLLM7w3BJ9oPIH34NTFqdwRsKJ9tLmWNjFtxWPEJZWgsDrux2k2JnGPrLPffjujfoKf6Asukl_WkDsbKoja3hC_LekFRTpJI7NI2-cxj2kJQMfTI_cc0vHDdFa0VTOSE_u8xx2mE0vB04CjE0GzdUZoqB8BaZlzHFCv&amp;uniplatform=NZKPT&amp;language=CHS","pages":"98-108","volume":""},{"id":215,"author":"王挺斌; 孙鹤玮","title":"2022年汉字史研究概述","abstract":"本文概述2022年的汉字史研究。2022年的汉语史研究,总体上以字词考释为主。无论是古文字学还是近代汉字学,均以释读文字资料作为核心任务,逐渐形成了以甲骨文字、铜器文字、简帛文字、玺印文字、碑刻文字、写本文字、刻本文字七大文字材料为主体的研究格局。与此同时,研究者也在加强理论建设,一方面总结经验教训,另一方面展望未来研究,积极推动整个汉语文字学的发展。","categories":["09_其它"],"year":2024,"publication":"汉语史学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLW_qZZho-LRHIa8T-xe1AkT7MhLgVRWprgZb1quHqr2s_q1YxWyniIq9ybpz4x5vBiGGw_Qg8S3tHoan-2mBBAIY-djKxetqX6FrzINFlaoXbRpEq8ZT7T2Oh2NgBZdfVQwrTsxmpRZtrlEI6fn0MZAmmcDe2-bA2xiFKO1EE1qw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"157-168","volume":""},{"id":221,"author":"朱其智","title":"白川靜《金文通釋》中的語法研究與銘文考釋舉要","abstract":"本文將考察白川靜在《金文通釋》中是怎樣從語法研究角度來考釋銘文的，將從詞法和句法兩個層面進行考察。詞法方面包括：“百生(姓)”的廣義與狹義、“對各”是二人名還是一官名、“後”的詞性、“遹”的虛實之辨、“日”是名詞還是副詞；句法方面包括：“不■(遂)不■”的句法結構、“■(司)寇”還是“■(司)■”、賞賜物的詞序、“史帶受(授)王令(命)書”爲“主語+動詞+雙賓語”結構等。本文充分肯定白川靜通過語法來進行銘文研究所取得的成績，同時對於不足之處也提出更佳的方案。","categories":["09_其它"],"year":2024,"publication":"出土文献语言研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKPUy0FVz7ql1eameYXqE7RSOFUQduoBeuWX3o8KjbQDpw96soRUiU3HmlLjfFN7tJzJhG8NhlYImO1OzKP4kDxKW3TJZkd95CXx_3gujKsKCTz0nkkge4wiYHrg8MXxkjW35d3iMdS1gkREEpWWYvpWkiXZr_-YaV5SWCzURZlMA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"41-52","volume":""},{"id":226,"author":"孙启灿","title":"先秦钟镈铭文阅读顺序研究","abstract":"有关先秦钟镈铭文的阅读顺序,从20世纪30年代开始就不断有学者论及,但是限于时代和材料,其结论多不完整甚至有和新材料相抵牾的地方。本文收集了目前已经公开发表的先秦时期有铭钟镈703件,对其中铭文存在连读关系的498件进行了系统的分类,归纳了先秦钟镈铭文阅读顺序的部分规律并总结了由此得到的启发。","categories":["09_其它"],"year":2024,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iImxZlY-pvmW6YU28wmadD1rwjmIBWrUde-1gTESNWpMcynthIWLPae0s70rUCp8jLROKSYfhxbZX-F9frCZZmSA4OibKamky6E3gQkdxV4D3rTvXweNvcwmfMvmMp65Gpt6qvpD1P2Ws59-rapvKvKcIzQdZIthzJS975AuB_9UA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"27-37","volume":""},{"id":229,"author":"黄德宽","title":"新时代古文字学学科建构","abstract":"以跨学科视角回顾历史学、考古学、语言学、古文献学等学科对古文字学形成和发展的推进，从古文字材料整理、各类工具书编纂、古文字考释和专题研究，以及学科建设等方面可以勾勒出我国古文字研究和学科建设现状与存在的问题。古文字研究和学科建设，要围绕加强理论综合研究、交叉学科人才培养，以及信息技术与人工智能应用等关键环节，着力建构具有中国特色、世界影响的古文字学自主知识体系和新兴交叉学科。","categories":["09_其它"],"year":2024,"publication":"历史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLqIyn-Z85oWY0Lu83ro6ygOo3zZre1XzroWT110pGj6mU7HtHfrUh9_ros_V08x_ve1fYjcXat847343BhuG4kk_rGUKkmXPs6OdMBDYbGVP02lAKxFS5QemIimpC_H7y6soezpnPDIU9y3AnYsOCB1XjxLH4J8x8bfmUVhMD0EDmL3cWmS13i&amp;uniplatform=NZKPT&amp;language=CHS","pages":"4-25, 184","volume":""},{"id":231,"author":"张钊","title":"作册般铜鼋为偶然射猎之物考","abstract":"2003年，中国国家博物馆征集到一件青铜器，学者称其为“青铜鼋”或“作册般铜鼋”（下文以“铜鼋”指代）。从造型看，该器几乎真实复刻了一只鳖（下文以“鳖”指铜鼋原型）。背甲上有4支箭，铸出了箭羽和杆尾的栝，生动写实。此外，背甲上还铸有4行32字铭文：丙申，王（游）于洹，隻（获）/。王射，（缵）射三。率亡灋（废）矢/。王命寝馗兄（贶）于乍（作）册/般，曰：奏于庸，乍（作）母（模）宝。","categories":["09_其它"],"year":2024,"publication":"大众考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIJEBsKixkXOyxTbhlCzG0bBWeV32juymMjFNm1AvJ9-yUGUa5H42lAL5kdvpMK69xoYNF4rT8htbDS_X0o0NLHoDsDfO5Ce2x4yTzF-S-cHMNKBmfER0YwXZypxYvcNjsfWJZ_yazIApXlysVEF-mBpk2i3N05rkfE5AgwyhsUvB5mwT-6fqoz&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-47","volume":""},{"id":232,"author":"徐加跃; 李春桃","title":"大语言模型时代古文字研究的机遇与挑战","abstract":"大语言模型通过其强大的文本生成和处理能力，已在多个领域显示出卓越性能。然而，在古文字研究这一专业领域，其表现尚未达到理想状态。本文尝试从大语言模型的基本原理出发，系统阐述其优势与局限性。通过分析大语言模型在回答古文字领域问题时的实际表现，探讨其在古文字领域表现不佳的可能原因。最后，探讨了大语言模型在古文字研究中的应用前景及其面临的挑战。","categories":["09_其它"],"year":2024,"publication":"中国语言战略","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIPK138kSX4oIelfHrw_qTLlAmn-Z20mwjyS4MsUf7s0AdnT0j04NmlTRCKbmvOpC3_RbQPniKQeQRvqI6ubF0qtKJPl71U8aj2siZAjhwiTk22CY-aAPh8U1YSb5SjxAnDeavh8QOynb6KZouFZtAJUwQ_mAvEpNhlZ0tsaD9OMw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"48-58","volume":"11"},{"id":237,"author":"包孟鑫","title":"“楚公逆”相关问题研究综述","abstract":"宋时嘉鱼县曾出土“楚公逆”铭文钟，经清代学者孙诒让考证，“楚公逆”当为西周晚期楚君熊鄂，此后学界便广泛沿用“楚公逆”为熊鄂的观点。借助于梳理与“楚公逆”相关铭文释读、钟的形制、晋楚关系等的研究，能够促进对清代以来“楚公逆”研究史的理解，也能在一定程度上厘清其真正的身份。","categories":["09_其它"],"year":2024,"publication":"东方收藏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLPBPCLssF3Ej5n2GPwWDEctZarsh0AnuhdcIGOJJwuOYsXTk22BHuLTBK0z3KfU40biZJKaJ0Aar6fFfVgAWD5y4Fe-MUGChpkM5-wWNyF00Q0AcDp44PKDJ-cM3KoeCv9aP3B7agJ-yYhYJ244ygwVr2v3fj4-KMauFVuKGKv0OgfBZjRM-DU&amp;uniplatform=NZKPT&amp;language=CHS","pages":"33-35","volume":""},{"id":240,"author":"葛亮","title":"“銘文重合辨偽法”補説——以兩組春秋金文爲例","abstract":"作爲判别僞銘或重複著録的簡明方式,“銘文重合辨僞法”不但適用於春秋之前、整篇金文的比對,對於春秋以後、非整篇金文的比對也有重要參考價值。在非考古發掘的傳世品中,有不少略似“全銘模”“單字模”“複合模”製成的銘文,仍能以重合法判定爲僞銘,但需要綜合器形圖像、新舊著録等各方面材料作具體分析。","categories":["09_其它"],"year":2024,"publication":"出土文献综合研究集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJSjM-l9w3Bp1n2W5BFfumEVVXjWIXRalXYsblORPuHdBW0ZrdPPUWHKW2WTf0UOgUmMQpua63fF6WyAobU325gPp8EgW1aJYtV5pe_FBOEibgYRlZaSl_TqqRTTcgdDQJaUNKb7pM-3B9_hZWY2L4UA8-D09qTkCW429tFTj9MOQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"29-42","volume":""},{"id":247,"author":"褚旭","title":"从徽宗《置书艺所诏》看宋代古文字书写取法的转变","abstract":"在汉代至宋初的广阔时空中，曹魏《三体石经》与东汉许慎《说文解字》中的“古文”是人们认识、学习古文字的主要基础，“科斗书”几乎成为古文字的代称。然而随着所见钟鼎彝器铭文日渐增多，宋人逐渐认识到所谓“科斗书”并非三代古文原貌，钟鼎彝器铭文才是古文字书写可资取法的范本。这一观念上的转变，当以宋徽宗《置书艺所诏》为鲜明标志，直接反映在钟鼎文大量进入宋代“法帖”系统，更催生南宋以钟鼎文写卷轴书法这一新形态的出现。","categories":["09_其它"],"year":2024,"publication":"西泠艺丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKooXkhUYwrCDtBUUnNBA-2jiL5oAQpc6hzGwSmfHhK1q4MJt3Rt699UYWSOFvK8Nc-Lw_GH4Kg2A-TFqybr35p-hdzNrZe5jyk-y0KiVJjCGqnMUUPDGo7Gz88i5IxeyQkUlJvud_t20-xJLdgMTfBrJVITub5M73gXQ553cgl2OEeXVQZJoQ_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"82-87","volume":""},{"id":248,"author":"孙启灿","title":"师望鼎出土及流传问题补正","abstract":"本文根据一组新见的清人金石拓片题跋材料对师望鼎的出土流传信息作了两方面的补正，其一是指出该鼎并非为左宗棠收复新疆时所得，而是1873年后出土于陕西汧阳；其二是指出该鼎在沈秉成后、程霖生前另有一收藏者“泉塘徐氏”，但并非旧说所认为的徐楙，具体为何人尚待考证。","categories":["09_其它"],"year":2024,"publication":"收藏与投资","link":"https://link.cnki.net/doi/10.19897/j.cnki.scytz.2024.11.060","pages":"75-77","volume":"15"},{"id":249,"author":"贺思谦","title":"晋姜鼎“铸前作铭”的制作与书手身份蠡测","abstract":"晋姜鼎是春秋时期铭文字数最多的青铜鼎，其铭文的铸造技术继承了西周晚期长篇铭文的传统工艺特点。晋姜鼎铭文，可能采用“铸前作铭”的制作形式铸造成文。这一过程涉及草拟铭文底稿、制范、刻画、翻范、浇铸、打磨等复杂的工艺程序。铭文底稿通常由专业的书手或书写史官负责草拟，并在泥模上绘制；随后由铸刻工匠依据铭文底稿精细刻画铭文。负责草拟晋姜鼎铭文的书手，隶属于晋国的官方机构直接管理，他们的职责与身份在当时的社会结构中占据着重要的地位。","categories":["09_其它"],"year":2024,"publication":"浙江艺术职业学院学报","link":"https://link.cnki.net/doi/10.15965/j.cnki.zjys.2024.04.016","pages":"100-106","volume":"22"},{"id":250,"author":"王祁; 岳洪彬","title":"中国北方地区出土商周铜铙研究","abstract":"“铜铙”是指流行于晚商到西周中期的一种带柄合瓦形青铜击奏体鸣乐器，罗振玉依据《周官·鼓人》注“铙如铃，无舌，有秉，执而鸣之”称这类带柄合瓦形青铜乐器为“铙”[1]，学术界一般沿用这一称呼。从考古学分类而言，“铙”可分为北方小铙[2]和南方大铙，本文主要讨论北方小铙。故此，若无说明，本文所说铜铙，多指北方小铙。“铙”未必是铜铙的古名。","categories":["09_其它"],"year":2024,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIGvhdi8kjVxxNbaM9vZjlfRcY3jD8vZTcATcR9mfGQSvyvSTeghO7C189CgiqPXe6WOy9EYoNWzlZa1EjmsA3besjQDJPhqk2wmJStDtK6c_uHfbgEEuW-04otnYAg0hPjQzGf8b196l1tDF5JqoCuedhQHJKCkmS7rsAtq4baeRx-xDDZ5cOu&amp;uniplatform=NZKPT&amp;language=CHS","pages":"94-106","volume":""},{"id":251,"author":"陈闯","title":"崇古革新——宋代兽蹄足夔龙纹错银铭文铜鼎","abstract":"中国青铜器拥有源远流长的历史，在世界艺术史上占有独特地位，其中以商周时期的器物最为精美，这一时期的青铜器器型种类繁多、造型庄重典雅、纹饰繁缛绚丽，又是宗法礼制与礼仪活动的重要物质载体。汉代以后，青铜器逐渐退出历史舞台。宋代崇尚复古，统治阶级希冀通过礼制的思想将皇权的约束力渗透到人们的行为中去，而仿制商周青铜器则是一个直接有效的途径，故宋廷大规模仿造商周青铜器，或取其外形，或采其纹样，以古入今，以旧营新。","categories":["09_其它"],"year":2024,"publication":"春秋","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLaBo85Czhm6Yo70j21gdDi4bIn3gbLZZDHmY4rH0l8uBAn9BT43BT3plxb7OSe3g9-iblD4MrFGS_HS2DPmLRhEE8JNAHgS55Uttd_r-REjkhGawnq6ynUBHKcO0cMT27gcj0nTRp8xc0pSEOdDaoHQ_qpN8k_kZlhMwtXKZk6NyX0rb5rI7GY&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-72","volume":""},{"id":265,"author":"张闻捷; 周宇锋","title":"商周铜器铭文制法研究与相关问题的讨论","abstract":"本文以商周铜器铭文的制法为主要研究内容，首先系统地梳理了各类铭文的一般制作方法，其中内壁阴文的制法是讨论的重点。目前学界关于青铜器内壁阴文制法的讨论可以分为模作法和范作法两大类，因此本文分别对这两种方法的具体分类和基本内容进行了梳理，从理论和考古材料的层面对提到的猜想进行了可行性分析，进而认为一些简单的铭文可能是用硬模单次翻范法制成，而更为复杂的铭文现象则暗示了堆塑法的普遍使用。","categories":["09_其它"],"year":2024,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLf0jdnrXqEqDyutrAPM6JNsjZkj73XqBqxAaeezBh7dPoQf4n0QZDVrgNIKpF19IHofILVIAVtecBu9oqfIqTyYx5TFRKfilVzdxgZnc4jEDKoN797z9J2y3-ObksDbe96tHEes-fM8hRyE-yPOX828CuTrkM0bDLjSJCNlFVF6FZNE4A9lNOB&amp;uniplatform=NZKPT&amp;language=CHS","pages":"84-95","volume":""},{"id":313,"author":"王红亮","title":"周王畿出土铭文与古史新证——读王晖教授《周王畿：关中出土西周金文整理与研究》","abstract":"金文资料是西周史研究的第一手资料，具有非常重要的史学价值。关中地区是西周王畿所在地，也是晚清以来出土西周青铜器最多、最为集中的地区，且这些青铜器多带有珍贵的铭文。因此，进行关中金文的整理研究，对于推进西周史研究无疑具有重要的学术意义。王晖教授主编的多卷本《周王畿：关中出土西周金文整理与研究》（三秦出版社，2022年出版）一书，就是关于周王畿地区出土金文资料整理与研究的集大成之作。","categories":["09_其它"],"year":2024,"publication":"河北师范大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13763/j.cnki.jhebnu.psse.2024.05.015","pages":"2","volume":"47"},{"id":316,"author":"楊建忠; 李開","title":"胡小石先生古文字學學術思想研探","abstract":"胡小石（1888.8.16—1962.3.16）是我國著名的古代文學研究專家,也是古文字學家、文字學家和古音學家。《胡小石論文集》第一編收有古文字學論文三篇（1）,《胡小石論文集三編》載有古文字學和文字學著論十一篇,古音學著論一篇（2）。胡先生文字學、古文字學論文共十四篇。可以説,有關胡小石先生古文字學和文字學成就遠未得到研究和闡釋。","categories":["09_其它"],"year":2024,"publication":"古典文献研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKu6W72oz2oPKoRanMNUjnVgjdNcXcNlDqO0REPGsEPpBu5ZWTV_xI_pgo6w7NlqPT3gRq3aVonwVBM4J033quSWC3FvXIw0mYeXTlGv8yjVJI7Hwa7H_xbgX3tV4gwiMJcJXCCe8jUTF7gFQOBt0rf8qfXETsg4zJWncT2L21LjA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"339-363","volume":""},{"id":323,"author":"丁一兵","title":"西周金文《毛公鼎铭》与《虢季子白盘铭》艺术比较研究","abstract":"金文是书法艺术的瑰宝，《毛公鼎铭》《虢季子白盘铭》作为西周金文经典，在艺术上极具美学价值，书法家多从中汲取灵感。《毛公鼎铭》是西周金文的庙堂经典，铭文数量位居青铜器之首。《虢季子白盘铭》是金文向小篆演变时期的代表，为历代学者追捧。二者虽都处于西周晚期，且都于宝鸡出土，所呈现的美感却不尽相同。本文通过图像对比的方法，探求二者书风之间的异同，以期对金文的书法创作提供借鉴。","categories":["09_其它"],"year":2024,"publication":"收藏与投资","link":"https://link.cnki.net/doi/10.19897/j.cnki.scytz.2024.08.005","pages":"22-24","volume":"15"},{"id":326,"author":"王其秀","title":"论阮元《积古斋钟鼎彝器款识》的古文字研究方法","abstract":"探讨阮元《积古斋钟鼎彝器款识》中的古文字考释方法和对古文字字形演变规律的认识。其考释方法包括对照法、偏旁分析法、文意推测法，初步形成了古文字考释方法系统；对古文字构形规律有了初步的理论总结。在以古文字考释为基础考经证史的过程中，呈现出“二重证据法”的实践应用。阮元学术领袖的地位，推动了清代金文学及古文字学理论和实践的发展。","categories":["09_其它"],"year":2024,"publication":"安徽工业大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJvfEIN3rHH4f4C-4rxvNFH7QhhZarMNutTHONFU_xM9IctdyffveroAVUcSSaknqKRDpIm3q9hpifo6tx5dQy12HdGaptoWefLplW_UIY-zc_e5HBq8ArTmGRmyIlYoQIw_y0Lf1M3jpiGb-7lvRvGBg3PwcyWbIL51lI6_No4oWcxhzyeOcH_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"37-38, 47","volume":"41"},{"id":330,"author":"郝梅梅; 高燕","title":"皖南出土青铜卣的艺术特征及其礼乐文化","abstract":"青铜卣是商周时期重要青铜礼器之一，亦是西周时期周天子锡命、册封诸侯的“九赐”之物。皖南出土青铜卣纹饰迤逦多彩、繁密规整，造型庄严敦厚、秀丽典雅，呈现独特的艺术特征。作为西周礼乐文化的物质载体之一，皖南出土青铜卣的“尊卣”配对列器组合，纹饰、形制以及铭文所承载文化内涵，皆体现了西周礼乐文化在皖南地区的映射以及皖南本地土著文化与西周礼乐文化的交融与吸收。","categories":["09_其它"],"year":2024,"publication":"铜陵学院学报","link":"https://link.cnki.net/doi/10.16394/j.cnki.34-1258/z.2024.04.002","pages":"46308","volume":"23"},{"id":341,"author":"汪受宽","title":"早秦档案：青铜器铭文考述","abstract":"嬴秦族人从商后期迁西垂（今甘肃礼县），直到秦武公元年（前697年）将都城迁往关中平阳（今陕西宝鸡境），在陇右390余年。本文探究了宋以来出土的早秦有铭青铜器，如昭和钟、秦公簋、不其簋等秦人有意保存的金文档案，揭示了早期秦人历史和思想发展的脉络，证实了秦人在陇西时已经确立统一天下的愿景，制定了相关策略，采取了有效措施，终于崛起于西方，为秦统一六国和建立统一多民族专制皇朝奠定了基础。","categories":["09_其它"],"year":2024,"publication":"档案","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJqTQ8T_4Wme0bREAsqJmBaeZUdGd0vgcNdKnkRdAz9UR8x3ciPlAS5-dAcJuIQA6eA-ZVdKYCDDMR2HsbZ3OArgOtet_DExEUBEFw7LLIQ2urozzhFNEw8mn55nF4ErfhZQ9OmZGI3lgiLeBRyBtYQjlR21k04Aa6_cdkb0oBAvqzgIDkUfGEK&amp;uniplatform=NZKPT&amp;language=CHS","pages":"24-30","volume":""},{"id":342,"author":"王建欣","title":"青铜兵器研究现状综论——兼评《两周青铜兵器定名研究》","abstract":"青铜兵器研究在铭文及器物形制的考较，国别、断代、官制等古史问题研究，以及铭辞格式研究方面已经有了丰硕的研究成果。本文全面梳理青铜兵器的研究现状，指出当前青铜兵器研究存在缺乏均衡性以及研究角度相对不足等问题，兼评青铜兵器研究的力作——《两周青铜兵器定名研究》。","categories":["09_其它"],"year":2024,"publication":"常熟理工学院学报","link":"https://link.cnki.net/doi/10.16101/j.cnki.cn32-1749/z.2024.04.012","pages":"120-124","volume":"38"},{"id":352,"author":"周剑; 张昕瑶","title":"泾渭流域殷遗民墓葬鼎制研究","abstract":"殷遗民鼎的形态大多继承自殷墟时期的同类鼎，仅个别形态有所创新。食器组合中以鼎、簋为核心，或加甗，或加鬲，个别以鬲取代簋。泾河流域、沣镐地区和周原地区用鼎组合有所差异，用鼎数量和食器组合各有特色。同殷墟和西周周人用鼎制度相比，殷遗民墓用鼎在继承和吸纳殷墟时期及西周周人用鼎制度特点的同时，形成了具有自身特点的用鼎制度。墓主身份方面，泾河流域用鼎墓当为为西周王朝戍守边疆的军事贵族，沣镐和周原用鼎墓的中高级贵族为政治贵族，小贵族为手工业者。","categories":["09_其它"],"year":2024,"publication":"河南科技大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.15926/j.cnki.hkdsk.2024.04.015","pages":"103-110","volume":"42"},{"id":355,"author":"葛亮","title":"金文翻拓本辨識","abstract":"在清代民國的金文舊拓中,有一類將金文摹本翻製到硬板上,再捶拓製成的“翻拓本”。其形態近乎原拓,材料性質則與摹本類似。當代集成類金文著録及相關研究論著中,仍有未識别出翻拓本,而誤以之爲原拓,或徑以之爲僞銘的現象,均應注意辨析。","categories":["09_其它"],"year":2024,"publication":"中国古典学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKFNeRcxNsr4HVXm4QjkQFsvobX0Rd60gwC3XVJblpNN1PpGAPcNi2rzyttb-FbU4GpwroE0Nyc3iDW38GyRKsjUH5YLdml0_dR0rkxpgIQmQgYia_9MMF3ocWa26Yjjy0Cro-1F0o5Du9txy73RScRzDkjNmb5X9HK63iH0zKfjw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"287-309","volume":"5"},{"id":366,"author":"徐淵","title":"談談以青銅器銘文研究兩周禮典的幾個誤區","abstract":"通過兩周銅器銘文來對禮典進行研究,存在幾個方面的誤區。一是要避免在確定涉禮青銅器銘文時,由於對銘文的誤釋而造成漏收或者誤收的情況。二是要避免將青銅器銘文涉“禮”與涉“事”相混淆。三是要避免因爲銅器銘文涉禮標準泛化引起誤收的情況,這主要是指將一些不具有禮典特徵的内容認定爲與禮典相關。對以上三種情況導致的兩周禮典相關金文誤收、失收、性質錯判等諸種情形加以細緻分析,才能得出以青銅器銘文研究兩周禮典的正確範式。","categories":["09_其它"],"year":2024,"publication":"中国经学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLvciQzoT3g3SU-AJFEKZMVyWLTGdAVzbcqSn9687YL05gBSro1Ihysj9ilSgyWTz4S0_dK5ZYqbLNOTOWQ6iRbaxiGwnSR3YmNxuLCoyNnWlj1e-cJThiuHUKEZFStiaapfqqzCrsRjAnqP_pJ9ws5idU29rrBHbJUTTDT0TnZGw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"83-108","volume":""},{"id":393,"author":"陳建新","title":"試説仲■父盤銘文真僞及相關問題","abstract":"一《總集》6753[1]著録有仲■父盤銘文,其釋文如下:中（仲）■父作婦姬■（尊）般（盤）,■（稻）■（粱）■（菽）麥,用■（夙?揚?）■（醢）仲氏■（羞/饈）。《集成》與《銘圖》未收録該銘,大概二書的編者認爲是僞銘。但有多位學者論及此銘,並不以爲僞,早期如孫詒讓、于省吾、吴闓生、楊樹達、陳夢家、張政烺、趙錫元等,[2]近年如裘錫圭、周忠兵、李春桃、謝明文、黄錫全、董珊等。[3]上舉釋文即參考上述各家意見而成。","categories":["09_其它"],"year":2024,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ-VTCTLYgLfad_mzruDkJmVncKBwxY_4YrsLiMSzrbLWI4-PKhwsCV5kC6e6kGZoZdQzO_xyY-zFb23rZeT8HMR8L_t-lHexwLSkJUNFW4TU1WQuLwgA8Y26tSGi-fpCQktMareDO3981zp6CxjNW5di9AiTTNTC7t7qtIuhr4sA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"219-231","volume":""},{"id":406,"author":"庄雯; 徐昭峰","title":"商周“信”观念研究","abstract":"","categories":["09_其它"],"year":2024,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJQXcWYActeJ4QBnJkV6yfY9fLoS4XGdo0VGCao-IaFf_sclsjuo55ITXnfUAFRskKqaRqed6Tb4Kgdq1BqJBCtfOnv583r8QzVKAcK4hKEL-rcN7NHL8RuEWJrUz1DgQLtXwbHrX3IQCcCyJlrjFefD7IGdVFFmAQ_SxhXnueUjQunio5jJP75&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":409,"author":"唐惠清; 马军霞; 李永平","title":"南阳盆地东周楚系墓葬出土青铜容器研究","abstract":"南阳盆地在东周时期为楚国北疆,在境内发现出土铜容器的楚系墓葬共81座,出土了929件铜容器。本文以此为研究对象,对其器形、组合、纹饰、铭文进行研究。南阳 盆地楚系墓葬出土的铜容器按用途可分为食器、酒器、水器、挹取器等,通过对铜容器进行类型学分析,可将其分为十一组五期。第一期年代约在春秋中期至春秋中晚期之际;第二期年代约在春秋晚期;第三期年代约在春秋战国之际至战国早期;第四期年代约在战国中期;第五期年代约在战国晚期。南阳 盆地楚系墓葬出土的铜容器组合形式按器类可分为五大类:食器+酒器+水器组合、食器+酒器组合、食器+水器组合、单纯食器或水器组合。根据组合形式又可将墓葬分为甲、乙、丙三类,甲类墓葬等级最高,其铜容器组合形式为食器+酒器+水器,每一器类下又有几个器种,有车马坑或殉人陪葬;乙类墓葬次之,铜容器组合形式为食器+酒器+水器组合或食器+酒器组合或食器+水器,器类或器种减少;丙类墓的铜容器","categories":["09_其它"],"year":2024,"publication":"","link":"https://link.cnki.net/doi/10.27410/d.cnki.gxbfu.2024.001093","pages":"","volume":""},{"id":410,"author":"王为丽; 查飞能","title":"商周冉族铜器群研究","abstract":"冉族,一个活跃于商周时期的族群,其影响深远,不仅聚居于晚商与西周的核心文化区域,且活动足迹分布广。与商周王室保持的紧密关系,在政治、军事和文化等多个领域均有所体现。对冉族铜器群的深入研究,为揭示商周时期的家族结构和社会组织结构提供了重要的研究材料和分析视角。首先 ,从冉族铜器的空间分布来看,其活动范围广,北至东夷,南至荆楚,东至齐鲁。从铜器出土数量的集中区域——殷墟、周原等商周政治中心来看,冉族在当时的社会地位显赫。在湖南、山东等商周文化与其他文化交汇地带,冉族铜器的散见也暗示了族群间的互动与迁徙,这些迁徙往往与军事征伐和文化交流紧密相关。其次 ,通过对冉族铜器的类型学研究,可以进一步了解其时间分布特点。铜器类型的变化和分期结果显示,冉族最为活跃的时期为殷墟文化三期至西周早期。礼器中的酒器占比高,其丰富程度体现了商周时期祭祀文化的盛行和礼制文化的发展。铜器组合的多样化也揭示了铜器实用性的提","categories":["09_其它"],"year":2024,"publication":"","link":"https://link.cnki.net/doi/10.27047/d.cnki.ggudu.2024.002205","pages":"","volume":""},{"id":421,"author":"劉國勝; 朱迪","title":"2023年中國大陸地區戰國出土文獻研究概述","abstract":"本文擬簡要介紹2023年中國大陸戰國出土文獻(包含楚簡、金文、陶文等)的研究概況。一、楚簡研究2023年新公布的楚簡材料主要爲清華簡(第13輯)以及荆州王家嘴楚簡中的部分簡:清華大學出土文獻研究與保護中心編,黄德寬主編《清華大學藏戰國竹簡(拾叁)》由中西書局出版,共收録《大夫食禮》《大夫食禮記》《五音圖》《樂風》《畏天用身》等五篇竹書。","categories":["09_其它"],"year":2024,"publication":"简帛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ6ZjXY7O2ZcE3-nUpxeEwvIPv_FZCf3IfYGuPweTG1mUIWwhrL8lbR9gm6eneV_tbNiQhQ1U01xWwpbYZQcSE79hpFRZ5wAsulzUgQEkfeFW5bix9Fdz5IokvMCTOWKtx8y7D7c5LVMfWbSKmmeMcn8dyjVkvMmh2r8KlcfbG_RQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"273-309","volume":""},{"id":438,"author":"郭妍彦; 刘鹤翔","title":"金石学在近代湖南的传播研究","abstract":"有清一代,以经世致用为旨归的宋学一直是湖南地区的主流学术,乾嘉时期趋于鼎盛的朴学和金石学在这一区域并不发达,湖南当地也缺少全国知名的小学家和金石学家。但自晚清以来,随着湘军的崛起,湖南地方文化也获得了长足的发展,在金石书画领域,以何绍基为先导,出现了一批全国性名家。本文旨在考察金石学在近代湖南的传播过程,并藉以揭示地方政治、经济与艺术文化发展间的互动关系。本文主体分为四个部分:第一章节试图对清代推行的一系列文化政治举措、南方考据学风盛行等文化背景进行历史事实叙述,并将其引论至清廷对湖南地方朴学学术研究的推动;继而从乾嘉至晚清时期湖南朴学的发展动态,探讨湖南地方进行金石学术研究的合理性。第二章节通过湖南金石学家何绍基个案,对嘉道年间金石学者的广泛交游、收藏来源进行了详细的人物考辨;并籍由名拓本《张黑女墓志》题跋中出现的相关人物的治学倾向,以揭示当下金石学家进行金石研究的诸种学术态度,以及“溯","categories":["09_其它"],"year":2024,"publication":"","link":"https://link.cnki.net/doi/10.27661/d.cnki.gzhnu.2024.005910","pages":"","volume":""},{"id":441,"author":"朱雨豪; 吴良寶","title":"春秋金文地名集釋","abstract":"本文是對春秋金文地名原始資料和研究意見的系統整理,在全面整理春秋金文地名的基礎上,彙集各家考釋意見,並加以按斷。同時對春秋金文地名中疑偽和誤判材料進行辨析,以期展現春秋金文地名的研究現狀,爲學者查詢及後續研究提供便利。論文 由緒論、正文、結語、參考文獻、附錄五部分組成:緒論 部分,首先介紹本文選題緣由,敘述春秋金文地名研究歷史,分析以往研究存在的不足。其次對本文地名收錄範圍進行說明,陳述地名判定標準。最後是本文的研究方法與不足。正文 部分爲論文主體,共收錄390個春秋金文地名材料,分爲以下四章:第一 章春秋金文一般地名集釋。本章主要收集春秋金文中的一般地名(指城邑(縣里)地名和自然地名),按照地名所屬地域劃分爲“中原地區”“東土”“南土”“西土”“北土”“區域歸屬不明”六小節。每個地名下首先羅列該地名的全部出處及所在春秋青銅器的相關信息,其次彙集諸家研究意見,最後陳述本文的意見。部分春秋金","categories":["09_其它","08_金文著录"],"year":2024,"publication":"","link":"https://link.cnki.net/doi/10.27162/d.cnki.gjlin.2024.007365","pages":"","volume":""},{"id":442,"author":"杨迎思; 田河","title":"西北师范大学博物馆藏商周青铜器器形及铭文拓片整理与研究","abstract":"西北师范大学博物馆共藏有商周青铜器器形及铭文拓片共66幅,其中64幅青铜器拓片都有铭文,多数为字数较少的族徽铭文,也有几幅篇幅较长、铭文内容较为重要的青铜器铭文拓片。馆藏拓片采用全形拓,拓工精良,保存完好,本论文以西北师范大学博物馆藏商周青铜器全形拓为研究对象,对西北师大博物馆藏商周青铜器拓片的器形及铭文进行整理与研究。本文 将馆藏全形拓与目前已有著录的青铜器进行对比,从青铜器的纹饰形制以及铭文书写的细节入手,找到馆藏全形拓对应的器物。馆藏青铜器拓片的器形及铭文都十分清晰,可以为后续这些青铜器的研究提供参考。文章 按照食器、酒器、水器、乐器、兵器的顺序分别介绍每件馆藏拓片的情况,包括拓片图像、器物图像、铭文、器铭著录情况以及铭文释文;从青铜器器形及纹饰入手,综合学界断代成果及考释意见,对这批馆藏拓片上的青铜器进行年代判断和铭文汇释;对铭文中出现的族徽,整理目前发现该族器物,试从青铜器的出土","categories":["09_其它","08_金文著录"],"year":2024,"publication":"","link":"https://link.cnki.net/doi/10.27410/d.cnki.gxbfu.2024.001076","pages":"","volume":""},{"id":445,"author":"曾峙衡; 赵际芳","title":"中山三器铭文风格创作研究","abstract":"战国中山三器是中国考古学中重要的发现。“三器”即是圆鼎、方壶、圆壶。自1997年出土以来,凭借其独特的风格和内涵,引起了广泛的关注,各界学者都对其进行了研究且发表了许多相关的考释文章,但遗憾的是,对中山三器风格创作的研究较为稀缺,故本文选取中山三器铭文作为研究对象,对其艺术风格进行探究,深入其创作方法。本文 旨在研究战国中山三器铭文,深入探讨其历史背景、艺术特点以及对当代书法创作的影响。首先,本文先从中山古国的历史概况进行了概述,重点探讨了中山国文字的发展情况以及对周边地区的影响。其次,聚焦于中山国青铜器艺术风格的研究,通过对三器及其他器物的艺术风格分析,揭示了中山三器铭文的独特之处,并与其他国家相近风格文字进行对比,探索其艺术特色。接着,探讨了中山三器铭文在当代书法创作中的现象,着眼于徐无闻的创作风貌,以及其他书家在当代中山三器创作方面的表现,以展现其对当代书法艺术的影响和价值。最后,通","categories":["09_其它"],"year":2024,"publication":"","link":"https://link.cnki.net/doi/10.27456/d.cnki.gyndu.2024.002420","pages":"","volume":""},{"id":448,"author":"徐静静; 程燕","title":"陝西近出有銘青銅器整理與研究","abstract":"本論文是對2000年至2023年12月陝西地區新公佈的有銘青銅器材料進行的信息整理彙編及銘文校注。時代上至商代,下至戰國末期。全文分四章進行,第一章爲緒論部分,第一節闡述本論文的研究對象、目的以及意義,以明確本文的研究範圍及大致框架。第二節梳理陝西地區出土青銅器研究的歷史,並概述目前國內外對陝西地區近出青銅器研究的現狀與主要成果。第二至四章是具體的銅器彙編及銘文校注,按照時代先後分爲陝西近出商代有銘銅器研究、陝西近出西周有銘銅器研究、陝西近出東周有銘銅器研究,每章下根據器物的用途大致分爲食器、酒器、水器、樂器、兵器等幾小節,每一器物下標明其所屬年代、著錄情況、出土時地、墓葬信息等,盡量選用高清的器形圖以及質量較高的拓本,銘文如有公佈的高清照片也盡量收錄。在全面總結前(5學者研究成果的基礎上、綜合對比其他出土文字字形資料以及傳世文獻資料,力求給出一個更加準確的釋文,並對其中的疑難字形、字詞的","categories":["09_其它","08_金文著录"],"year":2024,"publication":"","link":"https://link.cnki.net/doi/10.26917/d.cnki.ganhu.2024.003453","pages":"","volume":""},{"id":459,"author":"钟倩; 蒋晓春","title":"宋代金石学研究法","abstract":"两宋之时,以青铜器和石刻为主要研究对象的金石学研究蔚然成风,学者在治学过程中探索出了涵盖材料搜集、金石鉴定、文字考释利用、著作编撰诸环节的金石学研究方法。学者 通过购买、借阅、赠予及实地寻访四种方法获取石刻、铜器、拓本及前人金石著作等研究材料。宋人从青铜器的物质形态、碑文书法及碑文内容出发判断金石真伪,通过历史文献法、比较法、特征归纳法、据出土地推测、据历法推定五种方法推断金石时代,并采取结合器物自名、形制比较及文献记载作综合判断的方法给器物定名。金石 文字是金石学研究的基础。宋人辨认彝铭主要采用字形比较法、偏旁分析法、形象分析法、辞例推勘法等方法,研究基本是对字词的辨识。对于隶书的考释主要是通过文义分析判断假借、异体等情况,以及通过偏旁分析、历史分析和碑文文例比较破解碑文义理不通之处。利用金石文字考证历史是金石学研究的主要目的,学者通过将碑文记载与各种纸本文献记载进行比较的方法,充分发挥","categories":["09_其它"],"year":2024,"publication":"","link":"https://link.cnki.net/doi/10.26917/d.cnki.ganhu.2024.000479","pages":"","volume":""},{"id":460,"author":"陈新映; 胡燕; 李伟","title":"面向古籍的文字类型和文字内容识别方法研究","abstract":"古文字作为中国古代文明的瑰宝,不仅承载着丰富的历史信息与深厚的文化底蕴,更是历史的见证者和文化的传承者。但目前相关的研究却相对不足,这主要是因为古文字形态多样,解读难度大,且很多文献已失传或损毁,加上需要跨学科的综合研究,使得研究更具挑战性。古文字识别是古文字学的重要课题,具有极高的研究价值。通过计算机技术,我们可以更深入地了解古代文明,推动古文字学发展,并为文化传承和历史研究提供有力支持。然而,在古文字识别的过程中,目前依然面临着诸多挑战。具体而言,古文字中同类文字存在大量的异体字,这些异体字在形态上虽有相似之处,但细节差异却可能导致识别错误。此外,不同类文字中相似文字的图像特征区分性较差,使得识别系统难以准确区分。同时,古文字的数据量相对不足,且存在数据类间不平衡的问题,这进一步增加了识别的难度。针对上述问题,本文选择古文字图像作为研究对象,旨在实现古文字字符的准确识别。本研究采用了深","categories":["09_其它"],"year":2024,"publication":"","link":"https://link.cnki.net/doi/10.27381/d.cnki.gwlgu.2024.003227","pages":"","volume":""},{"id":463,"author":"邓君浩","title":"亲昔贤之手泽：从《兰千山馆砚谱》探讨清代金石学家砚铭文化","abstract":"“兰千山馆”为林柏寿（1895—1986）的斋号，在近代书画鉴藏史中是不可忽视的重要课题。林柏寿收藏丰富，以庋藏书画名品闻名于世，并托谭旦囧编《兰千山馆砚谱》，而其古砚的收藏却易被世人忽略，本文即从砚谱考察其收藏的趣味及清代金石学家砚铭文化。台北“故宫博物院”出版的《兰千山馆藏品特展目录》中专辟“古砚”一项，与“法书”、“名画”并立，可知其收藏古砚的数量与重要性。本文将进一步通过砚铭，考察清代金石学家阮元、翁方纲、黄易、叶志诜、张廷济、吴云藏砚的金石鉴藏与交游活动。从砚铭文化探讨，可知林柏寿所藏古砚的文史价值与清人书法的艺术价值，反映出其藏砚的文化意义。最后，本文考察林柏寿收藏砚台的趣味及目的，丰富其收藏形象与文化视野。","categories":["09_其它"],"year":2024,"publication":"西泠艺丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJgwB7SgbAnhKcxdAAQOP3MQV2lOESs3RYX-9l1qVDVhI6No0F1lT9DP0bRmFDm6aJUZkm5L5P4q0qMIzA2Jl3XH7HRGVQ1Fn6CzGuN3357V59zq_XqmEdFs7of6L4klkUMRFJGKDUeB-5MbQR8rsdpcI5z544aF3G6A4M_bri9BNNBi45Rw2QL&amp;uniplatform=NZKPT&amp;language=CHS","pages":"19-27","volume":""},{"id":474,"author":"周建山; 姚磊; 董越","title":"河南省周口市古文字资源调查概述","abstract":"本文就河南省周口市古文字资源调查情况做了概述,并择要介绍周口市十余件带有古文字的馆藏文物,最后介绍周口市地理位置、行政区划和文物资源情况。","categories":["09_其它"],"year":2024,"publication":"汉字汉语研究","link":"https://link.cnki.net/doi/10.13513/j.cnki.41-1041/h.2024.01.013","pages":"9-21, 124","volume":""},{"id":485,"author":"兰凯帅; 乌峰","title":"宋代金石学视野中的汉阙题记","abstract":"汉代石阙作为金石学石刻研究中的一个重要类别,一直受到历代金石学者的重视。相较于阙身画像来说,汉阙题记更是备受瞩目,历代金石学者对其进行了多方面的研究,从文字考释到字法整理,从题记内容到证经补史,从拓本比较到书法鉴赏,从搜罗题跋到实地考察,所作研究详实有据。金石 之学,极盛于宋,宋代的金石学者对汉阙题记所做的很多工作都是开创性的。本文从宋代金石学的视野出发,窥探宋代金石学者是如何看待、分析、评价他们所见的汉阙题记,并分析他们的观点有何异同,依托现存汉阙遗迹去判断他们所作出的研究成果。","categories":["09_其它"],"year":2024,"publication":"","link":"https://link.cnki.net/doi/10.27267/d.cnki.gqfsu.2024.001414","pages":"","volume":""},{"id":487,"author":"刘可欣; 王慧琴; 王可; 王展; 王宏","title":"多类别形态的未隶定青铜器铭文细粒度识别","abstract":"未隶定铭文的识别主要依靠传统卷积网络提供单一的全局特征，却忽略了部位识别和特征学习的关系，导致模型难以充分表达复杂形态的文字构造，进而产生识别误差。针对上述问题，提出了一种姿态对齐的多部位特征细粒度识别模型(MP-CNN)。在第一个阶段，构建空间转换器引导铭文统一字形姿态，辅助模型准确定位文字的鉴别性部位；在第二个阶段，构建级联的ECA(efficient channel attention)注意力机制引导特征通道组合，定位多个独立的鉴别性部位，并通过相互增强的方式细粒化地提取铭文的形态特征，解决复杂形态的文字识别问题；在第三个阶段，构建特征融合层获取识别结果。实验表明，该算法在铭文标准数据集和多类别形态数据集上的识别准确率分别为97.25%和97.18%,相比于传统卷积网络ResNet34分别提升4.63%和8.89%。结果显示，该算法能够有效针对铭文实际形态的独特性，实现未隶定铭文的细","categories":["09_其它"],"year":2024,"publication":"计算机应用研究","link":"https://link.cnki.net/doi/10.19734/j.issn.1001-3695.2023.11.0594","pages":"3194-3200","volume":"41"},{"id":490,"author":"汪丹","title":"新见曾国有铭青铜器研究综述","abstract":"2011年湖北随州叶家山发现西周早期曾国墓地，是继1978年曾侯乙墓发现之后的又一次曾国考古重大发现。近十年来，湖北省陆续出土了不少曾国有铭青铜器，如南公簋、曾侯丙铜缶、楚王媵随仲芈加鼎等等。这些青铜器地域特征明显，是战国青铜器研究中不可或缺的一环。本文先对曾国青铜器的历史研究进行了回顾，并从新出曾国青铜器的铭文研究及考古报告等方面对2010年以来曾国新见有铭青铜器的研究现状进行了整理，最后对曾国有铭青铜器的研究做了展望。","categories":["09_其它"],"year":2024,"publication":"今古文创","link":"https://link.cnki.net/doi/10.20024/j.cnki.CN42-1911/I.2024.08.035","pages":"119-121","volume":""},{"id":497,"author":"耿淼琳","title":"西周动物形青铜尊、觥、卣的造型演变研究","abstract":"动物形青铜尊、觥、卣指整体制成动物形或利用动物身体结构制作而成的酒器，流行于商至两周时期。此类器物既属于青铜酒器，也属于青铜雕塑，它造型题材丰富、纹饰精美，兼实用性与艺术性于一体。西周时期是继商代后动物形青铜尊、觥、卣发展的另一高峰时期，这一阶段的动物形青铜酒器种类繁多，个性化得到极大发展，造型风格与商代产生了极大的差异。西周动物形青铜尊、觥、卣的造型演变研究，有助于从艺术学的角度帮助人们对西周的青铜文化有更深入的认识和了解。","categories":["09_其它"],"year":2024,"publication":"苏州工艺美术职业技术学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIjFFKtOBKdEF_Qf2ls5t71UAIW2Ay6CR7BTMQ9nOvSRvyZ-cvZPnZKeDT0uAOeqMgMps4q-He-9vT2Zijs02MVjBI6dt3fFnuCS97YeEns4AH9n-KfDpHoGWI4ZVwVxeYRaSyiWY-ZzdoqY2aEugyfuyK2RBsCnJwoEAVKO_fIEFvH9Q3VJY6k&amp;uniplatform=NZKPT&amp;language=CHS","pages":"18-23","volume":""},{"id":525,"author":"施漉妍","title":"古文字“畀”的源流演变","abstract":"文章以西周铜器铭文和战国简牍文字为研究主体，基于历时的角度对“畀”字的形体演变和使用情况进行研究。在字形方面，“畀”是象形字，甲骨文字形象有宽大箭镞的箭矢形，金文字形在继承前者的基础上，将曲笔中间空白处填实；秦隶将这部分拉长，箭镞变方；小篆使箭镞部分与箭杆分离，同楷书“畀”字接近。在使用情况方面，“畀”在商代甲骨文、西周铜器铭文和战国简牍文字中的用法差距不大，均表“付与”义，而在具体用法及意义上有一定区别。","categories":["09_其它"],"year":2024,"publication":"汉字文化","link":"https://link.cnki.net/doi/10.14014/j.cnki.cn11-2597/g2.2024.01.022","pages":"26-30","volume":""},{"id":507,"author":"王月妍","title":"懷履光與洛陽金村文物拓本","abstract":"洛陽金村墓葬群是近代名揚中外的考古發現，其出土器物之精美豐富，至今仍令人驚歎。該墓現世於二十世紀三十年代，因非科學發掘，其墓葬形制、文物種類和數量都没有準確的記録。學界對於金村古墓及出土器物的研究，主要是參考加拿大籍在華傳教士懷履光的《洛陽故城古墓考》和日本學者梅原末治的《洛陽金村古墓聚英》兩書。[1]","categories":["09_其它"],"year":2023,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iII4Zig4QiMoRJgkphsujDrJO_B3jBDzsNhchaKiDDKKWpMzRPeiSIZTCyMr-2AkGIjnhf-rlT62fXCYfahrQf2AN-vV9oDcI5Mhb1Hku3P8FERRGhUSSL6cys95gzx4PVIjmgxeVdWjPrzTdFqKNDZHFSGcZPZz8n92QhcBsNjvg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"173-183","volume":""},{"id":512,"author":"陽雪","title":"友朋致陳邦福札十八通考釋","abstract":"陳邦福先生作爲近現代著名的金石學者,與金石學界、考古學界、古文字學界等交往密切。國家圖書館藏陳邦福友朋信札多通,其中有王襄、郭沫若、顧頡剛、郭寶鈞、于省吾、陳夢家、陳邦懷、郭若愚信札各一通,商承祚信札兩通,容庚、胡厚宣信札各四通,其内容大多與甲骨、金石相關,或托尋金石藏品,或交流學術觀點,或托查資料,其中也有私人相關事宜,這些内容頗能展示諸位先生治學之嚴謹、交往之情誼,具有學術價值和史料價值。","categories":["09_其它"],"year":2023,"publication":"文津学志","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKmN59g4uMcFFBDRko0jhS-6kVWo5pb0UiScYMro-aL8i4SOVbr9oQK7dP8R4eMmX8rOlxhBOpxWq0i-bk6ObGTKP0DqyiUcKAeTmjj1wkPJAYFVj9z0bdu1vNDQdx-alhB7_9zWqNpTfhM8CzY-8UKaf3-_GzTmyPLd8nlLrGC6Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"222-238","volume":""},{"id":529,"author":"孫合肥","title":"由越王丌北劍銘文辨僞兵器銘文一則","abstract":"安慶市王家山出土越王丌北劍銘文内容和形式都非常重要，由銘文内容知劍主爲越王丌北，即越王無彊。劍銘字體爲鳥蟲書，且多用裝飾字，如“古”“自”“之”。由越王丌北劍銘文的釋讀可辨朱劍銘文爲後人僞刻。","categories":["09_其它"],"year":2023,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKFEjRlvx3uAYD5zzUd5UrZftlDn_bkK0t4ZNBlMuoy4E6tjfq2EjI8mw7H08m6yNE7Pi8Pes8oR2U5a8-1D1wOXDkglZeGfqIzwwHzPlZLQvFP5Q8NwBlOZAtDb0dtgEn_NzbDot_Dc4pHf0t6HnQrsGfm28G8tCSf-chqhZRrVA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"220-225","volume":""},{"id":543,"author":"苏超","title":"徐国青铜礼器铭文探微——以结构、分类及铸造方式为中心","abstract":"徐,《世本》载为“嬴姓”1,《元和姓纂》及《通志·氏族略》载:“徐氏,子爵,嬴姓,皋陶之后也,皋陶生伯益,禹封伯益之子若木于徐。”2至少在夏代,徐人已作为一支不可小视的政治力量登上了历史舞台,在中国古代漫长的历史河流中,徐国历千年国祚,并铸造了一批青铜礼器,文章试采用文献分析与比较研究法对徐国青铜器铭文的结构、分类与铸造方式等方面进行整理研究,以探寻其独特的青铜文明特征。","categories":["09_其它"],"year":2023,"publication":"东方考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIHAA6eKsVnRhxwinsHuaTn3L0gZI_KPBfp7OicCTB6otu21Be2lopGRA6QuSmVP3ir4dxsMDWj4Z9CjmO2Z5kuC3T-4IFx-3E4jEpzcJjoUbWlz4f2FuLEzIV4y2tbhhhCDZOmFDatEymrIfUrSL71Pf5wvB1o0fjpiY5V9Ld4sw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"39-52","volume":""},{"id":547,"author":"刘智; 刘云涛; 苏荣誉","title":"山东莒县西大庄出土周代青铜盘和匜及其探论","abstract":"西大庄盘、匜出土时现场其他信息缺失，故未同西大庄M1资料一同发表。本文着重从此二器的造型、铸造工艺入手，认为其东夷文化属性较明确，盘匜组合的象征意义大于实际功用。其中西大庄盘独特的造型与装饰，赋予了它超出盥洗器本身的内涵，成为贵族赏玩的艺术品。它的这一属性或为解读其他装饰特殊、工艺精湛青铜器背后的功能和文化内涵提供了思路。","categories":["09_其它"],"year":2023,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIkVOa-EeYh67JCbwGNYzJ-7e4nl_ISiCgK_kqddeCHhc4r0t6LMvrVfLU509ns-PIQqtfyo-eyEIeoVOI_uS4b4L_9HuOB_ps0gL6ECYxPWal6PF0wSUhzo7Fbb9Jm0wBgh32ZmkkFYPBbj7gSIauDiaFUr41_mgwahmN-Wz_U-cWwifeewtDD&amp;uniplatform=NZKPT&amp;language=CHS","pages":"168-174","volume":""},{"id":550,"author":"李红薇","title":"主持人语宏观把握细节考索","abstract":"典籍中关于铜器发现的最早记载可追溯到汉武帝元鼎元年，但真正意义上的金文研究，实肇始于北宋。宋代不仅产生了如《考古图》《博古图》《历代钟鼎彝器款识法帖》一类的金文著录，还出现了《金石录》《集古录跋尾》等侧重文字考释、铭文评述的研究专著。宋人在铜器分类、纹饰命名及器物定名等方面均为后世研究奠定了基础。至于器物年代，一般却只笼统分为商周或秦汉。关于商周器的辨别和年代考订即便偶有涉及，但由于目标不明确、方法不得当，往往产生很多错误，且总体研究缺乏系统性。","categories":["09_其它"],"year":2023,"publication":"郭沫若学刊","link":"https://link.cnki.net/doi/10.16142/j.cnki.gmrxk.2023.04.001","pages":"1","volume":""},{"id":559,"author":"段凯","title":"立足宋人金石文字释读成果考察宋代仿古铜器以“州学祭器”为例","abstract":"宋代是中华文化之大发展时期，陈寅恪在《邓广铭〈宋史职官志考证〉序》中写道：“华夏民族之文化，历数千载之演进，造极于赵宋之世。”1在璀璨的宋代文化中，金石学是其中一流，这门学科从传统史学中分化并逐渐独立，在北宋臻于鼎盛。2从宋代金石学的发展脉络来看，有两股力量从中推动，内在的力量是思想上证经补史的学术理念，外在的力量则是政治上追古复礼的现实需求。这两股内外力量互相影响，相辅相成。","categories":["09_其它"],"year":2023,"publication":"新美术","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKv8dCAJlrqraI5WRKN00SqEhsPKaDP9wYRAWJCc3LSq_kW_E1SAWL6yka6SqsIELwAf2zLnUZaKbgSTvsI5_jq37mAK8r062H0d7DJhQEfW-t0MigpATAy0HL_d9DUoq_FgvH_LQJYQCOv9SJzNdY259ed5W5YZ8G5cOl-dL9veTo1BQUPDRVx&amp;uniplatform=NZKPT&amp;language=CHS","pages":"125-133","volume":"44"},{"id":562,"author":"曹芳","title":"青铜器与铭文鉴定解析","abstract":"我国青铜器在漫长的发展过程中形成了不同风格。从商周时期到清代中期,随着社会生产力水平不断提高和政治制度改革,青铜器逐渐由单纯实用向装饰美化方向转变,不仅反映出当时人们生活水平和审美情趣,且对后世产生重大影响。目前,在青铜器与铭文的鉴定中,学者们多采用传统方法进行研究,但这些方法往往受主观因素限制,较少考虑器物本身的形制特点及纹饰特征等客观条件,无法客观全面地评价青铜器的艺术价值和历史文化内涵。故而,建立一套科学、系统的青铜器鉴定法成为亟待解决的问题。","categories":["09_其它"],"year":2023,"publication":"收藏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKm5zgAezZYd4KzN8lASy9Hx2l99fQ-w368qC-IvzPCjqGN7vL8o-h-fxeywIBfc25Yu1CE3feLaW8uXasyApcLPoltHgZi4TcKmJvTh9_kjNcKFyQ4JJn8rB_oGpDqwM7VT2nCZ3dpQsF1a3cmL7nYAxsef6ZJeaYoFHi5VXljejVQMLvLN4Ew&amp;uniplatform=NZKPT&amp;language=CHS","pages":"16-18","volume":""},{"id":566,"author":"黃艷玲; 單育辰","title":"于省吾《新證》研究","abstract":"于省吾是語言文字研究領域的大家,其研究成果主要集中在甲骨文、金文的研究和古代典籍新證两方面。本文將對其《新證》著作中的部分條目進行分類研究。于省吾《新證》專著主要包括《雙劍誃群經新證》和《雙劍誃諸子新證》兩大部分內容。《雙劍誃群經新證》由《雙劍誃易經新證》《雙劍誃尚書新證》《雙劍誃詩經新證》組成。《雙劍誃諸子新證》包括《雙劍誃管子新證》《雙劍誃晏子春秋新證》《雙劍誃墨子新證》《雙劍誃荀子新證》等11部著作。《新證》中多有利用古文字材料校訂先秦典籍而提出新說之例,本文根據所使用材料的不同,分三個小節,分別是:利用甲骨文進行古籍校訂;利用金文進行古籍校訂;利用古器物進行古籍校訂。《新證》所使用的古文字材料以金文為主,內容也較為豐富,故本文又分為利用金文同源分化字校訂典籍;利用金文中所體現的通假規律校訂典籍;利用金文中形近易)字校訂典籍三部分。此為第三章“利用古文字、古器物校訂傳世文獻”。于省吾","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27162/d.cnki.gjlin.2023.007645","pages":"","volume":""},{"id":571,"author":"李無未; 張品格","title":"林泰輔《中國古文字源流》稿本(1907)發現的意義","abstract":"文章就日本學者林泰輔博士學位論文《中國古文字源流》(1907)一書發現過程、體例、内容及相關問題進行探討。林氏將中國文字分爲篆體時代與隸楷時代,提出象形、指事兩大造字“綱領”説,古文字變遷三期説,其《古文變遷表》以字形爲分期依據,具有明確的地理文字學意識,對秦漢之前古文字分爲8類,將《説文》小篆與秦代金石文進行對比,或同或異,直接相關,小篆繼承古文籀文,開啓後世楷書之端,隸楷時代“異體百出”,打破了小篆造字規則,創立新的楷書造字規則,其古文字“字形比較法”,繼承與發展了《説文》的傳統,更爲系統化、精細化,開辟了走向現代化的中國古文字學研究道路。","categories":["09_其它"],"year":2023,"publication":"出土文献综合研究集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLuLSfFjPxvs8AwvAgejXbglmNEKFPZQvHOPnkUMMsRb7l2TIZQnkXr2iCSpxbmJ80bMpdq4qN6Z1O7c-a9gSnS9kWgFNhJUT_FzRNaM545yK6uqiuX4ZrxpONxcdRNCsP3fr-d7Vb3DYAaUTDrF-9eGW5iimdTKbjoeivQKGlu4g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"149-174","volume":""},{"id":578,"author":"凌晨","title":"笔与笔意：古文字构型的媒介方式与书画用笔探源","abstract":"从上古的结绳记事、仰韶文化时期的陶纹字符、商代的甲骨文到周代的金文，古文字的演进更替具有密切的关联性。早期主要依赖“象形”与“指事”所构成的文字进行记录和思想传递，这两种构成方式自始贯穿于中国文字发展变化的脉络之中。其中可看到软、硬笔书写的笔触痕迹，这不但说明早期硬质书写工具与类似毛笔的软质书写工具始终同时存在并使用，还表明选择毛笔作为书画的主要工具，是人类在漫长的古文字时期通过不断为传达思想意识、为实用和审美需求做出的最终选择。从最初组成书和画最基本造型的形态与方式“点”“划”，发展到可被人们体察的笔意势态，体现了人们对基于材质和工具特点的用笔方法、效果以及笔墨组合的认知和总结。它是中国书画用来“言志”和“传情”的一种手段，更反映出中华民族对传统书画语言的共同了解和认同。","categories":["09_其它"],"year":2023,"publication":"中国非物质文化遗产","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKYto4icEw6uvDZ7fB3OlXw8gnu4lV5zgr8OV8QqMEyR5fUfMk2HKRlS4c7p52ef7lAQFirLvU0CnDrAFFdD6TpjQG53azNwSWMW3ogCczxpR_8l0zTfa5pOpOQFvNL7aZzluNUGhpaMg0VlnyBohv6sMLC1XkMAo8bDuOkH7uDKHlI2BencEdA&amp;uniplatform=NZKPT&amp;language=CHS","pages":"100-105","volume":""},{"id":610,"author":"叶玉纯","title":"王国维序跋古文字研究述要","abstract":"序跋是王国维学术创作的重要组成部分。王国维的许多重要学术观点都是通过序跋提出的。本文通过对文字学相关序跋的研究发现，王国维从古文字学定名、研究对象、研究方法、注意原则等方面初步构建了古文字学的学科理论，其“六国用古文”的独到见解奠定了战国文字研究的基础，在文字学史上的创始之功，实至名归。","categories":["09_其它"],"year":2023,"publication":"黑龙江社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJW0d9OMQ5763ygda46pjp9Wzs1Rw996W946PGSNFIgd3iLYZ2IdOzwNWyXTx6htoJpVYwnFnsU_m43k3Onojx4zQ1zf3JaWvqwjcUl2xN0MXOt_H2PizbJNa_zqqh4AFsW6iypV2gVDBHPnh1zSba5hCrcrbjQpdYSc7dov-u9e1TP6UqcwhS-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"125-129","volume":""},{"id":619,"author":"顾湘","title":"论章太炎对钟鼎文字的态度转向","abstract":"人们普遍认为章太炎不信钟鼎。但从章氏书信、年谱及著述中有关钟鼎彝器的观点，可发现其对钟鼎由“疑”到“信”，只是对宋、清人的释文评价甚低。章氏曾搜求铜器，对铜器的制作材料、铜器拓片以及钟鼎著述都有过关注或研究，还参考钟鼎文字解释《说文》以及《三体石经》等。章氏对钟鼎文字与《说文》关系的讨论，反映了他作为传统小学家“以《说文》为中心”的主张；同时他又不得不承认以《说文》解释古文的局限性，因此也兼采彝器古文。","categories":["09_其它"],"year":2023,"publication":"文史杂志","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIwNoxnP7EgLk2xzI3p71GoR4JoIConBdOwXcvSVZW-tgtiSOnOUE-F0e0ql7cEv2lOKoRcnyBTXkGe1Wt6TgAM4RJqf52UiLw4PFb9rc7W1HSYcVg8kB2YnqCAWYCpYK0aPeKgQIzHZQHaDOUJo-RITQKXqohEpRZaZFW6nlsKuMd3l3vTT2tr&amp;uniplatform=NZKPT&amp;language=CHS","pages":"102-107","volume":""},{"id":627,"author":"","title":"《齐系金文研究》简介","abstract":"“齐系金文”是指铸刻在以齐国为中心包括鲁、邾、郳、任、莒、杞、滕、薛、邿、铸、祝等诸侯国所铸造的青铜器上的文字。据现有的出土资料来看,其起止时间为:上承春秋中叶,下迄秦统一以前。齐系金文作为两周金文的重要组成部分,与其他区域文化的铜器铭文相比,具有自身突出的特色风格,并成为中国东方文字体系的典型代表。在今天对先秦文化进行分区、分域研究日益深化的学术热潮中,就齐系金文进行深入系统地搜集、整理与研究,具有重要的学术价值。","categories":["09_其它"],"year":2023,"publication":"现代语文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKsDyhzeRFIAwchFRHMIhyANzQkWFf3PUpfeIBqGOoQO8ChN0w272Xo8bZJoU9C4taf5Ne2RdhjslKNVuiS3n6TxqkNDnqKsmWXKdmOq-gggxajjAXDk72CS4iZMocGFGUyLRRtI5A1-gSpNB2CMWnr-UuvxBCfViPCuP5FW7StAnKEV8VB9I3a&amp;uniplatform=NZKPT&amp;language=CHS","pages":"98","volume":""},{"id":655,"author":"刘成纪","title":"殷周青铜之变与金文意义之诞生","abstract":"一九一七年,王国维在其《殷周制度论》中指出:“中国政治、文化之变革,莫剧干殷周之际。”[1]在他看来,“殷、周间之大变革,自其表言之,不过一姓一家之兴亡与都邑之移转;自其里言之,则旧制度废而新制度兴、旧文化废而新文化兴”[2]。王国维在此提出了殷周变革的“表”与“里”问题。一般而言,历史的表象总是可见可感的,而其本质则因潜存干事物内部而难以把握。但是,在中国文化中,历史的本质性内容从来不会与其表象分离,","categories":["09_其它"],"year":2023,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLN9ZgYXNCfms-GFI4cJOYJHM-M3--24lBBpuYQjHPyxsthagsyExOxMIrrfFZryTxkOzWFeC4-V7Yc7V-Dzzhss4xecro9Ngr1DBomX6p49s79t47RpyduKBq-VldIWHHEu96FukaEdmqhWAr6U9sbDfExFqLdVGNoGpR67p8chYfgJrub2jS8&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-49, 2","volume":""},{"id":661,"author":"韩鹏; 徐习文","title":"作为仪式的器物：先秦礼乐艺术研究","abstract":"先秦礼乐为中国艺术的萌芽提供了一个较为完整的理论模型和叙事背景:人在制作礼乐器物、展示礼乐仪式时的思想、方法与行动都深刻的影响了早期中国艺术的形成,礼器与中国艺术之间的联系本质上就是器物生命史中物(外在的力量及其媒介)与人(内在的思想、行为)之间的层累式变化(从人神沟通走向神、人与社会的建构)。以这一视角来讨论三代礼乐器物与艺术之间的关联路径,可以在西方的康德审美理论或者传统的儒道艺术的解释方法之外,找到更具拓展性的研究方向:不仅仅从艺术史,更是从社会学、人类学等各个层面讨论礼乐如何借助器物从一类在萨满系统中运行的、以泛神为基础的自然物逐渐成为一种建构理性秩序、充满了丰富物质性和表演性的人工物。在这个基础上,礼乐器物带着强烈的自然性与社会性、历史性与现实性相互交织之二元性特征,逐步溶解到中国艺术的目的、方法和观念中去,成为中国艺术关照自然、命运和现实的动力之源。总的来说,文章力图建立一个理","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27014/d.cnki.gdnau.2023.005705","pages":"","volume":""},{"id":669,"author":"李紅薇","title":"《郭沫若全集》金文著作中的編輯問題","abstract":"1978年郭沫若逝世後,相關部門成立“郭沫若著作編輯出版委員會”(以下或簡稱“編委會”),裒1作者生前出版過的著作,編成《郭沫若全集》(以下或簡稱“全集”)三十八卷。全集包含文學、歷史、考古三編,是目前郭沫若著作中最通行易得且使用率最高的版本,但誠如不少學者所言,問題不少。過去的討論多集中在文學、歷史領域,本文主要探討金文著作中存在的問題。","categories":["09_其它"],"year":2023,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIrhf_lofHXT1I7Q6sIa9o1q_nMC5p_tECl79SnRNjE4saStrX5DXnhgNZ-Mkyz-MCzYVmHiMo4BvCEsGr63ExEESqywuTekOypPV2zIXsKVXZ_OPiFEPMHrTj1LFdh7LJjqYgOQUQfCzTH1eAn_U9vkUgYVBwzkahk2V64CwU2FA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"199-209","volume":""},{"id":683,"author":"丁海斌; 赵婧尧","title":"中国古代档案史金石史料及其应用研究","abstract":"金石史料在中国古代档案史研究中具有独特的价值，其本身作为一种史料，具有很强的真实性。《金石录》《集古录》《殷周金文集成》《古代铭刻汇考续编》等汇编中涉及的档案史史料内容较为丰富且被使用得较多。金石档案史料的内容主要集中在科技档案史料、金石档案的作用、档案官职、档案收集与整理工作、档案名词这几个方面。档案学界在此前对于金石档案史料的应用研究主要集中在档案名词、档案职官、档案工作、档案种类、档案文化等方面。金石史料保存完好，但出土数量有限，其内容仍有很大的发掘空间。","categories":["09_其它"],"year":2023,"publication":"陕西档案","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIk5oI2eWJqcsu59aSXqCKdiWgoGyQXBducrkHLNsV0dy7kLiFmdUjqmceOT2wkfOPZaTVWaYqxLO_46rFLrTNR84TtzYOtbSlEmfMOIHA74rKMHi9kVVx0nayTG1yY7p9bY5s6u71Tp4qur_lAN16krf_haktmla1if2XM99oMyD348nmeXbHi&amp;uniplatform=NZKPT&amp;language=CHS","pages":"11","volume":""},{"id":685,"author":"贾洪波","title":"先秦服式的右衽与尊左问题——先秦服式札记之一","abstract":"先秦中原华夏族服式，上衣以右衽为常制，是尊左观念的反映。右衽是外衣常制，于内衣则似无定式，即左衽、右衽及对襟等均可。而周边所谓“蛮夷”族服式，实际可能存在左衽、右衽、对襟等多种情形，中原华夏族是以异于自身外衣“右衽”常制的“左衽”作为蛮夷服式的代表而称之。","categories":["09_其它"],"year":2023,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2023.03.005","pages":"46093","volume":""},{"id":698,"author":"邱龙升","title":"近四十年古文之研究","abstract":"本文所论“古文”属狭义之传抄古文,是指以《说文》古文为主,包括石经古文、《汗简》《古文四声韵》古文等历代辗转传写而保留下来的古文字资料。近四十年来古文研究在《说文》古文、石经古文、《汗简》《古文四声韵》古文、其他传抄古文以及隶定古文等领域都取得了不错的成绩,研究范围不断扩大,研究材料不断丰富,研究内容不断深入,为汉字研究提供了新的语料,也有力地推动着古文研究朝着更深更广的领域发展。","categories":["09_其它"],"year":2023,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJRpkmxkUgBAI4IPTxJZ0aws_P43XTQGidHutFlzyKUw3wCZUrf1Nm4kdAdqcsXDjUaEG73nqDth1Kq7MarBY0NnEo2B0ngboSxc-iCzGz89j_L0bXEFGPE-xtReNldY811BGNa06A6FP1GEhOhWyXA1Ja5g1tVylsT9uYxaslCTA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46140","volume":""},{"id":699,"author":"熊贤品","title":"论新见嗀甗中的“司寇”及相关问题","abstract":"从册命铭文内容与载体甗之间的矛盾，及“右”“宝”字形、铭文“王曰尹册命■”“用作祖考宝”“万年子子孙孙永宝用”句式等疑问来看，新公布的嗀甗可靠性存疑。仅就铭文内容而言，也看不出“司寇”的具体职责。嗀甗铭文存疑，缺乏作为史料的可靠性，不能作为反映西周中期已经存在“司寇”的金文证据。","categories":["09_其它"],"year":2023,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJj144PBTuGY2fRa-qE322DCXXbTTY6TdWmxQFqbXaPkoSE31FCsDvxcZQpcvNKizvnBC-nDEIznvICUfwyiX3OERbRz16zHA9Qm0R5myf-r-6Wju4Z_z3Po2pLwJTewlDnrW6FUZjpPSUwlVosDFPmGXCfeuT8qnPY1ChBrm2ZKFkwQL6bD4Ei&amp;uniplatform=NZKPT&amp;language=CHS","pages":"77-83, 156-157","volume":""},{"id":701,"author":"王渭清; 赵磊","title":"宝鸡出土西周青铜器铭文的文学史价值","abstract":"西周青铜器铭文是礼乐制度的遗存实物，宝鸡作为周文化的发祥地和中国青铜器之乡，出土的众多青铜器铭文在内容上反映了西周时期的祭祀、赏赐、册命、盟誓、约剂、征伐等方面的历史事实；将其与《尚书》对比，可以印证诰、誓、命、典等《尚书》类文体在西周时期的实际运用，旁证《尚书》中与西周相关文献语言的真实性。宝鸡出土西周青铜器铭文呈现的独特鲜明的文学特质和体式美、伦理美、实用美三者统一的艺术精神，奠定了中国文学现实主义的基因。","categories":["09_其它"],"year":2023,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2023.03.003","pages":"17-25","volume":"43"},{"id":717,"author":"李昭陽; 馮勝君","title":"陳夢家銅器學研究","abstract":"陳夢家(1911.4-1966.9)是著名的考古學家、歷史學家、古文字學家。在陳夢家廣闊的學術領域中,青銅器研究無疑是歷時最長,也是成就最高的。在此領域,陳夢家先後完成了以《海外中國銅器圖錄》《中國銅器綜述》《美國所藏中國銅器集錄》《西周銅器斷代》為代表的一批極具分量的著作。本論文即以上述幾種著作為中心,兼顧其他論著,從青銅器研究的功用、形制、紋飾、銘文、工藝等重點問題出發,全面梳理陳夢家的學術觀點。利用陳夢家的信劄、日記等材料,結合陳夢家所處時代的學術環境和研究水平,分析其銅器研究內部方向轉變和觀點形成的原因。本論文主體共八個部分:一、緒論。介紹陳夢家銅器研究的各個階段,劃分其青銅器研究的時期,探討各時期中的學術旨趣;簡述陳夢家的銅器學著作;總結陳夢家青銅器學的研究現狀,評價之前學者取得過哪些成就,還有什麼不足;陳述本研究的範圍、章節設置、方法和不足。二、專題研究。本部分包括正文的第一章","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27162/d.cnki.gjlin.2023.000982","pages":"","volume":""},{"id":718,"author":"李琦; 李春桃","title":"清代的金文学研究","abstract":"在金文研究史上,清代是繼宋代之後的第二座高峰。清代研究金文的學者群體廣泛,相關著述數量眾多,金文釋讀水平大幅提升,對古文字構形也有所闡述。總體來看,清代學者在金文研究方面取得了令人矚目的成績。本文以清代學者的金文學研究爲對象,以清代金文著録書籍爲基礎,結合器物與銘文的圖像拓本、學者的書信日記等相關材料進行了較爲深入的研究。本文結構與相關章節的主要內容如下。緒論部分首先介紹選題緣由以及研究材料的範圍,論述在學界已有研究的基礎上重新梳理清代金文研究情況的必要性與可行性,並明確“清代”“金文”等概念的範圍與含義;其次是從“整理”與“研究”兩個方面對民國以來學界對清代金文學研究的研究情況進行評述,指出了學界對該問題研究的一些不足。第一章介紹漢代至清代的金文學研究的整體概況,其中又以清代爲重點,分析金文研究興盛的原因,劃分學術史分期並概括評述各時期的特徵,同時對清代金文學研究的成績與不足進行介紹。第","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27162/d.cnki.gjlin.2023.000821","pages":"","volume":""},{"id":724,"author":"关月; 朱添","title":"陈邦怀《金文拾补考释》研究","abstract":"陳邦懷(1897—1986),字保之,室名嗣樸齋,祖籍江蘇省丹徒縣,生於江蘇省東台縣,是我國的古文字學家、考古學家、書法家。《金文拾補考釋》是陳氏金文考釋的力作,書中包含當時新發現的鐘彝銘文和未著錄的舊拓本,後排比畢工編成此書。此書旨在彌補《商周金文錄遺》無釋讀之不便,其按語中旁征博引,滔滔不竭,不僅以當時的新材料、新發現為考釋證據,更引經據典、遍稽群籍,其考釋正是將出土材料和傳世文獻此二者結合起來,可見其金文考釋功力之深厚。本文立足於《金文拾補考釋》對陳邦懷的金文考釋實例進行校議,並在此基礎上梳理陳邦懷《金文拾補考釋》的考釋方法,總結出陳邦懷金文考釋的成就和缺憾。除緒論與結論外,本文共計四個部分。第一部分是對陳邦懷生平經歷、著述及其內容,以及《金文拾補考釋》的主要內容等内容进行研究。第二部分是本文的主體部分,此部分主要依照原文作者的行文順序對此書進行校議,利用傳世文獻以及考古發掘報告等多","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27212/d.cnki.glnsu.2023.001461","pages":"","volume":""},{"id":733,"author":"田燕芳; 马军霞; 李永平","title":"博物馆中面向儿童的青铜器展览研究","abstract":"随着社会的发展,博物馆社会教育功能不断受到重视,博物馆儿童教育也受到越来越多的关注。同时由于近年来考古发掘的进展,学者们对青铜器文化内涵的认识不断提升,青铜器文化的传播也越来越迫切。展览作为青铜器文化传播的重要途径之一,现有研究主要集中于青铜器及展览本身,很少有研究关注青铜器展览如何更好地为儿童服务。因此,研究以青铜器考古资料、学术研究资料及历史文献资料为基础,运用田野调查法、文献分析法、跨学科研究法及个案研究法等来进行探析,通过创新设计来尝试解决青铜器如何给儿童做展览的问题。旨在为面向儿童的青铜器展览提供相应的可行性措施,为博物馆儿童教育及青铜器知识的传播提供新的思路与方法,同时通过创新展览来弘扬中华民族优秀传统文化。研究以青铜器资料为基础,运用儿童发展特征,结合实际融入相关教育理念,如STEAM教育、游戏化教育等来设计展览。同时博物馆依据青铜器特征在展览内容与形式上做相应的创新,使得青","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27410/d.cnki.gxbfu.2023.001702","pages":"","volume":""},{"id":738,"author":"朱旎; 孔令伟","title":"貘尊及其相关问题研究","abstract":"本文以貘尊为锚点,对貘尊、貘纹等材料进行广泛搜索与整理,试图探讨其相关的器型、定名、象形、来源、意义等问题,并以此解答日益模糊的貘尊与牺尊的关系。从存世貘尊的定名脉络、器型、象形三个角度出发,明晰貘尊与所象之貘的关系及其从“现实之貘”转化为“青铜器之貘”的过程中承载的写实类动物造型青铜容器的造型巧思与意义折射,明确貘尊所象之貘在中国古代的确栖息并且此貘与古籍中的“貘”一词并无关联。在此基础上展开对貘纹的整理收集,考察貘纹装饰的内在规律及其与貘尊的关联,貘尊是貘纹的复现与立体化,其实质是周人对非真实的图案传统的延续,更是当时社会发展状况及先人精神世界的映射。现今貘尊与牺尊的混淆是新出土考古材料与传统金石学的碰撞,其根源在于丰赡多彩的青铜实物与金石著录、传统文献的不匹配,而本文通过美术史的方法进行研究,以期从内涵至图像层面将二者相区别。","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27626/d.cnki.gzmsc.2023.000305","pages":"","volume":""},{"id":744,"author":"宋婷婷; 朱添","title":"陈直《读金日札》研究","abstract":"陳直為我國現代著名歷史學家、考古學家,在史學、文學、文字學等多領域皆有所涉獵,著作頗多,名譽中外。但目前學術界對其古文字學方面的成就關注不多。曾有學者對其古文字學著作進行簡要的概括或論述,但未對其古文字學成就進行全面梳理。為此,本文以陳直《讀金日札》為研究對象,對此書的內容、貢獻及疏失之處等進行討論。全文 除緒論、結語外,共分為四部分,第一部分為陳直生平及著述概況。簡述陳直生平經歷和學術概況,並對《讀金日札》一書的成書過程及體例格式進行說明。第二 部分為陳直《讀金日札》校議。此部分為本文重點內容,這一部分依據《讀金日札》原書章節順序,依次按照文字通論、傳世銅器、發掘銅器、璽陶簡石四部分,對陳直的考釋研究進行校議。其中文字通論部分共校議14字,傳世銅器部分共校議44器,發掘銅器部分共校議12器,璽陶簡石部分共校議2條。校議的內容主要對文字的形、音、義等進行校正補充,此外也對其他內容,如句讀、","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27212/d.cnki.glnsu.2023.001144","pages":"","volume":""},{"id":750,"author":"李琦","title":"《紙上吉金》讀後記","abstract":"金文題跋的整理與釋讀對金文研究具有十分重要的作用。近年來，金文題跋整理的相關成果不斷面世。《紙上吉金：鐘鼎彝器善本過眼録》一書公布了上海圖書館所藏的大量青銅器全形拓善本，大多皆有豐富的題跋，爲學術研究提供了寶貴的材料。然而此書對原跋文的整理存在一定的不足，主要表現在誤解跋文原意、誤解跋文内容、誤解跋文所引文獻、標點斷讀錯誤、體例不一等方面。本文主要對該書中的疏漏進行校議，並據此討論金文題跋整理過程中應當注意的一些問題。","categories":["09_其它"],"year":2023,"publication":"出土文献综合研究集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKNeKMTkMVWt-4dUSWiiFVBL1ZkQB93AY_OHWCe-hd2j48JBCjRxssdFHLCv1lp1sdLXHiP06L0EutC9CRIx0PRPfjngbbWnT0aYPidkox79yK2PawZPPydA5ubZc_d0lL2XBRGQDo8yreT5_FZPMopdRICuGkT4BKin7WRHPDf2A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"67-79","volume":""},{"id":753,"author":"刘涛; 唐晓涛; 潘汁","title":"山西浑源彝器百年考古发现与研究（1923-2022）","abstract":"作为近代中国发现最早的东周青铜器,浑源彝器以精美的艺术形式、高超的铸造工艺,推动金石学向古器物学演化变革,贯穿整个现代中国考古学的成长历程,也深刻影响海外汉学与艺术史的发展。浑源彝器反映了山西侯马铸铜遗址鼎盛期的铸造技术,同时广泛吸收北方文化带青铜装饰风格,形成了独具一格的融合形态,是中国青铜器发展史中的重要代表,其地位之高、流散之广、研究之深在中国考古学史上十分罕见。本文依据后过程主义考古学思想史和范式理论,对百年来海内外学者围绕浑源彝器开展的收藏、著录、调查、发掘与研究进行回访调查,厘定出四个发展阶段:1、探索期(1923—1931年)。在古董商与学者的共同推动下,浑源彝器初步完成从私藏古董到学术公器的转变;2、繁盛期(1931—1950年)。浑源彝器引发私人争抢与国家收购混乱局面的同时,在金石学、考古学、艺术史三大学术领域掀起研究热潮;3、赓续期(1950—1992年)。浑源彝器的纹","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27035/d.cnki.ggxmc.2023.001021","pages":"","volume":""},{"id":757,"author":"莫伯峰; 张重生","title":"人工智能在古文字研究中的应用及展望","abstract":"本文对近期人工智能在古文字研究中的应用状况进行了回顾和总结。在古文字字形相关的任务中，古文字识别、古文字检测都已经取得了较大进展，可以为古文字研究提供切实的辅助。古文字分类、古文字考释离实际需求还有较大距离，但是发展思路已经逐渐明晰。在古文字材料整理类任务中，甲骨缀合、甲骨校重、青铜器断代等都已经取得了阶段性成果，推进了古文字研究的进步。展望人工智能与古文字交叉研究的未来发展，多模态模型的应用将会是主要发展方向，生成式人工智能的发散思维将为古文字问题解答提供更多思路，而借助大数据智能的数据挖掘能力则可以发现更多古文字中的规律性现象。","categories":["09_其它"],"year":2023,"publication":"中国文化研究","link":"https://link.cnki.net/doi/10.15990/j.cnki.cn11-3306/g2.2023.02.012","pages":"47-56","volume":""},{"id":765,"author":"徐梦; 朱新林","title":"许瀚文字学研究","abstract":"许瀚(1797-1866)是清代道咸年间著名朴学家、文字学家、音韵学家、金石学家、校勘学家、目录版本学家、书法家,师承高邮王氏父子,同时与汪喜孙、王筠、张穆等著名学者相交游,有“北方学者君第一”的称誉,在山东学术史上具有重要地位。许瀚精通文字声韵,致力于研究《说文》学。不仅研治《说文》,并以《说文》理论为指导,校勘并刊印桂馥《说文解字义证》。同时,受扬州学派兼容并包学术氛围的影响,许瀚笃嗜考据金石文字。因此,许瀚的文字学理论主要集中在《说文》和金石文字两个方面,二者相辅相成,《说文》学根柢是考释金石文字的基础,而对金石文字的考据也进一步巩固《说文》学理论。本文采用文献法和分析归纳法研究许瀚文字学理论,包括《说文》学和对金石文字的考证。本文分四个部分对许瀚的文字学进行研究:第一部分为许瀚生平述要,本文从先世和家门六代两个角度梳理许瀚家世,将许瀚生平分为孜孜求学、应考入仕、南北校书和教书讲学四","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27272/d.cnki.gshdu.2023.003500","pages":"","volume":""},{"id":771,"author":"吴云峰; 中野仁人","title":"秦公簋铭文章法的设计性研究","abstract":"为了使秦公簋铭文在当代设计领域能发挥其独特的艺术价值，笔者通过对于相关文献的研究以及中国国家博物馆的调查走访，归纳总结了秦公簋铭文章法的设计性，并分析其与当代字体设计的关联，明确秦公簋铭文在当代字体设计实践中应用的可行性，这样的实践不仅使古老的书法艺术得到传承，更是给当代字体设计注入中华秦文化的精神血液。","categories":["09_其它"],"year":2023,"publication":"大众文艺","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJTGno9A3Q-jYfz_tzeIhtA2eY1zg_7mM8gEzgp0oKNQSlZma55lSGvvRpnEg1ZkT77fGqWI6Y5f2w7GeSVTlbedj0h-9QI7k3_2kSTU6WQ1Nf0xDAhUK0gstulDNExTExPrHkWVqBzbqCHeOY_nQ3J1-8sWeR4uVcOCvtfC8XMD7c44GKRkfLn&amp;uniplatform=NZKPT&amp;language=CHS","pages":"33-35","volume":""},{"id":774,"author":"王瑾; 杨振国","title":"董逌金石书画鉴赏研究","abstract":"北宋金石书画鉴赏风气的形成、发展与文人群体对书画鉴赏认识的转变存在着密切的关联。在某种程度上说,北宋文人在收集书画与金石碑帖的过程就是对自我认识的过程。生活在北宋中后期的董逌书写鉴赏文本《广川书跋》《广川画跋》时,也就是对自身世代环境的认识与反应。董逌 字彦远,山东益都人,喜以广川为郡望,自称学术为“广川家学”,董逌书写流存的跋文颇为丰富,董逌子董弅辑录为《广川书跋》《广川画跋》二书,并以传世,其著作中考究之“精鉴”被后世之人雅称为“书画中董狐。”因而研究《广川书跋》《广川画跋》文本不仅可了解董逌的书画与金石的见解,还可见其世代的印记。因此本文以北宋董逌为中心,著作为切入点,探究董逌生平事迹,讨论在北宋政治变革之中的鉴赏以及在儒学思潮下的艺术品鉴特征。","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27245/d.cnki.gnjsu.2023.003785","pages":"","volume":""},{"id":782,"author":"李修平; 何景成","title":"李學勤西周金文研究成果的整理研究","abstract":"李學勤是我國著名的古文字學家、歷史學家和考古學家,在西周金文考釋和西周史領域都取得了豐碩的成果,本文以他的西周金文研究爲主要考察對象,分爲歷史研究和字詞考釋研究兩個角度進行了分析研究。論文共分爲上下編兩大部分。緒論主要介紹了李學勤的生平和西周金文研究的主要學術成就、國內外研究現狀和研究方法與論文結構,對李學勤西周金文研究的突出成果和特點進行了簡要的概括和梳理。論文上編整理李學勤對西周時期的歷史研究成果,前三章“西周早期歷史研究”“西周中期歷史研究”和“西周晚期歷史研究”,按時代先後整理李學勤對該時間段的歷史研究成果。在每個章節中先簡要介紹李學勤對該時期銅器的斷代研究成果,再按照每個王世一節的標準分爲四個小節,每小節內又分爲“該王史事相關研究”和“具體銅器所涉史事研究”兩個部分,視具體情況有微調,相關銅器斷代基本依據李學勤的最終觀點,具體可參見附錄“銅器著錄信息表”。第四章“專題研究”整理了","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27162/d.cnki.gjlin.2023.002302","pages":"","volume":""},{"id":797,"author":"臧坤; 徐清","title":"阮元宦浙时期吉金学术活动研究","abstract":"乾隆六十年(1795)至嘉庆十四年(1809),阮元担任浙江学政、浙江巡抚期间,因地制宜地开展吉金学术活动,且进展高效、成果斐然。这不仅是浙地吉金活动的典型,亦是清代吉金研究的代表。本文将阮元宦浙时期的吉金学术活动置于清代吉金学术文化和浙地学术背景下加以考察,展示其在吉金收藏、绘图、模铸、考释、著录、刊刻等各个环节的丰富内容和活动细节,揭明其吉金收藏与学术研究之间的良好互动和密切关联,并探究阮元在吉金学术和书艺两个层面对当时及后世产生的积极影响。阮元“以金证经”的经学研究需求是其高度关注三代吉金的重要原因。宦浙时期,阮元延续和发展了此前任职山东时的吉金探索,并受宋著旧本的影响,将研究成果凝结于《积古斋钟鼎彝器款识》一书。乾隆、嘉庆两朝帝王的经世之举,也为阮元的吉金收藏与研究提供了良好的学术氛围。在阮元的这一系列吉金活动中,各类学者的热心参与和多方协助,是其得以顺利开展、不断推进的重要保障,","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27076/d.cnki.ghzsc.2023.000559","pages":"","volume":""},{"id":805,"author":"杨莉; 朱光耀","title":"晚清苏州青铜器鉴藏活动研究","abstract":"晚清金石鉴藏活动大都以群体考证模式展开。这一时期,不少金石学家以地域为纽带进行鉴藏活动并形成各地的金石文化圈。吴云是晚清金石收藏大家,太平天国运动后退隐苏州,与苏州士绅们一起品鉴三代彝器,碑拓古籍。他既是晚清苏州青铜器收藏者中的佼佼者,又与各地青铜器收藏大家联系紧密,是一个中心式的人物。本文通过剖析以吴云为中心的士绅群体的青铜器鉴藏活动管窥这一时期苏州地区的青铜器鉴藏风貌。首先,对晚清苏州地区的青铜器鉴藏风尚予以阐述,揭示晚清苏州金石文化的社会动因,并对苏州青铜器收藏者中的士商阶级进行深入分析。其次,历史还原晚清苏州青铜器鉴藏网络,尤其对中心人物吴云的鉴藏网络予以系统梳理,探究以其为中心的青铜器鉴藏网络的人员组成,并对这一群体成员的鉴藏观、藏品资金来源及藏品聚散做详细考察;最后,围绕晚清苏州青铜器市场,从作伪、鉴真、交易三个方面展现晚清苏州青铜器市场的时代印迹,以揭示吴云等晚清士人在艺术鉴","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27170/d.cnki.gjsuu.2023.001196","pages":"","volume":""},{"id":806,"author":"喻寅轩; 詹莞如","title":"试论西周青铜器铭文的铸造方法","abstract":"西周时期青铜器的铭文部分，常见三种现象：版印痕迹、阳线方格、版印痕迹与阳线方格并存。前代学者对于前两种现象出现的工艺原因已有诸多猜测，但是对于第三种现象的成因仍缺乏一个令人信服的解释。本文提出了两种新的青铜器铭文的铸造方法，有助于解决西周时期中国各地域出土青铜器铭文篇幅普遍增长的问题，并对我国青铜冶铸技术中较为困难的一环——铭文铸造技术的复原具有重要意义。","categories":["09_其它"],"year":2023,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2023.02.014","pages":"83-93","volume":""},{"id":810,"author":"邹国力; 李禹阶","title":"先秦两汉“节”观念的嬗变及其社会意义","abstract":"在中国古代社会,“节”观念在伦理范畴体系中有着重要地位。“节”观念起源于春秋,形成于战国末期,盛行于两汉。在先秦两汉的历史演进中,“节”观念的内涵随着时代发展而不断演变,其具体表现在:起源于春秋,形成于战国的“士节”,主要强调士人对贵族、封君阶层的个人效忠;至秦汉大一统,“节”观念则转变为对国家、君主效忠的“臣节”,并在时代演进中不断扩大其内涵,而进一步拓展为“女节”“武节”“节行”等。至此,“节”成为中国帝制时代一个重要而多元的社会伦理观,它与“忠”“孝”“信”“义”等伦理范畴一起构成了中国古代社会人们的价值取向与思维模式,并对维护中国古代社会的统治秩序起到了重要作用。本文 以先秦两汉“节”观念的发展嬗变及其社会意义为主要研究对象。首先,从古文字的视角释“节”之古义,以窥先秦两汉“节”观念的渊源,以求探究其横向和纵向的历史嬗变脉络,由此探析先秦两汉“节”观念的起源及与当时国家民族、社会政","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27342/d.cnki.gscdu.2023.007829","pages":"","volume":""},{"id":813,"author":"沈鱼","title":"略论齐、秦金文结构造型异同之原因","abstract":"春秋战国时期，齐、秦二国金文在西周金文的基础上作省形、增形、变易等改变，使两国金文在结构造型上形成极大的差异。尝试用丹纳在《艺术哲学》中提出的相关理论诠释造成齐、秦两国金文字形差异的原因。","categories":["09_其它"],"year":2023,"publication":"语文教学通讯·d刊（学术刊）","link":"https://link.cnki.net/doi/10.13525/j.cnki.bclt.202304026","pages":"78-79","volume":""},{"id":815,"author":"杨皓月; 吴新江","title":"李慈銘的文字學思想與實踐專題研究","abstract":"晚清著名文學家、史學家李慈銘,於《說文》之學亦甚精通,相關成績,主要見於其《越縵堂日記》和讀《説文段注》眉批之中,但是較爲分散,缺乏集中的呈現,很值得加以挖掘和整理。關於李氏文學和史學思想及其成績的整理和研究,前人時修的成果頗豐,而對其文字學,則迄今關注者不甚多,深入研討者更屬寥寥。基於這樣的現狀,本論文從集中考察李氏讀《説文段注》眉批和日常用字著手,探究其“《說文》字”諸認識及其文字學思想,藉以爲李慈銘研究填補一點空白。本論 文一共三個部分。第一 部分挖掘《越縵堂日記》的史料,關注李氏與文字學相關的讀書和交遊活動以及時人用字風氣。李氏好讀文字學相關的書籍,不僅喜愛閱讀《説文段注》等經典,也喜愛閱讀同時代人的《說文》相關著述,李氏的朋友中亦不乏《說文》同好。李氏日記還提及當時科舉試卷違例使用《說文》字的風氣,可見研究古文字、使用古文字不僅是李氏的個人治學愛好,更是晚清學者的“時尚”。第二 ","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27245/d.cnki.gnjsu.2023.000705","pages":"","volume":""},{"id":824,"author":"马静; 田永德","title":"毛公鼎递藏考述","abstract":"毛公鼎被誉为“吉金之冠、国之重宝”，对西周史、青铜器铸造、书法和艺术等方面的研究具有十分重要的价值。在捐献公藏之前，藏家为安全起见，大都秘不示人，以致有关其递藏的诸多问题众说纷纭，或语焉不详。本文利用新发现的拓本题跋等文献资料对毛公鼎的收藏历程进行系统考证，以期推进毛公鼎收藏史的研究。","categories":["09_其它"],"year":2023,"publication":"收藏家","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI69yF-_2Ce8iJO6IobwWP3piwvpQ7hxaSg9Sx1L7ilaWWy3AHHkF9UnxWwdLJWcsRiLudEniDXK1KZgUw5NWVNGrzmcvgbIcJDRBu42L2HnhFqYSBle1sWGIEXSkwUuJu5V3SPk0UHXNPZ5S9Xw5eM0MlqvhbmGL_b4Q3rU0aOXmaRL7F-HcZR&amp;uniplatform=NZKPT&amp;language=CHS","pages":"50-65","volume":""},{"id":830,"author":"胡天正","title":"箑边铭刻与嘉道后金石学的交融——以释达受金石狮兽扇骨为起点","abstract":"《金石狮兽扇骨》是清嘉道时期金石僧释达受在禅修、博古之余，偶涉箑边之作，共铭刻格伯簋、齐侯匜、吴越王金涂塔等六种图文，技艺精妙，意趣深远，为释达受重要的箑边作品之一。本文拟以此作为起点，探讨释达受“减地阳雕”、多器并存等现象背后的“摹古”思想、重构意识以及“八破辑古”的综合艺术观念，进一步揭橥《竹人录》《竹人续录》等文献所见箑边铭刻与金石学之关系，以期为释达受个案研究和嘉道时期金石学史的构建提供些微参考。","categories":["09_其它"],"year":2023,"publication":"西泠艺丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKmzzb2BrvpiizYnXPSg6ZA9Kdo3xER_f5GdEsv2vSECq7W2pkPmp9WgpkeOTkxRyVOtkFn2YXldnIDT3KqVZjNlKJ5QKyhGJnZDzt0NnpD67e7NqUw4jLzlgR7JJK7NXzJ9HtbpC2LeP1Sd3g40QXvXbG3MJovVcoX_xXAccRgRFx51mDX7jt3&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-66","volume":""},{"id":844,"author":"丁忠明; 苏荣誉","title":"晋公盘的铸造工艺分析","abstract":"晋公盘是一件失去考古背景的春秋中期的晋国珍奇青铜器，具有双附耳，三人形足，内底有五类共十九只可旋转的圆雕动物附件，其中鸟喙能启闭，鳖头上半部能伸缩。本研究采用计算机断层扫描技术（X-ray CT）分析盘的内部结构，揭示出圆雕动物内的立柱结构分两种，动物体内均设有对应的卯与之配合，构成间隙连接；据CT图像，可以判断人形足与盘体铸焊，附耳铸接，而立柱铸焊连接。这一研究揭示了高级贵族对以特殊工艺铸造玩好器具的偏爱，并在结构和形式及工艺技术上均有所创新。将晋公盘与子仲姜盘的铸造工艺进行比较，不仅反映出二者在设计、制作中的紧密联系，也体现了春秋中期铸造技术发生的重要变革。","categories":["09_其它"],"year":2023,"publication":"文物季刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLmodx-xVzvdxcvc0csVumYa3CKrvxyPELjB9eEf-KBAgebMNRamRsaG3I-nYerkqbkuqOq4FuU-l6aa4MoSIwx7eFj9pGVf9kgdozxM1CYKqCsmNgjUzdaNi-gLsJRaBVHg_FhyjQLC319YNp2SMEp0iV1MqPURfrEoetESU2BvOLRDogA7STE&amp;uniplatform=NZKPT&amp;language=CHS","pages":"97-110","volume":""},{"id":847,"author":"王馨泽","title":"杨沂孙《在昔篇》中的小篆与古文字","abstract":"清代中期兴起的考据学风掀起了古文字学习的热潮，时至清代末期，篆隶的研究范围逐渐扩大，涉及石鼓文、金文等众多方面。晚清时期的重要篆书书家杨沂孙，在顺应这一时期古文字风潮的背景下，学习融合两周铭文、石鼓文和邓石如书法后，开创出古朴肃穆的晚清篆书新风尚，对后世许多篆书家产生了深远影响。《在昔篇》作为杨沂孙的篆书代表作品，不仅呈现出了他独特的篆书美学特征，也从内容上对古文字书法进行了详细论述，是一篇对书法与古文字学兼具重要意义的作品。","categories":["09_其它"],"year":2023,"publication":"艺海","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL-b9lCMgPiDf0yI7P55WyCkJ2K_AbNrQO26pNFFExvFtq6mNfWVY6Yj3f0g0Is7WV_unILPkcOInqiuvQrbfw5WyBBvXOqdQ21qQuo9Wce_WBY_4Jq1RjvaA01XnCCNlhOeZLI11irj7Ts6SXjKAc2apmqhUL0Td-XwkOYnVhBPHqIgjqb8lZC&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-67","volume":""},{"id":852,"author":"王相帅","title":"钱坫金石学研究述要","abstract":"钱坫是活跃在乾嘉金石圈的一位重要学者。他一生阅览金石无数，学术积累丰厚，结合考据学盛行的时代风气，对金石学有深刻的理论思考。钱坫主张摒弃前代溺于鉴赏把玩的金石研究习气，掘发金石学服务于经史研究的学术传统，致力于考辨文字源流，证验古代经济社会制度、区域地理沿革等切于实用的学术研究。钱坫的金石学研究方法反映出乾嘉小学的发展水平与理念追求，囿于时代情形，得失互见，具有学科发展的阶段性典型特征。","categories":["09_其它"],"year":2023,"publication":"宁波大学学报（人文科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI4KPAgwhFQleYWH1Ei1p-Rg66pa7_HiVtaqYsvlarRpT_4QcJftl3wTxjfbJCYhGhLEzUeb4GOAxqvPUmLGDgjTfVM4Rj0FPgbnHEHCaOBdizzsEmn4Pt5vDHKEurtRSn3MUm5L6trve8ofImkjR3Y7qcgP9P-Og_5vWBLDapcWzEPwPIf9hkN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-71","volume":"36"},{"id":853,"author":"李无未; 周士瑶","title":"中日学界关于中国金文研究的互动","abstract":"贝塚茂树与白川静分别写有金文学史，力图客观而全景式地展现金文学发展史，并无“国别”与“域别”之分，但他们站在日本学者的立场，“隐形”地流露日本化中国金文学史的意识。白川静认为，郭沫若运用考古学研究方法研究古文字，明显受到滨田耕作《泉屋清赏》商周铜器“形态样式”理论与考释方法影响。本文从梅原末治等与郭沫若、容庚的学术互动，以及滨田耕作、梅原末治金文学贡献谈起，力图缕清中日之间的这种学术关系，并对中日近现代古文字学术关系史研究提出个人的看法。","categories":["09_其它"],"year":2023,"publication":"国际汉学","link":"https://link.cnki.net/doi/10.19326/j.cnki.2095-9257.2023.02.011","pages":"86-94, 157-158","volume":""},{"id":856,"author":"范馨文; 张欣","title":"商、西周时期青铜鼎设计研究","abstract":"商、西周时期是中国传统造物的起始阶段,奠定了中国传统造物的发展走势,从而明确了中国传统设计思维发展的基本方向。青铜鼎作为其跨越千年的物质载体,上承新石器时期与夏代之余韵,下启春秋战国之先声,是青铜时代的代表器物。故本文将商、西周时期的青铜鼎列为研究对象,以造物史、设计学为研究视角,遵循史学研究的基本原则,结合考古学的分类方法,以出土、遗传实物结合文献,来梳理商、西周时期青铜鼎的发展演进过程,并对其冶炼技术与工艺、形制与功能、纹饰与铭文中所传达的造物观念和蕴含的设计思维进行探讨与论证,旨在发掘商、西周时期青铜鼎发展演进的艺术价值和今日对中国设计所带来的社会价值。本文 将从以下三方面入手展开对商、西周时期青铜鼎的设计研究:一、立足于考古学相关研究成果,对商、西周时期青铜鼎冶炼技术、形制与功能的演进历程进行研究。通过对商、西周时期青铜鼎冶铸技术的起源与发展进行分析,强调冶铸技术对青铜鼎形制演进所","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27022/d.cnki.gfzhu.2023.001941","pages":"","volume":""},{"id":860,"author":"李润娇; 白国红","title":"东周吴越地区青铜乐器研究","abstract":"本文在前人研究的基础上,对吴越地区考古发现的青铜乐器进行搜集和整理,通过类型学分析对其进行分期,总结其特点与发展规律,并把握其文化交流与功能的演变。本文除“绪论”与“结语”之外,主要由四部分构成,摘要如下:第一部分吴越地区青铜乐器的考古发现。介绍吴越地区的起源发展和文化背景,并且将吴越地区青铜乐器的出土情况按照行政区划分,进行整理和论述。第二部分型式分析与分期。本文以东周时期吴越地区出土的青铜乐器为研究对象,依据其形制、纹饰、铭文等进行类型学分析,并根据分析结果将吴越地区青铜乐器划分为四个时期,并总结其特征和年代。第三部分吴越青铜乐器的文化交流。根据上一部分的型式分析,研究吴越地区出土青铜乐器中带有的中原文化因素与楚文化因素,探讨其所受外来文化的影响,并进一步了解东周吴越地区青铜乐器的自身特点和源流发展。第四部分吴越青铜乐器的功用研究。根据传世文献、器物组合与铭文探讨吴越地区出土的青铜乐器","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27363/d.cnki.gtsfu.2023.000785","pages":"","volume":""},{"id":861,"author":"王一迪; 乌峰","title":"吴式芬金石学研究","abstract":"吴式芬是清代道咸年间著名的古文字学家、金石学家、印学家。著有《捃古录》、《捃古录金文》、《金石汇目分编》、《双虞壶斋印存》、《封泥考略》等多部金石学著作。本文将从吴式芬的金石学研究背景、金石交游、金石学成就及其金石学的当代价值几个方面进行探索,试图通过对其金石学全景式展陈,以引起当代学者的学术重视。在清代考据学、金石学兴起的学术生态环境及海丰吴氏家族、宛平外祖查氏的影响下,吴式芬自幼酷嗜金石文字,平生致力于金石、训诂及校勘工作,尤擅长于考订一事,凡是钟鼎彝器、碑碣石刻、汉代砖瓦、古印古玺、唐镜之文,皆硬黄双钩或摹拓以收录。时人称颂其为“齐鲁才名盖一时”（1）、“平生著录书等身”。（2）此外,他交游甚广,与各界文人学士皆有来往,如金石学家阮元、陈介祺、许瀚、古钱币学家李佐贤、书法家何绍基、文学家龚自珍等,且多有往来手札传世。交游内容则以金石活动为主,主要包括对金石的搜访收藏与传拓、金石鉴赏、","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27267/d.cnki.gqfsu.2023.000146","pages":"","volume":""},{"id":876,"author":"冯文静; 齐晓燕","title":"阮刻注疏本“春秋三傳”附釋音與通志堂本《經典釋文》對比研究","abstract":"唐陸德明兼採漢魏以來諸家音切,作《經典釋文》三十卷,爲典籍經注釋音辨義,具有極高的學術價值。然而,針對其版本源流的研究,相對缺乏獨立性與全面性。關於音義的研究,亦缺少注疏本附釋音與單行本兩種版本間的對比。因此,以“春秋三傳”爲線索,系統探究單經本、全刊本、附釋文注疏本的版本源流,有助於把握其演變脈絡。基於此,爲通志堂本《經典釋文》與阮刻注疏本“春秋三傳”所附釋音建立音義對比庫,並置於網站http://110.41.7.52/呈現共享,以期爲版本對比等研究提供檢索便利。通過音義對比,發現異文發生率約爲15.8%,并且約67.9%集中於文本層面,反映出注疏本附入《釋文》時,對其進行了相關改造。自文 本層面觀之,校勘性異文表現爲)、脫、衍、倒四種類型,校正兩個版本的經注及音義)誤336條,其中多因字形相近而誤。半數以上的脫文、衍文、倒文反映出經注合刊《釋文》時,在不影響實際注音的情況下,對其進行","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27157/d.cnki.ghzku.2023.003805","pages":"","volume":""},{"id":877,"author":"王丽娟","title":"新乡市博物馆藏商周青铜器铭文铸刻位置研究","abstract":"通过列举新乡市博物馆藏商周有铭青铜器铭文铸刻位置,分析出从商代到西周青铜器铭文铸刻位置演变的大概趋势,即从较为隐蔽转化为较为明显的地方。进而以铭文铸刻位置作为切入点,探讨古代文字所蕴含的历史价值、演变的过程并思考演变的原因,以及反映出来的社会变革。","categories":["09_其它"],"year":2023,"publication":"文物天地","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHopJrE83IxSOs7f_YB0MWbzofX1qAF9bqx4i5JIf5zt81-cG8rBYdwVYsn_wOMD5pEpHyRTcKhzZBfPIonlIehar_PKijkx28TsOq41Y5p2IFCKzzkrps_ineg8rDsQmWy7fVeAxNg4VnSkxM7V8CGewJ3QjSrOUupx0k09qUOwyEfJ9X2_Dt&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46120","volume":""},{"id":894,"author":"崎川隆","title":"商周青铜器铭文铸造中的机械复制技术——从淅川和尚岭二号墓出土编钟编镈铭文谈起","abstract":"本文通过对淅川和尚岭二号春秋晚期墓出土的编钟、编镈铭文铸造特征的仔细观察，结合同时期比邻地区出土的相关铜器铭文材料，对春秋战国时期楚地青铜器铭文铸造中“单字模”或“全铭模”等机械复制技术的使用情况进行分析，进而对商周时期“同铭青铜器”铸造工艺中“机械复制”技术的出现与发展及其社会、思想背景等问题进行初步讨论。","categories":["09_其它"],"year":2023,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKjQE10xOUx9EfwoKfufHFt9t3nWsIFBfg6lkUVFr6vjrwYKTd_iI0c5VZei-DcPITGpfynuXmNmN2mXB0gJtJaj1Dne4JjNG0kFt1rCkzGIPNszOkODBoCC8x8TJJ9TUY7fotLwaM6hCbL__VzeHI5aCEPkbUkLQ0-kf2_sHVrWu-ILtOzL-Gl&amp;uniplatform=NZKPT&amp;language=CHS","pages":"57-79","volume":""},{"id":899,"author":"鲁大东","title":"从西周青铜器铭文范铸中的“书范说”看金文的书写性——以《史墙盘》为例","abstract":"青铜器铭文，是讨论和学习商周时期书法风格的主要资料，然而，由于中间经过了比较复杂的制范浇铸工艺，最终呈现的形态与最初书写原貌一定会产生距离。(1)阮元(一七六四—一八四九)在《散氏敦铭拓本跋》中，推测了铭文铸刻的四种方法：余所见钟鼎文字,揣其制作之法,盖有四焉：一则刻字于木范为阴文,以泥抑之成阳文,","categories":["09_其它"],"year":2023,"publication":"书法","link":"https://link.cnki.net/doi/10.16769/j.cnki.31-1067/j.2023.01.029","pages":"87-89","volume":""},{"id":904,"author":"李金","title":"“中山三器”代表的文化同化","abstract":"“中山三器”是战国时期中山国的三件代表性青铜器，分别为中山王舋鼎、中山王方壶、中山妾次圆壶。“中山三器”的器型构造独具艺术特征，既带有中原审美的特点，又表现出强烈的文化、民族融合之特征。其上的长篇铭文，承载了中原的儒学思想与天道观念。“中山三器”的器物特征及其所刻铭文反映了鲜虞白狄游牧文化与中原文化之间产生的同化，代表了北地民族与中原民族之间的文化融合，堪称我国青铜器珍宝。","categories":["09_其它"],"year":2023,"publication":"东方收藏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKFHroJq1VJQDtj7QyDdPZKO7GtrFVCQuWdflhy7bCktVLJaX7yvUZzwvl9tVLv9bZS8TQquwrxRGzkMJIHVO5IMJHMmTEcrnsm-0-v-t0x9ADsUKg8qsPtL1tK-4AsJ2W9ug3TKoUDmzNhcQ0hoyghwCoh3BEde1ovRcgk_1TqdssfQq7d3Ha3&amp;uniplatform=NZKPT&amp;language=CHS","pages":"15-17","volume":""},{"id":986,"author":"郝斯尘; 陈优广","title":"基于Transformer的古文字文本检测算法研究","abstract":"古文字具有极高的历史研究价值,在纸张出现以前古文字一般以甲壳、石碑或器具为载体,为了更好地保存并传播这些跨越了数千年历史的内容,需要进行数字化的工作。文本标注工作作为古文字数字化中的重要一环,需要耗费大量的时间成本,且对标注者的专业素质有一定的要求。本文将基于深度学习的目标检测算法引入这一过程,实现古文字拓片的自动文本检测。本文以魏晋南北朝石刻字数据集以及商周金文数据集作为研究对象,经过对数据集内容的分析,发现古文字文本图像存在背景噪声严重、文本尺寸大小不一、行文不规整等一系列问题。针对这些问题,本文对所选择的目标检测方案的各个部分进行了改进,实现了较高的检测精度。主要工作如下:(1)提出基于Transformer的古文字文本检测模型:根据古文字拓片数据集的特点,提出基于Swin Transformer和Faster R-CNN的面向古文字的文本检测模型。基于视觉特征提取中常用的Swin ","categories":["09_其它"],"year":2023,"publication":"","link":"https://link.cnki.net/doi/10.27149/d.cnki.ghdsu.2023.000158","pages":"","volume":""},{"id":1079,"author":"罗彤瑶; 王慧琴; 王可; 王展; 王宏","title":"融合形态特征的小样本青铜器铭文分类算法","abstract":"现有的青铜器铭文变体种类较少，利用深度学习网络训练容易出现过拟合现象，且深层卷积网络对青铜器铭文细节形态特征提取能力不足，导致铭文分类准确率较低。针对该问题，提出一种融合形态特征的小样本青铜器铭文分类算法。首先，引入形态学算法对铭文进行孔洞填充预处理，降低孔洞对铭文形态结构的影响；其次，调整AlexNet结构，并在各卷积层中引入批量归一化，控制每批随机输入值的分布情况，使输入数据符合正态分布标准，避免网络向单一方向过度学习，抑制过拟合现象；最后，使用speeded-up robust features (SURF)算子提取铭文细节形态特征，并将其与卷积神经网络提取的抽象信息融合，增强分类器的表达能力。在自制青铜器铭文数据集上的实验结果表明，所提算法的分类准确率高达98.86%，优于LeNet5、Vgg13、Vgg16、ResNet、AlexNet等传统算法，说明改进后的算法能有效解决小样本","categories":["09_其它"],"year":2023,"publication":"激光与光电子学进展","link":"https://link.cnki.net/urlid/31.1690.TN.20220713.1450.428","pages":"175-184","volume":"60"},{"id":597,"author":"杨蕾","title":"走进西周贵族的世界——评丁进著《西周铭文史》","abstract":"西周铭文研究发端于汉代,觉醒于宋代,兴盛于清代,所包含内容涉及西周的政治、军事、经济、礼乐等多个方面,充分反映了西周贵族生活和情感。自20世纪70年代以来,随着新材料的不断发现,越来越多的学者着眼于商周青铜器铭文的相关研究,丁进教授所著的《西周铭文史》1就是其中的新起之秀。《西周铭文史》共536页,篇幅厚重,该著以“史”命名,力图反映西周青铜器铭文的发展历程。诚然,书中以时间为经,以空间为纬,以西周王朝贵族铭文创作为主干,以主要诸侯国的铭文创作附之于后,清晰地将西周257年的铭文写作发展全貌呈现于笔墨之间。","categories":["09_其它"],"year":2022,"publication":"中华历史与传统文化论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKx5P0joI1sQK33OvWDlo3ljtgZYToANfrFtU872BM0Hht25EwnrDWq3tawOXXpK0UytibK90HlxJ4XPVjidX_jAS0BFUbZxyTvzyiHAVr8hFtYXSArtdDonpVBC4tCWwdGcKzBw3WOX-T5kQANaWUuTAB1kW_vE-fqal0S_7_73A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"741-744","volume":""},{"id":663,"author":"孙明","title":"《宣和博古图》收录的几件南方风格商周铜磬、铜铙与镈钟","abstract":"宋代金石家们所著的《宣和博古图》，对古代器物图其象，写其形，全面而科学地记录了古代器物的实况和形制，给后代治古器物者奠定了深厚的基础。该书收录的4件铜磬、9件铜铙、1件镈钟，器形、纹饰与南方地区出土的商周时期同类器物颇为相似，其出土地点应在南方地区，尤其是长江中下游的湖南、湖北、江西一带。","categories":["09_其它"],"year":2022,"publication":"湖南博物院院刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIfVUC3AZn8Wx1Z7MC2uh_mLjZ4Gq_1sTBakZ8lQyIW0Iw8f7-90kZenJFfp6fd7AqUhrZc6FhJpstisq0arO_NDhTIkYbn0h5dbNWlDsrm6-fgGq45rXiw98raX0VPzHa6o2xWV3CkffemIw_K0IkztZZjy2wR7vofwt-MdGBctQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"193-202","volume":""},{"id":906,"author":"韋心瀅","title":"西周晚期兩種經典鼎型之探源","abstract":"西周晚期流行的兩種鼎型,一種是“改良式垂腹鼎”,一種是半球形腹鼎。本文不僅探討了此兩種鼎的流行時間、源流變化,更詳實分析其從伊始、發展至衰亡的過程及原因。","categories":["09_其它"],"year":2022,"publication":"上海博物馆集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIwPNsS7-zVKM7OTst6BGk-wYMtXhxpDxda_EPhswKd2E22t5R97eecFyK59y9GSOreTdVQ9gOFRlcDKb9iGcuORnF6FejbEWxCsVBB40Z2oEhajHO-C4R60ZbLfSh4m7dvY9CauWI6apzb5JsPUxaSXyUvUAqhW6lypSTYiXS1bw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"29-39","volume":""},{"id":914,"author":"毕洋; 桂珍明","title":"《秦汉金文录》收录“厌胜牌”“宜月器”考","abstract":"本文将《秦汉金文录》收录的“厌胜牌”“宜月器”与相关金石学著作及考古出土的同类器进行比较;同时围绕考古出土材料,结合相关文献,在铭文、形制、纹饰等方面对上述两器进行综合研究,考察“厌胜牌”及“宜月器”中的“巨久”“巨万”“宜月”所反映的文化意涵。","categories":["09_其它"],"year":2022,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIGIkhtcTcXKJfMxClfQBehfsCZbq1fu8p7AhGR6tvDEBT4fe6s17T_UiEsM0rkAoRRhBtSzsvwRVAl0UsbS_s5QlywTXZqwoya0yV05VL5ThYDs5aZvFaA-nZRXLnU9uC26dBEyeiugxg76tkYUAGEtUX2pMkHaZiGGDBDxgISWQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"107-114","volume":""},{"id":916,"author":"王挺斌; 赵平安","title":"试论近代汉字与古文字的关系","abstract":"加强近代汉字学与古文字学的沟通、交流，对双方的研究都有好处，也是当下整个中国文字学发展的题中之义。文章在前贤时修的基础上，继续探讨近代汉字学与古文字学之间的关系。一方面，古文字学有助于近代汉字溯源，还可以提供器物形制知识；另一方面，近代汉字资料保存了不少古文字，有利于考释古文字。与此同时，还应注意同形字以及字的时代性问题。","categories":["09_其它"],"year":2022,"publication":"汉语史学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKFTsJD7fzfCJPDR-Nxel4S3Kawz39q3rFNTDaU-qAZE0wqD-dTi-yNaJMPQtfOZLyzML2fTKVpYXpuJtEI0htNPHYu4Jr8D6b9YwW8f0qdKQM16BLWhgbajwoaVLazN7Cq47DKRSilk8u8GYdhXHivkG9hdNCxzDv0geOZ1tJUTg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"65-83","volume":""},{"id":922,"author":"陳英傑","title":"青銅器辨僞讀書筆記——兼談青銅器與金文著録的基本信息建設","abstract":"青銅器圖録書籍一般只是反映銅器的某一個角度,而且二維的圖片不具備從實物本身得到的那種直觀印象,銅器的説明文字——包括出土地、同出器、同銘器、器物組合情况、尺度重量、形制紋飾、分範情况、鑄造狀况（範綫、加强筋、墊片、補痕等）、範土存留狀况、製作的精粗、銘文部位及鑄刻方式、文字大小、字畫内有無填充物、銹蝕狀况、器體附着物的痕迹、器内盛實情况、器物使用痕迹、有無修補、著録、收藏以及其他有關信息,其重要性要高於圖片本身。[1]","categories":["09_其它"],"year":2022,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJjaUhPsLNDhEErPN2um80fZaZuyUvKlN0I6dAFqi5BX3VeBp_DaBMhtxoPwfGjxnAdSRvbZxaL1EMDb4NMU5PTtte1Q3tW_Yq-eBWBKqO5edq18azPbebeVM3Q9TpAdkhfH92Ue-ce-ZzxdOisUpZP29ftKGgk_DVmSXwJz19ukA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"129-175","volume":""},{"id":925,"author":"杨凤武","title":"宋以来朱提堂狼铜洗的研究述评与展望","abstract":"本文首先对宋代以来朱提堂狼铜洗的研究史进行分期，按照研究目的、内容、方法、主要观点等将其分为三个阶段，并对每个阶段的研究特色及不足作简要的述评。其次从深化类型学运用、加强铜器组群的研究、注重宏观与微观视角结合、辅以科技手段四个方面进行展望，并在最后进行简要总结。","categories":["09_其它"],"year":2022,"publication":"西部史学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIvKGIB9Xj8w-VX-DyN91M3m6an7U-7nDTCZRahdcHBb2_DEaXGVtdSEYxD6FS3psK0XVkn0usfsdyw97e4hEgzeI2dhmp0p7-L-qwfswjIsC5UvU9VvHAjP9XSM655KFMUjefyDeMz6leF26wUp8K3_7vxUS3HoXwjfjweee_Naw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"29-45","volume":""},{"id":932,"author":"葉玉英","title":"21世紀以來利用古文字資料研究漢語上古音的回顧與展望","abstract":"本文對21世紀以來利用古文字資料的漢語上古音研究進行了回顧與展望，從五個方面回顧了21世紀以來利用古文字資料的漢語上古音研究，分別是音系構擬、上古聲母或韻母的專題研究、音變研究、諧聲通假研究、出土文獻與傳世典籍異文與上古音。對於利用古文字資料研究上古音的前景，本文指出今後應利用古文字資料對上古音作分期分域的研究，從字詞關係入手，比較不同時期、不同地域的用字習慣，發現語音綫索；以詞為中心，開展形、音、義系統的斷代研究；並對出土文獻和傳世文獻異文進行系統整理，發掘共時的語音特徵和歷時的語音演變，進一步研究漢語上古語音演變史。","categories":["09_其它"],"year":2022,"publication":"出土文献语言研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHPZnHLhWIwhfSU1tuKiCKTK5_VNd6YomibvQZE4zV-bL3GIhsZAFwQNlgBaOYtqGkLSraEmIQK96kMUEAKEZX__rhbheiemDx0Ld-CccR8D8D-z8jHZ6hFJEfDk88WCgKPhz6n0Z1lBMgkGWCqo5u6A5PpT5WEc7-ALZAUruxaA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-39","volume":""},{"id":935,"author":"蓝凡","title":"帝、巫同在：商代的行巫与舞蹈——中国先秦时期的巫与舞之新考论（二）","abstract":"巫在商代殷墟甲骨文中,以神鬼的面貌出现,而“■”和“■”为甲骨文中特有的合文。行巫——跳巫的甲骨字形的创造,既表达了殷商巫舞的形态意义,又表达了巫舞的社会意义。这表明了,殷人的巫、行巫和跳巫,是一种具有时代性、社会性的巫、行巫与跳巫。商代的跳巫——行巫时的舞蹈,是殷商王朝神权与王权统一的代表与标志。这种身份的特殊性,决定了巫在商代,既不可能在大规模的祭祀仪式中以群舞者的身份参与,只能以领舞者的身份存在;又不可能为祈雨被暴或被焚;更不可能成为“恒舞于宫”的商王朝的专职“娱人”舞人。在商代,跳巫的特殊性在于,其是神、人、鬼之间的三位一体,是天、人、地之间的三位一体,是帝、人、王之间的三位一体。作为特殊的女性,巫以中国早期奴隶制最后的女性特权,躲在奢华的面具背后,以身体的动作,进行着神界与人界的通道联系。这是身体权力在中国先秦时期的表达。可以这样说,跳巫是商代王权的权力之一,它是商代神权与王权相","categories":["09_其它"],"year":2022,"publication":"当代舞蹈艺术研究","link":"https://link.cnki.net/doi/10.20070/j.cnki.cdr.2022.04.002","pages":"25-38","volume":"7"},{"id":955,"author":"杨叶帆","title":"1922—1946：容庚先生北平治学的学术交游","abstract":"1894年，容庚先生出生于东莞莞城旨亭街8巷，原名肇庚，字希白，初号容斋，后改颂斋，是我国著名古文字学家、金石学家和收藏家。容庚毕生致力于学术，尤精于金石之学，书画、碑帖均有涉猎，编撰专著32种、论文94篇。其一生治学可分为三个阶段：1894—1922年东莞启蒙阶段，主要师承舅父邓尔雅治小学、攻篆刻，撰《雕虫小言》为治学之始；","categories":["09_其它"],"year":2022,"publication":"岭南文史","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKB9y3XNwGE9Cn4mTBJBrswrQWacRFQI-aTKZ0SDz3tHf111E3tdmhEgAtefFQM1W9QYgupkJDcQDowhYidUUSZ3izsClsGSMCEzRhxQYGdwj_OL6rzAiK6qfp84OluHVJxFA-P4INiWu0SbSmVwHCFHuBPqsDSUWCUgfEmKEicSC8ckflhpCRm&amp;uniplatform=NZKPT&amp;language=CHS","pages":"75-83","volume":""},{"id":960,"author":"信明华; 郑杰文","title":"周前时代的表意、书写与知识建构","abstract":"将“文本”的范畴边界,从“书面性”这种单一形态标准的束缚中解脱出来;而直接以其功能和角色的特殊性为依据,将它们作为一种用于呈现和传达意义的装置来看待,如此才算得上触及本质。其中,语言、表情以及肢体动作这类基本能力,直接依托于人类的身体而发挥作用,无疑是所有表意方式中的最基础类型。除此之外,人们还将这种能力延伸到自己身体之外,通过对周围世界中的客观物质进行刻意改造,来实现对于自身意志要素的客观化呈现和表达。那些早在旧石器时代就开始出现的人造工具,至少在目前可见的情况下,可以算得上是这类装置的最早雏形。从新石器时代开始大规模出现的一些特殊材质和造型的非实用器,包括各种装饰品和仪式用品以及玉器、蛋壳陶在内,则是这类装置不断复杂化的结果。在这个过程中,原本包含在各个装置中的实用性要素不断缩减,同时伴随着其中所凝结的表意性成分比重不断凸显和提升。对于这个过程的具体呈现,正是本文第一章论述的主旨之所在","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27272/d.cnki.gshdu.2022.006287","pages":"","volume":""},{"id":970,"author":"张雁勇","title":"两种研究思路的碰撞：《周礼》鸟兽尊彝形制问题再审视","abstract":"在《周礼》鸟兽尊彝形制问题的讨论中，力主象形说而反对刻画、饰物说是目前相当流行的观点。从所列证据来看，象形说的学术价值仅在于“质疑”刻画、饰物说，并提供象形的“可能性”,但无法形成定论。其实在没有充分证据的情况下，对《周礼》鸟兽尊彝形制不宜给出任何一种明确的结论，而应暂时予以搁置。科学的历史考证，谋求在史料充分和考证过程严谨的基础上得出相应结论，否则极易导致论证无效而结论切近，甚至论证无效且结论无效的后果。论证过程模糊化而论证结果明确化的背后，实际上潜藏着根深蒂固的历史还原主义倾向，值得从理论和方法层面深入反思。","categories":["09_其它"],"year":2022,"publication":"史学月刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJK89GDoeDnehnEz_8hbm-FBuFUbgnt3P6-9WiU_LAgRAmTem-2rIA0R3ldHmpzEV1LXB9xFMQObkJMbZiDSz4Fb_bHSzTlgvZ_PUItPgeXHbSg6Xbrc_YwTDioNyecW-UAS6jroWOx8LtXY3O_HWylQZSTvBpXanj2wDrMlyDk9w3vGyoge_kC&amp;uniplatform=NZKPT&amp;language=CHS","pages":"19-28","volume":""},{"id":977,"author":"郝晓亮","title":"青铜器铭文拓片中文字元素价值的体现","abstract":"青铜器铭文具有极高的研究价值，既是中国早期的叙事文学体裁，也是特定时代特有的文学表现形式，同时还为我们研究金文字词训诂提供了重要的史料。中国大部分的青铜器都是铸刻有铭文的，研究人员通过对现已发掘的青铜器铭文进行研究，认为铭文记录的内容多数和古代的朝政事务相关，比如功勋表彰、赏赐、盟约、训诫、祭祀等等，从中可以看出古代人们具备敬畏过往、敬畏祖先以及知荣辱、知礼节、明事理、明是非等方面的优秀品质。","categories":["09_其它"],"year":2022,"publication":"黄河.黄土.黄种人","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJeRxTruJJVTTwZSlG8SVwtTGbc0P1Q45L1tUqoVtG8E1bKiFmscbQAveaCN10K0lob2sEc0MWXRc8paTdXeP6sOEGgxR19MaK7an_BBZKM0avyDJzZe9oQOiwMaD3bjDVR22uGqxSDwW_uLFa21WDEJhc5qVTRtLKvaBHY1hwjJrZ7HX2XzRl1&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-61","volume":""},{"id":984,"author":"万佳俊; 周忠兵","title":"商周青铜器辨伪史","abstract":"青铜器是中华民族的瑰宝,国之重器,历史悠久。尤其是商周青铜器,形制和纹饰均蕴含着政治和文化意义。因为这样的价值,从古至今商周青铜伪器层出不穷。伪器作为学术研究材料使用时,会影响研究结果,得出错误结论。商周青铜器辨伪研究在各个历史阶段取得了不同程度的研究成果,但一直缺少系统的商周青铜器辨伪史整理。梳理商周青铜器辨伪史,可以总结出商周青铜伪器的特点、辨伪研究的演变历程和发展规律,促进青铜器辨伪研究的发展。本文按照时间顺序,分别介绍了清代以前、清代、民国、1949年至1980年、1980年以后五个时间段商周青铜器辨伪研究的社会背景、伪造特点和辨伪研究成果,全文分为以下几个部分:绪论包含本文的选题缘由,“青铜器”、“仿造”、“复制”、“伪造”和“辨伪”的概念界定,商周青铜器辨伪史的研究现状和本文的研究范围。第一章将清代以前的商周青铜器辨伪研究划分为宋代以前、宋代和元明时期三个阶段。这三个阶段的发展","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27162/d.cnki.gjlin.2022.007644","pages":"","volume":""},{"id":985,"author":"方展腾; 陈优广","title":"不平衡数据分布下的商周金文分类算法研究","abstract":"商周金文历史悠久,具备很高的史料和艺术价值,但是这些文字距今年代过于久远并且和现代汉字差别巨大,因此有很高的识读门槛,一般性的识别工作都需要知识渊博且经验丰富的学者手动完成。此外,商周金文数据集存在着严重的样本分布失衡问题,有些类别有上千张样本,而有些类别只有几十张样本,前者被称为多数类或者频繁类,后者被称为少数类或者稀有类。直接使用原始数据集训练出来的模型往往在少数类上识别效果很差。鉴于以上存在的问题,本文将深度学习技术运用在商周金文的智能识别的场景上,重点提升模型对于样本数较少类别的识别精度。具体工作如下:(1)从数据增广方式的角度出发,提出增强少数类样本生成算法(Enhanced Rareclass Sample Generator,ERSG),该算法通过在神经网络训练阶段嵌入一个样本生成模块来动态的生成少数类样本。本文数据集均来源于青铜器,同一来源的古文字有类似的书写字迹和背景特征","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27149/d.cnki.ghdsu.2022.005492","pages":"","volume":""},{"id":996,"author":"李伟敏; 申红宝","title":"《闽县陈氏澂秋馆汇集吉金文字拓本》罗振玉题跋考论","abstract":"北京市考古研究院收藏的《闽县陈氏澂秋馆汇集吉金文字拓本》是陈宝琛为其父陈承裘旧藏器物及清末民初诸多收藏名家收藏器物所做之拓片合集，其中附有罗振玉所撰题跋46则。这些题跋或考证古器物，或考释铭文，间有史实纠谬、真伪考辨等内容，尤其部分题跋尚未见于著录，对辨明罗振玉学术源流、认识其学术进程具有重要的参考价值。","categories":["09_其它"],"year":2022,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2022.05.010","pages":"69-83","volume":""},{"id":1004,"author":"王清雷","title":"西周甬钟篆带对角“两头龙纹”定名考辨","abstract":"青铜器纹饰的定名不统一、不规范等问题由来已久。李学勤先生早在20年前就已指出这一严重问题，但至今仍未能有效解决。如果学科的基础理论问题都难以科学化、统一化、规范化和体系化，又如何落实习近平总书记《建设中国特色中国风格中国气派的考古学，更好认识源远流长博大精深的中华文明》讲话的精神呢？又如何构建有中国特色、中国风格、中国气派的中国考古学话语体系呢？基于此种现状，对西周甬钟篆带所饰“两头龙纹”及其异名进行全面梳理与考辨，希冀能在青铜器纹饰定名的统一与规范性方面有所推进。","categories":["09_其它"],"year":2022,"publication":"音乐探索","link":"https://link.cnki.net/doi/10.15929/j.cnki.1004-2172.2022.04.002","pages":"46322","volume":""},{"id":1027,"author":"朱添; 关月","title":"陈邦怀的金石学研究","abstract":"陈邦怀一生致力于金石材料的搜寻与研究，著述颇丰，对其人其学却鲜少有人研究。为了对陈氏的金石学研究价值进行较为全面且系统地展示，本文运用文献考据和历史考证相结合的方法，通过对陈邦怀及其亲友著述的搜寻与整理，分析陈氏所藏的金石材料的来源及特色，并通过陈邦怀的金石著述总结其金石考释特点及金石学思想。","categories":["09_其它"],"year":2022,"publication":"文化学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLGw6YydtmgxP3rXDywAO9ILEQnw0CSe9woJTri4j_x4quJQKwbvJufgJ_6fXgvRYwkLbcm-0ZclCKlgHXxAt0voRiDGwLHrp-GoDCWNe3q88xtDmt30rlq_WpqAFYZ48wL-oDi0BTWlfMQt70U-2BSATwaGDMagngIYGjvOO-PBc_TgWYmf8dy&amp;uniplatform=NZKPT&amp;language=CHS","pages":"248-251","volume":""},{"id":1041,"author":"曾庆炳","title":"杨树达致容庚书札一通考释","abstract":"《广东省立中山图书馆馆藏名人手札选萃》一书所收杨树达致容庚书札一通,写于1951年5月2日,是目前所见杨氏写给容氏的唯一书信。信中内容反映了杨树达与容庚在学术上的深入交流,凸显了二人的为学风范与学术品格。信中还涉及杨树达对唐兰学术的评价,对研究唐氏学术也有参考价值。","categories":["09_其它"],"year":2022,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iImKXT2osZp7qJAWzXb6-PHMJKZ-umepWcjLClgrZ8aX_Hz3G8vGBGgbUas3KSYSEtbqc8U4DlvnRbGQxIaP47Ynq6r3U-lh_384bqpXzmncDZUTEEHH-3LINq3t_PCTczRByVTcl9BWDE771VkY2SxpZJy1n7YZrP9IRY5P8T31Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"86-88","volume":""},{"id":1048,"author":"阴崔雪","title":"出土文献与中国教育史研究的改进","abstract":"出土文献中的教育信息是教育史研究的第一手材料，甲骨文、金文和简帛文字中呈现出丰富的先秦两汉教育史料，这些史料对部分中国教育史料起到补充和改进的作用。但是目前教育史教材对于这些出土文献并未做到科学合理地征引，未能突破20世纪古代教育史研究框架，这需要当代中国教育史学者不断反思，在未来的教育史研究中充分运用出土文献进行中国教育史研究。","categories":["09_其它"],"year":2022,"publication":"教育学报","link":"https://link.cnki.net/doi/10.14082/j.cnki.1673-1298.2022.04.015","pages":"182-195","volume":"18"},{"id":1056,"author":"孙思雅; 韩雪; 霍宏伟","title":"青铜器与文明交流——第三届中国古代青铜器研究论坛综述","abstract":"2022年6月28日至29日，为庆祝中国国家博物馆创建110周年，中国国家博物馆举办了“青铜器与文明交流—第三届中国古代青铜器研究论坛”。该论坛由国博研究院、馆刊编辑部与北京大学出土文献与古代文明研究所联合承办。论坛邀请了海内外青铜器研究领域的36位专家、学者参会，紧扣论坛主题“青铜器与文明交流”，以线上、线下相结合的方式进行深入研讨。学者发言内容可分为四个方面，即“海内外博物馆藏青铜器研究”“结合近年考古新发现推进对青铜器与商周史的研究”“对青铜器制作工艺的探索”“对青铜器铭文及其历史内涵的考证”。","categories":["09_其它"],"year":2022,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJAmj8gkTOxFaYirq_5CiWEfdEfUcf-MOzggobuSCPnhsbzjtSx3FHPDYme2CyfU2BtFSd-eLVurJ3VDvuZ9U_Hnm3l5G7GA8vxhtl5B3djBsi4YUkT072zR3xWildb9d4fu3vAaJjXsod6uuFhGRuJb5kTLtyg9Tk61cOorVrOUQ4Vsl1IgU9D&amp;uniplatform=NZKPT&amp;language=CHS","pages":"37-44","volume":""},{"id":1060,"author":"史本恒; 宋爱平; 张冲; 王青; 郎剑锋","title":"山东邾国故城新莽铜度量衡器铭文的制作方式","abstract":"2017年山东邾国故城遗址出土了8件新莽铜度量衡器，每件皆有铭文，学术价值重大，但对其铭文的制作方式，学界分歧较大。通过显微镜观察铭文特征，发现其笔画上呈现出有鱼鳞状或台阶状痕迹、末端器表凸起、横截面及末端呈V字形、两侧翻卷隆起、打磨线变形等5种显微形貌特征，与铭文的制作工艺有关。将这些特征与模拟刻铭、模拟铸铭以及不同时代青铜器的铭文进行比较，可知该批铜器铭文应为刻制而成，并非铸造完成。这对重新审视我国古代高超的金属刻制工艺技术有较大启发。","categories":["09_其它"],"year":2022,"publication":"四川文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJPxEwrFYSU1cXvWBzp7gq-hCR2IDD-E2r3FzYP_1YH6vXOJQOI8fx2qGOPSY9RbubJhyQ-wlnwOOTVfIVtKnoZkihFXL6XzkSlHUB29bXka1AUCQw9_6bZ2H8y-4bMRuX1_VQ0aoH2RrVfy_u2z9tWZvCn2L6_vSdQj5qAmCHd58ur6hBKScDG&amp;uniplatform=NZKPT&amp;language=CHS","pages":"77-87","volume":""},{"id":1070,"author":"王睿璿","title":"两周青铜器铭文对文献的佐证与反证","abstract":"两周青铜器的铭文资料，对历史溯源清流起着无法替代的重要作用。两周青铜器对历史考据有着深远而长久的影响。这种影响不仅体现在对历史文献的佐证上，也体现在对历史研究方法的影响上。两周青铜器铭文研究深刻地启发了考古工作对“二重证据法”等传统考古研究方法的思考。本文探讨了两周青铜器背后的社会世界观和价值观。","categories":["09_其它"],"year":2022,"publication":"收藏与投资","link":"https://link.cnki.net/doi/10.19897/j.cnki.scytz.2022.07.053","pages":"59-61","volume":"13"},{"id":1075,"author":"王成梁; 孟凡港","title":"阮元《两浙金石志》研究","abstract":"《两浙金石志》是阮元仕宦浙江期间所编录,收录了浙江地区自秦至元的金石碑刻680种,是浙江金石学的集大成者。阮元作为清代大儒,一生著述颇丰,《两浙金石志》是其金石学研究的杰出代表,该书内容丰富,体例严整,价值突出。本文对阮元《两浙金石志》一书的研究,分四个部分:一、《两浙金石志》是由阮元及其幕府成员何元锡、赵魏、许宗彦等人共同编纂完成。本文对主编者阮元及参编者进行了简要介绍,并论述阮元、何元锡、赵魏、许宗彦等人在《两浙金石志》编修中的作用。阮元主持编修了《两浙金石志》,其自起凡例,以幕友辅之,最后定稿,不愧为《两浙金石志》的主编者。而何元锡、赵魏、许宗彦等人在资料的搜寻、书稿的编撰与校订等方面,出力极多。二、《两浙金石志》的编修不仅与清代复杂的社会背景与学术背景息息相关,同时也与阮元的金石志趣有关。清朝建立后实行文化专制的政策,至清中期,乾嘉考据学蓬勃发展。此时的社会背景和学术背景都对《两浙","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27267/d.cnki.gqfsu.2022.001535","pages":"","volume":""},{"id":1078,"author":"叶春; 孔义龙","title":"论“钟体核心数据”对商周铙形制研究的意义","abstract":"铙的钟体形制影响乐钟的音响性能，体现乐钟的演奏方式，展现古人的铸造技术，对研究铙至关重要。“钟体核心数据”是根据青铜乐钟的形制结构特点测算的六个数据，能较为直观、具象地呈现乐钟钟体形制特点。以统计学为主要研究方法，以钟体核心数据为切入点，统计和分析了出土的157件商周铙和33件早期甬钟的钟体核心数据。通过分析数据，探讨不同地区、不同时期铙的形制特点与规范性，以及铙与甬钟形制的传承关系。","categories":["09_其它"],"year":2022,"publication":"音乐研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIfRMmuOxHgnbJl21Nww1oX7raBxH1W2h6p2-MutI5kmu86UvrnLWhipYb6Mrk1gOPUvmXD59wXlJzbRqd3H9gTv-JB99-bTB9TY4S5tX6VRn4Drb-PRIpy-5-sSHt9XpwGSDV35DSli0Wq6QwQpKYQq6ELCXSANJ0W4a3P_3EiurGOmBOHwnl7&amp;uniplatform=NZKPT&amp;language=CHS","pages":"14-27, 109, 145","volume":""},{"id":1090,"author":"苏天运","title":"章太炎《春秋左传读》引钟鼎文字考论","abstract":"一般认为,章太炎先生对出土文字材料持较为保守的态度。但通过考察我们发现,受时代氛围、学术师承的影响,太炎先生在早期的学术实践中对钟鼎文字进行了一定的引证和运用。我们即以章太炎的《春秋左传读》为研究对象,详尽考察其中钟鼎文字的材料来源及所发挥作用,并尝试对其运用得失进行评价。此外,我们通过太炎先生其他学术著作中的相关材料、论述,还能够看到其前后部分材料观点上的延续性,以及推测他对钟鼎文字等出土材料态度发生转变的原因。","categories":["09_其它"],"year":2022,"publication":"励耘语言学刊","link":"https://link.cnki.net/doi/10.13554/b.cnki.liyunyuyan.2022.01.005","pages":"46348","volume":""},{"id":1105,"author":"王沛; 王捷; 姚远; 邬勖; 陈迪; 周博; 黄海; 乔志鑫","title":"回顾与前瞻:甲、金、简牍法制史料研究述评","abstract":"中国中古之前的法律史框架基本由出土法律文献建构,只有全面整理与精研甲骨、金文、简牍法制史料才能突破早期法史研究中的“瓶颈”,才能厘清早期中国法制演进的宏观线索,才能准确认识中华法系的形成过程及其世界价值。近30年来出土法律文献数量急剧增长,新的重要发现层出不穷,对旧材料的认识亦随之发生诸多变化。本文分别对甲骨、金文、简牍法制史料的整理研究情况加以综述,并对未来的研究前景加以探讨。","categories":["09_其它"],"year":2022,"publication":"出土文献与法律史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLDmFbhjpx7BX0DDSh8vvxMxgdc6ByUcHyTQ4aptfcwPBpsPGVsb_J-KeB1JSbcooiBPXkdzbi0cgqkN2YVloNGfs87-vfKmqgsLz2uMqMoWnng0D1upNrGYv4tcSfKZwXNzx2upQXMEoUDfDbQFIWqwbktA2n0RFg-OjKPryFFaQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"165-200","volume":""},{"id":1109,"author":"王虎; 何辰瑞","title":"近十年《古汉语研究》词汇研究综述","abstract":"就《古汉语研究》中近十年所刊关于词汇研究的文章进行了梳理。依文章类型进行分类，从研究内容与研究方法的角度总结出近十年古汉语词汇研究的特点:研究内容很丰富，研究中运用域外文献，但偏重词义考释。最后提出未来词汇研究的展望:加强词汇系统性研究，扩大词汇的研究方法并充分关注域外文献。","categories":["09_其它"],"year":2022,"publication":"平顶山学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKuYzwvUKNxkr1ABV_Gr0x2WE_zETvxGNOr0rKLles3o2YJfdwZNi8t-CEvRqsRlNzahmihNzLE8TEwyQmtx6PF__gijvrA2jzimR1ohm_4UA8M0PT1sYY5tsvJo92e9NeoUhMKYIleTbwG-lPAdNlmA5EY5klrkUjVVGIQsJIBQd_cjMWkwekL&amp;uniplatform=NZKPT&amp;language=CHS","pages":"36-42","volume":"37"},{"id":1116,"author":"朱凤瀚","title":"甲骨与青铜的王朝","abstract":"二十世纪以来,现代考古学在中国的持续发展与甲骨金文等出土文献的不断发现,为上古史研究提供了新材料,开辟了新视角。朱凤瀚先生是当今学界中国上古史领域最有影响力的学者之一,本书选取了朱凤瀚先生在上述学术背景下从1981年至2020年发表的文章八十余篇,在一定程度上反映了朱先生治学的视野、旨趣、方法和取得的成就。上册、中册综合运用了历史学、古文字学、考古学等学科的理论与方法,分别探讨了商和西周时期的社会结构、政治制度、家族形态、宗教观念、政治地理等方面的问题。","categories":["09_其它"],"year":2022,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJghwLU9BQ4RKPEwSaFwuMyMfRLFtZJMSlqZIwjDmklw8Ld0FZZgnU7mbeoLEyxJMqHZ-rNqfr6EaoWN9OPE1ZeC_pzpWgeJTX4uLqj-3O7-5SCi4PGyfgpZIDzZLT7W0L9uqZefEarq5YdYBa16L-8U_09CFtHdSy21nngHtyiYWpdwxLbnWGM&amp;uniplatform=NZKPT&amp;language=CHS","pages":"160","volume":""},{"id":1121,"author":"谢治; 李立新","title":"造物的转型","abstract":"东周是中国上古社会造物的重要转型历史时期,而这一转型由殷商、西周造物传统的积淀而“涌现”。它源于殷商时期的事“神”,历经西周“宗教伦理”的造物历史沿革。东周造物结构和造物层次的转型,是在造物的内部动态结构与反馈机制的互动中实现中国古代造物的第一次“突破”。春秋早期延续西周时期的造物传统,从而确立了以“神”、“宗教伦理”为前提的造物转型的起点。本文通过对关于东周时期考古资料的深入挖掘及诸子思想的收集、整理与归纳,建构一种关于东周设计生态的历史诠释。通过对考古发掘报告的信息梳理这一历史时期出现转型的关键时间节点,以及从造物设计的角度对器物进行分析、归纳,为东周造物转型的研究提供有力的实物证据,结合造物的外部环境因素对其进行诠释。在东周造物转型的研究中,将自然地理环境、商品经济、社会心理、政治理念等与造物设计密切相关的文献予以重视。在考古资料与文献结合的基础上,并进行实地调查,获得有关东周造物转","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27250/d.cnki.gnjyc.2022.000011","pages":"","volume":""},{"id":1123,"author":"宋松","title":"烟台市博物馆藏青铜器全形拓评析","abstract":"全形拓，又名“全角拓”“器形拓”“立体拓”，是一类将古器物的三维立体效果展现在纸面上的特殊拓片品种，主要以传统墨拓技法为主，同时结合素描、绘画、剪纸等手段。全形拓的传拓对象多是青铜器，也包括陶器、石刻。烟台市博物馆收藏有数万件古籍碑帖，其中有一定数量的青铜器全形拓。本文选取10件尚未发表的清代至民国时期拓本进行评析，对古代青铜器、传拓技艺及拓工的研究具有参考意义。","categories":["09_其它"],"year":2022,"publication":"收藏家","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKKpEEdS0uaJbpaxVbf48ud5KJLIB3yn_8WRH2lDB6g7fMaJ3y7VUtlOl7M6DNCL9lcervw5lV0jZG4WxV1qxUcs2j3YJZEupmGl5JadWt4py0a0UkPLhhpd2uyfp3vE42vq-whqDJtJQ81nabzhv7_h30Z84fdxBH0c5wXg43B999uIHn67H--&amp;uniplatform=NZKPT&amp;language=CHS","pages":"105-110","volume":""},{"id":1135,"author":"黄宇; 毕经纬; 尹夏清","title":"中国青铜器辨伪史","abstract":"青铜器辨伪是青铜器鉴定的重要内容,是青铜器研究的基础性工作,是一门学术性与社会性、理论性与应用性兼备的学问。辨伪 是单个的辨伪主体根据自己树立的的辨伪观念,形成相应的辨伪方法进行辨伪实践,产生辨伪成果的过程,其中辨伪观念是辨伪主体对辨伪总的看法和根本观点,即如何认识辨伪,内容包括辨伪的目的或意义、辨伪应具有的态度、辨伪的范围界定、伪器的类型划分等。辨伪方法是指在辨伪过程中具体可操作的方法,即如何进行辨伪。辨伪 史囊括了各个时代一切辨伪主体的辨伪过程,是一切辨伪观念、辨伪方法、辨伪实践、辨伪成果的总和。青铜器辨伪史自春秋时期齐国辨伪谗鼎开始,千年来各种辨伪主体的辨伪观念、辨伪方法、辨伪实践、辨伪成果需要我们归纳整理,阐释青铜器辨伪史的发展过程。本文 以时间为轴,尝试分析每一时期青铜器辨伪的主体及他们的辨伪观念、辨伪方法、辨伪实践、辨伪成果。以辨伪方法的变革将辨伪史分为两个大的阶段,第一阶段为","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27292/d.cnki.gsxfu.2022.001572","pages":"","volume":""},{"id":1136,"author":"罗彤瑶; 王慧琴","title":"基于图像特征相似性的青铜器铭文辅助释读方法","abstract":"青铜器铭文记录了商周时期经济、政治、文化信息,是珍贵的文史资料。由于铭文字形复杂、笔画繁多且变体差异较大,直接使用传统特征提取算法对铭文的识别精度较低。随着人工智能的发展,深度学习技术异军突起,为古文字的识别工作提供了新思路。本文围绕青铜器铭文图像特征相似性开展研究,以准确释读青铜器铭文为目的,研究基于图像形态特征的隶定铭文深度学习分类方法和基于孪生神经网络的未隶定铭文相似度评估方法,并设计青铜器铭文智能识别系统。主要研究内容概述如下:(1 )针对隶定铭文分类过程中因传统机器学习算法对细节信息提取能力不足导致分类准确率低及过拟合的问题,研究一种基于图像形态特征的隶定铭文深度学习方法。首先,采用形态学算法对铭文进行孔洞填充预处理,降低噪声对铭文形态结构的影响;其次,在各卷积层中加入批量归一化层,抑制过拟合现象;最后,将SURF算子提取到的铭文细节形态特征和卷积神经网络提取的抽象信息进行融合,","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27393/d.cnki.gxazu.2022.001624","pages":"","volume":""},{"id":1139,"author":"董钰欣; 杨存昌","title":"商代青铜鼎美学研究","abstract":"青铜鼎作为青铜器中的典型器物,呈现着中国古代青铜技艺的演进过程,承载着中国古代青铜文化的丰富内蕴。从烹煮之炊具到祭祀之礼器,青铜鼎的地位在商代逐渐崛起,其形式与内涵都产生了相应的变化。从夏铸九鼎到钟鸣鼎食,神圣化、艺术化的商鼎在其中起着关键作用,其技艺之精绝、意味之无穷、历史之厚重都值得我们关注与探索。绪论部分针对选题缘由、研究现状等分别展开了较为详细的介绍,并对研究的对象、思路和方法进行了界定和说明。本文从美学角度对商鼎进行研究,遵循从局部到整体、从形式到内涵、从具体到抽象的原则,以出土实物为参照,结合相关文献记载进行系统深入的分析。基于商代青铜鼎的构成要素和美学研究的逻辑需要,本文主要包括绪论、正文六章和结语三个部分。第一章从政治经济、宗教信仰和科技工艺等层面对商鼎所处的历史背景进行梳理。首先,神权政治的笼罩是青铜鼎得以在商代崛起的主要原因。青铜作为重要的政治资源,青铜武器为政治统治提","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27280/d.cnki.gsdsu.2022.000927","pages":"","volume":""},{"id":1144,"author":"王耀國; 党懷興","title":"吳元滿《六書總要》研究","abstract":"《六書總要》是明代小學學者吳元滿“會合三家爲一,裒集諸說所長”而撰寫的一部六書學專著。自清代以來,學界對其讚揚推舉少,批評否認多,甚至將其完全否定。但事實上,其對六書理論的新看法以及追溯文字形體本原,自覺運用古文字資料考證文字的大膽實踐都對後世產生了深遠影響。研究漢語文字學史,我們應當對《六書總要》作系統深入的研究,還其本來面目,給予其客觀公正的評價。本文分五個章節對《六書總要》進行研究:第一章,概述。本章分爲六節。依次介紹吳元滿的生平及著述,《六書總要》的成書條件、寫作目的、現存的版本、體例,以及收字與字體。第二章,吳元滿漢字起源論及文字分化孳乳系統。第一節,吳元滿的漢字起源論。受前人影響,吳氏認爲文字由聖人所造,雖然這是這一時期的主流觀點,但卻並不符合文字產生的客觀實際。第二節,吳元滿的文字分化孳乳系統。吳氏根據戴侗的子母相生理論,刪減了《說文》中不能生的八十四部,增補了能生的八十四部","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27292/d.cnki.gsxfu.2022.000869","pages":"","volume":""},{"id":1145,"author":"张翠玲; 王洪军","title":"文献载体变迁与先唐书籍形成发展研究","abstract":"书籍是物化了的思维,凝固了的意识,是中国古代文化的主要载体。研究书籍的物质形态,对书籍的形成发展、学术思想的转变都有着重要意义。从书籍整体研究上看,随着新材料的出现,学者跳出传统研究的束缚,利用新方法新视野对书籍制度、装帧、成书、流传等方面展开研究,成果硕硕,著述颇丰。但焦点多聚集在出土文献的内容上,而对文献物质形态即载体本身关注较少。出土文献载体方面又多集中在简牍形制上,简牍形制研究已进入成熟期,对其他文献载体还有待进一步揭示。但在探究载体形制上,多就形制而形制,对于载体所体现的物质力量揭示较少。文献载体的变迁不仅可以反映书籍的形成发展历程,还可以揭示出不同历史时期知识的产生和传播状态,同时也反映了人类文明的发展进程。本文根据文献载体按材质的不同分为硬质载体和软质载体,硬质载体主要以甲骨、金石为主,软质载体主要以简帛、纸张为主。从书籍的物质性角度出发,以已知的出土材料研究先唐文献载体的变","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27064/d.cnki.ghasu.2022.001010","pages":"","volume":""},{"id":1167,"author":"刘美顺子; 殷晓峰","title":"金文对中国当代造型艺术的影响","abstract":"古往今来，任何一种文字创造之际都作用于语言的记录，最初皆以图形、刻画符号等方式，当社会发展到一定状态，开始出现记录语言、交流信息的需要，促使文字系统产生，但从符号至文字系统的发展转变是一个漫长的过程，一般的符号并不强调造型变化及结构中生命力的呈现，而文字与之不同。众所周知的世界古老文字，如埃及圣体书、两河流域的楔形文字、玛雅文字以及中国黄河流域的汉字(甲骨文)等，唯独中国汉字不断发展，沿用至今，其他古老文字分别消失于数千年前。","categories":["09_其它"],"year":2022,"publication":"文艺争鸣","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI4cYlrcO_-H5jdPhStSmXmSuyq-gHDjiWfCUQ0_S_B2kae8pC6cHdp4zTFFLuWL0dtAXOVJ-A1b1mEqXlN6EmxLr8kZEYPekxQybvhBZlyCmZVH549XTM3wiGTRZo18WGik1bbQTaFCvoIDGrkZM1XbZYynxqxvBxfc9s0Ll8kc0AdMJ-wpGme&amp;uniplatform=NZKPT&amp;language=CHS","pages":"192-195","volume":""},{"id":1187,"author":"林賢; 党懷興","title":"形聲學説史研究","abstract":"形聲的應用是漢字發展成熟的標誌。對於形聲研究,歷代學者取得了豐碩的成果。20世紀以來,學術的發展促進了形聲學説史的研究,出版了幾部斷代形聲學説研究論著,但唯獨缺少一部形聲學説通史研究著作。因此,本文通過搜集分析漢代以來的形聲研究成果,藉助史源學、歷史比較等方法梳理形聲學説的發展脈絡,以期總結形聲學説研究的成就、不足,探究其未來的發展方向,進而爲促進相關學術史研究貢獻一點微薄之力。第一章形聲學説史概説。將形聲學説史分爲創立期、探索期、發展期、創新期四個階段,分别概述每一階段的主要研究內容和重要的形聲學説研究文獻。第二章漢代至唐代——形聲學説研究的創立期。主要討論漢代許慎《説文解字》對形聲字的定義、分類、位次、釋名等問題;三國至唐代,形聲研究觀點主要見於歷代筆記、字書韻書、經典注疏中,以晉代衛恆、南朝梁顧野王和唐代賈公彥、李陽冰的研究較有代表性。這一時期處於以形聲字本體研究爲主的階段,理論總結","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27292/d.cnki.gsxfu.2022.000651","pages":"","volume":""},{"id":1194,"author":"孙薇; 成联方","title":"《孙星衍&lt;魏三体石经遗字考&gt;》疏证及遗字逸体补","abstract":"孙星衍《魏三体石经遗字考》一书,是研究宋朝洪适《隶续》卷十四《魏三字石经左传遗字》一书的成果,该成果在“三体石经”研究史上具有重要意义。但是 ,由于时代原因,目前要理解孙星衍《魏三体石经遗字考》一书,其实已经非常困难,为了让该成果得到更广泛的理解和应用,有对其进行“注疏”的必要。孙星 衍《魏三体石经遗字考》中的字例,全部出自洪适的《魏三体石经左传遗字》一文,字形也就难免讹误,而且,遗字的三体常常不全。纠正讹形,对遗字的逸体进行补佚,能为以后更为完整的《魏三体石经》全貌做一些基础工作。文章 主要从以下几个方面着手:第一 部分研究孙星衍的生平事迹和学术成就,是为该论文的背景研究;第二 部研究《魏三体石经遗字考》一书的成书过程、内容、体例、版本等内容,呈现研究对象的全貌;第三 部分研究《魏三体石经遗字考》的价值,呈现这本书的历史意义;第四 部分对此书的遗字进行考勘,并对遗字的逸体进行补佚,这是本","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27456/d.cnki.gyndu.2022.001339","pages":"","volume":""},{"id":1195,"author":"余阔洋; 唐楷之","title":"朱为弼金石之学综论","abstract":"乾嘉道时期,金石学发展兴盛,金文著作不断涌现,彝器之学复兴,藏家辈出,海内士夫闻风承流,相与购致古器,搜集拓本,为清代金石学发展奠定基础。在此期间朱为弼是嘉道时期恒赫一时的学者书家,他集经学、书画、诗文、金石、考据、收藏研究于一身。从朱为弼《蕉声馆全集》中不仅能够看到他丰富的交游阅历,且其中所载诸类文章对于经史亦有裨补之作用,他的金石诗作中的诂考勘定与交游叙事的经历也为我们提供了大量的史料资源,丰富了乾嘉道时期的金石历史文化。除此之外,朱为弼仕途亨通,生平结交了众多师友,他于阮元幕府期间,为阮元分纂《经籍纂诂》,考释《王厚之钟鼎款识》、编撰《积古斋钟鼎彝器款识》等,参与了大量博古赏玩钟鼎彝器,椎摹手拓金石铭文等活动,即使在离幕之后,仍大量结交金石好友。他的每一次金石活动都会与自身金石学力紧密相连,在寓玩于学之中寻找乐趣,可以说是学在其中,思在其中,乐在其中。朱为弼对于金石之学的研究和贡献也","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27456/d.cnki.gyndu.2022.002264","pages":"","volume":""},{"id":1196,"author":"樊凯宁; 钱宗武","title":"王引之《经传释词》虚词系统研究","abstract":"清代高邮王氏家族世代治《书》,王引之自跟从父亲王念孙读《书》之时起即关注《尚书》虚词用法。先以今文《尚书》二十八篇为研究对象,后扩大范围至九经三传及周、秦、两汉之书,遍为搜辑,爬梳整比,以尽其类,再结合时人之说,著成《经传释词》一书。这是汉语虚词研究史上具有里程碑式的重要语法著作。前人对《经传释词》研究虽称丰富,然运用现代汉语虚词理论对其虚词系统进行整体研究鲜有所闻。本文以上海古籍出版社2014年出版的《经传释词》作为研究文本,进行“竭泽而渔”的资料搜集,条分缕析的演绎归纳,以求为汉语语法史研究提供重要的理论参考和实践启发。绪论部分主要介绍王氏家族及王引之生平经历,概括本书创作背景及研究价值,综述学界对《经传释词》的研究现状,简述本文的研究思路及研究方法。正文部分分为上下编:上编对《经传释词》虚词系统进行现代观照。参照周秉钧先生古汉语虚词分类方法,分别对《经传释词》中的虚词及语义类型进行词","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27441/d.cnki.gyzdu.2022.002339","pages":"","volume":""},{"id":1201,"author":"任振宇; 钱耀鹏","title":"两周时期铜戈的制作与使用研究","abstract":"铜戈是两周时期常见的武器,作为两周时期军队主要的装配,其演变过程最的重要原因就是大限度增强自身杀伤功能使之适应战争的需要。本文在梳理总结已有的研究成果基础上,结合考古出土实物和图像、文献资料,进行铜戈范铸的模拟实验和戈柲制作的模拟实验,对两周时期铜戈的制作工艺与使用方法进行探究。在制作工艺的模拟实验中采用范铸法制作铜戈,对其制作铸造工艺进行研究。发现铜戈是采用双合范模范法铸造的,批量生产需要一定条件。此外在戈柲制作的模拟实验中,制作榫孔式戈柲和劈缝式戈柲两种戈柲。通过两种戈柲的制作,并结合出土实物和文献以及使用方式对比,了解到戈头装配方法的改变和金属工具的使用有关。戈柲制作完成后装配戈头进行使用的尝试。通过铜戈的使用尝试并结合考古发现、文献资料,分析其使用方法,发现铜戈用法以击为主包括劈啄和劈斩,勾割在步兵中应用较少,主要是车兵在使用。最后,对戈的起源与消失的问题进行讨论。认为戈起源于石斧","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27405/d.cnki.gxbdu.2022.000276","pages":"","volume":""},{"id":1209,"author":"李喬羽; 党懷興","title":"吳善述《六書約言》研究","abstract":"清代是中國傳統文字學研究全面發展的黃金時期。“六書”學研究在這一時期也臻於極盛,鴻儒(5出,巨著矗立,爲現代語言文字學的建立奠定了堅實的基礎。近代以來,學者們對清代“六書”學著作的研究已經取得豐碩的成果,但也有部分著作尚未被重視,如本文的研究對象——吳善述《六書約言》。因此,本文在系統研究全書的基礎上,總結《六書約言》所反映的文字學理論,客觀評價其成就和不足,從而在學術史上對其作出一個較爲準確的定位。吳善述的《六書約言》成書於晚清時期,該書集中體現了吳氏的文字學思想,並在一定程度上豐富了清代的文字學理論。但自其刊行以來,並未受到學界的關注。雖然有少數學者或對吳氏說解進行分析,或對《六書約言》作出主旨性的評述,但也只是寥寥數語,浮泛不深。目前,尚未有學者在文字學方面對其進行專題研究。因此,本論文採取文獻分析法、歸納法、比較法等研究方法對《六書約言》進行探究。論文的內容主要有二:第一部分,研究","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27292/d.cnki.gsxfu.2022.001043","pages":"","volume":""},{"id":1224,"author":"苏荣誉","title":"特殊角形兽面和牺首装饰的青铜器探论——兼论提梁华丽型的青铜卣","abstract":"在人类早期青铜艺术中,古代中原青铜器的风格卓尔不群,突出表现在造型的怪异和装饰的独特。虽然装饰可以分为加到器物上的附饰和器物表面的纹饰,但二者往往构成同一个装饰单元,在这一方面动物形装饰尤为突出。一些哺乳动物头部表皮及真皮特化会形成角。表皮产生角质角,如牛、羊的角质鞘和犀的表皮角,真皮形成如鹿的骨质角。动物学通常将角分为牛科特有的洞角、","categories":["09_其它"],"year":2022,"publication":"考古学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ5YpeFGCi1NAYBEOtMQJtNeKrQTQnIVW4SvNScu806vcRzJkSP_wZL2WeJIZkUbSREf8_mctNSlagBKxUrC2v97eKcuoWA8rSG9yFFua4Ea8s32X9hIpaFqLfvekGlCxgiPLo0Mjr1OvyrmsNEbcOPw-Pzg_CQF8SRN5hcoLbuRA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"369-416","volume":""},{"id":1244,"author":"牟金梅; 杨怀源","title":"徐中舒先生文字學研究","abstract":"徐中舒先生是傑出的古文字學家和歷史學家,在文字學界產生了深遠的影響,對其學術成就的研究具有重要意義。本文廣泛收集了徐中舒先生留下的一百餘種論著,對其進行了全面閱讀和歸類,從中提取了屬於文字學研究的四十多種代表性著作。然後對這部分文字研究的成果進行了系統分析和整理,以此為依據總結了徐中舒先生文字研究的特點,並從學術史的角度理性評價了其文字研究做出的貢獻。全文 共分為六大部分:第一 部分為“緒論”。首先介紹了徐中舒先生的生平、學術成就以及人才培養三個方面的内容;其次介紹了國内的研究現狀;再次介紹了本文的研究内容和研究方法;最後對本文的研究目的和研究意義進行了說明。第二 部分為“徐中舒先生文字研究的成果”,是本文的基礎材料,共有44種。從形式上將其分為兩節:第一節是文字研究論文,一共43篇,從研究内容上可以分為三類,第一類是“古文字和古史互證”,共28篇,第二類是“器物銘文考釋”,共10篇,第三","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27684/d.cnki.gxndx.2022.005499","pages":"","volume":""},{"id":1247,"author":"银睿; 蔡梦麒","title":"吳元滿六書理論研究","abstract":"明代吳元滿著《六書總要》《六書正義》等研究“六書”理論之書,繼承前人理論,廣匯各家學說,並在此基礎上創新提出極具特色的六書理論,於“六書”之下詳細劃分小類,收字分類也與現代構字理論具有相似之處。但學界較少關注其著書,歷代學者對吳氏評價也較有失公允,尤其是清代人對其多持批判態度。因此論文將運用對比分析法,以吳元滿《六書總要》為主,輔以《六書正義》一書,與《說文解字》《說文解字注》《說文繫傳》《文字蒙求》《字源》等書製作對比表格,並進行關於六書分類的對比分析,以此研究吳元滿六書觀的進步與不足之處,力求給予其一個公正評價。全文共分六章:第一 章為緒論部分。首先,綜述近二十年來的六書理論研究。包括以下內容:其一是概述六書理論自產生以來至吳元滿成書期間的重要發展階段;其二是關於“六書”近二十年的研究動態,主要分為對六書理論、六書分類、字書中六書研究三個部分。其次,綜述吳元滿生平及其著書,總結前人對其","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27137/d.cnki.ghusu.2022.002818","pages":"","volume":""},{"id":1283,"author":"张韬","title":"毛公鼎价值摭谈","abstract":"中国传统文化史，由汉字萌芽、发轫、演变构成层累结构，两条脉络清晰可见：1.直线结构，以篆、隶、楷、行、草五种书体发展先后秩序为特征的直线线性结构，逻辑规律清晰可见。2.螺旋结构，以五种书体不同字构形态互相渗透、作用、同步发展为特征的圆形曲线线性结构，逻辑秩序呈复合状。比如篆书书体殷商甲骨文、商周金文，小篆与石鼓文同步发展特征。","categories":["09_其它"],"year":2022,"publication":"中国民族博览","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLoaKa7-kGslHoJQRztxKfyxu8vLxZALnRSD-tq5vzlk_KAUZ4v9HHWjXvX4At1CpWz6Ithwda3TpTx69xThyVgAoIO0ZSpcf4NAC21RC0oh1N9jCu6SU8vhxHrSpvozvHxSVHApjh1hIN9PWG321xwv5rAAlpCjNv2KXd_oMgiFLdOr0ZOoUWc&amp;uniplatform=NZKPT&amp;language=CHS","pages":"35-38","volume":""},{"id":1293,"author":"苏荣誉","title":"晚商作册般青铜鼋的工艺及相关问题","abstract":"国家博物馆收藏的作册般青铜鼋是一件造型特别、铭文多歧见的晚商青铜器，曾引起学界对其真伪及诸多问题的持久讨论。事实上，另有一件与之成对的青铜鼋散落台湾，通过对两器的比较分析，特别是借助X光成像，明确了该器的铸造工艺，具有若干商代南方风格青铜器的工艺因素，应该出自南方迁殷墟铸工传人之手。其工艺渊源清晰，确非伪作，为技术辩伪一实例。此外，文章还对两件青铜鼋的作器者、作器目的以及商代青铜俏生器略作引申讨论。","categories":["09_其它"],"year":2022,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI4K4M51KR9HxiaVtLpzU7J8Gt4fTPg8LMFOpll54WJV1YhMTJ5fcCw-kCFuuuEufltf9Zm6zP6VQTmTJhtooj0wPY5YmjriBxeRpeSpIvu1DyZdF8cNOvyPlNg1dL4OzibUZTmZZro959zq3_U6U0HlhCBL2_EHahwMEiZ7tZHaqfBPmmqcHRA&amp;uniplatform=NZKPT&amp;language=CHS","pages":"106-112","volume":""},{"id":1301,"author":"陶淑慧","title":"薛尚功《历代钟鼎彝器款识法帖》对清代嘉道时期金文书法之影响","abstract":"宋代古器物学勃兴,当时涌现了很多辑录商周古器铭文的相关书籍,然在这些刻书中,如论辑录古器铭文之精且博,当数南宋薛尚功的《历代钟鼎彝器款识法帖》。此书更成为清代嘉道时期书家学习金文书法的重要取法来源,可以说此书对嘉道时期金文书法的兴起也起着重要作用。目前学界对于此书的讨论,不是针对版本的梳理鉴别,就是对书中器物的年代、铭文、真伪等方面的个别考订,罕有关注此书与书法艺术之间的关系。故本文通过梳理此书的版本、嘉道时期对此书的评价,以及嘉道时期金文书家对此书的取法,从而揭示此书对嘉道时期金文书法的重要影响,并进一步指出当时书家更倾向取法此书的哪一版本,以及哪些书家更喜欢取法此书。","categories":["09_其它"],"year":2022,"publication":"西泠艺丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLxmJ7R730Up08dTfhe2Q1gfj38QCle_j7aFS9RG2hksft1oMwHcn7-_GuMt7Hk7UUd72mGPJPmw4t6dhqDKuKl9IoXYdbQnBuCAKpW6OSRcRGPmQMwhv1dOM0vl-eSOo14T9jwsUVvWKL2c5UYvACovEaZaQVWoD943Q8g7TanSEy-wVVZINZs&amp;uniplatform=NZKPT&amp;language=CHS","pages":"44-56","volume":""},{"id":1307,"author":"王鹏","title":"先秦“图案文字”与“鸟虫书”金文装饰特征比较研究","abstract":"先秦装饰文字是我国古代文字书体的重要构成部分。&quot;图案文字&quot;和&quot;鸟虫书&quot;金文是先秦时期装饰文字的代表,中国古代装饰文字正是发源于此。通过比较研究法分析了&quot;图案文字&quot;与&quot;鸟虫书&quot;金文在装饰特征方面的差异和关联,这对先秦金文字体的深入研究以及我国古代装饰文字的体系化研究具有一定的理论意义。","categories":["09_其它"],"year":2022,"publication":"天工","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL8U-jmj2xo_MNyMmcjnBowuTr42bxvlkEngQK-x5XrnvDARY_BUUrNGUTdbpJT1f1UV-csHFC-waXoqf3_FLjvuFH_LMV0vQRfzvXXdPBFoYntVJpl5z6WIYA2ZteMjGBBahQBAoJVhb0uGLCVwS-mEO5r3HREbNZj45SyP68MCY8foDZuBrhx&amp;uniplatform=NZKPT&amp;language=CHS","pages":"28-31","volume":""},{"id":1312,"author":"邓晨钰","title":"玩古与复古——&quot;文王鼎&quot;在清代的多重角色","abstract":"文王鼎,或称文王方鼎。因铭为&quot;鲁公作文王尊彝&quot;而得名,此处之文王即是西周文王。据《宋史·哲宗本纪》记载,元符二年（1099）九月,果州团练使仲忽进献了一件带有该铭的古方鼎1。这应是文王鼎初次见诸典籍。随后在徽宗朝编纂的《重修宣和博古图》中,文王鼎位列周鼎之首,并称它&quot;奇古可爱,足以冠周器&quot;2（图1）。由图可知,它是一件扁足方鼎,立耳、方唇,口、腹作长方形,腹壁斜直,平底,扁足作夔形,足底上卷,纹饰以兽面纹为主,","categories":["09_其它"],"year":2022,"publication":"收藏家","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLjn0slZ7VjeYLabmhmqqgypLcI_Myw-mUGe_rVG3eYLQzLVlQU1aFM1uA2H_NnjJyX8-2Y4FZo7wSeK4HQzxN7AvRri2C97Df2ueLp1rEO5wIveJ9_OJtfiMp4X8fjaRG1DWzpgOQ-bsSCgnajZ2clrX_5iyfbkimGrwbi-V8FCppOmHZPRcfh&amp;uniplatform=NZKPT&amp;language=CHS","pages":"41-48","volume":""},{"id":1317,"author":"赫俊红","title":"陈介祺藏钟及对潘祖荫邰钟的考释","abstract":"后世学人盛赞的金石学家和鉴藏家陈介祺（1813～1884）,历晚清嘉庆至光绪五朝,毕生倾心于金石的藏鉴、研考和传承。早年因得春秋曾伯■簠（图一）而名其居为&quot;宝簠斋&quot;,后以&quot;簠斋&quot;之号行世。簠斋的金石收藏类目,从他晚年61岁即同治十二年（1873）手书的一份在售拓本类目及价格的《传古小启》[1]（图二）中可窥知大概,包括:吉金彝器约一百五十余种、钟十种、泉笵百余种、三代秦汉六朝古铜器小品及铜造像百余种、汉镜百余种、汉瓦百余种、汉魏六朝砖百余种、","categories":["09_其它"],"year":2022,"publication":"文物天地","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKh5RecIz0bHKAt4V2V8G9bcBT7e7Qx5MBVY9KMDPWBWeVruMmHEO1_8YtSdR39ssXw7PDtJOp8_i-gJLn1N33DaoUSnSUkEmcgkQrfYjhFwJwF0_B2ufy0FJeJ3LdG54F5yug53L95-ZWbW0pkRTcrDJ2A8WiGFY9dIq65T8HPI9JnZF_fYQ41&amp;uniplatform=NZKPT&amp;language=CHS","pages":"97-107","volume":""},{"id":1442,"author":"刘文腾; 王慧琴; 王可; 王展","title":"基于拓扑与网格双特征的铭文图形识别方法","abstract":"青铜器铭文图像有效特征的提取是进行铭文识别的关键步骤，针对以图像为信息载体的铭文特征提取方法由于特征维度高、特征向量复杂而识别准确度低的问题，提出了一种基于拓扑与网格双特征的铭文图形集成学习识别方法。以图形为铭文特征的表征，所提方法提取拓扑特征和7维文字结构图形特征，有效描述了铭文文字的结构信息。在此基础上，所提方法利用降维后铭文全局结构信息和局部结构信息的8维4方向弹性网格特征，解决了提取铭文图像特征导致的特征向量维度高的问题。最后，以拓扑特征和弹性网格特征作为集成学习样本的特征向量，利用Bagging方法对特征向量敏感程度不同的机器学习分类器进行集成，提升模型训练效率、提高识别精度。实验结果表明，与图像特征提取方法相比，所提方法对铭文识别准确率提高了15.54个百分点，并且铭文特征向量维度及运行时间大幅度降低。","categories":["09_其它"],"year":2022,"publication":"激光与光电子学进展","link":"https://link.cnki.net/urlid/31.1690.TN.20210716.1730.070","pages":"229-239","volume":"59"},{"id":2572,"author":"吴炫奇; 陈优广","title":"基于深度学习的商周金文文字识别研究","abstract":"金文,是中国古代商周时期用于记录的主要书体。研究商周金文,对了解古代历史、考察古代社会生活等均具有重大意义。识别商周金文文字是基础性的工作,但目前其仍需由经验丰富的古文字专家费时费力地完成。随着现代计算机图像识别技术的成熟,特别是深度学习技术的发展,计算机实现文字识别的方法取得了巨大的进步,现今已可获得良好的识别结果。基于以上背景与需求,本文旨在使用深度学习相关技术,对商周金文文字识别任务进行研究。本文的主要工作有:(1)归纳整理出一个格式统一完整的商周金文数据集,并对该数据集进行数据增强。使用平移、旋转等仿射变换方法和弹性变换方法扩充该数据集;使用3D建模软件Rhino进行二次开发,为数据集引入模拟的光照效果;使用隐式语义数据增强(ISDA)方法进一步实现数据增强,帮助模型获得更强的泛化能力。(2)研究了基于注意力机制的商周金文文字识别方法。本文探索、研究使用神经网络实现对商周金文文字的","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27149/d.cnki.ghdsu.2022.000453","pages":"","volume":""},{"id":2573,"author":"匡博; 陈优广","title":"古文字拓片的目标检测算法研究","abstract":"古文字是历史研究的重要材料,一般依附的载体是铭器或石碑,经过处理形成拓片。研究古文字首先进行的是费时费力的古文字标注工作,本文将深度学习引入这一过程,实现古文字自动化检测。本文主要在商周金文拓片和魏晋南北朝石刻字拓片上研究古文字检测问题。通过对古文字拓片数据集的分析,发现检测过程中存在拓片背景复杂、文字分布不规律、小文字密集以及重叠检测等一系列问题。与现代文本检测不同,本文将古文字检测问题看作是目标检测问题。本文的主要工作如下:一种用于古文字拓片检测的新型检测网络结合古文字拓片数据集的特点,基于Dark Net-53网络改进的特征提取网络具有更强的特征提取能力。基于现有网络Bi FPN(Bi-Directional Feature Pyramid Network)、PANet(Path Aggregation Network),提出的重复特征金字塔网络dual-FPN(dual Featu","categories":["09_其它"],"year":2022,"publication":"","link":"https://link.cnki.net/doi/10.27149/d.cnki.ghdsu.2022.000464","pages":"","volume":""},{"id":1344,"author":"李琦","title":"清代著録邾眉父壺與鄭義羌父匜銘文試述","abstract":"在金文研究的學術史中,清代可謂繼宋代之後的第二個高峰,其中一個比較突出的表現就是清代著録的金文數量遠遠超過宋代。《殷周金文集成》作爲目前學界經常使用的銘文著録書籍,除當時所見的出土材料外,還收録了許多傳世青銅器銘文的拓本或摹本。另外,《殷周金文集成》對傳世銅器銘文真僞的鑒别十分精審,所録僞銘極少,體現了編纂者謹慎的態度以及高超的辨别能力。然而,一些銅器的銘文或僅見摹本,或剥蝕殘泐,或寫法怪異,往往會被誤判作僞銘。趙文傑就曾對《殷周金文集成》收録拓本材料時的取捨態度評價云:","categories":["09_其它"],"year":2021,"publication":"出土文献研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJW43VN6lLQqJaVjjIN7CWOHO6n-LZNkn_ywGPPf2--evKosGXiZJAbuf5aYg7G3Xgh2nZ7OMMKKrgIsKedJyPxm64RbKmNmF9P4urErcW7tWTIt2i2MdeV0qGUG4mxOtmx-lwbtkaq9X2klABOA_0-Gvx20GUkb88s7MOn36rx8w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72-79","volume":""},{"id":1365,"author":"侯文佳","title":"《周道荡荡——丛文俊临述西周金文二十四品》编辑手记","abstract":"《周道荡荡—丛文俊临述西周金文二十四品》一书缘起于三年前，荣宝斋《艺术品》期刊主编王登科和主任唐昆拜访作者丛文俊，便有了“吉金夜话”专题，后又更名为“吉金丛谈”，成就了二十四篇沉甸甸的金文宏论。丛先生在本书的后记中这样写道：“在《艺术品》月刊连载的选题，使平日自适自足的临帖开始有了比较严肃的学术意义。”去年伊始，征得丛先生同意，荣宝斋出版社将这份连载集结付梓。章太炎说：“文字和语言本身就是历史。”殷墟甲骨、商周青铜、燕齐陶文、两汉画像、六朝墓志，蔚为大观。然岁月沧桑，风雨剥泐，金石难寿，反托石墨相传，","categories":["09_其它"],"year":2021,"publication":"艺术品","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKpefMczqid42q2cH49GFmnd0fL18VEZb_Qs8sSKJL3PQIuCeHZiDLs-YTt71m55k3SKggjFh2Zjj8Y0NSPOCDL7QvS5TX0up-tJbSAPFR6hpmcvna1lZuejZdKejXxAcrp0UUcL-arbN6KpAiR-wxGgCE-6cd0AFifY19IMxsrtayG0rtqZBIm&amp;uniplatform=NZKPT&amp;language=CHS","pages":"118","volume":""},{"id":1367,"author":"田飞; 吴虹宏","title":"商周“青铜器”的功用分类和金文文化内涵","abstract":"金文是指铸刻在商周青铜器上的铭文,其字形比较规范、粗细均匀,符合商周时期&quot;藏礼于器&quot;的礼仪文化特点,被奴隶主贵族用于记录当时祭典、征伐、赐命、契约等事件。在一定程度上反映了当时的经济、政治、文化、礼仪、风俗等。&quot;国之大事,在祀与戎&quot;,青铜器在当时主要作为礼器使用,本质上体现了奴隶社会的宗法制度,是研究中国古代奴隶社会结构不可或缺的重要实物资料,对研究商周社会历史和人类文化史有着重要的意义。在金文中存在着一定数量有关于青铜器的文字,该文通过对这些文字的探究来解读其功用,并进一步解读其文化内涵。","categories":["09_其它"],"year":2021,"publication":"文化创新比较研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKGw5QfrvBxx7ptUW2APLm9PmtnibNJOeUzQqKW0Vu2pS9LTjlfraRApfNw_OrK10FgM-iYavtafcIJk4Wc8OR_Hy86VC1OR-n2SC2gHRYGROexz-xNUYUXrjcbOjk_uucdXcPDIPy3R_snZQeQrIq5RpLxbnaTAriI3kWbyGA1J93QeO5riHVW&amp;uniplatform=NZKPT&amp;language=CHS","pages":"107-110","volume":"5"},{"id":1368,"author":"易华","title":"周人尚赤综考","abstract":"叶舒宪尝试从玉文化解释《礼记》所述夏人尚黑、殷人尚白、周人尚赤,用琼玉即红玛瑙流行解说周人尚赤说。考古发掘与研究表明周代红玛瑙流行只是周人尚赤物证之一方面,与此密切相关的另外两个方面是朱砂和红漆广泛应用。丹书、彤弓是周人尚赤证据;玄衮赤舄、骍马彤车亦是周人尚赤体现。周人不仅能分辨黑、白、赤、青、黄五正色,还认识到了间色。&quot;周人尚赤&quot;贯彻了周代贵族一生,体现在许多方面。夏朝流行黑色,殷商流行白色,周朝流行红色,其后三色并行红色更加突出。周人尚赤,前有羌后有楚,汉人继承了尚赤传统,发展成了中国红。","categories":["09_其它"],"year":2021,"publication":"百色学院学报","link":"https://link.cnki.net/doi/10.16726/j.cnki.bsxb.2021.06.001","pages":"46035","volume":"34"},{"id":1377,"author":"岳洪彬; 王祁","title":"晚商和西周早期兽面纹大圆鼎研究","abstract":"晚商时期的兽面纹大圆鼎,不仅形体硕大,花纹特征明显,在墓葬中的出土位置特殊,且只出一件,在当时社会生活和丧葬礼仪活动中,应扮演着非常重要的角色。西周早期兽面纹大圆鼎也较多见,使用规制延用殷礼。此类兽面纹大圆鼎多自名为■。据此判断,此类大圆鼎应为蒸煮牲体之器,与东周时期高级贵族墓中的特大型圆鼎有着渊源关系,应具有相同的功能和称名。","categories":["09_其它"],"year":2021,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI7gXQuNVpvJT9NylVfDMR9JY7DQV0UvaZpSK_BUINuXLXUtYrw0Z0nvYq_jX8EM8NVj_I6Sw6YpmvzyGnNM0GrC4AzvIhHoKa3X3OrbqrS19g5bKoXjt1aP_I7eitb8dtnJcevdmv8cGZZQd0yAAkFGf-aRhAc2uMGVjk8Sd_-H-h--2ixxU7h&amp;uniplatform=NZKPT&amp;language=CHS","pages":"82-90","volume":""},{"id":1392,"author":"李霏","title":"《敬吾心室钟鼎款识》稿本析论兼及《积古斋钟鼎彝器款识》续编诸问题","abstract":"《敬吾心室钟鼎款识》稿本,六册,清道光年间朱善旂编集,现藏于上海图书馆。书高39厘米,宽25.8厘米,封题&quot;敬吾心室钟鼎款识&quot;,金镶玉装。据朱善旂自书题识,此稿本为道光年间续编《积古斋钟鼎彝器款识》产生的两部底稿之一,另一部经龚自珍、陈庆镛、吴荣光先后编纂,道光二十二年(1842)由吴荣光在粤刊刻为《筠清馆金石文字》(以下简称《筠清》)。稿本对于厘清《积古斋钟鼎彝器款识》续编史实及相关文本、《筠清》编纂过程,提供了一手文献和研究线索。","categories":["09_其它"],"year":2021,"publication":"新美术","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLJEP7XvMzatLjuOlLnt1Ch46RPgaaZpJDISp5hX00LsRmPBLXLI2C0GqpAa2OpQLEGZENatZbfaJoH0NJiFReXyVeFLT5zxnDCA6s2z2A5DWV3B379hYi8b6JQYtDzIAoIjOvLn6E_6OMMMXZ5AEoOvkbzakwaPAJR5I2BP_y6nK6L5f72x7NI&amp;uniplatform=NZKPT&amp;language=CHS","pages":"86-101","volume":"42"},{"id":1406,"author":"石安瑞; 王翔宇","title":"铸铭之前的书写：论西周青铜器铭文制作使用的写本","abstract":"近年来,战国秦汉简牍研究已成为热潮。相比之下,战国以前的写本由于出土材料的阙失,其使用情况不甚明朗。本文根据西周铜器铭文的布局特征及特殊现象,对铜器铭文制作过程中使用易腐材质制作的写本的痕迹进行了探讨,并对其物理性质及在铭文制作过程中的具体作用进行了复原。基于分析,本文指出在铜器铭文制作过程中使用了两种不同的写本:一种是用于校对的&quot;底本&quot;,另一种是用于铭文实际制作的&quot;蓝本&quot;。制作一套同铭器时(包括不同器类的器物),工匠们会轮流使用同一份蓝本。不少铭文在起草过程中已对铭文字数、文字布局进行了细心设计。因此,每一篇铭文的释读工作应该从考察铭文的视觉特征入手。此外,本文为泥条堆塑法在铭文制作过程中的应用提供了明证,复原了西周晚期铜器铭文制作的全部流程。再者,本文还涉及西周时期铜器作坊中工匠的读写能力、劳动分工以及西周时期青铜铭刻的展示功能等问题。","categories":["09_其它"],"year":2021,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLyzweERX-muVnyi-QiGX-EbWVOTGXz_HCbj4W-QKe5ZaXFkmmIDxeHS_w6o6_u9KiifrnEtZg3EWZs1YmNe-XVTZH6sUJU4cSlbuVcKOtk2sS3qOP_jeabST_ytLVH0PYezd7o2bC2Tv_Y1rbNUkDvMBmDQz_ZUQ0UKvD2ifsc8SjFKL9o0yWj&amp;uniplatform=NZKPT&amp;language=CHS","pages":"125-153, 158","volume":""},{"id":1412,"author":"李运富; 王立军; 齐元涛; 何余华; 黄德宽","title":"汉字学研究现状与展望","abstract":"&quot;十三五&quot;期间,汉字学研究在理论和方法上都取得长足进步,尤其是汉字职用研究得到重视和发展;在研究材料和研究视角上也更加多元化;汉字发展史和汉字学史也有新的拓展;特别是古文字学研究由冷门变热门,不仅得到中央领导的重视,召开了甲骨文发现120周年纪念座谈会,在学术研究方面,如出土文献整理、疑难字考释、数字化和智能化等领域也都取得了可喜的成果。&quot;十四五&quot;期间,汉字学研究在既有成果基础上,将在材料的普查、整合、著录方面形成国家级文化工程,更加注重理论方法体系性建设,特别是要深入开展汉字与汉语关系的动态研究,开展古文字考释成果的覆验研究,提炼出古文字考释方法并加以理论建构,还要将汉字文化价值的推广应用落到实处,&quot;为推动中华文明发展和人类社会进步作出新的更大的贡献&quot;。","categories":["09_其它"],"year":2021,"publication":"语言科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJMeLLUqjdigXhfgX6dinyObn9PDrRxjemA9ztQSZxpkVw6VL7gY8Y_UF-ph9VzexUuPQhuzutfpOhB4WwgbwJgD0CTxbmzV9iZE_QSLCA1x9SgellVS7KnTx9s0V6-FrWLP7zGwWB2U1SfP1Qc7sn0HaUdeGt-EsaGP8kdXJp22aD3_mm-HmQ8&amp;uniplatform=NZKPT&amp;language=CHS","pages":"450-473","volume":"20"},{"id":1424,"author":"王义娟","title":"“法”字的美学范畴与流变研究","abstract":"&quot;法&quot;字之美,美在结构,美在意蕴,文字中蕴养了中华民族的审美与思想,是中华民族内聚力的体现。法的起源与字形变化体现了我国文字变迁过程中由繁到简、由具体到抽象的复杂变化规律,法的语义的丰富与扩展,有其在中国传统文化演进过程中的独特性和深刻性,法的语义实现了早期古法的涵义到现代法的涵义的转变,不仅是中国古代的法制思想的变化过程的体现,同时也是中国古代法制文化风格美学的形成过程的体现。","categories":["09_其它"],"year":2021,"publication":"汉字文化","link":"https://link.cnki.net/doi/10.14014/j.cnki.cn11-2597/g2.2021.16.078","pages":"171-172","volume":""},{"id":1428,"author":"陈絜","title":"2020年先秦史研究述评","abstract":"2020年的先秦史研究特点鲜明,热点比较集中,多围绕重大问题及考古新材料而展开讨论,尤以夏文化探索、两周封国研究、地理交通与族群交流等问题的精细探索引人瞩目。今从九个方面择要介绍如下。","categories":["09_其它"],"year":2021,"publication":"中国史研究动态","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKFMvvnf8kOB8zXc_pdnXqEKDt9As5F-qwGJOvHwVULkpk3RwSalVvUtCbzHWNSgyubJqRc8x-NkaiNhxKWlNnGSZ9jsEiMOUCaVAkt67ogOqYnz7mAJ0RcXNrnizF7kwxfJ-pzRROi0yVSEBWI-VFVdOmeZ9Fh61ga3mCOk1v9MC99F0EKpV6y&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46156","volume":""},{"id":1450,"author":"邢建丽","title":"王子午鼎的工艺创作价值研究","abstract":"青铜器的工艺创作是一个完整系统的过程,多数器物的铸造、造型、纹饰、铭文四位一体,紧密结合,构成青铜艺术独特的美。王子午鼎鼎形高大,器型形式感较强,铸造工艺精湛、高超,造型雄伟、凝重,纹饰精细、新巧,铭文书体整齐、优雅,突出地表现了春秋时期的青铜工艺水平和审美趣味。精美绝伦的王子午鼎,在当代仍具有较大的工艺创作研究价值。","categories":["09_其它"],"year":2021,"publication":"大庆师范学院学报","link":"https://link.cnki.net/doi/10.13356/j.cnki.jdnu.2095-0063.2021.04.011","pages":"89-96","volume":"41"},{"id":1457,"author":"徐发","title":"考据之风与晚清印谱的编纂——以陈介祺金石圈为中心的考察","abstract":"清代考据学的兴盛促进了金石学的发展,以金石证史蔚成风尚,而此时期金石学家的印谱编纂也反映了这种考据之风的影响。本文通过以陈介祺为中心的金石圈诸友的印谱编纂考察,指出陈介祺在编选《十钟山房印举》中,屡屡致函金石诸友搜寻瞿中溶《集古官印考证》一书,欲参考其书对《印举》加以释例。正是由于陈介祺对瞿书的推崇,其金石圈诸友如吴云、吴大澂、吴重憙、孙文楷、高庆龄、郭裕之的印谱编纂,无论在考据思想还是编纂体例上,都受瞿书影响,且这种影响一直持续到民国初年,几乎囊括了晚清考据印学著作的全部。而此时期印谱编纂中将印章与经传史籍相互参证,考察印章的职官、地理、文字,补史籍之缺漏,不仅成为此一时期印谱编纂的主要特征,也是此时金石考据风气在印谱编纂中的具体体现。","categories":["09_其它"],"year":2021,"publication":"西泠艺丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKrYIWaW6-QaGaoTyW1_QAO6eLY0EP01cNUvF9SQtJnr5dVTQJmb6Y1siQ6E_iJAd_2wx_yvSxFvvSE9fdIg46Zjmu4fXF0GcO6vZEDG7Tt4Uu97p9ElPwIP7kQavIpb1zYuExDXQZdnJ4bo9AcMOfZxEmAO6bGGTaU0uI2Woo-YfeHKoO9mK5f&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-75","volume":""},{"id":1473,"author":"张凯","title":"试论铭文中反书、倒书等特殊书写形式的形成原因","abstract":"针对铭文中出现的反书、倒书等特殊形式的书写现象,本工作采用泥条贴范法,从铭文制作的工艺角度对反书和倒书进行了讨论,并搭建了一套以树叶刻字为基础的推论模型,通过模拟实验进一步地阐述了在此模型下反书和倒书的产生的可能性及原因。","categories":["09_其它"],"year":2021,"publication":"文物保护与考古科学","link":"https://link.cnki.net/doi/10.16334/j.cnki.cn31-1652/k.20200201664","pages":"127-131","volume":"33"},{"id":1482,"author":"王望峰","title":"制名以指实：先秦造物的语言符号学之思维","abstract":"作为符号的语言不但是交流的手段,也是思维的工具,因此可以从语言符号学的角度探讨造物的观念思维。先秦时期对造物的制名指称表现出显著的语言符号学特征,&quot;制名指实&quot;的现象构建了文字和词语两个层次的符号系统。带有理据性的文字符名以不同的构成形式对形态、功能、材料、工艺、类属等造物静态的属性要素进行指称,而词语符名也通过其三类不同的构成形式折射出了造物内涵的意识变化。文字和词语两个符号系统能够从不同层面揭示先秦造物所蕴藏的某些观念趋向,也展现了语言符号对这一时期造物研究所具有的特别的方法和意义。","categories":["09_其它"],"year":2021,"publication":"山东工艺美术学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iINODDMxCO6ohA7D_oCftCgdQv0NbLsQyXEKTMGZZmgUQ7MXd_cbUK38-aOstjxYRt3E83b7oR0jOXKcgbMr6WKiSgGITyhtFbx3lOV9LrXUbQbhpxYIs4yEFqfrRabPLRU3FVqTsXAgVJmojCH3VgqWeOdILPwA_NVrNl44FJ4xZpl2HG56iJg&amp;uniplatform=NZKPT&amp;language=CHS","pages":"76-82","volume":""},{"id":1486,"author":"曹雨楊","title":"戰國楚、晋、秦系墨迹筆法的上承下延——兼談先秦毛筆墨迹與金石文字之差异與成因","abstract":"戰國時期楚系、晋系、秦系墨迹書寫筆法上承殷商西周毛筆書寫筆法演變而來,楚、晋系基本是原貌繼承,幾乎未發生變化,秦系則在書寫技巧上發生了變化。同時,先秦時期金石銘文筆畫形態與毛筆墨迹不同,這主要是由于早期銅器銘文&quot;泥條法&quot;的鑄造方式,後來的金石銘文繼承了這種筆畫形態。秦系小篆是繼承了金石銘文筆畫形態和文字結構演變而來的,并非當時日常毛筆書寫文字。","categories":["09_其它"],"year":2021,"publication":"书法研究","link":"https://link.cnki.net/doi/10.19489/j.cnki.1000-6044.2021.02.007","pages":"103-120","volume":""},{"id":1493,"author":"杨锁强; 王培圆","title":"周原金文与周文化","abstract":"《诗经·绵》云:&quot;绵绵瓜瓞。民之初生,自土沮漆。古公亶父,陶复陶穴,未有家室。古公亶父,来朝走马。率西水浒,至于岐下。爰及姜女,聿来胥宇。周原膴膴,堇荼如饴。爰始爰谋,爰契我龟,曰止曰时,筑室于兹。乃慰乃止,乃左乃右,乃疆乃理,乃宣乃亩。自西徂东,周爰执事。乃召司空,乃召司徒,俾立室家。其绳则直,缩版以载,作庙翼翼……&quot;《诗经·绵》中所记述的周原乃周文化的发祥地。据《史记·刘敬列传》记载,汉初刘敬上言高祖:&quot;周之先自后稷,尧封之邰,","categories":["09_其它"],"year":2021,"publication":"中国书画","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIPdKFTWH5pRvNUplC2tdeYCFWih6vK1mZDpdCi_0_cb6Tqs1cHEypvUNnWBR-iP6U_sLa24D4PBUEg-SHJNtQU4ARR0g_wJGkkLzKqN-6kFj8RQP51LxpPKd8QC7Ps3-MCHHIirndms69fzGszy3mDTlPLjzOL6KAaVYOeHw5TQrlOiK2y9V-a&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-25","volume":""},{"id":1497,"author":"暨慧琳","title":"出土材料与传世典籍所见“四海九州之美物”合证举隅","abstract":"裘锡圭先生指出,地下材料在整理先秦秦汉古籍工作中有重要作用,整理年代久远的传世古籍的时候,应该尽量利用各种地下材料,其中既包括各种古文字材料,也包括文字之外的各种有关考古资料(1)。中国历史悠久,物产丰富。先秦两汉的文献中记载着这样一类物产——&quot;某地之某物&quot;因其质量特高而闻名天下,甚至一度成为该类物品的象征,在众多文学作品中被广泛称引。","categories":["09_其它"],"year":2021,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIGboYtx0qzLVjoAwUrfujF13GF-QOBarwTkauaE4kMddLQnKptmcBfx8yM7oL4zjnub1KLzVn3YJ-4QrI8mFlTOD_icCMqiHGAbdOTLOgRsoPXaGgKwdH16Oap38EY8oAALnZCIQ26VBgACajE0UMHzNvQ2wtVl4OeA83I0ACFTTSjzZwf7yPa&amp;uniplatform=NZKPT&amp;language=CHS","pages":"287-292","volume":""},{"id":1500,"author":"","title":"金文","abstract":"金文是商周时期铸、刻在青铜器的钟或鼎上的一种文字。因铸刻于钟鼎之上,故也被称为钟鼎文。它是在甲骨文的基础上发展起来的文字。金文上承甲骨文,下启秦代小篆,流传书迹多刻于钟鼎之上,所以大体较甲骨文更能保存书写原迹,具有古朴之风格。金文在笔法、结字、章法上都为书法的进一步发展做出了贡献。金文起于商代,盛行于周代。商代金文的字体和甲骨文相近,文字内容或者是记事功的,或者是录训词的。金文发展至周代进入全盛时期。","categories":["09_其它"],"year":2021,"publication":"科教文汇（中旬刊）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIGeqAkwGOSHALyEB128Rs-3oLg93tJ69ixGT8Fn3cuvT79LnGNXjEE4iGV35HzxSOxo8pg3IXgK4Pt6zszhYu4PgAcjhwGpLV_B_KJKJz_H1ItcpY2yoZp_9CaW9S6n7T-SMFx22eYGvYlCmgTozQukvtQ53n3BrRN2Sb2Esrb1MYfL2s2AZ-c&amp;uniplatform=NZKPT&amp;language=CHS","pages":"194","volume":""},{"id":1518,"author":"李文君","title":"吴大澂致杨秉信信札考释","abstract":"故宫博物院藏吴大澂致杨秉信信札6通,此前从未刊发。这些信札写于吴大澂任职吉林与开封期间,内容主要围绕吴氏托杨秉信从西安代购各种古物展开。除吴氏书法的艺术价值之外,这些信札对研究晚清古物的流通及补充吴大澂相关研究都有一定的价值。","categories":["09_其它"],"year":2021,"publication":"文博学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJsiRzoMaeb6RwmznAYEbknti0WK8WBWd1dmxr1YOhTZjF_Cmg_WUczUzqwpJP79fRHzupTkuczmcvKALwb3tp8McE6ys9Y9xv2TfF9RAfx90xxlA3q91LB8uFg3G_r7MJIqxfUPThmhYLKeovxa1GQDfIzVOyo2By_NvChSgLT5-jNebSEkhui&amp;uniplatform=NZKPT&amp;language=CHS","pages":"94-102","volume":""},{"id":1531,"author":"夏含夷; 李纪言; 石从斌; 杜清雨; 李举创; 杨蕙旬","title":"一篇可能失传的经典：《摄命》","abstract":"《清华大学藏战国竹书(捌)》中收录了一篇整理者题为《摄命》的竹书,整理者认为该篇竹书即是古文《尚书·冏命》篇的原作。本文旨在对此论点进行评估,并通篇翻译全文。在此基础上,本文探讨了该篇竹书对现有西周史研究可能产生的史学影响,以及该篇竹书从成篇(可能早在公元前9世纪)到抄成(约公元前4世纪)的实际流传过程。","categories":["09_其它"],"year":2021,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKubyL5ZTPrS969SPH4FNCQ_ufqixiW9i5tC-r_gaDaY1LFn4G7YgxKBlN14MiaOBiqt8fpZkIAol4RzMB5NLFBGcYya1WSfrpIwm_0WpCSUjlT9vetK4bs1k2mVxrp3VDtO-BoX6cOqvSKaa7Gh_12z6VLUjU0Z4c6ihNmvyvUpEUt00XcaxLz&amp;uniplatform=NZKPT&amp;language=CHS","pages":"1-18, 154","volume":""},{"id":1554,"author":"刘瑞鹏","title":"晋系金文书风述论——以晋侯重器铭文为例","abstract":"周代金文之书体式样与书法风格颇为丰富,为中国书法史上不可忽视之重要篇章,各诸侯国之金文对周室作器铭文既有继承又有创新,晋系金文亦不例外,种类繁多,异彩纷呈。本文主要撷取晋唐叙虞时《叙虞方鼎》至晋文公时《晋公盘》等一系列晋侯重器铭文来探讨晋系金文书风之分期,通过研究可分为四期。","categories":["09_其它"],"year":2021,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIDPT4crl9tAecZC5ziTCK70eD9fhDfMyiJrAySk7CaTWNIwVsEn9BtsygVGpOu6MXQZw9qmr2J81a2rSeAiJ7TydfgeTlN7dHfimJbQ-uG_izvy8ORZ5HhVsL3w66i10c8QoasTx43onEHPU4VgM9GvwwmKX8rGAgOIKkkwhxnQ33zCVlhY2-u&amp;uniplatform=NZKPT&amp;language=CHS","pages":"114-127","volume":""},{"id":1556,"author":"邓君浩","title":"台北公藏《毛公鼎全形拓》调查和探讨其上题跋价值——兼论其在收藏上的定位","abstract":"本文研究目的在于调查台北地区公藏《毛公鼎全形拓》。因毛公鼎为西周重器,也是铭文字数最多的青铜器,借由全形拓上的题跋可以了解毛公鼎的历史文献及与其相关的问题。毛公鼎全形拓金石拓片以台湾&quot;中研院史语所&quot;傅斯年图书馆与台北&quot;故宫博物院&quot;为大宗,所以调查其公藏的陈介祺与叶公超旧藏《毛公鼎全形拓》及探讨题跋有其必要。其上的题跋,反映了收藏的信息与学术考据以及金石交游等脉络关系。","categories":["09_其它"],"year":2021,"publication":"西泠艺丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLxdAA2IJjQIEd4oEJ45c9Vwm7OiAL1fVU9Oy4kQC49ZyUKBVJjVlR4-1P5mSARh0NG7tIVYfx7ey7aMtJBWYnKnPJBLAPXLxdvai_CyTQCCCtby43vKyKo08aVR-vp3V-hp_GQ4MFYOWvZj91eFIeAMU3-HdgNP5KLSwhDt51PiqNrbTtRa0oT&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-69","volume":""},{"id":1559,"author":"曾宪通","title":"容庚先生的治学","abstract":"容庚先生毕生著书20余种,发表论文和著作近百篇,是一位著作等身、学问渊博的大学者。先生之所以能在许多学术领域中取得如此卓越的成就,是同他做学问的精神和做学问的方法分不开的。从治学的角度来考察,不难发现容庚先生确有自己的特色。","categories":["09_其它"],"year":2021,"publication":"大学书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLVkgrScxtJCSgoLAc_R0kOayJsi2pbIuZ7RwPs918pSqdGTepusRDiYCqypfLk5XRv11P6py9UGvxamN2j6GaICRfdmonZWrpAiZAnPv3_5Ry5cLPtePdzsKCT8ZHZk5lgUgp80bzf6s8OFnyaJ7CtfXvAb6xRRCe29GIdR8vWNaV09bk7ZBo8&amp;uniplatform=NZKPT&amp;language=CHS","pages":"14-15","volume":""},{"id":1560,"author":"马国权","title":"容庚先生的学术成就","abstract":"容庚先生一生于学术研究致力甚广,当然,最主要的贡献是在金文和铜器学方面,但在甲骨学、文字学、书画篆刻、丛帖学、文学等方面,皆各有可贵的建树。(一)金文和铜器学容先生从中学毕业,到逝世前的近70年中,一直都从事金文和青铜器的研究,先后撰集《金文编》《金文续编》两部字典,编著《商周彝器通考》《殷周青铜器通论》(与张维持合著)两部综合性研究青铜器的专著,还编纂了金文录、铜器图录等八种,并撰写了十余篇论文。从&quot;纂录其文,考释其义,参证于经史&quot;,到铜器的形制、定名、时代、辨伪等各个方面,都无不兼到,贡献至大。","categories":["09_其它"],"year":2021,"publication":"大学书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ9M9_j3-GZu7YHcxh9hIiy2-yGqHSpawU8c6Rskz4Qfxh39JYQv7BIX9BwagW6-LAA_1zmLARc6OuHo6hb9lJZeb2fqPVHyg9tuH83gA2BJYEPSvZaQNh5IweqdgCff3t2CL6sulTv9RlxsJsPrGRVfGmP7BZk0eghcW3uie7X0LUXWfjiUyEl&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30-34","volume":""},{"id":1571,"author":"赵成清","title":"20世纪上半叶西方的中国青铜器收藏与研究初探","abstract":"在对中国青铜器的认知、收藏和展览过程中,西方学界开始了对中国青铜器的研究,并涌现出罗杰·弗莱、福开森、高本汉、巴希霍菲尔、罗樾、顾立雅等一批杰出的青铜器研究学者,他们在探索中国青铜器鉴赏和研究方法的过程中,也在不断地向西方传播着中国艺术文化。","categories":["09_其它"],"year":2021,"publication":"南京艺术学院学报（美术与设计版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKUn3Q6kU3zZsEURBev_zkd-k2BmlkIehaG1RrWdzLwhjqW7f8Ix3F3v26H52tVxDVEgZrA1lvN19-zal22hq8CyXX8AAuoMVpVPocRFuarvCBoMrPbWjwIpcZeC2STICMgXaxxzGF-fUL-8bWUE7d4izyN0uCza9PDKJcpww0t2Kx7dod-a_2Q&amp;uniplatform=NZKPT&amp;language=CHS","pages":"36-43, 217","volume":""},{"id":1597,"author":"商立丽; 王慧琴; 王可; 王展","title":"基于Hu矩和TF-KSURF的多测度青铜器铭文相似性度量方法","abstract":"针对单一特征无法表征铭文全部信息的问题,提出一种基于全局Hu矩和局部聚类加权加速鲁棒特征(TFKSURF)的多测度青铜器铭文相似性度量方法。通过提取Hu矩特征描述子与加速鲁棒特征(SURF)矩阵,获取铭文图像的全局与局部特征;利用K-means算法和加权策略对局部SURF进行聚类加权,构建TF-KSURF向量;最后设定两种测度的权重,形成多测度相似性度量,并将其应用于青铜器铭文的图像检索。实验结果表明,与单一特征测度相比,所提多测度相似性度量方法能够准确分析铭文的整体特征,提高了铭文的检索性能。","categories":["09_其它"],"year":2021,"publication":"激光与光电子学进展","link":"https://link.cnki.net/urlid/31.1690.TN.20201021.0955.006","pages":"123-131","volume":"58"},{"id":2180,"author":"王静; 郗文倩","title":"先秦两汉“形法”研究","abstract":"“形法”,俗称“相术”,是指通过客观对象的外在形态特征,来鉴别其优劣好坏,以及对人吉凶祯祥影响的数术形式。先秦两汉时期是古代形法观念、类型发展的重要阶段。《汉书·艺文志》“数术略”形法类,收录凡相人、相地相宅、相六畜、相器物四类文献图书,真实反映了当时社会呈现出来的知识结构和思想系统。中国古代相人术起源甚早,先秦两汉时期相人术相法原理与运用策略已经形成了较为成熟且稳定的知识体系。然而,此时相人术在发展过程中受到特定社会制度与思想观念影响,体现出不同时期相术观念与行为的变化。在相法观念上,传统相人术与“圣人异相”完成了从分离到融合的演变过程,其对于人体形貌特征的描绘带有谶纬之学的深深印记。在女性相法建构上,在先秦时期男权社会下,“男女有别”的礼法规范对于女性形象建构显示出强大的规约性,女性相法行为在数量上颇为少见。迄至汉代,两性关系中阴阳性别象征体系的确立,为女性相法提供了广阔的理论生长空间","categories":["09_其它"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27019/d.cnki.gfjsu.2021.001960","pages":"","volume":""},{"id":2186,"author":"卢忠敏; 张节末","title":"东周青铜器叙事性画像研究","abstract":"东周青铜器画像是中国最早的叙事性艺术之一,再现的是“威仪反反”、磬折肃穆的礼仪场景,是研究中国早期美学和礼乐文明的密码和钥匙。回顾东周青铜器画像研究史可以发现,古人不遗余力地运用当时最先进的装饰技术将这些繁缛的礼仪场景镂刻于青铜器上,且几与《仪礼》的撰作时代同期,简单的“礼崩乐坏”或“弄器”难以诠释画像与文本的间性。是以厘清画像内容和主题、挖掘画像叙事模式,是还原式解析青铜器画像的关键所在。首先,叙事性画像是以青铜器为载体,若仅凭视觉经验直接对平面画像摹本进行分析,容易产生主观臆断。应“纹归于器”,即充分考虑器物空间大小、器壁曲直、位置经营、装饰技法等客观因素对画像的影响,透过纷杂的画像表象探其原型与本质。还须将其放置到早期视知觉语境和构图法则中,重新思考二维画像是如何“翻译”三维空间的。可以发现:采桑母题表达的不是情爱主题的“会男女”社会风俗,而是桑蚕以做祭服的躬桑仪式;射侯母题反映的不","categories":["09_其它"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27461/d.cnki.gzjdx.2021.003023","pages":"","volume":""},{"id":2576,"author":"刘文腾; 王慧琴","title":"基于集成学习的青铜器铭文识别方法研究及应用","abstract":"青铜器铭文是商周时期经济、文化、社会活动的历史见证。通过对青铜器铭文的研究,可考见当时的社会制度,纠正古籍中的伪缪。青铜器铭文的识别对探究古代历史和古代语言文字具有重要的意义。现阶 段青铜器铭文图像特征提取与分类器模型识别存在两个主要问题:首先,铭文是铸刻在青铜器上的文字,由于工艺、手法、年代等差别导致相同字头下的变体之间图像特征差异较大,难以有效的进行相似点聚类,无法区分不同类型铭文文字。其次,单一类别铭文数据量较少,使用机器学习分类器进行学习时容易出现过拟合现象,导致识别模型的准确率降低。针对 上述问题,论文结合拓扑学性质与网格技术对青铜器铭文的特征进行研究,并设计了一种对训练集样本变化敏感程度低的Bagging集成学习分类器,提高对离散程度高的铭文数据集的适应能力。主要工作如下:(1 )研究一种基于拓扑特征与网格双特征的铭文图形特征提取算法。结合拓扑学中无向图的概念,将铭文抽象为一种","categories":["09_其它"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27393/d.cnki.gxazu.2021.001579","pages":"","volume":""},{"id":2581,"author":"闕思琪; 党懷興","title":"高田忠周《古籀篇》研究","abstract":"十九世紀末二十世紀初是中國傳統文字學向現代文字學轉型的時期,這時的文字學家們接受到考古最新成果,試圖結合出土文字材料,探索一條新的文字學道路。同時,海外的漢字學研究也在發生變化。在這個重要的轉型節點,傳統文字學如何走向現代文字學的道路?海外漢學家的研究對文字學的轉型產生了哪些影響?衹有將學術史上這一轉變的細節探查清楚才有利於我們進一步深入地研究。衹有對這一時期有影響力的每一位學者之學術成果及思想進行梳理歸納,才便於正確勾勒出學術史的樣貌。高田忠周是日本明治時期的漢學家,其書《古籀篇》是一部吸收了古文字材料的《説文》學研究著作。因此,本文選取高田忠周的《古籀篇》爲研究對象,通過梳理《古籀篇》的文字學思想及其實踐,爲高田忠周確定一個較爲清晰的學術史地位,也爲勾勒出二十世紀初的海外漢語言文字學史研究提供一份具體的案例。目前,針對《古籀篇》的專書研究仍存在一些問題,如研究範圍不夠全面,研究視野過於","categories":["09_其它"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27292/d.cnki.gsxfu.2021.000228","pages":"","volume":""},{"id":2586,"author":"王媛; 孔令伟","title":"钱坫及《十六长乐堂古器款识考》研究","abstract":"乾嘉时期,金石学复兴。一时间名家云集,人才济济。众多金石学著作面世,出现了百家争鸣、百花齐放的金石学发展盛况。钱坫是乾嘉时期著名经学家、书法家、金石学家,生平改经证史,善训诂,精考金石碑版,工篆籀。钱坫在清代金石学领域取得了一定成就,是乾嘉时期促进金石学研究风气转变的先锋代表。其金石学著述《十六长乐堂古器款识考》由家藏金石器物汇集而成,最早私家著录金文的专著,也是清代最早使用铭文拓片的书籍。首先,本文将通过对家世与生平、入京与游幕、交游等三个方面的论述,全面了解钱坫其人;其次,本文将对《十六长乐堂古器款识考》做一个系统的研究,主要包括成书背景、版本以及写作体例等内容;再次,针对《十六长乐堂古器款识考》中器物的命名情况,对器物的错误命名进行纠正,主要分为自名器物、以器型命名的器物以及其它模糊命名情况等三类;最后,将《十六长乐堂古器款识考》与大型官修金石著录书《西清古鉴》对比分析,更加清晰地了","categories":["09_其它"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27626/d.cnki.gzmsc.2021.000371","pages":"","volume":""},{"id":2593,"author":"刘禹彤; 陈双新","title":"信息化时代新旧字形问题再研究","abstract":"字形规范化是汉字规范化的重要内容之一。随着信息化时代的到来,古籍整理用字的需要以及实现海峡两岸书同文的目标,使新旧字形的规范问题越来越突出。本文以CJK字符集中20902字符与《康熙字典》作为测查材料,找出其中含有新旧字形差异的字共5895个,占20902字符集的28.2%,并按照一重、二重、三重差异对这些字进行分类。本文追溯了新旧字形的来源问题,将新旧字形问题与繁简字和正异字更好地区别开来。通过对测查数据的归纳分析,总结了相关部件由旧字形到新字形的变化规律,新旧字形在笔形、笔画数、笔画关系、部件、结构5个方面发生变化。根据这一变化规律总结出新旧字形的类推范围和选取理据,大部分新旧字形可以全部类推,只有少部分是有限类推,有限类推没有规律。其选取理据不完全遵循文字学的传统,更加符合从俗从简,便于书写的原则。文章对信息化时代古籍整理用字和海峡两岸用字中与新旧字形有关的问题进行讨论。","categories":["09_其它"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27103/d.cnki.ghebu.2021.000263","pages":"","volume":""},{"id":2622,"author":"李子怡; 孔令伟","title":"吴大澂1888-1893年间的古玉鉴藏研究","abstract":"吴大澂是活跃在金石收藏圈的晚清官员之一,所收涵盖钟鼎彝器、碑帖印鉴、砖瓦陶片、古玉古瓷等,尤以古玉收藏为著。吴大澂基于经史考据的、带有古器物学倾向的考释方法开启了一条古玉研究的新路径。自1889年起,他先后著成付梓《古玉图考》与《权衡度量实验考》两本著作,前者是对收藏、经眼的两百余件古玉器的考释集成,兼及以等比例线描图的形式记录器物尺寸、形制与纹饰;后者则基于考据学的研究方法,试图以出土玉器作为实物例证考证经史典籍中记载的度量衡。吴氏的古玉收藏趣味广泛、种类丰富,有关玉器的收藏活动在1888至1892年间异常活跃,收录于上述著作的只是他这段时间内网罗收集的一小部分。未收录于吴氏古玉考释著述的玉器中不乏精品,如1892年出土于山西的“汉建初玉券”。此券出土后先后入藏吴大澂、端方、龚心钊的书斋,1979年入藏上海博物馆,流传有序且考释丰富,是研究《古玉图考》成书后吴氏晚年收藏趣味与收藏活动的重","categories":["09_其它"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27626/d.cnki.gzmsc.2021.000393","pages":"","volume":""},{"id":2637,"author":"高明珠; 漆子扬","title":"刘喜海及其金石学研究","abstract":"刘喜海是清代嘉庆道光年间著名的金石学家之一,他为官半生,不释书卷,以研谈金石为乐,结识了如阮元、金锡鬯、刘师陆、瞿中溶、戴熙、陈介祺等一大批在同一时期金石学界享有盛誉的大家巨匠。时代背景、家族背景及交游促成了刘喜海的金石学成就,其金石学成果对于清代金石学研究有重要价值。本论文归纳刘喜海金石学成就产生的背景,梳理其金石学研究领域及治学方法,总结其金石学价值与影响。以刘喜海及其相关的金石学成果为研究对象,分三章对刘喜海及其金石学进行分析研究,内容包括刘喜海所处时代背景、家族背景、学术背景,以及刘喜海的金石学研究领域、研究方法等诸方面。关于“刘喜海金石学成就产生的背景”的问题,主要采用文史互证、知人论世、文献考证与理论研究相结合的方法,以《清史稿》《清史列传》《(乾隆)诸城县志》《(道光)诸城县续志》《(光绪)增修诸城县续志》《长汀县志》《瞿木夫先生自订年谱》《宝素室金石书画编年录》《岁贡士寿臧","categories":["09_其它"],"year":2021,"publication":"","link":"https://link.cnki.net/doi/10.27410/d.cnki.gxbfu.2021.001372","pages":"","volume":""},{"id":2929,"author":"苏文勇","title":"天津师范大学藏毛公鼎拓本考","abstract":"天津师范大学藏有两份毛公鼎拓本。历史文化学院文物室所藏拓本是拓自陈介祺入藏时期毛公鼎原器,拓工为陈畯。图书馆古籍善本室所藏铭文拓本应是拓自晚清时期簠斋中所制摹刻版,其全形拓片是雕版刷印的。通过对图书馆所藏铭文拓本册页中题跋内容的释读和评析,可以展示晚清学者传统金石学的研究思路与方法。册页内容的解读对其他毛公鼎拓本中题跋的辨伪也具有借鉴意义。","categories":["09_其它"],"year":2021,"publication":"古籍保护研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iICdmQrUpNMp5gkwJ95H9Djcx-pyxLcMKu_5KoozCm_bJ-HZcygUPOszHZMAB-5epdDqJCS5DQ14fV535O3RAF-NexOO4NJ3LeP8DvZjAjYJ3KfrozDB_t7U0ZEqApZAReBqM8CUYM3RLkyyD23tZwtqDlj859peQLsLerSCOZchw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"199-222","volume":""},{"id":2933,"author":"苏荣誉","title":"论商前期青铜双耳簋的风格与工艺——兼及早期青铜簋风格与工艺的地域性问题","abstract":"随着古代青铜器资料的增加、搜集和研究的推进,与其他青铜文明相对照,愈发突显中原古代青铜器卓尔不群、无与伦比。其特点首先表现在造型怪异、复杂,但实用性差;其次表现在装饰和纹饰独特、华丽甚至繁复得匪夷所思,母题纹样从来不曾在其他文明中出现过,而且新近的研究还揭示出其中不少原本是瑰丽多彩的。最后表现在实现功能和风格要求的制作技术大相径庭,以泥范块范法为独占工艺,几乎没有其他文明通常甚至优先采用的锻造成形工艺,","categories":["09_其它"],"year":2021,"publication":"三代考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK6DDltp7pd85dCtY7ClKUm3oNjL46mLBpVL2-01YA9HCIumIMYWYl0zDc2XgatPqTB1IOCMjO2YX-7TrfUH_MX7T_IEw_7aCe-v2V6Djw_JDf0UA4N-f0AMrz9uV7op-bq78XByf_qdrXkmDknuHxn2VEGvg43jSz36-D_VIdArA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"569-609","volume":""},{"id":2944,"author":"杨菁","title":"新见即盘辨伪","abstract":"《文物鉴定工作中发现的三件西周青铜器》一文公布一件新见西周即盘,本文根据目前所披露的材料,结合即盘与即簋的器形和纹饰,在对即簋铭文拓本进行分类的基础上,通过分析两者的铭文字形与书体的差异讨论即盘真伪问题。推断即盘为西周中期器物应可信,即盘铭文则是以采拓不精的即簋《集成》拓本为底本,掺杂■簋的铭文伪造而成。","categories":["09_其它"],"year":2021,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJEt1yZ0J0t34UsUjHPDiey_73PnSsFF5u-gQ-l8gJiKhj4UrUMlXiaqsRvSlT3QvcQl0RY4kYuWJ4xsf-baj5LjhlOmXXcs7It4H2xTiVT90TDZYaIdkg6RxYl51F3C74FchX1PvL6sRlccGhasuwAlaEQQpMZjonDBO8xEBVVLw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"22-33","volume":""},{"id":2954,"author":"蘇榮譽; 李耀光","title":"論戰國中山王■鼎及其銘的鑄造","abstract":"20世紀後半葉在平山靈壽故城的考古發現和發掘,特别是1974年發掘的中山■墓,揭示出史籍零星記載的戰國中山國具有輝煌富麗的物質文化和藝術創造。以青銅器論,其中不乏極品和孤品,技術和藝術并稱雙絶。尤其是中山三器——中山王■鼎和方壺及葑粢壷,因長篇銘文而著名於古文字和藶史學界。[1]這些會銅器雖然面世四十多年了,仍有赛于周題含混不清。[2]本文針對中山王■鼎的鑄造工藝及相關間題再做探薄,以求證於學術界。","categories":["09_其它"],"year":2021,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJmfqm1h38TDhQmuUxDU442A8Zbirzh8kvDymwNStauyCRnsrVaQkP8eiKo1L1ZTsOxR3_XMzgW2Jl8_6GHRbd65K3PCpEoM8kg_ySonHgxB0go0C7_i-xl5EzK4k7otv7WlP8R-RMZQL_0Yj-BL2MG_fNNNyggZJVcGxWETfla6Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"154-169","volume":""},{"id":3694,"author":"苏辉","title":"廿年琐忆：夏商周断代工程参与史","abstract":"1996年,笔者在北师大校园内一个报栏前阅读宋健先生的《超越疑古走出迷茫》这篇名文时,从未想到在本科毕业后能有幸追随夏商周断代工程专家组组长李学勤先生学习,从而与夏商周断代工程(以下简称&quot;断代工程&quot;)产生交集,并且这种学术关联一直持续到今天。断代工程在开展学术研究的同时,十分重视后备力量的培养,为了达到既要出成果,也要出人才的要求,在教育部的支持下,利用中国社会科学院、中国科学院、北京大学、南开大学等单位已有的学位培养体系,","categories":["09_其它"],"year":2021,"publication":"黄河.黄土.黄种人","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIyWOQUTBrooO62AIF_3-_PWCC_zL0rT6tySXcXBtty4q9VNmaNhPXz14KBbUgPxEgCiTjjEHv-d32y-ZlgVawk6YxNe3YjCZOfgWcQkRaI2Nb6gLOdoGSZrE6n6O0mKpeR6B9hdp6MsDQgxTaDxNzgk5RCf1lgInf7vgK9YaiCQMtWPPtF-Fyq&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46246","volume":""},{"id":3696,"author":"顾万发","title":"新论饕餮的本质、商周青铜器图像意义主题及有关问题（三）——从商末周初一件青铜尊的特殊图像论起","abstract":"上接第六期中国的道家在东汉以前是一个阶段,魏晋以来是一个变化阶段,本文所论的这些考古发现现象表明这些龙、虎、神祖甚至是巫师、墓葬主人等图像组合及其器物本身的意义,至少应是道教流形、合气、治气、形解抟精文化的早期来源,并且显然是中国道教思想的早期表现。本文已有的论证表明,商周时期,人们经常把苍龙唾、散精气,龙虎阴阳抟精气、精气的动物化神兽、震卦之象的神兽、&quot;雷出地奋&quot;场景及其组合,以及氏族神祖神诞神话、神诞符号等以生为德之首、呼应道家的文化和宗法制度作为青铜器的主体纹饰。商周青铜器图像意义复杂,除了装饰之常规功能以及我们所论的一些功能,","categories":["09_其它"],"year":2021,"publication":"黄河.黄土.黄种人","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI05S-Wcfz7ee2PZduq8wLi9_aclogOozY8ovpmVga5APkLCjwIqkeURpJ1lBUI2Npy7Q_l6Bbq4Nb2wlLJKcEeQmtnb08aD1lqiYBWdaU7SLzJTzECFDOBDvjc4fGTKMbukWg0fRoju7y0sUVq8hmHAku_2cOu_ODk7L4CWM3GfnQYkpbw-JEh&amp;uniplatform=NZKPT&amp;language=CHS","pages":"29-64","volume":""},{"id":3699,"author":"顾万发","title":"新论饕餮的本质、商周青铜器图像意义主题及有关问题（一）——从商末周初一件青铜尊的特殊图像论起","abstract":"著名的德国汉学家卡尔·亨彻（Carl Hentze）所著的德文版《青铜器在中国早期文化中的重要性》（1941年版）一书中编号140的一幅图①（图1）较为特殊。我们知道,商周铜器标准化饕餮两旁一般是呈现对称的兽面苍龙、鸟首苍龙或者是特殊的神鸟②,少数是有火字形花纹的小苍龙,有的还有两条小苍龙,有的神鸟还为苍龙系的夔龙所食,即赋予精气能量和表现其有类似晚期文献记载的丹术修炼的行为以及得道的功德,","categories":["09_其它"],"year":2021,"publication":"黄河.黄土.黄种人","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iId8BbOkYm0RGCqJAqwnjZPQ2rlkfEI2X22w__geMUjtKWCukzrG_FbZtyrjPs2pOzfxxBY2edMm9aw2e_ruBaXvUjg4UoCKSgywFi_uadonQJqgVnpJLMuu4sN8NdijK1KoawgO8Q3vOuDvp4erwvuCANX5hXynUSIac-xi2BAf0PDvejUBwvj&amp;uniplatform=NZKPT&amp;language=CHS","pages":"38-63","volume":""},{"id":1574,"author":"袁泉","title":"器用宜称：宋以降国朝礼器中的鼎制之变","abstract":"&quot;器用宜称&quot;是宋代国家坛庙祭祀礼器酌定范式和制造颁行的重要标准。所谓&quot;上法先王之意,下随当世之宜;稽古而不迂,随时而不陋。&quot;既尊仿古制,又斟酌时风。由宋至明,国朝大礼的器用体系均体现出既法三代古制、又应当世之变的精神。论文拟从礼器整理和礼图考证入手,以国家典仪中&quot;鼎&quot;的发展为线索,探讨礼器著录与研究的不同系统在宋以降国家礼器颁定与实践中的交互影响;并通过梳理日用燕器对传统礼器体系的替换和补充,管窥礼制建设的从宜之变。","categories":["09_其它"],"year":2020,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2020.06.005","pages":"54-68","volume":""},{"id":1581,"author":"谢乃和","title":"2017—2019年先秦史研究述评","abstract":"三年来,先秦史研究不仅在新材料、新方法和新理论的带动下新成果层出,而且在先秦传世文献整理及传统专题研究方面也不断推陈迭新。《诗经·小雅·裳裳者华》言&quot;维其有之,是以似之&quot;,是谓前人有所得,后人宜嗣继之。虽欲竭泽而渔,然三年来研究成果丰硕,顷筐塈之亦难免遗珠,祈见谅于方家。一、概述作为先秦史研究的基础,传世古书与新史料整理始终是学界最为用功之处。三年来,古籍整理研究相关成果以杜泽逊《尚书注疏汇校》《尚书注疏校议》","categories":["09_其它"],"year":2020,"publication":"中国史研究动态","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI24eRYeFb1sbTu5BN1UTLCgwg_fMXkIfZ0wpLIlX_2-rjKt-TiPQMNn4lt7rcGdRBq6ur5ryWyAgU0Xq_aH3EXW8DAiv0VEmCnZo62vZlbaMPy9oY90WlJ84AsgX5p2Kk_6--6545M8LdxC7itlNDqxA6xsIz4GeXh7eD3aFSXuTKI_CU_EyDB&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46346","volume":""},{"id":1584,"author":"曾庆炳","title":"新见杨树达《辛卯甲金文讲义》和《壬癸甲金文说》初探","abstract":"《辛卯甲金文讲义》和《壬癸甲金文说》是20世纪50年代杨树达任教湖南大学时编写的两份讲义。前者仅存《新识字之由来》一篇,是目前所见该文的最早版本;后者包括甲骨论文18篇和金文题跋79篇,其中内容多已收入杨氏专著,但异文颇多,且还有一些仅见内容。通过文献比勘,可以反映杨氏学术观点的变化,订正杨氏专著中的一些错误,展现杨氏相关著作的文本形成过程。","categories":["09_其它"],"year":2020,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLvoSp6ato1oO2SQOLf5e0w_5z1LxVxD33-Ys1tFezcyZ_LUIUC2VrClIhfxCEIEP_jthRLLhrmyoVp94mfeAeW_e4G6dV-d5V49uTqUoLdbHwQIo4qh-M6Nhlf6jCHTLRFf6Q2OGIqlkLLr4FNnGlweRWxBU3KDlIiRqafZ3Xh5H7nXyeynzHv&amp;uniplatform=NZKPT&amp;language=CHS","pages":"143-153","volume":""},{"id":1589,"author":"卢星君; 彭作飚","title":"容庚、郭沫若学术交往","abstract":"一九二八年二月,郭沫若流亡日本,开始研究中国古代社会。在研究的过程中,郭沫若发现,&quot;以《易》《诗》《书》为研究资料大有问题。《易》《诗》《书》虽可证明其为古书,然已传世数千年,正不知已经多少改变;而几千年的传世注疏更是汗牛充栋。要排除或甄别那些旧说绝不容易。&quot;[1]他说:&quot;真实地要阐明中国的古代社会还须要大规模地做地下的挖掘,","categories":["09_其它"],"year":2020,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIsp70xpJ_hB_yJjRiaogv8fqEDpuux8IgJ4T0mcB3KAzSv_ssp5xvO1EdHh9hAkVcsIMZQP3KmmmvY4lCoEVL-iHv-Ldzw2MbHvL1UzR0mNBzQ24b_qNcoa1MetzKZv2OUuLgd5v6qA1S-npQmGXpVTwfKkxXOpNQBOqC1sxSJArPUI02JELFY&amp;uniplatform=NZKPT&amp;language=CHS","pages":"52-55","volume":""},{"id":1604,"author":"李霏","title":"《眉寿图》拓本考略","abstract":"清道光二十三年(1843)金石学家张廷济与阮元合摹《眉寿图》泐石,艺林传为韵事。作为眉寿韵事的一个载体,《眉寿图》拓本在清代金石鉴赏史上留下了瑰丽的一页。本文重在考察刻石之由来、拓本之流传,试分析《眉寿图》刻石的原初意义、其作为拓本文献所产生的影响;次则对摹刻的过程加以辑梳,对比拓本间的差异并对原因提出解释。《眉寿图》刻石集诗画图咏、拓篆考释、缩摹迻写于一体,对于考察二家金石交游,考释齐侯罍、汉砖&quot;千石公侯寿贵&quot;,具有重要文献和艺术价值。","categories":["09_其它"],"year":2020,"publication":"西泠艺丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJyVkIypatAuVR9W-6Iyc2iDJ3gx6xNLySKKrvZRB5-BN17Dq_AYnPzrRYUTKsyFCoBdHV4efFKjAWtp6NOe0ocPHO8K8vfC0pqWA5gU6uKemls1TDzmyzgiYyu3ZshF07ZgJwFmMrL7QbSONYD1GBGeZ7kL_FgIsWKclkNhuzi6OyWQ0C73SjU&amp;uniplatform=NZKPT&amp;language=CHS","pages":"31-48","volume":""},{"id":1610,"author":"康盛楠","title":"杨树达金文研究对前代的继承和发展","abstract":"金文自汉代就受到关注,两宋时期,有学者开始著录和考释金文,清代的金文研究已成为时尚,晚清的金文研究进入颠峰期,内容涉及到著录、考释、以金文证史等方面,并且已成熟地运用&quot;对照法&quot;、&quot;偏旁分析法&quot;、&quot;历史考证法&quot;等多种研究方法。杨树达的金文研究对前人有所继承,有所发展,一是研究内容的继承和发展,一是研究方法的继承和发展。","categories":["09_其它"],"year":2020,"publication":"语言研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLz4x0EeZPdDQikAcghksPGndaYTAdCxOPQl543ge6GBUd46dfUNfzcA3Sgvdtia6kltylhYKoDpkoYKafAy0RDoVcl_iBZs61fIeca9-MCjY_HwqwrlNxoEXzu7pg04pS4Ox-2V4HScrZeRcJhl3udFMq3AArsuUgQ6z2cP9AxKEwmo3uwWbC-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"102-106","volume":"40"},{"id":1631,"author":"杨欢; 杨戬","title":"商周青铜器铸后制铭工艺考证","abstract":"学界普遍认为商周时期青铜器的铸造铭文早于铸后制铭,并认为铸后制铭技术只出现在西周晚期以后。本文通过对商周时期若干铸后制铭青铜器的研究发现,铸后制铭可分为錾铭、刻铭与琢磨铭文三类,后两类的出现与应用不晚于铸造铭文。这些技术脱胎于夏商时期的玉器加工工艺,当与甲骨文的契刻技术同源,工匠至迟在商代晚期就已掌握,但出于生产效率与容错代价方面的考虑,选择了出现较晚但更为节省时间和人力的铸造铭文技术。铸后制铭因为其本身的缺陷,只作为一种边缘技术长期存在。","categories":["09_其它"],"year":2020,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJHuCLAw9alhO92RxlQoibQNHKVrC1d6FEtGEy-TYv6kP08W3EtQzp_E3bwS_k_dELKxAw3FpPscJOXZbeVNGbWVtXxMicGgMoPxH2FI2yv-RZ50uvEdsA0-KquctsPOor9QWFB009TvySgnUtZL9f2ysg4XDA-UTcRwnE2n14Dv5tfacN0kz6n&amp;uniplatform=NZKPT&amp;language=CHS","pages":"100-106","volume":""},{"id":1632,"author":"郭士嘉; 种建荣; 雷兴山","title":"孔头沟遗址铭文芯与西周铭文制作方法","abstract":"陕西岐山孔头沟遗址铸铜作坊内出土的一件西周晚期刻字陶范,其上残存3字,皆阴刻、反书。从形制、颜色、字形、浇铸面金属元素成分等方面,判断该范为芯而非模,阴刻字乃底稿线。从铭文字体与格线、制范技术基础、出土铜器铭文等多方面论证,该铭文芯所见西周铭文制作方法,可称为&quot;堆塑泥条芯作铭法&quot;。","categories":["09_其它"],"year":2020,"publication":"江汉考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIGmortUG2FtxuRTLVP0Qn0uElIIa-Sl59M1wM4-mPJf2O9qRvEsvLUHflnqumPw11fGo8SbR4-DDc6BvzWBIT2uhdPvVCYprYg6ADqbz8xVYir2iz102G13ruGwY_1oYXcEOfMpN3crimjOML1g_1N-_fsa_S_cJ7ADpISao3PY8DUnJvnvUnc&amp;uniplatform=NZKPT&amp;language=CHS","pages":"107-114","volume":""},{"id":1661,"author":"万晓","title":"良季鼎全形拓辨析","abstract":"良季鼎1933年出土于陕西扶风上康村窖藏,实物下落不明,以往学界著录的良季鼎资料均以北京图书馆所藏良季鼎全形拓为唯一依据。陕西历史博物馆现藏两件与北京图书馆不同的良季鼎全形拓资料,通过对三件全形拓上器物形制、文字以及题跋信息的对比与分析,重新辨别良季鼎全形拓资料内容的真伪,为这件不知所踪的西周青铜器提供了更为可靠的历史资料。","categories":["09_其它"],"year":2020,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKsG792YWzP1DUcACvIo4qLEtZBOas2ng5zkhNcecfLK2nvrGKmAt3JVlvMHgMtDN89hbOpjv0mfsGZspBJ6VJxcBBTLE57lZ0XXaAnm_K1A3tnYK1WOevPLgxdsQ4MhXa1oqgGfRtG7vNR9MuncZ1f6p7r-NhKupdZMvD_OhDdPaWeqWi6Bl0s&amp;uniplatform=NZKPT&amp;language=CHS","pages":"49-52","volume":""},{"id":1677,"author":"崔璨","title":"文献足征:试论《考古图》之礼学阐释","abstract":"对比《考古图》与《三礼图》中的牛鼎,可以发现宋人理想中的牛鼎与实物的差距,由此进一步分析其实际功用及命名依据。牛鼎纹饰和铭文的意义并非全然如《三礼图》所描述。而通过散季敦分析吕大临的器物命名,并对敦和毋追、兜鍪语源关系进行分析,发现三者密切相关。可见礼学家在追求经学阐释的过程中,将古器复原视作经学实践的一部分。","categories":["09_其它"],"year":2020,"publication":"南京晓庄学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKt8smseRWhzak4C3_hlvUpijjYYb1lDgH2Hb_yWmTQ_nGpIEI1dhjgfUxpOb6xZrbUzszLhzUdEaIrNmFp7K2xlLLtN3Yac5LZZ9R41bYQqFGDrNmT1jZ3eF_hj0QpCO3FnXQU6Kqo6e68xIWhB5PVDCW0F46SiO-hJ5xh-JRyRPlneNxaBED8&amp;uniplatform=NZKPT&amp;language=CHS","pages":"89-97","volume":"36"},{"id":1685,"author":"魏清源","title":"用科学的汉字理论指导汉字教育","abstract":"由于缺乏科学理论的指导,在当前的汉字教育中存在着许多问题。一是误析字形,包括汉字结构类型分析错误、汉字构件识别错误、误以简化字形体为分析对象等;二是错释字义,或是因对某个构件意义理解有误,或是以阐释汉字文化内涵的名义随意联想、主观臆测。这些都会导致对汉字科学系统的破坏。进行汉字教育必须以科学的汉字理论为指导,对汉字进行结构和意义的分析必须重视实证,才能使汉字教育事业健康发展。","categories":["09_其它"],"year":2020,"publication":"汉语言文学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iION7jyWSV169SAwZfid4CAoHW9ySz4uaCSvdpZwg-ixYHtFcHPFiN4JJaPEzQg5TWiq95gS0Xwbkn0zW_b8orMaZXwmOAB8UgE6a4vK934abKUCwcwz26pNJPKlZ4hQZrddRS_2DVldmihdCzam_2RjkLJXmJKJFO5njcazarNgvD2t7T3ldro&amp;uniplatform=NZKPT&amp;language=CHS","pages":"129-135","volume":"11"},{"id":1701,"author":"陈靖","title":"《金文集联》之《散氏盘》散议","abstract":"近年来,以先秦文字为研究对象的古文字学发展尤为迅速,这得益于地下出土文献等新资料的不断涌现。从微观角度看,一些疑难问题也往往由于新资料的发现迎刃而解,特别是过去一些不能释读、误释、误读的字通过新资料的文例比勘或与传统古书对读而涣然冰释。应该说这类成果是巨大的、丰富的。本文试就《金文集联》所作的举误体现这些成果。同时,书法创作的用字规范、历史语境等问题也应该引起书学界的某些思考。","categories":["09_其它"],"year":2020,"publication":"书法教育","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIgr6q6UUsmGSGmExKKa39m_5RFdsNZW2XJ_BYEj9xJRcl8D8HuP5prirwenZv30657Ggfkwq3VkyrAsGLhTIG0OfIcvj_bIvxg3FDlBFGs4IpJHulvWBsT3lLxwpSPmD9QAlqWj8WnyM56MykOh3b5f1eXsLCm3KC9aOJuoXnbfVaIxaem5q53&amp;uniplatform=NZKPT&amp;language=CHS","pages":"99-102","volume":""},{"id":1711,"author":"谭飞","title":"孙诒让古文字研究的贡献与局限","abstract":"孙诒让运用历史比较法、偏旁分析法、音韵知识、文例句式等方法正确或基本正确地考释出了不少甲骨文和金文。提出汉字起源于图画和刻画符号。在考释、分析汉字时,区分篆意与篆势。认为转注是一种造字方式,提出了一些自己的观点。文字考释时重视《说文》但不拘泥于《说文》,对前人工作多有纠正或推进,首释了一些字形。受研究资料等主客观条件的限制,孙诒让文字考释中也存在不少有待改进的地方和错误。","categories":["09_其它"],"year":2020,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLo3oxrY5MO70cMAthfHqcW5zX3unp6R-UueWFKGhGxA3WIegAZx7zsMAE1gxI65ncwyIWsBTPWEcq_MlccxqaXQARGLy4tpn4bkBzwaG3lNd9I44uJn0ES5yS4iZ4LMSPLZZFWVl7FaOYYxrkH90EeDmOrjF528K0ZFMRwQBYQ0ZlRU7DQbl7t&amp;uniplatform=NZKPT&amp;language=CHS","pages":"120-125","volume":""},{"id":1762,"author":"李冠兰","title":"君子观于铭——两周铜器铭文的阅读方式与文体观念之变","abstract":"西周时期,对书史类铭文的观看是凝视式的审读。春秋以后,铭文铸刻更注重装饰性而非可读性,对铭文的观看亦趋向浏览而非细阅。书史类铭文衰落,&quot;器主+祈匄&quot;类铭文占据压倒性优势,削弱了对铜器铭文的阅读需求。在祭祀仪式中,对彝器的观看是一种整体的沉浸式感受。而在对宗庙重器专门陈列和观览的情景中,对铭文的审读则呈现更明确的主动性。春秋战国以后,铭体的阅读主体从宗族扩展到范围更广的贵族阶层甚至万民,其文本突破了铜器的实物载体,从物质性、实用性的礼仪文体转变为文献性、观念性,甚至可以被构拟的书面文体。","categories":["09_其它"],"year":2020,"publication":"文学评论","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJDv-2E3YDz3mVaLf0eJpGORdM1fi3Rp7eJWPO6woNlFU37U_JdTqY2_HhtTiF9z43AftFt1EARA39E5ZShtwF92ImPgzxmY6yig2X1UhJ9aYQFk9N5JJGzqjrP-pum9d5ptpPtKe7Ql9MAIobhqoXv5M2shmplph_k52z36Dv0wNF327iYKS1j&amp;uniplatform=NZKPT&amp;language=CHS","pages":"124-132","volume":""},{"id":1767,"author":"胡译文","title":"君子之器——陕西蓝田吕氏家族墓出土仿古敦研究","abstract":"以往关于北宋士大夫古物研究的讨论主要集中在观念层面,陕西蓝田吕氏家族墓的系统发掘和古器、仿古器的出土,为深入了解吕氏家族的礼制和古器物实践提供了重要契机。蓝田吕氏随葬仿古敦,符合其士大夫身份,并以此标榜自身学识以区别于其他士大夫家族,但在仿古敦的具体实践如材质、形制、铭文等方面又刻意与古敦不完全相同,即在仿古的同时与之保有距离以示敬意,而这正是蓝田吕氏修养德行的重要体现。","categories":["09_其它"],"year":2020,"publication":"艺术学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ05nB-Tg-SVjqeYSMyDuPBLyriY1oS_Fl5Hd9qcIWYvTojk7vW94dctMWABAsGERrHSy8Qn54-O0Exkc0WYl7X1wKUBO7-FWqQInjaXTNtwOk8v0NlLZhzg77pbboihv4KRSriE6rTSoeo3v1j0PBRsYpYnYUscGgVdbHh4Wul17-HWqbPJXHc&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-80","volume":""},{"id":1791,"author":"李霏","title":"阮元摹刻宋拓《钟鼎款识》始末","abstract":"南宋王厚之辑《钟鼎款识》,自南宋辗转流传,屡经鉴赏名家之手,至清嘉庆七年(1802)归阮元积古斋收藏。阮元对册中款识重加考释摹锓,于是年秋刻成《宋王复斋钟鼎款识》一书。阮元考释具有续成王氏之作的意义,并增加了其学术影响。考释摹锓此册的过程,又衍生了阮氏一部重要吉金著作《积古斋钟鼎彝器款识》。本文重在对摹刻背景、阮元题识内容作出论述,次则尝试从乾嘉之际金石鉴赏、两浙金文研究等角度,对阮氏积古斋影刻本提出一点思考。","categories":["09_其它"],"year":2020,"publication":"艺术工作","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIaxhAi2hlAt0kD6czxDPeUMhDqV3tH_aQgMnHveya2f0Hi8EzH2REj7EhrfXe8o8g5VJvb5OL2Iq88dqmVmJmFOhyoH4mDJ4_Hx1yf6soxiPHQ1-rBNGE6DHg96rFiOGcEqpsLYVwh1zxZOyak9E4IxPrDbqjjiDlf-HzXRVQDBc6wk_lLPASV&amp;uniplatform=NZKPT&amp;language=CHS","pages":"66-80","volume":""},{"id":1803,"author":"张晓梅; 谭中华","title":"汉字多元视角取象特征分析：基于手语与汉字的比较","abstract":"汉字与手语是人类传递信息的载体,同属于视觉符号系统,都具有空间性特质。汉字是一种历史悠久且具有表意特征的象形文字,体现出其独特的观物取象特征。手语是聋人表达思想、进行交际的主要工具,是一种形式和意义结合的视觉符号系统,所体现的多元视角下的取象特征比汉字更直接、更明了。基于手语与汉字的视觉符号性和空间性等共性特征,文本将手语与汉字的取象视角进行比较,使汉字中积淀的观物取象活动凸显出来,指出汉字具有平视、仰视、俯视、流观、复合等多元视角取象特征,并认识到汉字多元视角取象特征的形成与人类在自然界中所处的位置、观物取象的视觉经验、视觉符号的创造、表达意义的需要等因素直接相关。利用手语所负载的信息可以研究更多的汉字问题,为汉字研究提供一种新的视角。","categories":["09_其它"],"year":2020,"publication":"新疆师范大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.14100/j.cnki.65-1039/g4.20200707.003","pages":"121-130","volume":"41"},{"id":1806,"author":"夏国强; 尚振宏","title":"基于自动化剪枝策略的青铜铭文识别方法","abstract":"准确并高效地识别青铜铭文在考古学、历史学、文字学等领域具有重要的意义。构建了公开的青铜铭文数据集,为后续研究提供了数据参考。同时在基于L1范数的卷积核剪枝基础上,提出了一种自动化模型剪枝策略,无需人为设置剪枝比例即可自动完成剪枝操作。实验结果表明,以LeNet网络为基础模型,剪枝后的参数量和FLOPS仅为原模型的30%和69%,准确率达到97.62%,所提方法适用于青铜铭文数据集。","categories":["09_其它"],"year":2020,"publication":"激光与光电子学进展","link":"https://link.cnki.net/urlid/31.1690.TN.20200601.1709.123","pages":"257-264","volume":"57"},{"id":1809,"author":"李忠林","title":"“第二届西周金文与西周史国际学术研讨会”简述","abstract":"2019年9月21—22日,由中国先秦史学会和陕西师范大学共同主办的第二届西周金文与西周史国际学术研讨会在陕西西安召开。与会学者共提交44篇论文,从以下6方面展开深入研讨。1.西周政治、礼仪、军事制度。王晖《从金文册命赐旂礼看西周爵位制》全面","categories":["09_其它"],"year":2020,"publication":"中国史研究动态","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKYOTqefkGIbEI-HYR4f5oBlVhioWptGFluxbFbt0pK9WDJpDirPVOImqawry5_gnOT_QHkOSBhkqK94GPBFPf-G3iXi1vGXFQ3M93GnGHSke0ANPZkEI-z9qka0zxQHN1kw3BUsnmBeoAWK0U7enpp8AogGuRippeXmXdyLdbcSUMlSKbNSZfQ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-64","volume":""},{"id":2188,"author":"邓珍; 程邦雄","title":"郑珍文字学之研究","abstract":"郑珍是晚清著名的文字学家和诗人,目前学界对郑珍的研究大都集中在诗歌创作方面,对于郑珍在文字学方面所取得的成就并没有进行全面深入的考察和研究。本文在全面观照郑珍文字学著述的基础上,选取《说文逸字》和《说文新附考》作为主要研究对象,结合个字与同时代、同类型的他书进行对比,总结其文字学研究方法,挖掘其主要文字学思想,对郑珍的文字学研究做了相对全面的考察。我们认为,郑珍的《说文逸字》和《说文新附考》代表了清代逸字和新附字研究的最高水平,郑珍的文字考证方法是文字学研究方法变革史上不可或缺的重要一环,郑珍的文字学思想在近代文字学思想史上应有一席之地。全文分为六章,除去第一章绪论和第六章结语,主体分为三个部分。第一部分是郑珍文字学著述的内容研究:第二章和第三章分别对郑珍《说文逸字》、《说文新附考》的内容做了详细的归类研究,并与张鸣珂《说文佚字考》、钮树玉《说文新附考》进行了对比研究,在此基础上对各书的学","categories":["09_其它"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27157/d.cnki.ghzku.2020.007414","pages":"","volume":""},{"id":2192,"author":"徐世平; 华人德","title":"金石拓片题跋中设计因素的研究","abstract":"本文研究的主要对象是金石拓片,在金石学产生、兴盛、发展、复兴的过程中,拓片扮演着极为重要的角色。拓片不仅为金石学研究提供了史料,也是古人临池的范本类型之一。随金石学而兴起的拓片题跋,从最初的卷册形式为主,到清代乾嘉金石学复兴、碑学兴起,整纸拓的题跋、悬挂、欣赏,逐渐成为新的时尚。历来对于金石拓片题跋的研究,大多偏重于史料的价值,兼及书法品评。而以现代的设计角度来观照这一传统的艺术样式,则有许多新的发现。金石拓片的题跋作品中,拓片是主,题跋为宾,围绕拓片展开的题跋,毫无疑问是学术和艺术的高度融合。通过对宋、元、明、清、民国以来留下的大量金石拓片题跋作品的分析、研究,在看似不经意的题跋中,却蕴含着诸多的设计因素。由此可知,拓片本身既有金石的设计基因,又有拓片的传拓工艺,还有文人为了题跋而预留空间的设计。至于题跋中的设计因素就更加丰富了,从内容到形式,都需要设计。内容包括题跋文体的选定、叙述的角","categories":["09_其它"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27351/d.cnki.gszhu.2020.003653","pages":"","volume":""},{"id":2667,"author":"赵若晴; 王慧琴","title":"青铜器金文图像识别方法研究及应用","abstract":"考古出土的青铜器金文是宝贵的文字材料。准确、快速地了解其释义和字形演变源流对考古学、历史学和语言学研究均有重要意义。本文进行了金文拓片的数据采集与预处理,构建了金文图像数据库;研究了金文字头的字义分类与金文变体精确匹配的识别方法,为文物专家研究金文识别提供科技辅助支持。主要内容包括:(1)青铜器金文图像数据库构建。以《新金文编》等权威文献资料为金文信息采集的原始数据源,研究了金文图像的自动采集分割与预处理方法,实现了原始数据的数字化标准采集;分析了金文、青铜器、字义之间的关联关系,基于关系数据库的原理,设计了汉字--金文--青铜器数据之间的ER关系,构建了IB数据库对青铜器金文数据进行标准化存储。(2)基于混合特征和SVM的金文图像字头分类识别方法研究。针对单一金文特征无法表征金文问题,研究了混合特征的青铜器金文图像字头分类识别方法。针对当前金文图像样本较少不利于分类器训练的问题,基于金文","categories":["09_其它"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27393/d.cnki.gxazu.2020.000954","pages":"","volume":""},{"id":2677,"author":"王鑫彬; 党懷興","title":"容庚文字學理論研究","abstract":"研究上世紀著名文字學家容庚的文字學理論,目的在於提煉歸納他的文字學理論和思想,並將其與其他文字學者的理論進行比照,以求客觀地總結其在文字學史上的貢獻和不足。除緒論和結語外,共五章,分別從不同的角度對容庚的文字學理論進行歸納和述評,具體如下:第一章是容庚生平及其著述,重點介紹《中國文字學形篇》《中國文字學義篇》《簡體字典》三部著作。第二章是容庚字體分類研究。容庚將漢字字體總的分為古文、小篆、隸書、正書、草書、行書六類,其對每一類都有界定和論述。總體來説,其分類原則是合理的,界限是明晰的,但是在具體小類的細分上,他也存在一些問題,比如大類名稱和小類名稱都使用古文這個名目,這在邏輯上造成混亂,此外,對於繆篆的歸類也不夠妥當。第三章是容庚六書理論研究,分為兩部分。第一部分是提煉容庚對六書各書的看法,主要是從定義、分類以及收字幾個方面去加以考察,發現雖然偶有新見,但基本上還是沿用舊説界定六書,其分類","categories":["09_其它"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27292/d.cnki.gsxfu.2020.002506","pages":"","volume":""},{"id":2681,"author":"张新华; 谢尧亭","title":"大河口墓地与横水墓地出土青铜器垫片技术研究","abstract":"垫片,也有人称作金属芯撑,是指利用范铸法铸造青铜器时,设置在范、芯之间的金属小片,用以支撑、固定范与芯或者芯与芯。本文以大河口墓地和横水墓地出土的青铜容器为研究对象,通过实物观察以及X光射线成像技术等,仔细分析了两个墓地青铜容器垫片设置的方式。并依据观察结果,细致的讨论了垫片在青铜器铸造中的作用以及垫片设置方式发生变化的原因,并且与西周时期其他地区的墓葬、遗址出土的青铜器垫片设置方式进行了比较。研究表明,大河口墓地与横水墓地青铜器垫片技术使用非常普遍,且大部分器物设置规范,且某些器类垫片的设置方式存在时间上的变化。西周早期,三足器中鼎底范垫片的设置方式主要有两种,在器底中央设置1块,或者在三足连线中心的位置各设置1块。西周中期,鼎底范垫片出现靠近三足设置的方式。其他三足器自西周早期开始,底范垫片就设置在三足附近。西周早期三足器腹壁垫片还不算普遍,大部分只有零星发现,只有横水墓地两件鼎腹壁垫","categories":["09_其它"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27284/d.cnki.gsxiu.2020.000863","pages":"","volume":""},{"id":2685,"author":"侯孟琦; 李春利","title":"先秦时期天下观研究","abstract":"“天下观”作为一个庞大的思想体系,包含了哲学、政治、地理甚至是宗教的观念。要了解它的产生和发展,显然要从寻找它的源头开始。在先秦时期文字记录和口耳相传中,保留了许多古人最原始的“天下观”。本文按照“天下观念”的萌芽、形成和演进的发展顺序,对先秦时期的“天下观”进行了整体考察。试图在抓住从西周到春秋战国间“天下观”的具体表现和细节变化的同时,努力将先秦时期的天下观念与后期“大一统”局面联系起来,揭示天下观念对夏商周三代历史演进的影响。首先,第一章从“天下观”的萌芽期谈起,西土意识和“天命观”的产生和发展是推进西周时期“天下观”最终形成的重要动力。此时周人的天下意识还很模糊,只是迈出了自我认知的第一步,以为所见即是“世界”。他们在有了“天下”的概念之后,才逐渐把所谓的“中国”和“四方”凸显出来。如此一来,此时的“天下观”既包含了王者居中的意志,又突出了内外区域和秩序的差别。但无论是此时的“中央","categories":["09_其它"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27212/d.cnki.glnsu.2020.000958","pages":"","volume":""},{"id":2688,"author":"李明辉; 张国强","title":"先秦乐律学若干问题再议","abstract":"本文以先秦文献与出土文物为依据,对七律、正声、中声、曾钟八度分组术语、奉五声等先秦时期的乐律学问题进行思考,在已有研究的基础上提出一些新的见解。本文认为,“七律”为定律之律钟,曾侯乙编钟、编磬上的蕤宾、嬴孠、韦音、应音、姑洗(宣钟)、穆音(太簇)、浊姑洗为律钟所定七个律高的名称,在层次上高于各国律名,并且在各国之间通用。先秦时期的“正声”,在音乐型态方面应为“徵、羽、宫、商、角”五声,为阶名,音高并不固定,并无八度分组之意。“中声”则仅限于“中音区”的“徵、羽、宫、商、角”五声,音高固定,具有八度分组之意。而“正声”“中声”皆有中正平和的美学含义,体现着先秦时人的音乐观念。对于曾侯乙编钟中无前缀、后缀且处于适中音域的“徵、羽、宫、商、角”在八度组中的命名,应为“中声组”,而不为“正声组”。“奉五声”一句中的“五声”是弦上取音所得到的“徵、羽、宫、商、角”五声,并非音阶范畴,前提为弦上取音,","categories":["09_其它"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27114/d.cnki.ghnau.2020.000070","pages":"","volume":""},{"id":2714,"author":"陈笛; 郑岩","title":"从学术到艺术","abstract":"本文的研究对象是清中期以来出现的拓片与绘画结合的“博古图”。不同于以往对于这类图像的诸多讨论视角,本文关注于这类作品中拓片的表现方式和对其进行观看的方式。文章第一章是对拓片的学术传统及背景的梳理:作为一种记录和复制手段,拓片是金石学中对文字、图像著录的产物。清代全形拓的出现,使得立体的古器物形象也可以以拓片的方式呈现,由此体现出、也进一步促成了对拓片观看方式的转变。第二章开始进入对具体图像的讨论。以晚清六舟的作品为代表,在对图像进行细读和具体创作情境梳理的基础上,分析其中拓片的不同表现方式,及其在画面中作用的方式。在这类作品中,来自金石学领域的拓片成为主要被观看的对象,且体现出与学术领域中的拓片不同的表现方式。本文的最后一章,是对图像中所呈现出的部分问题的理论化的探讨。首先,拓片与绘画结合的“博古图”的出现,某种程度上是对拓片的不同于以往的观看方式下的产物;而在这种出于视觉审美的观看方式下","categories":["09_其它"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27666/d.cnki.gzymc.2020.000154","pages":"","volume":""},{"id":2744,"author":"杨文昱; 周宝宏","title":"张亚初先生的古文字学研究","abstract":"张亚初先生是当代卓有成就的古文字学家,学术造诣颇深,尤其擅长金文研究,在学术界有深远的影响。本文以张亚初先生研究古文字所取得的成就为研究对象,系统论述了张亚初先生在甲骨文考释、金文考释与研究、青铜器及历史文化研究、汉字理论、有关专著等方面的成就。文章共分为五大部分。第一部分为“绪论”,主要介绍了张亚初先生的生平和主要学术成就,国内研究现状,研究内容、方法、目的及意义。这一部分内容,对张亚初先生的求学经历、工作经历以及学术活动的特点进行了简短的概括。第二部分为“张亚初先生的文字学考释与研究”,是本文的重点章节,分类讨论了张亚初先生在甲骨文考释、金文考释与研究、青铜器及历史文化研究等方面的成就。在甲骨文考释方面,本文介绍了张亚初先生对甲骨文中“铸”、“(?)”、“挞”、“讯”等字的理解;在金文考释与研究方面,本文介绍了张亚初先生对金文中“免”、“(?)”等字的考释成果以及对多友鼎、太保罍、作册","categories":["09_其它"],"year":2020,"publication":"","link":"https://link.cnki.net/doi/10.27363/d.cnki.gtsfu.2020.000344","pages":"","volume":""},{"id":3025,"author":"李峰; 王一义","title":"西周国家","abstract":"前言如果有人要指出中国历史上持续时间最久的王室,那一定是周(公元前1045—前256)。即便周朝辉煌的一页已经揭过,&quot;周&quot;的名称仍然承载着可观的尊严,并曾经成为五个政权尊奉的王朝名号。在长达857年的时间里,这些称为&quot;周&quot;的政权或统治近乎整个&quot;中国&quot;,或控制了它的很大一部分地区。对于孔子及其追随者来说,西周时期(公元前1045—前771)是文明史上的黄金时代。但西周国家相对较早地开始衰退,并长期受到内在和外部持续的政治压力带来的困扰。周朝一系列独特的政治和礼仪制度被不同人群融合而成的居民所接受,逐步形成了一个文化系统。","categories":["09_其它"],"year":2020,"publication":"法律史译评","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI5RgVh763um8FyHQ2sTS8gzl_vwG_EQETVloTC2v5btstfHBDPC2HpRbb9BRyoX9SxM5zsduJbYF9tdXG99BhY-N1p38BXbUrz_THZF1dpdFdJv97Fpe577UrBtIgq_7e1jdYZQyrKpWj-Y73qP5fObUCEfTbahnS2DUrvlcCNpw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46046","volume":"8"},{"id":3043,"author":"劉浩","title":"東洋文化本源的研究——理解白川静學術體系的一個重要基點","abstract":"白川静（1910-2006）是日本著名漢學家。他是一位筆耕不輟的學者,一生著作頗豐,除學術論文和專著外,還撰寫有如《漢字的世界》這樣的通俗讀物。晚年爲推廣漢字而編寫三部字書——《字統》《字訓》《字通》,皆獲大獎,[1]在日本的漢字研究及推廣上,起到了巨大的影響和帶頭作用。[2]白川静的漢字研究在日本影響極大且自成體系,被譽爲&quot;白川文字學&quot;。","categories":["09_其它"],"year":2020,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJp_tU_WzZG8ehepi6XjqJOaub1ii_yG9D8rVdqeKHPj3c-BKogamNAKxrn887dU8nPxiOsseao7z3fvMNP_t5WD1U-bs6Ykk76D1U8i9npX79FYU43mWR34ev4WsJUYHF7bwkD7bKa1NzUChx9uEsMTrsvewPfWdK-HwAMxhzXUw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"175-188","volume":""},{"id":3067,"author":"李红薇","title":"近代金文拓本所钤印章的几个问题","abstract":"金石文物收藏,往往聚散无常。金文拓本多钤有收藏、鉴赏的印记,表示曾为某人考藏、审定、鉴赏、经眼①。这种印记与藏书印类似,或可称为藏拓印、鉴藏印。印章种类繁多,印文长短不一。大体可分为公家印章、私人印章两大类。公家藏印,如&quot;宝蕴楼藏器&quot;&quot;故宫博物院古物馆传拓金石文字之记&quot;,表示曾属公家某机构收藏。私人的藏拓印章,又可分为名号印、堂号印、箴言印、图像印等。","categories":["09_其它"],"year":2020,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKZOCi9BTQmRtZC9h8xRUxesBO8mYWj32wIOA3Bhh7Vh3G8Xnc9tdNukyzNOSYCJ4IaQU4r3jfBs0pyse_eSGIv8knz7QHjpX1OSDS3CHhGX1whA1pUoKiRxX-KphYXH_KG0osGcyVo6x4UA23Jb8fzmSaO8ayYFQC_s_at-4ae4g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"665-667","volume":""},{"id":3093,"author":"斯彦莉","title":"恐以赝器校正史——章太炎先生题注清宫旧藏新莽嘉量全形拓片考","abstract":"杭州章太炎纪念馆藏有一件清宫旧藏新莽嘉量铜器的全形拓片。章太炎在拓片上书大段关于&quot;新莽嘉量&quot;的考证文字,指出1924年紫禁城再次新发现的&quot;新莽嘉量&quot;有三处疑点,推断该器并非时人认为的新莽原物,而是后朝根据《隋·志》文献制作的仿制品,恐&quot;以赝器校正史&quot;。从这场关于新莽嘉量铜器鉴定讨论中,可探究章太炎源自乾嘉考据一脉,对金石文字的严谨态度。","categories":["09_其它"],"year":2020,"publication":"杭州文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK5UmvmsnDkvBR3qawmy-_janLwG0EHbpHg5Vdvfi8gSNzcBez7GKzsoowOylguGW72ZyujHupH5PX0VgO-iiBON8Gfp0aE5NjRUojn9LRWt0CjTfZS1UnmoSpAfBvtA8UlkXg9HFKpI9miLOjGzLtQa4D_AOrXmCsBOdVRbStnjA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46065","volume":""},{"id":3707,"author":"顾万发","title":"乾隆御藏一件西周早期四足铜簋的图像学","abstract":"《西清古鉴》曾经著录一件乾隆御藏的四足铜簋(图1),在佳士得拍卖行等一些拍卖行拍卖过,价值不菲。实际上,该件青铜器的图像也具有一定的学术价值。该铜簋的耳朵,是一般鼎、簋、罍之耳或牺首所蕴含的常规而又经典的图像组合或构图形式,即神兽食神鸟纹样,虎食人卣或其他铜器以及陶器之虎","categories":["09_其它"],"year":2020,"publication":"黄河.黄土.黄种人","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKkRPEknvsgsvOeBgDB6SBME9QIDId1fnGxozxPACznNL1dTPKCozz8Y3rgIwnB5j9gOtAfuWuNTJefYd6xCTTbmuGJC0XKrh1dkStPbm285JpA8d12ldbZyd02iYedv7X9Mutclaw1TKPWTkWAajiMHaGOTKLWo6b_t-SVgwBTZDdEcRswE7ax&amp;uniplatform=NZKPT&amp;language=CHS","pages":"58-61","volume":""},{"id":1723,"author":"刁筱蓉","title":"浅谈《四库提要》对《钟鼎字源》的评介","abstract":"《四库全书总目》是我国现有最大的官修目录书,所收3万4千余种提要,皆为当时著名学者所撰写,至今仍是学术研究的重要工具书,通过研究《四库提要》对《钟鼎字源》的评介,有助于我们更准确地把握《钟鼎字源》在古文字学史上的地位,也有助于对《提要》加以拾遗补缺。","categories":["09_其它"],"year":2019,"publication":"汉字文化","link":"https://link.cnki.net/doi/10.14014/j.cnki.cn11-2597/g2.2019.24.012","pages":"24-25","volume":""},{"id":1730,"author":"李斌","title":"“十七年”期间郭沫若古文字学著作的修订重版","abstract":"郭沫若在流亡日本期间,曾撰写了十余部古文字研究著作,在学术界有着重要影响。但这些著作印量不大,且多数在日本出版,故而查找不易,加之有些观点需要更正。&quot;十七年&quot;期间,郭沫若在学界要求下,将这些著作增订再版。金文著作的再版得到容庚、陈梦家等人的帮助,甲骨文著作的再版得到于省吾的帮助。","categories":["09_其它"],"year":2019,"publication":"郭沫若学刊","link":"https://link.cnki.net/doi/10.16142/j.cnki.gmrxk.2019.04.016","pages":"68-74","volume":""},{"id":1731,"author":"丛文俊","title":"吉金丛谈·乖伯簋","abstract":"乖伯簋,西周中期恭王时器,出土情况不详,吴大澂、郭沫若等学者均有著录,今藏中国国家博物馆。器铭十四行,行十至十一字不等,共一百五十字,其篇章布局疏密有差,带有一定的随意性。西周金文是向成熟大篆演进的一个重要阶段,新旧两种因素俱在,呈现出自由、变化、生动的书法状态。它们少了许多古形的质朴容颜,也少了若干习见的标志性字形、偏旁的修饰和肥笔,写意增加,曲线美在被关注和强化,","categories":["09_其它"],"year":2019,"publication":"艺术品","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLO44k3nEy5SuS2owYf3GDFn86sSvau0c7b89ZkPHHYj2V93rM87nYDjSNv0KRibjeGe5Ffd4_jDGEytFHDdG4BdgWKaGIvkKpJqSYST5l0k1x2gHtYl6j97hq0GxV7jS3WBW_XoAvzOY4WZlbGMkuQvAS8fExaRxgeU__-VmMNsaO4lClQ0k_p&amp;uniplatform=NZKPT&amp;language=CHS","pages":"56-60","volume":""},{"id":1740,"author":"赵伯雄","title":"王玉哲与《中国上古史纲》——“南开百年名家名作巡礼”之九","abstract":"壹先师讳玉哲,字维商,河北深县人。生于1913年,卒于2005年。先生系农家子弟,早年曾接受过当时的所谓新式教育,在高中阶段,就对文史产生了浓厚的兴趣。1936年,先生考入北京大学历史系。在北大期间,受顾颉刚、钱穆等先生的影响,逐步走上了古史研究的道路。不久,日寇全面侵华,平津沦陷,北大、清","categories":["09_其它"],"year":2019,"publication":"博览群书","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ4dNj7Bnt_cYLJCXAeD9s5kCRfi49Kvn3lmPYbxH3G6iFDzIjL308Bm2_ljOAw9swOumDkOxUaceVOZjmicVUTTV2EdRj3HMSM19Sb_AVBsN7HGkJuje3XSguxfFavnevrE59dJWOWSCL4-lMyr3wCHYedqJN8QSzoDN8C9i3aXi0liXEfneKj&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-63","volume":""},{"id":1741,"author":"连秀丽","title":"两周铭文与中国古代文体发源","abstract":"随着青铜器的大量出土,现已发现两周时期百字以上铭文400篇之多,其中最长的一篇《毛公鼎》铭文长达499字。这些长篇铭文记事完整,叙事清晰,语言简炼,其中可见早期中国文体的发源情况:青铜铭文中祈福的嘏辞,是祝体文学的发源之一;两周时期的&quot;诰&quot;体铭文,与《尚书》六体之一的&quot;诰&quot;体的写作内容和行文方式是一致的;西周中晚期册命制度的建立,催生了&quot;命&quot;体铭文的成熟并形成模式化的写作方式;&quot;铭者自铭&quot;,铭文的颂赞本质是中国早期&quot;颂&quot;体文学的活头源水;铭文的箴刺鉴诫功能为古代&quot;箴&quot;体文学的发展提供了方向。两周铜器铭文以其记事的生动丰富和写作的不同方式,成为中国古代不同文体的滥觞。","categories":["09_其它"],"year":2019,"publication":"齐鲁学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK1KRRqFMC__bDRAMqAY8rCkoe95HKzfB23bIJlwIDze5uzij8lHuy-x68ehTrXmhRR6N4opxVxfHNXmJEAn7RYdUchVLSoXPNAIup39FhRmXqvgPyrlAqoH5eIRashtsAFJVyB8FDnJBqF4CVghPj_3s9Wt4CQ-OCGFbTxbeJIkYpIzZi2ITbU&amp;uniplatform=NZKPT&amp;language=CHS","pages":"118-126","volume":""},{"id":1823,"author":"叶庆兵","title":"原始崇拜视野下的殷商金文图像","abstract":"殷商金文中存在着大量的图像,这些图像还未发展成文字符号。这些图像,普遍与&quot;X祖(父)某&quot;的文字内容构成整体,当不是随意刻画,其与铸造者的祖先有关,很可能是部落图腾的标志。此类图像,还常常复合组成新的图像,这又与部落兼并、联合后图腾的组合有关。殷商金文中还存在一些变异的图像,其与日常生活中的实际事物已有一定的距离,而与神话中的形象近似,也应是原始崇拜的产物。","categories":["09_其它"],"year":2019,"publication":"商丘师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIaGAL87RBtAm3zD7gP7zEjuvBV9Ig6_MasA7QTBCwBcphRdjGsq5uyQUw4seR11wzh8t92r62qmR2YgGpHgSdFLwXNzaYU_7AFWOHzwdSwcvvg00tlrMEMCnBHUmdzqcwHNhz5GKvh20e8r4dXPqUV1EQ7GAYXC44NFaCfi1zEM00ru1HUCS1l&amp;uniplatform=NZKPT&amp;language=CHS","pages":"43-48","volume":"35"},{"id":1827,"author":"苟家容","title":"由出土文献看先秦“德”观念的演变","abstract":"&quot;德&quot;是中国思想史中较为重要而复杂的观念。由于受社会政治以及思想文化的影响,&quot;德&quot;在先秦不同历史时期呈现出不同文化内涵。具体而言,先秦时期&quot;德&quot;观念主要经历了殷商时期的&quot;天德&quot;、西周时期的&quot;政德&quot;以及春秋战国时期的&quot;人德&quot;三个阶段。当然该阶段的划分并非界限分明,后一阶段虽有新特点,但仍然或多或少地保留了前一阶段的相关内容。这在甲骨文、金文以及简帛等出土文献资料中均有较为直接的体现。","categories":["09_其它"],"year":2019,"publication":"职大学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJEgTtNnXrFEMEPGnrAk8TO9eYzZ1w2SyO-3deVdmYOcl8cDIY00XJt6Uhmtsp3kV-yzwgqYI1dShB8hjDrPGqULqBICLDDdc4DZQn91EKJox45HZXis7cGsWihhVsjBDHyY77UPUiZ_he9N7moDV0ZsCB6EDhmLK0XXJCHvPRviC1UYb8A3taX&amp;uniplatform=NZKPT&amp;language=CHS","pages":"111-115, 120","volume":""},{"id":1830,"author":"钟发远","title":"汉字结构中的亲情关系","abstract":"汉字作为记录汉语的书写符号系统,以其独具特色的结构形式和演变轨迹,生动而系统地表现了中华传统伦理中极为重要的亲情关系。这种亲情关系包括父母对子女的养育和爱护,也包括子女对父母的赡养和孝敬,还包括具有泛爱性质和交互性质的爱。汉字在表现这些爱的时候总体上是各有专责的,但也有个别特殊复合结构如&quot;字&quot;字呈现出有别于其它字的词义融汇特性和表达张力,以至于它可以将中华民族从血缘纽带到亲情关系的主要线索勾勒出来。","categories":["09_其它"],"year":2019,"publication":"汉字文化","link":"https://link.cnki.net/doi/10.14014/j.cnki.cn11-2597/g2.2019.20.003","pages":"46086","volume":""},{"id":1841,"author":"冯时","title":"西周以刑辅德思想的启示","abstract":"历史研究的重要意义在于为今日乃至未来的发展提供借鉴。西周社会崇尚道德,孔子赞之曰&quot;郁郁乎文哉&quot;。西周金文显示,西周社会所崇尚的道德的核心在于诚信。与此同时,西周还视刑德为一体,以刑辅德,标准既高且严,这对于形成&quot;郁郁乎文哉&quot;的社会是至关重要的。汲取西周以刑辅德思想中的合理因素,对于我们今天把社会主义核心价值观融入法治建设、坚持","categories":["09_其它"],"year":2019,"publication":"智慧中国","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKJ6zFZylGuOn3PIX8R9ul-fU66DuL6UTPhXNM3ZL3R1aEHgr6NHeAM4lNmpZoKDzNuPY21weAOzu4L2LKnFD6lQnpkwkjPWwClLpLXbyLenW1W6-eLgj7XlHj-BVpltbejjD7eUFldvhUASlnXYyWQyz_vKlXxO5b5Jl74LdL4h-CWn0mayL2o&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-71","volume":""},{"id":1851,"author":"孙璋","title":"观心堂随笔","abstract":"商周金文,灿若星辰,线形多变,境界苍茫,风格、形式多样,不自觉,非理性,集天然与人工于一体、无我与有我共存,自在、优美、生动,取其中一派,便可自成一家。黄宾虹以&quot;礼崩乐坏&quot;之春秋战国为重心,自成一体。西周金文,混凝厚重,大小随意,穿插自由。东周(春秋、战国),诸侯争霸,王室衰微,列国争战,地域分散,金文风格华丽斑斓。","categories":["09_其它"],"year":2019,"publication":"中国金融家","link":"https://link.cnki.net/doi/10.19294/j.cnki.cn11-4799/f.2019.09.058","pages":"135-136","volume":""},{"id":1852,"author":"韩腾飞","title":"浅谈文物与文字之间的关系","abstract":"文物是历史遗留下来的产物,它见证了一个时代的兴盛和衰败,为我们解读历史提供了重要的依据;文字是一个时代特有的标志,它随着历史的发展而一步步演变至今,是我们表达情感、记录生活的重要方式。而文物在历史遗留的过程当中可以反映出文字演变发展的过程,通过解读具体的文物,我们可以很直观地观察这些文字,通过具体的文字来发现文物背后的历史。因此,将文物与文字建立起这种关系对于我们还原过去的历史、解读现在的社会有着很重要的意义。","categories":["09_其它"],"year":2019,"publication":"文物世界","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL_rVuq1N3OYzsxkV_syZShQj-4TMoTVhw__Q9jjI8DFgNEqn8M5NusbHgA83X_HfPPBko2Uc_axxNbjhCT-B7FkDfHtjIte0H-9yfj69by_ynE9tLvyGGpqOc9CO-CSrryuwIQFR-7Wzr02TaEXBdjLwkPo3zlyKEKcszYogfVQlNquOKjYank&amp;uniplatform=NZKPT&amp;language=CHS","pages":"57-59","volume":""},{"id":1867,"author":"陈光鑫","title":"燕世系研究的学术史启示","abstract":"燕早期世系是一个&quot;千古之谜&quot;,虽然郑玄等经学大师提出过种种解释,但直到20世纪50年代,陈梦家、唐兰等学者通过金文研究才切实推进了相关认识。这一问题的学术史给燕国史研究带来诸多启示,持续关注和思考基本问题,系统而科学地整理基本材料,重视学术史的梳理,把握新材料的价值,燕国史研究在&quot;京津冀一体化&quot;国家战略的实施过程中定能有进一步的发展。","categories":["09_其它"],"year":2019,"publication":"洛阳师范学院学报","link":"https://link.cnki.net/doi/10.16594/j.cnki.41-1302/g4.2019.07.013","pages":"56-61","volume":"38"},{"id":1877,"author":"吴盛亚","title":"录尊真伪再考辨","abstract":"录尊现藏于台北故宫博物院,其真伪迄今仍无定论。容庚曾认为此器乃卣之有铭残底而镶入无字尊内。但这个意见并未得到公认,近年来也不断遭到质疑。台北故宫博物院一直未公布录尊的X光射线透视照片,学者的讨论多基于对器物外部的观察,存在一定的主观性。本文采用版本学的思路,对录尊的收藏与流传历史进行梳理,共勘校十一种铭文拓本,考察其各自产生的时间及彼此的因承关系,发现拓本可以截然分为两类。而只有原器损毁,有铭文的卣底镶嵌到尊内这一过程,才可能导致两类拓本之间差异。","categories":["09_其它"],"year":2019,"publication":"文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJxXYt77OYTm8V8KGmNX5ArRSAOlu9uxjc7TpDr5Q4D3U6Z01Yr7QAj67SglRv0Wlo0n4kZO77LAo4LqMXlii_mXuXKjC4reqrHw9jYG6bZDxbHkzeIkd8MR_GBYshHUh9X_GkMdD2AWNnOmeygvPwaQ4rhNYFjxXuotMRFGaxIvb3Kr-Y4JDFb&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-85","volume":""},{"id":1904,"author":"潘建明","title":"周钟综述","abstract":"周钟是指钟口向下悬挂敲击的悬钟。周钟是周人的创制,使用范围以陕西关中地区为中心逐渐传到各地,反映了以周人为主体的各民族间文化的互相交融和影响。其通行时代大部分在两周,上下长达千年,春秋战国间是其发展最为辉煌的年代。文章对周钟源流和它在古代仪礼乐器史上的地位,钟的各部位名称作用及发音原理和音阶乐律,进行了综合论述。这份四十年前的工作笔记,真实记录了当时历史条件下对周钟的部分研究方法和认识过程。","categories":["09_其它"],"year":2019,"publication":"黄钟（武汉音乐学院学报）","link":"https://link.cnki.net/doi/10.19706/j.cnki.cn42-1062/j.2019.02.005","pages":"50-67","volume":""},{"id":1924,"author":"刘月","title":"商周青铜器铭文:中华美育之源","abstract":"商周时期是青铜器功能价值转型的重要时期,本文基于商周时期代表性的青铜器铭文研究中华美育源头的内涵,探讨尊礼尚德、人文化成、天人相和等美育要素在商周青铜器铭文中的体现,对美育在新时代的重要意义提出个人的见解。","categories":["09_其它"],"year":2019,"publication":"文化学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKNFaBTK1GYTcicuaY5xa8ap_oIjlmSqtvP02jR46MazUp6cSWVK0ylGyDK27LTOYd_fjNB7l4u7442bqkqCjCvXM8fOlZru0-KyJOySZfDX2FZ-70sSMflRviDHJ7ZHvMm_ySKYasM5QMnjbjg-6YxrmkFwKnETeZyPHUOteklzM1O03uUTH91&amp;uniplatform=NZKPT&amp;language=CHS","pages":"216-219","volume":""},{"id":1951,"author":"俞珊瑛","title":"六舟拓周伯山豆考","abstract":"道光十六年(1836)初,六舟经吴廷康引荐,与程木庵相识于杭州。同年二月,应邀赴新安传拓程氏铜鼓斋藏历代金石器。此后,六舟分别在道光二十年(1840)、二十一年(1841)、二十二至二十四年间(1842～1844)数度赴徽州,为程木庵传拓古器物,数量颇可观,其中就有一件&quot;周伯山豆&quot;。一、&quot;周伯山豆&quot;及定名见于《钟鼎插花图轴》(图1),纸本,纵103、横32厘米。钱镜塘旧藏,现藏浙江省博物馆。画面为&quot;周伯山豆&quot;拓片,上绘设色菊花、折枝梅花。其下题跋:&quot;周伯山豆,是器藏新安程氏,款字倒制,其文曰‘伯山父作尊豆万年宝用’十字,乃器中之仅见者。道光丁未清明节,","categories":["09_其它"],"year":2019,"publication":"收藏家","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL7-_TBRPnX3Ym6Rgfw7cm3we-CUvzTJ1sRB7v2sqGfEDdICVK-cAHyXyy0Jj1_MTOlSCpOGoW-LndbEG3FkffgHw6mZ9e2Qnxhc7m1IzeVY2cPyqZ8hmahEIwvZGHC2HHXTC8sHNgs9KpkJflYxJ1zagb9Z17OeH0_RWnPaTyZ3I55v2MGpUFr&amp;uniplatform=NZKPT&amp;language=CHS","pages":"85-88","volume":""},{"id":1955,"author":"董睿","title":"20世纪以来两周青铜礼器研究综述","abstract":"两周青铜器是中国青铜器发展由盛至衰的转型阶段,20世纪以来国内外学者从青铜器分期断代、区系类型、铸造工艺、礼制、器主身份考证等方面入手,取得了较为丰硕的成果;但是推进两周青铜器的研究,仍需从研究对象、研究方法和研究思路方面深入拓展。","categories":["09_其它"],"year":2019,"publication":"博物院","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIoOE54pNtmp1FZqCIncFcPg0oisqYXyegX0iQpgBTpq-ykNnDwR9H6_XSZ0XXEDlBHN1nPvs06xpnbzRRuu0hFmd2p6BTiYk6Z8hONCFWc-mclxfA5WcamRrGWjw2oBlSbA_YMcXEuV4On3XJjXLpiDmHmFnIbem2UHkPCqzSPRYj4H7Jq1Qbo&amp;uniplatform=NZKPT&amp;language=CHS","pages":"57-62","volume":""},{"id":1964,"author":"孟璐茜","title":"妇好鸮尊所属的鸟兽形尊的源流及其文化内涵","abstract":"妇好鸮尊是现存鸟兽形尊中的精品,其独特的神韵和精湛的铸造工艺反映了妇好在华夏民族延续中所具有的重要历史地位。鸟兽形尊的源流和纹样,证明鸱鸮形象在殷商时期重大政治生活即祭祀活动中的重要地位。器物上呈现的纹样,不仅仅是审美表达,更包含着宗教和文化的含义以及对神明象征的崇拜。通过对鸮尊形象所呈现的不同文化背景进行分析,发现鸱鸮形象代表的不是不祥之鸟,而是骁勇善战的神秘力量。","categories":["09_其它"],"year":2019,"publication":"郑州航空工业管理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.19327/j.cnki.zuaxb.1009-1750.2019.01.008","pages":"59-66","volume":"38"},{"id":1965,"author":"喻遂生","title":"甲金文东巴文比较研究札记三则","abstract":"甲骨文金文和纳西东巴文是不同民族的古老文字,考察二者在如何用表意的方法创造表示声音的字、在古老的文献中写一个字要同时读几次的情况及两种文字竖向和横向延展书写形式等方面的异同,有助于促进文字的研究。","categories":["09_其它"],"year":2019,"publication":"岭南师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKhlqBobuRH1-9kEUIacNhqrOpZrJLmP-GbFhR4nypn4OouVMsbFqpeRSu471jrhMHv-oQaiRvxhjbejIddXSW5GcBFDI-BICMNXoN6dQj5dbnTgccEVI2V_l2pMG0bXvpIQD403Knj3O3AVY8O3o3JhSxi7B40_l-vG9ezQc9PGJc2MmM-XjR8&amp;uniplatform=NZKPT&amp;language=CHS","pages":"80-86","volume":"40"},{"id":1973,"author":"王固生; 王茜","title":"青铜时代——中国青铜器基本知识与辨伪(三)","abstract":"青铜器辨伪的方法1.铸造辩伪夏商周三代青铜器均为陶范法制作,春秋有了失蜡铸造技术,但绝大多数的青铜器也是用范铸法,只有个别形制复杂而镂空的器物,如曾侯尊盘之类用失蜡法铸造。唐宋以后的仿品和伪品则是用失蜡法或翻砂法铸造的。由于作伪人只讲究器物的外形,还不知古人铸造的原理和方法,或为节省成本(陶范法一个陶模只能生产一件)。因此,判别青铜器的铸造方法,观察反映在青铜器上的不同的铸造现象,为辨别真伪提供了主要的依据。","categories":["09_其它"],"year":2019,"publication":"收藏界","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJQgGV2YQ4Dx9dEqzr7j6vrQBi8K9XMdrp7Rj3kRWgJA5sizu37vw6OBpLUNGavve7XKE_GHhb6FKRC6JKgsaghbY1uUw8YGKD17ryhU-oqVHHA15eV2uhBeuqteEJljNZQXHifJy5czloCydDbVg1NFoHxGMwdzIwovLf8IKjdGT0GdUh6fffO&amp;uniplatform=NZKPT&amp;language=CHS","pages":"80-83","volume":""},{"id":1978,"author":"龙红; 黄中","title":"论《愙斋集古图》的文化意义","abstract":"《愙斋集古图》由清代著名金石学家、古文字学家吴大澂等人创作集合而成,具有图像、文字、艺术等多方面价值,本文试图从它的多种性质出发,论析《愙斋集古图》在文化上的重要意义。","categories":["09_其它"],"year":2019,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLgOCDvBy2E-vInSW_6EdjpKD2OIjiQrfygx-6c5YD7bKSngae8CRDe-Tc_iGRfGkGU_qoAET-6BC2hItKT8Jf0MH5LXa-Ws8cZ3R7KuSffGjq51upk7sit8q4KkF5Bc2qFUWuxqhVwSQDwnba2m0EXpNXszMf62FVog1otkb4r_k0iDdTDbbV6&amp;uniplatform=NZKPT&amp;language=CHS","pages":"127-142, 210-211","volume":""},{"id":1984,"author":"丛文俊","title":"吉金丛谈·史颂簋","abstract":"史颂簋,本作颂簋,西周晚期宣王时器,此其盖铭。传世颂器颇多,有颂鼎、颂壶、颂匜等。旧题史颂簋者为西周共和时器,传世共四件,均器盖同铭,共6行63字;颂簋为宣王时器,传世共五种,亦器盖同铭,共15行152字。前后题名不同,而均为史颂所作,余之所临即后者。西周晚期,金文大篆已经成熟,象征礼乐文化秩序之美的&quot;篆引&quot;形式成为正体书法的主流。篆,指","categories":["09_其它"],"year":2019,"publication":"艺术品","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIrHUPB4-CHMIh1QGOCgN0BD6KOn8AWIfoIIzE5g93HKvBYqUIthdpsygycLWlr_q3imgyUjovZWGbcWqOlfdMqpl_gXtoVg6nt9_SFZbn3QDoTcf7dYZITjovD-sHrOzH4GqcX554rc445Q3zWR1og638OJYUeIA0r3jg9El6hInDjVXR77Lmw&amp;uniplatform=NZKPT&amp;language=CHS","pages":"68-73","volume":""},{"id":2202,"author":"金瑞; 徐時儀","title":"《漢語大字典》水部字研究","abstract":"《漢語大字典》是在現代辭書編纂理論指導下編寫出來的一部新型字典,從1975年計劃編寫到1990年八卷本全部出齊,用時15年。第一版出版後,從1999年開始正式修訂,到2010年第二版由四川出版集團、四川辭書出版社與湖北長江出版集團、崇文書局共同出版,又用時10年,卷軼浩繁,體量巨大,堪稱我國語文辭書編纂的標誌性典範,在一定程度上反映了我國辭書編纂的學術水準和文化軟實力。本文以《漢語大字典》水部字為研究對象,結合前賢時彥的相關研究成果,在詞典學、文字學、訓詁學、詞彙學等相關理論的指導下首次對《大字典》水部字整部字從收字、注音、釋義、書證等方面進行全面考察。主要從兩大角度入手,一是從辭書編纂和詞典學角度入手,將《漢語大字典》和《漢語大詞典》等(必要的時候還有《辭源》《近代漢語詞典》)大型語文辭書整部字進行綜合比較,試圖較為先行地發現兩部辭書在收字釋義和書證等方面的問題並進而探討大型語文辭書編纂","categories":["09_其它"],"year":2019,"publication":"","link":"https://link.cnki.net/doi/10.27312/d.cnki.gshsu.2019.000152","pages":"","volume":""},{"id":2204,"author":"周敏珏; 陈振濂","title":"端方及其交游圈的金石鉴藏研究","abstract":"伴随金石学在清代的复兴,对古代金石碑版的收藏与鉴定,成为金石治学的重要路径。本论文以端方(1861-1911)及其金石收藏为考察基点,将端方收藏过程、仕宦经历、他与学人的金石交往结合考察,深入挖掘三者之间的直接关联,探索以端方为中心的金石鉴赏群体的金石趣味、时代特性及文化关怀。端方收藏体系庞大,品类丰富,并以其强烈个人印记的收藏风格与方式,引发了诸多极具话题性的收藏事件,如青铜柉禁的整体收藏,秦权的主题性收藏,多本《华山碑》及《刘熊碑》拓本的序列性收藏等等,这些端方收藏生涯中的标志性事件,奠定了端方在晚清金石收藏领域的绝对地位,也成为他收藏体系中赫赫有名的代表性藏品。同时,端方身边围聚着一个学人群体,他们以金石学为纽带,以端方的金石收藏为依托,通过购藏、品鉴、编撰、研究等一系列文化行为,共同成就了端方的收藏事业,创造出丰富的金石研究成果,也带来晚清金石鉴藏的最后繁盛。而西方新式技术的引入,","categories":["09_其它"],"year":2019,"publication":"","link":"https://link.cnki.net/doi/10.27461/d.cnki.gzjdx.2019.002100","pages":"","volume":""},{"id":2748,"author":"林驰; 孟凡港","title":"清代潍县金石学初探","abstract":"金石学从宋代开始发端,而到清代达到顶峰,在清代中后期,山东出现了众多金石名家,时人谓“金石学在山左”,而其中潍县对山左金石学的贡献最大,呈现出了家族性和群体性的特征,并且著述众多,对当时的学术界也有较大的影响。本文以这些学者的著述、家谱、信札等为基本史料,对清代潍县金石学加以探析。本文主要内容如下:一、清代潍县金石学兴盛的背景。从外部环境和自身优势两个方面,探究潍县金石学兴盛的原因,从而得出这样的结论:外部环境方面,清代金石研究之风盛行,金石大家翁方纲、阮元等督学山东,推动了山左金石学的发展;从自身优势来看,潍县地理位置优越、交通便利、古物众多、经济发达、科举兴盛,加之当时世家大族及金石大家陈介祺的推动,使得潍县的金石学脱颖而出。二、清代潍县的金石世家。本文借助各家的家谱及其他学者的相关研究,探讨以陈介祺为代表的陈氏家族、以郭麐为代表的郭氏家族和以高鸿裁为代表的高氏家族的金石学成就。通过分","categories":["09_其它"],"year":2019,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKPMyC08VWEzpvG2y-c0aPmqUz-54u7zhiUe6-xfRMPkZdcK6JMzErYLrgaMDJypE9W2dpKjp57AvMlvfOD0YUTALQrE26f-8Yh98G3yku5y9pQXWOjN_jH4ZiWJUnvRpQ500aKy6W5vtJAk5kSVMGHYHVCM0TtS_DGdjvmbhHV4Opab7H5pD4v&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2757,"author":"李紅薇; 吳振武","title":"郭沫若金文著作的文獻學研究","abstract":"郭沫若在古文字研究方面貢獻卓犖,其代表作《兩周金文辭大系》依年代與國別科學系統地整理了兩周金文,開創了“標準器”斷代法,奠定了現代金文研究的範式。該書是郭沫若所有學術著作中修改次數最多,持續時間最久的一部,是其金文研究最重要的著作。本文以《兩周金文辭大系》爲中心,參照郭沫若歷史考古著作中相關意見,從文獻學角度對郭沫若金文研究進行整理與研究,梳理其觀點演變脈絡。鉤沉書信、日記等相關史料,著重探求作者觀點變更的背景及原因,盡可能還原郭沫若學術研究歷程。本文主體由六部分組成。一、緒論。簡要介紹古文字學術史研究概況、郭沫若古文字學的研究現狀,分析以往研究中的不足之處,敘述本文的選題意義及研究方法。二、《兩周金文辭大系》成書史及其版本概述。從文獻學角度釐清《大系》成書過程、版本源流及嬗變情況。三、《兩周金文辭大系圖錄》研究。對所收器圖、銘文逐一溯宗考源,輯錄諸版差異,從學術史的角度認識其價值。四、《","categories":["09_其它"],"year":2019,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI0HEJVEbM-1B3UZEQLmCYZwMe01EvmUQitjhoucxpty6jha_n5voQc7p93RQXALBFiFL5SZP94HfWDbP4HNrXcOhaiW8KDWFFMFkcZzIiK2dfLeSOzUJeypnBs5eL9sYz0ERgvgzAzLxtJ_c3Y3TTq3-P4F_zjZBF6gffdw_pxLdb-3TppAQz6&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2769,"author":"李超; 柳建钰","title":"基于字料库的《篇海类编》与《详校篇海》字头比较研究","abstract":"《篇海类编》改编自《详校篇海》,两书在编纂体例、收字数量、注音释义、字际关系说解以及失误情况等方面基本一致,所以《篇海类编》是在《详校篇海》的收字基础上略作增删,以部首排序、按义类归部代替了三十六字母排序,将训释内容稍加改动而成的一部坊本伪书·《篇海类编》与《详校篇海》两书收字类型以共收字为主,漏收字与新收字极少。单见字中字形歧出显著是《篇海类编》与《详校篇海》收字类型最显著的特点。共收字占绝对优势与大型字书兴起后盛行转录前代字书的编纂方式有直接联系;漏收字与新收字极少的原因不仅与省时、省力、省成本的编纂目的有关,而且与部首的设立、成书时间也有一定的联系;歧出字字形差异主要体现在笔画差异和构件差异两个方面,其中笔画差异最为显著,这与字形异写、书写者的习惯、字书编纂目的、字头讹误等有很大的关系。共收字与歧出字的联系主要体现在字形上。歧出字是字书转收前代字书时,已收字形与转收字形之间发生变异难","categories":["09_其它"],"year":2019,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJRLWPxp2_cLZ1WnxEzdeG15X8DwgAyFxCH2VSdchfVhMx9hB7dMAXcrKAegjWwFggH5wF-0BTSbya6kRExsSYQEYZEZom33xDRLkKxtwOeRnZjpwDRhU83zAYBZ4i1vfGL7eibvAyLeVYcjFH02nl2tFVSeJqHawSVz7Q66NMniovzGW4GaQ2K&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2781,"author":"黄洁; 方小壮; 言恭达","title":"洪亮吉的游幕活动与金石书法研究","abstract":"洪亮吉,江苏常州府阳湖县人,于经史、舆地、诗文等方面有着非凡的成就,同时在金石书法上也有着不凡的表现。身处乾嘉学派与乾嘉碑学兴起的大时代,洪亮吉身上兼有这两方面的特征,可以说是这个时代大背景的缩影。洪亮吉无疑是游幕书家中受到幕府生活影响十分明显的一个代表学者书家。洪亮吉的流传作品较为分散且少见,本文试图查阅洪亮吉的诗文集、传记年谱等相关史料,首先勾稽出洪亮吉生平行迹,对洪亮吉的游幕生涯有概括性了解。从而梳理洪亮吉在两个幕府中所受到的影响,包括学术与艺术上的这两方面,而这对洪亮吉金石书法有着不可忽略的影响。其次在尽可能完整地搜集洪亮吉现存的书法作品图版的基础上,分类考察其创作审美取向,比较其不同阶段的存世墨迹;运用文献与图版实证相结合的综合研究法,深入分析和探究以洪亮吉为代表的游幕书家的活动情况,并溯源探流,试分析洪亮吉其书风的成因与影响。","categories":["09_其它"],"year":2019,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKRTcn6u51N1Q4P-0fOCSX1WJf4jKck77Kps97v3MozUcKPMBdcOLaHrjXAUoKAEi1AVLN5c-CEtudWgNiGv9gxWz8Qtceh0zdysCrUNR-Xq3acoKlP2Wc9a9Ttd3wx8gmPfoSPc0O5GohztxTLL0eGDauZxoa2Mly16qsbZKIEVXJ4OnJ7GA0w&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2794,"author":"钟琦; 萧圣中","title":"古文字教材文选研究","abstract":"漢字作為漢民族悠久文明的載體,不僅傳播了一個偉大民族燦爛輝煌的文化,而且作為這種文化的鮮明標誌之一,它也傳播了自己。漢字產生於中華文化的沃土,數千年來延續不衰,始終保持著旺盛的生命力,是世界上現存唯一的自源古典文字系統。古文字是漢字的歷史形態,主要指先秦到漢代早期的漢字。一般來說,狹義的古文字指的是先秦文字,這類文字材料主要是傳世古文和地下發現的先秦文字材料。其中,古文字學的研究材料,重點是出土的文字材料,《說文》小篆和傳世古文不是其主要的研究材料。廣義的古文字還包括《說文》的小篆系統和漢武帝以前的早期隸書。古文字學是一門實用性很強的學科,它對相關學科領域如古典文獻學、歷史學、考古學、語言學等都具有很重要的實用價值,古文字學知識也是漢語言文字學專業和相關學科專業的學生所必備的基礎知識。因此,為適應不同專業古文字學學習和教學的需要,選擇合適的古文字教材顯得尤其重要。筆者仔細研讀了六本重要的古","categories":["09_其它"],"year":2019,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIeweWXKf3IxKHXH-jHmHnWnnYI8-70Qa0rSqAX7yByIskOpiNZCu163XiCvE_B-ARuFqHLmtsiC7QL9stCUTqUypAvyA_FTFWRRrmjI6wuFsmAOebCKtnJpkBPbc4T5dUe1R5V94RuO_muhq2BoyQA6iRxFKVpan-C_KbAhYF42YNTBqh3qOWY&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2795,"author":"李雪; 党懷興","title":"20世紀象形學說研究","abstract":"“六書”學說一直以來就是中國傳統文字學的核心,而象形則是“六書”學的重要組成部分。在20世紀,學者們利用大量出土的古文字材料,積極借鑒西方語言學思想對象形的相關問題進行了更為科學而系統的研究,取得了卓越成就。本文旨在通過對20世紀象形學說相關著述的整理和分析,梳理出這一時期象形學說的發展脈絡,闡述其承前啟後的學術意義和價值,並指出其不足之處。全文共分7個部分進行論述:第一部分,引言。首先對20世紀以前的象形學說作簡要概括,進而闡述20世紀象形學說的發展背景和主要情況,說明選題的重要性和必要性。其次,對20世紀象形學說的研究現狀作以綜述,總結其成就和不足。最後,介紹本文研究的目的和方法。第二部分,20世紀象形學說文獻概覽。分別列舉20世紀涉及象形學說的重要著作和論文,並對其中的覲點加以介紹,展現這一時期象形學說的整體面貌。第三部分,20世紀象形定義研究。上個世紀的學者有沿用許慎對象形定義的,","categories":["09_其它"],"year":2019,"publication":"","link":"https://link.cnki.net/doi/10.27292/d.cnki.gsxfu.2019.000379","pages":"","volume":""},{"id":2796,"author":"任健行; 党懷興","title":"20世紀“形聲”學說研究","abstract":"20世紀以來,我國的學術發生巨大變化。隨著西學傳入中國,西方的語言文字學理論也開始進入我國學者的視野。同時,甲骨、金文等新材料的出土與運用,促進了古文字學的發展,不少學者開始利用古文字材料重新研究漢字。在此大背景下,形聲字的研究也取得了巨大進步。本文的目的就是從學術史的角度入手,對20世紀的形聲字研究成果進行初步整理與評價。本文的主要内容是對20世紀的形聲學說進行初步梳理。除緒論外,本文共有七章,分別從不同角度對20世紀的形聲字研究成果進行整理,具體如下:第一章是20世紀形聲文獻概覽,主要有兩部分内容,一是對20世紀涉及到形聲字研究的重要著作進行評價,二是對20世紀涉及到形聲字研究的重要論文進行討論。第二章是形聲字的產生,主要梳理了 20世紀學者對形聲字產生途徑的研究成果。相比前代,20世紀學者對形聲字產生途徑的研究相對深入。20世紀學者也以此為基礎解決了諸多形聲字研究中的問題。第三章是形","categories":["09_其它"],"year":2019,"publication":"","link":"https://link.cnki.net/doi/10.27292/d.cnki.gsxfu.2019.000340","pages":"","volume":""},{"id":2813,"author":"李学嘉; 邹芙都","title":"秦系私印整理与研究","abstract":"玺印除了用于封检之外,还有凭信、象征等多方面用途,因此对玺印的研究是多层次、多角度的。其中秦系玺印资料的内容涵盖了秦的职官、地理、文化、社会生活等各个方面,对研究秦的历史有重要价值。但较之秦官印的研究,秦私印的研究则比较滞后,对它的专门整理较少。因此,对于秦私印的整理与研究是十分有必要的。本文研究材料的时间范围包括战国秦和秦王朝两段,主要以秦系私印,尤其是姓名印、成语印为研究对象。在充分考察前人著录及研究成果的基础上,对已公布的秦私印进行梳理,同时揭示秦私印中蕴含的历史文化内涵。主要内容如下:第一部分是绪论,其中对本文涉及到的重要概念进行了说明和界定,并梳理了秦系私印的发现、著录情况。在分析了秦私印文字、形制、姓氏、取名等方面研究的具体情况后,指出了相关研究还存在的不足之处,并由此提出了本文的选题意义与研究方法。第二部分是正文,包括秦私印的判定、秦私印所见姓氏研究、人名研究和成语印研究四章","categories":["09_其它"],"year":2019,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ9GQlC6ISPqrVA5WNODkJaILESAGEaj_mGbEGHP2PvtRQ46jPvsDxgF6qT_AA6lPw5LHaA0aeBbQPKWTasbZrHRBq8Xr8IRIP-T0inPxMwLAJF-leQmK3giGH_XLaP8qNQUF9VQ6vBP9PogXpHRT6x5fmfwXStq7360pZHobRjkt3wNzNxTAVY&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2815,"author":"刘昳岑; 于景祥","title":"北宋铭文研究","abstract":"在文体学研究领域中,铭文是一种重要的文体类型。一般来说,文体学意义上的铭文是指镂刻在器物上的文辞,它是一种兼褒赞与警戒两种功能的特殊文体,以四言韵语为主要的语体形态。它有金石之坚,即永志不忘和不朽的义涵。北宋铭文佳作颇多,数量可观,但前人对此关注不多。本文对北宋铭文进行专门研究,探源述流,并与唐代铭文的比较中兼及题材、体式和艺术性的嬗变。本文分为以下几个部分:首先是绪论部分,重点是对本文的研究范围进行限定,其次对北宋铭文的研究现状进行介绍,同时说明本论文的研究方法和研究目的。第一章,主要介绍铭文的概念以及相关问题,其次探讨铭文在宋前各时期的发展流变。铭文是中国古代历史悠久的古老文体,它萌芽于先秦,定形于秦汉,在魏晋南北朝走向成熟,并发生变革,在唐代得到极大发展,北宋时更蔚为大观。第二章,探讨北宋铭文蓬勃发展的社会文化背景,以及北宋铭文的概况与分类。政治上重建礼制的需要、科举制度的发展完善、","categories":["09_其它"],"year":2019,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLstGOi5yc0lQyeVb9x7L1rO8rcPclYhrVtLS9QbuV7skb-KbmO4JSonPsBy77hFof3fiC3hnJV1zUFu_PmRdfMjPKx4cs1GNqydkg9a75kXw_Uu3DNX-AKLaUeb30Eyf633zaOQJZQZtQlKL_EMLwIBMMRCQ0pXkQRmJrc8JbGbwurBKFfdVlk&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2821,"author":"戴曉棠; 郝士宏","title":"華學涑《文字系》研究","abstract":"華學涑先生素抱改良文字之志,深感我國文字研究沒有可以依據之系統,搜集整理歷代金石文字,分類別族,聯繋牽屬,窮十餘年精力著成《文字系》十五卷,用以追溯文字之本源,探求文字孳乳繁衍之規律。華學涑先生的《文字系》一書是從一個全新的角度對漢字分類系統做出的探索,將文字以事為類,分為象天、象地、象生、象蟲、象鳥、象默、象人、象體、象手、象足、象宫、象用、象器、象事14大類,共52族統系文字。全書依聲系聯,於每字之下引古文字資料,按時代先後排列,直到《說文解字》小篆形體。其所引古文字資料有甲骨、金文、貨幣、刻石、陶文、璽印、瓦當、石鼓和兵器文字等等,有些圖畫形符號,置於甲骨形體之前。華學涑先生《文字系》就形釋義,敢於打破以往舊框框,亦多發揮右文之說,頗有心得,同時有助於辨別、識記漢字,了解漢字發展演變過程。但書中說解漢字形體多以會意說形聲字,有些歸屬不明確,也多有牽強之處。總的來說,華學涑先生的《文字","categories":["09_其它"],"year":2019,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJOLYQLRHw1AIbyHpUfaE3JC8tOUAb1LVaK8WxNHIHJN19J7hbBbrkCpNKxFNMNpPgMNE1XommEGNQ6uTYuAhB6DvnTy5hjuEZjaf0nksS1Ou6VGtRiXh6CLdpSYAuR5wui_Ls-eG17ZpNi75tLyxeseggC4WTdYwzYih0O-61HBiD_iJOwaQEH&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2825,"author":"薛永剛; 党懷興","title":"《同文備攷》研究","abstract":"《同文備攷》(以下簡稱《備攷》)成書於明嘉靖庚子年,即公元1540年,是明代學者王應電(以下簡稱王氏)編著的一部字書,包括卷之首三卷、正文八卷及附錄,共三大部分。附錄部分為音韻研究,約占全書四分之一,其餘正文八卷及卷之首三卷均為文字研究。該書文字研究部分以“取古文諸書正小篆之謬”為宗旨收字,並將所收字按意義類屬編排,即天文、地理、人容、人道、人體、動物、植物、用物等。從對所收字的編排及解說等角度可以看出,該書在漢字研究上有以下幾個主要的涉及方面:對以往漢字字體及歷史發展的獨特認知,對漢字構造及書寫的獨特認知、對漢字字形的獨特改變,對前代字書的獨特借鑒,對六書理論的獨特理解等。通過研究可知,王氏師從魏校,勤敏好學,其字學研究以《備攷》為代表。王氏編纂《備攷》,期間既受流離之苦、又受疾病困擾。然王氏持之以恆,於嘉靖十九年完成初稿,又歷七年修訂,頗多不易。后收入《四庫全書存目叢書》,為較為完備的","categories":["09_其它"],"year":2019,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJyk2b8vNtzrXyTorAS3g99bTVVD8_4J_dEXhjyeao_P3rLRANTxVpqgyMflSLFymhhWSsGKMYODq5Q2EeHksKLL8GXW347zM4Ff0eXLjjWIp56vesQkDS8ALP2HU-or2Po0uNSmcRLHdrCqiUikPY23st36QaIgugAW57a3sqrn4MBJXVzIgxV&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3092,"author":"康森杰; 黄天荟; 李谦诺","title":"早期中国散文中作为文本构建工具的音韵修辞和音韵模式","abstract":"除了少数几个例外,传统的汉语语文学研究主要集中在语义和语境中特定段落的意义等方面,而针对修辞结构的探讨则经常被忽略或仅仅被粗略带过。本文认为,我们可以高效探讨音韵模式和音韵修辞结构,通过它们深入了解早期汉语文本,更强调学者应该在任何早期汉语的细致研究中都经常使用这些方法,以帮助现代读者理解这些文本。此项工作的一个关键元素是新兴电子及计算机工具的诞生,例如《古汉语词源字典》(可于edoc.uchicago.edu在线获得),它聚合了大量二手信息(如各种语音转写、训诂和古代汉语拟音,或是学者对语境中特定汉字的诠释以及对它们传统、非传统用法的评估),大大减少了查询和汇编各种已有证据的时间,有助于判断特定汉字在修辞语境中的功能、角色和作用。这项研究集中于一系列传世文献或出土文献中的早期叙事性散文,学者们举例证明其中体现的音韵修辞方法,并初步总结了传统方法中应用现代工具的优势。本文也指出了目前知识和","categories":["09_其它"],"year":2019,"publication":"韵律语法研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJzh9XSjZSpfCkVK3JmctziRjCYZ5e9JIoMYB-fZ_9JJahpyyfwsHMOZLmiVehOj2yTWBRZ-XKHYX_xcPTxC5ulCFpvBHlxlXYilhe0zrAnvq45EYBvVVfqetI2NbF4j0E3o7bpKuBqPwKfBBqpad2v5ZBHlLroAfhOZg2ysk33gA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"18-63","volume":""},{"id":3309,"author":"張懋鎔","title":"關於一千年來中國古代青銅器研究史的幾點思考","abstract":"中國古代青銅器的研究,自兩宋以來,已有一千多年的歷史,取得了豐碩的成果。當我們跨入21世紀後,有必要對一千多年來的青銅器研究歷史做全面而綜合的分析,在總結已有成果的基礎上探討繼續深入和拓展的課題和方向。[1]限於學力,本文只是談幾點想法,希望得到大家的批評指正。","categories":["09_其它"],"year":2019,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKYxj7ICFvx3RNHmhQUihaMB4hWCuQHp_-AJssmACrqsPqiBNCuiekAGJHXCV9H1UJwgE0ydZHtCoK-bqJNzsiph_mEyVmVFIxrRSvJ0GfPpJS5bLaGuByS10L7lB6957snTlZsKayU0fe7zrKhsZfK0oq8vcVtemCBS5Ps4x3ceA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"301-312","volume":""},{"id":3323,"author":"黄锦前","title":"新刊侯氏盘匜辨伪与旧录侯氏诸器辨析","abstract":"本文对《商周青铜器铭文暨图像集成续编》著录的侯氏盘、匜进行辨伪，指出盘、匜铭文字体拙劣，部分文字如“侯”“麇”等写法明显有问题，字口也粗细深浅不均，可断定系伪作，盘、匜应系春秋早期汉淮流域一带之物。同时对河南平顶山应国墓地M95出土的侯氏鬲与湖北襄阳蔡坡等地出土的侯氏簋进行了辨析，指出二器的侯氏应皆指应侯，当非同时之人，厘清了过去的一些错误认识。","categories":["09_其它"],"year":2019,"publication":"湖南省博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKq6-Pb8fVuxeQ0v50Lp0WYTWMLbHUwFvczlfqVr9Qw718QsmWvTHD0Bw-A195_vbVFLIs3YIKphUfGqnsVoh4aaZlvekUSOjdrxl-TvombhMH0PUMTuBocqKnNuGgQsfJGL6cndTLybd1UNAtj2Fm22XbIHSYupjLtz6fUgnOy5g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"237-241","volume":""},{"id":3324,"author":"曾庆炳","title":"杨树达两篇《新识字之由来》的比较研究——基于文献学的考察","abstract":"《岭南学报》第11卷1951年第2期上发表的《新识字之由来》是《积微居金文说》版《新识字之由来》的前身，学界当前少有关注。通过文献比勘可以发现，无论在条目分类、例字选用、理论总结还是行文表达上，《金文说》版《新识字之由来》较《岭南学报》版均有大幅度修改和优化，这反映了杨树达对此文的经营和推敲，也体现了他的学术思想与治学精神。","categories":["09_其它"],"year":2019,"publication":"湖南省博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKq6-Pb8fVuxeQ0v50Lp0WYTWMLbHUwFvczlfqVr9Qw718QsmWvTHD0UJiZ74sM6E4WdYSVU2AF30MQMd2FwUSzI_n-KKnqU7xyYh-CTQQ2RW15N9D0mA7FXAZTL7h_JPe4zhI5Jev3ehPEYka7hudrjeeaG8Oi9b_Q8fFIj7-t_A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"535-544","volume":""},{"id":3339,"author":"潘薇薇; 黄伟嘉","title":"《汉语同源词大典》评议——兼论科学语源学研究核心问题","abstract":"近日,汉语史上迄今为止规模最大的考释同源词的工具书《汉语同源词大典》出版。文章将该书与不同类型工具书及同类型考释著作进行对比,讨论了诸如&quot;语源&quot;&quot;同源词&quot;定义、语音关系、语义类型等科学语源学领域的核心问题,并对该书的独创性及不足进行评议。","categories":["09_其它"],"year":2019,"publication":"语言研究集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLtUSQciw0GoKYT3DogT-8j1fz48BIt7m5w98QVyz9pWlCpqvXRgMHh7KvC1MO6SknqMFdbsHudRLp3TJ7mhjNbh78ph-ocCtXvECI3llJpYayg1JoZbkRWZ1Ka_pgwnfuQE1gkVEqVBBrqeaBVN5iKz93IoJjtAp0tr_4zTY-hDA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"396-405, 436","volume":""},{"id":3343,"author":"袁金平","title":"古文字理論研究的一部力作——劉洪濤先生《形體特點對古文字考釋重要性研究》讀後","abstract":"中國古文字研究歷史悠久,發展至今,不論是文字考釋,還是出土文字資料的整理,均取得了十分卓越的成就。但不可否認的是,總體而言,我國的古文字研究向來有重實踐、輕理論的傳統,古文字學的理論研究相對薄弱。不過隨着大宗古文字資料的發現,尤其是20世紀70年代以來多批簡牘、帛書(如馬王堆漢墓帛書、郭店簡、上博","categories":["09_其它"],"year":2019,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJaJ8IcGFfWJahYUFbZ8-XouJru1NX0cQNJUwavK9zWxA6ymCokFe57oNRFeK2_zlcWnctLNvXmXAyth3_dFqP10Gwdc-Hb3kpDR3-imOH759uc0Qz3MXJ6RsvKRLhyrSmfvRmxpeqxYGYcXxMyHtzZUspoOgGS1LuZWF--hRRLgg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"366-368","volume":""},{"id":3358,"author":"董恬","title":"高唐神女原型考釋——再議“高禖說”","abstract":"二十世紀三十年代,郭沫若、聞一多、陳夢家三位先生先後發表論文研究高唐神女的原型問題,並提出&quot;高禖説&quot;,將高唐神女的原型看作各民族厥初生民的女性先妣。這一觀點流傳至今,依舊爲當今學界高唐神女原型研究的主流。但是,由於時代局限,郭氏、聞氏與陳氏對於&quot;高禖説&quot;的分析存在一定疏漏。本文試從傳世文獻、出土文物、語音演變等角度對&quot;高禖説&quot;正本清源,釐清其中存在的問題。","categories":["09_其它"],"year":2019,"publication":"新国学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJhuUnGiCMgNY6HRxCgfeCavKQyp5Jt_X4GP3CsWZnujFpt8uamNgltDLTCJ31YqmboqVXAHM6D8IitnSD41eLNNUflmIRw5jec1p5gkx-VauxmgseInPqM7q7inL_buuauB1sEbpFt5S4rS4xcqvF0zHKWG4-_901XJEFJdJ4L3w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"88-116","volume":"17"},{"id":3368,"author":"曾庆炳","title":"《积微翁回忆录》所见杨树达金文研究资料","abstract":"《积微翁回忆录》中有不少杨树达金文研究的资料,对全面了解杨氏金文研究有重要意义。文章从杨树达的金文研究之路、杨氏对金文题跋的修订和补充、散见的杨氏金文研究、同期学人对杨氏金文研究的评价、杨氏对其他学者金文研究的评价、对《杨树达先生著述要目》的补充等六个方面论述了《回忆录》所反映的杨树达金文研究。","categories":["09_其它"],"year":2019,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLKVmgP6kLmgNZOwdIYXDyhtqP96MSriYFQAuZX7WkrjV-x4Fh57sQkgeWReb1oeFyJqDwYzHVzoLJgudsd4gMhihiiwXDWgbokreuNFJghB0FVqWc6DegoU6uhnTq6R5PHpKfNPLxz1BBimUUJbNF-5dcI5NJNTRcteHTzPK9x5Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46-52","volume":""},{"id":3714,"author":"牟柏苍","title":"西周金文——中国文字的成熟","abstract":"本文节选自《中华文明的早晨——西周史说》西周的金文,是在甲骨文基础上,使中国文字更完整、更成熟。金文是指铸刻在殷周青铜器上的铭文,也叫钟鼎文。在青铜器时代,鼎为礼器、钟为乐器,&quot;钟鼎&quot;是青铜器的代名词。西周时铜的冶炼制造已有进步,周人将铜也叫金,所以铜器上的铭文就叫作&quot;金文&quot;或&quot;吉金&quot;。金文应用的年代,上自西周早期,下至秦灭六国,约800多年。金文的字数,据《金文编》记载,共计3722个,其中可以识别的字有2420个。","categories":["09_其它"],"year":2019,"publication":"艺术品鉴","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKtrHrL4PWWUe7sEYwMsuNIHTP9nPL8JyN_0G_ObBD0Yb7ZVenjRw278l-9SfI4CuZbf-CfO2Wx9cIpp0YMBrHyv4wZMGJ4EE0bTJgt-cFqdi0PJlzs0_Cc0ZPK8YctM9bvnDyqUihQdjSwNpXa_AysmRjtHG7SufMGdEY4QDwqDOyIvyIlNo6s&amp;uniplatform=NZKPT&amp;language=CHS","pages":"166-169","volume":""},{"id":3717,"author":"吴健","title":"《散氏盘》铭文","abstract":"《散氏盘》铭文是西周晚期大篆范畴的书法经典范本。其用笔豪爽朴拙,线条醇厚精严,笔姿恣肆稳健,意态古雅生动;字内空间布白疏密开合,张弛有度;字形结体横向取势,扁圆右沉,萧散自然;字法循规蹈矩,气格古雅;全文章法布局平中寓奇,意蕴博大宽厚。《散氏盘》铭文尤其值得称道的是高古沉着的气格里萦绕着一股跌宕回旋之势,意境高远,素有&quot;草篆&quot;论评,此在金文书法中特立独行,立异标新,彰显着内力弥漫的低调奢华。","categories":["09_其它"],"year":2019,"publication":"江苏教育","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJx1KHeePy_wNvtTrFv5i4xdir7zQjXKlyTF_gV8b0NugwRmU2HhFalvld9xLfknL0fOUZTQzRl5j2rmeMX9F8YIaeWl0ebWY6n8Dub3YfjW7sLbseCRJzlZFogo0J10l-lnebvjPOcDlzRYTuZ-H4m-3qqSOnTu-0EOEt_O8Pb3ULjp9o3v0qz&amp;uniplatform=NZKPT&amp;language=CHS","pages":"35-38, 46","volume":""},{"id":3719,"author":"吴健","title":"《毛公鼎》铭文","abstract":"《毛公鼎》铭文是西周晚期大篆范畴的书法经典范本。其线条瘦劲爽朗,笔姿优美流畅,古朴凝重,姿态生动活泼,在金文特有的凝重感中增加了灵动的秀气;字内空间布白,开合有度,匠心独运;字形体势纵长,萧散自然;字法循规蹈矩,气格古雅;全文章法布局,气象温和,宁静纯真。尤其双向弧形排布的纵行显现出独特的分行布白之美。较早期的金文有不同,线条的运动节奏更加明显,中国书法线条的写意特征由此渐趋明朗,下开石鼓,后启秦篆先河。","categories":["09_其它"],"year":2019,"publication":"江苏教育","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ5-7J1qOm-pvMcDcctyTbdkTKh0Wh_h8iaiHeHK-Oq0HoQD4p1Ao3ZRilpd3rq1RkVJlCL_9nXAoVbS8fkvxjWEXLkhxSRoRxHoaEhPft6_9tgngzc0FjSyTSZOJsX82EFhKtTivqBwTyoQEJZ5aqlfSYWD491Hn-qkT35oe21-4hbWCTmP0Nu&amp;uniplatform=NZKPT&amp;language=CHS","pages":"34-37","volume":""},{"id":1994,"author":"张莉","title":"宣统《山东通志·艺文志·金石》案语研究","abstract":"宣统《山东通志·艺文志·金石》是一部具有极高学术价值的金石文献,其最精华的内容就是&quot;谨案&quot;部分的考证说明,案语广征博引,考订严谨。编纂学者对金石文字进行尽可能详细的解读,比如疑难字、异体字、通假字以及汉字背后的文化内涵等等,他们对铭刻文字的著录与考释,为挖掘金石文字的史料价值提供了必要的前提条件。","categories":["09_其它"],"year":2018,"publication":"济宁学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJyTFEAElVPek7qD78mLETw-JTc9ybL2oiN9Uo4mQjR4XorRWOs5nAvibDFhJIhNvZ2PGwQ02f-HDmuOk5fK5IZNVM0i97kxeUqoc0_3QibjeqetU27rUyppcVKi6bHKEB_TFfFHjvHUUDOKzPti_SozNVN7gyn2KMPnrFQl2loHlIVoQiMIEVq&amp;uniplatform=NZKPT&amp;language=CHS","pages":"37-40","volume":"39"},{"id":2007,"author":"张煜珧; 张天恩","title":"石鼓山青铜器铭文铸作工艺初识","abstract":"石鼓山周墓出土较多青铜器铭文,整理金文资料时观察到铭文形制有别,经过分析注意到其差别是因铸作工艺不同所致。直接刻于范上所铸铭文即一般所说之阳文,属于范刻工艺。而阴文则是刻于模芯翻范后再铸。但晚商及西周早期多在修范时会加工字形,就是在字划贴塑泥条致笔画加粗而轮廓清晰,往往有肥笔现象则属&quot;芯塑&quot;工艺,不加泥条修范的文字笔画僵硬,属于模刻工艺。三类工艺技术的运用,以范刻最早可至中商,且一直可见;芯塑流行于晚商到西周早期;模刻也见于晚商及西周早期但较少,西周中期以后至春秋一直流行。","categories":["09_其它"],"year":2018,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJmDl_WDPQ59uH0nL_mhwUd1K6uJQyLCkn0KPm4BFEK2DKGcmPRi1Yd_H90k07nr9xZhR9cSTJHUBUu4YSlbdrQeYXM0N9FuyKFBpWVlzo5VLlXEYo9X2RwY-iGfpPXUz-5M2gVkEAS65t7T6LsHPQ8ZCEySXP96qYvRxFqrGx9_615ePpXic76&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-69","volume":""},{"id":2009,"author":"邓帮云","title":"郭沫若古文字学贡献及影响研究","abstract":"郭沫若是我国现代全能型文化巨人,他在古文字学方面做出了卓越贡献,对当时及以后古文字学界都具有深远影响。很多专家学者都曾回忆与郭沫若在古文字学方面的交往、交流和论辩的经历,并述说郭沫若对学界和自己的影响。本文借助2015年社科重大课题&quot;回忆郭沫若作品整理与研究&quot;的平台,主要从回忆者的角度,研究讨论郭沫若在古文字学上的影响及贡献。","categories":["09_其它"],"year":2018,"publication":"郭沫若学刊","link":"https://link.cnki.net/doi/10.16142/j.cnki.gmrxk.2018.04.006","pages":"26-31","volume":""},{"id":2011,"author":"张雨欣","title":"论青铜器的崇高美","abstract":"为进一步探究青铜器丰富的历史和文化内涵,分析了青铜器的独特艺术和美学风格,并从青铜器的审美特征、审美功能、审美距离等方面探究它崇高的审美意味。青铜器数量之多、体积之大、纹饰惊奇、铭文灵动皆体现了其崇高感,这种崇高美也满足人们的审美教育、审美认识和审美愉悦的需求,而它存在的时间距离、空间距离及心理距离更增添了崇高感。通过感受青铜器的美,以期能够更深层次地认识青铜器的崇高感,体味它令人敬畏的肃穆神秘。","categories":["09_其它"],"year":2018,"publication":"宿州学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIJ8SJIrbL034zgILh1GsLZQpjaeVckYpdICh1Na7TZiEipMURewO0Ug3YkQJMOGwLrN-_DDlDqpcSS2DxqCy7OigFB7hEgSVAa-gEPWYyo6xRAy0D8atSePdCMPLL_7crXP59z39uTBiWViR9SRZoa6ZUif0Lwdw2QOLHpREuh8RW8t3c3e5ne&amp;uniplatform=NZKPT&amp;language=CHS","pages":"91-94","volume":"33"},{"id":2017,"author":"张涛","title":"唐兰早期甲金学研究表微——以唐兰致刘体智书札二通为中心","abstract":"1934年,在北京大学等学校任职的青年学者唐兰致函给大收藏家刘体智,就刘氏所藏夨令尊、曾姬无恤壶等新发现的青铜重器有所讨论。唐兰并称已与安徽图书馆商定去整理寿县出土青铜器,此事在唐复年、唐益年所编《唐兰年表》中无载。另外,唐兰还提到整理的北京大学藏甲骨即将出版。由此线索,可以考知出现于&quot;中国书店2012年秋季书刊资料拍卖会&quot;上的唐兰手稿至少应该包含唐兰未刊稿《北京大学研究所藏甲骨刻辞》的部分内容。唐兰致刘体智书札对了解唐兰早期甲骨、金文研究具有较高价值,目前尚有两通保存在刘氏后人手中,鲜为学界注意,可补《唐兰全集》之不足。","categories":["09_其它"],"year":2018,"publication":"文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIBFhHpiZmm2Jbn2leuRQiMZVga0vtuHFQhYOi63ocgwSDLmtSHcNGpRff-i8Q-tx7IFA03UmNHmIyCZJw5o_q5aSKBKJQ6Uqra_ocj8RrcVC_qmSNqJ9EFHdGrqlhBekEhIc2VWmeXuElY_kir7IC2ESyxL8NPnzcVb2nvGcZGljesPm6GZp_a&amp;uniplatform=NZKPT&amp;language=CHS","pages":"16-24, 2","volume":""},{"id":2020,"author":"李紅薇; 崎川隆","title":"新見日藏郭沫若手批《兩周金文辭大系考釋》輯錄","abstract":"日本亞非圖書館藏有郭沫若手批《兩周金文辭大系考釋》。書中批注從未公開,幾十年來鮮爲人知。原書卷内天頭夾行處多有批語,或補充修正原文,或校勘訂補文字,或削删字句,絶大多數意見未體現於作者後來的論著。本文逐條輯録這些批注,並參以郭沫若其他論著,梳理其觀點演變脈絡。","categories":["09_其它"],"year":2018,"publication":"文史","link":"https://link.cnki.net/doi/10.19325/j.cnki.11-1678/k.2018.04.012","pages":"269-276","volume":""},{"id":2033,"author":"李运富; 温敏; 韦良玉; Li Xuenings","title":"改革开放四十年中国文字学研究","abstract":"改革开放四十年来,文字学研究取得了丰硕成果。汉字材料方面除传世文献,大量新出土材料和跨文化环境材料得到充分利用,整理手段也由传统纸笔发展为高科技和智能数字化,还有各种专题数据库和综合数据库。汉字学理论体系从偏重形体结构逐渐调整完善为形体、结构、职用三维一体的立体汉字学,各理论专题研究在广度和深度上多有拓展,讨论和认识问题更加多元和宏通。研究方法在继承传统的基础上,有综合化、理性化、动态化和跨学科化的趋势。汉字史研究也从单一的形体演变发展为形体、结构、职用三线共进,断代研究由厚古薄今发展为古今并重,近代汉字和汉字传播研究受到关注。相信未来的汉字学,在现有基础上,应该更加注重新材料的开发、新技术新方法的运用、新理论的完善和汉字发展史的全面贯通。","categories":["09_其它"],"year":2018,"publication":"孔学堂","link":"https://link.cnki.net/doi/10.16349/j.cnki.52-5035/c.2018.03.006","pages":"60-79, 196-210","volume":"5"},{"id":2041,"author":"孙明","title":"商周时期宽耳铜簋浅析","abstract":"宽耳铜簋,这里指器身两侧置对称的双耳,双耳的上端横向宽大、纵向深厚,形成一个方鼓的空心兽首的铜簋。此类铜簋由于数量较少且分布较散,以往虽有学者简单提及[1],但尚未引起学术界广泛关注。本文拟从宽耳铜簋的发现与分布、型式与年代、起源与传播及铸铆铸接工艺等方面做一简要梳理。一发现与分布根据现有资料可知,宽耳铜簋共计32件,其中考古发掘品14件（图一）,国内外藏品18","categories":["09_其它"],"year":2018,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2018.08.003","pages":"38-45, 96","volume":""},{"id":2046,"author":"万红; 熊博文; 芦刚","title":"论中国古代青铜器的鉴赏","abstract":"从中国古代青铜器的种类、纹饰、铭文、铸造技术四个方面,论述了鉴赏古代青铜器的基本知识,从而为鉴定与收藏中国古代青铜器提供参考。","categories":["09_其它"],"year":2018,"publication":"铸造技术","link":"https://link.cnki.net/doi/10.16410/j.issn1000-8365.2018.08.017","pages":"1700-1704, 1708","volume":"39"},{"id":2048,"author":"赵寅","title":"饕餮纹和铭文在商周的发展","abstract":"青铜器的发展和图案的演化有着密不可分的联系。从饕餮纹在早期出现,到逐渐发展到鼎盛,再到慢慢消失,其中不仅体现了社会的变迁,更体现了许多人文的变化。铭文从商代具有甲骨文风格的雏形,发展到周代初具书法韵味。纹样从厚重深邃到柔美自然,多种变化手法令青铜器的纹饰更加形象生动,具有很强的装饰性。","categories":["09_其它"],"year":2018,"publication":"美术教育研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ01VEr5lGIqhNE2OqhrowtcyoTpcRrjvrTvUcZ_SySZC5_Yh21aq89TOdZkpjoYrD9ABplgXZEuvfhEZgPZVvyKQnYQSwB2tnMy8QjNobnviMRW8vdDDsokGvrM4wEcnx3ny0sMlJWPiyVkvqBlCQl_TbNzDPO3dyjxBQifzRUMWoUlys55Xza&amp;uniplatform=NZKPT&amp;language=CHS","pages":"31, 41","volume":""},{"id":2055,"author":"徐正英","title":"出土文献“大文学”研究与坚定文化自信","abstract":"&quot;表现性&quot;及&quot;抒情性&quot;是我国古代&quot;大文学&quot;区别于西方&quot;再现性&quot;文学的独特存在形态和文化优势。殷商甲骨刻辞、两周铜器铭文、战国秦汉简帛等出土文献&quot;大文学&quot;文本告诉我们,这一形态早在上古就已定型并固化,其表现得比传世文献更为显明,并且春秋时代已经获得这方面的理论自觉,从创作实践和理论建构两个方面更加充分地证明了其优势之所在,使坚定的文化自信更为坚定。","categories":["09_其它"],"year":2018,"publication":"文学遗产","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJeGcdXfRWopbhcA5waC3OZUQ48GcY6mmSiYqTQqifzImXyxTE2drERmQ44XMUFUXn_tumAbWtkUqrRdp5qm5PjSYhPV9Hc1-AcyigT7j108yNRG12liYDQD-KmZk8a-k_afS9feSNA-TNPV-uLjDZww65aGVzrRiri-O6PZOKlAERcnCOPfjUs&amp;uniplatform=NZKPT&amp;language=CHS","pages":"26-37","volume":""},{"id":2075,"author":"孙璋","title":"书中有我追慕商周——金文学习漫谈","abstract":"古人称铜为金,因而铸刻在青铜器上的文字称为&quot;金文&quot;,又称&quot;钟鼎文&quot;,钟为乐器,鼎为礼器,&quot;欲问古今兴废事,请君问鼎于河洛&quot;。作为权力象征,青铜器被古人视为祥瑞之物,金文刻于钟鼎之上,时间愈久愈显古朴厚重,一勾一画间尽是汉字意蕴之美,存世绵延上千年,后人更是青睐有加。宋代,金石之学大兴,欧阳修对金文作过研究和记载,作《集古录》,成为金石学开创者。近代以来罗振玉、王国维、郭沫若等学者整理研究,对金石学作","categories":["09_其它"],"year":2018,"publication":"金融博览","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJUqLZqOdDYeFyqBW-9OdWywr10774Gvm8OAtcwEeif9xqnxgLOv3zOOj1BEoayJYWHaOXICrkJhbzyUrk7t7xt8uVyBpK0MUJHB3gMmSr3D9WOEKZ1Y_iVy1yTJuW-iOmf4VrwkkqGd2Np67A3vp-799yH9tEo16SyyHcCz04CMV4xCRiAaYMr&amp;uniplatform=NZKPT&amp;language=CHS","pages":"92-95","volume":""},{"id":2080,"author":"沙伟","title":"青铜兽面纹鼎:商周时期的“国之重器”","abstract":"兽面纹亦称饕餮纹,其盛行于商代和西周早期,为商周青铜器上最常见的纹饰之一。《吕氏春秋·先识览》中有&quot;周鼎著饕餮,有首无身,食人未咽,害其及身,以言报更也&quot;之记载,说明饕餮是种贪吃的野兽。饕餮是人们通过艺术的夸张和抽象的手法,并综合多种动物特征而形成的幻想中之怪兽,令人有神秘威严之","categories":["09_其它"],"year":2018,"publication":"东方收藏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIPiwdmpwi27REhRyKdFpKt3rQlt0Qh2oWXEHt5uS4eAdk1UIRzG-iz1SBosCq7QZJmL_BLDnx7T9LuTFTJFRzk2aRaVFICijzSNLhTsf02VSvjuCv_-ZxPBnIZ7F-Oy8CVW9zR_S6rMpIAgtGELLizOzJQLhGk8legRCQyLsyCYHmIp0Iz-eaD&amp;uniplatform=NZKPT&amp;language=CHS","pages":"29-36","volume":""},{"id":2107,"author":"付强","title":"司徒雷登旧藏德师簋铭文真伪考辨","abstract":"西泠印社2017年秋季拍卖会&quot;中国历代青铜器专场&quot;中有一件珍贵的拍品——德师盂,系民国时期驻华大使司徒雷登旧藏。青铜盂平唇口沿,深腹,近底内敛,下有高圈足外撇。颈部有高浮雕龙首,双角折卷,占整个头部一半。两目呈&quot;臣&quot;字形,嘴部简化。以龙首为中心,对称分布浮雕爬行龙纹,头部相对,上顶尖角,下有一小足。背部弓起,尾部岔分两向,其一前勾卷曲,另一蜿蜒至地复又内卷。腹部装饰百乳雷纹,亦称","categories":["09_其它"],"year":2018,"publication":"大众考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ8iaCwnXKNOfFxuFRgEh4qJ76AL4OY8Rz1wM3MypJH-FGYUjXBB8HFqFReaaPS9LhZ6pW7szhItwVr_d0SylMPMLH5uJvEhQ1cSP0UD_WUxDkWXdVO6nN3VTob3A5FbpN4Nnm0T6wO09XBTIapFaK4V2vCobiIIpo893GDYaN6tZUN5KB6P6wG&amp;uniplatform=NZKPT&amp;language=CHS","pages":"76-77","volume":""},{"id":2119,"author":"赵敏俐","title":"中国早期书写的三种形态","abstract":"书写是几千年中华文明得以传承不断的重要方式,甲骨文、金文和典册文是中国早期文献的三种主要书写形态。它们运用不同的书写工具,有不同的书写方式,承担着不同的文化功能,也有各自不同的发展历史,在中华文化史上各自具有独特价值。甲骨文和金文以实物传承的方式,向后人展示了中华民族早期书写技术和制度文化建设所能达到的高度,但它们都属于具有神圣色彩的特殊书写,在中华精神文明传承过程中影响有限。要充分认识三种书写形态特点,特别是认识中国早期典册文献所承载的历史事实与文化精神双重记忆的功能,将其进行分层研究,与甲骨文、金文书写互补,与当代丰富的考古学成果相互发明相互印证,进而从中华文明的物质考古深入到精神考古,开创早期文明史研究的新局面。","categories":["09_其它"],"year":2018,"publication":"中国社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLWqYLQWzdeeuAs7aixO0BrnnLCKJiqdZhIJaCEo4sLbkH5YXEffju2IgYykWcsiJ73pqU0zIcSwLixdXxJj0scEtpLOq5iCsfbyauA65zeRq0Aq3r2MUJC770PCRTBfnlAHXodkkvoNcNRx8aALwR51Uwt9hLU36yjPCG4EQkHnzWeY9nTGLMm&amp;uniplatform=NZKPT&amp;language=CHS","pages":"162-183, 208","volume":""},{"id":2125,"author":"张翀","title":"金文整饬的动力与方法——以早期铜鼎铭文为例","abstract":"金文,指的是铜器上铸造或錾刻的文字,为中国古代青铜器显著的特点之一,也是与世界古代文明中的青铜器物的主要区别。很多情况下,金文作为古文字材料进行研究外,也被视作商周时期的书法材料。在讨论先秦或早期书法史时,大多直接采用若干青铜器的铭文,并加以论述。无论是古文字学还是书法史,讨论金文时,都不同程度地使用到&quot;风格&quot;一词,说明两方面的学者都或多或少注意到金文风格变化的问题,或者更为通俗地称之为&quot;书风&quot;。容庚先生在《商周彝器通考》","categories":["09_其它"],"year":2018,"publication":"艺术工作","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIjrDDUtPhI6s4UtlR5Sd6rQ3DMeCBVWfhpJUPfhoIymaqAVFPpM07a3-LBxFt2aPlSjGzPlyZaYRVzEQdg7oCbcKijpDfnEOfFXjPK1eXP4udfg0CM6n75cf58MepGMi6Icps_OUzpnY3eIJTAyGny5fpisXgXoII180zRfPkRZUfc4ggfAp7a&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-68","volume":""},{"id":2127,"author":"付强","title":"新见铜器辨伪三则","abstract":"文章介绍了三件新发现的伪作铜器,通过仔细分析和辨别,发现这些铜器都是根据以往的真器伪作的,这对于认识伪作者的伪作技巧和提高学者辨别青铜器的真伪都有一定的帮助和意义。","categories":["09_其它"],"year":2018,"publication":"文物鉴定与鉴赏","link":"https://link.cnki.net/urlid/34.1312.K.20180210.1129.010","pages":"18-19","volume":""},{"id":2130,"author":"孙敬明","title":"陈介祺《周矢朐瓦盘图》小笺","abstract":"山东潍坊市博物馆藏清代潍县金石学家陈介祺《周矢朐瓦盘图》,上半部为&quot;矢朐&quot;铭文墨拓;下半部为瓦盘全形拓;右上为陈氏篆书&quot;周矢朐瓦盘图&quot;六字;左侧为陈氏长篇考证跋文;通图钤印十一枚,分别为&quot;大兴周咨度收藏金石书画印&quot;&quot;澹然珍秘&quot;&quot;海滨病史&quot;&quot;收秦燔所不及&quot;&quot;古瓦量斋&quot;&quot;齐鲁三代陶器文字&quot;&quot;姚公符作图&quot;&quot;有周陶正之后&quot;&quot;齐东陶父&quot;&quot;三代古陶轩&quot;&quot;谘度藏","categories":["09_其它"],"year":2018,"publication":"走向世界","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKfGXGXvAvfqcxISVpX0rDLtrVo0r-Vsj5bF8AGdfAruw-uGZs5AB0G7Gj_4VGkF2t4ceEjZ7R3Al_RJbL4kveBPZScUGZAP_j-A4JROI3g-WGnprxrsQBCkvN1NdkMjCWwKv8kODZI_L_ETrYC1jQiHBswOFnEHZCk3a0_j4aBIDytnLdozAlC&amp;uniplatform=NZKPT&amp;language=CHS","pages":"68-71","volume":""},{"id":2142,"author":"刘卫华","title":"战国铭文大美在兹——中山三器铭文的文化艺术内涵","abstract":"1977年,考古工作者在河北省平山县三汲乡战国中山王墓葬群发掘中,出土了大量的铜器、陶器、玉器等中山国文物。其中,有三件青铜器分外引人注目,这三件青铜器不仅铸制精美,且都刻有长篇铭文。三器上的铭文均有明确的中山纪年,内容丰富、文采斐然、书法精湛,是战国时期青铜铭文的典范,被学者们并称为&quot;中山三器&quot;。","categories":["09_其它"],"year":2018,"publication":"收藏家","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKQAw9ELlGPZAX-2mNmDUxzMk0PwMY_fhepxO1AtBRZdBZZKvJ_bsucDYnkt6WGR8Nk5MwrtEZ7EFpWX2Id54JPOonJ-pe_qG8bJQWjzMJ6ryayPO6cMFrBHGM8r_6PiLPdxhy2Y3IMfH3Ka5LHlJTNFw2dswjsFpntued-YF8ddD1wFDpROHm6&amp;uniplatform=NZKPT&amp;language=CHS","pages":"15-20","volume":""},{"id":2216,"author":"郭侃; 馮勝君","title":"《穆天子傳》文本整理及相關問題研究","abstract":"《穆天子傳》為西晉初年出土於汲縣戰國古墓中的竹簡,是汲冢竹書中至今唯一被完整保存下來的。本文即以《穆天子傳》為主要研究對象,結合近年新見的出土文獻及研究觀點,對《穆天子傳》文本作重新整理。正文分上、下兩編。上編共分為三部分。第一部分“《穆天子傳》校釋”是對《穆天子傳》原文進行重新整理、校注,主要內容是標注目前筆者所見各版本間的文字異同,收集前人的校釋成果,最後以“案語”的形式陳述筆者自己的研究觀點,包括一些直接隸定文字的釋讀,一些語辭的訓詁。第二部分“《穆天子傳》中所見地名集釋”是將前人考證的“穆王巡行地點”論著、研究文章做搜集整理,析出觀點,最後依然以“案語”的形式陳述筆者自己的研究觀點。第三部分“《穆天子傳》中所見氏族名、人名集釋”是將前人考證的“《穆天子傳》中所見氏族名、人名”論著、文章做搜集整理,析出觀點。下編共分兩章,皆為《穆天子傳》的相關問題研究。由於此前已有大量關於《穆天子傳","categories":["09_其它"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKKQXyb8X5kWjVtjMuYRZt1HG2bkbegR-07WIyb0tLfeDXaevCYqmflJVCnTXeLyn2kCqHSN6yhb_InzKuXICPRBibKwvu9IqYENmlyJOQmi5Fal3UYRQUHZIYTa3yJGh5fHt-bNTosgJRXwxBvu9kieRhv_DU4QG877-cUH6ydsWxdSXa3vWlO&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2220,"author":"郭国权","title":"清代金文考释对照法的运用","abstract":"清代金文考释广泛采用对照法,尤其是对《说文解字》与传抄古文的利用。清代学者对照《说文解字》字形考证金文取得丰硕成果,但他们对传抄古文抱审慎与怀疑态度。这种态度一方面制约了传抄古文的利用价值,另一方面,则体现了他们的严谨精神。","categories":["09_其它"],"year":2018,"publication":"北方论丛","link":"https://link.cnki.net/doi/10.13761/j.cnki.bflc.2018.06.020","pages":"96-98","volume":""},{"id":2224,"author":"郎剑锋","title":"青铜“灶鼎”研究","abstract":"在考古发掘出土与传世的青铜器中,有一类器物的形制比较独特。器物主体部分为鼎形,或方或圆;其与常见青铜鼎的区别在于,在鼎腹下面附加托盘或围合出独立空间,或将鼎腹内部进行分隔以形成夹层。关于此类器物的名称,学术界有&quot;温鼎&quot;、&quot;附灶鼎&quot;、&quot;灶鼎&quot;、&quot;鼎形温食器&quot;、&quot;异形器&quot;等多种称谓,或径称&quot;火锅&quot;,亦有不知其名而归入&quot;杂器&quot;者。笔者认为,&quot;灶鼎&quot;之说因有铭文根","categories":["09_其它"],"year":2018,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIZz6eJh09UlE0xQdwG0ek3UEmPDJuKT0nBZDPVS7DtxdvJPT3m7dr1oDdRr-czd7w6lHOL9l2YZE2MTvsM33AT67Orq4ApNk9rrsEQl3SLwXQkqXT8rDiBmaB4vusWvEMP9q1b85xiqD07lJevqD9hhjOT0AUbqmY2FfqmLFyuPT3T8bRXL_Sp&amp;uniplatform=NZKPT&amp;language=CHS","pages":"85-100","volume":""},{"id":2229,"author":"李文英; 曹斌; 曹春水; 黄永祯","title":"一种基于深度学习的青铜器铭文识别方法","abstract":"考古出土的青铜器铭文是非常宝贵的文字材料,准确、快速地了解其释义和字形演变源流对考古学、历史学和语言学研究均有重要意义.青铜器铭文的辨识需要综合文字的形、音、义进行研究,其中第一步也是最重要的一步就是分析文字的形体特征.本文提出一种基于两阶段特征映射的神经网络模型来提取每个文字的形体特征,最后对比目前已知的文字研究成果,如《古文字类编》、《说文解字》,得出识别的结果.通过定性和定量的实验分析,我们发现本文提出的方法可达到较高的识别精度.特别地,在前10个预测类别中(Top-10)准确率达到了94.2%,大幅缩小了考古研究者的搜索推测空间,提高了青铜铭文识别的效率和准确性.","categories":["09_其它"],"year":2018,"publication":"自动化学报","link":"https://link.cnki.net/doi/10.16383/j.aas.2018.c180152","pages":"2023-2030","volume":"44"},{"id":2832,"author":"黄薇; 张懋镕","title":"中国古代青铜器发现与研究史","abstract":"中国古代青铜器是享誉世界的文物,自史前时代诞生,到战国末年,至少有三千多年的历史。有关青铜器的研究自北宋金石学始,也有一千年的历史。面对不断涌现的青铜器发现资料和研究成果,需要我们整理归纳,考镜源流,阐述近千年来青铜器研究的发展历程与基本特征。本文采用时间分期的方式,尝试综合分析每一时期青铜器研究的特点与方法。共分为五期。第一期是萌芽期,谈宋代以前的青铜器研究。宋代之前的人们认为发现铜器是一种祥瑞之事,并且已经开始对铜器年代进行初步判断,研究成果大多零星记载于文献中。第二期是雏形期,谈宋代到清代的青铜器研究。宋代学者的最大的贡献是确立了青铜器研究的著录形式与研究体例,对铜器进行了初步的定名与分类,开创了青铜器研究的最初研究范式,为后世树立了典范。清代学者将青铜器作为学术研究的对象,纠正了宋人在定名与分类等方面的一些问题,且研究者众,著述丰富。本期重要特点是重视铭文研究,并取得较高的成绩。第","categories":["09_其它"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKqu9EEVoJ3rnXtjK-xak0nxiQ-ZZT-QCV4JrsR7-LuLfnnIvEct4256cwm3aCSUVkpKlM3r-akSUcLltmcRL58QigtOEXswV8klU0WODoMZr24pqpdUB97uS3AVCCnesLZJ20ai0mbdujcLSUq_6z-4_nMCH-AESaGD3zPBPtX3YXGXbI1o0i4&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2841,"author":"诸莉君; 顾宏义","title":"《宣和博古图》研究","abstract":"《宣和博古图》作为宋代金石学著述的代表作,作为现存唯一的一部是北宋时期官修金石图谱类书籍,具有很高的文献和学术价值,其内容多可起到证经补史之用。本论文主要通过考订《宣和博古图》的撰者、成书年代、书名含义以及其编修体例、著录器皿方式、器皿分类、纹饰类型与意义等,指出书名“宣和”一词乃徽宗时宫中之宣和殿,其撰者为王黼,成书于徽宗大观年间。同时,通过图文分析,指出《宣和博古图》收录的各类器皿之数量、纹饰特点及其蕴含之意义,并着重探讨了饕餮纹饰的基本特征、分类、纹饰演变等,由此讨论了《宣和博古图》一书对宋代社会、文化、艺术以及对后世的影响。","categories":["09_其它"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIyO69UaG1X1jlIKUEnOql5EefzAg98vETO3rI_Aeto_i3M5XbABIZI-TH_4CdYIKhOvvSN95T-nu41PPSFnWyYlKfy1hWu7TztpwMI6u8SvHCA0K-pDsaJPcV4klPw5Otx7mK76qt2Y4xY7a2qGYPRDW7SILrZMSRJQFHgLQXaNfw_QrGesnml&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2855,"author":"欧阳瑜倩; 孔令伟","title":"《积古图》研究","abstract":"阮文达公《积古图》一卷,是展示阮元早年金石收藏的绘画作品,其内容集书法、绘画、捶拓、治印为一卷,艺术鉴赏价值、文献史料价值都值得称赞。本文除了从图像内容及作者、拓片来源、题跋等方面系统的对《积古图》进行梳理之外,还对积古斋中所藏的重点器物予以笺注,在此基础上,再对阮元的金石收藏思想做讨论。希望由此能以小见大,窥探阮元的金石考据、金石收藏及相应的史学观念,体会阮元对金石学产生的巨大影响。","categories":["09_其它"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI-3AMKgJiVMWzCaCaPuhzgj6lVeSKVyZ2noDoBYQJl5Y0yiFf4eQMkNG-pe5Yu6MyEYOmyg-f2C0-baZO8dKxbxNDHrXc9zjXCpPQz6q5qaME3pc6-_3Cjbr5lee63mB6Qf4_hHZDBTKzIzzrwWpdVFna4RCvG0lXpIaF9pfJu-QHnOQoMOuWQ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2866,"author":"朱华美; 周宝宏","title":"何琳仪先生的古文字学成就","abstract":"何琳仪先生是当代著名的古文字学家,一生致力于古文字研究,尤工于战国文字考释,学术成果很多,在古文字学界有很大的影响。他的《战国文字通论》是第一部战国文字通论性质的著作,对战国文字的研究情况进行了综述,有很多文字考释的成果。《古币丛考》辑录了 26篇货币铭文研究的文章,每篇考释都非常精彩,对古文字学以及古钱学研究都产生了重要的影响。《战国古文字典——战国文字声系》是一部汇集战国文字成果的综合字典,既有当时的学术前沿成果,又处处体现着何先生自己的发明或学术成果,编排方法新颖独到,是我们研究战国文字必备的工具书。《安徽大学汉语言文字研究丛书·何琳仪卷》收录了何琳仪先生的多篇古文字考释的文章,何先生重要的商周、战国文字考释的论文大部分收录在此卷之内,在文字考释方面,何先生提出了很多独到的见解,体现了他深厚的古文字功底。除了战国文字,先生在甲骨文字考释、青铜器铭文考释等不同领域也取得了重要的成果。此","categories":["09_其它"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKjM4QRUYDHO1TS3rJUUTCOtdQGqhPkU5MaEWIp4wkV6Tpo6xIPxdcxseFDLbuPWqzER2jBApYPeC-Ll85r3ctC-D1Bu3X-5ST1hNaqVgrZq0nYuWGoNKFnPTZXNbxPV3-tYRuapuS_ZqYSAQX5aOSOs3G_LyTWB1y4PamlwmWGfmFOZ2L86uri&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2868,"author":"徐思奇; 周宝宏","title":"刘雨先生的青铜器铭文研究","abstract":"刘雨先生是著名的古文字学家、青铜器专家。本文以刘雨先生在研究青铜器铭文方面所取得的成就为考察对象,分门别类地系统论述了刘雨在金文礼制研究,金文月相、断代及年代学研究,金文考释与研究,主编参编的著作这几大方面的成就。全文主体部分分为四章。绪论部分包括两方面的内容,第一节概述刘雨的生平及学术成就,第二节介绍研究意义与研究目的。通过这一部分的内容,我们可以了解到刘雨的生活经历和求学经历,并对他学术活动的三大特色有一个宏观的把握。第一章探讨刘雨的金文礼制研究成就,金文礼制是刘雨学术研究的重点内容之一,他致力于为我们还原西周礼制的原貌。本章将刘雨的金文礼制研究分为六大板块,即金文的射礼、金文的祭祖礼、金文的军礼、金文的封建礼、金文的飨燕礼、金文的相见礼。第二章探讨刘雨的金文月相、断代及年代学研究成就,金文月相、断代及年代学研究是刘雨学术研究的又一个重点内容,提出诸多独到新颖的观点。本章主要分为三大板","categories":["09_其它"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL_5zezcNBvrmEVgwY_ef6Vb5PfvVh1mQWJ1y_MPKSKKe2e5zas-K-aHC306ZEzVsNziKXme0FOA9HkvIci9N7vAQk8cpyYaCMq2boFlNvY7vBVfNPxXN1zsqtS28nEoOANRudF9p1tVnm-3xgvV56H-iaXbLwOuvCV74sDkp6mqYzQ7jYFp7X1&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3136,"author":"许敏; 郭永利","title":"论高本汉的中国青铜器研究","abstract":"高本汉是瑞典汉学家,他对中国青铜器的研究也很重要。本文重点分析了高本汉的《中国青铜器中的殷与周》、《殷代的一些武器和工具》及《中国青铜器新研究》等成果。在《中国青铜器中的殷与周》中,高本汉通过分析青铜器的形制、铭文、纹饰等信息,将带有“亞、析子孙、举”等三种图形文字的青铜器归为殷商时期;带有周代国王名字、周代王室宗庙、周代封国名字、周代大臣名字等青铜器归为周代。《殷代的一些武器和工具》,高本汉运用类型学的方法将所收集的青铜武器和工具进行分类,在此基础上确定了他所收集的武器和工具的年代,并结合国外一些学者对带有动物风格的青铜器起源地的相关论述,探讨他所收集的中国青铜器与西伯利亚地区卡拉苏克文化时期青铜器的关系,得出中国殷商时期是动物风格青铜器的起源时期,西伯利亚地区卡拉苏克文化时期的青铜器受到殷代青铜文化影响的结论。《中国青铜器新研究》,重点分析了古典式中的A、B、C三类,他认为A、B两类纹","categories":["09_其它"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJjaY_Xt_NrlZSky8hJ5XA8310RBBFLRjDJ4md3GPuTYafryXHODlfuEgK9nIlDGRagTiTdxyLK_WdQAoAMLtry_gUTRxIHoSQDE08NP7XEGuK_zh-0CPYTGAJYHtgDzld0620ijBwBmflUKUemesjdDnbvgFGxPjpP_APlE7KgUuwsFhqpaIiC&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3146,"author":"王瑩; 徐在國","title":"湯餘惠先生古文字研究初探","abstract":"湯餘惠先生是我國著名的古文字學家,他在甲骨文、銅器銘文、戰國文字等方面都卓有建樹,著有《戰國銘文選》、《戰國文字編》、《古文字學概要》(合著)等著作,主要學術論文有《略論戰國文字形體研究中的幾個問題》、《讀金文瑣記(八篇)》、《古璽文字七釋》等等。本文在全面研讀湯餘惠先生古文字學相關著作的基礎上,探討湯餘惠先生的古文字研究實踐,總結其考釋古文字的方法和特點,并對其研究成果做出較為合理和相對客觀的評價。本文主要分為三章。第一章緒論,介紹湯餘惠先生生平及其學術述略,同時說明目前國內外研究現狀,以及研究本課題的內容、方法、目的和意義。第二章是湯餘惠先生的古文字研究評述,第一節是湯先生的主要著作概述和工具書的編纂,分別介紹《古文字學概要》、《戰國銘文選》、《戰國文字編》以及幾部大型甲骨文工具書的編纂。對於《戰國銘文選》,主要參考劉釗先生《讀新出版的<戰國銘文選>》,他对該書有一個中肯的評價,我們從","categories":["09_其它"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK-LiyruguGN6im7vg_OWV9uKIciGyh0UzgnDhpdjYXS47Eu6Mq49TBlIRFL8wIS-fcH_TMF1u9EzFRvNTKL_efoYge5tFlhqp7RSNTprJeQ6C1rCD41DCoLvuFHoNrufmip_sVgjjmjINYD9UgxDIl_sNZxxfiios9PoMHAKCwEj1KvzqAbEKj&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3148,"author":"楊菁; 徐在國","title":"陳介祺金文研究","abstract":"本文以陳介祺的金文研究為研究對象,在充分利用大量資料的基礎上,通過綜合運用比較、歸納、演繹的方法,梳理出陳介祺金文考釋的具體成果。并以此為依據總結出陳介祺的“釋古文字,以多見為第一”、“以出土古文字材料來訂正《說文》,證補《尚書》”等學術思想,指出其對晚清金石學發展乃至古文字學發展有不可忽視的貢獻與影響,從而達到本文對陳介祺金文考釋研究成果做出全面、系統、客觀的考察,填補陳介祺金文考釋研究方面空白的寫作目的。文章主體分為四個部分,第一章為緒論,主要介紹陳介祺的生平述略、著作及學術成果,并說明本文的研究內容、研究方法、研究目的、研究意義及目前此課題國內外研究現狀。第二章為本文的主體內容,是對陳介祺金文研究內容的整理與評述。以陳介祺對其所自藏有銘文商周青銅器的考釋為研究對象,并將其分為兩類:第一類是金文冊釋、藏古目及題跋中包含的金文考釋;第二類是單篇器物考釋文章中的金文考釋。此部分重點整理出陳","categories":["09_其它"],"year":2018,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKSL_rwMDSTEDA9WX6d7YwPFPVtUSGpoDmh40yPnRYuQ_vNoM_Htz4gMrWFzQNwTV8AB3Jtjb5p1Ztglmp0l58mlADqa002MBjebQIHAHhJnPyIxVCWi5VlbzRwbFLKVvu3quexUycQ_FhorCa93zzRrSnkffZV5Io9UWwW41QL8i94PDiZyJJU&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3271,"author":"杨蒙生","title":"■羌编钟海内外研究情况述评","abstract":"二十世纪三十年代初出土的■羌编钟是一套十分重要的战国乐器。编钟铭文记载的公元前404年三晋伐齐一事,对于战国史研究具有十分重要的学术价值。然而,由于时代原因,此套编钟很早就散失海外后续综合研究多以国外学者为主,相关成果在国内亦少有见到。在新的历史条件下,为了有效挖掘此套编钟在我国先秦史和音乐史等方面的研究价值,有必要对其本身各方面情况和海内外的相关研究成果进行系统梳理。这就是《■羌编钟海内外研究情况述评》一文的写作初衷和主要内容。","categories":["09_其它"],"year":2018,"publication":"海岱学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKvKVNVwK-2lg1nlsY6zbTPpA2ZoNiaPycBThCf0IGbT0o-FLF55QJlywvqzuacQPG3JHg0wC-fpCjWMM4hHgTnJJ7hWXDJdwY5boVmrKHaLWyy_O5alZ5pS7QhIo3VsWMICsPMju0dwFGnI7f2wfc2_3wP_rhL4St7vguoJVU85w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"56-90","volume":""},{"id":3338,"author":"韩炳华","title":"关于两组与“师雍父”有关青铜器的辨伪","abstract":"师雍父是西周金文中重要的人物,铭文作师■父,见于■鼎(集成02741)、遇甗(集成00948)、臤尊(集成06008)和■卣(集成05411)。师雍父又称伯雍父,见于伯雍父盘(集成10074)、录簋(集成04122)、录■卣(集成05419、05420)。与师雍父相关的人物又能系联很多铜器,在西周铜器断代上有重要的价值。最近有两件与师雍父相关的器物,一件为山西博物院藏的■鼎(以下简称晋博■鼎),一件为首都博物馆藏的臤尊(以下简称首博取尊),这两件器物过去都没有著录,但铭文却分别与■鼎","categories":["09_其它"],"year":2018,"publication":"三代考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKeW-z8Bm3e1nmrIUEhN60SeXc163H1hkycpR4eC9mwu2mzhwtQgrtebHlwjANMoksaYi9HoQ6MfLLmQ3j_onQ-MhryRoJrLnGpCruVeTihVZTppqaFu2vBnnINHrPONXLroyEUxunZiWDFokrzbNQM3pfaTmIVwJT8zlt_Srtqpg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"518-526","volume":""},{"id":3389,"author":"冯锴","title":"中国王国时期文明特征管窥——以随葬品为观察对象","abstract":"特定随葬品特征一旦普遍、重复出现,就代表了某种文化,即指导该随葬品特征形成的思维方式、行为处事方式和价值观。本文从器物本体、器物上的纹饰、器物上的文字三个维度出发,对中国古代王国时期随葬品特征进行研究。最终得出王国时期的文明特征为:以礼与规矩为核心价值观,以中、对立、变通为思维方式和行为处事方式,以汉字为书写和交流工具,以崇尚鬼神为社会风气,以血缘关系为家国关系的根基。这些文明特征在王国时期萌芽或形成,并在以后的历史长河中不断传承与发展。","categories":["09_其它"],"year":2018,"publication":"常州文博论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIfjDXcEuVpb8g-2VkXHnDAeD4NxP9vxD4MDvFTTHZ9yMJUNmqv_pwuEJtrGP2qV24luGeAeW9s12SdoOmXjes4d519D8v_E2uTS_oCSJMa-qMc11rDDAXCx3foMdLBkvyEImbdDbnQJyE1S-k2YmPqgyZ1cGvHh0yKPlWnyaZBWQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"16-24","volume":""},{"id":3390,"author":"宋紫姣","title":"八大山人与《历代钟鼎彝器款识法帖》之关系略论","abstract":"本文通过对《历代钟鼎彝器款识法帖》的版本及八大山人家学渊源作了初步考证,并将八大山人的花押、《石鼓文篆楷书册》与《历代钟鼎彝器款识法帖》中相关内容进行比对,认为八大山人的书法在一定程度上是受到《历代钟鼎彝器款识法帖》的影响的。","categories":["09_其它"],"year":2018,"publication":"广州文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIfjDXcEuVpb8g-2VkXHnDAeD4NxP9vxD6xMWeGuQ9uUXOkx7FDsPgq4Z-Wjo2ZwcsHHrt4aXTHR7RwbQ7Iy6nIpiq3J6tM-tWJoo0-Xj20i7OdohgeIzIBRw1B-C7Gcx8zFo-acWIcsMSEqwmP3oyw6vEwmxJPiHqksk-MSYzeTw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"268-273","volume":""},{"id":3396,"author":"邵英","title":"中国早期文化视域下的古文字研究——《古文字与中国早期文化论集》读后感","abstract":"汉字的产生是人类历史上惊天动地的一件大事,文字的使用是人类社会进入文明时代的一个最准确的标志。中国文字起源时代是中国文明诞生的一个组成部分,而且是一个最重要的判定标志。中国文字正式起源的时代距今5500-5000年,古文字形体本身就是当时社会生活的真实反映,具有&quot;活化石&quot;的作用。通过古文字甲骨文、金文的字形结构分析,并与考古文物资料、古文献资料相结合,运用考古学的观察方法,把古文字字形当作考古对象,探讨其文字字形本身所蕴含的上古社会所赋予的文化信息,我们可以了解远古时代的社会生活、生产工具甚至思维方式。这种文字形体考古文化式的研究方法不仅扩大了历史学史料的使用范围和途径,扩大了学术新视野,而且也是新的学科增长点。","categories":["09_其它"],"year":2018,"publication":"陕西历史博物馆论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJsrXHW209Zue9J6XF8ubbngl1rIqYO8Nh-OCvzOX5DXnLdjNQct5rYV5baL43Lq7s8WbNLNNFE2VdPTphloio_u3744f2Qvs3Qe-CjuMdMmgPkMpp4v3v9kTUoRdEvsPTcQrn1ssrD-r9AtsOn2gczmg0VRWHtEySIdvmAxpbhYg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"409-412","volume":""},{"id":3400,"author":"黄锦前","title":"近刊铜器铭文辨伪举隅","abstract":"近年公布的一些文物市场和私人藏家手里的青铜器甚多,其中又以先后出版的《商周青铜器铭文暨图像集成》（1）（以下简称&quot;《铭图》&quot;）及其《续编》（2）（以下简称&quot;《铭续》&quot;）收录较为集中,我在研读之后,对其中部分器物的真伪有一些不成熟的意见,写出来向大家请教。一眉子鼎《铭续》著录有一件私人收藏的眉子鼎,（3）直口窄薄沿,方形附耳,深腹圜底,三蹄足,颈部内收,腹部有两道细箍棱,盖面隆起,上有轮形捉手。通体饰蟠虺纹（图一-1）。《铭续》定其时代为春秋晚期。鼎内壁有铭文（图一-2）,《铭续》释作:","categories":["09_其它"],"year":2018,"publication":"陕西历史博物馆论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKyV6e7a6cvxQwz9iSWGF2VQNMH4Wvu2v6L3knTdlP5dcqfw8YpA2GRIBo-mKfLGcpObFl-OhmPLNwJrcy1CfwM5GTc8vubB-s9HngwFIJVoPyBnIUJTsAHW3Qn5J9YooXFEpBeLclfeQVgLMXA1tBwg56nfL8KsBzStNjhXU-t9w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-67","volume":""},{"id":3421,"author":"周亞","title":"貉子卣真僞之我見","abstract":"《西清古鑒》(以下簡稱《西清》)15.9和15.11著録有兩件貉子卣(圖一),前者爲貉子卣一,後者爲貉子卣二。據《西清》繪製的圖像和描摹的銘文,兩者的區别在於貉子卣一的蓋兩側有犄角歧出,蓋上是圈形捉手,貉子卣二的蓋兩側無犄角歧出,蓋上是菌形鈕;貉子卣二的器、蓋鹿紋間有一個凸起的獸首,而貉子卣一的鹿紋中没有這個獸首;貉子卣一的銘文最後兩行分别有五個字,而貉子卣二的最後兩行分别是六個字和四個字。","categories":["09_其它"],"year":2018,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKj0eOm3ShWbmuxJ4CnF1HsodlvrFLxmfC4GTn39D5oC4BZ5Ep3Rrxsl1RhQkPgd_AUCq0OuQfUBPe6OdDAG2DGcXlbhdppMLzgf2Fq206SuSosPKPVNG_y6U2ay6IFcpYP0iHkCiiY_yw89WhMiF4Q1MpVG5tcGp5S-f-kIyaYrg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"358-367","volume":""},{"id":3422,"author":"蘇榮譽; 岳占偉; 柳揚","title":"論鉸接提梁卣中的樞分鑄青銅器","abstract":"甲骨文和金文中所及的&quot;卣&quot;,似爲酒的容量單位,是否後來發展爲容器,并無自名證據。現今所言青銅卣,本爲宋代金石學家定名,可將具有剛性提梁和蓋的容器統括爲卣,歧義雖不少,却無關宏旨。據此,卣的出規可上溯到商早期。1982年鄭州東關口南向陽回族食品廠","categories":["09_其它"],"year":2018,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKj0eOm3ShWbmuxJ4CnF1HsodlvrFLxmfC4GTn39D5oC4BZ5Ep3Rrxsg88PegbicZZ2aY7L4KK1wsgA4ZTh084AYP-QBzeCGCa8zzjp3wAAwSJuHUkMEr3_ITMNFmveB5TRKK5_DOhkenoOXCWiSRglscfQn7K3hTf8dDFveAMUIQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"368-386","volume":""},{"id":3434,"author":"馮時","title":"經學、小學與考古學","abstract":"經學不僅是中國傳統學術的根基，也是中國文化的根基。從六經皆史到從經學發展出史學子學，無不體現着經學作爲中國文化淵藪的意義。何謂經學?澄清這一問題的關鍵在於我們對“經”字的意義如何理解。《説文·糸部》:“經，織也。”甲骨文、金文“經”本作“巠”，象織機但布經綫之形，後則增加表意的“糸”符以爲形聲字。古人紡織必先置經綫，然後才可能於經綫之中穿以緯綫，最終織成布帛，故無經綫則無以施緯，更無以成織。經綫作爲紡織的根本，由此引申便可以經作爲一切事物的根本，於是學術的根本也就稱之爲經。","categories":["09_其它"],"year":2018,"publication":"中国经学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIV89oXURuetWBUMvSQIwUl0KlbvE3j-nr8yA3Rdynv23tlUC_VX-As-XnIBAY2z8Js_kvqusGEAEYUWQ9nuJWXqh__n35itfYqYOevQMgnZf_TLPFTSM2F-b4PmYiFd7A2c5iV37WmC10FOYrdg02luIZa67ibzaV_aOn3W6JlbA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46117","volume":""},{"id":3444,"author":"程存洁","title":"容庚先生商周青铜器藏品的流传及学术价值","abstract":"容庚先生是我国著名的考古学家、古文字学家和收藏家。新中国成立后不久,他于1956年先后两次向广州博物馆捐献自己珍藏的古铜器共计95件。对这批古铜器捐赠品,无论是捐献时间,还是捐献数量,长期以来,学界存在不同的说法。本文依据捐献清册原始档案,不仅理清了上述问题,而且就这批捐献品的流传情况作了追本溯源的考察,由此也更加坚信:这批古铜器是我国文博界为数不多的比较完整的旧藏铜器,在广东乃至全国的商周青铜器藏品中尚不多见,具有极高的学术意义,特别是该批铜器上的金文,学术价值更高。","categories":["09_其它"],"year":2018,"publication":"湖南省博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKGONRGqKD44MS9L_99gV3Urxitnepr2I-iZR0lDrrm73dXTGZKQ9hr9sr3DhgjTjAeykM8mB06FVYb_5R1JFJ7W60kRhQxHCmV_Rg7PZSRzeDgsDjvSI8doZOqIb_2fwIkDQK2eoPnb87SUxwgOunxYqWYjf09JO596ScnGUrwag==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"87-99","volume":""},{"id":3445,"author":"苏荣誉; 吴世磊","title":"桃江金泉青铜马簋及其相关问题研究(下)——兼论马形器、长颈牺首饰和悬铃诸器","abstract":"桃江金泉出土的马簋是一件造型独特的孤品青铜器,对其年代和产地有不同的认识,类似的现象普遍存在于商周青铜器研究中。青铜器本身所包含的艺术、物质和工艺等信息,是探讨上述问题的直接材料。本文仔细提取马簋的艺术和工艺信息,通过对其风格特征的四个要素:马形与马饰、长颈牺首饰、高浮雕的内壁相应下凹和悬铃饰,进行来龙去脉的梳理,分析这些风格要素的工艺表达方式。","categories":["09_其它"],"year":2018,"publication":"湖南省博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKGONRGqKD44MS9L_99gV3Urxitnepr2I-iZR0lDrrm73dXTGZKQ9hrsH53XEjGtTVId7eYkqARPf4TeZeWxmjgPVgIem2v_YC6_f-F4Vk4DPhn3C0yxXn7lDbXbV1U9erJEgnWi4Gpwpe4X4S9nJQppYUvTXHJyR4FPi86Al_KcQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"285-309","volume":""},{"id":3476,"author":"张乐","title":"新出陶觥铭献疑","abstract":"陶觥乃新见之商代青铜器,出土情况不明,就其铭文考察,存在诸多可疑之处。首先,铭文首句记小臣脯被王赐予百工之事,以当时之语言材料考察,与情理难容。其次,铭中&quot;圭&quot;&quot;璧&quot;&quot;章&quot;等字写法均与其常见形体不合。第三,出现了&quot;上祖癸&quot;这一生造之词。第四,铭末的&quot;嗣&quot;字用法不明,既无法以&quot;继承&quot;之本义解之,又与其时&quot;嗣&quot;字的假借情况、使用情况相悖。故笔者以为此铭实有作伪之嫌。","categories":["09_其它"],"year":2018,"publication":"励耘语言学刊","link":"https://link.cnki.net/doi/10.13554/b.cnki.liyunyuyan.2018.01.007","pages":"103-108","volume":""},{"id":3477,"author":"刘明科; 郑红莉","title":"秦公钟与甬钟的组合探析","abstract":"青铜编钟类乐器,由于其演奏旋律功能属性之需要,决定了它的存在不是单一的。也就是说,演奏一曲完美动听的乐曲,必须要有不同的乐器相互组配以共同完成。这些乐器或依大小相次,或依发音序列,或依墓葬固有配置,或依纹饰演变规律,或依器身铭文先后衔接而成为一套,这就是考古上常常说的&quot;组合关系&quot;。这种组合不仅包含有时代的特征,而且与棺椁制度、随葬品数量等因素密切相关,据此可以判断墓主人的身份与地位及当时的礼仪制度。因此在考古发掘中不可忽视。","categories":["09_其它"],"year":2018,"publication":"秦汉研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKwE1d_QUX1K-4l_kPQtv2SVL7LdqwQq8Ck8-wSHb0YI4mmED1n_qUsnPwGRrFU0JnNZjQ98OiLMCgZ0wcXFFQ6rnsB9jclCMM4VjrWft-_Wre0luPbGP_G4K2YEpGYE4gOqfzKov0OZdMPpLmZhCrNyYxxg8v1XGPiC4EhcaQRSA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"122-137","volume":""},{"id":3537,"author":"顧王樂","title":"新見“秦公簋”銘文辨僞","abstract":"吴鎮烽《商周青銅器銘文暨圖像集成》（以下簡稱&quot;《銘像集成》&quot;）04252收録了一件私人收藏的&quot;秦公簋&quot;（圖一）,蓋内鑄有銘文&quot;■公作寶■&quot;,傳出自甘肅禮縣大堡子山。[1]《秦出土文獻編年訂補》稱爲&quot;某氏秦公簋&quot;。[2]吴鎮烽《金文通鑒》系統已將其名稱改作&quot;秦■簋&quot;。《商周青銅器銘文暨圖像集成續編》（以下簡稱&quot;《續編》&quot;）","categories":["09_其它"],"year":2018,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIJ1EsWfwlyiuvRGNg6_sd-tU1hFfLg9X__K26l4FOXIFAZxBKfZbOlf2yneNn5yFkgLyqXj3BqWS70hJP1dM9Wkl_3N4HkgbuSsDIr2XrBgIIqkJwyEzd0HtK1p4G8UBB712EfearaREdBv2MHe4_HPbEtEpK_NQM2sBRIP4IFAw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"66-70","volume":""},{"id":3728,"author":"","title":"《汉字好好玩》","abstract":"传统的汉字学习总是强调笔画与笔顺,却忽略了象形文字的艺术美感,其实每个汉字都有属于自己的图像与故事,汉字学习的过程就是最好的文学与艺术的启蒙训练。在《汉字好好玩》中,作者将甲骨文、金文、篆文等古文字融于75幅原创汉字画作品中,让读者了解汉字的起源,感受汉字的魅力!","categories":["09_其它"],"year":2018,"publication":"发明与创新（职业教育）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKGS1xdHEHeVWR5WCWyCIyKfrIczYxHG1xRYSF6sMf-PLzs7vqVMRGN70HCdYsvSJ06WCYVpViY36puAzX_1y6BRekGc6fOgJc4YN1iLac2sdZJ7ykUFBOuICGPU2TgCYuqusLW-2CTvBWI15X7K8qmyjo5mdyMDJzcWIvw5pzmQn5DsYuXUv8E&amp;uniplatform=NZKPT&amp;language=CHS","pages":"81","volume":""},{"id":3731,"author":"陈心怡","title":"试析汉字的演变过程","abstract":"中国历史悠久的文明古国之一,中华民族祖先创造出广泛运用的汉字是现今世界上最古老的文字之一,距今已经存在有几千年的历史了。伴随着社会的不断进步与汉语的发展,作为记录实事的文字,有过很多次的演变发展过程,一般认为,汉字发展史上所出现的主流字体主要有五种,按照其历史特点,本文将我国主要的汉字分为两个阶段:古文字和今文字。贯穿我国发展历史浅析汉字的演变过程,从汉字的发展流传中去体会中华文明的博大精深。","categories":["09_其它"],"year":2018,"publication":"青年文学家","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ_iZ6NuA_pCvkDJVTQMAa9zoW1L3s3jS9KMUPIV2mhCeltR9Swl4w_5E9sYaqRt_r7WgNsA6H5qpVUhYohECVTpM2z-lzesiKUrIj5qO4Xdq7_lP0kXtZLBcu_XibO53XvCRw7b9exRmHyE_eo2eqCHhOBHlmbvZOhIRziofw70RLXhDp6Xx-G&amp;uniplatform=NZKPT&amp;language=CHS","pages":"185","volume":""},{"id":3732,"author":"耿玉璠","title":"国之重宝——从商周青铜器浅谈中华文明人文精神的逐步形成","abstract":"在我国夏商周三代为青铜时代,是中华文明的孕育期和雏形阶段,在此期间产生了数量众多、造型各异、用途甚广的国之重宝——青铜器,特别是商周两代为我国青铜器发展的鼎盛时期,出土或传世的大量青铜器造型优美、装饰富丽、铭文典雅、铸造精巧,具有重要的历史文化价值和艺术价值。其青铜器的变化发展体现了中华文明人文精神的逐步形成,对后世影响深远。一、商代青铜器概况与&quot;神本&quot;思想&quot;商代青铜器的组合中以酒器为主,它们造型凝重、纹","categories":["09_其它"],"year":2018,"publication":"知识文库","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIeJ2GQQUG5Sfdsn-_asyr0nUhUqHfvULhcyTT32r7xjK4C15E_jRv4w3PwPNWK4669mEmGzULfxjtydrVe0xMT2VyUWDE76yT9BSO55BZStK4CqBx92OHowMH150ZOMWkN9GRxBLjs_n0QIzFifjrfRqU3tCo2ORAsRNduWUoi59VLirJlMFeG&amp;uniplatform=NZKPT&amp;language=CHS","pages":"12","volume":""},{"id":1755,"author":"刘建峰","title":"细考铭文探古史姑依墨拓谈书风——登黄地区青铜器铭文书法简述","abstract":"据《山东通志》,登州所属有蓬莱、黄县、莱阳等九县。汉以前,蓬莱属黄县。唐神龙三年(707)始分治,后世因之未改。笔者今不揣谫陋,草成小文,介绍一下登黄地区的青铜器及金文书法,求教于方家。一、登黄地区青铜器反映了胶东地区古国的历史中华民族沿着长江和黄河两大流域繁荣发展,形成了中华文明的主流。在夏商时期,胶东半岛是一个方国林立的地区。这些被称为“东夷”的民族中,至少分布着嵎夷、莱、己、?、","categories":["09_其它"],"year":2017,"publication":"西泠艺丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJclkQ-a4sqBDuhI4EHilWXI3-bUAjEJQkAignpqA_S33abs1GSlmJuTYcN2JbE8XJ_Lf7Y2UgNKUvFo43j1RbY7IFWcNehr2IXRjdwclfL9kAW6EmiSZC-q6w9PCTKF94oouum2Use9IgH9qqQHwIbQKA-A31quZWTtIfbyaeU0bbnHLOeZ-po&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46188","volume":""},{"id":2147,"author":"赵孝龙","title":"一件青铜爵的综合分析与辨伪","abstract":"前段时间,一位友人将其收藏的一件青铜爵(图一)拿来分析,因感慨做器者高超的作伪技术,故将分析过程做了详细记录。众所周知,青铜爵是最早出现的青铜礼器之一,发轫于夏代晚期,盛行于商周时期。作为礼器,青铜爵大多铸造精美,且往往还带有","categories":["09_其它"],"year":2017,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKMI3AG_nyEQZF1R-4zl_jsztoYGJce3RqcwzQNanXSjMgl8nV6jaDxc9_WgIxOaZ7fM6ZEcG7ftBLho1BzTFDdazVqB3mt8KwS3-9DVVBNNpOTjn1qoh7otoE0YQyMO1WK_B4domqW0ZjdyLKh5PDy5dHOWIIDcmqtJ58xIzGKtN0CYyyEwlgW&amp;uniplatform=NZKPT&amp;language=CHS","pages":"151-155","volume":""},{"id":2163,"author":"江俊伟","title":"《从古文字角度谈〈夏商周:从神话到史实〉的若干问题》一文商榷","abstract":"张惟捷先生于《历史研究》2016年第1期发表《从古文字角度谈〈夏商周:从神话到史实〉的若干问题》一文,讨论了郭静云先生《夏商周:从神话到史实》一书中若干古文字学的问题。然细读张文,可见其内容舛误亦多,可商之处凡16组23条,其论据与释读存在诸多问题。总结而言,郭书虽有小瑕疵,然张文所论疏漏之处更多,主要有二大问题:第一,由于张氏行文多引学者文章,对于学者文章的引用或理解产生偏差,很多部分并不能作为反驳郭说的根据;第二,张氏还有对古文字的释读有误,或是对郭书理解不清的情况,这部分占张文全文之比例并不多,但有问题之处却不少。且作为一篇反驳文章,张氏除了少部分内容外,其余大多以学者的看法作为反驳的根据,并非直接针对郭书在材料运用、逻辑与推导方面进行讨论。由于张氏文中存在诸多缺失,导致其文可观者寥寥。","categories":["09_其它"],"year":2017,"publication":"齐鲁学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ9do8tgoouE5kYSRq-XRdP9kvFxoN-jKYw7HPDq_t2-O7E1tKMKl-vxmTBQrNkxHhWFbj7u8H_K5qxwXuIR9KO8xWq_8mwJpxexMyI4mMInmaVNqX9Gv4UGA0HV_F5vxMnUV_cQZf0EYQrSByxRPRY8nLNrBnjHTxyA6WVGEbBO6YcEI09gkwg&amp;uniplatform=NZKPT&amp;language=CHS","pages":"34-47","volume":""},{"id":2245,"author":"苏荣誉","title":"学科范式转换与青铜器图录:信息与青铜技术研究","abstract":"青铜器是中国古代具有高度象征性的艺术品,集历史、艺术和科技价值于一身,是具体技术的产物。对于青铜器的研究和著录,从宋代开始有一千多年的历史,研究内容可概括为名称、铭文、形制、纹饰、功能、制作六个方面,对应于器物学、史学、古文字学、考古学、科技史等学科。学科形成范式才能持续发展,新学科的建立和学科间的交差是科学发展的总趋势。宋代形成的金石学属于史学和古文字学范畴,民国初在西学影响下发展出的古器物学和考古学,以及略晚的科技史,都在以不同的角度研究青铜器。本文从青铜器图录所提供信息的角度,探讨不同学科对青铜技术的关注程度,并试图借以说明青铜器研究及图录的发展趋势。","categories":["09_其它"],"year":2017,"publication":"文化学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJQPbT5ZXwftJqpswo6t1aE7Ib-6R7mljwHx3_n_MNr4ksRuaNvbkdLXTr1VkhOHJuPONo9PHGCSjtlEaSIk_oCu9S6ycakUAN-loYH6hjW_8uLEbHY_5DNRXn3_Dh5U4uDO8HsvMNEOatIzohkcHe2qTRFDAhMHcEbuhr2PY3EqpifLWAO-kLT&amp;uniplatform=NZKPT&amp;language=CHS","pages":"19-32","volume":""},{"id":2259,"author":"王恩田","title":"荷卣、荷壶真伪辨——兼论荷簋、荷尊的年代与族属","abstract":"传世有9字铭文的荷壶,是利用战国时代的无铭鹰首壶,仿照商周时代的荷卣加刻铭文。荷是安阳殷都的望族。荷簋器主荷是子姓殷人。&quot;公■殷年&quot;即周公平三监叛乱之年。荷簋年代属周公摄政二年。&quot;乃令荷嗣三族,为荷室&quot;,&quot;室&quot;通&quot;师&quot;,意为任命荷为掌管三族军队的统率。&quot;三族&quot;即齐、纪莱和逢伯之族。荷尊的&quot;成周&quot;意为成王所建的洛邑的周都。根据葬谥制度,成王是谥称而非生称。&quot;成周&quot;可以作为武成铜器与康王及其以后诸王铜器断代的标准。荷尊器主荷是与康王同祖同宗的周人。荷簋的荷与荷尊的荷不可能是同一个人。荷尊通篇内容都是康王的诰,是另一篇不见于记载的《康王之诰》。由于荷尊是康王诰&quot;宗小子&quot;荷的,可称之为《荷诰》。","categories":["09_其它"],"year":2017,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLYq3l4VfSBP3_kXcsA6XbhCQmWvT89cfVD1wNaMN42bU-vXLm5wN5C-k1Ev_n3NlrbjPrfcfRPKNVZVPNUrnj5KlCCFP3ij5sslXxS4Eh8gwnDWx03tYrVsy4asTov937_1P1x3zsGZuXr9zSUCW7B5OYUtaY1k4uG6q4Gr1ESQsCY2vmgMfrH&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-59","volume":""},{"id":2260,"author":"米永盈","title":"合瓦体青铜钮钟及其发展源流研究","abstract":"本文对黄河中下游、长江中下游地区以及四川、广东等地发现的春秋初期至西汉前期合瓦体青铜钮钟做分型、分式、分期研究,并在此基础上探讨与钮钟发展源流相关的一系列形制问题。指出钮钟的形成与商、周时期的铃有密切关系,但两型钮钟的来源并不完全相同,A型钮钟是吸收铃与甬钟优势特征而成、B型钮钟则直接源于铃;战国后期兴起于齐国的A型Ⅱ2式钮钟不仅在当时影响到其它诸侯国的铸钟风格,还伴随着齐文化的传播成为战国到秦、汉之间双音钟铸造技术传承链条上关键的一环。","categories":["09_其它"],"year":2017,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIjXHxznpF0oqz_QIskGWxV-tIyhx73APrm8RQ13J8DXHLqVOMQfOhdGikqX1Il3z3t1RSRmSDxUhiMX3B5qW93IcgJgwMYM2ULuzsAiUxSeBXmQ-R1JKLBVfi9b8IfvYyFoY-5ZvzEErfDvcAmlhpypBBq-Cx0smmkU42qJe1hGSaAmR6H8JcK&amp;uniplatform=NZKPT&amp;language=CHS","pages":"74-83","volume":""},{"id":2265,"author":"张虹倩","title":"章太炎政治学术的互文及其对场域规训的体认——基于章太炎对出土文献态度的考察","abstract":"通常以为,国学大师章太炎的学术保守与政治激进似构成一对矛盾体。就前者而言,最典型的表现便是抵制其时新发现的出土文献。然而关于章氏对甲骨的态度,&quot;一贯否定&quot;说和&quot;始疑终信&quot;说均有待商榷。晚年章氏实已承认了部分甲骨的真实性(对释读仍表怀疑)。此外也肯定了大部分钟鼎彝器以及宋以前的考释(对宋以后的释读仍持怀疑),而对《陈仓石鼓》、《三体石经》的文字学意义则更是予以了高度肯定,甚至将《三体石经》提高到了与《说文解字》同等的地位。由章氏关于出土文献态度的考察,不但显示出其学术上并非简单&quot;保守&quot;,也揭示出其对学术场域内在运行逻辑的尊重。章氏在学术场域中的严谨与政治场域中的激进均基于其对不同场域内在规训的深刻体认,看似矛盾,实则互文见义,内蕴了深层次的高度一致性。","categories":["09_其它"],"year":2017,"publication":"华东师范大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16382/j.cnki.1000-5579.2017.05.020","pages":"165-172, 177","volume":"49"},{"id":2306,"author":"张法","title":"殷商乐钟命名·乐悬概念体系·乐钟观念定位——试论青铜乐钟的三个问题","abstract":"殷商乐钟无自名,被学界主流命名为铙,也有著名学人命名为庸,从青铜乐器由虞夏时代的铜铃到殷商时代的编铙(庸)到西周以后的编钟来看,铙是从铃的角度去看而得出,庸是从钟的角度看而得出,在铃-铙或庸-钟的演进中,庸更能体现殷商乐钟的本质特性。乐悬概念由簨虡、肆堵、宫-轩-判-特组成,三组概念不但每一后者都可包含前者,而且具有从夏到商到周的时代演进意义。青铜乐钟在最初进入以鼓磬为主体的乐器体系时,被定义为阴阳体系中的阴。随着其入主中心,其性质转为阴阳兼有且阴阳互含而灵活圆转。","categories":["09_其它"],"year":2017,"publication":"文艺理论研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIfYRNtmVNPmtaWcCbci-UFqXoGs8MsenyXhG9SDNcZEz55ItYvPDvOsJWnNU3oJfQoyExsIbTqKyzB1zjVLzrAAlotFHIb2CIcpHjp07Mt6IbzxwWVCpkfXmMGdwwxlcyp7H9JnX1fjYMkdrq-z6ACb8BAPkTsx58CxXJWlHmShK1Uak3d4oDz&amp;uniplatform=NZKPT&amp;language=CHS","pages":"164-171","volume":"37"},{"id":2319,"author":"姚苏杰","title":"商代青铜器铭文的体式与功能——兼论文学视野下的铭文研究","abstract":"文学研究不仅要注意观念的中西差异,更要重视古今差异。青铜器铭文应视为商代最具有文学性的文类。商代铭文内容规整且结构精致,具有文学发展早期的核心特征。其主要体式可分为游离式、主干式、因果式三大类,各大类下又可区分出若干小类。不同体式、类型的铭文其特点和功能各不相同,它们由简而繁的演变,展现了商代铭文的规则化以及商人铭文功能观的变化过程。商代铭文取得了很高的艺术成就,对后世叙事文学的发展有深远影响,具有特殊的文学史意义。","categories":["09_其它"],"year":2017,"publication":"中国高校社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI6jyJUP9fiOu_Julni8ZBUvZAqYftsfpdhT3ihYoNI8uvd124jx7PfhX5VGOUT97Xq1bU7cv_Jum0pINnx01RParo3w5ADXETdKCdLo3XF2hQ8AWzUImvpneZ7JpAwBPaXBKi4InjZtHYUtt6t4D2OYegjk8whsu4pR1Vm3PFus03bh5gDXenD&amp;uniplatform=NZKPT&amp;language=CHS","pages":"107-120, 159-160","volume":""},{"id":2326,"author":"陶智","title":"罗振玉金文研究述论","abstract":"罗振玉为民国时期著名的古文字学家,在金文研究史上具有重要学术地位。其研究内容所涉极广,在考释文字、考证器物、考证史实、考辨年代等方面,都取得了很大的成就。研究方法上,罗振玉善于将文献学、考古学、历史学等融入其金文研究之中,大大推动了民国时期的金文研究。在研究思想和方法上,罗氏的金文研究也一定程度上影响了后来金文研究者的治学路径和研究倾向。","categories":["09_其它"],"year":2017,"publication":"嘉兴学院学报","link":"https://link.cnki.net/urlid/33.1273.Z.20170418.1445.004","pages":"89-95","volume":"29"},{"id":2327,"author":"于成龙","title":"从康侯■器铭谈西周成王时期的金文书法要素","abstract":"西周成王时期的金文章法虽然因袭商代末年,即从右至左、自上而下的行文纵势,且兼顾文字之间错落的规整,但其中在族氏徽号、字列方向及视读平面形状等方面出现了一些新的变化,布局愈加规整,尤为注重视觉之美。这一时期的金文用字在整体上较此前更为匀称、协调,有利于发挥书写时势能的上下承接,保证通篇文字气息的连贯。商代末年产生的&quot;捺&quot;划,在西周成王时期的有关金文中波磔幅度加大,从而使这一时期的字形略有加宽,气势开张。西周成王时期金文多数为规范书体,少数为急就书体;同时,这一时期的金文结体少数左低右高,成&quot;欹侧之势&quot;;而多数金文则如《禽》、《何尊》及《献侯鼎》等篇,书体端正,以正面视人,庄重沉稳,导后世篆法之风。总体而言,在西周成王时期的金文中,存在新派与旧派之别。","categories":["09_其它"],"year":2017,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLDIVabVdXl5ccMPgY8kHZS8BuFpgKpd7GFqlQwDB_OxW3df3gy2LcxYwT0lgs8A-qaD7vurFsG_rdVFoMS-cKTUhccNhIQqBje9NlMK62v5QfDR_z6BHgqsxv675IuBpjO34D8x5y40Nq5XG5Y3Jg8uAkbjVJds_xMxavWsyqvQYRl7WQJRDLr&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46223","volume":""},{"id":2349,"author":"赵莉; 潘忠志; 杨晗","title":"从汉语言文学角度看中国商文化在铸造礼器上的传播","abstract":"中国的铸造历史源远流长,以商代的青铜器铸造为代表,铸造的生活、祭祀用品为我们研究商代的文化提供了重要依据。尤其是铸造礼器,有着重要的历史地位和研究价值。基于此,本文重点介绍商代文化特征在铸造礼器上的传播形式,以汉语言文学为重要载体,分析铸造礼器的文化传播表达方法。","categories":["09_其它"],"year":2017,"publication":"艺术评鉴","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJhF62tPUGmU0phijbNXl6vCllvQJ28jHAtPqUhGjNK6KFnJ45qgP6Qf8oaW--l4u4-WDunBLzkS674mbVJJG5izzhfPnDBK7p6shpyaG6WG2KQjvxFBKlAhKdv15m_YyQpcS7URmo42NHlQ1U7gvEXKoXVTa3jMM2U08EFVjoOmIBgoeEOyEzm&amp;uniplatform=NZKPT&amp;language=CHS","pages":"183-185","volume":""},{"id":2362,"author":"郭晨晖","title":"先秦时期周公形象的演变","abstract":"周公的形象在先秦时期可分为就青铜器铭文、史书类文献和子书类文献三个角度进行考察,不同类型文献有着不同的著述特点。周公形象也随着时代的发展不断演变,并被后来的诸子进行各种各样的演绎和利用,呈现出复杂的面貌。周公从历史事件的形象逐渐演变为圣人,乃至代表传统伦理道德的符号,其形象经过后世诸子不断的演绎变得日益抽象。形象不断变化的背后则是不同的书写目的和诸子不同的价值判断。","categories":["09_其它"],"year":2017,"publication":"史学集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKhOPHaw-AhuGU5yTAoYVlY1ubTmV_0Ml28vbj_eroJjRsLxiC15K-CuPvBDA2M0VVd_pD5tymLrELizliOx-cnDTupczNRIPlUV9m2kmvwYhyQJtLHFXAewLw0rIXGj0RjAS-VHXW1x3chFihr9PGw7FF6SC6GpwfiNgCYx7gXoDWqT0TSouCp&amp;uniplatform=NZKPT&amp;language=CHS","pages":"120-128","volume":""},{"id":2365,"author":"王业奇","title":"陈邦怀和他的古文字学研究","abstract":"陈邦怀为我国著名古文字学家,研究涉及古文字学、考古学、古典文献、诗书词赋及书法等,尤其在古文字研究方面的成就不可忽视。他在甲骨文、金文研究方面成果丰硕,《殷墟书契考释小笺》、《殷契拾遗》、《嗣朴斋金文跋》等对后世影响深远。一、陈邦怀生平简介陈邦怀(1897-1986),字保之,室名嗣朴斋、甲微堂,江苏丹徒人。1897年3月20日,陈邦怀出生于江苏省东台县(今东台市)一书","categories":["09_其它"],"year":2017,"publication":"汉字文化","link":"https://link.cnki.net/doi/10.14014/j.cnki.cn11-2597/g2.2017.01.007","pages":"34-36","volume":""},{"id":2395,"author":"罗香锋; 汪银峰","title":"汉字形体演变的文化透视","abstract":"汉字属于表意体系文字,包括字音、字形、字义三方面,与中国文化有着很深的渊源。主要从字形方面将汉字形体演变分为古文字形体演变、近代汉字形体演变以及汉字繁简演变三个阶段分析汉字形体各个阶段的特点,以此透视中国文化。","categories":["09_其它"],"year":2017,"publication":"沈阳工程学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13888/j.cnki.jsie(ss).2017.01.018","pages":"91-95","volume":"13"},{"id":2400,"author":"王其秀","title":"钱坫金石学研究述评","abstract":"钱坫是乾嘉时期卓有成就的金石学家,也是金石学研究风气转变的先锋代表。其著述甚丰,《十六长乐堂古器款识考》是首部汇录私家藏器而成书的著作。对金文收藏和研究领域具有先锋意义,改变了宋人款识临写风气,所收铭拓皆据拓本,推动了金文研究的进一步发展。","categories":["09_其它"],"year":2017,"publication":"安徽工业大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI7ElDHlfYGIm5b6xmAIWM0I8tZGnBZh6xNIuOLKBo6_Avz3VtAfk6oyXtudHHKOSoYdvMcMKj_FHWxTsfCGD_apLchFnxW-iWqdq7aPxs5k4o36DYoyerouyAxXUxoQfZkF8IHr0q9n5YG-DN8_WXaMeNnRlMqOrN3JvZIh13aYnKLab_I_13l&amp;uniplatform=NZKPT&amp;language=CHS","pages":"34-37","volume":"34"},{"id":2874,"author":"徐世權; 吳良寶","title":"學術史視野下的秦郡研究","abstract":"二十一世紀以來,隨著出土秦文獻材料的陸續公佈,一些不見于傳世文獻記載的秦郡名對已有的秦郡研究體系造成了破壞,學者紛紛撰文加以考證,但迄今爲止仍未能圓滿的解決這一問題。在這樣的背景下,爲了將來更好的利用出土文獻和傳世文獻研究秦郡問題,詳盡梳理自清代以來的研究成果,以學術史的眼光重新審視秦郡研究,便具有十分重要的基礎意義。同時爲新時期的秦郡研究提供寶貴的參考經驗,也爲新秦郡體系的建立打下堅實的基礎。本文主體部分共有四章,分清代、民國、1950至2000年,2001至2016年四個時間段梳理學者的秦郡研究成果。大體按照“秦一代郡數及郡名”、“秦始皇三十六郡名”、“秦郡始置時間”、“秦郡郡境”、“秦郡郡治”、“秦郡圖”,“秦郡個案研究”等七項內容進行概括總結,並設立專節總論這一時期的研究概況以及取得的成績和存在的問題。第一、二章後都附有一份學者秦郡研究著述表,介紹了一些基本信息並對其文的發表時間做","categories":["09_其它"],"year":2017,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI47O7-M_8aCi29aK2g_TOLJ6STdUPjnT8F6RzKmROdj_HIhfQUw-z9FHuSUqmKAgSBQUP0KGy8B9QzrTAmUAWxXmvrUw5jNwUgbrwx1dJLBgIrjTRGGt15KhvhVDZ7UK9H3Z68SLj0RBA_kd_LoxZdkhmkm_CmvcQdAGzA7LLFN6yymFWPk94S&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2882,"author":"吳文軒; 單育辰","title":"《孔子詩論》集釋與詩義匯考","abstract":"《上海博物館藏戰國楚竹書(一)》于2001年發表,至今已有十六年時間,《孔子詩論》是其中的第一篇,其研究成果已經非常豐富。本文對《孔子詩論》篇目前所見的文字研究成果進行了整理,是一篇集釋性質的論文。本文分爲以下三個部分:第一章是對《孔子詩論》篇研究情況的概述,就竹簡作者和定名、形制與編連等問題進行了梳理和總結,并在此基礎上排定了新的簡序,作爲第二章集釋諸家觀點的順序。第二章是《孔子詩論》文字釋讀的集釋,是本文主體,首先對幾個疑難字形的討論進行總結,接下來逐句羅列各家意見,盡量做到全面完整。第三章是對本篇簡文中出現的詩進行詩義的總結,收集歷代二十余家說詩者的意見,擇要摘錄整理,以期對詩之本義的顯現有所幫助。附錄部分包括竹簡形制一覽表和《孔子詩論》字形表,以便讀者參考對比。","categories":["09_其它"],"year":2017,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKMki_tb76Vt7a5MrF-IbvEEO_OhSRCCyfP4ZrVeqFPqB6Hz-JdbwILtlOd4aVPmnn8epVmGbo8Wd3PEbwk5CN4xFvYOvwHMwR-i0gkmg8Gy3weApsvxZ609Dt3MfUxeJjSEXdK30SY05L0WhnofinqLl3DjwaCO7gXfdso4XtNPoK-RueQT6x5&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":2888,"author":"谭梅; 陈松青","title":"楚系金文文学研究","abstract":"楚系金文数量可观,内容种类异彩纷呈,蕴含了丰富的文学及历史文化信息。本文主要从楚系金文的内容、思想和形式出发对楚系金文的文学特征做较为系统的研究与探讨。本文主要由四个章节构成,第一章为楚系金文的内容,第一节主要将目前出土的楚系金文根据其内容特点进行分类,大致分为:“祈介祝嘏”、“祭奠父祖岁时”、“宴飨宾客”、“乐律”、“记事”、“物勒工名”、“凭证及其他”等七种类型,并论述各类铭文的特点。第二节主要论述楚系金文内容中所反映出的风俗文化,包括对铭文中出现的“寿命意识”、“子孙意识与教化之思”、“择时观念”以及“婚嫁制度”等风俗文化观念的探讨与分析。第二章为楚系金文的诗乐思想,第一节主要论述楚系金文的“祈福”、“娱神”、“乐人”、“修德”等诗乐功能,展现当时楚人的诗乐审美取向,楚国诗乐文化的发展水平以及其与周王室在诗乐文化方面的交流与影响。第二节主要论述楚系金文中诗乐思想所反映出的楚国的诗教观","categories":["09_其它"],"year":2017,"publication":"","link":"https://link.cnki.net/doi/10.27137/d.cnki.ghusu.2017.000180","pages":"","volume":""},{"id":3157,"author":"徐青; 張靜","title":"《文字蒙求》與《澄衷蒙學堂字課圖說》比較研究","abstract":"本文以清末兩本識字類蒙學教材《文字蒙求》與《澄衷蒙學堂字課圖說》作為研究對象,將二書的識字類蒙學教材特點以及文字學方面的特點進行比較研究。《文字蒙求》從《說文解字》中選取了比較常用的2050個字,用平實的語言對這些字加以解說,並按象形、指事、會意、形聲分為四卷。此書既蘊含了王筠關於漢字結構觀的思想,又體現了王筠對於兒童啟蒙識字教學的思想。《澄衷蒙學堂字課圖說》是我國第一批建立的新式學堂--澄衷學堂自行編寫的啟蒙教材,全書共四卷八冊,收錄漢字3291個,插圖762幅,真正做到了圖文並茂,通俗易懂,此外也蘊含文字學方面的特點,值得進行深入研究。論文共分為五章:第一章是緒論部分,概述蒙學發展概況、《文字蒙求》與《澄衷蒙學堂字課圖說》成書過程以及國內外研究現狀;第二章是對二書作為識字類蒙學教材特點的比較研究,包括二書共同的特點以及不同的特點兩個部分;第三章對二書在文字學方面的特點做了詳細的比較研究","categories":["09_其它"],"year":2017,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKDqSz--h5aA7I82n1_k4PvGeY1bKTo25Oe1L5AQIDRFs70JKmFGeS0yoadN7AcRcmRo-EOCK89uR0eoiMkbewXQu5uuDKIngdOH-iyzRweD7E7ygw3RwMPzCdAxF09VhkNI6q9YLC_RddVsUbTk9KnNOHdETf_ZD_HEsB_OGEENAlt5x_yA6Wg&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3172,"author":"曾慶炳; 吳振武","title":"《積微居金文說》文獻學研究","abstract":"楊樹達是二十世紀著名的語言文字學家、文獻學家和史學家,在語法學、修辭學、文字學、古文字學、史學、文獻學、考古學等方面均有廣泛建樹。金文研究是楊氏晚年學術研究的主要內容,成就巨大,影響廣泛而深遠。其成果主要集中於《積微居金文說》增訂本(包括《積微居金文說》和《積微居金文餘說》兩部分)一書之中,目前所見已有8個不同的版本,但這些本子在不同程度上存在失誤,需要在理清版本源流的基礎上進行校勘。此外,楊氏金文題跋有不少篇目曾公開發表於各類期刊,其中有些與《積微居金文說》中篇目相較存在較大差異,可以反映楊氏學術觀點的變化,值得整理和研究。本文主要從文獻學角度對楊樹達金文研究資料進行整理和研究。論文分為六個部分,緒論部分簡要介紹了楊樹達的金文研究概况、研究現狀以及本文的寫作目的。第一章探討了《積微居金文說》一書的出版過程及相關問題,並對8個版本的遞嬗關係和各版本特點進行考察。第二章以1959年科學出版社","categories":["09_其它"],"year":2017,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIVX5QHe5qCXF1CAY-XxnMkkRluxJR-EQK4s3R8wBOkcZ36Ladj5dfadmrC-p30I4aAFrO8SjhYeq0faNrjC62ghoKfjpHU28UCSFRWEhktYBmzcyBqbAfBPD-m5aVf99CK4EG-G2j4-FKeHc9dMMXsMuxRpDhTf22ePXrbpvhEV9a1Kyh05IK8&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3179,"author":"朱文玉; 郝士宏","title":"劉節先生古文字研究初探","abstract":"劉節先生是我國著名的古史研究专家,長於古地理學、考古學和思想史的研究,在古文字上也有深厚的功底。他在古文字研究方面的成果主要收錄在《楚器圖釋》、《古史考存》兩部著作中,其中《古史考存》收錄的《壽縣所出楚器考釋》、《驫氏編鐘考》、《旬君孠子壺跋》、《麥氏四器考》、《說彝》等是其考釋文字、解讀銘文的代表。另外劉節先生還對一些甲骨金石學著述作了評介,其中以《<兩周金文醉大系>商兌》、《續修四庫全書總目提要(稿本)》(金石文字部分)最具特色。關於文字學理論的研究,先生有《古代成語分析舉例》、《中國金石學緒言》、《研究中國語言文字的新路徑》等論著問世。本裸题以割節先生的古文字研究方面的著述為主要研究對象,進行系统的整理分析,進一步歸纳總结先生古文字研究的成果、方法特點以及成就與不足,盡可能地做出客觀評述。本文主要分為三章内容。第一章為绪输部分,介绍劉節先生其人及其主要學術成果,并說明本文的研究内容、","categories":["09_其它"],"year":2017,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKzhiHxdNkooZ8fvHip8mWnzzQUFOg3TYnNVF2GePRrMvgR48F0GS2uLtaVwghokfJkx2Bl3CfYCGPZDrytevYelg7c_3Lgc81zQntOKM16Ekg7eteQR4A0sa1uajMwlFXq2Z3RaBBz6m28zC_OtUNTREFa-ANbMOlliwwND_Ee0IBi4ppfZrb4&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3180,"author":"吴鲁锋; 马亮宽","title":"吴金鼎学术人生述论","abstract":"吴金鼎是现代考古学史上的著名学者,在史前考古的发现和研究及中国西南地区考古事业的开创,做出了重要贡献。吴金鼎一生的学术研究经历主要分为两个阶段:其一,从清华大学国学研究院肄业至留学英国之前。在此期间,吴金鼎凭借在清华国学研究院所学的考古知识和训练,完成了《山东人体质之研究》;在齐鲁大学任教期间,六次踏访平陵地区,发现城子崖遗址,完成《平陵访古记》一文,并以此为契机于1930年进入史语所考古组,追随李济、董作宾等学者参与城子崖遗址和安阳殷墟发掘,并负责撰写了部分发掘报告。《城子崖》发掘报告中,吴金鼎独立完成第三、四章,并对其他章节进行了详细的修改。其二,出国留学及回国后的学术经历。鉴于吴金鼎在考古学上的贡献,在傅斯年、何思源等学者多方努力下,促使吴金鼎于1933年获得山东官费免考留学名额,赴欧洲留学。在英国伦敦大学留学期间,因吴金鼎对史前文化中的陶器格外注意,专门前往伦敦中央高等工业学校,学","categories":["09_其它"],"year":2017,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKzQ2t02X6VKHclxriWyWl_Oo1ZIzAWYGBIeMYyQKo9axX-6C0H1ykppF0w_ORVOiU4pqOaERbzf8kHhm6xFWAVsI5G8pd2fJdJpHARsm68AS0Y-fwQKfJ1PIBDC34VjXFgMPtdcBtB6LETIlQoobc2KEnpP1lRlY_8WjDUK9jjTLpWLbsr9176&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3191,"author":"赵琼琼; 白国红","title":"试论东周的工匠精神","abstract":"我国历史悠久,文明灿烂,应当继承和弘扬的优秀传统文化因子数不胜数。时下,我国社会经济发展迅速,但也面临一些问题。为了解决现实问题,我国政府提出了很多对策,其中,就有继承和弘扬传统文化中的&quot;工匠精神&quot;。本文就是基于这一热点问题,以东周&quot;青铜器&quot;为例,探讨东周时期的工匠精神,以及它对后世的深远影响。本论文首先,从传世文献对&quot;工&quot;的记载入手,梳理学术界对于&quot;工&quot;身份的认定,继而探讨何谓&quot;工匠精神&quot;,以及中国古代匠人是否具有&quot;精神&quot;的问题。以上内容主要是为下文展开讨论奠定基础。其次,以东周时期&quot;青铜器&quot;的制造为例,以器形、铭文和纹饰等细节方面为切入点,具体分析东周工匠的继承与创新精神、精益求精的精神和法治精神。最后,主要梳理后世历代文献对东周工匠精神的记载,探","categories":["09_其它"],"year":2017,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iImWBX-otel7IBRN2lmkxtsc5XtCT9XfYMUhKufFMlfrxY79AH2ih1TX2pb9MI-ExV9MfYC4LeZrtRv344fDyIf-8QcW1rGTZw6sB5nIQkrycc3afi3q0Q6bspyzcwwRIkVEBtXH5d5lS59B9AxyZLTuujaX3xmFZfkB6hIWTxHRQnBFZ-ZasCa&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3538,"author":"李明阳","title":"探寻制度与文献形成的互动——过常宝教授《制礼作乐与西周文献的生成》评介","abstract":"2015年4月,《制礼作乐与西周文献的生成》由中国社会科学出版社出版。作者过常宝教授为先秦文献研究名家,全书关注周初礼乐制度和宗教观念发展对早期文献生成的重要影响,对书类文献、诗类文献、占卜文献和青铜铭文的文本体制和文化内涵做出了实证性分析,为&quot;周公摄政&quot;&quot;周初八诰&quot;等先秦文献研究界聚讼纷纭的重大问题提出了可资借鉴的独特看法。本书体现出作者会通文史的人文修养和严谨求实的治学作风,观点新颖、思路晓畅,极具方法论开拓价值。","categories":["09_其它"],"year":2017,"publication":"斯文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIJ1EsWfwlyiuvRGNg6_sd-tU1hFfLg9X_7ECI5Tskf1qNyODXh_MVzkrReDk9S3qYkXmdq-qi4199ByohMzkPt7SnPSZhMk7E1Cf6JzHOi8DMZvGizaQpf1CbSt-cEhEwgKwFqk9Q7mV0dWJebs-WtcJF8_47qtBtL4VwviTF2oQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"321-327","volume":""},{"id":3540,"author":"吴慧","title":"商承祚汉字学思想述略","abstract":"&quot;汉字学思想&quot;是人类关于汉字学这门客观科学的主观认识、理性观念,包括对汉字起源、发展、性质、体系、汉字的形音义的关系,正字法以及个别汉字演变的情况等方面的认识和观念①。作为享誉盛名的古文字学家和书法家,商承祚先生虽无专文探讨相关问题,但从其文字学著述,从他在古文字考释对汉字特点的零星的、不成体系的表述中,我们仍可窥见其汉字学思想。一、汉字起源","categories":["09_其它"],"year":2017,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIqAtTnil73Tc1VCdBKb3YRquNPq_x75IJ3rWqXRkH3u7GnRYz1aSmM7sWLD1A2l_IKnMMnzrSfmmnt5_ZrOlQEd2R5Msn1fQLPM3nYGT9YL-qAGLGupV1pPOvy5smpyaxg1gW6EHd81fCf16AKa3VPbF8mj-qNsw8_ojy8-vn5wQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"320-328","volume":""},{"id":3543,"author":"陆锡兴","title":"论汉字史研究","abstract":"汉字史是中国文字学的核心,具有极其优越的条件。从民国以来的积累,特别是改革开放以来的飞速发展,有必要也有条件完善汉字学的建设,设立汉字史,与哲学史、文学史等并列于学林。本文总结了汉字史的发展历程,建立汉字史条件已经成熟。同时明确了汉字史的范围、方法以及不足。","categories":["09_其它"],"year":2017,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ-7XwxTTH9LaxN8VEd-vwZx6bnr2DLMndH_SvV2wZrfkO2GtFxiri0c2DpHkya03aUas8zpdNyTFoFZZDTEQQ35VdVgl_EvIAOJ2PDop9uYdloPzFYIfuIDuiiOYA1rVFSwvwp7rI4rNQGo74gPBX_A8JcGdRtZTGyiYcAG3Utvg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"101-113","volume":""},{"id":3547,"author":"杨勇伟","title":"廿七年安阳戈新考","abstract":"文物造假历史已久,高仿青铜器更是自古有之,现在对非科学发掘出土青铜器的真伪及时代鉴定,仅靠个人的目测经验来判断已经远远不够了,还需利用现代仪器进行科学的检测分析,从青铜器的合金成分、锈蚀物检测、制作工艺等诸方面以及与其他文献中的文物进行对比,从而证明非出土文物的真实性。","categories":["09_其它"],"year":2017,"publication":"东方博物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK5yN-fBkN-0uosRl4MiqxkWJ6UBb0PcH-8aOpwkBGT_xqV1ed9Nx6CPqtNffE9MWoF9yykNud44rMdWC0Yd5XkpF-_1iF-iTU0NzyxnSFJ-N_plCfVWVQ5jJmdYzZVGNcKnB6S1Tabj1qwoIgPPzHtqHZZ5rnF4PPML9R7bb9eUQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46-51","volume":""},{"id":3553,"author":"管树强","title":"由青铜器铭文铸造方法谈古文字释读的几个问题","abstract":"本文主要讨论了商周青铜器铭文的三种主要的铸造方法,以及其对古文字形体产生的影响,在古文字释读时应该受到重视。","categories":["09_其它"],"year":2017,"publication":"中国文字学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLjxcLuDXRFEgV7QufuAVc0BLylQiZrIAsGL5RPW2vTG-2VlOH1DcCLj6MLczYb2obgoM6DUqdiHo67dggK2zh0VqWJTnhQJV3Ci1sD8EYOzik_T9-JIqPntlozxIyAZwMWUTY2VqC7NFecDSDlpVEG7v7CDOmUMm0C1v3ekox7PQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-76","volume":""},{"id":3568,"author":"铃木舞","title":"殷墟青铜器铭文之字体差异与铸铜作坊——以花园庄东地54号墓出土“亚长”铭铜器群为中心","abstract":"本文以殷墟花园庄东地(简称&quot;花东&quot;)54号墓所出的114件&quot;亚长&quot;铭铜器群为研究对象,从铭文形态特征的分类入手,对器物本身以及其纹饰进行系统分析,试图复原制作&quot;亚长&quot;铭铜器群时的分工情况。研究殷周青铜器铭文之际,发现多数学者在研究殷周青铜器铭文时,较重视通过记载内容来复原当时历史研究的方式,并且对青铜器研究而言,考古学者比较重视利用器物本身和纹饰的类型来进行分类的研究方","categories":["09_其它"],"year":2017,"publication":"三代考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKDKgbz3h7q-uT8kYyT_ZVJjQpfTXjWt8o5HGNtxY9s1v75zyhb4UBwy7AIkSJvrpVLugAqvFcfK9mhfol8Qp9FFQQovoGgyvevL1qUUFUH-maS81V-lJQDgqQIUFElmBDR50o5wKOBKPWgEd8VO3HGDblsq7A3eMn6APujSDjqAw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"124-147","volume":""},{"id":3593,"author":"连登岗","title":"白川静“神圣汉字说”的失误(一)","abstract":"&quot;神圣文字说&quot;是白川静首创的一种汉字理论。该理论认为中国战国以前的汉字是一种&quot;神圣文字&quot;。对此,他从对汉字系统的阐述与对具体汉字的解读两个方面进行了论证,认为汉字起源于巫术活动,在战国以前反映着巫术文化、神话思维,具有神力,用于巫术神事活动。这种说法,视觉独特,观点新颖,颇能给人以启发,其中确有合理之处。然而,考诸史实,按诸逻辑,白川静的&quot;神圣文字说&quot;却难以成立。他对汉字系统的阐述,在许多地方是不正确的,他对于&quot;神圣文字&quot;所作的其具有神圣性解说是错误的,因而,他把战国以前的汉字定性为&quot;神圣文字&quot;的观点是难以成立的。","categories":["09_其它"],"year":2017,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLbXULNDPJqGWqtw_ZSi4pZR0IL_bTRrJVfVHnBwMBLAEuNaaOHsX2e1JuCy7idUIuxGW7TO9l96hgpu8GdXxtrdaDNpx8UhtCHHbDBcCrY8eULTNfXQtBZyqRattQdssQp4w1mr0pPgKaxlYDhVF6xPEPJMMWA2d2pK7a33OwW5g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"111-118","volume":""},{"id":3625,"author":"","title":"發刊詞","abstract":"對中國古代青銅器與金文的研究,作爲一門學問肇始於宋代,乃當時盛行的金石學主要内容之一。至二十世紀初,這門學問發展到金石學體系内所能達到的最高峰。自二十世紀二三十年代以後,相關研究開始進入現代考古學與古文字學、歷史學的研究領域,迄今已取得豐碩的學術成果,爲該學問今後的發展奠定了深厚的基礎。經考古發掘出土於墓葬與窖藏的青銅器,對於判别墓葬、遺址的文化屬性及年代有極重","categories":["09_其它"],"year":2017,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL2I0vzgydiLqhR_Bp7shsTwJzykc8ogIpHbKItlgf14rITOD3Zir1h2MOLeMvP9_Zt-jnMKET6FZKay1lI3-ToKz2K7sOmw5wcNM3rWXBnyPd5aTJ35_vqP7ogyVLJYMqbQuMk3VLIn8Dilm2hZGFxyjtpipPezC0Hx3FtkUxBJA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46024","volume":""},{"id":3642,"author":"夏含夷","title":"鏤於金石:西方學者對中國金石學的研究","abstract":"一、銅器銘文研究西方金石學特别是金文學,從其發端一直到20世紀的最後20年,進步十分顯著。但需要説明的是,其發展歷程並非一帆風順。總體而言,可以説是在整體進步的趨勢下,往往都是前進一大步,後退一小步;再前進一大步,又後退一小步。應該説,西方金文學在其起步階段就不是十分順利。","categories":["09_其它"],"year":2017,"publication":"青铜器与金文","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL25ZxXS8SdsIPZx6ujBqHciFak6N3XluYIdDj9bKWpBVonxan0NmxcRs05tUiLFni-TUh5SUJU-wCDkO7ZBRRmVnndosGGNHdUPx6qOVvhbu3Ep2W-ghk60xfzmxl74mrbulba3DMeEK2Vwdd4MsSk2YKggvjsgwyw1Sq13YtdwQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"637-672","volume":""},{"id":3733,"author":"陈筱","title":"就鬯的性质再谈青铜卣","abstract":"目前可见的青铜卣的定名,多继承自宋。由于缺少自铭器,且形制与提梁圆壶、觥多有近似,&quot;卣&quot;的命名至今存在争议。就传世文献来看,卣与鬯有着密切关联,是针对鬯的特殊容酒器。据此,本文从鬯的贮存时的密封性要求入手,结合鬯酒的取用和密封性要求,认为卣应当是一种有提梁的外扣盖广口青铜器,区别于内插盖小口的提梁壶。","categories":["09_其它"],"year":2017,"publication":"文教资料","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLM6fLoFJVZe_sXZXLdDvVs1fLheCY7pTYTnKQRAPdmGH9fhFztqndkRS6iZ27YbLuAaW0_iS4rcn1Ty3zfQYZAWwuCeYi79QiIt9JIDFaJOyo3iTT7ViO-4xpKhval5mt7kgR7dRAt1sNtwsLlJ2lwSe9iIF_TgHy_ijn7ZU3AYMe42twrijs-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"67-69","volume":""},{"id":3739,"author":"兰华丽","title":"读《两周青铜乐器铭辞研究》之浅见","abstract":"文明的发展产生了礼制,作为&quot;礼治&quot;象征的礼器,青铜器盛行,用以调节统治阶级内部的秩序,从而维护奴隶主贵族的统治。在对青铜礼器,尤其是青铜乐器的研究中,青铜铭文是最重要、最直接的材料。铭文的内容有乐律铭文、追孝祈福、征伐记功、媵女、宴乐、赏赐、简铭,当然还有一些因为种种原因无法考证其内容。","categories":["09_其它"],"year":2017,"publication":"明日风尚","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKCCbcj1hMIR4S7U9BF37A5xqV3xmgcSPttswlKRW9jV7PfjkcksqNtBLvmgEqHYXjdG15IEp2UoKE4C4yIxv7fCZlf0bZrkXG_ZHdJJ4nL1F-3hie8D-6BfUg0UfDPpTZicSn925fVM6Ey3icYpGfgwvUEptQdXSCQbEZ4OzgfoRF6QMkWCV27&amp;uniplatform=NZKPT&amp;language=CHS","pages":"283-284","volume":""},{"id":2410,"author":"郭小武","title":"“燕京皇城”四字的汉字文化说解","abstract":"汉文字是汉文化的结晶。通过生动形象的汉字字形来考察源远流长的北京文化与华夏文明,不失为一条直接的途径。下面我们选取&quot;燕、京、皇、城&quot;四个汉字,逐一贴出图形,并进而考察、讲述其丰富的历史文化内涵。一、&quot;燕&quot;——喜兴的吉祥鸟北京地近燕山,古属燕地,也叫&quot;燕京&quot;&quot;燕都&quot;。先说&quot;燕&quot;字。","categories":["09_其它"],"year":2016,"publication":"汉字文化","link":"https://link.cnki.net/doi/10.14014/j.cnki.cn11-2597/g2.2016.06.029","pages":"87-91","volume":""},{"id":2436,"author":"李天宇","title":"越王勾践剑:冠绝天下的铸造术","abstract":"在冷兵器时代,剑是最重要的武器,一把好剑就是一件克敌制胜的&quot;宝贝&quot;,剑的质量直接反映了该国的铸造技术。春秋时期,中国青铜剑已经拥有了非常精美的外形和复杂的铸造工艺,体现了当时青铜冶炼技术的巅峰。越国和吴国的铸剑技术处在当时时代的尖端,古籍中就曾明确提到过&quot;吴越之金锡,此材之美者也&quot;。而最能体现当年铸剑技术巅峰的莫过于闻名中外的越王勾践剑。越王勾践剑出土于20世纪60年代,其出土墓葬位于我国湖北省江陵市,此剑是该","categories":["09_其它"],"year":2016,"publication":"智慧中国","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLZVfLgUTDgN93T1vY0ca8S50-HoTXuD57WQ9xw3_C4Is4UYS7PYvZ9KZ8-v4ApisCX18RFNlt4KlHU8WIKJ7iaaFd0r0gmFnGU5x_n2TdJiNx5n8lpUDdfjvhEBpe1xKrU5-EHNOIY-w_fSexC5Qe73XHaygQRtTx7LNeGQBHjQzCwKO-bTwlx&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-72","volume":""},{"id":2442,"author":"陈利斌","title":"传统青铜器的当代价值研究","abstract":"中国传统青铜器制作精美,在世界享有极高的声誉,青铜器是国之重器,是中国传统文化的重要载体。文章简要分析了传统青铜器的特点,并从艺术价值、历史研究价值、青铜器文化的商业价值以及当代审美价值等几个方面分析了传统青铜器的当代价值。","categories":["09_其它"],"year":2016,"publication":"铜陵学院学报","link":"https://link.cnki.net/doi/10.16394/j.cnki.34-1258/z.2016.05.024","pages":"105-107","volume":"15"},{"id":2447,"author":"连劭名","title":"东周青铜器铭文与传统思想","abstract":"王孙遗者钟是一件著名的古代乐器,铸造于春秋时期,上有长篇铭文。&quot;遗者&quot;是作器者的私名,也是哲学术语,指得道之人。《墨子·经说下》云:&quot;遗者,巧弗能两。&quot;《老子》第四十五章云:&quot;大巧若拙。&quot;&quot;弗能两&quot;者,&quot;得一&quot;的意思。《老子》第三十九章云:&quot;天得一以清,地得一以宁,神得一以灵,谷得一以盈,王侯得一以为天下正。&quot;铭文还是研究古代音乐理论的重要资料。楚公逆钟铭文云&quot;工四方首&quot;,工读为攻,祭名,&quot;四方首&quot;如言&quot;四方神&quot;,与祖先神合祭,即古人所说的鬼神。天神曰神,人神曰鬼。《礼记·中庸》记载,鬼神无处不在,时时注视生人的一举一动。铭文又云&quot;楚公逆出求人&quot;,求、索同义,人指贤人。《冠子·王》云:&quo","categories":["09_其它"],"year":2016,"publication":"中原文化研究","link":"https://link.cnki.net/doi/10.16600/j.cnki.41-1426/c.2016.05.017","pages":"89-95","volume":"4"},{"id":2449,"author":"王晓光; 杨然","title":"理性精神下的“和而不同”——西周青铜器铭文所展示的艺术美","abstract":"青铜时代迎来人类文明第一个辉煌期,我国的商周正是这样的时代。青铜器从器形、纹饰到铭文,其艺术的美和溢发出的精神气质都是无以伦比的。[1]金文占据着中国书法史重要的早期阶段,文字乃至点画、笔触这样的细节里,凝聚着上古先民的精神诉求和审美意识,也折射了殷周社会文化与政治生活等诸多领域的时代","categories":["09_其它"],"year":2016,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJQMhVRorRBWXsNgxwfAc8BW_V-pq70B-glK30VZ6cAdnm05RBFW4HL4Q-Y-pgbkvMcCJT2e9JqOI8O0TM5twI_4f4FN1nsfrL5FP9pcjesZBm3XlU9Vu4UMeNcZz9BFPE42eVOsi2AHQgT53scYvcPIBjmfsNdbor9QLLheZwG2s2lsZ2wfprI&amp;uniplatform=NZKPT&amp;language=CHS","pages":"98-115","volume":""},{"id":2452,"author":"张蒙蒙","title":"试论殷商金文书写风格的来源及影响","abstract":"殷商金文与甲骨文书体间的关系[1]&quot;金文&quot;以载体而名,是指铸刻在铜器上的一类文字。&quot;金&quot;是指这种字体的最终呈现方式,而非最初形成的原因;金文除少数是刻在铜器之外,多数是刻画在泥范之上,而后通过范铸而最终成形的。金文之前,汉字已经历长时间的书写过程,可以推断,早期殷商金文的书写风格受到既有的其他书写方式的影响。如果要考察这种书写","categories":["09_其它"],"year":2016,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKFgI-8-WMUbnZNHzO7br_KA2k4fcp4681l3s8KZDYk08JLiz9PFV670Kz96mr5i4kuw_S4nW6f1u_qCeXqAnf8j3hBpkRd_s0SnR1wiNOO_9SYry47-JCOw6VTF4m9xti0YiGOwW-MoXiuIRJboz20B_3caaZB0O1WyHQI9Q88BMmMdfa5A35L&amp;uniplatform=NZKPT&amp;language=CHS","pages":"195-196","volume":""},{"id":2464,"author":"王卉","title":"六十年来两汉金文研究述评","abstract":"目前学界对两汉金文语言文字的研究主要集中在三个方面:第一,从文字学和训诂学角度对金文释文进行补正和考释;第二,从两汉金文词语考释出发,挖掘两汉社会生活中的历史、文化、地理、政治、经济等具体问题;第三,对两汉金文的语言文字进行本体研究。总体而言,对个体的考证和列举性研究比较多,缺少全面系统的研究,尤其是语言文字本体研究较为薄弱。","categories":["09_其它"],"year":2016,"publication":"宁夏社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLKnSXvP26C4P2iQPkgK9QJgr1J_I-eX-DwHopQtCMd2z8wsItYOK3NZt0NByevW78BjHR30EWYrGaYKx6nHzos1WeyIFm0wA7VnfOGJFr0ST3h6jcP7e-zpwlAc1OtkknQEzp04HeUey8dYc8ov7RPd7gGMjFuuZvUpkYgEx0vSqWUW5nVumHq&amp;uniplatform=NZKPT&amp;language=CHS","pages":"195-198","volume":""},{"id":2467,"author":"王立军; 白如","title":"汉字构形与中国古代的天人观","abstract":"天人观是中国哲学思想体系中的一个重要范畴,从先秦时期开始,对天人关系的相关论述就已蔚为大观。而商周时期的甲骨文、金文字形,则蕴含着更为古老的造字时代的天人观念,早期先民的这些朴素认识,是后世成体系的哲学思想的早期渊源。从古文字构形的角度梳理天人关系的发展变化,可以帮助我们更好地发掘传统文化的优秀基因,更加深刻地认识到中华民族精神的强大生命力。","categories":["09_其它"],"year":2016,"publication":"当代中国价值观研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLTiPIENlxdrvP9o3qghqNv_iut41bVi3djPBzTb8IgikWt87z_JEGn3wbrVdbiPDWv1Ij-a_zOtpLF5osp8tCTyTkqZobGPOopNJjBo6Zh_LX_nxzZodFLnjakIh8rEJXfgbJ_C3u9mLgxibAO7crO_PNsQFhOFk8i2d_3HcRJmvGF3NogtQpx&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46-61","volume":"1"},{"id":2489,"author":"","title":"汉字的演变——金文","abstract":"金文是指铸刻在殷周青铜器上的铭文,也叫钟鼎文。商周是青铜器的时代,青铜器的礼器以鼎为代表,乐器以钟为代表,&quot;钟鼎&quot;是青铜器的代名词。中国在夏代就已进入青铜时代,周朝把铜也叫金,所以铜器上的铭文就叫作&quot;金文&quot;或&quot;吉金文字&quot;;又因为这类铜器以钟鼎上的字数最多,所以过去又叫作&quot;钟鼎文&quot;。金文应用的年代,上自西周早期,下至秦灭六国,约800多","categories":["09_其它"],"year":2016,"publication":"工会信息","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJVIyBCw9XZBEpDoq56Z5zw1dTIY3zIj4esbyvFvsD-EsqCjRvfLWsJkej3RzEB_H_8aWB-seC3RQmPH84A0XmQb0V_SMj8Ypgt3xOBVFWqx33Se8zfZv4k0XH-bRKcEDbsGag-5O7PtAZYrQNYqvG8wWTPyq7ziSBXunmDcKuBRSngPrvrOF9B&amp;uniplatform=NZKPT&amp;language=CHS","pages":"50","volume":""},{"id":2494,"author":"冈村秀典; 秦小丽","title":"冈村秀典教授访谈录","abstract":"秦小丽:自上世纪80年代以来,您一直是日本研究中国考古学具有代表性的考古学家之一。请谈谈您是如何对中国考古学产生兴趣的?开始于何时?冈村秀典:首先感谢你这么认为。我出生在日本古都奈良,这是一座美丽而古老的城市,这里遍布古代遗址,从小生长在这一环境里,耳濡目染,自然而然就对古代文化产生了兴趣。其中对我影响特别深刻的是1972年奈良高松塚古坟壁画的发现,这正好是我的中","categories":["09_其它"],"year":2016,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLNuvkl6PsnQg0c_OU5mERdIrkDK69UDRZxp3tDvcb9uCW-4OWAtGp-KwonzMQ24eOSpQtyrOdMRKG0tDMFj5ihlszDWTBUV5UgWZcmtY1IHyk5YalVvaY_oV8oNo57OPX7LRSWYUExmQFbuZWcaTmGd-leMM_9ZiwLD3UasSJo3fYSL63t5ApL&amp;uniplatform=NZKPT&amp;language=CHS","pages":"49-55","volume":""},{"id":2499,"author":"张韬","title":"清代金文学、史学形态概览","abstract":"以文化视域看清代二百六十八年的历史,康、雍、乾、嘉、道朝国力强大,政权稳固,经济、文化、学术、艺术繁荣,后世学者称为乾嘉盛世。古文字学中的金文学、史学研究风气也炽盛于乾嘉时期。本文从学术史立场,从三个方面对清代政权下的金文学、史学形态进行论述,这三方面分别是:朝纲政权文化史观形态;官方和民间青铜吉金收藏、著录;金文学、史学研究成果概述。","categories":["09_其它"],"year":2016,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iINNknNRh9KlMFGUVxZknuUgpcVXzbalwyCsBX9P1x7p4Bh-eteILU8-szl4vz0UjsQc3OSe9efiUE8EFmUyvt7V26bx21-HmzniTJPTtaWpVAvnak9dWyiYuurg50CNyVGkyf09zEeerOw2LDjImd8DsbC8_evD4_XotBGyzAif6yDuwNDymcB&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-61","volume":""},{"id":2504,"author":"曹斌","title":"觯、饮壶、觚、尊、卣等青铜酒器关系刍议","abstract":"青铜酒器在发展过程中,绝非简单的单线发展模式。本文在辨析铜觯与饮壶、觚、觚形杯、尊、卣、壶器形异同的基础上,进一步探讨它们之间的相互关系,分析背后的原因,并最终揭示其在研究青铜礼器之间的关系、铜器器用制度以及西周时期礼制变革方面的意义。","categories":["09_其它"],"year":2016,"publication":"农业考古","link":"https://link.cnki.net/urlid/36.1069.k.20160615.1617.062","pages":"189-196","volume":""},{"id":2517,"author":"王祖龙; 王曼苏","title":"凤饰楚铭的文化解读","abstract":"解读楚铜器铭文的凤形装饰,不能单纯地以&quot;鸟虫书&quot;或&quot;花体杂篆&quot;视之,从图像学角度看,它是一个蕴涵复杂的象征体系,其深层结构中有着无限丰富的文化隐义和审美内涵。","categories":["09_其它"],"year":2016,"publication":"三峡大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJYOJEIkliw7buKOWumvfU_6Rd3yZR117otxlW845HpYKKw065R3Bmve6s3VBa-0kICbhK4zr-fBh7ONT_ilY4whWAh3QMD9Z2DSsDX1aGAxJV69SsuAydxYY_doDx61RNBhMUJuOZHK4TaSY7EJmOrrNDLpSH80cA1UKnHYh8OETA5ljpI8oW-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"97-100","volume":"38"},{"id":2537,"author":"张雁勇","title":"关于《周礼》鸟兽尊彝形制研究的反思","abstract":"学界关于《周礼》所载鸟兽尊彝形制的讨论,存在重考古轻文献的倾向,主要表现为用出土的象形尊彝否定文献中刻木画图的记载。其实,出土尊彝也有刻有鸟兽纹样者,可与《庄子》、郑玄注等文献相互印证,当引起应有的重视。在古史研究中,考古材料固然是必要的取证依据,但也有支离破碎的缺点,尤其在尚未得到充分解读且与文献记载相左时,更应在理论和方法上多几分谨慎态度,避免遽然否定文献。","categories":["09_其它"],"year":2016,"publication":"史学月刊","link":"https://link.cnki.net/urlid/41.1016.k.20160324.1115.012","pages":"21-33","volume":""},{"id":2897,"author":"尚文君; 申屠炉明","title":"先秦时期的福祸观念","abstract":"对吉凶福祸的关注植根于人之本性,渗透在人类的日常生产、生活之中。福祸观念表现的不止是人们祈福避祸的本性和祈福禳灾的努力,而且包含着对终极生命意义的关怀。本文主要依据《尚书》、《左传》、《国语》等传世史料,与甲骨文、青铜器铭文等出土资料,考察先秦时期人们的福祸观念。由于史料本身的性质,文章主要关注中原国家贵族社会的福祸观念。文章共分为五个部分。前言部分主要交待研究综述。第一章考察殷商、西周时期贵族社会的福祸观念,殷人更关注族群之福祸,个人福祸意识笼罩在族群福祸观念之中;休福主要表现为族群的强盛无亏、政治权势的永久保持,凶祸主要表现为族群遭受天灾人祸、战事失败,人之疾病也是他们关注的一种凶祸;上帝、鬼神是吉凶福祸的支配者,殷人常通过占卜来预测吉凶福祸,通过祭祀鬼神来祈福禳灾。西周贵族以长寿终命和禄命为福,以短命夭寿、生病、无后为祸。其中周王独享与天沟通的权力,以获得和继承天命为福,以失去天命为","categories":["09_其它"],"year":2016,"publication":"","link":"https://link.cnki.net/doi/10.27235/d.cnki.gnjiu.2016.001082","pages":"","volume":""},{"id":2904,"author":"张海侠; 崎川隆","title":"巴纳对西周青铜器铭文辨伪研究的贡献","abstract":"巴纳(Noel Barnard),著名汉学家,致力于中国古文字学和考古学研究,曾任职于澳大利亚国立大学。到目前为止,他出版专著13部,发表学术论文50余篇。他无论是在青铜器研究上还是在楚帛书研究上都取得了非常出色的成绩,在研究方法问题上和史料批判问题上,对同时代中外学者有很大影响,但很遗憾的是,由于他的研究课题往往是跨学科研究,而且其中大部分文章是用英文撰写,并在国外各种学术刊物上发表,所以目前国内学界很少有人系统地了解他的学术成绩,尤其就他对青铜器铭文辨伪的研究来讲,国内外学界几乎还没有人做过全面的介绍和总结。鉴于此,本论文拟在全面搜集相关文献著作的基础上,对巴纳有关青铜器辨伪研究,尤其对毛公鼎辨伪研究及由此引发的相关学术争论进行介绍总结,并对其学术意义进行讨论。本文分为正文和附录两大部分。正文部分共为三章。第一章绪论。首先简要介绍巴纳的基本情况及其学术研究;其次,介绍国内学者对巴纳研究","categories":["09_其它"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKuglxSuii8kIIZZisxMgb9TAQmJaImzdnusTAIY1KCFnjfNTNythUDR7qtE92QksDWjrF1CdTxTr-NIgzwk4QwOcvz3TsEyKAPhUTeqFsiNxkOI4kgCNr017fIpGlu2wnx9qCid7ugXwNyajmHiPrio2P9BrQvRt5VkIc8vvRo73Vf255Br7Gj&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3197,"author":"曹斌","title":"青铜觯研究：商周青铜器的考古学和礼制文化研究附录三西周铜器断代方法辨微","abstract":"三代青铜器一直备受学者关注,早在西汉,张敞就对尸臣鼎进行了研究。北宋,金石学兴起,第一本金石学的著录书籍《考古图》就用80%以上的篇目著录青铜器,且这一比例,基本在宋清两代著录书目中得以延续。民国时期,罗振玉提出古器物学,以取代传统的金石学,但是青铜器仍在古器物学中占有相当的比例。20世纪初,近代考古学开始传入中国,在发掘殷墟之后,李济先生就尝试用新的方法","categories":["09_其它"],"year":2016,"publication":"青铜觯研究：商周青铜器的考古学和礼制文化研究","link":"https://link.cnki.net/doi/10.26914/c.cnkihy.2016.001425","pages":"253-263","volume":""},{"id":3199,"author":"王伟","title":"建国后六十年间秦文字的发现和研究","abstract":"1949年至2009年的六十年间,秦文字资料层出不穷,秦文字及其相关研究不断深化。本文将此间的秦文字研究分为&quot;建国后40年&quot;和&quot;20世纪90年代以来&quot;两个阶段,在介绍秦文字的出土情况的同时,较详尽地概括和评述了秦文字的各项研究成果,并对秦文字的研究做了总结和展望。","categories":["09_其它"],"year":2016,"publication":"秦始皇帝陵博物院","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL9dUMjEO_yaL6Wb5JhoeyJYVefDhJoEm6Z7vAi6CmnvQbq2zC8k2TliT7PytIMYXQU5WyrBJgBUkObyOZ6fnzri_Rvr_kIJAvcLtMC-jvQPdTO3H7S-tn5i83PRDlBeZM-RswNNv5JlyUjZePaiioc9hrOz8zbH9KAhvvH24qLzw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"198-222","volume":""},{"id":3205,"author":"张江; 万俐","title":"商周青铜器上的蝉纹研究","abstract":"商周青铜器上的纹饰研究历来是青铜器研究中最为欠缺的一部分,而蝉纹作为写实纹样的一种,更加不能与饕餮纹、龙纹、凤纹等幻想型动物纹饰相提并论,这也给我们做进一步研究提供了较大空间。本文以商周青铜器上的蝉纹为主要研究对象,并运用考古类型学的方法对蝉纹进行分型分式。通过青铜器上蝉纹本体的研究,追溯蝉纹的本源,进而引发对蝉纹意义的思考。商周青铜器上的蝉纹内涵众多,说到底是王权统治的工具。商周王朝是人治与神治相结合的特殊阶段,青铜器是巫觋沟通天地的法器,蝉纹就是巫觋的助手,青铜器上的动物纹样被商王借助,发挥神力,作为神权统治的工具,极大的巩固了王朝基础。本文将分为蝉纹概述及其研究现状、蝉纹分类及其源流分析、蝉纹的内涵和结论四个部分来进行论述。","categories":["09_其它"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxaEAthDpgOtlQbdEfbfZ8H_Jhn8gz6P6w8bcQCtjWPsrij_fuxbcUokyAXg5yOsRm6f6zvV5AzW-f9EFt0AuHxifv-D71IHSiotBjAuzaQ0W9Vhz-jWeP368u1qoMCEjLifkbEJGmTRCFfvweOtsR-WPHuoLIElTdWbjV_Ghfy9ttU4ZWpAfn&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3208,"author":"花友娟; 史光辉","title":"郑珍《汗简笺正》研究","abstract":"随着殷商金文的搜集研究大盛,和清代《说文》之学的风行,以《汗简》为代表的“古文”,被认为上不合于商周,下有悖于《说文》,受到不应有的蔑视,学界鲜有对其作专门研究者。加之郑珍为古篆籀之学,恒奉《说文》为圭臬,又诬惑于溷乱许学而伪托古文者,遂积数十年之功对《汗简》“古文”追穷根株,精加研核,著成《汗简笺正》,在《汗简》研究史乃至“古文”研究史中占有重要地位。与其他治“古文”者相比,郑珍的“古文”研究有其自身的特点和价值,但目前学界对其作系统研究者还很缺乏。鉴于此,本文拟对《汗简笺正》的内容作全面的爬疏整理,通过与《汗简注释》的比较,借助《说文》、段注、《古文四声韵》和中国古籍数据库等文献资料,以及相关期刊文章,探讨郑珍治小学乃至古文字学的学术理念和训释方法,发现其在《汗简》乃至“古文”方面的研究价值,以期对郑珍学术研究起到直接的推动作用。按研究内容,本文共分为六个部分:一、绪论:主要介绍郑珍生","categories":["09_其它"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKauGN3SIgYeLBbJedSPkxYecwq824wSX_5fyReWUll4oH_ve-pEF74YSeLl2ok_wLcGe1CnUlyc1Xoyroi3-1mlXB8pxIyKl3VigTCsQJqk8L_PDCfcJSUuJZu0RFKZRSwDstzY_Lu-xpjxDXeczhnb_tWzO2cK5QbhTaAQJol4R5lrV8l51qe&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3219,"author":"李炎乾; 胡逢祥","title":"《国语·吴语》新探","abstract":"吴越之争是春秋末年的重要史事,《国语·吴语》是记载这一段历史的重要文献。本文主要讨论了《国语·吴语》的形成过程和性质,并对其部分记事内容作了辨析。全文分为四个部分：引言部分简要评述了目前为止国内外对《吴语》的研究,并指出了一些值得进一步探索的问题。第一节主要利用慈利《吴语》简和上博简《吴命》讨论了《国语·吴语》的成书时间、成书地区和流传。第二节对《国语·吴语》的部分记事内容作了辨析和解释,并加了新的系年。并附带对《吴语》末尾的“陈”作了新的解释。第三节结合出土“事语”体古书和一些兵家文献对《国语·吴语》的性质进行了讨论,认为它具有浓厚的兵家色彩,并非“直笔实录”的典型史书。","categories":["09_其它"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIORSxHnHm2cYnJKPuibSV9iHmtvI1aRkp5VjKDR9XYrGeXOuTbBGjbB_hlanIpvkkrUV_7WKGG-Gv5VaMI8rvInjGAtLhA0xDq-3LwAIREILbydxS7mbWa5iPn4k0ehfRbf8Br3plBaTLCWDCqR2YmAd7PJV4JqixzTHO6zHy3iVlFHbutmYNn&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3224,"author":"刘群; 张典友","title":"殷商铜器文字书刻研究","abstract":"殷商铜器文字数量丰富,内容完备,学术界对其研究集中于释读、分期等方面,鲜少对殷商铜器文字的书刻实践进行研究。本文以殷商铜器文字书刻作为研究对象,在《殷周金文集成(修订增补本)》和《金文资料库》的基础之上,明确殷商时期铜器铭文4378片,通过尽量全面的材料搜集和比较细致的统计梳理,对殷商铜器文字书刻进行较为系统深入的研究,以期为殷商铜器文字书刻的研究者提供较清晰和完备的依据。全文共分三章:第一章,对殷商铜器文字拓片进行全面地整理,分成内容和字体两方面,此为本文研究的基础性工作。整理文字内容可窥探到殷商时期铜器铭文发展的原因;研究字体分类可为殷商铜器文字书刻的实践特征奠定基础。第二章,结合殷商铜器文字的内容,考察殷商时期铜器文字发展的政治、经济原因,以及铜器文字的铸造方法,并将铜器文字分为殷商前期和殷商后期,总结其分期特征。第三章,重点分析殷商铜器文字书刻的实践特征。从笔刀运用、结构、章法三角","categories":["09_其它"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKBj-wRNHwNUkpJCSYAXoAI6EzlYQQsGNDRchmnpKzRDe49KgOT8kgb4mofvRIJdOPq_4Ka_yvhSr52TUSpTEYl9gDhYaiCHvovmhPJ1068ZF2PW0oTqSW4L9KaClBC31kJt1CWebhARvI_gT_Q_iVzG0MMWoGN7zQpi_rfrQaphFpaWQA2xRiE&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3233,"author":"董然然; 郝士宏","title":"柯昌濟古文字學成就初探","abstract":"柯昌濟先生是較早从事古文字學研究工作的學者之一，也是中國近代著名的文字學家和史學家，被王國維先生譽為古文字學研究中極具實力的“四少年”之一。他的研究范圍較廣，其主要著述有：《殷虛書契補釋》、《<殷墟卜辭綜類>例證考釋》、《甲骨文字解誼》、《丙编上輯小屯甲文字例重釋》、《鞾華閣集古錄跋尾》、《金文分域編》、《金文分域續编》、《讀金文編札記》、《殷金文卜辭所見國名考》、《散氏盤為氐羌族器考》、《讀<山海經>札記》等。另有幾部只見于學者在考釋字詞時零散提及卻無實物的書目，后經柯老後人證實，此著作僅存有部分書稿尚未刊行，如：《中華古代國族史》、《中華姓氏源流考》、《殷周氏族考》、《殷周史料三代地名輯證》等。本課題以現能搜集到的古文字學著述為主要研究對象并進行專門性的分析、歸納，總結其考釋方法及特點，并試圖从整體上對其古文字學研究的成果做出相對客觀、合理的評判。本文主要分為四章内容，第一章為緒論部分","categories":["09_其它"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKZsv-a0TvYWb3ySOX5IivjoL1cX_akYbVcwj1JUjgOda9DDFIO3Cww0goc8z8zq7tqdDZyugYxUt_IUCQvwpnovfioWHe-sdWwt4VjpvQoaS3_7aVqK0dOqp9bR_LwQCKv8B7c0iJFdzl7wMyzCaGH5O1vHKcO5KwwC8y0nsCcubok8pxFGqCD&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3234,"author":"曾雯瑶; 马卫东","title":"《逸周书》周初史事诸篇研究","abstract":"《逸周书》是一本先秦的周代文献汇编,内容上起文王,下终灵、景。涉及内容非常丰富,包括天文、地理、历史、军事、政治、历法等方面。其中部分如《克殷》、《世俘》、《度邑》、《作雒》等记录西周初年史事诸篇的史料价值十分丰富。本文拟对以上四篇的文献考证、史料价值和叙事特点三个方面进行具体分析。全文共分为四部分:绪论部分:分为研究目的、基本思路和《逸周书》研究综述三方面。目前学术界关于《逸周书》的研究成果颇丰,笔者拟按校勘考释、成书时间和《逸周书》与《汲冢周书》关系三方面进行简要梳理。正文三部分:第一章周初史事诸篇文献考证、第二章周初史事诸篇的史料价值、第三章周初史事诸篇叙事特点:这三章是本文的主体部分,首先汇集整理古今学者们关于《克殷》、《世俘》、《度邑》、《作雒》四篇成书年代的观点以及阐述作者浅见。其次,综合阐述四篇文献的史料价值。最后,通过对各篇章具体内容的分析阐述其叙事特点。笔者发现《克殷》、","categories":["09_其它"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIKOkkPRR3loZjVtNlVuGTrh3MlBKDM6JB0gMjg-9QxuA4_SQGODhWyVAvxRDBizJ2-_h5d8EX3dab38mi1e-nAaYAccQLBghbuQ8F9glyYvc8JYQnbrljZWdypzkdi-QAGrbClkJh4dzMHm2saxQgBhSt9QYCXKSkDRe2FACysw2-vlBM68cs9&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3250,"author":"袁田田; 郝士宏","title":"姚孝遂先生文字學成就初探","abstract":"Yao Xiaosui is a famous historical archaeologist and language philologist, who has made outstanding contributions in the fields of history, archaeology, linguistics and philology. He is an expert in philology, whose major works including Yao Xiaosui's collected papers of ancient Chinese characters{《姚孝遂古文字論集》),The study on Xushen and Shuowenjiezi (《静慎與<說解字>》), Explanations on Bones and Tortoise She","categories":["09_其它"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIPU2_Lj0pbR5l2bJ8E2PEWXDLVqOwwLlyH0F1bFJNApOPCwwTCP4Rc9L3gKDH13fhYArFA3Xq8hzDFRoqFHPkaKzTgoSHQdNx9oRC2yutwfMeGqsCx4ie2Y7Btupal4tALd8-b4Mbhjqz0yVxHWofLTzAiKpeRZDZ5ZOZBleLtMiBfPs41mGZ_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3255,"author":"赵红蕾; 何景成","title":"甲骨刻辞辨伪研究成果汇总及相关问题研究","abstract":"本论文主要收集和整理目前已经刊布的甲骨辨伪成果,所收集的甲骨伪刻总量在七百片左右,按照伪刻所在书、刊梳理辨伪研究成果,并且针对这些伪刻的相关问题进行探析。本论文主要由以下部分组成:绪论部分。简要介绍自甲骨文发现以来甲骨刻辞的著录情况和作伪现象的出现,同时说明本论文的选题范围和研究意义。第一章为甲骨刻辞辨伪研究成果汇总。以甲骨著录书(刊)为单位,以其刊布时间为顺序,对目前甲骨辨伪研究的成果重新进行梳理。第二章为关于《库》1506之真伪情况的论争。概述《库》1506刻辞真伪情况的论争,以时间顺序汇集和整理各家观点。第三章为甲骨伪刻的相关问题探析。本章分为三个部分:第一部分介绍学界在辨伪过程中有关伪刻本身相关问题的研究成果;第二部分我们尝试对已确认的甲骨伪刻进行分类;第三部分我们对伪刻在排版上所呈现的特点和倾向进行探析。附录部分。附录分为两个部分,一是图版,基本依照本论文第一章行文顺序排列,汇集","categories":["09_其它"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKwMJrq9YA3RDHEMS-x4GpMI9ZfSVjPHqW9DIc6597CEgUBvfoW7gCULsc8f5oAh3p9MNuupA3MP6TnetHAR9PqHsX5P6K1lwUjc4S__P-M--AwNyAImoasj1CwF9bcQ9wb6r_x8XkyUoAgKznJa8z38hkfZrrWocgfu3skJ1VS2bQxlQTg5_K6&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3257,"author":"王琦; 吳振武","title":"陳夢家《西周銅器斷代》的文獻學研究","abstract":"本文是對陳夢家所著的《西周銅器斷代》進行的文獻學方面的研究和整理。陳夢家所著《西周銅器斷代》現存兩個版本,一是1954—1956年間在《考古學報》上陸續發表的六部分,後文稱作“考古學報版”;二是中華書局於2002年將趙蘿蕤教授和考古所對陳夢家在1956年的相關未發表的遺作進行整理后出版的,後文稱作“中華書局版”。通過對比我們發現兩個版本的《西周銅器斷代》存在一些差異,這些差異既有陳夢家的個人因素,也反映出其所處時代的古文字學界的發展變化。因此,本文將兩個版本的差異進行了整理製作成表格,同時將同時期青銅器斷代的主要學者陳夢家、唐蘭和郭沫若對於《西周銅器斷代》中所提到的器物的斷代情況及原因進行梳理,并對《西周銅器斷代》中陳夢家所重點釋讀的、學界影響較大的19個古文字結合當前學界研究成果進行了梳理和討論。本論文主要由以下幾個部分構成:緒論部分。此部分針對文章的研究背景、研究範圍及研究的目標和意義","categories":["09_其它"],"year":2016,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iID9lCdl65_40K5H4My8jR6qi0Jb5vIGG4Ka1Wk96l2E3qBPrejqN1mYFORpA8_TAsvaReq-6Isq6ASoFtX6Xyqvrktb586C5nfnKSBNtZKM2ciUGaTIAT23lBMxCHuzoW2oL0Nwfai3sTrveLba9_O1IEYqLvWROO5n3J67UxDvLHajxdUySxb&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":3264,"author":"马跃峰","title":"金文：青铜上的历史记忆","abstract":"","categories":["09_其它"],"year":2016,"publication":"人民日报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLmU14ROvEa7nrvKbDIlxl_f7vkbXln1aBj0FP1dGmTB22EpXsej6z4MXONApblHDjPF5E-Kdle53tOO6vNjZmruvOCyA-x1JvaMkVi8JYcKQ7Hg2JF5bd1ZoATQmSDtz--wLe8hQHRUFbfBJwbJf_POrGbBjni_nrQV3TqadU7ZglezrkESOyz&amp;uniplatform=NZKPT&amp;language=CHS","pages":"7","volume":""},{"id":3652,"author":"夏大兆","title":"一部具有新材料、新创见的力作——读黄德宽先生《古文字学》","abstract":"任何一门学科的成长发展,都离不开该学科的教材建设。教材的好坏直接影响该学科的发展与否。一本好的教材就可以极大地推动该学科发展。古文字学也不例外。唐兰先生是较早具有建立古文字学学科意识的学者,&quot;古文字研究本是文字学里最重要的一部分,但过去的文字学者对古文字无深切的研究,研究古文字的人又多不懂得文字学,结果文字学和古文字研究是分开的。文字学既因语言、音","categories":["09_其它"],"year":2016,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJDo_CFb7k4f-TjseHV0mBwqmoZipLMPN1nvIqhg4CJ2rvwU4f1U2QBuPxL31sK-0HHtHaCR55_8kO_Mm3K2osl7pKWzs6sBeQb1HVNcFFMe1O6l7NZn__7p3tEPhkdCpobcVaTsS-K-HdjZ2ttQLiXSVWal43kaaPwFEguTyfReA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"302-305","volume":""},{"id":3743,"author":"周翔","title":"战国兵器铭文辨伪","abstract":"战国兵器铭文为数众多,价值亦大,见于著录者有一定数量的后世伪作。拣选发现的二十余条伪铭加以考辨,以供学习、研究者参考。","categories":["09_其它"],"year":2016,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLA19vr6u09rL9zieyHw_giXGoRG2gu7fPDNXKgt9STSwBidFSWsxbbmjStTIPSH3CyDC6A6RxocNJpK33yQpdksnmKy07ZNutuRe4uWopDhJdDyJf2_duRWuSRRigQ65GRIcBBhx4--9QbKRfpX-owWdVzPWeYuLjP58r1Q0ZW8ywb4h0Fc2NJ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"17-19","volume":""},{"id":3754,"author":"吴娇","title":"柯马丁的西周金文研究","abstract":"普林斯顿大学东亚系柯马丁教授考察了西周金文书写的作者、撰写、铸刻和字体的问题,指出史和作册官员是金文书写的监督者和表演者,且在西周中后期,以史墙为代表的史官群体已逐步具备了写作的意识,他们领导了一场规范各种场合的礼仪及相应金文格式的运动。在文献分析与借鉴文化人类学理论成果的基础上,柯马丁提出通过这次革新,文字的&quot;公共展示&quot;功能成为周人&quot;文化记忆&quot;与身份认同的主要表达方式,由仪式中的表演而传承,其意义在于塑造周人自身的历史、展望王国的未来。本文旨在结合西方汉学与中国学者对于相关问题的研究,发现中西学者在金文研究的关注点、原材料、出土文献与传世文献的结合等方面的异同,尝试指出柯马丁研究中的可借鉴、商榷之处。","categories":["09_其它"],"year":2016,"publication":"海岱学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLDiBBHdRbQmW0vfzPtw8_VP_CRrrqTGGBG3yw4RJAJqs0lzZ4zoxVqAduI9f4jmkYSCjN55WhHJkeHxTw2IJhu8XYCpQWXJSbU9X1fvMtEHzal6TFLUBZo9E4CW0EAVRR-jSkydTljCRRLbBjLfKozwjqBYnU1RX4OauiBpfn-lA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"235-246","volume":""},{"id":3756,"author":"罗卫东","title":"新中国以来的甲金文研究","abstract":"本文依据现有公开资料梳理1949—2014年期间的甲骨文、金文研究成果。从资料著录、文字考释、工具书编撰、理论探讨等方面归纳了新中国以来甲金文研究状况。《甲骨文合集》等资料汇编书籍的出版,推动了单字考释、甲骨文文例、词汇、语法等研究。专家们在甲骨文缀合、分期断代等方面进行了全面、深入研究。《殷周金文集成》《商周青铜器铭文暨图像集成》等书收集了现存金文拓片,学者们在充分掌握材料的基础上,关注金文的&quot;断代&quot;和&quot;分域&quot;,在郭沫若&quot;标准器断代法&quot;基础上,学者们运用&quot;分群界标法&quot;等方法探讨西周金文分期。随着安徽寿县、山西天马—曲村遗址以及湖北随州擂鼓墩、叶家山、文峰塔和枣阳郭家庙等地考古发掘,一大批重要铜器铭文公布,为国别金文研究提供了材料。甲骨文、金文多种文字编的出版,为学习和研究甲金文提供了便利。随着新材料的大量发现","categories":["09_其它"],"year":2016,"publication":"民俗典籍文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLtN584pEFyMjF8EnyTNr4p2vOgHg0LJ7LidVRF0W4UNDzqoBXQPKy59jSrKvzP-QgA89ffv_l7nAvzhZugojGxBwFsjTm12p4il7a7xLIIqioygW2Q9DaFJzUqC2x2bSYNaUUtwfkkO_UWl-RazCqPxuquaxUrtwbagQ8MGJ1Vjg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"177-188, 279-280","volume":""},{"id":3817,"author":"朱华东","title":"群舒青铜器研究三则","abstract":"本文旨就群舒青铜器的装饰与铸造、用器制度与葬俗、铭文特征等三方面展开论述。文章认为这批青铜器喜用立体装饰,纹饰较简洁,同时追求器表的光洁;其用鼎方式较特殊,以对鼎与单件牺鼎的组合为主,牺鼎被认为是盛装肉汤的容器;有铭青铜器数量较少,以单个族徽式铭文为主,所见多字铭文内容与格式与中原地区基本一致。总体看,群舒青铜器特征与中原青铜器趋同,但地方特征明显,并在纹饰、制作技术、铭文等方面保留了若干春秋之前青铜器的若干特点。","categories":["09_其它"],"year":2015,"publication":"东方博物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKXJRleg1DswLXoAMPPDQZycOPJEuQOBPEiso8dGCTMJGaJ224ED82RvaUhBkibjoVCqYV3AJgFm_CaxqVwRTizNYUQTsCOpBDLVy1cwjxGGBGAW1PzJ4pJWSc1lSSfqyyduORXkC4Sa0OAlooqsOqOmCmUqG2PpRMB_MO07iF3-Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-76, 6","volume":""},{"id":3867,"author":"辛德勇","title":"雒陽武庫鍾銘文辨僞","abstract":"所謂&quot;雒陽武庫鍾&quot;,是一件刻有&quot;元封二年雒陽武庫丞&quot;云云鑄器年份銘文的銅鍾,至清末始爲端方蓄藏,[1]後轉歸羅振玉夢鄣草堂。[2]該器今存大連旅順博物館,亦以其銘文見珍,儼若鎮館重寶。在清代金石學家當中,端方所蒐討金石銘刻,混雜贗品偽物最多,羅振玉在著録&quot;雒陽武庫鍾&quot;時亦嘗明言&quot;匋齋所録,頗雜贗器&quot;[4]。然而,羅氏對這件銅鍾,却略不置疑。逮王國維撰著《國朝金文著録","categories":["09_其它"],"year":2015,"publication":"出土文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK8Gdl72zHlgo_wt5ENcGh3ThkzLwKqTUcW4dvYIAf54SaI6aA27z-ygejyG-lHq-Ps7YDUmLjqjDvaZswiFo19YVfsqH9tfHv1fU5mknGOCWuoOFVHjzgVS2UcQ2OPaf7WSeMIHC2rbDoEAQjVYNlh-gb98f2jXrZ_-cTXkXeoKA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"19-28","volume":""},{"id":3885,"author":"李吾铭","title":"乾嘉时期吉金著作的编纂","abstract":"宋代是金石学发展的兴盛时期,涌现出了一批金石学家和金石学著作。其中欧阳修《集古录跋尾》、赵明诚《金石录》金石兼论(吉金所占比例很小);王黼《博古图》、吕大临《考古图》、王俅《啸堂集古录》、薛尚功《历代钟鼎彝器款识法帖》、王厚之《钟鼎款识》等则专论吉金。金石学经元、明两代的沉寂后,至清代复兴,涌现出更多的金石学家和著作。清初顾炎武、朱彝尊等都有金石学著作传世,但其内容集中于石刻,尚未包含吉金。","categories":["09_其它"],"year":2015,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIHf6JeD_2LcEORz13r6K3aWQo_wlsRTZ2fd2aHs9R4vobAddtF0ZRZkC7OQNeueqrylnhnEG6nNfzyNVZexxzke_MK7IObQ4ydYA3_i8RDqQa_4wQ__iYqK9bHiK4QkooJZ6M4X4PzWZ_7Qtso3dALL0r-ai2NUYVvQUcu_id49s1NHia2u4eV&amp;uniplatform=NZKPT&amp;language=CHS","pages":"190-193","volume":""},{"id":3894,"author":"李峰","title":"西周青铜器铭文制作方法释疑","abstract":"商周时期青铜器铭文铸造方法主要为&quot;嵌入法&quot;。带方格的长篇铭文的铸造要使用一组假范,在假内范上刻方格后翻制假外范。在假外范上刻字后翻制真内范,内范上就会有阴线的方格和阳线的铭文,而浇铸后得到的青铜器上也就形成了阳线的方格和阴线的铭文。不带方格的长篇铭文也用这种方法制成。阴文铭中有阳文字体是补刻所致。","categories":["09_其它"],"year":2015,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL0r2EU1qm0v7YRdQAsz5ym84IIJomeYWnxUDwwCbsjPdbP7dNuqUWsYTP-MvLFthz7067fpDM5clSuKkaSXqUUvJJQIf-N2gXid1dlLT_aNoV3GbwoVugedQF51AHq-ChtueaZfonQ-A1jkmA6ufQ1RIH-sZV9tfaoze9tvceb_W3l5qAmpgc2&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-91, 2","volume":""},{"id":3933,"author":"韩建武; 胡薇","title":"几件伪铭铜器的考释","abstract":"铜器上的铭文,是当时人们现实生活的反映,具有极高的研究价值。青铜器是陕西历史博物馆的重要收藏,除商周青铜器外,汉魏铜器也很丰富,但其中有些器物本身虽可确为汉魏遗物,但铭文却又有值得怀疑的地方,长安鼎、上林烛灯、王阳家当户灯、章武二年铜弩机、正始三年铜弩机、延熙十六年弩机等铜器,其上铭文从职官、字体、錾刻方式、衡制等方面考证,当为后刻,故作一辨析。","categories":["09_其它"],"year":2015,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKoxOBKFUVZVlRy45nWo2cJ4KLX0iOydZdgiqvN6ZVIEfdcFcgWab7lF_BWpTKLYFH8_6KpyJ8Aj2rCO7ATwfh9dMCzcDIqliESiQiHFUYU3FEO0-InPfhI8D5biMwb-RwD7kp_6tR2qWSaa8A4UE5y_WU_gDcyYp3xAYXoH6s9lomyhPHgzY3U&amp;uniplatform=NZKPT&amp;language=CHS","pages":"56-59","volume":""},{"id":3946,"author":"胡振宇","title":"吉金丹青两辉煌——读容庚先生与胡厚宣先生通信十五帧","abstract":"《金文编》为著名古文字学家容庚先生一生精力所萃,乃研究金文及古文字学必读之用书。该书于1925年正式出版后不断补充,先经1939、1959年几次修订,此后容先生仍注意不断补充新材料,不断完善旧书稿。1974至1977年间容庚先生致古文字学家胡厚宣先生十余封通信,记录了容先生于准备修订《金文编》期间的心路历程,间或述及甲骨文字和汉字简化。从中可以了解老一辈学人治学的艰辛、认真的态度及忘我的奋力,这于学术史亦是不可或缺的史料。谨以此文纪念容庚先生诞辰120周年。","categories":["09_其它"],"year":2015,"publication":"中山大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13471/j.cnki.jsysusse.2015.04.012","pages":"121-129","volume":"55"},{"id":3973,"author":"姚草鲜","title":"论吕大临《考古图》对先秦青铜器的定名","abstract":"吕大临《考古图》中共著录先秦青铜器计148件,除11件因无器物图或仅存器盖而无法判断其定名正误之外,定名准确的有82件,定名欠妥的有55件。其定名欠妥的原因主要有三:其一,吕氏占有的先秦青铜器材料有限;其二,铭文误释;其三,泥于自名原则,将大共名作为类名。","categories":["09_其它"],"year":2015,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2015.03.005","pages":"36-40","volume":""},{"id":3981,"author":"毕经纬","title":"传世有铭铜器辨伪一则","abstract":"青铜鹰首提梁壶出现于战国早期,但传世的一件铜壶(何壶)却铸有西周早期铭文。本文通过与该壶形制相类的铜壶以及铸有相同铭文的尊、卣相关特征的综合考察,推测这件被诸多著录书辑录的鹰首提梁壶很可能是一件作伪之器。","categories":["09_其它"],"year":2015,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJpIbV6qH9aaMDzx9Im028JhOW_0yp_rxDRwK13RxcTAnTjaw6lhw9MFS3H7lCusH61tFZP49ovCFrtzcMxz5BjsfHYIgVMR0gRjxZY0UglWb1M-xfdYfDCMHYXziHGyh67ksKB0ld-UFWtKaySybL05xx7qbUv_ObWQXV54gd7yIeCMfhfOlAx&amp;uniplatform=NZKPT&amp;language=CHS","pages":"111-113","volume":""},{"id":4012,"author":"高會彬; 喻遂生","title":"呂大臨的銅器銘文研究","abstract":"我國早在殷商時期就已經進入了青銅時代，到了西周时期青铜器的製造更是蔚為大觀，制作精美。我國古代對鐫刻在青銅器上銘文的研究萌芽於漢，興於宋，盛於清。宋代是铭文研究的真正開端，是金文學史研究中必不可少的一部分。宋代學者對青銅器的研究一般偏重於以下兩個方面：一是圖像的著錄；二是銘文的考釋。這一學術傳統延續至今。呂大臨作為宋初金石學研究者中的佼佼者自然不例外。呂大臨是宋代著名的經學家、金石學家，其學開啟有宋一代金石研究之風氣。他的金石著錄及考釋著作《考古圖》以及銘文整理書目《考古圖釋文》在金文學研究史上的地位不容忽視。本論文主要分為以下幾個部分：第一章“緒論”部分，共分為兩節，主要申說本文研究對象的相關問題。研究現狀部分主要介绍了有關呂大臨金文研究的基本情況，梳理總結了近三十年學界對呂大臨學術成就的研究情况，並指出學界對其學術成就研究之不足。進而引出本論文選題意義價值和研究方法。第二章“呂大臨與《","categories":["09_其它"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iICBKBlEZ5om3TgQPUshF7tkhx7rc6ciXxx39ttz0myRU6uJb2tm7nX5TdXUQSANrCw1-pgxUUp7534tw0l6Qy6FcKTOcsZY3B-wu1K9vy_tu8WtH_KheO4MqDuFVashEhHCQbz3dLSEE2lCF0HFkCWxLJv5y0lgyGXvbTgKZs53z8E7o-uy5ab&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4015,"author":"莫阳; 郑岩","title":"战国中山王墓研究","abstract":"中山是战国时期由北方少数民族建立的重要诸侯国。中山国的文化面貌,及其华夏化的过程是研究战国时期历史文化变迁的重要问题。上世纪七十年代,河北平山县发掘的灵寿城和两处大墓,不仅弥补了古代史籍记载中的不足,还为研究中山国文化提供了极为宝贵的材料。本文由中山国王陵入手,从艺术史的角度探讨其规划营建过程中的诸问题,并试图藉此考察中山国文化身份转换的轨迹。以往的研究中,无论是考古学还是艺术史,在观察墓葬材料时,都倾向抽取单个器物或门类进行讨论。本文力图避免将都城遗址、墓葬和器物三者割裂来看,而试图由作品生成的角度,将它们置于共同的背景下观察。本文认为,不仅王陵内的器物可被视为作品进行解读,王陵本身从规划到完成的过程,亦可被视为人力创造的作品。甚至王陵存在的城市及空间,都是预先进行过规划和设计的,而不是随心的产物。正因如此,我们可以将整个墓葬视为作品,讨论其生成的过程,以及它与参与构筑墓葬者之间的关系。","categories":["09_其它"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI0J0cpbUpbZqL1j1-v7vnu2gOg3XOeUp1ys3JjghaVeMW4H57oEe18z8AmJfLOt7ol14aiK8WHesgzmrHG6SLti7q9TArfbiLDVAzL8QBh19wNAfYhnsAn_b6U_4czBn11Kyzg7rCxbcPWaE2XduQzAsNF6t3zQv73IbNnNkYvXLohNqWkEeum&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4024,"author":"季越; 郝士宏","title":"胡小石先生的古文字學研究","abstract":"胡小石先生是近代著名的书法艺术家、文字学家,作品涉及面较广,且文字学部分相较於同时代的其他学者并不算丰硕,主要著作有《甲骨文例》、《书库方二氏所藏甲骨卜辞印本》、《卜辞中之(?)即昌若说》、《讀契札记》、《金文释例》、《寿春新出楚王鼎考释》、《寿春新出楚王鼎考释又一器》、《安徽省立图书馆新得寿春出土楚王铊鼎铭释》、《说文部首》、《说文古文考》、《金石蕃绵集》一、二等。本课题以他的古文字领域的学术为主要研究对象并进行条理性分析、归纳,总结其考释特点及方法,并对其整体价值做出较为合理的评估与判断。本文主要分为四章进行撰写,第一章为绪论部分,介绍胡先生其人其事及其主要作品,同时说明本文的研究目的、方法、意义、思路以及国内外研究现状。第二章为主体部分,又分为三个小课题分别阐释胡先生在甲骨文、金文、说文方面的研究情况：第一个课题是甲骨文的主要研究成果,代表作为《甲骨文例》和《讀契札记》。这里通过介绍","categories":["09_其它"],"year":2015,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKQE6EO1Ii6r2milqxqaxFUqVzg2oGJwLxcmmTh4QPVIh2p8EIVvyv4R-heLJlXsWgZEkH7d57UO3nW2KL_El_6DVOOVupAjBEtZqwBFia3UE5uZdQtrF1KNLEyneBucy6xHlgmD5rQZZeu-fJUqktbzS4Aun8ohOnzQeeF-NeRD6Z7SWhNf9vu&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4068,"author":"宋玉玺","title":"为了商周金文学术研究的振兴——刘正先生新出巨著《金文学术史》述评","abstract":"时值2014年末,刘正先生百万字巨著《金文学术史》由上海书店出版社出版。本书是一部对古今中外金文研究做通盘梳理的通史学术研究经典,弥补了金文学界没有系统、宏观的通史类著作的空白,是刘正教授数十年来研究商周金文积累下来的学术精品,也是金文学术潮流发展到今天所应当诞生的必然成果。本书熔铜器收藏史、铭文发展和研究史、海内外金文研究史和金文研究工具书于一炉,史料丰富、持论公正,思想性、工具性俱佳,定会对金文研究事业的发展带来启迪和促进。","categories":["09_其它"],"year":2015,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2015.01.022","pages":"118-124","volume":"36"},{"id":4126,"author":"金洋","title":"方法敛与散氏盘研究","abstract":"方法敛(Frank Herring Chalfant)的甲骨文研究一直备受学界关注,但其金文研究却甚少有人提及。20世纪初,西方学者与中国学者交流并不频繁的情况下,作为最早研究中国古文字的西方学者,方法敛的观点在很大程度上代表了这一时期北美甚至整个西方金文研究的方法和水平等。了解其金文研究情况对于了解西方金文研究及西方汉学的发展演变具有重要的意义。本文拟对方法敛《早期中国文字考》中的&quot;散氏盘&quot;释文和翻译进行详细探讨,指出其金文研究的优缺点,以期反映出早期西方金文研究及汉学初始阶段的一些方面。","categories":["09_其它"],"year":2014,"publication":"黄河文明与可持续发展","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHhZhf5P0cHKeDoTdsMg7WkKKb8l8V6wDtZLMM9p6VAVweLR_zfcaaAtVdaK2t5qXxtqMOPaxP7a904HsDdNE_7hujdirxRRZ_vv8c231_TrVe1saUTa3hBwgm0N3OZw1TbcJuthsl6MRcMgg_cmw8ByVYgtEdS_TuEh8qnqPd9Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"117-127","volume":""},{"id":4153,"author":"金洋","title":"方法敛与散氏盘研究","abstract":"方法敛(Frank Herring Chalfant)的甲骨文研究一直备受学界关注,但其金文研究却甚少有人提及。20世纪初,西方学者与中国学者交流并不频繁的情况下,作为最早研究中国古文字的西方学者,方法敛的观点在很大程度上代表了这一时期北美甚至整个西方金文研究的方法和水平等。了解其金文研究情况对于了解西方金文研究及西方汉学的发展演变具有重要的意义。本文拟对方法敛《早期中国文字考》中的&quot;散氏盘&quot;释文和翻译进行详细探讨,指出其金文研究的优缺点,以期反映出早期西方金文研究及汉学初始阶段的一些方面。","categories":["09_其它"],"year":2014,"publication":"黄河文明与可持续发展（第十辑）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKZfOWyy3GtGw3k7bT4SyNoL0HkCu-gWYA5Uu5nlOfRRcYngeVfsHs7mj1xtjRojkfqHugV3SaBpvrTf3eIVvngdrsDGSljEaqd9vls17gD0pOjIb3T5vosJw_UJOI3eGGMGtYDwDRAKUyMsA_eEtI1W9EjuLW8c97o6OD0de6eAgrMp1Z9Khmz&amp;uniplatform=NZKPT&amp;language=CHS","pages":"122-132","volume":""},{"id":4169,"author":"苏辉","title":"秦、三晋纪年兵器的刻铭及行款论析","abstract":"秦、三晋纪年铜戈的援部已经不见铭文,胡部铭文的主流形式表现为单一行铭文从援向胡的下端而行,但偶有的反向铭文可能是与特殊的用途有关。样式最多的还是胡部的铭文,根据字行与阑的角度可分为Ⅰ、Ⅱ两型,Ⅰ型又可分为a、b两式,铭文有铸有刻。矛、铍的铭文行款相对而言较为简单。就国别来说,秦和三晋者主要特点很相似,但也在某些方面各有特点。春秋时期以及之前的铜器绝大多数是铸铭,到了战国时期刻铭在数量上占了较大的优势,这种明显的转变背后有多种因素在起主导作用,其中工具材质更新、技术手段提高为直接原因,而社会各阶层普遍追求的雕刻风尚则是最基本的推动力。四国纪年兵器主要集中在战国中期到晚期,正好体现了当时刻划铭文成为主流的青铜兵器生产的大趋势。","categories":["09_其它"],"year":2014,"publication":"郑州大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK5DkMCkdwlJdNIuHG6NJcG0RK7afqyNG5Q_LjYIZv08UXuT5IbxhSbVAc8jUaWS_PO23p6RtZ0XeqSyyQpsNt8QDVaZh8H98CIq5FD-SzzQ4HB5-B0zDjoRcGl11LU_6LqRia3cKT0Iq9Y8AOew3u2yfiWACNUfXx7rZ4KYq5y9-gLgOD4Qp5L&amp;uniplatform=NZKPT&amp;language=CHS","pages":"152-155","volume":"47"},{"id":4181,"author":"陳英傑","title":"容庚《商周彝器通考》條别","abstract":"《商周彝器通考》(下簡稱《通考》)是最能代表容老在青銅器學研究領域權威地位的著作,1其構建了比較成熟而完整的青銅器理論體系,迄今仍是研究青銅器學必讀的經典著作。容老在書中對不少銅器的形制、銘文、定名、拓本、真僞、收藏等提出了重要的見解或提供了比較重要的信息,但散佈全書各處,不便查檢和利用,甚至易於被忽略,本文對其重要者加以1録並閒加考説。書中值得商榷的問題,本文也1録出來略加討論,因名爲&quot;條别&quot;,以就正於方家。","categories":["09_其它"],"year":2014,"publication":"简帛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL2YgfnCLjP6XQdXV0uJsB6H-MK3DDqSSfGqmbfwFB2ZPBJi_BKr-F2LlBO_2-kred2HsK0v3mjukybwfll8zDlLhI3M_CBA409BVKpDY_kVeEdZbRMv9A_Vb_XNpiBzbGYdKsZlAdzcU_8vjicbtddD3rQwKF9HVFV7onm2J0xSg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"345-364, 531","volume":""},{"id":4199,"author":"仲威","title":"吴昌硕藏《曶鼎铭》真伪谈","abstract":"二〇一四年元旦后的首个工作日,笔者在上海图书馆书库中检得一件吴昌硕旧藏《曶鼎铭》卷轴,其上方为《曶鼎铭释文》,中部为《曶鼎铭拓片》,下部为《吴昌硕长题》。拓片宽28c m,高28.5c m;画芯宽54c m,高134c m。馆藏号:Z1297。曶鼎于清乾隆年间在陕西周原出土,鼎高二尺,围四尺,深九寸,腹饰兽面纹。因制鼎人名为『曶』,故","categories":["09_其它"],"year":2014,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKnXG9d_BvjdK_dEzQF7fAFK_7oDfA7i8jHUmBA1YdQSb_N0OtMbnIzLs8H_JDO7pVMy3xYjcBHzgPC2VvKxfWMWL4DB2zTsUkijrMvO332jH_XQf40_3zKxbMLbN8bkD46srid7y8_w_NJA3HRMZP8NWnXjWmqCrq9GXZAADi3a5NwKnAW26fk&amp;uniplatform=NZKPT&amp;language=CHS","pages":"167-169","volume":""},{"id":4209,"author":"陈伟武","title":"读《金文编》第三版批校本小记","abstract":"曾师经法先生全面评介过容庚先生的学术成就和治学经验①,《金文编》既是容老成名之作,又是容老倾注毕生心血的代表作,从1925年初版至1985年第四版,历经半个多世纪,容老锲而不舍,反复琢磨修订,成了中国现代学术史上的一个范型。光是《金文编》序言的变化,黄光武先生就揭示了其中的不少意涵②。第四版《金文编》由张振林和马国权两位先生摹补③。后来林沄、高景成、刘钊、陈汉平、董莲池、严志斌等学者都有订议之作④,张桂光先生曾经撰文予以评","categories":["09_其它"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKJoRPuIuJocs7WOM5bLZ1n8P2Fssb1R_sdenySpA_vChV9j0BnB6SvAZ-uf2phbX75Vg6ErtD0nS1C63uNyUdIi-FKYUB3TAJUjXHrbwtgLclLQLHaA58f6zFMrsPMIC4GM7Eyg_MliYMFFr-n2GoybudBDa1JkIkcu2Xj7XQOdQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-25","volume":""},{"id":4210,"author":"黄文杰","title":"秦汉金文著录和研究史上的里程碑——读容庚先生《秦汉金文录》和《金文续编》","abstract":"秦汉金文的著录和研究源远流长。宋代的吉金书籍中已见秦汉金文。经元明时代,清代金石学著录的汉代金文的数量有明显增加,对秦汉金文研究的水平也有所提高。民国时期,秦汉金文的著录和研究有了很大的发展,出现了一个崭新的局面,其中引人注目的是容庚先生专门著录秦汉金文的专书《秦汉金文录》和专门收录秦汉金文的字编《金文续编》先后问世①。笔者拜读学习《秦汉金文录》和《金文续编》两书,获益良多。下文从两书的贡献和历史局限性两方面谈自己的一些粗浅的看法,请方家指教。","categories":["09_其它"],"year":2014,"publication":"古文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK-qlXqWWh_nhr6m5ScRSySs43IHJLP0_CzD_akvWZzV7lsoJQcAvE6sB6Rw4G3wFDL9SDa8UlSBcw5Dy5cg2BD7cmyN3Gf60RFnjNvma70jPKYACqW36Hx1PJQ8aYOciaeXdN2qgKsd8bf5NHCXy13viVpWcfDtkKb4z3SYKg32g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"26-34","volume":""},{"id":4237,"author":"姜守誠","title":"北大秦牘《泰原有死者》考釋","abstract":"北京大學藏秦代木牘《泰原有死者》是近年公佈的一份珍貴出土資料,它以復生者口吻講述了死人的好惡及地府冥界中的價值取向,對於研究秦代的婚俗、喪葬、祭祀、死後世界及鬼神觀念等具有十分重要的意義。我們着重分析了如下內容:死而復生者的身份認定及女子的婚姻歸宿,死人的財富觀念及黃圈的象徵含義,古人的魂魄觀念及形&quot;魄&quot;拘閉地府的認知,鬼神亦須飲食的祭祀理念及後世道教的天廚、地廚觀念,强調以故衣殮葬及其背後隱藏的薄葬用意,以揭示秦漢時人的宗教信仰和民間習俗,期望有助於理解這篇牘文的深層含義。","categories":["09_其它"],"year":2014,"publication":"中华文史论丛","link":"https://link.cnki.net/doi/10.16837/j.cnki.1002-0039.2014.03.009","pages":"143-178, 393-394","volume":""},{"id":4288,"author":"白于蓝","title":"汉字理论与汉字发展研究之扛鼎力作——评《古汉字发展论》","abstract":"关于汉字理论与汉字发展的研究,一直就是汉字研究领域的重要课题,同时也是最为基础的工作。近代以来,随着甲骨文、金文以及战国文字等古文字材料的不断出土,出现了以唐兰、裘锡圭、姚孝遂、林沄和黄德宽等先生为代表的一批著名学者,他们依据地下出土的古文字新材料,对汉字的起源、性质、构造、发展演变以及汉字的研究方法等多方面的问题都做过许多重要的理论探索,取得了许多重要成就。但毋庸讳言,相对于古文字考释和古文字资料的整理工作而言,学术界纯粹的有关汉字理论与汉字发展的研究依然是一个相对落伍和一个相对","categories":["09_其它"],"year":2014,"publication":"学术界","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKZro23tuoJW5rTSMIWM5-91Pf5ay9Bs-HFoedPBNdN0N2HiwEGNfPRN5rK8WZ2gGNRy_EJEUxDLgLUNK7rYzsdkjbcp29clm5QL5NDAmaeXO8F8w0tuw58ppdpa_LUpsl6Cfsprl7FatX-7Fkhe02J2hX7am4UF05scJje8Ctjyg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"231-236","volume":""},{"id":4290,"author":"董文强","title":"西周青铜器铭文书体艺术探微","abstract":"西周是我国上古文明的兴盛期,也是中国青铜文化最为发达的时期,此时期的青铜器及铭文的铸造和制作成果卓著。西周时期的文字形式基本上都是靠青铜器保存下来的。西周青铜器铭文内容丰富,在形式上与青铜器铸造技术的进步以及西周先民的文化审美互为表里,成为人类文明时代的重要标志之一,其在西周历史、文化研究上的价值远远超过了《尚书·周书》[1]。西周青铜器铭文的艺术美体现了中国文字和书法独特的文化内涵","categories":["09_其它"],"year":2014,"publication":"文物鉴定与鉴赏","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKdJiSJFk3DrKlJmgSuHV7xGHKcMZ_1CVIgQI7g83YBurwwf8UFElqqbksYqogG7OpX5I9SjmIrrpgjRIBdWp6AowoINftEkjH9Roxd4cob3mn2uTk0N_x8Z3X7ZdznpIUtTx8ve6rdsT1VOzjx8MjHStVOVeyvghYNXuioo9QQ5w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-75","volume":""},{"id":4342,"author":"兰娟; 沈立岩","title":"先秦制器思想研究","abstract":"吕思勉云：“历代学术,纯为我所自创者,实止先秦之学耳。”作为中国文物制度的原点时期,先秦传承了新石器时代以来的制器传统,更将制器活动推向历史第一次高峰。制器活动既有贵族阶层意识形态的灌注,又实践着当日社会的“一般知识、思想和信仰”,以亚里士多德的质料、形式、目的、动力四因说来看,无论是作器动机意图,对材料、形式的选择及对操作程序的选定,都充满了思想的成分,器物成为具有表意功能的载体,蕴含精微深远的文化语义。本文以三代制器活动为考察对象,拟从四个方面,即制器者的社会身份及其对器物的设计与制作,使用者对器物的使用及评价,器物形制纹饰与构造,以及思想家依托其政治、经济、社会与哲学思想而涉及的对器物的评述与批判,来探讨先秦制器思想。这一研究,不仅有助于揭示三代尤其“轴心时代”器物文化之全貌,也能为思想文化研究提供新的资源与视角,同时亦具为当下的设计实践提供宝贵思想资源的现实意义。然器物的表意方式曲","categories":["09_其它"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJoPfSxU9LioFuJbNGOBOr5z4RXz5KBv8-Z0wezloaT3zBKYtOliS9Q3BpVTHVcCvPMmjVq3G4dyzlMnDW1x1qzvnp6Wxm134tGgs3TTGAzvYvJzHgpXUpOjNDi692ow2-sio_hpWRePbadDa9s-kVtlICMw89yO0-UOH3Mlhx728qJYaeIfbko&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4366,"author":"宗椿理; 李立新","title":"走向集权的物质文化之路","abstract":"“秦”是个古老而极富传奇色彩的部族，同时亦是个饱经苦难与风霜，在剑戟与硝烟中浴血而生的伟大氏族。它源起于东夷族群，立国于陇东之谷，盛起于关中沃野，用铜戟铁锤建立起了中国历史上第一个封建的集权帝国。虽从立国至覆灭仅有区区数载，但就在这短暂的十五年中却融汇了漫长物质文化播种后所结出的丰硕果实，更多呈现出的是中华民族极具创造力的文化性格。秦人在刚毅坚卓的进取精神驱动下所流露出的开放、包容的价值体系，造就了秦代多元融合的设计艺术特征。值此，多元、体系、标准、规模也就成了今后数代物质文化发展历程中的框架与标杆，同时也为汉王朝的建立与内部一统的民族文化定型提供了历史与文化的蓝本。论文通过对有关“秦文化”文本材料的深入解读以及古籍文献的分类、浏览、梳理与精读，逐步将其变为研究过程中所需用的文献实证，从而建立起了秦代物质文化研究的理论基石。通过对大量由考古发掘工作所获知的有关秦人社会生活中的实物遗存与凭借","categories":["09_其它"],"year":2014,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIV5OX4C4362RfAx_8aAdDNuSeCoIP53KOH8lNqHiuTO7q0wGIkvFPhNnGlkYh9IzZODAWJlkULKdCNHhF1J1nLXa-tF8UrT2zqQsB0yR7BwxV2RCXzpxxY_zTEqzsIE7oVGL5oWhCUltt2Hg3tcu5llEDLA3c_gh4h43F-HqWXYVbIboShdxIy&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4394,"author":"吴慧","title":"略论商承祚古文字研究","abstract":"商承祚是我国著名的文字学家,著述颇丰,影响深远。本文从古文字资料搜集与著录、文字考释方法、文字学思想三方面考察了商承祚古文字研究的特点。","categories":["09_其它"],"year":2014,"publication":"语文学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK2DXfCzGWjSqMjBtaF7w9pAwvJ0gER0qyxHwPXDU1tFM58BBDOJoXI7SycDi6RwrHufXAQY4FBm0Sc0ueqEIN-DCEHMuSTQWWTT4DkjjKNdHgBdxLDRVhlnd1xscoIkx2ulWRg2RV4P8Rc30QQsWEWjVtcG0-r1jyanBR7RnE-Fqpb_kaqbD0G&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46024","volume":""},{"id":4400,"author":"孙刚; 李瑶","title":"“陈■车辖”铭文辨伪","abstract":"《殷周金文集成》12023号、12024号著录两件车辖铭文拓本,其中12024号车辖原器为罗振玉旧藏。本文指出,车辖铭文在内容上与《殷周金文集成》11036号&quot;陈■散戈&quot;十分相近,对戈铭中&quot;■&quot;、&quot;散&quot;两形体的旧有释读意见进行了归纳总结,并分析了戈铭所表达的含义即此戈为齐国贵族&quot;陈■&quot;所有或由其督造的&quot;杀伐之戈&quot;。在厘清11036号戈铭文释读及含义的基础上,对车辖铭文的书写风格与内容进行了考察,指出铭文本身存在着很多疑点,并从辖铭&quot;散&quot;字书写方向、&quot;月&quot;讹作&quot;夕&quot;、文字笔画完整性及铭文含义等方面进行了分析论证,从而认为车辖铭文很可能是根据《殷周金文集成》11036号&quot;陈散戈&quot;铭文伪作的。本文还讨论了《山东金文集成","categories":["09_其它"],"year":2014,"publication":"中国国家博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ46piLlxpwtgo5RkC460LQPcniT6WY8jHinns_2VxJK9IcGmeqnNXkiaGq0zcQTdWsjV36UZt6EHnCNHPcCAy4IPLuIaVFOVvw49lanwHkVnK2HhjVuKh5DJtxlnEewlgrL2kfm2yKr4-6-5BJK-Y3piKUfy3qBqyeShdZ0d0LIw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-74","volume":""},{"id":4443,"author":"王其秀","title":"吴东发《商周文字拾遗》校评","abstract":"一、生平著述吴东发(1747～1803),字侃叔,号芸父,又号耘庐,浙江海盐人。乾隆时诸生,嘉庆时岁贡生。吴东发父亲早逝,家境贫寒,以授徒为业,科举和仕途屡屡失意。遂废科举,致力于金石考据。尝从钱竹汀游,多所商榷,钱引为畏友。后又与海盐金石学者张燕昌一起受知于浙江巡抚阮元,阮元也深谙金石学,因此深得阮元赏识。阮元《定香亭笔谈》记载:&quot;嘉兴吴侃叔东发,老诸生也,博古能文,识古文奇字。尝谓石鼓文章句,谓石鼓文中,有次章即用首章之前半,重叠读之,如毛诗之列,徒因刻石简省不重书刻之耳,所言颇为前人所未发。&quot;(卷二·二九)又记:","categories":["09_其它"],"year":2013,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ2DdIL7i-JO36qJK1AOpvnAbhfxHBzHpY1cv0jgcrFAvEMkad3Ldc9gQQU_b8hKWXi-t3MbfsBBzyCmXe2trFjzCOjmJmhPdxbCG1DFzKi8TWSngOYtGb2CETuX3u2dUQRt3upTUseI965HBcp8w_9TtG-seFVs16YT2R5fsxCpA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"71-81","volume":""},{"id":4478,"author":"徐再仙","title":"齐国金文的“装饰”特征小考","abstract":"&quot;装饰&quot;作为古文字追求美化的方式之一,在东周时期得到广泛应用。但齐国文字相对保守,装饰程度也颇为朴素。本文将以传世器和出土资料为主,对其收录的金文资料进行研究,从五个方面分析齐国币文的&quot;装饰&quot;特征。","categories":["09_其它"],"year":2013,"publication":"长春工业大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJucAfWhhHFr2VXOvY7IXIqay9ZLRW8MAlLOScWmuJNyfC9HYlMiQAe-d50cbVNacYSOXg27baD2m-htQmxrkcP-uiG31Xgiqm4uMFeZ6q3Gqn-WuMh3IHSqtBtnJO4_i9_1XpOrzte_L_SJ-RwRKQjoGmP-b6TaE9kK01gFHZ3sw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"85-87","volume":"25"},{"id":4493,"author":"宋江宁","title":"文献、金文和考古资料在西周史研究中关系的讨论——以洛阳西周时期成周、洛邑、王城的研究为例","abstract":"在三代历史的研究中,学者一直面临着如何整合文献、金文和考古资料的困境[1]。无论具体的某位学者是否同意这种困境的存在,但从宏观上来看这三种资料之间的不重合甚或矛盾是客观存在的。这种情况既存在于历史学界和考古学界之间,也存在于考古学者之间。笔者在对洛阳地区西周时期的资料进行研究时,深感这种情况尤为突出,故不揣鄙陋,在此试对关于成周、洛邑、王城的讨论进行简单的分析。","categories":["09_其它"],"year":2013,"publication":"三代考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJFU4bBYuRFWZhJLSlhYQBUuxLcrfzWqVC0IzMupzqVVQX_MGl8AQrBjL154FkS1SJCX2Bbe40pwgE7Kp84NUZ2jjq9ckPPhcGVldD4_QvSLwWSbqsYeXTpWzoXTUFikH0lY11tjuWE_UQyV59-0pYDPp58IuQLpzfYuACtZQsIwg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"253-259","volume":""},{"id":4531,"author":"李义海","title":"郭沫若辞章视点金文考释方法运用举例","abstract":"郭沫若辞章视点金文考释,是郭沫若研究成果的学术应用,是郭沫若研究的学术增长点。它将通过商周金文所载文化元素的发现,丰富文化考古的研究成果与研究方法。","categories":["09_其它"],"year":2013,"publication":"郭沫若学刊","link":"https://link.cnki.net/doi/10.16142/j.cnki.gmrxk.2013.03.005","pages":"32-35","volume":""},{"id":4534,"author":"张海丹","title":"王国维的“二重证据法”及其例证","abstract":"&quot;二重证据法&quot;的提出,可以说是我国史学研究领域的一件开天辟地的大事,王国维总结多年的古史研究经验,从理论角度提出了这一科学严密的论证思路,为我国史学理论的日臻成熟做出了巨大贡献。&quot;二重证据法&quot;即用地下之新材料考证地上之史料,充分利用甲骨文、金文、简帛、石刻等出土的新材料来考证补充传世文献的记载,这一理论为我国古史考据、史学甚至文学等研究都提供了一种科学有效的方法与态度。","categories":["09_其它"],"year":2013,"publication":"信阳师范学院学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLgolZZUZ7TDwcYJIXN90EnVdfrWpDtLHMkPj1GfjA_NE62GE8CvFR9DstmgYuVJU3hWiedvQo8VGnD8VLgECpUFQovgqMvPBPVWY0tXI90i29dAUDsBp7nOzFpTWumGRYBbuttfo3HM7VbCNrW_wgdBoV709b5sM_HJAyjnpIMzg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"138-140","volume":"33"},{"id":4535,"author":"陈国成","title":"《散氏盘铭》的历史评价及其书法意义","abstract":"出土于晚清、铸于西周厉王时期的《散氏盘》,其铭文书法极受艺林推重,评誉之高,摹习之众,影响之大,在先秦书法中只有《石鼓文》差几近之。然而,人们只是欣赏其美,对其风格原委尚无深究,致使摹习者难得其法,论说者也大都不得要领。从《散氏盘铭》的源流入手,对其著录、社会时代背景进行剖析,并做出历史评价,寻求其风格原委,进而探讨其书法价值。","categories":["09_其它"],"year":2013,"publication":"大庆师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ4-szPI1tSmjYJZ8psiUT1eJyHWcFTPxm00LZgJsNl9B61u8mTjuudw075MwYZ0mxHBzWMwUgwSGiMvzNAfQ9rLZFFCAuLAjzb_gPtVFRynOPTO0dpP6UtYQLJVoCFeAah8EJci62rJjnS_GdRz_VaLnOcHrGltiMQ78cdvL5irw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"134-136","volume":"33"},{"id":4571,"author":"马晓风","title":"论金文研究兴起于宋代的原因","abstract":"金文研究兴起于宋代的原因是多方面的。政治上重建礼制的需要、宽松的文化政策、疑古创新思潮的盛行,为金文研究的兴起提供了良好的环境。青铜器的大量出土,是金文研究得以展开的先决条件。《说文》的校正、刊布与流传、古文字的整理与辑录、《三礼图》的编修及法帖研究的兴盛,为金文研究的兴起提供了必要的学术积累。雕版印刷术和拓墨技术的广泛使用,为铭文摹本的流传提供了有利的技术条件。","categories":["09_其它"],"year":2013,"publication":"图书馆理论与实践","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJXzIhOG1uIE8ww2M7eot94P5YI3KHxd4tgAOYLApeA3EVfG0lMdybcDS9-X8f0woaAtYTjvVPpr3QD02oh9B_yJEqflYdAlD-Oofv2VR6s976JhqCELmkXAqzH-DQVFH2nXXcx0kUbEME7qT775wwYbqe_AlSRjuovnkaM2ZXKNQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"94-97, 112","volume":""},{"id":4582,"author":"侯书勇","title":"通方知类承先启后——王国维金文古史研究综论","abstract":"在近代学术史上,王国维有着极为重要的地位,无论是哲学、文学还是经史之学,都取得了卓著的成就。其论著不仅能继承前人既有成果,而尤能开拓新的学术区宇,在学术范式转移方面有着重要的推动作用。就金文古史研究而言,王氏虽未有专著面世,但其以突出的问题意识所作有类于专题性研究散见于相关论著中,若就此作系统的梳理,可见其承先启后的重要地位及对此后相关研究的深远影响。","categories":["09_其它"],"year":2013,"publication":"河北师范大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13763/j.cnki.jhebnu.psse.2013.04.012","pages":"115-122","volume":"36"},{"id":4611,"author":"张子松; 刘子建","title":"基于信息可视化技术的周秦青铜器数字化艺术研究","abstract":"青铜器是历史留给我们的重要文化遗产，是青铜时代创造的物质文化和精神文化。大约从夏代开始，我国进入青铜时代。到了商代，青铜器的应用几乎涉及社会生活的各个方面。处于青铜时期的周秦青铜器更是因为造型优美、纹饰繁缛、技艺精妙绝伦、铭文含义深刻而闻名于世，具有极高的历史价值和艺术价值。周秦青铜器作为文化遗产的一部分，代表着我们祖先所创造的灿烂文化，反映了当代人的审美观念、工艺水平、历史文化以及政治、经济发展历程，体现了其历史、文化、艺术的研究价值，同时对我们现代艺术设计发展也起到一定的推动作用。二十一世纪是信息发展的时代，信息可视化技术作为信息时代的产物影响着社会的进步，推动着各行各业的发展，在高端工业技术领域（航空航天、船舶制造、汽车仿真、轨道交通等）、能源领域（石油开采、天然气加工、核电站运行等）、国防科技领域（战场模拟、仿真训练等）、生物医学领域（手术模拟、远程医疗等）以及教育科研领域（军事学","categories":["09_其它"],"year":2013,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLkD49QrBAmC2UfG1Fmv_qv02Z_l35iXohIqAybFcdgxJbZmERD5EAxxV5M94xuRAJPFFSJBLRkzTVNoPqheMZDjs73ejYqeIOahXe4RxTMAistjnV5Jpu4ktJmRVrKVcwy-7DTKlrmUH7Ose4g4MFnS90xzoj9fVXKLjq5a-0sdwdUssDK139B&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":4627,"author":"马晓风","title":"论宋代金文研究的发展与演进","abstract":"根据两宋金文研究活动、产生的代表作品和取得的成就等,可将宋代金文研究分为四个阶段:发生阶段、发展阶段、兴盛阶段和深入细化阶段。仁宗嘉祐以后开始了对金石器物的广泛搜求和初步的整理研究,代表著作是欧阳修的《集古录》。神宗元丰以后,私人搜求和著录器物仍是金文研究的主要形式,代表著作是李公麟和吕大临的两种《考古图》。进入徽宗朝,官府开始编修金文著作,代表作是官修的《宣和博古图》和赵明诚的《金石录》。南宋初,就现有的材料继续进行编集、著录和考释,使得金文研究走向深入,薛尚功的《历代钟鼎彝器款识发帖》和王俅的《啸堂集古录》是这一阶段的代表性著作。","categories":["09_其它"],"year":2013,"publication":"兰州学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIvboX_KfqYen1s4APeoCpk1QzqTjJv75knsqHylqFliaN0Fcqa3edvS5K7esEnreqU-8T4et1jRlDL7OAFd5w_5tMnG4szF7AqScEviTO51brTkVCYq5S0QXBephGWeiDi-sYh6cevvAzr7er5e7JN8j-z8rlzjMGOAxpw31IwxQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"172-175","volume":""},{"id":4663,"author":"马晓风","title":"宋人对青铜器铭文的摹录及其价值论析","abstract":"宋人对所见或所得青铜器铭文进行摹录,既为宋代金文研究的深入和扩大提供了保证,也为后代保存了相当丰富的宝贵资料。宋人所著录的铭文资料对现在某些相关史学问题有重要的价值,也为古文字、音韵学等方面的研究提供了一手资料。","categories":["09_其它"],"year":2013,"publication":"延边大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.16154/j.cnki.cn22-1025/c.2013.02.007","pages":"57-63","volume":"46"},{"id":6568,"author":"佘玲珠; 秦颍; 董亚巍; 张亚炜","title":"商晚期圆底簋的范铸模拟实验","abstract":"中国青铜时代的青铜礼器都是采用范铸法生产的。笔者依据商晚期青铜器的铸造条件,进行了商晚期圆底簋的范铸模拟实验;实验铸出的圆底簋,其范铸特征、纹饰效果等与古代出土的同时期器物之特征、纹饰效果十分接近。这表明,实验采用的&quot;分型制模&quot;、&quot;分模制范&quot;、&quot;芯盒制芯&quot;、范面纹饰&quot;压塑&quot;及&quot;堆塑&quot;等技术,当是商晚期青铜礼器范铸工艺的真实反映。","categories":["09_其它"],"year":2013,"publication":"湖南省博物馆馆刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIt5OJuoHNQ9Jk0xS0mm2eoYxTfF0xXLhOhQxf159Jlj88Dyae93s0UYxULj_WYeiCdeKoRVLWm_ep70aBBJ9dGc-0TOH8HooDYUQ25U67fnqonq1BTFeOswQdBFJ16ROMn5CW-pVNz8ACv2xhvRDfD-ePpyP9iBTxk02wkwI_tDQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"139-148","volume":""},{"id":4764,"author":"周崇云; 朱华东; 陆勤毅","title":"江淮地区商周青铜器研究的回顾与思考","abstract":"针对江淮之地出土商周青铜器的研究已有80余年的历史,根据各个时期的特点,可以将学术史分为三段,即萌芽期、发展期和初步繁荣期。受材料所限,前期研究的时空范围十分有限,参与学者少,研究方法单一。新中国成立后的30年间,处于逐步发展阶段,但研究方法和对象上仍受到很大限制。最近30年,大量新材料得以公布,期间研究成果丰硕,研究角度多样,研究热点不断涌现,研究队伍不断扩大,呈现出一片初步繁荣的局面。","categories":["09_其它"],"year":2012,"publication":"安徽史学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL8TZCEq6y4ptvqVZVF1CNB7r6wgXl6q09ZMzHy-dCBGqXq-1xADCH6oevXmImq12J4IfAbWpFLYT1qE-Rk6jTP3FWH7zHwC2fe5SvH4QXeXACj1K85OQectXASO0F_Z55_ooiX9-ooplNRgqemKt5ZvXUovbg1FPOOsHF_ReDutg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"94-102","volume":""},{"id":4782,"author":"马晓风","title":"简论薛尚功的金石学研究","abstract":"宋代金石学家薛尚功著有《历代钟鼎彝器款识法帖》二十卷和《广钟鼎篆韵》七卷。《款识法帖》以摹录铭文为主,并做释文和考说,逐一对器物的制作年代进行断定,开创了后世考释类金文著作的通例。考释文字方面,基本使用了对照法、推勘法和偏旁分析法,已经能释出大部分常用金文,对金文构形特点和古文字发展的一些普遍规律也有所认识。古器物学方面,提出了器物断代的几个标准,对器物的用途也有比较准确的认识,表现出了比较高明的识见。","categories":["09_其它"],"year":2012,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2012.01.014","pages":"129-133","volume":""},{"id":4914,"author":"刘秋瑞","title":"宋代人的金文研究情况初探","abstract":"宋人始为彝器款识之学,宋代金石学著作是历史上第一次大规模研究古器物的集中反映,它标志着对古代器物的研究成为一门专门的学问而受人关注,具有极其重要的学术价值。","categories":["09_其它"],"year":2012,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2012.04.016","pages":"121-124","volume":"33"},{"id":4946,"author":"管荣臻","title":"探赜索隐铸史存真——评刘正先生《商周彝铭学研究史》","abstract":"在当今汉语文字学界,简帛学与甲骨学是各方关注的重点,最近十几年有关的著作如雨后春笋般地冒出,可谓风头正劲。与此同时,传统的金石文字之学却陷入了一片沉寂。而从传统的金石文字之学中实现了凤凰更生的金文研究,随着现代考古学和古文字学体系在中国学术界的正式定型,却反而出现了学术界对商周金文研究陷入止步不前的境地,进而也造成了对商周历史和思想、文化、政治制度等方面研究的严重缺陷。正是在这样的背景之下,刘正教授积十年之功力,向学术界贡献出了他的这","categories":["09_其它"],"year":2012,"publication":"南方文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJoIWC-hwjdVucDZJyF_9kZFGU5bKEQat66VA-HtZMKqCnEJsAJVGEPQmdEv5vrqG_ILUM7L5q0B_GyjALjZRMNzqZbRPjhPBC9f7AF9zo8teLTt5Ob2i5zst9qdjnSFnFKsfZcLddt6OWpjNtEl63hbCoIxUY17fSVMLm52VaFFg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"180-183","volume":""},{"id":4958,"author":"岳占伟; 岳洪彬; 刘煜","title":"殷墟青铜器铭文的制作方法","abstract":"殷墟出土青铜器铭文的制作方法,可分为铸铭和刻铭两大类。铸铭占绝大多数,刻铭极少。铸铭的制作方法有模作铭、芯作铭和范作铭等三种形式,以模作铭为主。刻铭出现于殷墟四期,目前虽然只发现4件刻铭铜器,但其意义重大,不仅把中国青铜器刻铭的历史追溯到商代晚期,而且为研究青铜器铭文的制作技术,尤其是刻铭技术,提供了十分珍贵的实物资料。","categories":["09_其它"],"year":2012,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKrUAtqH9_-bxA__evOeRLCJAI7WrWGw6O0oLthS3ZPmDrOl_qMCNcFw5Mz_PO7s_NTfQjuyCeTaDXr8AX0pDxiJgwu99fY8X7FbJWQiWNO7rH9JEKlCjec4kr-VoCiIw-kbjep4TSgVglyxTMWnEC7_i2l5s8_4O62aGUBWmvi9w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-68","volume":""},{"id":6262,"author":"陈有路; 刘成","title":"商晚期椭圆型青铜壶范铸工艺研究与模拟实验","abstract":"从二十世纪二十年代末开始,全国大规模的考古发掘,出土了大量商周时期青铜器,以及铸铜遗址和遗物,揭开了学术界关于青铜器技术方面研究的序幕,打破了长期以来仅对器物形制、纹饰、铭文等外部特征的研究。从铸铜遗址出土的遗物和青铜器表面的历史痕迹来看,商晚期青铜礼器的制作方法为铸造法,其中陶范铸造又是青铜时代的主流铸造工艺。现有研究资料表明,范铸工艺是一个复杂的系统工程,主要由制模、制范、制作纹饰、制铭、熔铜、浇注几个环节构成。到目前为止,学术界在范铸工艺的研究中,对模和范材料制备问题、制模工艺、纹饰制作、铭文制作、焙烧温度、熔铜合金配比等方面取得了众多成果,但是分歧仍然很大,没有一个完整的、公认的范铸工艺框架。目前为止,关于几何造型的青铜礼器中,已经开展过鼎、觚、斝、尊、簋等具有圆形横截面器物的复原试铸和模拟实验,还没有关于椭圆型器物范铸工艺分析和模拟实验的开展,笔者拟通过商晚期椭圆型青铜壶的范铸工","categories":["09_其它"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ1eewyFO282H5l7_RqShZXLYRaF6rcIWYbUhei9DVfobDbF9Boc1jdYMzpNduAVDtMxIKwLqpbchsq2--4dDrPFGfk76BGY4DL_97VMohqTXsLlZ767LLxyNTPJ0bQ-_r75NWqfvzeBUsOZSH4dXL_qH7oQiyIWK4KDiUglJBGZLobsZLMh_CP&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6277,"author":"林文华; 林志强","title":"《广金石韵府》研究","abstract":"《广金石韵府》是由清初闽籍学者林尚葵、李根在明代学者朱时望所作的《金石韵府》的基础上进行增修补订而成的一部金石学方面的著作。然而,一直以来,学术界普遍认为《广金石韵府》只是对夏竦的《古文四声韵》和薛尚功的《历代钟鼎彝器款识法帖》等书的简单照搬。但是通过对此书进行的分析和研究,我们发现《广金石韵府》在继承《汗简》、《古文四声韵》这两部著作的研究内容的同时,也是有所创新的。由于《广金石韵府》和《汗简》、《古文四声韵》这两部记录传抄古文的重要字书有着密切的传承关系。因此,我们将本论文的研究重点设置在对字形的分析上。包括对《广金石韵府》和《金石韵府》中不同的古文字形进行历时与共时的分析,对《广金石韵府》中的传抄古文进行疏证,对《广金石韵府》中的“省文”进行整理研究,还有对此书的作者、版本、编写体例等情况进行分析和归纳。基于清代是金石学得以复兴的黄金时期,本文尝试对清代的金石学以及福建金石学的发展情","categories":["09_其它"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKOph7sIAsRsLPjRJl8dfaWOQtdnyBVIpVC21A0ObynFm1EwXd3baO-yGQ1sDBTtdWvdfsYQLR214rF-UBiSVQjzS2vWjDZHd5eE8zdb8MVZg3YUfdKst77RLxC81F8Tt03aNw5LSntNOfZ2t1yv8Az_l92oyNHQtX8rbY-ofyKUagrgQuTxcl0&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6296,"author":"杨伟微; 郝士宏","title":"朱德熙先生古文字研究初探","abstract":"本课题主要以朱德熙先生的古文字成就为研究对象,通过理論和文献实例相结合,对朱德熙先生的古文字研究成就進行综述與評介,动態觀察朱德熙先生治学轨迹和学术研究脈络,以及與其他学者在学术研究上的继承发展关系。全文共包括四個部分。第一章绪論,包括朱德熙先生学术述略,现代学者对朱德熙先生学术的研究情況以及本课题的研究内容、方法、目的、意义等方面。第二章,系统论述朱德熙先生古文字研究成就,初步歸纳朱德熙先生古文字考释的特點和方法,简述朱德熙先生的古文字研究成就在古文字学史上的价值及啟示。第三章为结語。","categories":["09_其它"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLXPOtJG9k2tUKP5kybZPjL-lN0r8kxB1uQVxPGmvJkVN0XkPfzm0cWxSJyTVDS20N1uNinT7C-4RyvWc-3mMIhq5x81BgaVr0XO5TEKBvMhyuEyIOe71zx65QU5Zw6BYpZKi09QsHyPr4gn2Wxi4j9P8xrCSme0Prj_B2JQOuoUaeQ3-_mvIqq&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6315,"author":"李嘉; 王艳","title":"造物史视野中的先秦青铜“壶”形器研究","abstract":"先秦造物史是中国传统造物史的重要组成部分,也是中华文化的重要组成部分之一,它深刻影响了中国造物艺术的基本走势,为中国造物艺术的发展明确了方向。从造物史的发展历程来看,“壶”形器的使用几乎贯穿了中国造物史的每个时期,它的发展演变形成了一条较为完整的线性发展轨迹,而先秦时期的青铜“壶”形器又具备上下承和的典型特征,作为中国先秦时期重要的青铜器物品类,在各地的大量发现,从一个方面揭示了中国厚重悠久的历史文化,为我们解读先秦造物的历史提供了丰富的视觉图像资料,同时也为后人营造了一个异彩纷呈的“壶的世界”。本文以现代人对于壶形器的认识,将先秦青铜盉、青铜壶、青铜卣列为研究对象,从造物史的视角,分七章对其进行论述：第一章,引言。对与课题相关的国内外研究现状进行综述,并对课题研究的意义与目的、研究方法、研究框架以及写作思路、相关概念作适当的说明。第二章,先秦青铜“壶”形器的铸造技术与工艺。立足于与研究内","categories":["09_其它"],"year":2012,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLzIdbaNaa0e67SEo6k6ozQPerI5f7Gwh-5VNp4i7Fdaew_G93mbKudZ4nK-ox6cijxxuRGAt9RP-P_6myY_en0G7gIScwp-qRS4pWQE_PzJVsPcHqEtZkJwH0hjxAMmFr8jgLUEr6q4Qs4x2IKe4UCuatI8xkeReTOXi2dIYrRyV4Prikwglio&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6579,"author":"吳婧","title":"曾國金文研究綜述","abstract":"曾國是文獻記載的小國,20世紀以來出土了大量曾國有銘銅器,學者對曾國銅器及金文做了大量的研究。對這些文字的研究有利於我們解決有關曾國的其他問題,本文试图对前人有關曾國金文的研究情況進行梳理,為其他研究曾國金文及其歷史的學者提供方便。","categories":["09_其它"],"year":2012,"publication":"励耘学刊（语言卷）","link":"https://link.cnki.net/doi/10.13554/b.cnki.liyunyuyan.2012.02.011","pages":"189-206","volume":""},{"id":6602,"author":"李义海; 康国章","title":"郭沫若辞章视点金文考释的文化考古学当下意义举例","abstract":"郭沫若辞章视点金文考释,是郭沫若研究成果的学术应用,是郭沫若研究的学术增长点。它将通过商周金文所载文化元素的发现,丰富文化考古的研究成果与研究方法。","categories":["09_其它"],"year":2012,"publication":"郭沫若与文化中国——纪念郭沫若诞辰120周年国际学术研讨会论文集（下卷）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIUOfJ-KqMQqfHorAK1nlyLlBaPpHkE_aDMWjJu7d4bNwdDlk5rr1fBACLIQCuGqqX4m63rBUFYKh8Oc2AmOYuo37pBybW3yk6VSjlzT58yCbHMXgrNIn0DJvxMy02KO-0wccUv6InalYOlUYp7FbUAVg5f7ShHjpPEFyztDwZwyZBpTLuC5tIk&amp;uniplatform=NZKPT&amp;language=CHS","pages":"196-200","volume":""},{"id":6615,"author":"朱彦民","title":"戴家祥先生在津古文字研究述评","abstract":"戴家祥先生是我国当代著名的历史学家、古文字学家。1934年至1936年,他任职于南开大学经济研究所。在津期间,戴先生担任教职之余,尤致力于甲骨文、金文、石鼓文等古文字的研究,撰写并发表了十多篇文章。这些成果虽多属对时贤论著的评论,但其中可见戴先生早年的研究风格、治学态度和学术观点,弥足珍贵。总结戴先生20世纪30年代在南开大学的教学科研经历,对研究其个人的治学历程及整个学术史都有着积极的意义。","categories":["09_其它"],"year":2012,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIFjobjokugJ9sTnAFswfMk0LjJqenLAm3dX0r6PQFShDEGu0geN0gGZssk-mga4sE0FX0TPTnUoIdW9w1Ynu8lNcV2WC0yCTh8N-nw2-pb337KoGhE0cNC1szC8OEs6rgUJIK-d03kBDZqA1vuq2njfxdbxwee_2BJjpPwOBKZtw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46221","volume":"16"},{"id":5032,"author":"蒋书红","title":"金文研究分期述要","abstract":"金文研究萌芽于两汉,形成于两宋,成熟于晚清,鼎盛于二十世纪八十年代之后。各阶段的金文研究,逐步推进,不断丰富,在研究成果的内容、形式、数量、质量和研究的方法、侧重点等各方面,时有变化、补充、完善。今后的金文研究,唯有在全面了解前人研究成果的基础上,增益弥补,开拓创新,才能避免简单重复,取得新的成绩。","categories":["09_其它"],"year":2011,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLgMV7Sq22zV4sTQ0qcYLOYPuyE51hnOhOTlhIAaVyOQs5zzKy8R-UxcN8u-4LarzBs1ZAf3y_4dNBBNhcljdDmKQZY6L8xstFeSwsf42Od2UIg0ATPJofp89cxI0dntsMXnd2lyi7fDr_kZ7Y66_I0PtUUw1BJmt1nmHR3iHGWEA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"49-57","volume":""},{"id":5033,"author":"李义海","title":"“体用同称”与郭沫若辞章视点金文考释的当下意义","abstract":"郭沫若先生在辞章理论的框架下,从创作行文的角度进行西周金文的考释,不仅解决了许多重大疑难问题,而且为学术界树立了通过金文语篇的整体理解来考释局部细节的典范。郭沫若先生的成功经验,对当今正确训释疑难词语的意义将更为凸显。","categories":["09_其它"],"year":2011,"publication":"闽江学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK8-JKHAmvB1ZK8rrXZf3iGd0tN5fxk7RItMYTignU91qVQ6RLOsqQ_ICRqEfoanRPhAxuvHqaD643NAhDa32kpRYNk89Gqq2H8Bu_tr3BKlD8zEdeKHIcAFxibHiQTsy18Dp1WwuKlCywmVLtZ8ptprlEJJDkXwryuNRRjq3O_dQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"86-90","volume":"32"},{"id":5052,"author":"赵爱学","title":"前“古文字学”时期隶定史述略","abstract":"&quot;隶定字&quot;是汉字中客观存在的一种文字现象,但相关研究历来比较欠缺。近代以来出土文字资料大量出现,相关考释中隶定字的使用非常混乱,给一般读者和古文字数字化处理带来了很大的困扰,这也对隶定研究提出了要求。梳理汉代至清代各历史时期的隶定情况,总结前人隶定的经验,对今天的古文字隶定可以起到一定的参考作用。","categories":["09_其它"],"year":2011,"publication":"廊坊师范学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.16124/j.cnki.cn13-1390/c.2011.03.010","pages":"27-31","volume":"27"},{"id":5058,"author":"武振玉","title":"殷周金文语法研究综述","abstract":"针对殷周金文的语法研究可首先分为词类研究和句法研究两部分,词类研究包括实词和虚词研究,句法研究则主要是句式研究。从研究对象看,各方面是不平衡的,主要表现为词类研究多于句法研究,虚词所受关注早于且多于实词,实词中代词的受关注程度高于其他类。从研究角度看,与句法、虚词及代词、数量词相关的研究多为语言层面的,其特点是将殷周金文视为上古汉语的一个重要组成部分,以相关研究佐证或补充传世文献;而与名词相关的研究则多出于佐证历史、礼制等目的;与动词相关的研究,其直接目的是为了通读铭文,但客观上对众多词义进行了探索梳理。从研究方法看,早期多为训诂式的,侧重一词一器的个体研究,近年来则引入了共时比较、历时比较、定量统计与定性分析相结合及现代语言学理论等科学方法对殷周金文进行全面系统的深入研究。","categories":["09_其它"],"year":2011,"publication":"吉林师范大学学报（人文社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJtP2ypttSM86Ak4faW43Z2pM69njFEyiL5O4g2zyhI3z74cIOAEGf7weCHc404GMk9FQmevvCzcZUTkH4VR18-b1rwf7vKp65uqFNudlH4gbTankW4Q386rsddhMSX8xjouKkvaIWojK0IX9AyEa2XcFh4cdvG8GXenpllR4_LJA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46-49","volume":"39"},{"id":5061,"author":"邵英","title":"上古时代的氏族、国家、王权等观念的古文字形体学考察","abstract":"从古文字资料看,中国上古时代的社会,氏族是重要的组织结构,有着独立的标志和武装。封土植树是原始的地域界线,随后,国家疆域意识成熟并实行疆土规划,在部族之间的征战中王权意识形成。上古时代的氏族、国家、王权等观念较为形象地保留在中国的古文字形体结构中了。","categories":["09_其它"],"year":2011,"publication":"陕西师范大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJHHJaVIRCIX7L-hNoKSobITznJi27taZ_VFj19FhvwiI-6lGVkqPpNjsnR6zmM_PxL6881EqLbKkkIcCm5p6Nt0Wieo7BH0tmanDaCDMGPheUuv8dr1xK8N9aNf1cM2_xF2QdHArcAMOkdqN7OWVifaGSWHJr2Kjk8q848FdVaiQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30-35","volume":"40"},{"id":5078,"author":"谢应举; 谢祥熹; 谢红伟; 谢晓峰","title":"对《夏商周断代工程1996—2000年阶段成果报告·简本》的质疑","abstract":"《夏商周断代工程1996—2000年阶段成果报告.简本》中,除依据《尚书.召诰》的记载而得出&quot;成王元年为公元前1042年&quot;这一条是正确的外,其余论述都不够严谨,或明显是错误的,因此不可轻信。依据现存先秦文献,可以求得周武王灭纣的准确日期、西周及西周以前若干位帝王的在位年代或其元年。依据出土西周青铜器的铭文,可以求得西周某几位周王的在位年代。结合青铜器的铭文及先秦文献记载,已求得西周共和元年以前全部十位周王(武王、成王、康王、昭王、穆王、共王、懿王、孝王、夷王、厉王)的在位年代。现存先秦文献中,有唐虞夏商周历代帝王在位年代记载的唯一文献是《竹书纪年》。《竹书纪年》中,从西周初年至西周共和元年这段时间内的记载,的确已被后人篡改,因此不可置信。但除此之外,《竹书纪年》中西周共和元年以后的记载、唐虞夏商时期的记载,没有遭受后人篡改,仍基本保持着晋代出土时的原貌,因此应与《古本竹","categories":["09_其它"],"year":2011,"publication":"学理论","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIYRrseICPsRY9GxoC1MTGunGcZsbxA2mCmWJDi8ZmdRXJBTtu9oRFwfRZpHabB21lyFzbsETpj3_Rr2LLOOhvI0t5UPvyPBs-HpSqEWSiPEUQ9t17ljOB28JWTKDpg9lAfZVyTNAFpo5Ik9YXt7vU6tgJtEXCAndGoVWPzI5cjBA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"78-102","volume":""},{"id":5081,"author":"胡长春; 吴劲松","title":"近十年来(2001-2010)的殷周青铜器铭文研究综述","abstract":"本文系统总结近十年金文研究取得一些重要成果:如新出土青铜器铭文的著录与金文的资料整理,金文工具书的编纂和修订,金文铭文考释与研究,特别是对叔夨方鼎、豳公盨、陕西眉县发现的青铜器窖藏引起学术界的广泛关注,取得阶段性成果;此外,金文族氏铭文研究,金文语法研究,社会史研究也取得一定的进展。","categories":["09_其它"],"year":2011,"publication":"学术界","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJBW_pYR-23d8xvfOuViC22eXTJvKK1_2m0vkNkb89SWbGeggB-ZwXDp5Ql3Fd99uzBFnag39D9n_b7O7AQWcKZJ1DMq1-JDmIKuzizfCQdZIw-HGrd1s7inSZRhs3oqGwz5Fxa5OkPxht_gD8J85X0dFC3Nwv0FxHaHeVOZib69w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"197-205, 288","volume":""},{"id":5082,"author":"曹祝兵","title":"二十一世纪以来利用出土文献研究上古音的新进展","abstract":"进入二十一世纪以来,利用出土文献研究上古音又取得了新的进展,研究材料有新的发现,研究方法有所创新,成果丰富。地下出土文献不但可以弥补传世文献的不足,而且还可以和传世文献互相印证。可以说,利用出土文献研究上古音,是为上古音的研究开启了另一扇&quot;大门&quot;,必将成为今后研究上古音的主流。","categories":["09_其它"],"year":2011,"publication":"敦煌学辑刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLGV1UE5fMiCi2AcLFV4QyaAQaoMoAQ0Qoplrq6KNbsfMGQ1_ovlmtYPWqJs2ajK3SU4AxS7BMDWx3Q3waTDkqvWTx6NOuXJnZJYxvBshml1ul7CTk4VIHR3KazeIpA-lQgqUgEdgB0zlfTO9i9I2dGUZj2UqFQCuFWP9Mw2ebVfA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"143-152","volume":""},{"id":5084,"author":"刘玉堂; 张硕","title":"文化史视野下的曾侯乙编钟","abstract":"曾侯乙编钟是我国古代音乐史上的奇迹。对编钟的研究印证了七声音阶、十二律、十二个半音体系、一钟双音、和声概念在中国先秦的存在。对编钟制度的研究,使得编钟作为周代后期雅乐制度的核心,地位更加突显,而乐悬制度、礼乐制度的传承线索亦更形清晰。编钟的铸制集中反映了范铸技术的新水平。编钟铭文字数多达3755字,是楚系文字的重要组成部分,其书法总体偏于美术化,是南方花体篆书的典型。","categories":["09_其它"],"year":2011,"publication":"武汉大学学报（人文科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIHSPTfxaTtwswRcq2jEjBjFZE8KwmIaMDu34aswTyBiC7JD2BI1LNZehjCxzLA14fp4Bk3pMkn3dAMGqZ9nq6rgAmO8QCBmGur02uEJSf4qfKOrBVpVtGy3m4CqfyllkAT4NX7qYjjZFIMevaLop9UdB2LzSGoqLyvJBnFCeT9FA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"109-113","volume":"64"},{"id":5090,"author":"王会波","title":"《名原》对象形字的理论探讨","abstract":"《名原》系由清代著名文字学家孙诒让在光绪三十一年(1905)写成,是作者从文字学角度总结自己研究甲骨、金文的一部著作。书中所含的一些关于象形字的理论很值得归纳研究,在象形字的分类上作者将其分为原始象形字、省变象形字和后定象形字,同时又提出&quot;象形文&quot;与&quot;骈合文&quot;的概念。以上观点的提出不仅在作者所处的时代很具前瞻性,对于我们今天从事象形字的研究依然有启发性。","categories":["09_其它"],"year":2011,"publication":"北方文学（下半月）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKlYDuoE4_7kCbn0LnyDdKSMoy1DWuJg_GrwcOZziB_kUug-NEE0abVCIBMVd8YErf1YeHrhs8Dw1iW7nYXjMsDC2_CBtP6YHurITz6eRlWAr0RlfDZyOqeLTYVBuZkikLdEXNxyQAbAhwR-_nY-Xuh5PItf4QKgbfII7Tvhakjjw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"119","volume":""},{"id":5100,"author":"刘碧虹","title":"王国维致沈曾植遗墨三种考释","abstract":"浙江嘉兴博物馆与海宁博物馆藏有王国维为沈曾植70寿辰而作的三件文献。分别为&quot;王国维行楷《海日楼歌》诗稿轴&quot;、&quot;王国维行楷致沈曾植信札&quot;以及&quot;孙德谦书《王国维〈沈乙尚书七十寿序〉》中堂&quot;。这三件墨迹在研究沈曾植的历史地位、王国维与沈曾植的关系以及王国维的书法艺术等方面,","categories":["09_其它"],"year":2011,"publication":"收藏家","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL-s3qxabh4m0wYvmGSs7RpskBw6PIG0mk_5GrKGUj7GR_sQlwAnCwpwlSpKFnBKSwI5xAGybWFLUQMOd-zgHb2JH6wrUlRX9E-t138lf1maUka7Y1YX7ir_RvaRWxLF7RhkM6gmPPGnl3JHchmUyostzR1KULdNCB-JrGCR9Lf7g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"47-52","volume":""},{"id":5104,"author":"孙合肥","title":"商代金文搜集整理的历史与现状","abstract":"自宋代始,古文字学家就以极大的热情去整理和研究商周青铜器铭文这一大批异常宝贵的资料。随着商代金文文献的大量出土,20世纪以来,其研究内容的丰富及研究成果的丰硕超过了以前任何一个时代。从商代金文的著录、工具书的编纂两个方面对商代金文研究资料搜集与整理的历史与现状做一梳理,以有益于今后商代金文的研究。","categories":["09_其它"],"year":2011,"publication":"唐山师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKmFYo2qEvFCCljQcsQiLrSeO0Wxld4Y_ufjWT0lBhw-z9IONYWYj0GI6BO709gNqauLuIvQNYC-8DmO0WjwJi89dF92PpfODW4BLMniG2wYaft8xqJ65SfrD7G-WXGMvqoYfxp5i5VM8zgoGAmDjC2LWh8dydtF_Ve0yUe3b5-SQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"13-16","volume":"33"},{"id":6324,"author":"包瑞峰; 詹子庆","title":"嬴秦礼俗研究","abstract":"嬴秦族是我国境内历史上很重要的民族,秦国是我国古代很重要的诸侯国,秦代是我国历史上第一个统一的帝国。嬴秦人以一个居于西垂之地的民族,在不被当时人们看好的情况下,凭借其强大的军事力量、不同于东方诸国的礼俗一统中国,随后又在短短的十五年内迅速灭亡,这一现象一直为历代政治家们讨论的话题。梳理嬴秦的礼俗对于弥补和促进嬴秦历史和文化的研究,进而推动对整个中国历史的研究都是大有裨益的。本文共有五章,分为绪论、嬴秦礼俗产生的条件和背景、嬴秦历史阶段的礼俗状况、嬴秦礼俗的特征、嬴秦礼俗和古代社会。第一章主要叙述了本文的背景、意义,本课题的研究现状,本课题可以依靠的主要史料,本文研究的基本思路和基本方法。对于嬴秦历史和文化的研究自秦亡以后就开始了,历朝历代的政治家门都会对嬴秦的历史进行反思和回顾。当时真正把嬴秦历史放在学术视野中来研究应该是从上世纪初开始的,尤其是新中国成立后,唯物史观的应用和上世纪七十年代","categories":["09_其它"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJKbkZ6dLy7GjYmE3Y_fR7YlloBO0aupvqmTmyyeIt21RIg7rpzULB999W2LUihi51J9Ss8O-obHZH7gWJLprWCZxLAYwjA7BZtTxe3o_IBZozUlYvtq6a9HxPBPOvgFL0CmUuStIosLno1uU3dGaOuPryybw_fTQz0KDT4lfL2rbAYFdAtOewe&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6328,"author":"牛镭; 段建军","title":"夏周商的青铜器美学研究","abstract":"从历史学角度来看,青铜器是夏商周社会、政治、宗教、文化高度浓缩的物质代表；从美学角度来看,青铜器是夏商周艺术审美的物态化体现。然而将历史与审美相互融合,青铜器则是中国美学由原始的审美意识发展为中国传统美学思想的缩影。春去秋来,体现着青铜器美学精神的传统美学思想在现代社会依然折射着耀眼的光芒。基于上述认识,论文以青铜器本身作为切入点,以美学与美学史的基本理论为阐述依据,按照时代先后顺序,将夏商周青铜器放置于不同的时代背景下,对其造型、纹饰、铭文等美学特征进行分析阐释,揭示了夏商周青铜器基本的美学内涵,挖掘出形成中国传统美学思想的精神根源。论文最后分析了夏商周青铜器美学对现代造物审美与社会核心价值观的影响。论文由此分为以下五个部分：第一章：绪论。简要阐述本论文的研究背景、研究现状、研究目的和意义、研究内容与方法等。第二章：夏商周青铜文化源起的背景。主要分析青铜文化源起的政治、经济、文化等历史背","categories":["09_其它"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJyLkpJoxlc-ITrdqs2KMGOyXesO3_DuzvWCtDl5VeAKHnTVN6PF4u-vqqYt2DRnFzs5DaequWaUOKYPCHDmNVJzam13uQbkz1MsoDwuSLPaHQm1dcCeXvSbRoqRYXlNx68LZivgxPClci85uYsU3ifah4lG7kpdM-nbpcXqtv5EaclqcMBi_P_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6332,"author":"闵胜俊; 谭好哲","title":"战国中山国青铜器铭文美学研究","abstract":"1977年,在河北省平山县中山王陵出土的中山三器铭文以其篇幅长、史实记载清晰受到各方的关注。铭文出土40多年来,对其进行军事、政治、文化等各方面的研究浩如烟海,但遗憾的是,书体美的研究成果却甚少。本文将中山三器作为主要研究对象,旨在对其书体特色和书体美进行研究考察。中山国青铜器铭文作为战国时期文字的重要组成部分,一方面体现了战国文字的“文饰”潮流及战国中晚期文字简化趋势这一共同点,另一方面展示出在多元文化的综合影响下所产生的独特的装饰美感。其中具有“文饰”特征的中山三器铭文,端庄修美,从笔划到文字构形,从构形到字体风格乃至用字都展示出独特风格和独立的审美价值。而大量的“物勒工名”铭文,自由松散,呈现出疏朗风格特征,体现出民间文字普及后“趋急就简”的特点。战国中山国青铜器铭文的艺术风格不仅具有书法创作价值,还为我们展示出身处战国中晚期的中山国人的审美特点。导论部分重点说明中山国青铜器铭文的发","categories":["09_其它"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI2AILSVYC8ugc1YruUDdhg0yAlOz7dt-zjp58gCTmFVf90HgjgovR913I6eEufpAR65__A106Zn9g_G2SbYm7KuOtQsc-VLE-RG-Vrd6SYbX-hk8Cpxt0XFybeX-Sh3jDcD7uwC1eLATK6l-k1yKws5ieDK6z6AEAeXoRs922UfysaZETAIlqX&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6335,"author":"江帆; 黄亚平","title":"图形符号与文字关系研究","abstract":"在中国各地发现和出土的早期文明阶段的各类岩画、陶器、骨器、玉器以及商周时期的青铜器中,存在着多种多样、极为丰富的图形符号。这些图形符号分布广泛,延续时间长,形态丰富多彩,在不同的方面与早期的文字有着多种联系,是汉字起源过程中的重要一环。对早期图形符号与文字关系的研究,对推动史前文化研究,探讨汉字的起源和发展规律,沟通文字学与艺术学两个相互交融的学术领域,丰富汉字造型理论,都有着重要的价值和丰富的意义。本文在全面搜索文献材料的基础上,运用文字学、考古学和艺术学的理论方法进行分析,将论文架框为四个部分进行研究。第一部分,总结了学界在图形符号与文字关系研究方面的成果,提出了本文的理论依据和研究资料来源,确定本文中图形符号的定义。第二部分,在共时平台上对图形符号与文字的关系进行深入分析和探讨。通过对商周青铜器中的图形符号和早期文字金文、甲骨文进行比较,确立它们在社会功能和造型方面彼此对立又相互统一","categories":["09_其它"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHRjzizbKUx-sAuRYeiM9zsKh1weF_CsOLQWMxRsCY72R4-7gIdAskptrRarn57F42cWIkZFzCgJqwJrzZLP5sUlbV96gTVoTCkK17qKceRoMNJ0vWRF9M3SwvYNOoztFg_Ky1vGMpeIalYGw063lnWeaWvDW5srD4xEt0mXtb-_TseuqD8pC7&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6340,"author":"易德生; 徐少华","title":"商周青铜矿料开发及其与商周文明的关系研究","abstract":"商周作为中国青铜文化的发展、繁荣时期,出土了大量青铜器,然而,铸造青铜器的青铜原料来源如何、青铜矿料(即青铜原料的矿源)的开发及产地状况如何,一直是学术界颇为关注而又难解的学术谜团之一。本论文结合近些年科技考古和考古学的成果,综合运用多种方法,对商周时期青铜矿料的开发和产地分布状况做了系统考察和分析,在此基础上,又对青铜矿料开发与商周文明的关系加以阐述,得出了一些有意义的结论。第一章是关于研究方法的讨论。迄今为止,由于商周时期古矿冶遗址发现不多,因此,要考察商周时期青铜矿料的开发和产地分布,面临着很多困难。论文认为,要初步解决这个难题,需要充分利用多种方法。这些方法包括历史文献法、科技考古法和综合性方法等。第二章充分利用多种方法,对商代青铜矿料的开发及产地状况做出了推测。对铜矿料而言,商王朝的铜矿料产地应主要位于中条山铜矿区,长江中游的铜料可能只是少量输入到商王朝,大部分还是供应本区域范围","categories":["09_其它"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKcZ2fca4_2KQBUob7I5U0uJc5aLXVF99Qhddo3Rwc9ZfXruaCrO2s6KaBBX03Dt8xJG5GzXaaXF3c6qVyK0L5dJtehpcMh3RX3rU3YCY-mwMRCPCU_vlnCPPmxVQIqBJCm7TMsd1wN3NInLscKPJzeRenUERQfNk-1cwzrSZ0zNSUVu7saLs4P&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6354,"author":"田芳; 刘宝俊","title":"从玉部字的发展演变看中国玉文化","abstract":"语言是文化的符号,语言文字记录文化,同时又反映着文化。一定的语言文字是一定社会文化的载体,在特定的文化轨道中,语言文字得以发展。汉字作为世界上最古老的文字之一,属于表意文字系统,它是“汉族人习惯以直觉形象的眼光看待一切致思途径的对象的文化产物。”正由于汉字的因形示义,使得汉字具有丰厚的汉文化意蕴,因而,几乎每个汉字都有一定的文化内涵。汉字有部首,从而形成汉字的系统性。部首相当于形符,标识意义范畴,所以每一个部首的全体字,则系统地反映与意义范畴相关的文化。例如,在《甲骨文字典》、《金文编》中玉部字仅有寥寥可数的几个字,而在东汉许慎的《说文解字》中玉部字就收字126个,发展到今天,以玉作词素构成的词语简直数不胜数。从玉部文字的发展中,我们可以想见玉文化化曾何等璀璨辉煌,尽管历经了沧桑变迁,玉文化仍然传承不息。玉文化的变迁在玉部字的增减中得以体现,而内涵丰富的玉文化也能从玉部文字中窥见一斑。我国","categories":["09_其它"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJi3mzsJNZEWDEwXDJd47Zta5BjCNfYM0l9mINVAhWL5TUEmyVs_pl8c3RCMjplGZfro9ml6sNSt0AdgjMGTUCcfOjd9oYP2nIj_glo4b8OD55Z8uz15qjgbRKBRTBJ5xyonHgQHk2v5ZhVDRIZyzxZoZ0LSv0xrOB4Lw0RF3crSRTGEOF4t20L&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6369,"author":"马洪菊; 王冀青","title":"叶昌炽与清末民初金石学","abstract":"叶昌炽(1849-1917),清末民初著名学者、藏书家,学问领域涵盖校勘、目录、版本、金石等诸多方面,并且都取得了极大的成就,该文所要探讨的是叶昌炽所取得金石学成就。该文以时间顺序为纵轴,以叶昌炽在各个阶段的金石学实践活动和成就为横轴,深入探讨叶昌炽对传统金石学发展的贡献以及取得的成就。此论文一共分为五章及附录部分。第一章介绍叶昌炽的家世和青年时期的学术经历。对目前研究中存在的叶氏籍贯的几种错误说法进行了纠正,重点对他参与编纂《苏州府志》和校勘铁琴铜剑楼藏书的活动进行价绍。同时指出,叶昌炽早年学术的致力点并不在金石学。第二章介绍当时的大收藏家、金石学问大家潘祖荫和吴大澂对叶氏最终走上金石学道路的影响。同时对清末民初的金石学发展状况作了详细的分析,从中总结出叶昌炽可能受到的各种影响。第三章对叶氏在京为官期间的金石学成就进行介绍,详细分析他家贫但富藏的原因、经幢拓本的收藏及研究情况,并对他在金","categories":["09_其它"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iINAq57-w2iR6CtaUc6TSk9H3fe3SUrIrULW7_3ORzfbmA0uPgDuoNoOMux-I4FXOzoM-NyAD5N3j6q2iANNP290yG57nRBUOl7e5PH2hEfWEURmA1PRJRXHeyAGf2Y5YOYsPEJi9K5O4cqWwt_wmOsBdQPRLek6cgl8_OCZn7hwBOgXL7hh112&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6373,"author":"郭国权; 李守奎","title":"清代金文研究綜論","abstract":"清代是中国文字学研究史上最为關键的时代,在文字学发展史上估有顯著地位。晚清学者正確韶识了文字的演燮遇程,基本上摆脱了宋代以来直至清代前期的臆测之風,二十世纪以後的古文字研究,正是從这里起步。清代末期的古文字研究,走上了寅事求是的科学道路,是文字学研究史上一個重要的转折點。清代统治者实行嚴酷的文化统治,這是清代以考據为特點的金文学发达的社会政治原因；学術上的遞相经承和科学的研究方法是其内在原因。此外,宋代金文学的成果为清代学者提供了大量的研究资料和实用的研究方法,新出土的青铜器为学者的研究提供了更多的第一手材料,这些因素尊致了清代金文学研究的勃具。晚清甲骨文的发现,封古文字学研究来说有著劃时代的意羲,晚清学者開始利用甲骨文材料,以一种具有理论高度的视角審视汉字的发展和演燮,取得了僳出的成就。清代的金文著錄超遇以往任何一個时期,徒民国初年至今,不断有学者封清代著錄加以整理和研究。清代以收缘青铜","categories":["09_其它"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKvdMbb0v77DL8DjnyVN-MEd47l2uL28yScTiguRZcUeZe4rv3nKe0SoClnXZMXo5BE6d4ga7IC9EO2sCzVS7rYw8bvEvzoTKkTVz8hwV2YDgKfTTEot3lgkbPeRg6ZG3rmub5xXSKJfEYEonukAMIs5i-XqOX0hBzPKMxzHuJsITm688JO57Qy&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6385,"author":"倪玉湛; 张朋川","title":"夏商周青铜器艺术的发展源流","abstract":"本文以夏商周时期的青铜容器为研究对象,详细论述了青铜器艺术的渊源、起源和发展的完整过程。青铜器艺术的渊源是指青铜器萌生之前的史前艺术、技术与礼仪传统,这些因素对夏商周青铜器的产生有着直接或间接的影响。青铜器艺术的起源是指青铜容器产生之前的早期铜器艺术,具体则指以纯铜或各种铜合金制作的非容器类的工具、武器和装饰品等。青铜器艺术的发展包含三个方面的内容:形制与纹饰的发展演化、铸造技术的发展演进以及青铜器所反映的夏商周制度与观念的嬗变。青铜器形制与纹饰的发展演化是最为直观可感的动态过程,其中亦折射出人们追求实用和美观的心路历程。但是,形制与纹饰的发展演化又会受到特定铸造技术以及所处时代礼制与观念的制约,故而有关铸造技术的发展演进及青铜器所反映的制度与观念的嬗变均需加以研究,这样才能更加全面深入地分析青铜器形制与纹饰演变的动因。全文由导论、五个章节和结语构成。导论部分首先介绍了本文的研究角度、意义","categories":["09_其它"],"year":2011,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJhwQYEk5EMjk4kb-HBaOix148qbhLaUfigXZN6T1UYUKmMWs0KdN8Xi6W5xLJUHWviPhEYUihLtpbzh7EjcNx_AzTAEK5LkylPPNjZ8DsYbi_zotiT9fdq3fs9sUr95d5iSDnuq26cUGPkO1FOKJDjjFDA-AIAZw3IYomCWuXdI4hwn0ZQ_oSo&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6674,"author":"孙才顺","title":"吴式芬与金石学","abstract":"海丰吴氏家族,作为清代一方望族而著称齐鲁,吴式芬是其文化世家的典型代表。吴式芬自幼深受父系家族和母系家族渊源家学的熏陶,遂生平汲古邃学,成就卓然,以《攈古录》、《攈古录金文》、《金石汇目分编》、《双虞壶斋印存》、《封泥考略》(与陈介祺合辑)等金石学名著,奠定了其有清一代一流金石学家的地位。尤其他首开古封泥研究之先河,收藏、著录并考释封泥,以封泥文字证史、补史,在古封泥学术史上具有开创性的意义,为其后的古封泥研究创设了范例。","categories":["09_其它"],"year":2011,"publication":"齐鲁文化研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKrcyId_vJKsrcHM8TkMyNZFwkQZzA4kh29hJqg4SqsxRWzvoSzarW8yh06eRAqzioAzTSWgHdpF9BhCb2rUgZX75Kt18uxxGLZTRi7_NvPrziu5r_PnhjR4yp0OeJdDJNjksQhpJaA1_C1M8PBB-fUtUhz6979wa4-B7AhNzTqNA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"313-332","volume":""},{"id":6681,"author":"王伟; 王辉","title":"秦文字的发现和研究简史(1949年之前)","abstract":"秦文字在《史记》和《说文解字》中已经有记录。此后历经隋唐宋、元明清,直至民国时期,秦文字一直是重要的研究对象。本文分先秦两汉时期、隋唐宋时期、元明清时期、民国时期,共四个阶段,对秦汉以来至1949年之前的秦文字发现和研究情况作一回顾总结。","categories":["09_其它"],"year":2011,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK3jaw2COfMpWKfWrv-CxckXJmL4ZjB88n_UdA8iKMv97Q4X1QACdwxgKsFvUY5v3WHjShisnK7KqA8m3Q3G2utVrniWUWgA-bup8b2LxjUTzUw-cBBnJ-IVTG4roHVnlKAzHeQOsRNOIePZ57wk3IMFT1nWN5S9bWwG3FebqFY8Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"65-82","volume":"15"},{"id":6707,"author":"毕秀洁","title":"宋代以来的商代金文研究述评","abstract":"本文从纵横两个角度对商代金文的研究成果进行述评。时代上,包括宋到清末的商代金文研究与20世纪以来的商代金文研究两个阶段;其中对20世纪以来的商代金文研究成果进行了比较全面的综述,包括商代有铭铜器的著录情况、图形文字的研究、商代金文的考释与研究及其他几个热点问题等。并指出,商代金文的研究已经取得了一定的成果,但研究尚不够系统和深入,商代金文的研究还有很多工作要做。","categories":["09_其它"],"year":2011,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIZS1JrYkDmVFV6qPB0MBp0NsZYAtBgGHjRwu8lHgdgPGqQ31pElmkmLXQ_UOXtyrnbI7VIOgkx9OtuBuyyrvcFZxvtd-uk9qQu4BFfQXfT9cy5bdwY2DhVEursiV4_c3YqAZcaNFLTbGn8aOK4tP_nmL5J3FzoTpWR6EAsOgkS9A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"31-41","volume":"14"},{"id":5164,"author":"张昌平","title":"商周青铜器铭文的若干制作方式——以曾国青铜器材料为基础","abstract":"本文以曾国青铜器为基础材料,通过对铭文形态特征的观察,归纳出商周时期青铜器铭文的不同制作方式。除了举证青铜器铸后的刻、錾等不同的铭文制作方式之外,重点讨论了铭文的主要开工——铸造的阴文铭文的制作。文中分析了流行的模作铭文观点如独立范法、皮模法等使用范围的局限性,并以实例说明贴泥条的范作铭文技术应是铭文制作的主要方式。","categories":["09_其它"],"year":2010,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2010.08.009","pages":"61-70, 1","volume":""},{"id":5168,"author":"葛亮","title":"谈谈“小子■簋”铭的真伪及相关问题","abstract":"上海博物馆藏&quot;小子■簋&quot;(《集成》3904)系真器伪铭。本文通过对其铭文字形、辞例的分析,认为该伪铭并非臆造,当有所本,且仿制较精,与真铭的距离不会太大。由于真铭所在的器物未见著录,我们仍可将&quot;小子■簋&quot;铭作为一篇早期记事金文来使用。&quot;小子■簋&quot;铭的时代当定在&quot;商代晚","categories":["09_其它"],"year":2010,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJpMpMXg6zYMSp_UMGTXmXvMGELyFlRJAJeQ9q97ayXEeJGZ1eY-rlWcM3X-Lb_TrE8mAFwQDknUHnfhB-sYZ7Yl5BA-xoyQec_reOKIpRdd23bThQCeeAZWxwFbTxV9a3TP7OZ0DIS1f82pEMxuz2UyaUp2FNCSmYpY-TLsWQn-g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"22-26","volume":""},{"id":5183,"author":"张翀","title":"青铜铭文作伪:雅声外之杂音","abstract":"中国古代青铜器有一个独特现象,就是器有铭文,我们常以&quot;金文&quot;&quot;钟鼎文&quot;称之。在青铜器发现的肇始阶段,带有铭文的铜器就被发现、注意、瞩目,这与中国汉字一脉相承有关。在文人雅尚、玩赏之余,铭文甚至能够脱离铜器而独立存在,宋朝人薛尚功就编过一部关于铭文的著录书《历代钟鼎彝器款识法帖》,言外之意就是将青铜器的铭文作为书法中的&quot;法书&quot;,脱离铜器本身,单独著录。薛尚功首开先河后,","categories":["09_其它"],"year":2010,"publication":"艺术市场","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKpAsvqUsSzknYrcCBXC1GdSB9yZJd5rE_M4c3KAffIcSwvFJTQ8kZQPkMYKKg07TvDERrY2zVdLT3CiFBkN9qdR0tifN5zTu-A6bZG7jbJ08h0AmTfuUlnOVOeqXhe8oA-tsWP49upWWVIJIitB2L9cp3a-zKSNiWEoi3boCUlIw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"62-63","volume":""},{"id":5200,"author":"查屏球","title":"西周金文与“修辞立其诚”的原始意义","abstract":"西周铭文是现存较早的单独成篇的文本,《易传.文言》中&quot;修辞立其诚&quot;之观念虽是后起之说,但其所强调的&quot;诚&quot;应与早期铭文之类写作活动相关,可能就是对这类文本写作经验的总结。西周铭文是祭祀者与神对话的记录,以诚心获取神之佑助是铭文写作的动机,向神展示诚心是其核心的内容,诚也是铭文行文的基本要求与行文风格,故借助西周铭文,可以为这一文论观念作更具体的文化溯源。","categories":["09_其它"],"year":2010,"publication":"学术探索","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLSfCZAdK3WEIbGCH9wZLgN0_r0IqEjkmS2yO7J9QFz3LDC1ldpmT-PB4pdusH7HAIYhKrwZvDgrlDfka1ydYeUs7Xii84j24Q-on0zCsIBKNy2nci5HvJ54K_1d0H8DwcSsjCdFWJ8skUgW9yMh2kKrYdjtzASSbmCj3H0hgjvEQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"125-133","volume":""},{"id":5211,"author":"单晓伟","title":"秦文字出土与研究综述","abstract":"秦文字上承商、周文字,下启今文,从文字学发展史来看,秦文字既是中国古文字之终结,又是今文之发端,是中国文字发展史一个关键的转折点,因此对秦文字的研究就显得尤为重要。对秦文字的发现及研究状况进行回顾总结,使学者能够快速、全面地了解秦文字的出土和研究情况;并对秦文字的最新研究状况、热点及存在的问题进行分析评介,提出了一些看法。","categories":["09_其它"],"year":2010,"publication":"合肥学院学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK87zXVj1OgPGedNEfn5B8Mwbca7_skak-dLMZt8qGaxPHbWwQKtJx35p-speCVd0vEwRAYZWNWqYm_Vt80li1FVGXOMiIkLXWoDXIZdWEnaYdu5MQiOyn4lLXnzl9ojEaNNEX26AoowJeHrTCaCWelOKEcbShmxGn6uvMFAGak2Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"32-36","volume":"27"},{"id":5218,"author":"杨秀恩","title":"春秋金文研究综述","abstract":"春秋金文是历史上春秋时期列国诸侯及卿大夫铸造于青铜礼器、乐器及兵器上的文字,①其使用时期从公元前770年至公元前476年将近三百年。从整齐规整的西周金文演变为异形严重","categories":["09_其它"],"year":2010,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLZPpMhqxOiTptpY1jKk0M66zwdZz3Q7-8JJTVdcDng93vDjab-0cj1zEFrsDL0u6ZEtLAUEahYGPkFQ1w05NaxtrAIwKoVjUXMfU3rCSKdFUHyFtpsqyN5nXhKtRZWmabhwM5aSGOnqZJaH4_9L13hPnHx_MkTjXjnFHXxevUyaQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"69-73","volume":""},{"id":5235,"author":"杨洲; 张素凤","title":"民俗在古文字和古文献研究中的价值","abstract":"民俗是一种重要的非物质文化遗产,由于其保留着许多远古文化的遗迹,因此,它不仅是民族文化的标志和社会历史发展的见证,同时还是珍贵的学术研究资料。本文主要从古文字考释和古文献解读两个角度分析了民俗在学术研究中的价值。","categories":["09_其它"],"year":2010,"publication":"河北学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLfbwebcdNWVqbIPASFL8pPyyjZAofJKCrHFe7uWPEs_xB-eE5feTslv81KFcPjZ6X71dOhQfgVJSS2akeFsiXGA5LNodBZRZEGbz0OWiD3_15ZT2u3vlzIAipiNcvGoZnqdfxiPs_pWR1D5OrwpqGEOn5j4hKLViCXrda5wnb7wQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"143-146","volume":"30"},{"id":5238,"author":"黄国辉","title":"略论“姬凫母温鼎”中的人物关系及婚姻制度","abstract":"","categories":["09_其它"],"year":2010,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ-vh4LuFdE9RYdHzCPiKX5i9kSynzWnq2DuY0gmOqsAibFJuvRRc35_mrEDoR5Kk_F9SlyOVUmrZQq5QFC4QGOoViwn3YKN4EgkhsCljj7EZp5A1Xboy4EByQ8w9Tbo9uSEsCjNurBUzf_uhxZMveJorI69qHJiTv_zpz6OJPQ_g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"173-176","volume":""},{"id":5250,"author":"徐峰","title":"评《西周的灭亡:中国早期国家的地理和政治危机》","abstract":"In the discussion of the fall of Western Zhou, there are two noteworthy aspects: firstly, this book drew in the concept of &quot;process&quot;, making a long-term survey to the development of the Western Zhou, instead of traditional historiography being limited to the political events; secondly, this book interprets the political crisis of the Western Zhou from two sides. Inside, this book was gui","categories":["09_其它"],"year":2010,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKZAVm3GmsXNlwD-wx2MJ6iilZzO6DWHgyowr7r-aAxtzfKdvP4MOWBjraDn86wsIidSYz5tYLUF2ZFOZTcMdn12kFzn-IvfWYfRIeNvqSEnIqMj0qc3-NuraOjDsJX3O04zQ38Wmv_7UAY3r4xFaPcVQxzAYY6yKBHVX5QfeFTfw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"90-96","volume":""},{"id":5253,"author":"臧振","title":"穆王西巡三千年祭","abstract":"2008年是西周穆王西巡归来三千周年。本文主要回答有关此结论的三个问题:一、本文认为《穆天子传》是西周实录而非战国小说家的编造。二、本文赞同贵州大学张闻玉先生的观点,认为穆王西巡时间为公元前994——公元前993年。三、关于穆王西去昆仑山和归来的路线,本文认为不经河西走廊,更不在青海,而是在内蒙居延海至河套一线。","categories":["09_其它"],"year":2010,"publication":"贵州大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.15958/j.cnki.gdxbshb.2010.01.019","pages":"80-86","volume":"28"},{"id":5254,"author":"胡志明","title":"甲骨金文与殷商语音研究述要","abstract":"学术界利用出土的甲骨文、金文材料语言文字材料对殷商语音的研究取得了一定的成就,对殷商时期的语音面貌有了大概的认识。不过,目前对殷商语音的研究还主要停留在对音系的宏观描写和概括阶段,对具体语音发展的微观分析还很少。","categories":["09_其它"],"year":2010,"publication":"福建师大福清分校学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJTr6Phghq3-tPN3IJTxMTX8Pzw-qhrnIF6UABJPptsSGCZm5WvKCpoePOMB_SySpoCIPcFhNimDbQhaYmp5JpR-r-jQ33PzN1BDx9gfYVngi7Ioq3UL25mo2Bk_JRfv4ic9DL66TN12Z5zHATmd7A8puOpl5uL_yyVTYB7ukKlLg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"98-101","volume":""},{"id":5258,"author":"张立敏","title":"《全辽金文》指瑕","abstract":"山西大学整理出版的《全辽金文》为学界提供了很大的便利,但其中下册金文部分在收录、系年、校勘和句读方面有一些瑕疵,主要包括重收和误码、系年错误,文字校勘与考订错误和句读献疑四个方面,对此逐一进行了整理和归纳。","categories":["09_其它"],"year":2010,"publication":"嘉兴学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIGQJGDkb8eqpd3iycq45i94WljJqPALHzJ_NM0EsL08cCmschboUP7NPwBT4qvQ_LWBkgyw1lIHXGCpoZs_BtvBp1sN1S1rQ3dYHXViODrk-8dJJ7QBaZsIK22NeFU0E-Xba53vLji_gcWM9zcKgqwllOZUbZeTVlLWfPGvh17kA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"84-88","volume":"22"},{"id":5259,"author":"樊俊利","title":"战国金文研究概述","abstract":"20世纪以来,战国金文大量出土,其研究内容的丰富及研究成果的丰硕超过了以前任何一个时代。文章从战国金文的著录、字典编纂、分域和断代研究、文字的考释及理论研究等五个方面对20世纪以来的战国金文研究做了一个简单梳理,并评介其得失,有益于为今后战国金文的研究辨明努力的方向。","categories":["09_其它"],"year":2010,"publication":"山西大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13451/j.cnki.shanxi.univ(phil.soc.).2010.01.010","pages":"50-55","volume":"33"},{"id":6388,"author":"姚堯; 吴金华","title":"《春秋公羊传》词彙、语法专题研究","abstract":"本文属於汉捂史専害研究,以《春秋公羊傅》的词汇、语法现象作为研究封象。《公羊傅》是儒家“十三经”之一,是研究上古汉语和汉语史的宝贵藉料。本文较系统地描写了《公羊傅》的词会、语法面貌,並在此基础上造行専题研究。词会研究主要有复音祠、典故词、同羲词、方言词四个専题。语法研究主要有代词、介词與连词、疑问句與疑问祠三个専题。另外,徒藉言研究的成果出发,封以何休《解诂》为首的幾部重要《公羊傅》注释、整理文献中的捂言训词问题造行了刊谬補缺工作,並编纂了《公羊傳》语言词典。本文主要有以下几个创新点：第一、第一次较全面地描写了《公羊傅》这部重要儒家典籍的祠会、捂法面貌,焉汉语史断代和専题研究提供了材料。第二、共造行了七个词会、语法専题研究,每个専题又包括若干子専题。其中能體现新材料、新方法的有：1)在复音词分類中提出句法结構式、跨曾结構式雨种类型。分析复音祠的词会化过程和楼制,並解释不同颊型复音词词会化程","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLzBePrHgyZTULsvWjOVlJMIQn1jAH61kAoFOmGGow6uShpW0-Kh_JG3CyXX1jlrnDylBe7cC7UxEoK7UlOmXsLMHsRw5uJjI6_HmYkHQSJUOlPP8vE6w4E2kCwN7orzcG_S9etobKuI0F7arN_IHeCCowd6UXKWv36j8qgTMDlW2xwe3gWqOAK&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6394,"author":"李刚; 吴振武","title":"唐兰的青铜器及铭文研究","abstract":"唐蘭是我國著名的古文字學家、考古學家和歷史學家，他在青銅器斷代及銘文考釋領域取得了豐碩的成果，本文以他的青銅器及銘文研究為考察對象，主要從以下幾個方面進行了分析研究：一、唐蘭的生平及主要學術成就，通過這一章的分析我們可以知道，古文字學是唐蘭從事時間最久也是取得成就最大的的研究領域，他的古文字研究成果涉及到考古學和歷史學等領域，以他的青銅器及銘文研究作為論文選題有著重要的現實意義。二、唐蘭在青銅器銘文考釋方面所取得的成就和不足，本章將唐蘭的金文考釋成就大致分為字形考釋、詞義詮釋和文句疏通三個方面，肯定了唐蘭對誥、郊、襮、(?)、(?)（夷）、剌（厲）傳等字的釋讀。三、唐蘭與西周青銅器斷代，本章對唐蘭提出的“康宮說”作了重點分析，認為目前還無法否定青銅器斷代中的“康宮說”，肯定了唐蘭對昭王時期銅器的斷代，本章中的西周青銅器斷代比較表可以幫助讀者了解郭沫若、陳夢家、唐蘭等學者在斷代結論上的異同。","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKkBu_f1ehkwthfdyteaTYInEITF3xqIZMrgou-Nk24zokreJIJUMCSWmg5UnSyGr-JqwB_WWwYm21oFiYxCLJflv0Z4yY5C8R6TLRAp3hzR14SbYREdTpoqIq9dhm-xOETFh4dUlR8rN75hVz6poY9ckGiNpM2AUShj1qLgx-IBn40l5kv4gZ7&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6399,"author":"何飞燕; 王晖","title":"出土文字资料所见先秦秦汉祖先神崇拜的演变","abstract":"摘要：本文主要从先秦秦汉的出土文字资料入手,并结合考古学以及文献资料,研究先秦秦汉祖先神崇拜的特点、性质及其发展演变。本文主要分为以下五个部分：第一部分,绪论。首先,就前人有关祖先神崇拜研究的情况进行概述,对研究现状进行总结。其次,论述了出土文字资料所见祖先神崇拜研究的价值与意义。最后,对文中涉及的几个概念予以区分,分析了祖先神崇拜的理论基础,即灵魂不灭思想,进一步指出祖先神崇拜就是中国古代的本土宗教。第二部分,祖先神崇拜的滥觞时期。初步探析了传说时代颛顼以来的祖先神崇拜与神权政治,并剖析了考古资料中所见的灵魂不灭意识与祖先神崇拜意识。第三部分,兴盛期的祖先神崇拜与殷卜辞中体现的神权政治特色。论述了商代甲骨文中所见祖先神在神权崇拜中的地位、商代甲骨文中祖先神崇拜的祭祀仪式。并总结了商代祖先神崇拜的特点。第四部分,主要论述了兴盛期的祖先神崇拜与周代金文中分层化的祖灵祭祀。在这一部分,首先分析","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJwmhSvQ7s6u1JjziPuDR3Ec-5pciJ5srhHDd7RlNqfC7TGrB2MDNdnvB2PtKcb1TYiospwiaUnHmKmdNhIdXtMX1xYY4lhuTJtuCUhbhac66Gb-qxneTJbLIarNvAaqK8JeLHR8R9hnoQOhvN1yNsj2Cz-iUdmShgdmJXGyvzA6xY3EekuMySt&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6403,"author":"李建平; 张显成","title":"先秦两汉量词研究","abstract":"漢語中量詞的存在,形成漢語(及漢藏語系其他語言)跟其他語言相比而顯示出的一大特點,同時也是一大優點。先秦時代是漢語量詞的萌芽時代,两漢時代則是漢語量詞從产生到成熟的最重要發展時期,因此系统地研究先秦两漢文献中的量詞,不僅对先秦两漢量詞斷代史的研究具有决定性的重要作用,而且对於探討漢語量詞系统的产生及其語法化的動因具有决定作用。先秦两漢時代文献浩繁,流传至今的传世文献語料较爲可靠的近一百種,這是我们研究先秦两漢量詞的重要材料；而20世紀以來大量出土文献的問世爲漢語史研究,尤其是上古漢語的研究提供了崭新的、極富真實性的語言材料。本論文綜合利用传世文献和出土文献,对先秦两漢时代的量詞进行断代研究,并在此基礎上努力發掘先秦兩漢量祠發展的内在规律；借鑒前人及时賢民族語言學的研究成果,探討漢藏語系量詞起源的動因。論文共八章。第一章绪論。对百年來古漢語量詞研究的歷史做文献綜述；根據先秦两漢語言的實際使用","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iItRfso2hJxe0MTn0CJBzNc9tgV_0-KpFrGChh2AkmA-a2JDG-HtB1ndKx0oZEwKoxqPCNUtCER2wAEeJsU0BqYBcH3d-Ac037kquvahoYEeBSAmrsWYghJWjDmUY4u-dxT6L2TPbux6uyiF8SPQsvJjt06DBSMBCxRMUTxlvBKVTDKj_bt2J9i&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6405,"author":"谭飞; 程邦雄","title":"罗振玉文字学之研究","abstract":"罗振玉,著名的古文字学家、金石学家、考古学家、校勘学家、收藏家、出版家、书法家。他一生著作达189种,校刊书籍642种。在古文字研究领域,他取得了极高的成就。我们使用计算机将罗振玉相关著作文本化等方法,在全面观照罗振玉文字学相关著作的基础上,系统总结了罗氏古文字考释的方法与特色以及其古文字考释的经验与教训,全面归纳出罗氏对古文字特点及文字发展演变规律的认识。通过将罗振玉与孙诒让、王国维进行比较,设立甲骨文、金文、石鼓文等专题进行讨论,第一次全面、系统、深入地对罗振玉文字学进行了研究。本文共分9章。第1章“绪论”,主要介绍选题缘起及研究的价值、研究涉及的材料、研究方法、相关研究综述等。第2章至第4章是“方法论”部分,包括第2章“据形考释”,第3章“据音考释”,第4章“据义考释”。这一部分总结了罗振玉考释古文字的方法,在归纳考释方法的同时,还随文对其考释中的失误作了讨论。第5章“罗振玉的文字学","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLmCsIHTw80krSrSCwPW3M06Ik6e0zmoTzuJv-8bW_R4AeFylfGMEw9ICz0dn-iS_nE-m107-3Uan7nznypu5vrdS3A1NGdCPlX6Ewfl9bjIvA-8_BKvrMT2MgHkZhNQWLqXHa7_XtqvKadguSpWvrKlGA60NqNfeactwAHMEzXj-1Xr9_t0n7U&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6407,"author":"吕庙军; 陈启云; 张荣明","title":"中国古代政治文化符号","abstract":"周公是研究中国古代思想文化及中华文明史上重要的关键的历史人物。上世纪八、九十年代学术界对周公的研究主要围绕周公摄政称王这一热点问题而展开的。进入二十一世纪以来,学术界对周公的研究倾以格外的关注,因而形成几部有重要影响的系统研究周公的专著。这些研究成果不仅是对当前全球蔚然成风的“儒学热”、“孔子热”等国学研究广度、深度的拓展和继续,也是对孔子之前的前枢轴时代思想文化的追溯和反思。这些思路和运作的意义无疑都是应当得到肯定的。然而,周公研究的课题涉及的方面和领域特别宽广,加上周公研究本身的复杂性,远非是几部著作所能囊括的。本文择取周公研究当中的若干重要专题尝试进行攻疑补缺式的研究,分别从周公的政治身份、事迹疑点、思想文化诸层面逐一展开。论文融合了历史学、语言学、考古学等多学科的研究方法,在充分尊重和利用前人学术成果的基础上,考证和思辨并重,对周公的诸多疑点和思想文化等问题尽可能作出言之有据、合乎","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKuMCkf_QP2_gaZdp63IpS17m4vs50fk71pCA3Zem1nOQE8MLQqsLa_l9jgW09chQWXi_MAoj60brKHolC-RPBMZ7sc5U7CQV_j7tKppStn9rQwuEIb1tyPiw3h107iQTdG0frdjonUNJ8QnVRD31SxrKz2bt6fyOe-JZIxP9QHrxYdQB0tNI8_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6409,"author":"刘红岩; 张世超","title":"孙常叙先生的古文字学研究","abstract":"孙常叙(1908-1994)先生的古文字研究打破了自秦汉以来古文字研究的藩篱,是一门以马克思主义语言学为指导,以词和字的对立统一关系为指导的新的文字科学。《孙常叙古文字论文集》收录论文21篇,是先生古文字学术思想的集大成之作,其中很多理论研究与学术实践方法独特,见解独到,纠前人研究之不足,开后世研究之新风,在汉语研究史上具有开拓之功,在国内外学术界产生了重要的影响,为学界所赞誉。对孙常叙先生学术成就的深入研究有助于后人借鉴其理论成果,掌握新的研究思路与方法,推动古文字学的发展。当前,关于孙常叙学术成就的研究论文不是很多,现有的文章只是对先生的文字理论进行了简单的概述,缺乏较系统较深入的研究。因此,本文试图对其古文字理论进行系统的梳理,对其研究方法进行总结,便于我们对孙常叙先生的学术成就有一个整体的认识。本文的大体框架为：引言部分介绍本文研究现状、目的、方法以及研究范围；第一部分介绍孙常叙学","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLPuIqYiirJ9N48EqQVT62gfWINI4nYXl1ZXi2XKBMq6gT5kwTHmuNbaNUtlBYc9xdi0m5mxA9CHWxHHxX9Kza4GSxS30vCUor-_JrPPL_5n3kcNjKjKo7IwvhjkqshmXcENivPWexJKxe1I8M4voUN3cMyb_YXnRIB9iV-THbZVyMMZ6MLtrMP&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6417,"author":"柳腊梅; 王晖","title":"春秋时期“公”、“私”概念及其范畴研究","abstract":"在中国古代,“公”“私”问题一直是个比较敏感的话题,早在春秋时期,人们就已经对“私”害“公”的行为进行批评。战国时期,随着各国君主权力的加强,各国对危害君主权力的势力都不同程度地加以打击,这种“灭私”的行为反映在此时的法家思想中,并为法家所继承和发扬。韩非子作为战国法家思想之集大成者,从维护和加强君主专制制度的角度,在《韩非子·诡使》篇中明确提出“废私”的观点,从而奠定了中国古代在处理“公”“私”关系问题上以立“公”灭“私”为主的思想意识。本文主要试图从西周、春秋时期的金文材料和文献典籍中“公”、“私”二字的基本含义和使用范围,来分析西周、春秋时期“公”、“私”的概念和范畴,以及西周时期和春秋时期“公”、“私”二字在概念和范畴上的发展和演变,进而揭示出西周、春秋时期“公”“私”关系在社会上的表现,及其在发展中对于当时社会发展的作用。本文共分为五部分。第一部分是绪论,阐述了学者们关于先秦时期","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIkWR8nQ8M4QQvKTdwpTKFaCx491uAUhEBHz8Tgbu5BMtDGVnPy_Sz-2cVvgeSD4vBT5XrT_jbDIpwwcWsjmz8MbCy0Me6yoUQWwywsp026iBPsyu8JUTjIlHAg--QeaWLrFdZD0oSCqAvHOUGIdmoiQodCFbuEy0s3nGXSwb0y4wD9KRB3AVgD&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6420,"author":"马锦卫; 喻遂生","title":"彝文起源及其发展考论","abstract":"中国的古文字资料非常丰富,许多古老民族都有文字。彝文是中国民族古文字中较为古老的文字之一。尽管彝文产生年代久远,但彝文的起源问题没有准确定论,一直受到文字学界和彝学界的高度关注。自十九世纪以来,研究探求彝文起源与发展的论述不断增多,许多专家学者提出了各种彝文起源的学说。但纵观各家之言,都存在一定的不确定、不完整或不合理因素。特别是关于彝文产生年代、彝汉文字渊源关系问题,一直处于争论之中。有学者认为彝文产生于明代,有的认为产生于汉代,有的认为产生于先秦,有的认为产生于春秋战国时期,还有的认为产生于与甲金文同时的夏、商、周时代等等。本文在前人研究的基础上,对彝文的起源进行了比较深入地研究,取得新的认识。论文的主要内容包括：彝族历史文化及其语言文字,彝文古文献调查,彝文起源,彝文的性质和结构,彝文的发展和规范。本文以翔实的材料、系统的理论、科学的方法为基础,对彝文的起源、发展、特征等作出客观描写","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKFxFgDbs1KQo1i3FGX_rbDD5YqFA57OaK91GFCfI8lGzq8MD81WzgF4xsPMcYRQKKO2yFQPd7dwIAXtv9ThnPPYd77XOz95VlS7nkIL0-EauS2D6rJChpej1Y-cFPsQRl7F4Zv93BlLuohm8xPNDa2zNRSs-lc1DktexuWuuBs6QXRMXwV0XJs&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6427,"author":"陈永生; 王元鹿","title":"古汉字与古埃及圣书字表词方式的比较研究","abstract":"古汉字和古埃及圣书字都在人类文明早期独立地实现了完全记录语言的目标,成为成熟文字。成熟文字是通过完全记录语言中可独立运用的最小单位——词,来实现完全记录语言的目标的。成熟文字记录语言技术的核心就是表词技术,即“表词方式”。词有音和义两个方面,古汉字和古埃及圣书字等自源意音文字(还包括苏美尔文字、玛雅文字等)都运用了三种基本的表词方式：(1)从词义方面着手制造文字的表意方式；(2)从词音方面着手制造文字的表音方式；(3)从词义和词音两方面同时着手制造文字的意音结合方式。而这三种基本表词方式的基础是基本字符的制造技术,即基本字符的生成方式。本论文从基本字符生成方式、表意方式、表音方式、意音结合方式等四个方面,对古汉字和古埃及圣书字的表词方式进行了系统的比较,并在比较中注意考察了自源意音文字制造与人类认知心理、文明状况(自然环境、物质文化状况、精神文化状况)、语言特点之间的关系。一、基本字符生成","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKCPwCgGqeS4WajQwipbIjlWdeBeeA0eRWR2CPFEMoUUhv6zbCvC6wL0NTNz8kA4wdsPA9CdYTcQCdu2-dsoX6XgF3UdeVMLsGCJ5QWT-zvorj7j3IY6j3h64MJ5coHAa_U2TH7UIt8wKhax61qFePVQcTjCama68DRkUvBumjk-dwssK3Wi70H&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6431,"author":"黄丹华; 林志强","title":"孙诒让《名原》的文字学理论研究","abstract":"《名原》是晚清文字学者孙诒让的集大成之作,该书对汉字的源流演变及“六书”理论等都做了分析,但不成完整系统。学术界对《名原》一书的研究主要集中在孙氏的古文字考释方法上,对其“六书”理论、汉字起源问题及汉字形体流变问题的研究成果较少。本文试以综合分析、历史比较的方法,对《名原》的文字学理论方面的问题进行系统研究。本文主要研究《名原》的汉字起源观,“六书”理论(包括象形文的分类、转注文的阐释和假借文问题等),汉字形体流变学说(包括汉字发展的规律、变体字、异体字等),并将该书与同时代其他文字学著作进行对比,力求客观评述该书的得与失,为学术界《名原》的文字学理论研究略尽绵薄之力。","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIVClFVnLJok_3B0F4ApdbwosloBiTOs2nXUcrl-HVkx6aDAb9OEBaImyprKPwib2D4uHCN7Ougk-8xwoh8v2__vsNAft4PwPNPW4AI6jwS5Oa_s6kCReV65bZGGyURinfdmg0peh7YuCscaHqV1hgGSzp2VbSsrQszpY_zW2W8xS5B56_f4VDl&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6716,"author":"沈长云","title":"赵光贤先生的西周金文暨西周年代学研究","abstract":"赵光贤先生不是专治古文字学的专家,但于金文研究却颇有所得。作为一名专心于商周史研究的学者,他常常说:&quot;先秦史(研究)方面,由于留下来的古书不多,不够用,必须另辟蹊径,那就是学习考古学和民族学&quot;,&quot;对于史事的考辨,不能仅仅依据于文献的考辨,而且还要重视考古发现的资料&quot;(光贤师著《亡尤室文存》,第6、20页)。这&quot;考古发现的资料&quot;,就主要指甲骨文、金文。特别是他后来把研究的重点放在了周代,","categories":["09_其它"],"year":2010,"publication":"史学理论与史学史学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIVihwT9eCZLlIDyxS-vybA19XEehxnoO72RCeuyf16yzq6IdqXIevvnomGNjzE807lzSbHR_eMtBNiufU_D5a6a6818_8LI-3wBp_BiJ1MGZ81ZVCV7mCF2_uuVQEKNV8o4uPj0rHG7Jeg4HT6EGVsTDxqjW4kntEMrEuqs9mPaw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"120-126","volume":"8"},{"id":6727,"author":"陳致","title":"“不吴不敖”与“不侃不忒”:《诗经》与金文中成语零释","abstract":"两周金文辞例中,多有与《诗经》中语句重合者,学者每以为是金文的作者徵引《诗》句。如师訇簋(孝王时器)有铭文作:&quot;日天疾畏(威)。&quot;毛公鼎(孝王时器)作:&quot;敃(抿)天疾畏(威)。&quot;《诗·大雅·召旻》、《小雅·雨无正》、《小雅·小旻》皆有&quot;旻天疾威&quot;一语,与金文中之文句","categories":["09_其它"],"year":2010,"publication":"古典文献研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLVu6vB9_YdEMYlj0Rq-b2tbacfRsXwhY09oDKM1Ssj2RTQTvf-z9ohlnTMEXwm8mrJp1hZELZ1ASW7LfVJTdZ0oQBTOawXH2V5FKCIK8Lzru08nn5QDh_dgPJq_2XWIBSmGrVU-vIwjf5kPQly0ysaRxk6JvamP_Y7KWisYJMN5w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46131","volume":""},{"id":6729,"author":"杨鑫; 田旭东","title":"早期商人若干问题研究","abstract":"商人是社会发展到一定阶段的产物,是社会分工日益细化的必然表现,它作为一个群体起到中介的作用,贯穿于各个群体之间,通过商业活动把他们有效的连结起来。西周春秋时期,商业有了初步的发展,商人的活动也显著增多。根据史料记载,周代明确建立了“工商食官”制度,这种制度可能在商代就已存在,在这种制度框架下,官商在这一时期的商业活动中占据了主体地位,但其并不以盈利为主要目的,互通有无的基本职能更加突出。这一时期商人多聚族而居、职业世袭,其本身和交换行为受到政府严格的管理,其身份以平民为主,社会地位居于士之下胥徒之上,这种情况到春秋后期开始变化。商人群体从名称上又分为商和贾,二者在功能上略有不同,商以通物为主,贾则居积物卖之。除了世传史籍之外,各地出土的青铜器铭文中有“(?)”字,为我们研究这一时期的商业活动及商贾提供了宝贵的原始资料。","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLK9SigbYcBceVuQdvj56mipxOkSKbB4lnktJy1yWJG_OJBVrlTKL16-DduaPK3GkXvUOdjQxCf9v-Wq0unhcYtlre7Sz8kvs13QJxp27V0Y8VQV0UMj0v6mzclDzuDrN5tEGQvxjz3XwfDMb2B4CEmXxYtVQ46AhwM04fVphOjr2zNRwwWsbmr&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6731,"author":"袁萍; 吴敏霞; 贾三强","title":"许宗鲁家世生平及著述考释","abstract":"許宗鲁,字伯誠,一字東侯,號少華山人,是明正德、嘉靖朝一位在詩文创作、書法、刻書等方面均有傑出造詣的人。本文以許宗鲁為主要研究對象,根據相關文献资料對其生平事蹟及交遊著述考訂,编寫其年譜。因至今尚無許宗鲁年譜問世,故本論文可填補此空白。首先,本文通過搜集文献资料,封許宗鲁詩文集及相關友朋詩文、信件進行收集整理。其次,利用版本學方法,對所收集的各種詩文版本進行版本鍳別,選出校勘底本及参校本。最後,歸纳分析文献资料,按年谱寫作要求,以時間為線,考證許氏世系及其生平事蹟和交遊情況,同時纠正一些文献訛誤。本文創新在於對許宗鲁的著述收集整理最為全面,首次撰寫許宗鲁年譜,以此年谱为核心,封於其個人家世、交遊、著述,成就等方面造行深刻阐述,以期對許宗鲁的研究有所裨益。論文共分為以下幾個部份：第一章、許宗鲁家世及字號堂號考。在其家世后附許氏世系圖,封譜主的世系造行圖樣表示。第二章、許宗鲁著述。凡例：說明本","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLR_cxO11Pcx_X0CN58VN4_wXBcIFllP7oxb-n1c293vraJZb6fsXoLdwzyllu0tU4zvMwW_Gvka9Zp9E3XJy1SvJoGczFx2Z-GJM66t7qiH_Uyjpnmyw04sq1lEubj0-48auBQS9oMBoG94FQ_kXZrUvgEF7sGdP9c-JnJU_oJzOKniwIE-Y-l&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6732,"author":"符丹; 汪啟明","title":"郭沫若古文字整理方法研究","abstract":"郭沫若(1892——1978),四川乐山人,字鼎堂,为著名的“甲骨四堂”之一。郭沫若在古文字研究领域,成果丰富,多有创獲,得到了学界的广泛赞同,他取得古文字整理成果的方法更是得到了众多学者的高度评价。绪论介绍本论文的选题意义、研究方法和国内外研究现状。第二章从郭沫若甲骨文集錄和考释、甲骨文类编、金文集錄和考释、石鼓文研究、其他文字研究这五个方面介绍了郭沫若古文字整理的成就。第三章是郭沫若古文字整理方法的研究。该章立足于郭沫若在古文字研究中的成果,剖析其古文字整理过程,对其方法进行系统归纳,分为考释、辨伪、分类、校勘、断代、缀合六大类,于六大类之下,又细分小类,力为全面总结出郭沫若的古文字整理方法。由于郭沫若的古文字整理方法在以上传统方法基础上有了很大的突破,故该章又辟专节总结其特殊的古文字整理方法。第四章是对第三章研究内容的延续,该章从郭沫若古文字整理中的失误出发,对郭沫若古文字整理方法中","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJMNc4RhG5nIrMLUyXq-iCFT0SK-DtxSTRK7aM-rYIcwK3FLMHqgZDRNtbd2pE6HvSjxxVT-2wh5q5ASSV7_AkDjR_o1ODJk_FILJwz9jUl1u8VJjhgz4tq0oZG5k0Orm0jXR4VKbUmD3gAElVFG76SS1RXgaUQW4g8eHKjpa82J-_m-27JhHHV&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6734,"author":"曾四美; 郝士宏","title":"20世纪以来湖南出土商周古文字资料整理与研究","abstract":"二十世纪以来,湖南发现并出土了较为丰富的商周古文字资料,有铜器铭文、兵器铭文、玺印文字、简帛文字、货币文字等。这些材料对研究湖南地区的历史文化乃至楚文化都具有重要的学术价值。本文全面收集了这些文字材料,并对这些材料做了系统梳理和分类汇释。“绪论”部分简要阐述了湖南出土古文字资料的研究现状。“古文字资料分类汇释”部分按古文字材料的性质类型分节阐述,对本文所收集的五十多件有铭铜器、近六十件有铭兵器、少量的有铭货币、一百余枚玺印及十几件有铭杂器,纵向断代,横向分域、分国,对学术界已有结论加以甄别,吸取正确意见,并探析各类器物之间相关联处,总结归纳湖南出土有铭资料的特点及意义。“小结”部分主要是在综合研究材料的基础上对当前研究中存在的问题,提出了一些初步看法。","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIvt2AS83uXE6xO_cHGRCOdc4_gMI4mm4ciy3ocqdXSPN3iWVPGKi38-ItCrDBCk3uBWAd5kpcuY1YjWiONZQX3la6gEsUK7kkoFC-BbeiZVPTXF4SXzTCB9MNqttTYJ5I26FGAznARHLBLFbk8eGgMvTPC9q8d_iY5XSFIjOGsGNkF1MPP0ke9&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6735,"author":"栾维权; 喻遂生","title":"古汉字形声字发展史简论","abstract":"本文从动态的、历时的角度去研究形声构形系统的发展变化、变化的原因、机制以及它所带来的影响。本文把古文字分为四个阶段：殷商段、西周段、春秋段、战国段,分别进行共时的、不分地域的全面整理和研究。在每一个阶段,先将形声字清理出来,然后逐字进行构形分析,析出声符、形符；整理出其结构布局、结构层次。再将这四段形声字的属性进行对比分析,总结属性的变化,把形声字的发展演变过程列出图表。最后通过研究各段形声字中“行动字”,探索了形声字发展史的脉络。文章结论认为形声字发展的根本动力是汉字表意性的特性,诱因是假借现象的大量、长时存在,模本是会意字的复合结构；形声字发展手段有三：类推作用、类化作用(偏旁化)、符号化；原则有三：必要原则、适度原则、优胜劣汰。影响如下：对汉字的性质的影响、加强了汉字形音义的联系、提高了汉字的能产性。最后得出形声字发展史有以下特点：构形方式反复争夺性、声符形符的替换频繁、结构布局的不","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLtXwNn4b8EMiPNwfDGT53htBO8EuLxofKFWCNsXQtOju1GYvjFFEU9FwCzpeRfqiO8M6mAnwSRclq-qFv46eLKYTUkq9QTPYekxR9kcQBkEzkCIcAhi8mCnc9eJo4epKU3XvKBK5bULF2fP4rE5jJldatw0IlDM1wt5_-afTvy4m_wd9IjGZ0z&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6737,"author":"刘金红; 阚景忠","title":"《积微居金文说》研究","abstract":"《积微居金文说》是杨树达先生考释金文的一部著作,全书收文381篇,说解了314器的铭文。由于杨氏精通文字、音韵、训诂、语法诸学科,熟悉古代文献,所以他在考释字词时思路开阔,考证精细准确,常常能超越前人。对《积微居金文说》一书进行总结与挖掘,不仅可以凸显此书的学术成就,也对考释古文字具有重要的指导意义。《积微居金文说》对金文的考释,既取得了丰硕的成果,也积累了丰富的经验。其中所运用的考释金文的方法,立足于材料与理据,成效突出。杨树达先生在《积微居金文说》中主要运用了据形考释、据音考释、据义考释三种考释古文字的方法。具体地说,据形考释分为形体分析法、比较法；据音考释分为利用古音破通假释字、利用韵脚释字；据义考释分为依据古代文献释字、依据文法句读释字。《积微居金文说》文字学理论部分,主要探讨了关于文字发展和文字繁简的问题。杨树达先生对象形、会意字的分析,以及对文字发展规律的说明,都是通过研究《说","categories":["09_其它"],"year":2010,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK2-5_KKnRnbt6tFJE_mA_w7uVG1O2wH7EIuCa6mzYzOzapatcvNQ7NdBNqC5efRX65F64gjSE92vgICCT4OikxSFUe9ofj2bqd_VhyJ5lwaejb5WO7Cbz2MR26-LTsOg7UbLCu-kqSQ_D4vf06Z-9b7_Uv_mmbHPFkFO-TOFttGYsFpzZWUbIQ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6975,"author":"白淑然","title":"从汉字结构演变透视汉字的发展","abstract":"汉字由图画文字到形声文字的发展,汉字结构简化到行书的历程,都是从汉字的结构演变角度来透视汉字的发展的。实践证明,这些变化是符合汉字发展的内部规律的,所以其发展变化具有一定的合理性。本文拟通过分析汉字的结构演变,对汉字的发展做出规律性的总结。","categories":["09_其它"],"year":2010,"publication":"现代语文（语言研究版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJA15BaRCbAT3qSID4EdCrcIcsYyY_4OChQtlFihTaboT-io6rJegfjgkHGqcN3QC6TagGshQWGkZjn5P01UoKkRlagIRCnIQdmI41rs40aGzUZyw8ngzMiMGWbMGIOm0bVSp_q4lMgdHZvEwH6JpwODqkObG7Uymg8DShdBP6-gYIUk4ELXhfU&amp;uniplatform=NZKPT&amp;language=CHS","pages":"145-146","volume":""},{"id":6978,"author":"艾荣荣; 张飞","title":"说“剑”","abstract":"本文从《说文解字》出发,对&quot;剑&quot;字展开了论述,一方面通过对比&quot;剑&quot;的异体字进而提取其最初制作材料的相关信息,同时分析&quot;剑&quot;与&quot;刀&quot;的异同;另一方面从&quot;剑&quot;的名称及各本文献记载出发,考释&quot;剑&quot;的来源;最后结合文献记载、文学作品及日常生活阐述&quot;剑&quot;的文化意蕴。","categories":["09_其它"],"year":2010,"publication":"现代语文（语言研究版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIIIzZRJdDynyFc_4-QOdoVaSQn-NIlg6JzTxLKrYKOpzUbLkEqNjHL7Nz12Ie7zTyu3UT9rL3DwuvuGaHGrARLwVpsXbsWNYFzdfI6hTDXzEzjocmiYTQPCzRskA0AdlpJy-xDvkyhmzYKTIBZYOdkMQoqS712yLd0edUq5S9mG9J6FwGMMHU5&amp;uniplatform=NZKPT&amp;language=CHS","pages":"144-145","volume":""},{"id":6980,"author":"看云来","title":"金文以及金文的艺术特点","abstract":"何谓金文?答:殷、周青铜器铭文统称金文。青铜器起源于商代早期,盛行于西周。当时以青铜铸造的炊具为鼎、鬲、甗;食器如簋、盨、簠;酒器如爵、觚、觥;洗器如匜、盂;乐器如钟、镈;兵器如戈、钺、戟等数十种。人们在进行祭奠、锡命、田猎、征伐、签契约等活动并铸造相应使用的器皿时,在这些器皿上","categories":["09_其它"],"year":2010,"publication":"青少年书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLv2rZWmKczbcAve9mo-dNQdNba5XUfj9QRfe88li3ocnS_JTnbc2KNzvdOI0e7GOdTGJQNxObDjLOcDbYKf-XCXcg2GTR5EY6OTi7Oa615FQb--O0hy_m4z1_tGUYaMbdjc0lHkD1qzF9Ps7XktKV8PEUANSVYJ68jbYqmwUoXmg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"42","volume":""},{"id":6982,"author":"李朝远","title":"马承源先生的中国青铜器研究","abstract":"此文原为李朝远先生2005年11月16日在台湾大学的演讲报告,题目为&quot;马承源先生与中国青铜器研究——兼论中国青铜器研究的若干问题&quot;。此报告以马承源先生的研究成果为经,以若干问题为纬,对马先生在中国青铜器研究方面的成果和贡献做了精辟的叙述和分析,客观而准确。经由周亚编委整理并推荐刊出,以此纪念马承源先生、李朝远先生——两位上海博物馆重要的青铜器研究学者。","categories":["09_其它"],"year":2010,"publication":"上海文博论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJmHp-uDHmk7h8dH5gzJALw6r9DaI16Y3N6ad3SpopbagdmkxTzEKSfiuQernMc2owLn5xQqL8LK9AYyz0ZCuQAu8TDQ5J6oXDy2kti1qijyC2i-MEw-S3gNe5Ltp2jDCx00ZfHIUIvXemBxpLc_6Q2lyfeQWZFGkUUzXqyhZ9X4A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"17-25","volume":""},{"id":4845,"author":"李金泰","title":"论楚简的书法学意义","abstract":"一楚简用笔画取代了线条,开启了中国书法笔画化的新时代。中国文字的发展经历了三个阶段:图象化、线条化(此系文字学上的概念,与时下书家们的点画线条不是一个内涵)、笔画化。甲骨文金文是线条化的产物,而楚简用毛笔创造了笔画。什么是笔画呢?笔画就是组成汉字的点、横、直、撇、捺(见《现代汉语词典》)。显然,甲骨文、金文是没有笔画的,它们只有线条(见图一)。甲骨文以直线为主,长直线、短直线和斜线,我们看到的折线无非是具有或大或小夹角的短直线而已。这些扁薄平直的线条是无论如何也满足不了艺术对于书","categories":["09_其它"],"year":2009,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIUQbS0OVQyokdjFDA2-XC6_susaQ2ZKTH4KDiTylLjYBElwYzQqDnG6O5xPIyikalIbaf-z8UPfnt7W1Da_P72P05jhvI8ravA_TuwS6APlRTs6hU98c_bn3YyJrCutMvUn84kJ3tc0dZf8_Gi9YaDhnM5sQoC2rEWl2kX-2NBGe4BOS6gUJyd&amp;uniplatform=NZKPT&amp;language=CHS","pages":"31-34","volume":""},{"id":5264,"author":"陈彦辉","title":"商周青铜铭文文体论","abstract":"商周青铜铭文的发生以青铜器制作技术的成熟为前提,&quot;铭者自名&quot;的思想是商周社会人们更加重视铭文价值的重要原因。青铜铭文的体制因铭文记载社会生活内容的不同而体现出不同的文体特征,其歌功颂德的价值取向与文化内涵直接为秦以后铭文所继承。后世铭文虚化、纯文学转向使得座右铭等次生文体的出现成为可能。","categories":["09_其它"],"year":2009,"publication":"文学评论","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ58oMS5F18a9B89iZd5CJAICriw3crkkJrIYwdPaQoF7aSaFao_Biq8jmlNZjuX0r-0QbulW4BO4cGi8tW95y9qarZsHJyZAMpAlgxsUU-42THOkhSPOJvLToBctnecTdpul5DmtkYtSB-h6bZdDrbvCihfrpTszldpzwHz-c49A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"80-83","volume":""},{"id":5269,"author":"张玉金","title":"出土文献与上古汉语虚词研究","abstract":"出土文献具有保持语言原貌、时代地域明确的优点,研究上古汉语虚词时,应以出土文献为基本语料,以传世文献为旁证,这样会在上古汉语虚词研究方面得出更为可靠的新结论。","categories":["09_其它"],"year":2009,"publication":"华南师范大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iITQlpfQWrqMCexZ7sly79A_dXKOsQegoD3w9POvS8MQcB2T1Uz7czLUBdzHdj4q8an5yXALDG-9MtdRyb3dqzlk5Ujs4A5_ZPLuDYnu0tcupjJKhCClus-b-1Zt6SBu0zzs8xr6_mNLvCPnIylCLvoo1QgnO2tZJ4pae_fI3tZOw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46-50, 158","volume":""},{"id":5282,"author":"连劭名","title":"金文所见周代思想中的德与心性学说","abstract":"根据西周青铜器铭文的记载,中和与至德是周人伦理学的核心,《师才鼎》铭文中记载了七种德目,反映了当时伦理学说的发达。周人的&quot;敏德&quot;即是&quot;善&quot;,指仁义礼智。《师望鼎》铭文中关于明心的记载属于心性学说。","categories":["09_其它"],"year":2009,"publication":"文物春秋","link":"https://link.cnki.net/doi/10.13635/j.cnki.wwcq.2009.02.003","pages":"46343","volume":""},{"id":5284,"author":"张新艳","title":"试论古文字资料在古音研究中的重要性","abstract":"古文字资料在古音研究中有非常重要的价值,表现在以下几个方面:古文字资料为判定形声字声符提供依据,古文字资料可以揭示形声字声符的来源,古文字资料有助于古韵部关系的确定,古文字资料为细化古音分期提供文字基础,古文字资料有助于揭示古音中的方言差异。","categories":["09_其它"],"year":2009,"publication":"社会科学论坛（学术研究卷）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKLMuGVYf3LdV7_VfbMTLqe-A2utdaD2vtpmbzw3KWkfuIUcOAbzu4ePnzcHcjnjoVo2UlVeYpqA__5NzhtBNfqd8lx-t2-DB5RwJ76iedVqFtjUUc-oHj1jYLPRPXGiq7vnjkm3MxvrNaACAUhvl-cAuw0ocQxj7uD_qiz25NW0Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"164-168","volume":""},{"id":5296,"author":"陈彦辉","title":"“子孙永宝用”:商周青铜铭文不朽之思","abstract":"商周青铜铭文是研究商周社会思想文化的重要历史文献,内容十分丰富,其中蕴含着时人对不朽观念的认识和理解。铭文中经常出现的固定用语&quot;子孙永宝用&quot;,表明商周社会不朽的观念已经深入人心,春秋时代出现的&quot;三不朽&quot;思想为不朽的含义做了明确的界定,商周社会人们用自己的行为实践着不朽,把不朽作为个体超越生命的永恒精神追求。","categories":["09_其它"],"year":2009,"publication":"北方论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJKiN_HVvBr-lDYCQesAFpt5bzVg9avZgElPfdEBgrxBDzvxKI-j6slIEmaneRJEBIH4TO8X8mfAqnfOcIcYTl8HICA9FbYKjfy5xnHgZNjJlkuVE3MzT5eYvmcfxsDAP19J6PeJDoKXJF68sVxK7CQAOom5qsqShhlK4B80mRTog==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46025","volume":""},{"id":5299,"author":"李义海","title":"郭沫若西周金文修辞研究及意义管见","abstract":"文学名家郭沫若先生研究西周金文的一个突出特色,就是以中国古典文学的创作论为视点,通过与铭文制作人进行古今沟通,从整体上把握铭辞的意义,继而自上而下地进行词语的训释。在普通话语境下,面对不可完全再现的历史语境,整理归纳西周金文的行文格式与表述习惯,对于丰富古今沟通赖以存在的前提并进而提高古典文献释读的可靠性,有着积极的意义。在郭沫若先生西周金文考释成功范例的背景下,这一探索的意义将更为凸显。","categories":["09_其它"],"year":2009,"publication":"信阳师范学院学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKiJmI9Hz5e-48ahwsqvoQCgKF3IkJHpXxM3SfupQIh-OLsJsWbkplhDxIVvMGJeaEB2LcfhX-L_19dmiON3dRDrZr1c0XfJV3N0ztxMmNYbR5wg8UaOAnN2Q3b7mdjLA1ai3AgxWXqyfjR9cjP_ds-XriSQ3B3y5r1SqJSE2_e2w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"83-86","volume":"29"},{"id":5303,"author":"李学勤","title":"李学勤谈青铜器青铜器入门之三","abstract":"青铜器研究既然已经形成一个重要的学术领域,有着相当长久的历史,自然积累有大量的文献和材料,而有关论作又正在与日俱增,其数量的繁多,早就使读者目不暇给。上个世纪,胡适先生等曾编写&quot;国学最低限度阅读书目&quot;,这里仿其先例,列举一批关于青铜器和金文的最低书目,或许对初学者有所帮助。","categories":["09_其它"],"year":2009,"publication":"紫禁城","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLJsHyeMzit7QewfhHu3hCiQwHNYGWKawhXdAguyFZspGpD02dOm98CAcR7WbSmGEgFUuPSVl9A4BA4WoTxbP5kgLzTUWrIDyBQx1kdLnWky90uBvGVLMAASs2zY6myX8VZzGeOFKs-JDZtFmNDgc-A7YIWNYF3yk3M-9spFOyWKA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"64-65","volume":""},{"id":5309,"author":"刘晓","title":"万松行秀新考——以《万松舍利塔铭》为中心","abstract":"万松行秀为金元之际北方佛教著名领袖,属曹洞宗传人。学界对其研究虽然很多,但很少关注记载其生平最原始的资料《万松舍利塔铭》,本文即系在此基础上对金元之际曹洞宗及万松行秀生平的再考察。","categories":["09_其它"],"year":2009,"publication":"中国史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJZ_IsNVAP_JXRCnTdJKrWSoRtd5tlv8LvSCZLj0aPUVyZOF2dH-Z5ubo4iejObHSEgzamL8Nt3hrKUV_HW-RBp2kGzWq9XLtcp7xUyut8n5mvXKcmJdj9uCN0G-IH3jh65S9YBTqHIBKaAcm8o4xuMpVVB2d6cdnFDjFHcA-nasQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"123-130","volume":""},{"id":5325,"author":"吴艳娜","title":"《原本玉篇残卷》言部中的相关文字现象","abstract":"本文侧重于《原本玉篇残卷》言部中除古、籀文之外的其它文字现象,其中异体字数量最多,另外有通假字、古今字、传抄中的讹误字等,这些珍贵的文字材料对研究文字学,特别是对古文字的考释有不可忽视的作用。全文用不同时代的字书对这些文字现象进行初步探索,并上溯到甲骨文、金文。","categories":["09_其它"],"year":2009,"publication":"和田师范专科学校学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJBysP4P_nT3Tf0oGJVFAk0yNfChdG0iakuQsH7k9yBj8DgS8vhDBGc74yTKN4AG0WN2rj7ZoV-Z6k5XjJ9uUWaCUiscBnPrnF3WBMyKQx0Pn6J3O8la7z0YbWUfynsZKbzkGDt4Q1LAiy0B0rl16-8pDSyG08PKJzjQkgAWyCf6g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"63-64","volume":"28"},{"id":5337,"author":"董文强","title":"浅说殷周青铜器铭文及其风格","abstract":"殷周时期是我国青铜器极为发达的时代,青铜器铭文除记事和美化作用外,宗教功能也不可忽视。商中晚期金文的书写还不算太成熟,西周时期可分早、中、晚期,代表性的有大篆金书的&quot;四大国宝&quot;,东周时期铭文书写地域特征明显,可以以地域来讨论其艺术风格。本文将对这些特点作一简单探讨。","categories":["09_其它"],"year":2009,"publication":"黑龙江史志","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ2zLiThDykGi41JAVDpf2RFy-rjOrjQ7WNOMTcGA1vTYHp5IiWYj5LaGbnOQm5dbBf5DQSXqg6JO2iEzi_MExZp_TI5eCXiGWQjHEv5Zwcyy8RnKQJ0ttShpIYaEGQs9jcPl0--dxlj9jhEb2fTs1Zi7y4POllvHrAjjis2NUdBg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-21","volume":""},{"id":5340,"author":"陈文敏","title":"发现华夏第一史册——古汉字“六步相生”造字方法的“记史功能”","abstract":"阐述六书不是汉代学者根据秦篆体系总结出来的;而是商周学者根据甲骨金文体系总结出来的。六书是一个&quot;六步相生&quot;的造字程序,该程序既是&quot;六步相生&quot;的也是&quot;六步相释&quot;的,从而实现了甲骨金文体系独特与绝妙的&quot;记史功能&quot;。无论甲骨金文是&quot;渐创&quot;的还是&quot;突创&quot;的,其中的&quot;六步相生&quot;机制是客观存在。","categories":["09_其它"],"year":2009,"publication":"图书情报工作","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ6mmAUdo8gYYavMlqOOeopxNRxKvrbYjbjihfO5RTx3QmOrAmoTDivootsMPLzcXAHLxiEzL9Dlxg6DManyQjicebZrA3HaTTAN414eQv_EVrGYv8rT7f5C9TbhCO1rlO1Lcyp3sHRvVJlIXOFCdm8BxF9hmp-Yn3c0kMAahdsPA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"167-172","volume":""},{"id":5342,"author":"杨怀源","title":"体大思精嘉惠学林——读《古文字通假字典》","abstract":"","categories":["09_其它"],"year":2009,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKgBfE5xpGVbOtqYjfYHYemiDXURWpyVxpjxZKnrIN4pCGg5AXerUyjY-cpsmBk_hzjIcj1htccop5_XPBfOjNn_BTQ_UarxD1J1o3mGfqJA7qXA1-AX6Q2GXM-S-tHP0A9V5JKGE09tyqsj2Mo1yLkXiweFf7hYo36DOJPY001-Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"104-107","volume":""},{"id":5346,"author":"刘志基","title":"字频视角的古文字“四书”分布发展研究","abstract":"就整个文字系统的历时演变来说,四书中呈直线变化且变化程度较为显著的是象形和形声,前者历时减量,后者历时增量,最终互换了在总字形数和总字频中的主体位置,其字频统计远低于字形统计的增减幅度,更加真实地显示了文字结构的发展速度。会意自西周金文较甲骨文有较大增长后即在字形系统中占据相对稳定的比重,同样体现了正常发展轨迹。只有指事的比重发展缺乏规律,表现了结构发展的某种复杂性。","categories":["09_其它"],"year":2009,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIdkgec5hkC864_LlO9Di5sINiHGx9rSnm-6lpbmRQt2THb-dSsWAZDm24oyPtwOKx7NfOs_4b8rbGU4g6KrVUCrQUcxG6PFPKV-HNRHdztRVGusDauCWSZFjYaBeD9ykqIZ6Gse04BY7XrOEuKiSWgrqr9N571S-97FeYMpiOLEA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-63","volume":""},{"id":5353,"author":"李海英","title":"孙诒让的金石文字学成就","abstract":"孙诒让是晚清著名的经学大师,曾师从张之洞,与章太炎为忘年交,学术上为后者赞为&quot;有醇无疵&quot;,是清代著名的朴学殿军。在金石文字学方面,孙诒让也是成就卓著,主要表现在丰富的学术成果和独特的治学方法上。","categories":["09_其它"],"year":2009,"publication":"菏泽学院学报","link":"https://link.cnki.net/doi/10.16393/j.cnki.37-1436/z.2009.06.019","pages":"106-111","volume":"31"},{"id":5401,"author":"谢尧亭","title":"晋侯墓地研究述评(下)","abstract":"三、晋侯墓地的器用制度1.青铜器、玉器、瓷器、陶器等器物及组合研究李学勤介绍了一件古越阁收藏的晋公戈,认为是公元前837年晋釐侯物[123]。朱启新报道了上海博物馆购回的冒鼎[124]。李学勤认为北赵晋国墓地的青","categories":["09_其它"],"year":2009,"publication":"文物世界","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLuAcDCntJiZ_bEs9-wqJbKQSvdtKuITxI0NuW7vEYlXSnOjSeA2AC2q6RhUTjEqYez1tHIP5Xo4-dhu-fnh1dktuVwD4LEt_2d99zksiXPazJiDV4izDNie_Wbem8IOZKioCIGlGQWZOp9nqo4Ug7cJcFsoIcZiLq5XCH0O95RFQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"19-33","volume":""},{"id":5408,"author":"陈自仁; 杨莉","title":"西北民族大学图书馆藏王献唐题记","abstract":"西北民族大学图书馆收藏有王献唐先生题跋的拓片册页4种,跋文包括对摩崖、古匋器、石刻、砖瓦、泉范拓片文字的识读及评价,内容丰富多彩,异常珍贵,极富学术价值。","categories":["09_其它"],"year":2009,"publication":"山东图书馆学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIWlD9MaA0YRpvoMxPBVlLzCNtjZ9BSRh-WHUWDx5sLyyIeoQ7fkGcu7I294gNYVVhQ4xoFPSFskHde027y_KgSyhYwiJTWbby3Zt2QXAo-bMi6ZaF0Tth5ZNBOjAaYEahzaDuglJCXEsRCY66K9Uo_Hc5k0jejIv4Enpj55YjM1g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"68-71","volume":""},{"id":5409,"author":"李义海","title":"计算机图形学与汉语文献学视野内的豫北金文释读检讨","abstract":"计算机图形学使人们目睹清晰的青铜器铭文(通过拓片的图像处理)成为现实,为铭文研究提供了很大的方便。将这一便捷条件与汉语文献学结合起来,对于青铜器铭文特别是漫漶铭文的正确释读有着重要意义。","categories":["09_其它"],"year":2009,"publication":"开封大学学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKpoiNXYDPUtDBV5_4rFBhzUJtYY_-6DevLwb04v5XJEkyV9SZG2LicPKkwYqF1dH1sqXVnk205BPIJabbdRXlnnW7SuhXN593FMsyOU8G4qkEavt15K2-0Vej3o-xjerh0GhLRXQKAYKcFDGKSy_eEEgqrNsH2_jORghvRCtKmqg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"49-52","volume":"23"},{"id":5410,"author":"张仁杰","title":"汉代记重、记容铜器与度量衡的关系","abstract":"战国至两汉铜器中,有一类刻或铸有表示自身重量、容量或尺度铭文的器物,我们称之记重、记容铜器。西汉时期的记重、记容铜器最为多见,器形又以鼎、壶(钫)、灯为主。它们不同于政府发行的度量衡器,但有时也会在日常生活中充当度量衡器。记重、记容铜器的铭文无疑是研究度量衡制度","categories":["09_其它"],"year":2009,"publication":"福建文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKpoiNXYDPUtDBV5_4rFBhzUJtYY_-6Devh33QsjwbhuMZ7jZ03LTCEX87dMdppcQtSCLF2ZbAKrnPHB__bDFHRNn1W8LJvkyj9bAZiFR0LcJAtaWvbpRtiOai3B3DRWE1Ol_rHZKxU0sXSVpxQilKJn8y8N1tosh6JwwenLYuRRQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"56-59","volume":""},{"id":5412,"author":"刘志梅","title":"略论《商周古文字类纂》","abstract":"郭沫若先生是我国20世纪杰出的古文字学家,著述颇丰。他1944年于重庆编纂了《商周古文字类纂》,集甲骨文、金文、古玺印、石鼓文等为一体,为学者提供了学术研究的便利。但字形摹写有失真之处,释文亦存在一些问题。","categories":["09_其它"],"year":2009,"publication":"郭沫若学刊","link":"https://link.cnki.net/doi/10.16142/j.cnki.gmrxk.2009.02.013","pages":"29-33","volume":""},{"id":5413,"author":"侯书勇","title":"郭沫若金文古史研究的成就与局限","abstract":"本文从考据性研究和阐释性研究两方面,对郭沫若运用金文资料探索古史所取得的成就与局限试作述评,以窥其古史研究之一斑。","categories":["09_其它"],"year":2009,"publication":"郭沫若学刊","link":"https://link.cnki.net/doi/10.16142/j.cnki.gmrxk.2009.02.016","pages":"37-44","volume":""},{"id":5420,"author":"","title":"学者眼中台北故宫的“中华十大国宝”《散氏盘》","abstract":"散氏盘之所以珍贵,说白了就在于它的字多。共三百五十七字,记载了西周晚期的土地契约。造型与纹饰均呈现西周晚期青铜器简约的风格,文字线条宛转灵动,是研究西周金文重要的材料。这个国之重器成为人们得以研究商周时期历史的宝贵钥匙。","categories":["09_其它"],"year":2009,"publication":"中国电视（纪录）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJrGPOuLofXLY4SuNUigiW7-gVK-mZDT3KLjHQkuEiFhIXjWFhM40gWz2DiqhnRzxjIrGjHX2Ua7FxWmNXBWPHgvOZ0NvDILd0exrWgbOF5g4ydXXuse1ceTfUe4arma8AKLS7DvWemtBXlp4AWNY0is0amGVTnJQg4AC-7oZ8Iww==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-60","volume":""},{"id":6438,"author":"彭珊珊; 高兴","title":"山西出土先秦青铜乐钟的艺术学研究","abstract":"本文是一篇隶属艺术学音乐方向的硕士学位论文,其意在于借收集整理、分类归纳山西出土先秦时期的青铜乐钟,通过对其时代形制及其测音、音列的分析,来探索我国青铜乐钟的起源发展,试图寻找山西出土先秦时期青铜乐钟的工艺学、乐律学方面的特征,及其体现出的音乐观念的探索。我国对青铜乐钟乐器的研究最早可以追溯到北宋年间。当时金石学兴起,各界学者对青铜乐器的研究也逐渐开展起来。1092年由吕大临编著的《考古图》便是当时最早涉及钟类乐器的一本学术著作。著作中他具有开创性意义的把钟类乐器当做历史资料研究,开启了对钟类乐器的研究与探索。现代考古学兴起之后,我国发掘出土的钟类乐器逐渐增多,音乐领域中对钟类乐器的探索也进入了一个新的时代。60年代始,李纯一、杨荫浏等学者先后对钟类乐器进行了音律、形制、悬法、功能等方面的研究。1978年,黄翔鹏先生宣布发现了先秦编钟“一钟双音”现象,在音乐学术界引起轰动,将对钟类乐器的研","categories":["09_其它"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLx_zMH49DR6haD3LVmBE3C8W0_qiDznRGMNPQLgMC4vknmgEsC_BcWsF-ygonoamC8QwSyD49QzrIBw8WECRC07GGDY9cRAYdKoDyN1XFiVcXz-fMaQtzB7h7oFSvLM7lzdQXiU3yVwc49ZTfkw60XCR67VnURx4FSVzX9W7NAxycHbbWM0wM9&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6439,"author":"佘玲珠; 秦颍; 董亚巍","title":"商晚期圆底簋及西周早期方座簋的范铸模拟实验","abstract":"中国青铜时代铸造的青铜器主要是采用范铸法生产的。然而,对于古老的青铜器范铸工艺,至今仍没有树立起大家公认的框架。但任何器物铸后只要不经通体加工,一般都会在器表留下各种特征性铸痕,这为后人解读、复原其铸造工艺提供了可能。万家保、华觉明、谭德睿等曾复原试铸了鼎、觚、爵、斝等商周（西周）青铜器。他们的研究工作取得了一系列建设性的成果,但因实验条件、材料及视野的局限,有一些研究尚不尽如人意。如,用来翻范的模的制作,究竟是“塑制整模”“还是“分型制模”?如果是“分型制模”,怎么分型?范面的纹饰来自模,还是在范面直接制作?如果在范面直接制作,又是怎么制作的?同时,其范铸模拟实验也不是完全按当时可行的材料及青铜铸造条件进行的。董亚巍、何薇等依据商早期青铜器范铸工艺条件,开展了商早期斝的范铸模拟实验,成功浇铸出与出土器物范铸特征相符的铜斝显然,其从零开始,用泥料“分型制模”、“分模制范”、“芯盒制芯”等","categories":["09_其它"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJHH5YLTRVIGG6sKHGJVVxDGSxEb_9GlHjEFnBpsY-bzjcqjo_gWr6zS-jrjP2utDdHZ9WO12LxEpp5Oa5DHytt63pxKd1KbgSeWiGU1lRVGv70rJjQ-JrejEzDXfHRfJMLDM7djuS9b_6gjTCfUJK-mo-TQDgOW9zLjAcCqWwYU3ztdFLWHP13&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6445,"author":"李义海; 许嘉璐","title":"西周金文修辞研究","abstract":"本文对西周长铭金文所见修辞格式进行了系统性描写，连同“引言”与“余说”在内，共呈列十个部分，约二十七万字。基於对汉语修辞史的宏观把握，通过对前贤关於先秦汉语书面文献修辞格式的整理，本文在前辈学者关於西周金文修辞现象所做的指注或者考释的基础上，对二十世纪九十年代以前出土的西周时期五十字以上长铭金文的修辞格式进行了全面系统的描写，发现修辞格式近五十种。在此基础上，依据所见修辞格式之间的关系，缀为七个部分：字词句篇修辞、简明省约修辞、繁缛複沓修辞、错综律整修辞、情景再现修辞、敘事插说修辞与人物称谓修辞。西周长铭金文修辞格式的梳理，不僅有助於汉语修辞史研究的深入开展，而且有利於探求汉民族的思维习惯与表达模式。同时，这种实践，对古文字资料的释读，有可能会有所帮助，因为此前古代汉语书面文献修辞格式的整理对於阅读古书的意义已经有了学人的共识。基於上述认识，本文又呈列对几篇铭文的释读进行的检讨或反思，这就","categories":["09_其它"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKX6tJF9L57tRiKgf0JXXPyNeJCIzO4MuvcXdaitpV841VpIQAijrBFbv7T-RujUJO_xRtt7U33QgsNqYllxscfVn4N9OzeLiILD4s3O3wFVEO-ugzpDUYOM3__xSEtLydiPionL8cjM_Vrw5ZiNwlgOwbTsTCO8rY23WppJQIUH4Mtu8Z3uFeE&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6448,"author":"刘琨; 胡安顺","title":"上古韵部专题研究","abstract":"本文研究的問題主要包括三個方面,即:1、上古東、冬、侵三部的分合問题;2、上古脂、微二部的分合問題;3、上古陰、入聲韻关係考。本文使用的材料包括上古時期的詩文用韻材料和文字材料。詩文用韻材料包括兩周金文、《詩經》、《楚辭》、周秦群經諸子、兩漢韻文詩文等。其中“周秦群經諸子”的材料主要指江有誥《群經韻讀》、《先秦韻讀》所包括的文獻材料;“兩漢韻文詩文”材料以羅常培、周祖謨《漢魏晉南北朝韻部演變研究》(第一分冊)、于安瀾《漢魏六朝韻譜》中收錄的韻讀材料為主。本文使用的文字材料包括諧聲字、通假字等。其中諧聲字的材料取自《說文解字》、《說文通訓定聲》;通假字的材料取自《通假字彙釋》、《古漢語通假字字典》、《古字通假會典》等通假字字典。此外,還採用了少数方言、民歌材料。本文使用的研究方法主要有統計法、韻腳字系聯法、諧聲通假集證法、歷史比較法等。本文的結論主要有:一、從周秦到東漢,東、冬所代表的是同一","categories":["09_其它"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIaZTuKl-DCtFIidJPofP2M45WJYvM8hgQPYyBCn_ItTnTl2NGn6dlnxw_5PH7jb97t_ns74M9iCU0ChzlkyismXVzDxGamg6ATbtOybPbDmaIXeOhPch6Wylu3X4JtrM-ezQCkF06K0CW38lPulg2ZmgLr2K5NjJt0gESAB5IaUYQo-lwx18Bo&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6451,"author":"韩军; 徐超","title":"唐兰的金文研究","abstract":"唐兰先生是中国现代著名的文字学家、金石学家和历史学家,他从事教学和科研工作五十多年,其学前承清末孙诒让、王国维等学者的学术遗风,后领现代学术研究之风潮,在文字音韵、历史考古、甲骨金石、简帛写卷、汉字改革和诗文书法等多个领域都取得了令人瞩目的成就。因此,全面系统地考察、总结唐兰先生的学术成就,对于梳理20世纪相关学科的学术史,乃至于对当今相关专业的学术研究都具有重要的意义。上世纪80年代以来,学界对唐兰先生治学成就的研究逐渐展开;然其集中讨论的领域范围,多囿于古文字学理论及甲骨学,而对唐兰先生研治金文的成果,却迟迟未见有系统专门之研究。事实上,唐兰先生是金文研究领域世所公认的顶尖学者,纵观20世纪30年代至70年代的金文研究史,其中几乎所有的热点和重点问题的讨论,唐兰先生都有参与,且其意见多自成一派,影响巨大。因此,对唐兰先生金文研究的成就和特色缺乏系统全面的梳理研究,必将对在总结前辈学者学","categories":["09_其它"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLz8uhuCauJPov-cfJu1djiLyxzAItRDPQyHRsc43AFpCcmaqqNQHNTHCZKEiehG-2DIQNc_T6rCfcfsbGPqP6EpzawDIAuQ9GTzklEQU7lKOtphLo24w5puF6awG5xKL-vdvaZ8_Pl-31e4ZnwhG4jD1hrMZ3l4o9S0aZIc8LQt7VZwEqDR1eY&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6740,"author":"俞绍宏","title":"试述吴大澂古文字考释成就","abstract":"吴大澂,江苏吴县人,生于道光十五年五月十一日(公元1835年6月6日),原名人淳,因避清穆宗讳改名大澂,字止敬,又字清卿;有别号恒轩、白云山樵、愙斋、白云病叟。六岁(公元1840年)入塾,师从冯云槎(名受祉),十一岁(公元1845年)时,受业于王逊甫(名崧)门下。十八岁(公元1853年)时入陈硕甫(名奂)门下。也曾师从俞樾。同治七年(公元1868年)通籍(得中进士),授翰林院庶吉士,同治十年(公元1871年)授编修;同治","categories":["09_其它"],"year":2009,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxbbvTScVuLyArr-ITUXEUKc0w5gO0BhCvRxxB3B9dyydPbeONRjSGE_H3rj1YrYE5Rh48_yOs9pAfU_G_N1rVnxMDMHGcd9jqeMaqGBtCwLshE6LWCqTAZA-aGSaE4rmFT8xy_6HTHmvJe-S_2vc_uJ4HRZ3IScP4d7YoQL-cqg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"409-413","volume":""},{"id":6760,"author":"丹羽崇史; 近藤晴香","title":"从制作技术看战国时期江汉地区出土青铜鼎——论包山2号墓·天星观2号墓·望山1、2号墓出土青铜鼎","abstract":"一、前言笔者曾经写过《春秋战国时代にぉける青铜器生产体制复元のための基础的检讨—青铜鼎の制作技术の分析から—》一文(以下叫&quot;前文&quot;),此文以春秋战国时期华中地区出土青铜鼎为材料,对其范线形态、加强筋、垫片的布置形态、浇口和冒口的位置等有关铸造工艺的四种属性(attribute)加以分析并对其时间、空","categories":["09_其它"],"year":2009,"publication":"三代考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIZiL_GslvQYlvrghICVCCN3R9_-0fl8wRIXn9TdFohlIMpHZELTpRxA2SKsrN_haLpZ0ZMfeh3o-_LZLO1Tbhwrr9-5F_JpXHXOog1S7KkJlQlvFqw7OpdKp4wcgabAGs0cSWPjg_YUX1izwfc8JaaWnBCTp-xNuyAo7fn53Nx3A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"378-400","volume":""},{"id":6763,"author":"吴凯; 周星莹; 钱宗武","title":"《积古斋钟鼎彝器款识》考述","abstract":"清朝初期,以顾炎武为代表的大儒力倡朴学,至乾隆、嘉庆年间,惠栋、戴震继起,朴学达到了高峰。扬州地处吴、皖交会之处,一时名家辈出,诸如阮元、王念孙、王引之,著述如林。刘寿曾这样描述:&quot;盖乾、嘉、道、咸之朝,扬州经学之盛,自苏、常外,东南郡邑莫之与京焉。遂集北学之大成。&quot;乾嘉朴学的发展推动了金石考据研究,鉴赏文物之风更盛,出现了一大批卓有成就的文物收藏家、研究者和一批学术价值很高的著述。阮元的《积古斋钟","categories":["09_其它"],"year":2009,"publication":"扬州文化研究论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKEyoi6nrnrRpu8gfYY0hiKHZ-wSkKVd2k_CGr3hHpiUXle3kkt0fGHa0o6bwmmQlRAOoZ1K-DHvpP6Rm7BThO8qxhrB8oN8p901x5zfq3KXcSy7qImjeUHiF3qw6egIN-C-W184BmOGz-K1JF6rJ4uPKhP0ZoXTdEDxi8xu2b8sw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"61-68","volume":""},{"id":6769,"author":"朱葆华","title":"古文字考释成果之集成,研究者之津梁——评《古文字考释提要总览》","abstract":"《古文字考释提要总览》将古今中外学人对汉语古文字的海量考释意见汇集起来,以提要的形式加以呈现,要言不烦,读者可以在短时间内了解专家们对某个特定字的各种考释意见。该书诚为汉字研究者之津梁。","categories":["09_其它"],"year":2009,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKgmpJvGl5CyOKmLl_h_-uexawlHYoDjeUIBjPHt5P4sdhvRm7uXKnTzRsFv6fTLUchGRvcnfQvtgNIOya85GA45SzQSRRFK8bCkN5RxZpENTQuB7DyzdSTUqekXTUS8bUjwudBbNsfGcj_l97H23grfOsLPjPcdCzwMnWVD8MuqA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"207-209","volume":"1"},{"id":6775,"author":"谭德兴","title":"宋代金文著述引《诗》论略","abstract":"一、宋代的金文著述与考诸经传宋代的金文著述十分丰富。据容庚《宋代吉金书籍述评》,宋代金文书籍计有20种,分别是《考古图》十卷(吕大临著)、《考古图释文》一卷(吕大临撰)、《续考古图》五卷(赵九成著)、《宣和博古图》三十卷(宋徽宗敕撰)、《历代钟鼎彝器款识法帖》二十卷(薛尚","categories":["09_其它"],"year":2009,"publication":"诗经研究丛刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLPBd1mg-Z2SoXRWao8hCSkcFwvY0FULp5eAVQQRqfxFLhL4ArFlBJ12yglCglY0AHwCq54t8scZWpCwDME0997MWnooqOM3XnF9GLcFp6uiY-qVEfQoGbUt8ONvhRTmbR4MUngK42i1FPhNzSpaf-P5KkYM1nhpT8rDtYjgQRbhw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-75","volume":""},{"id":6776,"author":"劉海琴","title":"金文合文判断方法的初步研究——以《殷周金文集成》所载合文为例","abstract":"从位置上的&quot;一个字的位置&quot;、字数上的&quot;两个或多个字&quot;,意义上的&quot;固定词语&quot;三个方面出发,综合考察《殷周金文集成》中&quot;合文&quot;资料,发现金文合文的判断可以利用字与字之间的间隔,与所在文辞走向的纵横交错,共用、分书、&quot;=&quot;符号存在与否等方法来进行。","categories":["09_其它"],"year":2009,"publication":"传统中国研究集刊（第六辑）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL6dlIAioc-0i620_qyY3F7HWNqajlYWyfJrkwIHvQ-U-j4QJsVSrFLKJJPs6LTwTVX3K2LgE0uH0N9Sn7JB5sBXKkC1wkctzIcgG5uH9ziZpUVmOnHIpvdTApl8YuyuRn2IVwkqCMIYOwGpV07c_MzOtN-pHpmGUct6Cymrj7w-CtiunPs67QW&amp;uniplatform=NZKPT&amp;language=CHS","pages":"13-28","volume":""},{"id":6777,"author":"程克雅","title":"王国维魏三体石经古文参斠合证方法探究","abstract":"晚清民国初年之际,魏三体石经古文是经学、古文字学、文献学等论究时关注的考释议题。传统的研究,以宋人洪适《隶释》《隶续》之著録启迪先河,历经清儒如臧琳《经义杂记·魏三体石经尚书》、孙星衍《魏三体石经遗字考》,至王国维撰《魏石经考》《魏正始石经残石考》,对考释方法模式的建立可谓於焉备集。本论文擬探讨的魏石经古文,系指近世陆续出土,存有残石拓本的文献,是故以出土者为主,从沈曾植与罗振玉在考释方法上的启发、研究资源的流传两方面,探究王国维承继传统学者研究的成果,及其对人接踵而至的著述,在文献释读、古文字合证等方面的影响。","categories":["09_其它"],"year":2009,"publication":"传统中国研究集刊（第六辑）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIxz6hQmM5w5VWh23mhKlmJ3h5lxE1jxdu6wcEAsydvFFxQyH0Msjxsco9WW7WEFlANmW5Ap5epgeyxT3n5LqMHC8bV0QKw4AIIi2ivwRc3OspKoDJC3IWb9UHGR82YxDWrypV90Rj-BhMP3fiUX_7Sr07TI0a68hL7lOsU_KTTFnpBr0q7xZSt&amp;uniplatform=NZKPT&amp;language=CHS","pages":"368-388","volume":""},{"id":6778,"author":"万大卫; 毛远明","title":"贞观墓誌校補及研究","abstract":"唐代墓誌釋文,散見於各書而且校釋水平不一,加上墓誌本身的殘缺、泐蝕都給釋讀带來了不少麻煩,釋文免不了出現錯、訛、漏、缺以及標點失誤等現象。目前對某一具體時期的墓誌進行整理、研究的成果還不多,因此我們對唐代貞觀時期的墓誌進行全面的整理和校補。我們首先將散見於各書的墓誌釋文收集起來,再利用所能見到的拓片逐字進行校勘。所有文字的討論都提供實際圖片,以圖文并現的方式對原釋文的錯、漏、標點等問題,都一一更正錯誤、查缺補漏。最後對原有釋文在校勘中出現錯誤進行專題研究,分析其錯誤的原因並總結校勘經驗和方法。","categories":["09_其它"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLAJFYLfmpPtPmPyzipCNkPr_yqCOIElUBW0bDRat48Lbm3HnSiSwkKwpeNqhcmenwOfTwPRU-JWLxuSmz-GcviNUX2riMzy4kwSoMgFuw93V6rf_sanKHJAEm0IHLRl2AkrzPF8ukPcuuU5A72NbFNfQN2nm7aS9uy1j8cENrLq9QkO0yucTxg&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6779,"author":"霍文杰; 喻遂生","title":"上古汉语“在”词性研究","abstract":"“在”早在甲骨文时代就已经大量出现,到现在为止都是一个常用词。但是对“在”的词性,语言学界一直以来都有不同的看法,有的学者认为“在”在先秦时代只有动词的用法,其介词用法产生于西汉或者更晚的时期;另外一部分学者则认为“在”在先秦时代就已经兼有动词和介词两种用法。那么“在”语法化的过程和细节究竟是怎么样的呢?介词和动词的区别及鉴别标准是什么呢?这些问题的解决对汉语语法史的研究有重要的理论价值。全文分为五个部分,一、绪论,即前人的研究成果概述;二、甲骨文“在”词性研究;三、金文“在”词性研究;四、上古传世文献“在”词性研究;五、“在”的语法化过程。本文选取上古时期的多种文献材料(甲骨文、金文、传世文献)为研究对象,考察了其中出现的“在”的使用情况。通过对“在”的动词和介词用法的分析,我们得知,先秦时期,“在”在词性上仍然是动介兼类词,动词的用法更强于介词的用法,但是不能否认“在”从先秦时期就已经","categories":["09_其它"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLAJFYLfmpPtPmPyzipCNkPr_yqCOIElUBW0bDRat48Lff1LLc0N-rYNJX_Ks_fLm6GdDDNf8js3uQkGQhsbv-IboyzbiCzUG9UjHOU0ZI0DblGGnpmDH64ZcUhxlucoX67SnvoTa4-ve4_yW4gimCdWHBX7DTSafwOk19JBy8yoOES34pUkNvA&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6780,"author":"杨巧琳; 潘玉坤","title":"居延新简语法研究","abstract":"本文以专书研究的方法对目前已公布的居延新简材料进行语法研究,着重对其中的句式句法进行梳理、分析,以期丰富和加强居延新简明显薄弱的句法方面的研究,全文分为四章:第一章绪论。主要介绍居延新简的出土、整理情况以及已有的研究成果,说明课题的研究价值和本文的研究方法。第二章单句研究。本章首先以能否划分出独立的主、谓语将新简中的所有单句划分为主谓句和非主谓句两大类,然后再对两者作进一步细分。新简的主谓句又分为动词谓语句和非动词谓语句(包括形容词谓语句、名词谓语句、主谓谓语句)。通过考察发现,新简中形容词谓语句、主谓谓语句的数量不多,情况也不复杂;名词谓语句有名词语和数量词语充当谓语两种情况。动词谓语句作为主谓句的主流,在新简中使用频繁,谓语动词数量多、种类杂。虽然新简语料在记事上具有程式化倾向,但动词谓语句仍有多种表现形态:无宾动词谓语句、单宾动词谓语句、双宾动词谓语句、动补结构谓语句、兼语结构谓语句","categories":["09_其它"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iINJWln3b8EK1urwXOuXlhcbHG53xKiFFMBefY9ZG4rvcZBu9ruovZecz7LVcwy_dsx1J3Vgx2snYhRy9OKz0Hxgh07buPCW4DK8EDU78cjmhqjtEBJal-myVLLunwU3sPX3l6Gs2kTqTaOgOsvyIX6IQQdoGaleUFhkHuUggbPhVXFpXwYbdOV&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6782,"author":"葛学港; 张金霞","title":"杨树达古文字研究","abstract":"本文主要以杨树达古文字方面的学术成就为研究对象,通过理论和文献实例的结合分析,系统地总结论述了他在甲骨文、金文等古文字方面的研究成就,并对他的古文字考释方法理论进行了一些探讨。全文共包括四个部分。第一章,叙述杨树达其人及其学术贡献。首先对杨树达的生平进行了简单介绍。杨树达(1885—1956),字遇夫,号积微,湖南长沙人,我国近现代著名的语言文字学家和史学家。早年受学于朴学大儒.在传统小学方面基础深厚,又加之留学日本,学习了西方文法学与语源学,故而能够学贯中西,形成自己独特的学术风格。他被认为是当时有重要影响的学者之一。其次,对杨树达的学术成就进行了基本概括。他毕生沉潜学术,勤于著述,在文字学、语法学、修辞学、甲骨金文学、史学文献学等方面均卓有建树。第三,概述了自二十世纪九十年代以来,学术界对杨树达学术的研究情况。二十世纪九十年代初期,曾有一些学者研究并发表过一些文章,简略地介绍过杨树达的","categories":["09_其它"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJdYGbztMoh1GA1KlvN3harZHoM5rBxkSSAFCO0kCGIEP1jBDhi0fTIJpcvQZa0nHRkRGNWFamjh1Cq8yyEcH-h5HIgvL3mwXOJHbYOriRBOvQNZOjPa8_qw3M5wqYOJwCJblOoSP6y9DLmTEd1IRkVNAt2Aa62XGtrVIerCftfTBUSTsCVjt8N&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6799,"author":"暴慧芳; 喻遂生","title":"汉语古文字合文研究","abstract":"合文是汉语古文字常见的现象。合文从甲骨文时代就已产生,直至秦汉时期逐渐减少,最后归于消亡。自宋代金石学的兴盛以来,前人释读彝器的著作中就包含着合文的内容。古文字中的合文经过各类甲金文字典、简帛盟书文字编等专书的积累,材料比较丰富,目前学者对甲骨文中的合文进行研究的较多,对金文中的合文研究不够,简帛盟书中的合文也仅散见于各类文字编,没有系统的归纳、整理,对合文形成、发展、演变、消失过程的研究还不是很充分。系统研究古文字中的合文,对了解汉字发展、演变的历史有比较重要的意义。本文拟对从甲骨文到简帛盟书文字中的合文尽可能地进行全面的、穷尽性的清理分析,统计合文的数量,分类研究甲骨文、金文、简帛盟书文字中的合文,分析其不同历史时期的结构、特点。通过纵向比较不同时期的合文可以发现,合文的发展呈逐渐消亡的趋势,直至秦汉以后渐趋消亡。合文消亡的主要原因是不符合汉字一字一音的特性,通过文字内部的不断调整,合","categories":["09_其它"],"year":2009,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL7_iylMi56aDYF_IBgdt0X6DCS1-bTElWOIHYJaSwXH1BfXbGa8Gov-3H5fub8PUmFGyC9Us924FabPbY1etfSIxyFa5oThIJYokq_4qxqpAGi0YYkl4QguP23kTgFt2uMNlTBtKNVl-YObKI254k5V-mC3G0IKKj5etsMsRbU0eCinIY45_Wk&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6981,"author":"俞绍宏","title":"吴大澂的古文字考释成就","abstract":"清代著名古文字学家吴大澂一生潜心治学,发展了古文字考释方法,在先秦货币文字、古玺文字、古陶文字以及金文的考释方面均有建树。","categories":["09_其它"],"year":2009,"publication":"南开语言学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIED5cG6X9pMSPIMvlTW1R191C01bO9Kzll8zTsVFeDitp0AL3Vq-6rd_WpLR4Ma1keHUygV0EeSsrZ7kq8zp4VMVvfFAum5jb7yfuDX5HH0yb08NNmfHJOQbOunrHyIScuWe5FHVqJzifEvZZcbZoGGaVx6UU6LHPIfw9nGkie_A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"138-142, 181","volume":""},{"id":5438,"author":"杜迺松","title":"青铜器铭文的辨识","abstract":"金文研究属于古文学的范畴,因难度较大,以往也包括在&quot;绝学&quot;之内,现在则有所改变。这主要是因为科学考古事业的发展,提供了有科学考古依据的大量金文资料。前代学者也为后人研究金文提供了理论和实践方面的许多方法,留下了不少研究成果。","categories":["09_其它"],"year":2008,"publication":"艺术市场","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIQXQcFnZe5m05ET81tTXlXaaX-vLndp1XVm6iG_CdAYr7OXH22pRp3wxsHlDL018Uike7Sgec8BDI4Fh7FXiSWQXZcJO1Z7hihxoH8ZAFxbb0gdXrvCaI0eiNumwbWnMcgvUyMEJaWV8HLAbqc-F1785kRq7IjrtDbOkim5ROQ9A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"85","volume":""},{"id":5445,"author":"李晓峰","title":"西周金文语言研究的历史与现状","abstract":"金文语言文字的研究始于宋代,集中于对金文的著录。清人尤其晚清学者开始注重对铭文文字的考释和研究。民国时期,学者研究的范围和深度进一步扩展。对金文语法进行系统研究,尤其是作为一个语言系统进行研究的,是在解放后特别是1978年以后才开始的,研究方向集中于五个方面:一、金文语法研究。二、词类研究。三、句法与语序研究。四、语法史研究。五、金文字典及文选类书籍。","categories":["09_其它"],"year":2008,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKP5mpfyVcAgaE0glD4RvbDBVNlHTAPlHY9BEUQ6lPPmWVUsf6SJnFXTzQjUw1ZXbXi5AwHqAoFw4vNHTN8llCXgcGfdanJM5tPNSEdbBLvyXVwrLJFFtPPj-c14tn7UoaIRry4PvCfYoq5yo3ntUXjqoEzRJY5XwP1hhGEdXCZTw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"83-86","volume":""},{"id":5447,"author":"姚宁宁; 田炳学","title":"《金文编》记号及记号字研究","abstract":"以《金文编》作为金文的研究对象,从填空记号、代替记号、指示记号、别形记号以及记号字这五个方面进行分析,找出金文中带有记号或记号化的文字,进而更加有力的证明了在传统的&quot;六书&quot;说以及后来的&quot;三书&quot;说之外,还存在另一种&quot;书&quot;即记号字。","categories":["09_其它"],"year":2008,"publication":"唐山师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLEMOHlEz1VzNZHG8squRO-QZXNfk39YCwPpLiA6ot5ICRnw8jMmRFx3al1hRKyjDUF-Y_mlwxNVttG94LdPKVifZLaWzzNWNK3Dg8CWk2GBbIwp5Rfa7a6WFXTuQ_yt0G1cwWRuc1qelXMZkk_gbdoc4WTvTEOzc8zF-GCRh24IQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"65-67","volume":"30"},{"id":5455,"author":"彭玉平","title":"关于《殷虚书契考释》的一桩公案","abstract":"甲骨学名著《殷虚书契考释》乃罗振玉所撰,此在王国维生前从无疑议。但在1927年王国维去世后,少数王门弟子以及傅斯年、郭沫若、溥仪等,逐渐由怀疑而遽将此书著作权归于王国维名下,遂铸成古文字学界的一桩公案。其实,王国维在许多文章及通信中都详细描述过罗振玉研究甲骨文的进程,其中颇多对于罗振玉撰述此书的记述,略无隐言;而罗振玉则不仅将自己著作此书前后的心理变化坦陈无遗,而且对其后续增补经过也留下了细致的笔墨。就全书的形式和内容来看,王国维作为书写者和补正者的形象原本是清晰的,但由于罗振玉的政治身份以及晚年与王国维交恶的事实,遂导致学术界故意抬王压罗现象的产生。梳理这段学术含量极低的学术史,对于从一个侧面来了解一个特殊时代的意识形态不无意义。","categories":["09_其它"],"year":2008,"publication":"中州学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKOYT_Vb_7uV69KbhTnCYfhI2kVgs53jeFzDubP2cqGk7NRjRECHkm_QMtKykq8SR_1Fb40gyiZNmXxaLd_GWQ7YD4RkBaqskTB1ZH3XLx8w7T4Qhhu_kiuieBFY6hPOLTP7U0bBnJWtk8_63r5Bo-llYZ7_PuaTliXPtZ9Ys4A2Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"198-205","volume":""},{"id":5460,"author":"李河成","title":"甲骨传统与篆文传统间文化断裂的断想","abstract":"一、汉字文化中甲骨传统与篆文传统的姻缘汉字系统本为源渊长流的系统,只因历史的缘故而使我们的视界出现了局部的断裂。主要体现在甲骨传统与篆文传统之间。甲骨传统即包括甲骨刻辞和青铜铭文在内及其以前的传统。篆文传统即许慎以来的文字阐释传统。当然二者继承关系显然,只因甲骨等虽早存但晚","categories":["09_其它"],"year":2008,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK2hNM1sGHUOJIbaIfAejzegGZupoBXFlE-LtDP4ug1XAkrAyVnftejZBeo0jaBvwucGz1XGejsCsonMqbUqfRczyTmLvJJSUy1mmZs-bAAdJl73WT5V6RJEjmxKMqWvGrqhvjEpgLXORENJx_PDH8HbVkz0ohRJZqOkYzJP9se8A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"91-93","volume":""},{"id":5464,"author":"崔元","title":"浅析金文研究的方法","abstract":"金文的研究对于历史考古、文字史和汉语史的研究有着非常重要的意义,但是传统语言学对金文的研究方法有一定的局限性,应借鉴西方语义学理论,从字形入手,对金文文字做出语义场分析和义位分析,建立起完整的字义体系。","categories":["09_其它"],"year":2008,"publication":"山东行政学院山东省经济管理干部学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLw4nP_N70XSVZQNNK4hi0ZYONsd1MTcIQyFtsCxkEDMqOLNm6p3Ds6cTkpU433GXwhiiT9re-SVxhkP2A018-cx9usmo4z_-VWwOG8KPHYYi1LBFdkWtbxyCHC46GcAOYUXC5clNuYz0BA-224fpIs5UDS9zOecJBcsNfmNagfeQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"124-126","volume":""},{"id":5466,"author":"张长寿; 闻广","title":"闻宥先生落照堂藏大盂鼎墨本跋","abstract":"落照堂藏大盂鼎铭文旧拓本两纸,铭高33厘米,阔33厘米,其一左下方有&quot;闻宥之鉨&quot;朱印(图一),其二印在右下方(图二)。大盂鼎清道光初出于岐山礼村(一说出郿县礼村),同治末,左宗棠以重金购得,转赠潘","categories":["09_其它"],"year":2008,"publication":"文物","link":"https://link.cnki.net/doi/10.13619/j.cnki.cn11-1532/k.2008.10.006","pages":"88-91","volume":""},{"id":5470,"author":"雒有仓","title":"宋代学者对族氏铭文的整理与研究","abstract":"族氏铭文是金文的重要构成部分,其见于商周铜器,大多为作器者的族氏名号。族氏铭文构形奇特,考释困难,至今仍是金文研究领域中的一大难题。自北宋嘉韦占年间,有关族氏铭文的搜集、著录、考释就已经开始。毫无疑问,这是研究族氏铭文最基础也是最重要的工作,宋人筚路蓝缕取得的成果值得珍视。","categories":["09_其它"],"year":2008,"publication":"文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJfgZpb_QoXX5X9dHQobOyXigxGHw0mk4J5wl3Uk8dXVcNxx0nCW77dxEGW2dAw135m-K7LPFAvld-0AumqtUlMO-YNx7slyZCpydPyVPFOt258jxti4Jm6WSEhsmVBaJ8_qyNEVzZNgucCgQ61DBVP3rwrQ58Y5RKrL1wsma3rSQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"119-125","volume":""},{"id":5475,"author":"周晓文","title":"汉字形体关联度模型及计算","abstract":"汉字具有系统性是学界公认的,但是传统的汉字学研究,多以定性的、说解式的方式描述系统,对系统性没有刻画的指标,无法衡量,更无法比较。运用数学的方法从一个侧面定量地刻画汉字的系统性,就会使汉字的系统性在形体关联度上得以计算、各断代汉字系统的形体关联程度可以比较,其系统性通过形体关联度的计算得以量化。汉字个体之间通过构件在形体上产生联系,汉字形体关联度描写的是形体联系的紧密程度,反映的是汉字在形体上的内聚性、系统性。汉字形体关联度对汉字规范、汉字系统优化具有重要的参考价值。中国大陆推广使用简化字以来,简繁之争持续了几十年,通过对形体关联度的计算可以看到:虽然简化字系统对造字理据有所削弱,但从整体上看,简化字系统并没有降低汉字系统的形体关联度。","categories":["09_其它"],"year":2008,"publication":"北京师范大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKO_h0TLyWdVADb1ml8mNtwCnPAc5BaJvH77DUjnf_TNC6AO52L0jJ6azKNtgnI7r17sbrMLxc-xhO02M6HuLlpsn_6aljfOxRDA3s8QnwN7F9bK3TmwuOlmek5WKlFbqAQ6FLEAnhF77EA4zqVVds-OBwChhuLVtry94ZiSCpjDQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"56-60","volume":""},{"id":5496,"author":"张淑一","title":"金文族姓研究中的常见问题","abstract":"金文族姓研究对探索中国上古社会历史的意义重大,但研究中也存在一些问题,本文对研究中带有普遍性的臆断铭文性质、以媵器绝对为父方作器、混淆不同国族三个常见问题作了探析,冀为学者们以后的研究提供借鉴。","categories":["09_其它"],"year":2008,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJFj60713--Rx7Z1uqpO5CyODFomp_5l4HVqkI1IaTVZug9njbwzVYJ-2Vuf5Q5CaR34nCjg3B_SdTkl1c5CwpIo9Qju8JHr9tRZY6a8XHeaciLA81sJgaqeAzEjH3rNjdMyu4AzwArTXpurSbyXXW6pKzkRlXssvqa1b77gdh7DA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"80-83","volume":""},{"id":5506,"author":"加晓昕","title":"以“人”为本,文字与文化的合二为一——探析汉字中与人有关的若干文字的文化内涵","abstract":"汉字是一种特殊的符号,可以形探义,获取丰富的文化内涵。从字形的角度分析若干与&quot;人&quot;有关的汉字,可以多角度多侧面地展示出一幅幅社会生活场景,再现汉民族的远古历史文化。","categories":["09_其它"],"year":2008,"publication":"安徽文学（下半月）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLzK1ztbbekQWFBtQM9vgTi2d5gxJYUfORzwBGwHry7J9-svlLNT6I9SBngn1Y9JZaTpaqNButVEB9_iszusTAT1q1u166dhzei1bJZNJFzVHzbbG1rxzd4tGbPSNwBO1E4T3J1Q-FzUijIK4MSMuaahvRe4z7PDUWeT9ifOjeYAQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"272-273","volume":""},{"id":5515,"author":"金芷君","title":"金文述略","abstract":"金文主要是指铸在商周青铜器上的铭文,它上承甲骨文,下启篆书、隶书,是中国书法艺术史中的重要篇章。本文主要阐述夏商周青铜器及其铭文的沿革;《本草纲目·金石部》收录&quot;诸铜器&quot;;并涉及中药炮制及炼丹所用仿青铜器簋式炉等。","categories":["09_其它"],"year":2008,"publication":"中医药文化","link":"https://link.cnki.net/doi/10.16307/j.1673-6281.2008.03.023","pages":"54-57","volume":""},{"id":5518,"author":"刘钊; 叶玉英","title":"利用古文字资料的上古音分期分域研究述评","abstract":"近年来,利用古文字资料进行上古音分期分域的研究已经取得重大进展,有关殷商语音研究、西周金文音系研究、战国各地方言研究和秦汉语音研究的成果数量可观。这表明不少学者已经意识到古文字资料对于上古音研究的重要性。只有充分利用古文字资料对上古音进行分期分域的研究,才能尽可能了解上古音的实际面貌;只有利用各个阶段的古文字资料,才可能对每一个汉字读音的源与流进行探索。利用古文字资料研究上古音应该成为今后古音学研究的主要方向。","categories":["09_其它"],"year":2008,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKL30koCE8jqReaashEBBiLh5JvH_fEsfnNPolXmCg-6ffBeuHcEcm1O5uasJ3YeWq9rj1oCiOryBhae1wLFu2E-NMZFP1ERTm2pbpw_DxztuAHTM5pfaNmDdIhlNW3QWTHJqY7QLLCUXMTpe2OEk62MqJjHO04bRAzuFp4zJUkaQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46313","volume":""},{"id":5537,"author":"曾宪通","title":"容庚与中国青铜器学","abstract":"青铜器古称彝器,是我国青铜时代的伟大创造。青铜器研究肇兴于宋,延及清代,金石之学盛行。金石学以刊布彝器图像和摹释铜器铭文为主要模式。从20世纪20年代开始,容庚先生率先集商周彝器铭文上之单字为《金文编》,进而在充分吸收宋清两代金石学研究成果的基础上,益以近代考古学的新知,运用出土实物与传世文献相结合的方法,成《商周彝器通考》一书。是书对青铜器的形制、名称、时代、真伪以及铭文、花纹等作综合的考察和缜密的论证,与其前后所撰的一系列相关著作共同构成了一套比较完整的研究体系,为现代青铜器学的建立奠定了坚实的基础,开启了中国青铜器及其铭文研究的新时代。","categories":["09_其它"],"year":2008,"publication":"中山大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLH_PYTlxBZYfMEgC0zDytyImfhX9KqN-d4JNUPtceHxqhTiWRXUBcjgCYCOMspWwChdhD5Ioct7NUtT8A0XfJCqkSB2p3d3Bf79QlD1gnd_w6EU1RCC7RQHVvhtDCE_yByR1j-x5e8sdu_-HkWN1ZJjT4swdFqsU_2UgaZCdFFrA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"6-16, 204","volume":""},{"id":5539,"author":"黄南津; 刘家毅; 邱明波","title":"广西永福百寿图考释","abstract":"百寿图是现今所见的中国时代最早的集古代单字诸体为一身的摩崖石刻,但至今缺乏对百寿图及其一百个小寿字的全面记载及研究。文章在重新对百寿图摄影及拓印逐个核实小寿字及铭章基础上,对百寿图作研究考证阐释。","categories":["09_其它"],"year":2008,"publication":"学术论坛","link":"https://link.cnki.net/doi/10.16524/j.45-1002.2008.05.042","pages":"173-176","volume":""},{"id":5540,"author":"李守奎","title":"评《古文字构形学》","abstract":" The present paper is a review of the Morphology of Ancient Chinese Writing by LiuZhao and at the same time puts forward some ideas on theoretical problems of the morphology of ancientChinese writing.Firstly,the theoretical research on Chinese characters should be based upon thedeep-going study of Chinese characters themselves,and a good grounding in the basic skill for decipheringancient characte","categories":["09_其它"],"year":2008,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ4gyYtWqd9gPEQtk_r_wIgYhM7uCwOYFYQlrn6-wf3P2_L4Ik6vv0fkz8owkn_ap2tIObQGFr4SZpc1UZj12Xua9QGrYNx9gq7R7QOv_fKRSHCZ0CVWTgAOaEKDG3CSaiEowJhxPjqoWt-53WwLi3FJaD6esls0h6GgorE4IaAFQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"89-92","volume":""},{"id":5542,"author":"梁丽红","title":"一个半世纪来毛公鼎研究史回顾","abstract":"","categories":["09_其它"],"year":2008,"publication":"中国史研究动态","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIFXm-r48bhVPQwq_oLlGMykelmPhjg60XKho4hkdK_fKp2EAn2uh-aBKn6DQKlRpo4BrDDMyGpGxw_b93xvZWmN_1e92C062gnDEfhlnox1_3PIU6n7zohfNWd3Jq-ID0tSVZ0g4_suAcqCpLRERWFotKWO2t8U3yW8d5EG3W32Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46061","volume":""},{"id":5560,"author":"郭静云","title":"夏商神龙祐王的信仰以及圣王神子观念","abstract":"最近几年来,笔者以夏商礼器的纹饰、甲骨文、金文和传世神话内容互相参证,发现华夏巫觋信仰中有颇为关键的双嘴夔龙崇拜。此种崇拜滥觞于中原夏人巫觋文化中,且影响商周信仰的发展。在上述研究之基础上,本文进一步用甲骨卜辞、传世神话、古代美术探讨中国帝王观念与神龙信仰的关系。华夏先民相信,大巫魁酋或立国圣王都不是由人所生的凡人,而是由神龙所生的神人。圣王神子从其母体获得了超俗的智慧,故能通天通地,成大巫、国王,智明治理天下,管制黎庶。此种观点自上古流传至近代。","categories":["09_其它"],"year":2008,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2008.01.028","pages":"46033","volume":""},{"id":5570,"author":"雒有仓","title":"商周族徽文字研究的历史与现状","abstract":"","categories":["09_其它"],"year":2008,"publication":"中国史研究动态","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJHMYnkYLi-q08tCd7_KoUAfyUkcpo_EB9sgIEMBYIOmU8msc3AP9g9DV1_uywuD4iTNb9CSLUdyLLcgCnun7_2c-NhBWHv5X0bsPbVQ0nsIQRspRBuCOZZGJDZOIJ80FccrIE6dJeTd5UIFhiu4TyPdyFbZrFLGWvY3DY9w-Niqw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46063","volume":""},{"id":5591,"author":"雒有仓; 辛田","title":"丁山先生的甲骨金文考释与古史研究","abstract":"丁山先生是我国现代著名史学家,其考释甲骨金文主要是通过字形比较、辞例推勘、据礼俗和民族史料释字,其古史研究成就集中体现在史前神话、殷商氏族方国、商周史料考证、商周年代学研究等四方面。丁山古史研究的方法是&quot;二重证据法&quot;在三个层面上的运用与扩大,对古史辨伪理论也有继承和发展。这些方面,我们应加以继承和发扬光大。","categories":["09_其它"],"year":2008,"publication":"榆林学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ_kkyC-WFJIE47DtiKO-ogNhRdAT0-ldxN2ZscHNUBFeln2CgQKo0Vq6YvFZMe2h-Inyuk3s4nfoo_bnUZohdwbc5768sAcaRYBIYtcFpf-ZhKd3DinqSbY9JUUo5GSLFOcbbAJnvMKvXOvQ0MqUCpc6eQqp1pnNWuTTUeEJWJWQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-57, 62","volume":""},{"id":6455,"author":"马晓风; 党怀兴","title":"宋代金文学研究","abstract":"宋代的金文研究是中國學術史上金文研究的肇端時期,產生了四十餘部著述,無論在資料的保存還是學科的創建上,都做出了開創性的貢獻,留給後學一筆豐厚的學術遺產。而就目前來看,學術界對宋代的金文學重視不夠,很多問題的研究尚比較薄弱。選取宋代金文學作为研究課題,主要是出於這樣一種努力:即在傳統金文學的視域內,探究金文學興起於宋代的原因,探討並總結宋代金文考釋方法論,分析宋代金文學取得的成就及對後世尤其是清代金文學的影響,以期为金文學史、古文字學史、漢字發展演變研究史、器物學史等學術通史的撰寫提供翔實可靠的資料。全文共分七章。第一章主要包括兩方面的內容:其一,選题的緣由及意義。其二,研究的歷史與現狀。對宋代金文學自晚清王國維首開研究之風,其後民國時容庚、馬衡、楊樹達等均進行了一定範圍內的研究。近二三十年中相關著述漸多,也有所發明,但仍是籠統的評介過多,細緻的分析與舉證不足。分析前輩和時賢在相關問題的研究","categories":["09_其它"],"year":2008,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI1MK3DtyVSxDjqpTGkfAE4dCY1Wtw9XdNygXEXiyiyiEwVO_rKL8qL9vcY1VNjhBgiX5ObSX1rp9ljxl8XGOJiTgxqBFiuo112rvc4QowynO1NtAiY-qWoB1PTg_rbrg8X1TqewnkbuGXqrRfAzKMOIRfR5skdcGGLc8nTTMPfofSvrc6_mAm0&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6458,"author":"张常勇; 郑元者","title":"商周青铜艺术身份认同功能研究","abstract":"本文将商周青铜艺术放置在艺术人类学的理论视域内,以其特有的身份认同功能为契入点,发掘它和上古先民之间的内在联系,揭示先民在青铜艺术中的具体存在方式。通过对商周青铜艺术的重新定位和阐释,彰显艺术人类学对上古艺术世界的解读能力,探索艺术和人之间的深层关系是这部论文的理论诉求。在具体的研究中,遵循逻辑与历史相统一的原则,以走近情境为前提,根据青铜艺术身份认同功能自身的发展逻辑将问题展开如下:导论部分首先回顾商周青铜艺术的研究史,侧重讨论在学术史演进过程中,商周青铜器研究范式的变迁,提出艺术人类学的角度和方法是当代商周青铜艺术研究的内在要求和发展方向。接着具体解析所研究的问题,阐明研究中遵循的原则和方法。第一章概述商周青铜艺术的生存环境。商周青铜艺术既具有“地方性”,又是“作为文化体系“的艺术。据此,本章首先讨论生存地域、气候以及物产和青铜艺术之间存在的必然联系。再从生态人类学的角度讨论它的文化前","categories":["09_其它"],"year":2008,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iISRfo2d1r5WCpGiO-zT5-W0LUkyo6L4zPlPPnhIgKLAdhWCXs3uehf34yFBwzzhD53HiCNg4NHOZX1jbJGK4VznTMn4MThBa4RQShizKmm_kgASQp3PVOk6ttH2X1xdGtj_Ag853lPjzYRRcs4f757-9N9gKYlEG4eT1FYAK7DNDFllO20_-or&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6462,"author":"徐广才; 吴振武","title":"考古发现与《楚辞》校读","abstract":"大量的考古發現材料為校讀《楚辭》提供了可能。本文主要將傳世文獻與考古發現材料結合起來,在充分吸收已有研究成果的基礎上,對《楚辭》進行校讀,試圖得到一個“近真”的《楚辭》文本,試圖對《楚辭》文本做一個“近真”的解讀。本文共兩大部分,第一部分是緒言,第二部分是正文。緒言,包括四部分内容,第一節介紹了《楚辭》文本的形成過程及現狀,第二節回顧了《楚辭》校讀的歷史,第三節闡述了利用考古發現校讀《楚辭》的意義,第四節說明本文所用材料、主要内容及相關問題。正文部分分為十卷,共260餘條目,包括文字的校勘、詞語的訓釋、相关史寅的闡發、作者及作品的真偽等近300個間題。或證成成說、或指出前說之非、或提出新解。","categories":["09_其它"],"year":2008,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI-GA-PcakHoBMNzxgFqBAM40FhN7eZuLHlp5P6QJSAqhMg6qt-hIT-R9PdDJjemIxUhFm-NnLKhRGx7JHTnA_sqJBWu1SUtUbzdUBKqHgdLN1L8W--4QnVn4QgIY3mmjHB7aK-ppfBVGJdTc_scU_f9IGrP6AU76ZkwxEOL7RBN-onBYtrEy2x&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6804,"author":"李义海","title":"郭沫若西周金文修辞研究及意义管见","abstract":"笔者在尝试&quot;西周长铭金文修辞研究&quot;的过程中,发现郭沫若不仅指出或暗示了一些修辞现象或行文手段,而且还有以传统的辞章之学为视点进行铭文释读的成功范例。郭氏的这些研究成果,不仅为汉语修辞史及修辞学史的研究提供了真切的资料与范例,而且有利于我们总结前人的治学经验,并据此推进学术的进步。","categories":["09_其它"],"year":2008,"publication":"郭沫若研究三十年","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLXcGk2aeM7MiRPZ6NcffNkpsuO0LYDDErwk7uibTdNuUStJKtphQmKVuN2eXD3mi8GED0obUTm3wnA5NyPtbSQEEjDO_NWOwu9TlSC8h7NYHDqPeFSskr3DT1I-AaOIhE7PQRcuwYAEr-V38WJKRQuVaz5fwR6iHmkB1Am3zaHAY-SiKJ7r0f-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"109-120","volume":""},{"id":6808,"author":"郑锦全","title":"口语与文字在书写中的主导地位","abstract":"本文探讨口语及文字在书写中的互动。当书写的主导是文字时,如文言文,汉字所表达的语素的形体变异不大。而在以口语为主导的书写中,同一个语素会以不同的字形出现,现在台湾的闽南语、客家话的文字如此,唐代变文也是这样,西周青铜器金文文字的字形变异也能以口语为主导的理念来解释。","categories":["09_其它"],"year":2008,"publication":"“汉语与汉字关系”国际学术研讨会论文提要","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLBoq0KjCYDH5nrdbaTni4YLJ8g_cM4Pfn-OMk6ATl1zJpDaiwp5pR-B-EGxiAkEBYjupG6VPLgQFcStNztXHnGTi_7Y4nt-t7vv3VgGu9kkQ5ljiEeO2ocEJLvbh3E3as0J8J_eC59Y8vi5t4mckLeQdsabsdnDN2VGsaDdp3g6uAjdCo0K0GS&amp;uniplatform=NZKPT&amp;language=CHS","pages":"171","volume":""},{"id":6809,"author":"谢燮; 赵小刚","title":"女书中的疑似甲金文借字研究","abstract":"甲金文与女书都是有着众多未解之谜的文字。它们距今时代久远,文献资料有限。本文试图通过女书与甲金文字形等方面的比较,探索研究女书与甲金文之间密切关系的可能性。从而为女书的本体研究和甲金文的本体研究提供一点新鲜的视角与线索,同时也是文字比较研究的一种尝试。本文进行研究的主要方法和步骤是:首先,从地理位置看女书和甲金文之间有过接触的可能性。其次,通过比较部分女书与甲金文的字形特点,尤其是研究其中具有对应性变化规律的几组字,并找出具有甲金文特征的女书字符作为造字部件所造字族,认为在女书中极有可能存在甲金文借字。最后展示这些疑似甲金文借字进入女书后的异化现象,更加证明了女书与甲金文接触的可能性之大、影响之深。","categories":["09_其它"],"year":2008,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLp-ScyaMxhiXL2geOaoLVwaFcNaqjq6sRNr3OKjisowA9IkK0mn9ppZVn7EH0qb7qfTMSxDpmxRBNZYLEhYmUj_yCVuyJ5nlLNL9DEKGDjr4tSQcf7Nh7k3pWqrbCJ4nYvrwoI6ooX9Y6pdIxJ1o2q4i-aUyx70xgTYDEj5c2pCQ9Wf_0e6aNP&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6811,"author":"田笑霞; 李守奎","title":"汉字性质研究述评","abstract":"汉字学从传统“小学”到古文字学,已经发展到一个相当深入的程度,但汉字的性质是什么,是学术界一直争论的热点问题,由于论证的角度、切入点或者说标准不统一,出现了概念术语含义混乱,诸家各执一词、众说纷纭的现象。在大量阅读参考文献,仔细研究各家观点的基础上,本文首先对汉字性质研究中的二十几种说法分类按时间顺序进行综述介绍,其次,从五个方面阐述了各位学者判定汉字性质的标准。五个标准即:从汉字的不同时期或多角度进行判定、从汉字的外形特点来判定、从汉字记录语言的单位来判定、从汉字的结构角度来判定、从不同标准判定同一性质等。并依据造字理据,指出汉字是表意文字的正确观点。在肯定汉字与西方表音文字属于不同的发展体系,具有同级性的前提下,从“造字理据是表意的、运用同一造字理据所创造的各类汉字是表意的、外形体式发生变化的古今汉字都是表意的、含有表音成分的形声字、假借字的构字字符仍是表意的以及词义发生变化的各类汉字","categories":["09_其它"],"year":2008,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIsUFWD6xEyip94Nl0KqO2jR6UhDZ8kTnG-IERuL8crD8M7-id6TZCGFrJF6Ojne_yohc1K8wAjl69lDHg_Z7vMW2K_ceelnxZ96osKylQFI2KYkYXF8ffYXQZxkKMRhu0eb9bikpvDeajNOcHZrBTSC-ZFzGjcfEvOqhfCyKSn1NNx-P3GbXzR&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6812,"author":"张滨; 李守奎","title":"汉字构形研究的历史与现状","abstract":"汉字构形理论是一种以研究汉字本身构成和演变规律为目的的理论。古代汉语研究学者将音韵学、训诂学、文字学合称为小学,前人喜欢将汉字构形理论进行钩玄提要,而且研究成果也颇为丰硕。如许慎《说文解字》中“六书”说的提出,对于分析汉字结构和造字法具有划时代的意义,对后世产生了巨大的影响。进入二十世纪以后,随着文字材料的不断涌现和研究方法的进一步改进,汉字构形又有了进一步的发展,唐兰、裘锡圭的“三书”说、王凤阳、苏培成的“新六书”说、王宁的汉字构形模式从共时和历时角度分别对汉字的构形作了新的分析,使汉字构形研究又向前推进的一大步,为汉字构形理论的完善奠定了基础。本文即通过分析汉字古今构形研究的历史和发展现状,探寻不同发展阶段汉字形体结构研究的基本脉络。除结论外,本文共分五章,第一章叙述汉字构形理论的大致分期及研究内容的范围。第二至第五章分别讲述各时期诸家汉字构形研究的内容及研究特点。结论部分在概括汉字构","categories":["09_其它"],"year":2008,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIsUFWD6xEyip94Nl0KqO2jR6UhDZ8kTnG-IERuL8crDwb2xfeqpnvxEcLo8TGD_ukvSk1w5qDFA49_IlfA9GPGiwTsr1Bd6zfh4klGlTZRXffqxNZ2bJBxhbwYCFFFoio9VQg_FGe940m-E5fTu5v3_cAQOWH2SF2DrnkRq6LiODVJuhNLlgNf&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6815,"author":"韩英; 李守奎","title":"《昔者君老》与《内豊》集释及相关问题研究","abstract":"本文以上海博物館藏戰國楚竹書(二)的《昔者君老》和上海博物館藏戰國楚竹書(四)的《内豐》兩篇簡文為主要研究對象。文章分為上篇、下篇兩個部分進行闡釋分析:上篇,与两篇竹書相關的几个問題研究;其中主要涉及竹簡形制與筆跡比較分析、内容與分篇、兩篇簡文编聯及排序情況概述;下篇,《昔者君老》和《内豐》集釋。","categories":["09_其它"],"year":2008,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJqGDZzWJkAUN9bEeMd_ZAYp0dYd_CE0svY9T3o0yaCqjgfob5ll2DZBQY6uq8kMJwG0YFmtfombx7QNj40gUtCvhsNEeZQFpNYptiSthgS4oVTLtloFVRQ_2-wWRgn2WRCNq-0_SeETZqYXnvZsT96_lebzWSDJpCvUHPJhlsalqcN-Fi9C0KF&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6819,"author":"陈中岚; 陈四海","title":"殷墟出土乐器研究","abstract":"本文主要以商代后期都城殷墟出土乐器为研究对象,从乐器所在的区域、乐器本身的属性及特性的考察,同时利用地下考古材料和传世文献记载相印证的“二重证据”结合的研究方法,期冀对中国古代音乐史中有关商代王畿地区乐器的断代史作出较为详尽的描述,力求表现商代后期王畿地区的音乐文化形态。本论文主要分四个部分进行论述:第一部分:殷墟乐器的考古发现与背景概况。了解商代音乐文化首先有必要对殷墟概况作简要并全方位的概述。文中首先从殷墟乐器的考古发现中墓葬的分布区域和音乐文化分期作完整的概括,使大家对殷墟乐器的出土有个初步概念,作一简要的了解。其次,是对殷代社会生活的简要概述。从殷人生活的状态,整个商代社会的文化艺术及宗教信仰着手,通过商代社会的文化背景,为下文乐器的出现作铺垫,以此来探索商代乐器的分布状况及乐器背后反映的何种音乐文化。第二部分:殷墟出土乐器综论。文章用概括的性质,从科学考古发掘、出土文物的角度,对","categories":["09_其它"],"year":2008,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKYpytjS7IqFZU_CvMknDYdTn8qi_F7H0-hsRIVXt2AHYZudprFPuHDjkGHNOctpe21Rh9uZUg743ffmCoSY7GEuAeWsyVyzQTDuoZR71qGW_-CEFMlljGzyDJ_Iss1gccfN11dzvcGdFUGGAmFgUC4cOppcaM71GPIvoh8rM0oggBRSOxdCZ3J&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7000,"author":"刘向阳","title":"昭陵十四尊蕃君长石像与唐太宗时期的民族政策","abstract":"昭陵是唐太宗李世民（599—649）与文德皇后长孙氏的合葬陵。在陵山北阙的司马门内,列置有唐高宗李治永徽年间（650—655）雕刻的十四尊少数民族首领石像。十四尊石像代表十一个民族、十四个国家,真实地反映了唐太宗李世民创建唐王朝的功绩,体现了唐太宗&quot;自古皆贵中华,贱夷、狄,朕独爱之如一&quot;[1]的开明民族政策和唐朝与邻邦民族之间的友好关系,颂扬了唐太宗李世民开拓中西交往、反对外来侵略、志在统一海内的功绩和为中华民族的团结、融合、发展做出的贡献。","categories":["09_其它"],"year":2008,"publication":"乾陵文化研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJX4bgrCBR4ofUw6gWEy40NwS1FIgoNYgBnAMRSasOGLFcXDXFn_R5zoLzAESuzM1hWpYBAdk-npzroNVwhwhd7TO8gtXXQ4tyADdgaQUkEuCFZnNx3wrK65MEEGX_8vgrZtB5cB4EkdY0p1FRfIMweIq14p7wGGLUoHmViNnZXFQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"165-179","volume":""},{"id":7002,"author":"袁予生","title":"金文的启示","abstract":"文字是历史记载与文化传播的重要形式,就文字本身的记载来讲,追溯其历史就很有意义,它可以从材料与工艺的角度为我们开启另一种思路。以前众多的文章可能更多是强调了文字记载与艺术的功能,而对于文字工艺的作用着眼较少,本文旨在从不同文字工艺的角度,揭示文字记载的技术性对于后世的启迪意义。","categories":["09_其它"],"year":2008,"publication":"当代艺术","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKgJIFS3eMaL3mbMPplT5Pc_uFluLfSC8giACgMrNfvg3kKjxiYjg2ZjOijW89C0V7p6lebVXj9qmTwiAqHkwCyH0xxC5zJu0jk_BIAhZVTWz1itEzCmoP-_t6PaObu874rpIosOhhv7qmBZaw7uXruFZPZAiUUqS2RM3dyuHKtxA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"101-103","volume":""},{"id":7013,"author":"刘志梅","title":"谈《金文大字典》存在的几个问题","abstract":"《金文大字典》是我国当代金文研究集大成之作。但是,近年来随着学术的发展,《金文大字典》暴露出在字形考释和拓片的整理方面的一些问题,本文先把《金文大字典》的错误加以归类,然后在每类错误下举一至兩例加以说明。","categories":["09_其它"],"year":2008,"publication":"文教资料","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKLzdSlwwJNWIDHS1mPlKWLfqNVsEI50QmZJous9BhFa4Y3qIOsAbu63PEMH8m0ERbPGRMgs5SegbzJr8fkA5OukgXBYDxMG9nKtWxxMoDdq34YyAD07Mkb4_bLdKkdPQ4OQaAkxJXSpa-uFJiIoPH2p3P6BOUT56lSIyJ0-8KtHqkw6zy-iNpg&amp;uniplatform=NZKPT&amp;language=CHS","pages":"42-44","volume":""},{"id":4853,"author":"龚阳","title":"汉语“数·量·名”结构产生刍议","abstract":"汉语&quot;数·量·名&quot;结构产生于先秦时期,其过程经过了两条途径:一是在甲骨文、金文中,&quot;名·数·量&quot;经过了&quot;名·量&quot;、&quot;量·名&quot;两个阶段,进而转化为&quot;数·量·名&quot;结构;二是金文以后,&quot;名·数·量&quot;经过&quot;数·量·之·名&quot;阶段而过渡为&quot;数·量·名&quot;结构。","categories":["09_其它"],"year":2007,"publication":"语文知识","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK4RWsMzczEC-a2hT1O6zXaqFbywwh97noboZQD2caxlsmOCHVTgRekEm58fTy7CMaB3_8sHJxwKLPer8rAmDAfygsw5oRhomPJoGx07MJIvph8U8uMIXVfTsWAE0TS47PoQ-jwX8F5u86lUqVu2j-GynThLhN8vrkpXwYQ8N6ZkZ_JGDSgkMWW&amp;uniplatform=NZKPT&amp;language=CHS","pages":"83-85","volume":""},{"id":5603,"author":"韩军","title":"西周金文研究中的“康宫问题”论争述评","abstract":"&quot;康宫问题&quot;是西周铜器断代中的关键性问题,并导致了学界意见根本对立的论争。本文对持续数十年而未决的&quot;康宫问题&quot;的历史论争进行了概述,对两派学者尤其是唐兰的论证过程进行了细致梳理和简略分析,介绍了&quot;康宫问题&quot;在当代的研究状况,指出了&quot;康宫问题&quot;研究的出路。","categories":["09_其它"],"year":2007,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2007.04.021","pages":"61-65","volume":""},{"id":5621,"author":"梁彦民","title":"长颈圆体卣与提梁壶——谈青铜器形制演进、名称与功能的变化","abstract":"青铜器作为一种用器,其功能的变化对于名称有很大的影响,提梁壶之所以不再称卣,可能与其功能的转变有关。","categories":["09_其它"],"year":2007,"publication":"中原文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLhhlBLQcgSNS5UX_ct60LcaypqBMT1VQHzlJ7253z3mn86YSVjYgcCl0b8r785zwflce5OnKSSJywDXsDUaJqd6w0TLHaaQDe6_XO-8I59D-FNLdNd0OPdwVmBXJksv1pcaqYoalknypkkFAmQarR2XrnQxp7aX3gJx8tYme_pHg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"47-50","volume":""},{"id":5630,"author":"董珊","title":"“周公戈”辨伪之翻案","abstract":"&quot;周公戈&quot;先后被郭沫若、江村治村、林清源等学者认为伪刻。本文从戈的形制、铭文结合文献记载及对其他地方的同类出土物等分析,认为该戈及铭皆不伪,戈的时代属战国中期。从戈铭可以见证战国时代西周君主的称呼方式,并反映了西周地区的铭刻特点。","categories":["09_其它"],"year":2007,"publication":"华夏考古","link":"https://link.cnki.net/doi/10.16143/j.cnki.1001-9928.2007.03.009","pages":"92-96","volume":""},{"id":5644,"author":"刘海宇","title":"日本汉学家白川静及其文字学思想","abstract":"一、白川静及其学术著作介绍白川静是日本著名的汉字学家,他的研究立足汉字学,横跨考古学与民俗学,旁及神话和文学。他透过卜辞金文的庞大研究业绩,对汉字的体系与文化源流系统性、独创性地提出丰富又生动的见解,在日本汉学界产生了巨大的影响,对中国本土的文字学研究也有着独特的借鉴作用。","categories":["09_其它"],"year":2007,"publication":"汉字文化","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJIKsKYMk9SZfu3blqoEcRto48HcFDg2xPTdKJCA1YSzCes2Yj-RCVuh-iyTV9xaVDpJ9GOv4Xy1YmH8nX3hnRRrNUCBjDK8L9otAOXnmj7xHMSxuc5SmqOh9DNpJkxsywiWTfdT0H49F_9vK4fRxNv51LJhBsJFVR2HimIRkhgHA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-64","volume":""},{"id":5652,"author":"吴小平","title":"从铭文看两汉铜器皿的生产经营方式及其变化","abstract":"汉代铜器皿的生产经营方式多样,且变化明显。大致可分为三个阶段:西汉早期,国家的经济政策较为宽松,铜器生产较为自由,制作机构既有中央和地方政府控制的各级工官,也有地方诸侯和富商,产品得以自由买卖;西汉中晚期,由于对地方诸侯和私人工商业实行打击和限制政策,铜器的生产经营方式发生变化,地方诸侯和富商基本退出铜器的生产领域,铜器的制造由政府专控;东汉早期,随着政策的放宽,铜器由政府专控的局面开始松动,私人作坊造作的铜器出现,至东汉中晚期政府各级工官基本退出铜器生产领域,铜器的制作为私营或工官监制私人承制的形式。","categories":["09_其它"],"year":2007,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2007.04.006","pages":"100-107, 159","volume":""},{"id":5654,"author":"王卉","title":"汉代金文用字现象研究","abstract":"汉代金文是中国历史文化中的宝贵遗产,这些遗产的文化价值,已经被越来越多的学者所认识。研究汉代金文中的用字现象,可以更全面地把握汉代文字的特点,为汉字发展史的研究提供有价值的帮助。","categories":["09_其它"],"year":2007,"publication":"宁夏社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLEgg-pkXxNJZTu3CDp2lYxI4Ic6K3Et0mGa3CemjTPPq27yivIYbRRIeQKCOFmP_RDTix8lhFF1yPd5Q7AsuywIrFo1qK7VixKByLqRUjDfDPz3NGBvJS6cwyPHyZrGRbIf4y0opcwOGG_elA7MnZkkhRu9Cbhm0uGm6dx2TPsAg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"157-160","volume":""},{"id":5701,"author":"刘金荣","title":"论汉字的字体及其种类","abstract":"汉字的形体是丰富多彩的,从甲骨文算起汉字形体已经发生了许多变化。汉字形体一直是汉字研究中的重要内容,却又是一个还不被人们重视的领域,至今文字学论著都没有界定什么是汉字字体,也就使汉字字体的种类不甚明了。本文从界定字体入手,将汉字形体依其性质和功能区分为字体和书体两个范畴。汉字字体是在某一历史时期在官方文书中使用过的有一定规范标准的汉字结构体式,并以此标准归纳汉字字体的种类。","categories":["09_其它"],"year":2007,"publication":"绍兴文理学院学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.16169/j.issn.1008-293x.s.2007.01.015","pages":"77-82","volume":""},{"id":5716,"author":"杜廼松","title":"全国青铜器所见伪器伪铭考(五)","abstract":"青铜礼乐器与容器最早时代的伪作实物,是前面讲到的集安高句丽墓出土的战国式的小口鼎。该伪作铜鼎大有乱真之势,表明这时的伪作基本上还是尊重古器的制作规律。宋代在伪作器类上除鼎、簠、罍、尊、壶、觯、匜等商周青铜器外,制作较多的还有鸟兽尊一类的盛酒器,如:牺尊、象尊等。这时也喜","categories":["09_其它"],"year":2007,"publication":"艺术市场","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJV1jJORfK8AuLyVHleR0T2hf_4231P6cr2eSKKHmsFfee7LI-3V_kY-RUR9BEi65-SpMAaMTCDYvkUU1RXVLzpLArxqsWzpflpF-cxyRIsqqWUqvX2-DmfMVxM9GE7a629wUeFw9elvg2dQPSkUt8xfBnFO5qYK7_oCnIwnCQMrA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-71","volume":""},{"id":6466,"author":"管恩好; 王志民","title":"青铜文化与《诗经》发生学研究","abstract":"《诗经》是我国第一部诗歌总集，也是我国产生最早的文学作品集，是灿烂辉煌的中国文学的源头，在我国文学及世界文学史上都具有非常崇高的地位。《诗经》具有丰富的文化内涵和重要的史料价值，同时也是儒家文化的经典著作，历来对它的研究硕果累累、汗牛充栋，但其中对于《诗经》发生问题的研究却还是一个比较薄弱的环节，有许多问题还有待进一步研究和探讨。《诗经》的发生问题是《诗经》研究中的一个重要课题，关系到对《诗经》文本的正确认识和解读，廓清这一问题对于《诗经》研究的意义极大。但过去由于文献资料的匮乏，对这一问题的研究面临许多困难。虽然也有不少论著曾论及这一问题，但因多是从传统文献的角度出发，其探究问题的广度和深度都受到了很大的限制，一些有争议的问题也不能从根本上得到解决，因而从总体上制约了对《诗经》发生问题的研究。近代以来，随着我国考古事业的发展，先秦考古硕果辉煌，考古出土的大量文物，包括甲、金文资料及一些出","categories":["09_其它"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIJicTNRJFhcdM8-zmE0kjCgz1jpTJQhYZeAyfD7oQG-7Pwp2q6DU9M7CxLiaiemPW-YD66unCmHN199FVnmVOJL_CUgwUNyLe0MNYa2jG50b9O4YWLoHUPU9u8bTALAR8uwtDULcfZukUNEMQkhsU05KQsT-z54p8JkGpUoXW0FsmyYTJ0Glzp&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6475,"author":"卞仁海; 王彦坤","title":"杨树达训诂研究","abstract":"杨树达训诂远绍乾嘉段、王，近被时彦乡贤沾溉，又受西方语源学影响，取得了很大的训诂成就，被时人称为“神州训诂学第一人”，但相关的研究并不理想。本文第一次系统、深入研究杨树达训诂的理论和方法、成就和局限，以期说明处于语言学转型时期的杨氏训诂的特点，并通过杨氏训诂材料的整理，为当今的语源、训诂研究在理论、方法上提供借鉴和参考。本文以杨氏形义观、音义观、语义观及其在训诂中的运用作为阐明杨氏训诂的主体；以杨氏的语法修辞观及其在训诂中的运用说明杨氏训诂虚实兼治的特点；通过和章太炎、沈兼士、黄侃等三者的比较，说明杨氏训诂的时代共性和个体特征；从古籍整理、辞书编纂和文史研究等三方面举例说明杨氏训诂的应用；最后从形义之学、音义之学、语义之学、虚实兼治、专书训诂等五个方面概括了杨氏训诂的成就，并从宏观角度指出杨氏训诂的局限、以札记的形式从微观上提出了本文的商榷意见。全文分“绪言”等九个部分，约20万字。","categories":["09_其它"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLbd6f-HZxLab7zycrQ1sOEJ73Ix8SlPub0jhu5Rfgy3nOYtGEDKF7Py_o9x2WHomNVOFjMYVhIQtPNB2Bfo1U5-YyM-yHUcMizDHdYgO30mvxv1C1ZCVg5cUnUBy6wMsIYXY1DnV8rHMqF5XoKhaUtSQ3dICfqvKmh555mFFsEKOZUj_-GKmRv&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6478,"author":"王月婷; 黄笑山","title":"《经典释文》异读之音义规律探赜","abstract":"《經典釋文》是一部集大成的音義書，是研究上古漢語語音不可或缺的文獻材料。我們為之建立了字頭、音義、經注原文相匹配的數據庫，並從其幫組及來母異讀字中抽取出具有一定音義配合規律的60餘字頭，作為本論文的主要研究對象。由這些用例我們發現，動詞是上古漢語變讀構詞的核心，但詞性的改變與語音的變讀並不是完全對等的；上古漢語變讀存在跨動詞、名詞、形容詞三類的達及義構詞、完成體構詞、敬指構詞；亦涉及兼跨動、名、形三類的小稱音變以及語法化帶來的某些音變。本論文“導言”之後共分三章。第一章：《經典釋文》異讀之音義規律詞表。共收具有一定音義配合規律的60餘異讀字頭，有些字頭内部會有幾對音義配合。對每一字頭我們重點分析其音義規律，此外也涉及音切數量的統計、同條又音原因的分析以及其他較有特色的音變現象，如濁音清化、語流音變，等等。第二章：幫組及來母異讀字所反映出的音義規律。本章主要探討了動詞内部、名動之間、形動之間","categories":["09_其它"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKO__fdYeteKg7guNTQIQgsYDa6KAYihplnVMZPyireUNSe92cmpsz_W3RNVpOnmg_ERTouRf71H_Glkk4AKMa4RVoe3qectoSDCgSyJryxgaijrVo6ch-XwXD8Hhx5sZPxYK3_q5-hb5IzRubMxSHSdLpOhwyHLmn90dExaNJ_CPePiOLZnDsv&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6480,"author":"陈会兵; 马重奇","title":"古书中词语的特殊读音研究","abstract":"本课题所探讨的古书中词语的特殊读音是在我国古代文献里存在的异读字(词)、多音字(词)、假借字、破读音、押韵读音、外来词语专有名词的读音、古人名古地名古官名以及文字演变引起的歧异读音等等，这些读音或者超出语音演变一般规律或者不符合现代汉语语音规范。这些有几个读音的词(字)，我们一般以符合语音演变规律的或者最习用的读法为“正读”，而以特别、少见的读法为“变读”。即把一个字的本来读音以外的其他读音叫作特殊读音。这些特殊读音来源十分复杂，是汉语语音演变过程中出现的剩余。这些“剩余”的特殊读音，有些被赋予了新的意义或作用，成为语言中的有效成分，这是应该予以认可的；还有一些则仅仅是没有意义的“剩余”，成为语言中的赘疣，自然是应该予以清除的。古书中词语的特殊读音是汉语在长期的历史发展过程中积淀下来的语言现象，它体现着丰富而复杂的语言发展、语言运用规律，包含着汉语文化的历史存留。古书中词语的特殊读音涉及到","categories":["09_其它"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLEwks3neBlQZHpMV9aItus5Zp6BDV3X9o0sNrvXXP5muRKf6qCjOtEzh4nDtDHJFPclNYMEcw1HFL7AAWBlwCDCubxVKw6oUiPwHL4aa2_EETLtOGvGprGmorZrvUmIe_vrUN07TLwAmc6clKREPqvkxYr_i-mBYgytB4DEw_7mUsJkRKwK01l&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6821,"author":"刘海宇; 徐超","title":"白川静《字统》“载书”文字学的译介与研究","abstract":"白川静是日本著名的汉语言文字学家,他的研究领域以古汉字研究为核心,能将考古、民俗、文学等学科的研究成果纳入到古汉字的研究中,独具特色。他从甲骨文和金文的研究入手,构建了具有白川特色的古汉字研究理论体系,在日本汉学界产生了巨大的影响,对中国大陆本土的文字学研究也必然起到独特的借鉴作用。本论文共分四个主要部分。第一章首先简要介绍了白川静先生的学术生平和学术成就,对大陆语言文字学界对白川先生的治学的评介情况作了概括和总结,并重点介绍了白川静的文字学代表作《字统》一书的体例及其文字学理论特色。第二章选取日本版《字统》中带有“(?)”形的载书字进行了系统地翻译和研究,这些字包括口、曰、兄、君、命、若、如、召、各、谷、咎、史、事、使、告、可、名、右、周、啓、唐、商、矞、高、呈、哀、和、古、固、吉、吾、咸、含、合、襄、靈、嚣、舍、害、言、司、啓等字。根据白川静的注释,我们按义类将其分成八组,并逐一进行分","categories":["09_其它"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIdQ6i7aLSPtVs5V9tLHUxs0E8WvPO62QBq7__NdBm6cvCe19rtHVKUDggajPedcxrQkZWstXEDWriUfI4lPF1JOaRnr9j7lOheLm3dTdfVYz2s15xicvIHL5lxuO1g7U_CyGLff2OGxPIEGdCK4mRivxrIkgbj0kia16xKNL8avJF6tBRSb-WE&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6826,"author":"何飞燕; 王晖","title":"周代金文与祖先神崇拜研究","abstract":"周代是祖先神崇拜最为发达的时期，除先秦典籍文献中有很多关于祖先神崇拜的资料外，周代金文也为研究祖先神崇拜提供了非常丰富的资料。前辈学者在各自的研究领域内作出了卓越的成就，但以金文资料为主进行研究的尚不多见。笔者则从周代金文材料入手，并结合文献资料研究周代的祖先神崇拜。除绪论部分对祖先神崇拜的研究现状和研究意义作简要叙述外，本文共分为四个部分：第一部分对商、周的祖先神崇拜的特点进行了对比，分析了商代祖先神崇拜的特点为其神权高度集中于商王手中，商王主要掌控祖先神祭祀权，宗法制度不健全的殷墟文化是遍祀商王先祖：周代则是在宗法制度下，其祖先神崇拜是分层分级的，不同阶层享有的祭祀祖先时设立的庙数不同，使用的祭品不同，使用的器具及数量也不同，以及祭祀的权限也不同。第二部分主要论述了周代青铜礼器与金文中所见的祖先神崇拜。分析了祖先神崇拜的理论基础，即灵魂不灭思想，这种思想在先秦时期人们的思想观念中是普遍","categories":["09_其它"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJEE6Z--e6GkQD8QBulOKqMTO_h2KdZMmXg2MFDbKpQMVwTNq-JMbiK7hWs48GPfSmD3lGMmo_FWcsuONY7vd9QAUdWwjNLyXTlBzC-Qn8SHnh31XChzCK40aOYejjhU0AN5y1x5N3PwqX4O05dESzYAE8AGYn8skygrVS2xprC5RTtks06yTEv&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6831,"author":"张唯; 王铁","title":"《历代钟鼎彝器款识法帖》研究","abstract":"南宋前期薛尚功所著的《历代钟鼎彝器款识法帖》是一部极其重要的金石学文献，专门集录器物铭文，共收录器物铭文511件，大部分为商周铜器铭文，并加以考释。因本书在古器物研究、古文字研究及殷周历史研究方面都具有重要的学术价值，故后世金石研究著作对其关注颇多。《历代钟鼎彝器款识法帖》自南宋绍兴年间成书后，辗转流传至今已历时八百余年，文献著录及现仍存世的版本大约有二十余种，这些版本同中有异、相互关联，因历史、文化等诸多原因，在所收器物的名称、铭文形体的摹刻、释文内容等方面存在一定差异。本文从研究宋代金石学发展概况和梳理版本源流入手，通过《款识》与《考古图》、《博古图》及宋代其他金石学著作所收录鼎器情况进行对照，对《款识》资料来源进行了一定考证，进而说明该书之史料价值，为当代学者对于此书的研究利用，做一些基础工作。","categories":["09_其它"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJYu94F3rmsYxuVvHemq3bCT9E3f3vmsoZxrdyFowlOK0cXJHctzt7PEf16CnWTmoN1kCNp8a5PXgiUCHcc1Fws99O751y8rvx2x_Jz0ISMlMQBg1dO0sHPEaSO5xhEtZ-RfPCf-cs-J9HdHiov38H2C8B3GmKs1wRj8MPFOBJ7HY-UzT2bNKQQ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6834,"author":"周昉; 张再兴","title":"金文复音组合量化研究","abstract":"本文所研究的金文，主要指寫在商周青銅器上的銘文，其年代範圍大致從殷到秦漢，其中秦漢時期銅器的數量很少。金文是研究我國商周時期語言文字最重要的資料．以往對金文的研究，雖然涉及字形、語法、詞彙、歷史名物制度等各方面，但由於研究手段的局限，主要停留在舉例的層面上，缺乏整體的考察和分析。本文研究的範圍包括所有已出土的、可用的銘文，依靠數字化統計手段，全面系統地考察金文中複音組合的各種屬性及其後世傳承情況。本文共分四章，第一章緒論主要介紹本文的研究範圍、研究方法，複音詞的研究現狀，以及本文劃分複音組合的標準和方法，並對本文一些關鍵問題作出解釋。第二章主要描寫金文複音組合的大致面貌，從頻率、結構、語法功能、書寫順序等角度出發，對金文複音組合的各種語言屬性作全面的分析。第三章主要考察金文複音組合在後世傳世文獻中的傳承情況，統計出579個後世成詞的複音組合，並分析其書寫順序、頻率以及傳承的原因。第四章利用","categories":["09_其它"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLfnLT8ibOW0M2_yTHzf8mcLUv1RUAbeOk6_Uqnb3pmG9741wgNaM9TZ9LT3br9BOxryc5-7zZi_R6ML8p-P32kXslJhxX_1fGUR1MvG74kAlGXRfxVSk4aVWoAgZ-Fs-Ay-M7bnFasl57CWvw_m8v3pA5bCm4xCJpFyC-N8IlufuvkRkO08RSk&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6847,"author":"顾丹霞; 赵振兴","title":"西周时期副词系统研究","abstract":"西周时期的副词上承殷商，下启春秋战国，其间又有演变和发展，形成了一个较为活跃、丰富的副词系统。本文在穷尽式调查西周时期文献中副词语料的基础上，全面考察和分析副词的句法分布和语义功用，力图呈现西周时期的副词系统原貌。根据副词内部的不同层次，我们将副词分为八大类，即：否定、范围、程度、时间、肯定、情态、语气、关联。在文中每一类副词各为一章，共八章。分别描写。文章认为，西周时期是兴盛和衰落共存、安定与动荡同时的转型时期，词汇和语法发展有着独特的特点，整个时期反映了新旧语法形式的交替，诸多语法形式的萌芽或发展，至春秋战国时期得到巩固流行，从而奠定古代汉语语法的基础。西周时期语法的发展，主要表现在副词的发展上。副词也和其他虚词一样是通过实词虚化的机制而形成的词类，尤其是直接“实词副词化”，使副词丰富而庞大，成为虚词中的大户。副词从实位到虚位，从主要成分到次要成分，角色的转换，说明了语法的演变。文章在","categories":["09_其它"],"year":2007,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKC-kFNf7HyI13Oc84yNgXN9KvFoNqXY0cgEbN80g9ByBx-ROd71O6pzoZhQb7DTHZ4oAOt1uD0NEvftpsqWrICS2bhl4m3XBQwNAa60elddmTkCL8zGXmW6LZptGSuiSEFDOHCooflBej_XU2RreVhD5F6Rpt3Nrk6soT1_5O8munWQOTdb4hK&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7023,"author":"张懋镕","title":"商周之际女性地位的变迁——商周文化比较研究之二","abstract":"引言关于商周时期女性地位的问题,近年来多有文章讨论。鉴于祭祀祖先是颇能显示家族成员地位身份的一项活动,所以有一些文章从分析商周女性在祭祀中扮演的角色人手,审视她们在家族内的位置,提出了不少新的看法。但是关于商周之际女性地位究竟有怎样的变化,这一变化的具体轨迹如何,以及变化的文化动因是什么,尚有必要作进一步的讨论,本文拟于此作点探索。在14000千余件商周青铜器中,有相当一部分是为祭祀而作的,所以根据女性致祭者和受祭者拥有的器物数量的多寡和质量的高下,可以了解她们在祭礼中身份地位的变化情况。为了用比较准确的数字来说明问题,本文尽可能多地罗列相关资料,因而篇幅显得冗长,然而非如此,不足以勾画出商周女性在不同历史阶段中祭祀地位变","categories":["09_其它"],"year":2007,"publication":"西部考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIlkZL6m9HgAJxTyrLQnSz1JDURLUHK92NurSCmAzK4xU7QJbiqgh0DLkZBmZshft-3LaMKejjlgx3flfCHgsaPrSJwKmL8KcxvI5hs8WEF1FY-JUBaLHcfqCzAb59sQ_KxJSxhxutGtVXvonpo0wS1nFSj8p9h8n4JP7tCa0cbxQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"128-148","volume":""},{"id":7030,"author":"刘凌","title":"关于水字历史的思考","abstract":"水书和水字的历史缺少确切文献记载。从水书中汉语借字的形体与汉字楷书体、小篆的对应,从其读音和汉语中古音的严整对应,可知水字借自汉字甲金文说是一种误解。从文献记载、民间传说,从水族周边相同族源的民族的文字和历史,从水语所属的侗水语支的独立时期,我们推测水族形成为单一民族的时间、水字产生的时代不会早于宋代。从水书内容与道教文化的相似相通,从道教文化在水族地区流行的时期,从水字自源字的特点等,我们认为水字的原始面貌是一种由于宗教原因而导致的错觉,水字更可能产生于清代。","categories":["09_其它"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJPVhguAtBE_nzc5KOAfiJ1c7Xsjmyi3XBd5BRQN-AdsjI9XZZ5fhqcfQax3olF1TfeWWD7nNwcfaF_nfF67JnjbXDBwzi0jI1mBR83IqjKZYCTSeUDhTJ5kAm9Qb2IJwWwZFbcg5IKOHFnjFfzrGegpmZwhD_wT8A1DhsgEd96lA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"273-281","volume":""},{"id":7034,"author":"何景成","title":"20世纪关于族氏铭文性质研究的评述","abstract":"20世纪学界对于族氏铭文性质的研究主要分为两个方面:1.族氏铭文所代表的含义;2.族氏铭文是否是文字。本文从这两个方面入手,对学界关于族氏铭文性质的研究情况作了一番评述和总结,认为族氏铭文是家族的代表符号,相当于周代的氏,族氏铭文是文字。","categories":["09_其它"],"year":2007,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLXkyh8obKslPW8YYU-B8_ZBtgHsEv_k1-uVbym9iAXZ_OTCl5lvGkJYQ4sbL3CcI11acRR4O1ZZu3K5LjhN4e2LNJ8XBOKCqM8F-YHrKnzShH4FR_qqrWai6fSW2dtf_Tzbcqiet7a3HU2vcmmOjb59hFyq_2RNDyFjlvMFRDcvw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"128-133","volume":""},{"id":7042,"author":"李晓静","title":"简论古代汉字发展中的省简现象","abstract":"省简也称简化,是汉字发展的诸多历史阶段都普遍存在的现象。文字是书写符号系统,追求书写的简便以提高效率,是文字的重要功能和人们的共同心理。所以,为了便于掌握和使用,文字符号要求越简单越好,其主要结果就是出现字形的简化。本文将古代汉字发展中的简省现象分为偏旁部件的省简和笔划的省简两个方面予以分析。","categories":["09_其它"],"year":2007,"publication":"中国科教创新导刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL_rfsLVT0LgxF_QodXP71qXman3_RqBbyAk7I-4lfjTSC05K0wz1DMR5yhDhjGs_DtrHb15GPS9TcF4TMPi0fgsGkVV9mfTwmcYD1m3fweZIJqgQ_3g9_5_NB3kRatrbldYquoe8ibBC310GhvrP_2ka4R_rKalxvpf_ZXipW--w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"171","volume":""},{"id":7051,"author":"葛志毅","title":"中国古代的记事史官与早期史籍","abstract":"在古代,由于编年记事方法的出现,真正意义上的史官才能因此而产生。中国古代的史官早期偏重于记言之史的性质,其后经历了向记事之史的转变;相应编年记事方法的出现也经历了一个演进过程。以此为标志,史官始以纂录史籍作为职任,于是有《春秋》等早期史籍的相继问世。本文拟对此涉及中国古代史官制度与史籍编纂史上的问题,试加探讨。","categories":["09_其它"],"year":2007,"publication":"史学理论与史学史学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJvghoJ9jQXVuEhPdhfWWZIRP1MRSTNX_NQk9DDRbO1_JyLkAieY_nn8IHqtYQFQoTEDsX0Hpg2UCWIO7oI9Cnw9MiZa5kFxZexyw5T4MqPMKz-Iw1pNW2cASkTvyLgOy3ZrJ3uv8Ng9gDvgGbGXDX3lob6hFGaXGf1_QrjclpB0Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"107-120","volume":""},{"id":7059,"author":"张向民","title":"20世纪战国文字研究述要","abstract":"我们所谓的战国文字,是指春秋末年至秦统一以前的时期内各国使用的古文字。战国文字是古文字学中形成较晚的分支,但发展迅速,在20世纪初逐渐兴起,到20世纪末臻于成熟,论著繁多,本文仅从铜器、玺印、简帛、陶器、玉石、货币等方面总结一些主要情况。","categories":["09_其它"],"year":2007,"publication":"现代语文（语言研究版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iItFJd4DTWpEx3YMqgZdCYM4aKELaqeL4hDfbX2Uw_o9g2txbHxXjFf531zRKyiTOzUBgU4v2Ii0T6r61GbpOO-BkBJwrSFbsM_PYixF_BXEQAlW7Yr4YlyCedAvEK1jdfFl1_zgbfTQQp8SrDCx9djLSUp2t8yo8x_t3f_o0cJk2F4MLfzJnYu&amp;uniplatform=NZKPT&amp;language=CHS","pages":"119-120","volume":""},{"id":5718,"author":"周光庆","title":"汉字文化意义考释方法新探","abstract":"汉字的形体结构中往往隐含着深厚的文化意义,可以说为中华文化的一种类比性表征。本文在前人已创的方法之外,进行了汉字文化意义考释方法的新思考,提出了字词参照考释法、汉字文化互证考释法和系统比较考释法。","categories":["09_其它"],"year":2006,"publication":"江汉大学学报（人文科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iINANuWMW9nrVcIFdjtoXres8WvVmcBgm-3vEbTR-n8fUf8WzPmWfe1AFp3YwtGcHhh745VuilrvPRjWQqqYt1QMGY4TBh-7t1YFK2pgn7L3BFnz0NuY8TQLNJQOOO5yVM_7QGoa7AEp_JLCVtCn3DloasL9TjXwFuucaK9HgxMQw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"39-47","volume":""},{"id":5726,"author":"刘玉堂; 张硕","title":"曾侯乙编钟与中国古代艺术和科技成就","abstract":"曾侯乙墓出土的器物以及器铭文字资料数量众多、品类齐全、保存完好、内容丰富,被人们誉为世界音乐史上的一次空前发现,具有极为重要的历史、科学与艺术价值,是我国先秦音乐考古的一项重大成果,被我国考古学界评定为20世纪中国100项重大考古发现之一。特别是曾侯乙编钟的发现,不仅展示了中国古代文化的辉煌成就,而且在文化、艺术、科学技术诸多方面代表着当时世界同一领域的最高水准。","categories":["09_其它"],"year":2006,"publication":"武汉大学学报（人文科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI0xzEeyBPs7w-GO2JhGnX0eOKjz2JjKaG6CmMm0kGQnt3eUsCTpJXTHt5vS8YK_rUiyS_BzdIwEktaqyHRlOsLCE8cmp2ywZCDqCzLztyTgV2uJYj1A1atccMfJZSBmFHeWbWVD2loytS5vYJnURfIFWbQq4q_b1k9Ddr4rOv_-g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"593-598","volume":""},{"id":5727,"author":"杜迺松","title":"全国青铜器所见伪器伪铭考(二)","abstract":"2．真残器上加伪作部分,复原成完整的器物山西晋祠博物馆收藏一件商代曲内戈,“曲内”部分僵呆,是民国时期加上去的,戈援部则为商代真戈的遗留。山西省某博物馆收藏的一件铜豆,原残器仅留器身,伪作者加铸一圈足。还独出心裁地在器身上一侧加一鋬,这是违反常规的制作。器内还伪作了几个伪铭。甘肃省兰州市博物馆收藏一件铜觯,器身属真,盖是后配的,便成为一件完整体。盖上的花纹亦不清晰。","categories":["09_其它"],"year":2006,"publication":"艺术市场","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJawr0ehfFDuj4JOv_TblHvcVhv0FWjT9l_kbScR-cNwPJboayLsMyMlq-ez0mlrdyOH_ElX2OTGpm2wrHrKVnF02vF93-tlH8ceR3Skx7o4SVfPBacLCvFl82mWbZmxb5JoVKA0d7pDXpFa3nth8bw6hB3Ux4nFeOVKl4XJQPfhA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"52-53","volume":""},{"id":5730,"author":"冯盈之","title":"汉字中的古代服饰考释五则","abstract":"与衣服有关的汉字数以百计,其中,有些字如“的”、“袜”、“踊”、“胜”、“婴”等,虽然看起来与服饰无关,但其某个义项却记录了古代服饰的风貌,为研究我国服饰文化提供了难得的资料。","categories":["09_其它"],"year":2006,"publication":"广西社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIBqT6G-vflNFtA5eQWkXQKBT7coU8_5nwiRizR1Wn_QCkfRzeAw10ucy-dhmda7TCCoYTLuRSliG9a7CE5HvprrWWz4EV4pt_gDTXL1FF13kpjkvu0d9WpB8_jzkmU_xl5vuTWwFslcG5B5HdzUTErdbozVeckh812XO9K1lMGjQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"147-150","volume":""},{"id":5736,"author":"丁进","title":"青铜器铭文创作与个人写作传统","abstract":"青铜器铭文从铭刻作记号,到记载历史事件,再到抒发个人的感受,金文一步一步走向文学,终于在西周中期形成创作高峰,在青铜器皿上制作长篇铭文,成为贵族们竞相仿效的时尚,铭文创作已经超越了实用功能,具有审美意义。铭文是最早的私家著述,它开启了私人创作的传统。商周金文是目前所能看到的最早的个人创作。","categories":["09_其它"],"year":2006,"publication":"韶关学院学报（社会科学）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iItHbU0pNVGJm7z6deRjBjG6IXQZ00zj7S7vPAXCVFoRgxUtCpEdl3glVL_vFWiQJTrh4uD4Dg9NeHo_mkMJux_fIq1wVwDX-XnacvKkZZYNsb6gk7NKC8mBB_qVs0ce3fApoz0t40dm63-WvpSb95YHgKJgJRIhANWZlumDrr85Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46371","volume":""},{"id":5737,"author":"程光耀","title":"相对独立符号“-”在古文字中的能动作用","abstract":"相对独立的符号“-”在古文字(即隶变前的甲骨文、金文、小篆等)中的结构性质,一是可作部件,二是可作准部件。这种符号“-”在古文字中的结构功能既可作象形符号,又可作象意符号,也可作指示符号,这些是其主要的能动作用;其在古文字中的长短、位置、多少等有时也有着一定的能动作用。","categories":["09_其它"],"year":2006,"publication":"新乡师范高等专科学校学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJPCV_aeXhivYc01FOI7xWpPePcl8g05a-GOGw3tLQrvxVRHEpFlef_OXnZbXjs4iOkKCTLJQLnR3f7QyFQdli9yzxWWRaj8SoKjTAy_2CKx1aQuby9Lg9RP4YOoE0a1NWr_kmDf0u3xsN34ecmucTO0g2AWvSZePAA5Cl4HdVgPg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"128-132","volume":""},{"id":5738,"author":"温慧辉","title":"近二十多年西周法制研究综述","abstract":"","categories":["09_其它"],"year":2006,"publication":"中国史研究动态","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJRxoqHrzASzDAiQHbCziDGMHIqlEB3zAf6j3nAsZJNx-l5-4BmaiWvDUtWdWhomk08QArsRZiEpEmCLT3uHF8F_BXMclTq1ojAwwLi0HEAde4aF_GwL4eSa2vm2ePBWolzr5leYa1vNBlj7nDobW1iNZRCxZbJcLI5fZ3pkmeaBQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46279","volume":""},{"id":5746,"author":"张富祥","title":"“走出疑古”的困惑——从“夏商周断代工程”的失误谈起","abstract":"当下古史年代学研究可行的路径,仍应是在古文献“文本”的基础上多方联络和考证,力求将已有的年代系统调整到能够为大多数学者所接受的水平上。夏商周断代工程不由此途,而将主要精力放到非文字史料的调查和取证上,所得结果大都不可据。工程所提倡的多学科方法带有泛科学化的倾向,由此导致年代学论证上的一系列失误。这些失误表明,作为工程的指导理念,“走出疑古时代”的主张以及“超越疑古,走出迷茫”的提法,在理论上和实践上都是不妥当的。","categories":["09_其它"],"year":2006,"publication":"文史哲","link":"https://link.cnki.net/doi/10.16346/j.cnki.37-1101/c.2006.03.004","pages":"19-30","volume":""},{"id":5747,"author":"叶正渤; 陈荣军","title":"叶玉森古文字考释方法浅论","abstract":"叶玉森考释古文字的方法主要有以下六种:(一)注重字形分析,特别是据偏旁考察释字;(二)注重从辞例文意考察释字;(三)注重与其他古文字的比较释字;(四)注重从甲骨文的初形溯义,通过理解古人造字意图进行释字;(五)注重从甲骨文本身的谐声系统出发,利用古音学知识释字;(六)注重分析甲骨文中的合文、析文、倒书释字。叶玉森的甲骨文研究对后来人们系统提出古文字的考释方法,产生过一定的影响。","categories":["09_其它"],"year":2006,"publication":"江苏大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.13317/j.cnki.jdskxb.2006.03.012","pages":"74-78","volume":""},{"id":5761,"author":"潘玉坤","title":"总结·提高·开拓——古文字工具书编纂国际学术研讨会综述","abstract":"","categories":["09_其它"],"year":2006,"publication":"辞书研究","link":"https://link.cnki.net/doi/10.16134/j.cnki.cn31-1997/g2.2006.01.025","pages":"161-165","volume":""},{"id":5766,"author":"刘中富","title":"金文语法研究新突破——读《西周金文语序研究》","abstract":"上古汉语语法研究,应该说已是成果颇丰,基于传世文献语料的研究尤其如此。但同时也必须承认,某些方面的研究依然明显不足,成为制约整个先秦汉语研究的薄弱环节。比如,西周青铜器铭文的语法研究,上古汉语的语序研究。对于被孔子称为“郁郁乎文哉”的周","categories":["09_其它"],"year":2006,"publication":"中文自学指导","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL0BO_TK2f0r5TsdXXkySNIiYvVX_hZnGTogKF2pxnPV1mSXKbxT3wPe62CMbXY6fw_SxPCxT57RT2XxcdeX-rbTMrDO2aQbve1uaVAPgNgUTeh17omSgTCk_3yUUC7lPY09mOCoNSnhjpC_mEJoiqhxJjor345AxTrJPPlkC6bDg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-61","volume":""},{"id":5772,"author":"徐卫民","title":"出土文献与秦文化研究","abstract":"由于文献资料的缺乏,秦文化的研究受到一定的影响。考古发现的秦简牍、封泥、金文、陶文等,反映了秦社会方方面面,给秦史研究工作者提供了难得的资料,极大地促进了秦文化的研究,使很多历史上难以说清的问题迎刃而解。","categories":["09_其它"],"year":2006,"publication":"河南科技大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.15926/j.cnki.hkdsk.2006.01.001","pages":"46154","volume":""},{"id":5773,"author":"李玲玲","title":"中原地区出土古文字的历史研究价值浅析","abstract":"中原地区出土了丰富的古文字资料,这些资料对于研究古代文明起源及上古历史发展具有重要价值。一方面为研究中原地区上古文明的发展历程,提供了一个较为清晰的脉络和线索;另一方面这些古文字资料本身就是一套较为完整和系统的先秦文献资料,有效地复原了上古时期中原地区的历史发展原貌。","categories":["09_其它"],"year":2006,"publication":"平顶山学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLGZFLEzXnOhjUIGF0yABfjl10WVSVaqO_UYm2yoWaHAznbLkG_A3S_RrdfRx5n-B6t0MdSjUYnk1DSp79l4GwmD_me6WFLIQQixMkgp2hGI8kawtZRBM60LPnmgjJMTqP4-BaZxh-MjpDa1L64BNQ5825f7gs0kBax_PptG6j--w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-63","volume":""},{"id":5774,"author":"刘世彬","title":"莫友芝对水族古文字的研究","abstract":"当前水族古文字研究已成热点。而早在清咸丰庚申年(1860)四月,莫友芝就已于《郘亭诗钞.红崖古刻歌》中提出水族古文字“初本皆从竹简过录”,“云自三代”,“核其字画,疑斯篆前最简古文”的观点。这是目前所知研究水族古文字最早的史料。","categories":["09_其它"],"year":2006,"publication":"黔南民族师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iINHlxreXXkBAJfpJVBgh4fRwE_3bUycdy49jBY8C64wRQ2spV35iXXTU__5gfMoJJGWwxJ4ib9jLobOkJQDRSZ-16dLf0HLAqejxMHvEedo7ujWUHktxw0g4zEtPWKgNpuU0faFoEDPTcz7mz7U43R441azCmtWgbE6Znk9ONXrQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"16-17, 41","volume":""},{"id":5778,"author":"杜迺松","title":"全国铜器鉴定所见伪器伪铭研究——兼论鉴定的几个理论问题","abstract":"本文主要依据20世纪90年代国家组织的全国文物鉴定系统工程中, 所见青铜伪器、伪铭的典型资料,进行较全面的研究,依其伪作内涵,对器体、装饰、铭文等伪作的种种表现,以及伪作中相互交叉的各种情况,尤其是对伪作铭文的多种方法和内容的复杂性给予了较为详尽的叙述。对伪作铜镜特点,也进行了阐述。文章还从理论上论述了有关青铜器与金文辨伪中的几个重要问题。其中如伪作溯源和历代伪作主要特点,辨伪的理念与方法等,均具重要意义。","categories":["09_其它"],"year":2006,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2006.01.001","pages":"6-23, 157","volume":""},{"id":5779,"author":"周晓文; 李国英","title":"建立“信息交换用古汉字编码字符集”的必要性及可行性","abstract":"建立“信息交换用古汉字编码字符集”,对于古籍整理及文字学研究等的现代化建设有重大意义,是实现该领域现代化的必要条件。从古汉字的特点、字量、分类及编码方式等方面,讨论建立古汉字编码字符集的可行性,认为对古汉字进行单独编码是完全必要和可行的,综合分类法应是优选的分类方法。","categories":["09_其它"],"year":2006,"publication":"北京师范大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJjqqv072-K544ryWAtsbMXquuqbUqEmJFYoYAUb4CjNtGT9cjDEFawZyb9AvEQydF8epEoGTdcMcx-GRYpuC3qag2h5qqSYHbMiWW_5DC9FlekbobLawu51imq9PFcVVxJfZvuPN5xTjH8HCwWVd3Gc7bO8h45neAq-RKnIxDkXw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"77-81","volume":""},{"id":5784,"author":"张懋镕","title":"一部令人惊异的好书——读《新收殷周青铜器铭文暨器影彙编》","abstract":"今年五月,我应台湾中央研究院历史语言研究所之邀作短期访问。事后,朋友们问我:阿里山去否?回答:没有;再问:日月潭去否?回答还是没有。问者感叹:那你做什么去了?我说买书啊!此次台湾之行的最大收获是买到了一套刚刚出版的由历史语言研究所同仁编辑的《新收殷周青铜器铭文暨器影(?)编》(下简称《新收》),我非常满意,因为这是一部我心仪已久的书籍。","categories":["09_其它"],"year":2006,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI4NQmUjBfnhsCRBb6_vjbuh8EWxeb5a2wP1rvDi6N4obYZKzdxc_QPu_7f5ecFqkuk72MUhI9ux5K9NX51pFfHv0vCCGl2legJrPywtRAIuO84dwzLwEV7tFN_1Gy0sCiosITvi2RW1a08BDcbTLCUn9ZfqK9B6Ud90MxzW6dwIw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"80","volume":""},{"id":5789,"author":"商志(香覃)","title":"《殷虚书契考释》“王著罗窃”的由来及驳辩","abstract":"《殷虚书契考释》本罗振玉之作。一部分人却认为是王国维所作,罗是窃取者。然据多方真实可靠资料可知,王著罗窃之说十分谬误。漏洞百出,不可凭信。","categories":["09_其它"],"year":2006,"publication":"殷都学刊","link":"https://link.cnki.net/doi/10.16140/j.cnki.ydxk.2006.04.003","pages":"46250","volume":""},{"id":5803,"author":"杜廼松","title":"全国青铜器所见伪器伪铭考(四)","abstract":"一青铜器与铭文辨伪的重要意义青铜器与铭文的辨伪．是青铜器与铭文研究不可或缺的重要组成部分。众所周知．所谓青铜器鉴定．包含的内容是多方面的．从广义讲．包括青铜器与铭文的各个方面．如:造型、装饰、铭文．定名、铸造、真伪、时代、价值(主要是历史．艺术、科学和收藏等价值)、级别等．内容十分丰富广泛。如果从狭义看．青铜器与铭文鉴定．主","categories":["09_其它"],"year":2006,"publication":"艺术市场","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIFr1GaSTB1nnbecWNEklqKgF8NiZ_Aanb2QzgRdLl3QrdNoYF_aUu4awT38Co0eLto_Ywt00bDnLT2qDPadTXFXtLde2RGXCCgLcXG-MExxFTK6w4iJbGvBMoZQzyXuSgLE77h4zhwvzqN25Xpsy0HhwjWe2_0-MLq4laNZCxJ7g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-71","volume":""},{"id":5817,"author":"王元鹿","title":"十九世纪末以来的汉字发生研究的历史回顾","abstract":"从19世纪末起,汉字发生研究才真正成为一门科学,并在此后的一百年中得到了相当的发展。这一课题的研究可以分为以考古实践为出发点及以理论文字学与比较方法为出发点两类。在研究者的努力下,这项研究取得了多方面的成果,同时也有相当的不足。","categories":["09_其它"],"year":2006,"publication":"内江师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIZJtkfvyzhmUvnrSsCpAqBP8KCFxC74L1bRpmn-_I2JKpMmgD6rKuF29deTsuMA2VPFtlZ6h2wwaUlClxT4iW_0Ah4g5Mn8QbP6Zn_mRHq4jIqlBSTMEIGfWKEAchhJWDPh2bgVNJsKbqL-z7cF8-RBnQxFydruY_UnEL9a8n74A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"72-78","volume":""},{"id":5833,"author":"王祖龙","title":"金文“楚化”及其书史意义","abstract":"作为上古楚人的官书,楚金文的出现是楚人以自己地域文化的审美眼光对宗周金文进行“楚化”的结果。金文的“楚化”不仅表现在用笔、结体及构字法的变化上,而且还表现在楚人对大篆字体的变形、草化和装饰美化方面。“楚化”使金文具有了鲜明的地域性、装饰性、抒情性等特点,也强化了书法的书写意趣和笔致韵味,极大地丰富了金文的表现形态和审美趣味,为汉字走上艺术化道路迈开了决定性的一步。","categories":["09_其它"],"year":2006,"publication":"长江大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKNa_s9BVdinChn6MYY8U4NHyCoquy_rgqFDab3m39MC9w02wOsJZYVU_PvtYKsNQh1qQrstU7dXBLVrpuguJGd_XhHDThyK0f5VgNJpT4Eu4NvwrdUqtYp0DX86t7nTc7BU3oeVcn8KBTh0IBEVHdOQ7ghk7gfy4dtLXcTJVE1eQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"119-122","volume":""},{"id":5838,"author":"邹芙都","title":"读《楚文字编》","abstract":" 楚文字是中国古文字的一个重要组成部分,据现有资料,其起止时间上承西周中晚期,下迄秦灭楚之际,延续时间达六七百年之久,而就楚文字风格而言,则延续时间更长,如汉初马王堆帛书仍沿袭了诸多旧地遗风。对楚文字的研究则可上溯到北宋时期。当时楚公逆钟等器物一出土便受到极大关注,后历经元明清,其研究得到进一步拓展。1949年至今,其研究广度和深度均被向","categories":["09_其它"],"year":2006,"publication":"考古","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIZU9UmczxQczXDcfumNAoYPQEn_qUPimv7QG-nbhZaxOldSZ-Oswg2sQ7KRIb5bgvQOWE0-eBRLINIJ_vZIBmjxPtSCaygYHUpG2XxrLNWaT7qisHcyA1lebI2xLSqMXi3IraavYqwUh4zNXYuOY5i05YrEsGuUb3HlIjTFZYNzg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"89-93","volume":""},{"id":6485,"author":"张玉梅; 许嘉璐","title":"王筠汉字学思想述论","abstract":"王筠的具有中華民族特色的漢字學思想以較為科學的語言文字觀為前提，以六書思想為框架，漢字取象思想、形聲字思想、漢字發展思想、古文字思想及其成就是其主要的組成部分。本論文即以这四個方面為主要内容，整理和論述王筠漢字學思想的面貌，以期給王筠以文字學史、訓詁學史上的應有定位，有助於今日漢字學理論的探討和構建。漢語是漢字產生的基礎，古漢字是古漢語的記錄，所以考察漢字應該從漢語這個源頭上進行。王筠的漢字學理論大體上是從這個較為科學的語言文字觀出發的。王筠的六書思想由指事、象形、會意、形聲、轉註、假借的正例、變例組成，是其漢字學思想理論的框架。王筠的漢字取象思想大致可以概括為7種取象方法：物形法、意形法、借代法、比象法、順遞法、竝峙法、義類法。運用取象思想，王筠指出了《說文》常常據字形解字因而出錯的原因，並以取象解字的思路對《說文》等書解錯的字例做了糾正。王筠的形聲字思想突出表現為：指出形聲字是漢字早期","categories":["09_其它"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJxM_DqoLxl2OFDOJDg7x3krl7rPyQwYditMD_3Jb-6Ia1YJQ5iBKGXZwxOAuaqAa49sat94QomkR49ouYK3pOMkFwY0dKzYh_lHKJD9_TJwc_xf46U8gl2xaxU_7yzXtUd3dOWCbNnwYepMcZxb30mD6BRuKHS6BYXtqmlS8KHMUSgVOgP193h&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6492,"author":"何瑞; 臧克和","title":"宋本《玉篇》历史汉字传承与定形","abstract":"開展中古時期歷史漢字的定量調查研究，對于清理古文字到今文字階段的傳承演變類型和規律，建設符合中國文字發展實際的歷史漢字庫，都是不可或缺的重要環節。《玉篇》作為第一部的楷書字典，改變了《說文》以來字書上篆下隸的說解體例，并成為後世楷書字典編纂之范例，在漢字史上有著不可取代的地位和影響。《玉篇》是現存最早的從古文字到今文字的歷史漢字總匯，它以楷書形式將各個時間層次積淀的歷史漢字收集整理并予以定形規范，成為研究中古歷史漢字的重要坐標。宋本《玉篇》貯存的歷史漢字是經過歷代整理規范的，對漢字字形的規范化具有實質貢獻和指導作用，但由于宋本《玉篇》文獻結構和歷代整理情況復雜性，内部文本層次不易劃分，故各家的研究多是微觀著眼舉例說明，缺乏系統性研究，亦難以做到定量定性分析。我們對宋本《玉篇》歷史漢字的研究，主要解決了《玉篇》内部文獻系統的結構關系問題，調查了宋本《玉篇》貯存的歷史漢字不同時間層次的新增情況","categories":["09_其它"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKZbWx1vQQ2W-x2vcjOUWOYknXSMlOD3GOyW-20IO2dQ3xtF0AIg5Wkgkadp6VcwCKu7xDuKKu3QSoqYzn4fimQhl_TbZDSuld1sEAamGzAqimAsCE_S_WEu_VBLS5t7JYVgVZ4GCJ4_NIBEf2l83Wic6LkQytdcz70fgikJN3a_ssHEbfHSbbu&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6858,"author":"赵岩; 付亚庶","title":"几组上古汉语军事同义词研究","abstract":"古汉语同义词的研究近年来取得了长足的发展,在泛时研究、断代研究、专书研究中都不断有成果涌现,成为古汉语词汇学、训诂学研究的热点。但古汉语同义词的断代研究,迄今还是一个薄弱环节。上古汉语即先秦两汉阶段的汉语是汉语发展的源头,对后代的语言有重要的影响作用。军事词语在这一阶段已经形成系统,并且极为丰富。因此我们将断代研究与按义类研究结合起来,从上古汉语军事词中选取一些同义词进行研究,希望在得出几组有价值的辨释结果的同时,探索一条断代研究途径。我们选取了17组同义词(包括一些附及词),以组为视域,先证其同,然后分析其差异特征,在注重共时差异的同时,还从历时方面考察了一些同义组的历时发展变化情况。我们发现:研究上古汉语军事同义词离不开原文献、古今人们的注疏和前人的古汉语词汇研究;各同义组成员的语义类别不同导致差别特征的不同;就表示人及其动作的同义词来说,由词汇意义差别所体现出来的语法特征往往比较明显","categories":["09_其它"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKvl9E4oU_NvIFE9opeNFiaYSWxovGbFAKRsCkNFDPvv2_WMV8MnBLFlNWnG_SUXoZZ-u8SH7RnTtYub0cUNvvu8_wk8u4_fRHJZFj1BIquyOReSkgURErJ2B2f5iOrOiTAcox9c_1VXVQRMIZl0a5P6DZDRgtn551Vlfgx0hvvgsHm2D8Y1Zfc&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6861,"author":"董治刚; 陈顺芝","title":"汉字记号化研究","abstract":"汉字属于表意体系的文字，造字之初，“因义构形”，形义关系非常密切。古文字阶段的汉字保持了汉字的象物性，它的构意主要依靠形符体现，古文字中的意义信息非常明显；今文字阶段的汉字虽然失去了古汉字的象物性，但汉字所表示的意义却被继承了下来，因此，意符体现了构意信息。汉字在发展中也发展了自己的音符系统，用来帮助识记，拉近了汉字与汉语的关系。汉字从形成过程的开始就吸收了一些和所表示的对象没有内在联系的硬性规定的记号，在发展过程中，一些意符和音符又不断地失去表音和表意的功能，变成和整字没有音义联系的记号，记号部件和记号字不断增加，因此，汉字的发展表现出记号化的倾向。本文针对记号的概念以及记号和意符、音符的界限上提出了自己的观点，着力探讨了记号在古文字阶段和今文字阶段的产生和发展，力图从记号部件和记号字不断增加的事实中揭示出汉字记号化的倾向。","categories":["09_其它"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJiZz9WNiEBTaaSNlz8nSxF0g1WSU8n3VgnS0YVM67kb3yUAgc8OTKLJ5T_Em1YmwQ-3RHuHZL2dWArqnhxehDhD8_jQrQqhv0iiFG0m0zS8h9lTvhKZY6Sc-rzePrMzAWV2-5bntM8uLHmhOtH_ITU2aY4M2eG-CulDwBcEMvaeZ7mZTbYlgH-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6862,"author":"魏灵水; 刘信芳","title":"汉墓出土遣策选释","abstract":"本文分为上、下篇：上篇是汉墓遣策出土及整理情况概述。这一部分主要从两个方面进行论述：一是概述自上世纪六、七十年代以来，我国所出土汉墓遣策的总体情况。并用表格的形式列举出来使大家一目了然，以便于对比研究。并根据出土遣策的内容，把遣策大致分为以下几种类型：记录随葬的物品、记载随葬的物品和葬仪上用的一些物品、记录随葬的衣物、自题名称的等几种。二是从出土情况、整理和研究情况对几种重要的汉墓遣策作简要介绍，主要有以下八种：湖南长沙马王堆一号汉墓、湖南长沙马王堆三号汉墓、江陵凤凰山8号汉墓、江陵凤凰山167号汉墓、江陵凤凰山168号汉墓、江苏东海尹湾汉墓、广西贵县罗泊湾汉墓、湖北云梦大坟头1号汉墓遣策。下篇是本文的主体部分，主要是对汉墓遣策作分类选释。这部分以汉墓遣策内容的某一家考释为主，对其中一些遣策的考释提出讨论，在讨论的基础上得出自己的看法，并用按语的形式提出笔者的见解。在遣策器物分类的问题上，","categories":["09_其它"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKJHOSx_5u9MXmbRb374dwUSjyoWcq9sF7KYtmef5TeXU9RJ2suWyCK8KjiOnyF7-C7_P_nruCWt7lbDRkSHcmHhdUxC2pB_YKWFjR5TdO0EVG489My9RvrVze_rO9fFGlY0QNtkUvNMyaEauAwS7E6JFu8jUuLTS0Ujf0gJhvFYipy8Twh0XWg&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6868,"author":"孙英梅; 阚景忠","title":"唐兰先生文字学理论研究","abstract":"唐兰(1901-1979)是较早从建立古文字学角度来研究古文字的古文字学家,是现代科学古文字学的奠基人。一两千年以来,汉字研究一直缺乏系统的理论性专著。唐兰先生的《古文字学导论》和《中国文字学》填补了这一空白,具有开创之功。其理论研究和学术实践,不仅奠定了科学古文字学的基础,也开启了古文字研究的新风气。对于唐兰先生的深入研究,有助于后来学者吸收借鉴其理论成果,灵活运用其研究方法,秉承发展其治学态度,推动文字学的健康发展。建国后出版的一系列专著,对唐兰先生的文字学理论只是间或论及,缺乏系统深入的分析研究。本文采用描写的方法,对其文字学理论研究成果进行综合与评述,看看他是如何在继承前人的基础上建立起自己的理论体系,以及对后人产生的影响。本文的大体框架为:引言部分,简要介绍本文的写作目的、研究方法、主要内容及创新之处;第一部分,唐兰先生生平及文字学著作评述,介绍其生平及文字学理论、考释著作;第二","categories":["09_其它"],"year":2006,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIul4YRV7PeAccMH8zhTg_WV1mzaNKQvbjtUgNxQhvSWhb1CRikc3zI5sBBUg9-5Pfr6PU4OraWyKWl07NDVEiZVHGjALvIzUM602RdsunQgneZBVNwPEt6Va-TOhy6zWe3eRaAs-UT-3K8QY9M_iJesHKBKCX7m93zoE3KtPE59HzEeNXio2J5&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7074,"author":"虞万里","title":"商周称谓与中国古代避讳起源","abstract":"传世先秦文献和出土文献所反映的实际称谓与礼书记述相一致,呈现出上尊下卑的规律。&quot;字以敬名&quot;、&quot;谥以尊名&quot;和尊而称爵、讳而不名等形式,都承自遥远的珍名心理,是在等级森严的君主社会中的曲折反映。国外人类学、民族志和我国近数十年的考古资料,展示出原始民族惧怕鬼神和巫术的避名心理。殷商已将这种语言和心理隐约地体现在庙祭文字中。周人继承殷商讳名习俗,经过损益,纳入礼制, 先贯彻在丧祭礼中,随即与丧服制度结合,讳及旁系之亲,最后渗透到阶级社会中,形成绵延两千余年的避讳制度。从礼制角度揭示殷商庙号日干称谓之所以多用柔日,应与丧祭中的虞祭、卒哭、拊庙礼有关,日干称号即刻于庙主背面的拊庙日记号,这对争论不休的商王庙号研究无疑开启了一条新的思路。","categories":["09_其它"],"year":2006,"publication":"传统中国研究集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL0ZOVn7RXPzgPYJMvOsm2mgOyZHw70AhHYdBL-p3fau7-CcoWQfv5Td-LDMwHYVfeLw8WKMSsSNjprf7yhjZDRM31U3RkqlXqgqvoUZis-i4LMEAyba_7_KA2XGbiU-pVBcRPpEjuK5tCydjlqxQwbm_Szeiky9xYJxJQQNhIW3w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"110-183","volume":"1"},{"id":7083,"author":"夏军","title":"从系统论视角看《古文字诂林》","abstract":"本文从系统论的视角,通过研究《古文字诂林》内部字形系统和考释系统之间的层次、结构及相互关系,揭示这些要素是如何相互作用、相互影响从而呈现出系统的整体功能的;通过研究《古文字诂林》与外界环境的关系,确定它在文字学和辞书学领域的地位和作用。","categories":["09_其它"],"year":2006,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJgLFEWh0WBTTExkDZhQs-gHM4LvFM7PKZp9Ju4t1kxxvKBvx1PVP8aPyS-wGTM5ZOX1w-2CorPymjVUhsXnoWto7dmvgBdyKz1xa1FbhSSrOHPug8Y8iyn8WsIyPInzyi9QWKHw3nb-CMx-1usoJEYEz1MuS750e2fTvg2TbNlpQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"27-32","volume":""},{"id":7084,"author":"詹鄞鑫","title":"20世纪的中国古文字研究综述","abstract":"20世纪的中国古文字学发展迅速。古文字领域包括甲骨、金文、简牍、帛书、玺印、古陶、古币、砖瓦、石刻等,敦煌文字也属于广义的古文字。","categories":["09_其它"],"year":2006,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJgLFEWh0WBTTExkDZhQs-gHM4LvFM7PKZp9Ju4t1kxxvKBvx1PVP8amqbsHETlxeFHbL82may2WSsp5E96_V1BRW6yipKyRktxLW6-A4lqNwwPeR5Bd1Vus1jLqxUrENF0GvrkIqj59QvKCee0ekJ1vcK6Y8yG8gpLefCGZFjNYw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"125-138","volume":""},{"id":7085,"author":"朱刚焄","title":"80年代以来韩国的中国古文字研究述略","abstract":"20世纪80年代以来的这段时期在韩国是研究中国古文字的重要时期。现代学者在总结以往的中国古文字研究成果的基础上,又提出了很多说法,取得了可观的成绩,为古文字研究走向成熟奠定了基础。本文评介80年代以来在韩国对中国古文字研究的主要状况,必要时,也涉及70年代甚至更早的某些状况。本文拟从三个方面,即甲骨学研究、金文研究、《说文解字》(以下简称《说文》)研究,来做一简单的综述。","categories":["09_其它"],"year":2006,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLxfW5imyEBvyTQFAY2LLjvc3Js3LIzDtMvU9t8VxoidmJgPpux9IMdzLCV5U9GVvQjv1xb9cD3SidKdKnD_--QdIYPzde0sPXpZ-VnoRtb1zT0wMU1aLtyJ_ilGkUc2IGSExJkpFZ7g4SmAlD1TyQz6mrK8H87BgAj7XtwUJg41A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"262-264","volume":""},{"id":5846,"author":"靳永","title":"试论《在昔篇》在古文字书法学研究中的意义","abstract":"清代学者杨沂孙的《在昔篇》是古文字书法学上的重要文献,是古文字书法学独立成科的重要标志。杨氏手书拓本对这篇流传极少的文章进行了录文,从而为书法学特别是古文字书法学的理论研究提供了重要史料,为杨沂孙的古文字书法学理论探讨奠定了基础。他初步总结了古文字书法创作和研究的历史,明确提出古文字书法的创作要与古文字的研究相结合;古文字书法学的研究要与文字学、音韵学、训诂学的研究相结合;古文字书法的研究和创作要取用新材料,用不断发现的古文字材料来丰富古文字书法的创作。","categories":["09_其它"],"year":2005,"publication":"山东大学学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI94VKqF03mtCpP6aCtlOl6xtspeC-A3aM-un9dwOllCVjx_O35ZCnYdYgN6J7jyEQEYxhK-N0lc1cPOqmBu94MMlAGhJ6o4jemW99toqAdVQq7OOz3e_lqp1ZQKHuyU_G2TpYeUozDcYRCeoO_sU4fPgQCGzSaaSwSx-3fxLUE_g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"156-160","volume":""},{"id":5862,"author":"萧世民; 萧红艳","title":"也说叠用符——谈叠用符的历史沿革及“正名”之必要","abstract":"史有为先生的《叠用符刍议》认为中国人使用叠用符始于金文时代,并且考察了西周至汉代的使用情况。其实,叠用符的使用可以上推至商朝的甲骨文时代,汉代以后中国人还一直在使用它,直至现代社会,各个不同的历史时期都有使用的实例,具有广泛的群众基础。真可谓历史悠久,源远流长。因此,应该将其收入现有的标点符号系统中来。","categories":["09_其它"],"year":2005,"publication":"井冈山学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKqk5KPhzZZ9Pjho_Hb_XdjHKyjZdGzpCWwfBIVJ4yoBvh7QFl91VboBv2has537V148kxhYATREQAl0MxCwZwlROS5b7ehYhNKMo7oSe7bmZhEo7ajTfLAE9BGdpqEJSVOCgXkz0Wo-YJW_OynNBIWHGyyVlYUBzczPUwZ7s4xow==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46244","volume":""},{"id":5868,"author":"夏含夷; 王正义","title":"1960年以来中国古文字学的发展(上)——钱存训著《书于竹帛》英文本第二版后序","abstract":" 钱存训教授的这部《书于竹帛》今日已成为经典著作。当他从事此书写作时,虽然他自己并未想到,但其时机的重要恰与此书的内容相同。他开始写作是20世纪50年代末期,当时长期的抗日战争和其后的内战方告结束,在继起的那一段相当和平的年代,才能出版考古学者在战前所发掘的许多重要成果①。以此,钱氏方能将这些资料综合归纳成为他的一家之言,用以述说中国古文字的发展","categories":["09_其它"],"year":2005,"publication":"文献","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKuK8OkhLCZslIEnV18bTu4G4oh5u1-9kfo_aonooWl6Ku1H9a5dc6DV8mVE-jaFnPr3Sp3q_PVG2q6UhCLSIYjVf8TfaSv1lyCKiODcxCUAf60Me74sw93dFYjPwYzMyIPCrEp-XdSjbrJgNwZrC39Ob7PMfMynI6eKS_Z6icX8w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"13-27","volume":""},{"id":5872,"author":"王立民","title":"“集形短句”——汉字形成过程中由萌芽到成熟的重要形态","abstract":"汉字由陶文符号和图形发展到成熟的文字是一个漫长的过程。目前我们还没有发现二者之间存在的文字,但从金文中保存下来的族徽和“集形短句”看,可以推测出在陶文符号、图形与甲骨、金文之间的文字应是与族徽和“集形短句”相同的形态。","categories":["09_其它"],"year":2005,"publication":"北方论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iI6N0P8RTj-UglvjYvYacWCziAAVFad_z7PjzNTfzhFOeahrro-EKVGAqWbWk1PAK2EA0Iux953jkk4pq1_1OEb8apgf4aJpqDj89AILaFRRFuQS1xUCmx-omGfxZw3F9rPCNWj8-OusOiXqGGjQfCzBHzG8i5JyEwWvUTKBdt0og==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"60-63","volume":""},{"id":5884,"author":"黄震; 杨健康","title":"“法”:一个字的文化解读","abstract":"许慎在《说文解字》中对“法”字的经典解释,高度凝聚了秦汉时期人们关于“法”这一现象的认识,并影响了整个中国思想史。然而,当代学者对许慎的解释是否符合“法”字发生时代的原始意义提出了怀疑,从而启发我们重新探寻“法”字的原始意义。本文从“法”字本身表现的事实出发,从“水”“”“去”三个部分,分别检索古老的传世文献和地下出土文物,证诸神话传说和文化人类学材料、回溯到上古初民的社会生活中,重现了“法”的原始形象。","categories":["09_其它"],"year":2005,"publication":"湖南大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLGzFcK6Uw0oPsqQ6Ms2aQOqn3P7Gy6kCjxZVWfNCOOlEf9hzRAn5ydyfTFS9AaL02CoXwcktMgZu_FwRNpRd1Aa7irR7HIdS-BLi-aTb2k0z1eq5Y3O1uaCkjtOvDAQoFpRtkHQppc8g7hud07BpO8Jra_lgHr0J2w4M80TGh6Tw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"18-22","volume":""},{"id":5887,"author":"彭曦","title":"秦史研究新篇章——读徐日辉先生《秦早期发展史》","abstract":"徐日辉先生的新作《秦早期发展史》解决了秦早期历史研究中的诸多悬疑:一是通过对文献的梳理,证明秦人源于夷夏戎狄;二是突出考古成果,结合方志、民俗等学科资料进行综合研究,指出绵诸戎的活动中心,在现在天水北道区社棠镇绵诸大队;三是利用金文以补文献之不足,发现了许多极有价值的新资料。","categories":["09_其它"],"year":2005,"publication":"宝鸡文理学院学报（社会科学版）","link":"https://link.cnki.net/doi/10.13467/j.cnki.jbuss.2005.03.008","pages":"31-32","volume":""},{"id":5896,"author":"王元鹿","title":"汉字发生研究方法论","abstract":"方法论是汉字发生研究的一个关键问题。有关该课题的论述大致有3种类型,它们各有其合理性与不足。而这些类型亦可进而分析为10种方法。而上述研究的不足主要在于符号考释的不确定性与对出土文献的研究的孤立性,这是今后的汉字发生研究工作需特别注意克服的两个问题。","categories":["09_其它"],"year":2005,"publication":"黔南民族师范学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJDG2PEpzFLEpVz-wGTUR6oc_LzUlJpWrGjNjBgMG2q4lrKgEnBW_wrzjVvmlx9KmTLKMdsnCZNs7iU3fQ9LGtmMrf0zTQ7k6b8ZoZw2m4tZg1K9bPS7Szq5xbZlQRPg6tDc5H6Y5TX-qG7knPRMMwID4rts2b_Luq9nDnlxxeYsg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46026","volume":""},{"id":5912,"author":"韩伟","title":"汉字形体中所蕴涵的远古种植文化信息","abstract":"透过&quot;农&quot;、&quot;田&quot;、&quot;耕&quot;以及农业耕作的对象、生产的农业器具和收藏农产品的场所这些相关的古汉字形 体,可以探测到远古农业种植方面的文化信息。这些文化信息对于丰富和佐证我国远古时代的农业耕作史,具有 重要的意义和价值。","categories":["09_其它"],"year":2005,"publication":"中州学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKh33KYjzb0ARF9hKstH6CUo4U4UPaXn01kz_0Mxh5unVOcMV1TVQ5sd3U0YWH3tFspSePPewhjuyAmEIMz8C9GfA6kXORfc-yPLbBxFF_ansUSFMSeg879nmcZQEWriaHoe3GlSEuxMgYrvMgf746GgprEohZlieXCVD_tZRKCfQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"206-208","volume":""},{"id":6505,"author":"赵玉宝; 詹子庆","title":"先秦性别角色研究","abstract":"在先秦这一中国历史文明的开端时期,有许多文化和文明因素都经历了从无到有、从小到大、从简单到复杂、从萌生到成熟的过程。由此,先秦文化也就成为中国文化名副其实的“源头活水”。性别角色作为人类文明进化的产物,作为区分人类社会男女两性的基本模式,也在这一时期萌芽出现于中国的原始人群之中,并随着夏商周的漫长时间推移,受惠于各种纷至沓来的文明因素的簇拥和触动,日渐完善并趋于定型。这一过程,横亘于整个先秦历史的流程之中,留下了脉络清晰的印记和轨迹。本文的目的,就是要循着性别角色在先秦时期印下的串串足迹,进行探颐索隐的史学研究,将其基本形态和前后变化的种种表现加以全方位、多角度的把握,深入理解其产生、发展、变化和定型、完善的因果,藉此来观照中国传统性别角色的历史和现实存在,并为当今时代性别角色(或称社会性别)理论的中国化提供一种可资利用的历史资源或背景材料。为了达此目的,本文所采用的仍然是前辈学者所惯用的","categories":["09_其它"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ4w6_0hrXSEcxVovwCSgIYPEoNAk54oUIkG-Izt8LSGyR50gS2Dl5ZhBSW7aMZXIeMBjC6Kopnb_hwro83tqDL8fjO-gsDU7wU-adLz_vs6HdxbmQblPZVFpyqKd0ex9qDcLXmfmio_hMZVtjlnpWLJOR4TKp7KHMlaszOOoShYw0SS4wAZpsQ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6506,"author":"王琪; 黄金贵","title":"上古汉语称谓研究","abstract":"上古汉语称谓研究是名物学研究的一个有机组成部分。称谓词既是语言问题,也是与礼俗、法律紧密联系在一起的文化问题。由于中国传统文化博大精深,因此古今中外的人们对称谓进行了细致的研究和分析。无论是利用传统的训诂方法,还是采取较为科学的语言—文化的分析方法探讨称谓,都取得了一定的成果。然而我们也应该看到在称谓研究中还存在一些不尽如人意之处,如对称谓词的构词理据缺乏系统的考求,对社会称谓的系统性重视不够,遂而造成语文工具书对一些称谓词的解释似是而非或前后矛盾,难明称谓词之所以然的现状。针对于此,本文以上古汉语称谓作为研究对象,分为三章进行讨论。前二章是对上古亲属称谓和社会称谓的分类研究。在穷尽性地考释每一个称谓或每一组称谓时,尽量采用语言与文化相结合的研究方法,全面深入地揭示其造字理据或构词理据,说明本义造字、引申和假借造词的来龙去脉,并对同义词加以辨析。第三章是对前面内容的总结和归类。利用造字理据","categories":["09_其它"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKedsFSKdqcO6Ljd4p_CirBlrxuR2zayayqGVTMasMZYMhWqkmROhXnL3BVfEw1J1z0iFpsgGL33VSy_h6UKyWtQlkcxwjPm0v0Wfn6gIMQwlRYbPIG0OoPuQ6YXCGy2vcRDM3u4UGpWiu2hrjRLUmQmJMBU_EMbDVCj3rs3zYY2S9uWhV4_QhN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6871,"author":"虞万里","title":"商周称谓与中国古代避讳起源","abstract":"传世先秦文献和出土文献所反映的实际称谓与礼书记述相一致,呈现出上尊下卑的规律。“字以敬名”、“谥以尊名”和尊而称爵、讳而不名等形式,都承自遥远的珍名心理,是在等级森严的君主社会中的曲折反映。国外人类学、民族志和我国近数十年的考古资料,展示出原始民族惧怕鬼神和巫术的避名心理。殷商已将这种语言和心理隐约地体现在庙祭文字中。周人继承殷商讳名习俗,经过损益,纳入礼制, 先贯彻在丧祭礼中,随即与丧服制度结合,讳及旁系之亲,最后渗透到阶级社会中,形成绵延两千余年的避讳制度。从礼制角度揭示殷商庙号日干称谓之所以多用柔日,应与丧祭中的虞祭、卒哭、拊庙礼有关,日干称号即刻于庙主背面的拊庙日记号,这对争论不休的商王庙号研究无疑开启了一条新的思路。","categories":["09_其它"],"year":2005,"publication":"传统中国研究集刊（第一辑）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLxrXcWhudN8tCrHzZGpoPZikRfm2R-uwjeExdqKprlNfH42zkaAYy4cnw_S7tTp2lcDs-hACP2OKSe3AybGBC3YagDFATcxRxAVZA7jsLdjdlZZ5uUlNFc3sJ7muDMOW3lHdS9RV76LBmKK8olf-kyB4h7jT013wJxpuN6TcHEKRYnUs0FEYpg&amp;uniplatform=NZKPT&amp;language=CHS","pages":"120-193","volume":""},{"id":6885,"author":"杨媚; 李宝通; 初仕宾; 张德芳; 何双全","title":"秦汉爵制问题再探讨","abstract":"本文以传统文献为主,结合简牍资料,在专家学者研究的基础上,对秦汉爵制及其相关问题作一粗浅探讨。本文由四部分构成:第一部分介绍了秦汉爵制从春秋末到东汉末的发展概况;第二部分概述了秦汉赐爵的方式,主要包括军功赐爵、事功赐爵、国家赐爵、以德赐爵、因亲封爵、尊贤继绝等六种方式;第三部分以简牍资料为主,从政治、经济、法律三个方面分析了获爵者的权益:第四部分研究了秦汉爵制对当时社会的作用与影响,主要有:一、有利于统治者夺取、巩固政权,促使国家迅速富强;二、推动了早期官僚体制的产生与发展;三、它最终不利于官僚体制的发展;四、加速了人们社会地位的变动;五、是国家控制土地和编户民的有效手段;六、纳粟授爵是重农抑商政策的反映;七、军功赐爵造成秦民尚武功、好功利、不重礼仪的社会风气。本文认为秦汉爵制的价值在于它是实现人民利益与国家利益的一个契合点,因而基本上处于良性循环中。这一制度对后世乃至当今社会某些政策的制","categories":["09_其它"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLD_utgsi5pM2CGcyAlNu6JXyRzp2YyUNAfJafleGsYjAXU4CP74xVTicrXb3WglK4DCX_1gwMRL_MnvgbpMag8hYX_7jhdxSINl36lhHd71-Yqf0geU8LxWr8d--fN1qKynAmob0LFYMvk5Molxj3wQbNOTqoPOwFo-CVodj65pxXP27RskCXP&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6889,"author":"周波; 李天虹","title":"《二年律令》钱、田、□市、赐、金布、秩律诸篇集释","abstract":"湖北江陵張家山二四七號漢墓出土的《二年律令》之《錢律》、《田律》、《口市律》、《賜律》、《金布律》、《秩律》部分,内容極為豐富,不僅是第一手的法律類文獻,同時又是集中反映漢初社會經濟和職官制度,政區地理方面的珍貴史料。它們為我們提供了許多不見於現存秦漢史籍的新材料,填補了不少空白點,因而具備多方面的學術價值和意義。對於上引諸律的文本,整理者作了大量艱苦而卓有成效的工作,校正了竹簡在傳抄過程中的許多錯誤,一些簡文意義滯礙難懂之處,經過整理也得以解決。報告發表後,許多學者又對簡文中依然存在的問題,從编連、釋文、斷句、注釋等多方面進行闡釋,使研究工作不斷深入。但諸家對簡文所作的整理工作,依然存在着比較多的分歧,對簡文文義的解讀,在許多方面也不盡一致。本文立足于文本的整理與解讀,在原整理者所作釋文與考釋基礎之上,充分吸收已有研究成果,綜合運用文字學、文獻學等研究方法,對上述幾種律文在釋文、句讀、詞","categories":["09_其它"],"year":2005,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iId8DF_47Ay5XgZcSBS9dGfKvg1WT8d-L0VWJjZU7ywU5B3WhPbH9PizwIzjraSmkWJu6MgXz-06nrn-C2OKq2E9tdwOkxG8-WEj6v8DgKyWykUH4HPI_ENXU7Bq3Mr_gHDze2bGUpcFw-532NRzbcUIDeBv2zAXAz0k2BI-vMeHI6kaUQaNaDZ&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7098,"author":"黄家祥","title":"青川木牘隸書墨跡探源","abstract":"《文物》1982年1期刊載了四川青川縣郝家坪50號戰國墓出土的秦&quot;更脩爲田律&quot;木牘一件,引起國内考古學、歷史學和古文字學等方面學者的極大興趣,先後有約五十篇文章對牘文内容作了多方面的討論,論極精深。而對木牘文字墨跡書體的討論雖有提及,但爲數不多。青川木牘文字墨跡的出土,是戰國晚期西土文字中秦系文字的一個重要發現,因此研究牘文墨跡的來源、發展和演變,對認知其在中國文字書","categories":["09_其它"],"year":2005,"publication":"出土文献研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIf2yuV9bFMGxmtm1SltNuQG721Ug7TNn-aTLOdw3ccrJkIUKMLkX8tkggsw0kFO8NS9kaifx5-j-a07ZCyVb_UeDLQ3RandIJK3D7c9iF_CFnc6t6xESysw3xzFNV5pQJWldo0xWitenXnQUhp3wHBZWMphGqsmwHtltIKIoni6A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"172-175","volume":""},{"id":7108,"author":"王文耀","title":"戴家祥金文考释方法论","abstract":"本文从四个方面总结戴家祥先生金文考释的具体方法,并附以典型字例。","categories":["09_其它"],"year":2005,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKfofhfxBYcpdNMGmTUrjdug6Ghmvu0NxEBB6FNum_MG0B9JewbCupbRSGBWv6-jdsdgEp_IEeJGy-WG8HbI6hwvg_cj-oHF81QmIel9bj49UoGqDV0kPtG8LH_so0HMqYWJ5Jv_P9Fgo7jKxrk95T8KybAgf44N2TNevIzZhm9aQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"70-72","volume":""},{"id":7110,"author":"周玫","title":"商周玉琮功用分析","abstract":"本文就三礼所载的玉琮功用,结合甲骨文、金文的研究材料及考古资料作一番探讨,认为“礼地”是不可信的,“敛尸”有可能,但其制无法证实。作瑞信应是最可信的,但琮在其中的地位不如其他礼玉重要。在商周时期,玉琮之为礼器,更多地体现在用作贵族身份地位及其交往的信物,并且没有表现出如《周礼》所载的制度化的特点。","categories":["09_其它"],"year":2005,"publication":"东方博物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJsmfdPdkna28qQWuRlE17ru1Qq6jHP9xtr5RQwm7BWgeNcW43h84edSKyaOkwtZXjINX39FCRupHUEZrRMrv-49o5M7-ResMATlTzGH3P_XtQNggFKipvNdx9qvzWFUPVMVjEnYg3oVydnt9hDCnkRz12aCYd1IDlEcQAFjHNWYg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"21-24","volume":""},{"id":7116,"author":"陳鴻森","title":"阮元與王引之書九通考釋","abstract":"阮元(1764-1849)、王引之(1766-1834)為清代嘉慶、道光間最具代表性之學者。本文就羅振玉所輯《昭代經師手簡》二編中所收阮元《與王引之書》九通,逐一考證各信寫作年代,及信中所涉及之學術故實,並訂正王國維相關論説及劉盼遂《王氏年譜》繫年之誤。","categories":["09_其它"],"year":2005,"publication":"中国典籍与文化论丛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK4r9U6jycQFzua1V6Ca5mdQyTsoBNgnljlQvzKFA7w69UwRQ_Pxjcu9835sfYdbiFpwjKtns1QqqwUp33nDs-q3o06aJ0sibhkTz1r4LFcChR1lqokUJ1g8IqBE05ZMcnInkXMEsLFS313mn3XddYwlfrr-5JrEci_q91GnXXO7Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"246-266","volume":""},{"id":5931,"author":"王元鹿","title":"汉字发生研究材料论","abstract":"有关汉字发生的材料,是汉字发生研究问题的起始点。汉字发生的材料统其类型可分为八 类。它们中既有传世文献材料,又有出土文献资料,既有汉文资料,又有少数民族与外国文字资料,既有 文字范畴以内的材料,又有文字范畴以外的材料。","categories":["09_其它"],"year":2004,"publication":"柳州职业技术学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIV6fM7Q3x57sE16dQBzvYu2BfyQtOE0eaxGsILO0RvwgMYNpMktpjzSPtY7Bwx01XGEbOeT-N2HRFKHHeHtHSLAuHfuvZ9TAGyHHefS69kgae0msIy2FafOfzmMVmtX-bZWjfzMJ63hHZep-zdH8M_jegldFY5nRxfqVibs1DIMA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"59-63","volume":""},{"id":5936,"author":"洪飏","title":"古文字考释中使用通假方法的历史回顾——从晚清至二十世纪中叶以前起","abstract":"古文字考释中常常要遇到通假现象。本文从学术史的角度出发,追溯古文字考释中使用的通 假方法。这种方法的使用有其产生的相关学术背景,经历了从不自觉的实践到理论的提出,至反过来用 理论指导实践这一过程.","categories":["09_其它"],"year":2004,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHmTqjJFpQSLwVD55RhWvfT6UdA6mMxHmiGEE0kqLz-FGnM1oESOmUoRqqQzybYrg7rp1jLtOLd-02LO0YE1anmFzOHeA5KuAi7isduetmp9Y6GP6jeoNqXW1VzrUXHMbZfGN5AP4bG6noGQYu-Ovq5frtx9cLWOA_ifFPG3SoJw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"54-62","volume":""},{"id":5940,"author":"白冰","title":"白川静《金文学史》的汉语文字学成就","abstract":"日本学者白川静是中国学者熟知的汉学学者,他对中国汉字,尤其是古文字情有所感、研究深入、见解独到。所著《金文通释》全七卷九册,约四百万言,影响深远。本文就《金文通释》之通论部分《金文学史》的汉语文字学成就,试从文字学史、字形考释、治学特色三个方面进行总结,并加以评论或提出新见。","categories":["09_其它"],"year":2004,"publication":"江西社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKxXwn-wOpBa9U6mndVkJWw2gYlPT9kYkDoeiFHVj6P0Y4pCEAVa936uaifPgdzKQoefDLD1bocSjenqdmLkKo3kZFnaZz2PVWwF6WLnrwzj732A2KrrGfH98_lSsg0YDJoIhyPlrMfBfjhVAJutHoBgUL5KbbWZ8iAcKeAQ-EH2w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"96-98","volume":""},{"id":5954,"author":"李小光","title":"大禹“铸鼎象物”考","abstract":"本文以为,大禹铸鼎一事值得重新思考。“铸鼎”实现了先民信仰对象向中央政权的集中,而“象物”是灵的形象化,所象之物则使原来信仰的无形象的“灵”转变为有形象的鬼神。中国的国家雏形就是依靠这种对信仰的控制出现的。","categories":["09_其它"],"year":2004,"publication":"江西社会科学","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKx-QtUFHCm2Yz1cXMRnDPiCJ_75qrivDtZZ8qEuHEZoQYNZz9Krm_faeEaaEiUDZ4NvYTHcgpzFXGkh_2_iF-tHkVvhM4sgxdh_E_g2OBrQldfOd0-KPov4bQZAJLQfvjQ2U8ANGgp2JtDxoa0kre6KoDy-DfSTPACnD9R21McyA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"67-70","volume":""},{"id":5955,"author":"连劭名","title":"释文、圣、善","abstract":"文、圣、善是中国哲学中的重要概念。文有天文与人文的区分,天文是天象,人文是文明。通天道为圣。善是善良之义。","categories":["09_其它"],"year":2004,"publication":"北京教育学院学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK33Ecl9-2KctCoM-IOKqhTKSKT-kTfaywqQ1oKlmG5kLxUpnQUaDH5RwFN6VwSz7QK-vbgy8if3zSycKt7AUz9I06E-kLzVE5lpVovIC5rX6LBMBM0_37G7mj5UAS-A9wzS1_r_lNCWMEiI84rD4_BdeZkMO2u5nDmxr3pezHi9w==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46244","volume":""},{"id":5956,"author":"白冰","title":"白川静《金文的世界》翻译与校补(一)","abstract":"《金文的世界》是日本学者白川静依据铜器铭文论述殷周社会历史的著作,该书见解独到,影响深远。笔者在该书中译过程中,将其金文释文、注解、断代及古代史实,与国内卓工成就的金文考释著作仔细核对、彼此验证,于此翻译与校补13器,纠正白川先生援引文献的错误一处。","categories":["09_其它"],"year":2004,"publication":"五邑大学学报（社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKHP_QTW0I-9sdN1e6-fKskmFKDffarq_XGsAt9L6m_X-wBtcxwdiWv08H-VCz3W90TpDpgtnLb-UDKpZ81ZuoTE1PYW6zw-YiI9F7SjBfMv9Y-4a-tewyJLxxAC4MLMja3Kdtcz-bz-z7REyQyfGQKeZiX3t9BMSaGnoBcCfkyhA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"75-79","volume":""},{"id":5975,"author":"冯广宏","title":"巴蜀文字的期待(三)","abstract":"","categories":["09_其它"],"year":2004,"publication":"文史杂志","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJJk4koCsulGVIsLp6qEdUD6MewkrBHxfTHsllX4e79PYDICyQ2K_Ua8cB0HWRIM824SmZLdJnV0STo1F6TB31jITqUupYrnEkVRiZS4vrrmWyspMg3_lI5lcPqSM_ntUB8lQWhXh3nTXdpZz0iXzNDaQdUIHnr2x-tEaOLTR8GnA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"26-32","volume":""},{"id":5976,"author":"洪飏; 陈英宝","title":"20世纪利用出土文献研究上古音进展述评","abstract":"地下出土的文献材料对上古音的研究具有重要作用。对20世纪利用出土文献研究上古音的成果做了全面的总结并简单加以评述,包括利用出土文献对上古音系的研究;对上古某一声纽或韵部的研究;对上古方言的研究等。","categories":["09_其它"],"year":2004,"publication":"渤海大学学报（哲学社会科学版）","link":"https://link.cnki.net/doi/10.13831/j.cnki.issn.1672-8254.2004.03.027","pages":"98-101","volume":""},{"id":5979,"author":"蔡运章","title":"商周筮数易卦释例","abstract":" 商周器物上常见用三或六个数字组成的&quot;特殊符号&quot;。它是我国古代筮占的产物,当名之为筮数易卦。这种易卦在北宋金石著作中已见记录,南宋薛尚功已将其与《周易》的&quot;九六之数&quot;和&quot;制器寓象&quot;相联系。可惜,这种灼见没有引起后人的注意。20世纪30年代以来,郭沫若等学者将这种易卦视为&quot;族徽&quot;或&quot;奇字&quot;。1956年,李学勤先生再把&quot;这种纪数的辞&quot;与&quot;《周易》的","categories":["09_其它"],"year":2004,"publication":"考古学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKaLIIu8ljysSdHtDzOrc9cEYJupkVuyB-lPt0pYa5TwKshUgzjL7VmLpRRvY_qBo0BLnCDfXD4S76m18L1kua2_w4E3uslfrJiyFpVYqEEjRM7wCYfFvUe1HmKGfqaVHceG0uxwD8ZRWzn9DUh0kt-RrCNi7c0Z6mEQ6yFR1XzGA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"131-156","volume":""},{"id":5982,"author":"张玉金","title":"西周汉语第一人称代词的地域性和时间性问题","abstract":"本文在以往学者们研究的基础上,探讨了西周汉语第一人称代词系统的地域性和时间性问题,认为其时间性主要表现在一些代词的新陈代谢和“我”在称数方面的变化;其地域性主要表现在汉语共同语的基础方言在殷商、西周早中期是殷方言,在西用晚期、春秋时代主要是宗周方言。","categories":["09_其它"],"year":2004,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLPWCO0KaW67q0Ov9f18F4rLkydVgnUw7IK8V8ccHpsNKW3drnhJNXrkxAn3g0ey9NH7-pYePk_HSr4mCzKB9K_jaX7KRJuT3pmYfU4AnBpDywTCpdel3-Wkd40gLfompvCpj60z9VTUuPwwkMVrrSxvo3jBFD8qi7eS7gWyiDNpQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"42-50","volume":""},{"id":5986,"author":"孔刃非","title":"汉字起源观念的文化审思","abstract":"汉字起源的研究误解甚多 ,人们多以为汉字的历史是从甲骨文开始 ,其实 ,甲骨文不是中国最早的文字 ,也不是当时的主流文字 ,更不是当时中华文化的先进代表 ,相反却是那时一种职业性的落后的“变文” ;甲骨———金文———竹简书没有先后的继承关系 ,它们只是书刻文字材料的进化过程 ;汉字的起源不是考古学的问题 ,是心理学的问题 ,是人类文化学的问题。我们不能将文字与书写文字的物质材料等同起来","categories":["09_其它"],"year":2004,"publication":"乌鲁木齐职业大学学报","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKTvmrBtIlafJlre4sM6B9GAAaEjf_S9DnXTBoxFvnsdrcsdd7Bc6DLbPeveq6ZW5CysKKryjlBqva_VhEhtkmKZVpM8SiXKwKIWCQ1AdnbqeloH6IL65E8eCfvNmbWDHkLLDwDAVCX7FUKtzTEW1ojOigLhBVASVELQa1XQ7QkcA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"68-71","volume":""},{"id":6517,"author":"高兵; 陈恩林","title":"周代婚姻制度研究","abstract":"本文主要是研究周代婚姻制度和婚姻礼仪的内容与特点,探讨其形成、发展、变化的原因;分析周代的婚姻制度与社会政治制度之间的关系,概述婚姻伦理观念的特点。全文共分四章:第一章在追溯商代婚制的基础上,主要探讨西周时期的同姓不婚制度,周王室嫡庶妻等级婚制的发育程度,以及西周时期的媵婚制度。商王室已妻分嫡庶,但因未形成宗法制,故其嫡庶妻婚制不具有嫡长子继承王位,余子分封的功能。商王室在一定程度上还实行族内婚制。《诗经》和金文的内容反映出先周经历过由母系婚制向父系婚制的转变,周人不避与异性亲属通婚的主要原因是,母方交表婚有较强的隐蔽性及保证本族的婚配资源。周王朝建立前的嫡庶妻等级婚制亦无嫡长子继承王位和余子分封的功能。周初形成了嫡长子继承制和余子分封制,从而使周王室及诸侯公室嫡庶妻等级婚制的功能得到了发展。从50余例西周媵器铭文得知,西周时期作器者分别以七种名义为出嫁女作媵器。列国间以两国通婚为主。第二","categories":["09_其它"],"year":2004,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJEw586706QRQwGU4rOwaKGm4veZG--s8cDEyB2xpHIqzaDwbR5jkwQK_mWY3DQB4fj73ACnnUPzCq2jZju2S8cU1CZ4qpvG33JTedHgqRq6hX-qWdn0ArZ0p145YqqTJJCfkF5kJrDtmOVGAhFK4B4NV5BOyA9EmYq_HeUm6YX4ItAsmxIofa_&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6518,"author":"方向东; 马景仑","title":"孙诒让训诂研究","abstract":"孙诒让是晚清著名学者，一生著述宏富，在文字学、训诂学取得了很大的成就。鉴于目前训诂学界主要侧重于传世文献的整理与研究，还来不及对前人的研究著作进行系统的再研究；特别是国内国际对孙诒让的训诂进行系统全面研究的著作尚未问世，本论文通过对孙诒让所撰的涉及经学、诸子学、文字学、甲骨学、金石学、校勘学、目录学、文献学35部著作中有关经学、诸子学、校勘学方面的著作《札迻》、《周书校补》、《〈大戴礼记〉校补》、《九旗古议述》、《尚书骈枝》、《墨子间诂》、《周礼正义》进行阅读研究，一是爬梳整理出孙诒让研读古书所采用的训诂理论和方法，并同传统的训诂理论和方法以及清代其他训诂学大师进行比较，总结出特点；二是对他的训诂校勘的成果比照其他学者的研究成果重新进行审视和研究，顺带纠正中华书局版孙氏著作中出现的排印和标点等方面的错误。以便为解决这些古籍问题提供一部分材料和证据；对汉语史尤其是词汇史的研究和相关的学科研究","categories":["09_其它"],"year":2004,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIFtm4lNwrzodlldY4JcfvBLWWSISeUSX8XtummEsi1egF9QLtlwe8ZNU8vdHEbM-TnAcUUHJ_kuVZLMEcgAofU_WGeOFClvoNJM5qwMjY-G6xEglvz6VQ6C8FHumChfVpuGV4x4iR9s1y4-KUHteguj4YC2Gukb1AH6qWO1BYdi3w12p8STaWN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6519,"author":"芮东莉; 祝鸿熹","title":"上古汉语单音节常用词本义研究","abstract":"上古汉语单音节常用词是汉语词汇史之源，对于这部分词的本义的研究即是对汉语词汇史源中之源的探讨。本文在进行上古汉语单音节常用词本义的研究过程中，处处注重将理论阐述与实践考释相结合，在理清理论问题的同时，以实际应用为主要目的。文章的主要内容包括以下四个方面：一、对上古汉语单音节常用词本义的概念进行界定，认为上古汉语单音节常用词的本义是上古汉语单音节常用词在文献当中可以追寻到的最早词义，它是常用词词义系统的源头和总纲。本文还对上古汉语单音节常用词本义的特点进行了归纳，认为上古汉语单音节常用词本义具有源发性、单一性、模糊性的特点。二、详尽总结上古汉语单音节常用词本义的推求方法。本文认为依形索义和因声求义是探求常用词本义的主要方法，除此之外，探求常用词本义的方法还应包括以下两种：通过梳理词义系统探求本义和利用古代文化信息帮助确定词的本义。三、利用义素分析法对上古汉语单音节常用词本义的语义成分进行分析","categories":["09_其它"],"year":2004,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIQ-cGfJKJJkd9ZcnV93GhoQcRdzzs0AHZ8_cETXymPXW_ny3mma3GCv8YMDiZE1Jr23gjCUOt0lmxWmK0Z5mhsoQod_S7WS0tbcGM4kPvpt88rYOB1C3Rd0_HIoZfWgbhHeBTsnROLMAw-8c_8Jw32he33giBsx4pQx4i4-IU60pIFUYkrtvgw&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6521,"author":"周建忠; 孙逊","title":"屈原考古新证","abstract":"利用出土文献进行楚辞研究，目前主要在字词训诂、作品诠释层面，本文则着眼于作家层面，综合考古发现与出土文献、传统文献、民间传说以及学术史等多种信息，通过楚文化与楚辞的双向互证，解决屈原世系、生平、仕履、放逐、沉江五大环节中的历史疑难，推进屈原研究的进展。本文认为，第一，屈氏在春秋、战国两个阶段均为大姓，历久不衰。而战国三大姓昭、屈、景均源于楚王族，“与楚同姓”，昭氏源于楚昭王，屈氏源于楚武王，景氏源于楚平王。屈氏家族成员往往执掌要职，建功立业，有较高社会威望；对楚国、对楚君恪守忠诚；娴于辞令，有理有节，有鲜明而强烈的传统与家风。第二，通过对郭店楚墓墓主的考证，论定屈原与郭店一号楚墓墓主无关；屈原之从政、放逐、沉江，在汉人记载中是清晰可信的。第三，风靡学界的“左徒”即登徒之说，不能成立；王逸关于“三闾之职，掌王族三姓，曰昭、屈、景”的记叙是可信的，有文献与考古双重证据；屈原政治生涯的高峰是任“","categories":["09_其它"],"year":2004,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKIbdXF66Hlw1xSbXpb5NOEWSGdlVdG6jRMkfrw6B95pS_AurWv48u85lVBYFcxZFw_KNzG2kUqP-rMcafvvYBEUdjAB6AcMNpOs7_dGy2zZhdLr5uhOjBxbKfPl-uObw3GkttBQxuN0WCKqFqJ1V3WkHLpWZ5IBJqWUcAe3rXRUvA6s5x8qqzW&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6524,"author":"程邦雄; 李玲璞","title":"孙诒让文字学之研究","abstract":"孙诒让作为清末最后一位朴学大师，在经学、诸子学、文献学、训诂学、校勘学、文字学等诸多领域都取得了令人瞩目的成绩，其学前承清代主流学术乾嘉学派之遗风，后启现代学术之先河。因此，全面系统地考察、总结孙诒让的学术成就，对于梳理十九世纪后半叶和二十世纪的学术史，探究现代学术发展的走向、乃至对今天的学术研究都有着重要的意义。然而其主要著作问世近百年来，却很少有人作过全面的研究，即使是某一领域的，也几乎没有专门的全方位的研究。这对于学术研究是极为不利的。本文即是在这种思想的指导下，对孙诒让文字学进行的全面的、系统的、综合的研究。本研究的主体分为三个部分。第一部分是“方法论”，讨论孙诒让考释甲骨文、金文等古文字时所使用的方法。从大的方面讲，可以分为据形考释、据音考释、据义考释。具体地说，据形考释又分为“形体分析”与“历史比较”两法。形体分析法中具体讨论了“偏旁分析”“形符通用通作”等问题。历史比较法中具","categories":["09_其它"],"year":2004,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJ7bUZJ8p3Xk3Jhl34dMhf1OH3wl96E3NwpV9NEMgiNklXN368ss8x_uckCmzrXsqZzy2pGxhQ5sTN3OvVNELChZf_Ekr0Swd8KnWXqH5uvT157LvLQuD0Ph6s8SMBaBBjF5Ag-IaCtv6ZDSs6W47AXRo91kt02TpY89yKgL50giBpBLmd73J4p&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6910,"author":"江梅; 张世超","title":"碧落碑研究","abstract":"本文共分三部分。第一部分主要是介绍碧落碑的概括。包括碑体的自然情况，碑文拓本及其历史流传，其中重点分析几个关于此碑著录有出入的小问题：立碑的时间，关于碑的得名，关于书写者，及碑文书体风格。第二部分是对碧落碑文字的整理和注释。先是将可能见到的碧落碑拓本放到一起进行比勘，补出碑文的缺漏，校正释文的正误。然后以字为单位，将各种拓本的资料汇集在一起，主要依据字形对碑文进行考释。本文主要参照了黄锡全的《汗简注释》和徐在国的《隶定古文疏证》两本书的研究成果，对碑中文字作具体梳理，碑文与《说文》正篆完全相同者不作说明；与正篆略有出入者，作简要说明；而字形多有讹变、假借情况者作重点说明，并纠正一些释文的错误。对于碑文中有争议而又不能确定的地方或存疑，或参以己见。第三部分为碧落碑的再研究。通过对碑文的梳理，可以重新全面认识碧落碑的文字特点，以便得出结论：碑文确有所本，且来源广而远。并以一碑管窥唐代传抄古文的","categories":["09_其它"],"year":2004,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKI6Nni8NZOMDAGla9m3E_0RlMscWQU6fXtdmbKapTtWCrY8LTFVgj7glvusBAgUIT-Qskc5JYz5XFBqZWDujKOlOdj9Hvr3Esck_as6jr9zJMXLLgT6shUUg-vO0Fac9ShpP6pwPi800OxKuuGCpNcOHaK43yQdyuRJybnUQgBBalTKeub8nQ-&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7117,"author":"郝树声","title":"武威“王杖”简新考","abstract":"1959年在武威磨咀子18号汉墓出土的&quot;王杖十简&quot;和1981年在该地区征集的&quot;王杖诏书令&quot;册,是研究汉代养老制度的重要资料。自出土以来一直受到学术界关注,取得了相当的研究成果。但还有诸多问题需要重新认识。本文在前人研究的基础上,谈一点自己的看法。凡前人已有研究且为学界所公认者,本文从略;凡前人未曾言及或者已有研究但尚需继续讨论者,提出自己的看法,以求教于大方之家。","categories":["09_其它"],"year":2004,"publication":"简牍学研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK4r9U6jycQFzua1V6Ca5mdQyTsoBNgnljzPtegkevzMoTu0SV0p_1o03vZn3z9fSsE5WDPdQ_JQhZDbhxPQCdaPIJq4DVhnyD2b57wwCqM6y5EecnXrCFoNj9LgVTHD0Nss4u7DNEqXraoZe5LA_JDMAF5rn514YswCCUPoP3arg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"132-146","volume":""},{"id":7118,"author":"孙庆伟","title":"周代金文所见用玉事例研究","abstract":"玉器在周代被广泛使用,这在文献和考古资料中均有充分的证据[1]。此外,周人的用玉事例还见载于当时的彝铭,对此已有学者进行过相关的研究[2]。为了进一步了解周代的用玉制度,本文拟对周代金文所见用玉事例进行全面的考察。本文所引周代金文资料除注明者外均据《殷周金文集成释文》(下称《释文》)[3]。《释文》共收殷周彝铭12113条,是目前最为全面的殷周金文汇编。《释文》中涉及用玉事例的周代金文共20余条,大体包括以下几类情况。","categories":["09_其它"],"year":2004,"publication":"古代文明（辑刊）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLM-Ts_nDSw63uxv_Yabhfw2NHs4hovPSVyih-biVB2BqbmhSQ1wIkcD_KbhX1-UAMAWYrZDebph9i_-pWgfml9yzuzSX7csrdaAR3bIUGGMrWbC6wJJT-dtytIrHSURVqQGaDg4NzSPpi5DWQLk7x8NXAUTSNnX_bUiRf6AfYmJA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"320-342","volume":"3"},{"id":7136,"author":"向光忠","title":"古文字与古声韵之参究刍说","abstract":"本文通过回顾古音学的形成与发展过程和古文字的研究情况,结合理论与实际,论述古文字与古声韵的研究之交互为用的密切关系。","categories":["09_其它"],"year":2004,"publication":"南开语言学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKs415tYI5gRPmA_CYwjLsQXNtMYYxUiHvlXdfM1on34RRx36pss6XYPI-mGh523eRNCysL5lAiaV6oCnZWwfS2bn6tJYQLDTB2UkgO0GbL_J_shoBeccAk4y7kWzpELYa0BBqTsfQ1X-CMDdBv7QpNV448rOqTNvz5R-TsSsgnXA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"118-129","volume":""},{"id":6042,"author":"师玉梅","title":"张亚初金文考释方法商榷——读《殷周金文集成引得·序言》","abstract":" 张亚初先生《殷周金文集成引得》一书熔铸了他十年的辛劳,本人在了解到张先生编写《引得》的艰辛经历后,敬仰之情,油然而生。《引得》在4972个金文单字中,对其中一千多个字提出了新认识,凝结了张先生长期以来研究古文字的心血和经验。此外,他还在序言中总结了确定新识字的十二种方法,更有许多新见闪烁其间。但我认为所述方法中“利用金文装饰美化的特点释字” 这一提法还须澄清,“利用由繁趋简的规律释字”、“利用由简趋繁的规律释字”、“利用偏旁通转的规律释字”等方法还须加以限定。在此我想谈一谈自己的一些浅见。","categories":["09_其它"],"year":2003,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIyQNevO_HjlwEpZI3rGXaou--q5z7dUjegWqfoJs4E66OCq-EaBfJ5uJgZg2t1Bi-aYgTNzR3GuhjSRW-dYDqWrldI3ecVIBaWm7lsCOJ3yMmp_jqAm_8BzhKt2aWheiuFeavkKhoFmZJuv1-hgGbCuMIWSBjBvx4keYnCGpeWMA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"84-89, 93","volume":""},{"id":6078,"author":"孙瑞","title":"日本泉屋博古馆所见先秦私文书(三)——春秋战国青铜私文书的衰落","abstract":"日本泉屋博古馆展藏的春秋战国青铜铭文器明显少于西周,从著录的金文集里看,春秋战国的青铜铭文器数、字数及内容,与西周相比也骤然减少。其原因是奴隶制度的代表制如分封制、宗法制、礼制等,到了春秋战国时期逐步走向衰落,家庭或家族的铸器铸铭之风,也必然要随其走向衰落,这是青铜私文书衰落的一个原因;另外,代替青铜私文书载体的其他材料如铁、竹木、玉石的大量使用,是青铜私文书衰落的另一个原因。总之,从先秦青铜私文书的发展变化中可以看出,任何一种社会文化的发生与发展都与其政治制度的兴起、鼎盛、衰落有紧密的联系,是社会事物发展变化的必然结果。","categories":["09_其它"],"year":2003,"publication":"日本学论坛","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKkzTWXSJLFL3InDyfqs0stCBxeIWb8I6aMuO-PqGiWhVKr8mmp4tsjx67VkbLAB3xiWBUS5iD5yJLpu6mwNY7j5Prr34gM1fZ10p84O5mdZylisGlE4OgWg7jsMW58Qg_kvjsOzPCNcisKjScwJVmga6FGU5ruCAHdaoUFQ8z3tQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"19-22","volume":""},{"id":6088,"author":"李守奎","title":"出土楚文献文字研究综述","abstract":"出土楚文献非常丰富,是当今学术研究的一个热点,而文字的正确释读是充分利用这些重要 材料的前提。本文是对近七十年的出土楚文字研究的综述。","categories":["09_其它"],"year":2003,"publication":"古籍整理研究学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKgremmxh_9n4cIROWLxRkC8Ru73ZzktWw2UWsfueosiMf92Vwg7uwKLwXk3VedmQzNDRRbYVDSTqadn-p0vBbdIygU-goOPwXOTDD1RYA1Woc5cDy_SaS6LJ8bIsMaypdIaByYrMfvwFJWAZK2GW799sJRuoBXOSdfQtSs65nZ6A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46282","volume":""},{"id":6527,"author":"潘玉坤; 臧克和","title":"西周金文语序研究","abstract":"相比于从历史、考古角度对西周金文所开展的研究，金文的语法研究一直比较薄弱，迄今还没有一部以所有己公布的金文材料为研究对象的语法专著，更不用说从语序角度进行的专门研究了。形成这种状况的原因可能有两个，一是青铜器铭文艰深古奥，释读困难，二是材料分散，收集不易。《金文资料库》收录了2001年以前国内外见于著录的青铜器铭文，搜罗宏富，规模空前。它的建成，为金文的语法研究提供了很大便利。本文以《金文资料库》为依托，选择八个专题，对西周金文进行穷尽调查统计基础上的语法、特别是语序研究。全文八章，内容如下：第一章，被动结构与语序。依次讨论了有形式标志的被动句和无形式标志的被动句，对前人没有论及的内容有所补充，对前人可能有误解的句子予以辨正。第二章，双宾语结构与语序。首先以36个双宾动词为线索对双宾结构的使用情况进行描述，接著对双宾动词的类型、两个宾语先後顺序的理据、双宾结构在句中的位序等问题作了探讨，然","categories":["09_其它"],"year":2003,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJA10C_RaXkwN_lfOQqxn2XdpWprRrf0MHcSOMrTJWu51DsGLf2_JNv4hmMAaBU5wXxasRllGK-FjA6scGU1WIexven0_-cbIMKp-d_EEODTxP91f4PfXxONIqx8p5MCLcfh_N_l8oPSQyjmfprqmpzPVrGUzaXrvAuhht0NPEObik5rkUW9zpt&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6935,"author":"叶玉英; 林志强","title":"《文源》的文字学理论研究","abstract":"《文源》(附《六书通义》、《古音说略》)写定于1920年，是一部以金文定本形、本义的字书，也是第一部较为系统地利用古文字资料订正《说文》的著作。作者林义光，福建闽侯人，写此书时在北京，1932病逝。由于作者早逝，《文源》很少有人问津，作者的生平资料也极少。新中国成立以来，随着古文字学的蓬勃发展，《文源》日益受到当代许多著名学者的关注，引用《文源》的文章相当多。然而，很少有人专门去研究它。拙文旨在阐发，《文源》的学术价值，同时对林义光在古文字学上的贡献作出一定的评价。因此，我比较重视利用现当代古文字研究成果来验证《文源》，从继承和发展的角度探讨林义光对古文字学理论的发展和创新。研究结果证明，林义光在六书理论上颇有创获，这表现在：一、他最早提出了“形变指事”、“二重形声”等课题；二、在形声字的来源问题的研究中取得丰硕的成果；三、较为科学地阐发转注、假借造字之旨。他特别重视音在文字产生、演变和发","categories":["09_其它"],"year":2003,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iL_cip8eZHwnC2ZEV6_HjNtugv0yZHs9yCNEEA1VrxsvAdQba3Un0qe35UNMaTJBMQI3fa3JADydChRUJRMOeXk-QkslhBe7JqMIVWKAGw92cYrc472hx5QfZErIcLAm66LMf7yVU1dpVn2GFalxhEiO_zkL72sPqG8O0ALzhIR39f0UUvUovdI&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6936,"author":"王安潮; 陈应时","title":"石磬形态通考","abstract":"本文运用比较的方法，将有出土资料记载的石磬，按照形制、纹饰等形态要素对之进行了新的分类。这种分类着眼于石磬本体的形制、纹饰、铭文、音律等要素，将其分为“模糊型石磬”、“变革型石磬”、“稳定型石磬”、“美饰型石磬”。依据这种分类法对石磬发展、变化作出了细致的分析，总结了各个类型石磬的特点：1)“模糊型石磬”的形制变化多样，呈迥异的个性，有的跟器主的喜好有很大关系；有的则反映了早期石磬图腾崇拜的主题，纹饰以粗线形式阴刻描摹动物的形象，只有一例有“纪事”类的铭文，音高上尚无绝对音高可言，可见这一类型石磬是以祭祀性礼器的用途为主。2)“变革型石磬”形制变化仍然很多，但已有明显的趋势，即在向股鼓、倨句分明的方向发展；纹饰依然以线条的阴刻为主，但线条细腻些，有着色朱漆的探索；在铭文的发展上，以“纪事”为内容，但字数增多；开始出现编磬，但由于没有调音技术的支持，这些编磐只能算特磬的组合。3)“稳定型石磬","categories":["09_其它"],"year":2003,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLqzZuMv2RSRsSx_xaVj-VwbSeyQgW9VGMN2H8_8uVtiuKXl_EbbMdjlpGN2AkqVnbPTVlBdJ3KlCoRrF5si7ONyIys-1O9l7u361qX6OkOOpoS5YA20Z_BcpmCB35dltxGVU9mAZiFg4b3sx06eMJULZr0tXrTMmdUoD076KtUDewynYod9PAs&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6946,"author":"员雪梅; 陈宝国; 蔡克勤","title":"三门峡市虢国墓地出土玉器考释","abstract":"三门峡虢国墓地位于河南省三门峡市上村岭的台地上，地势东西狭长，北高南低。历经50年代和90年代两次大规模发掘后，出土33000余件(套)珍贵文物，特别是5900余件玉(石)器，其种类之全，质地之优良，制作之精美，文化艺术价值之高，可以反映西周晚期到春秋早期玉器的特点。在目前西周王朝天子级墓葬尚未发现之际，两座保存完好且各有大量珍贵玉器出土的虢国国君墓的发现显得尤为重要。如M2001虢季(国君)墓为已发掘的两座国君墓的一座。墓主入葬时有五组不同的项饰、头饰，胸佩七璜联珠组玉佩，腰下垫玉，足下踏玉，甚至八个脚趾缝中也各夹以玉件，时代最早的人工冶铁制品镶绿松石玉柄铁剑、镶绿松石铜内铁援戈都为目前国内所仅见。虢国墓地发掘的这批玉器为研究两周史、文化史、宝玉石史等诸方面提供了难得而庞大的标准器群。本文主要是利用这批资料，试图从地质学、考古学、文献学的角度，对虢国墓地出土的玉器进行全面系统的考释性的研","categories":["09_其它"],"year":2003,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIsLBNvzSWuKfKXbbx8BlD1pzRg7luvjsSWdNM_2makBRb-D0SEZQ7L6JAN1xT4jIl88t-WTstiP9xNd3yWXnyEVDlWexUCLZv7ndqx282qzU996JS-7OHMIxTMwPn5RNsCYdpDMnS-wMNcKQENz5f3D1-UZrnxfmC4zY0o9zXcCbQMR6jo2li8&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7151,"author":"在国","title":"读《商周金文书法谱系类徵》","abstract":"王长丰先生的新作《商周金文书法谱系类徵》由文化艺术出版社出版。近日拜读一遍,约得以下数事。一、视角新颖有关铜器铭文研究的著作可谓林林总总。有集大成式的著作,如《金文诂林》、《殷周金文集成》等;有字编,如容庚先生的《金文编》;有字典,如《金文常用字典》、《金文大字典》等;有专题研究之","categories":["09_其它"],"year":2003,"publication":"古籍研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLIrrtqm0WWKJ1fwVa2EF48JR8H--Fi7FApq0IOQ53HdKWeMBsNMEnOgseM1xkrFqxLADLyTjY3FrE_oHLEWLKseWc6SITcbkkLuJYzmlneIJzilDdFoyzTKBWaXoV-otDr9oo11G5XBtDfcrVn9Z5jUWn_y2tgnMVyybkjRjB2Uw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"137","volume":""},{"id":6108,"author":"罗江文","title":"早期民族观念在古文字中的反映","abstract":"汉字蕴含着丰富的文化内涵 ,通过对“中国”、“华夏”、“夷”、“蛮”、“闽”、“貉”、“羌”、“狄”等汉字字形的分析 ,结合文化史资料 ,可以看出 ,上古时期 ,由于华夏族与周边少数民族所处的自然环境不同 ,文明程度不同 ,形成了以“中国”为中心 ,以“华夏”为至尊 ,扬“夏”贬“夷”的民族观。","categories":["09_其它"],"year":2002,"publication":"民族艺术研究","link":"https://link.cnki.net/doi/10.14003/j.cnki.mzysyj.2002.05.007","pages":"45-49","volume":""},{"id":6133,"author":"董珊","title":"景初元年帐构铜考","abstract":"在中国古代,帷帐制度是舆服制度的一个重要组成部分。在清代以来的旧著录中,有4件属于曹魏景初元年的帐构铜,其中一件现藏故宫博物院。本文从新发现的另一件景初元年帐构铜及与之相配的3件铜饰件出发,对于相关器物的著录和研究情况加以清理,重新考察了这些“帐构铜”的形制及铭文,由此对该类帷帐的形制提出了一个复原设想。本文最后把帷帐制度跟丧礼中墙柳和荒帷制度作了一些比较,指出二者的关系非常密切。这种比较的目的,是希望有关舆服制度所见等级内容方面的研究能够得到学术界的重视。","categories":["09_其它"],"year":2002,"publication":"故宫博物院院刊","link":"https://link.cnki.net/doi/10.16319/j.cnki.0452-7402.2002.03.008","pages":"56-68","volume":""},{"id":6152,"author":"之其","title":"从《金文引得》说到“金文资料库”——兼论古文字信息化处理中的若干重要问题","abstract":" 一感谢你们提供了一个非常杰出的研究工具,考虑周到,印刷精美。我会经年累月地在工作中使用它。我本人也用计算机编制过甲骨文索引,所以深知这本书里凝聚了多少心血。向你们表示由衷的感谢,不仅仅是为了送给了我这本书,而且为了你们为这个领域的所有研究者编制了这本书。","categories":["09_其它"],"year":2002,"publication":"中文自学指导","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJDyP-W-ADUM7NbaSnq1PeKnuXIwAtgE6WtSdxhhb5V1B5S87i0KzCFcC_M8UL3ibfU2y9CQf129cD3sOWg19QXUe4_4JzgTwp9AElOkUtFqMB_PxYLQR5yW7AH_tOO0OKzfacagZXtc1y-Q4Gm_3aVkDDbjH6lOtSRES-uC6SmrQ==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46088","volume":""},{"id":6153,"author":"王晖","title":"盘古考源","abstract":"东汉时期出现的创世主神盘古 ,是由上古土地神 (社神 )“亳”音变而成。亳异体为薄、蒲、蕃等 ,变为双音连绵词有薄姑、蒲姑、蕃吾 ,转而为盘瓠、盘古。盘古作为创世主神虽在东汉时才出现在典籍之中 ,但其具有能迅速生长扩大、孕育世间万事万物的性质 ,在商周之时用来分封薄姑五色土的亳社神崇拜中就已经初蕴其义了。盘古神并非像后世学者所言 ,是最晚出现而被积薪式地列为时代最早、地位最高的创世主神","categories":["09_其它"],"year":2002,"publication":"历史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKlmZ0yb-IP7uOFKiIgy5H8X36NxKZYO6g3k5c1fBGnkI8FAaEUktkVfcSHqiGDncLGpijY8D3MaPljGdhgTPz5e9BDbw5QGm4lvSX9EKnfZ_sLXkLTNW4muTo2JQUfFBQQUlX525fclvYvFi52Pva-yhUWLD4SjcmdRWBCLDdcDw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"3-19, 189","volume":""},{"id":6155,"author":"张青松","title":"试评《西周金文语法研究》","abstract":"管燮初先生著的《西周金文语法研究》一书通过精确的统计 ,对金文的语法现象进行了系统的描写。该书与《尚书》语法进行共时比较 ,较全面的反映了西周语言的语法规律。但该著仍然存在着严重的不足 :在研究方法上 ,最大的缺陷是没有进行穷尽性研究 ,其次是缺乏“史”的观念 ,历时的比较不够 ,再次是有不少地方以孤证立论 ;在资料运用上 ,没有充分利用古文字研究的成果 ,过分相信第二手材料 ,导致语法分析有误 ,许多例句重见时 ,在引文、标点、译述乃至语法分析等方面存在自相矛盾的现象","categories":["09_其它"],"year":2002,"publication":"华南理工大学学报（社会科学版）","link":"https://link.cnki.net/doi/10.19366/j.cnki.1009-055x.2002.01.017","pages":"79-83","volume":""},{"id":6171,"author":"王政","title":"三星堆青铜立人新考","abstract":"本文试从原始宗教象征学的视角 ,考察三星堆青铜立人赤足、花冠、大耳三种现象所潜含的巫术语义与原始象征内涵 ,并且联系文化人类学同类事象的广阔背象取证分析 ,揭示古蜀先民原始宗教思维与其他民族的一致性与趋同性 ,以及这三种现象作为一种“微观文化单元”在原始宗教象征史上所具有的典型意义。","categories":["09_其它"],"year":2002,"publication":"天府新论","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIALF_-PVeB4txn42VDzk1pNW8LSY05w-8lPcYfAFHBdsRHr8Y0P_t4o7pniU7XaOnIwVJeBUYbvG9irPb8BWoR_jnrXt1GzAllG8iHadwf1y9KGVQo10HDLfTwBl6kJmp0-qLi7e_HiJLfFSppb5MD-KnB3l-r4BsZ9Z9DffJ7bg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"86-91","volume":""},{"id":6173,"author":"刘丽霞","title":"闲话“大丈夫”","abstract":" 在汉语中,“丈夫”总与“大”难分难解,与“大丈夫”类似的说法还有“伟丈夫”“大男人”“顶天立地的男子汉”等等。其实这种意识早已窈在于举大&quot;和&quot;夫&quot;字中。在甲骨文卿金文中,&quot;大&quot;&quot;夫&quot;本是一体的:才贪(甲骨文),大(金文)。这样一种.正面站立的人的象形,既是&quot;大&quot;字,也是&quot;夫&quot;字。&quot;大&quot;与&quot;夫&quot;","categories":["09_其它"],"year":2002,"publication":"咬文嚼字","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLbIjCuL8yq3x2hE684Fb1ptev9UrP3MiKEDt3SoqCgl8jD-X7n0WHWl-ZbXjUHVAZVrCAf9YHI-Q8PUVaDdH5_lI6KiZzQ6lP8c3YdyxtGzqY4TEhyqE9pCRXJHqK5r7cSlD2yHJ16TFPNPgnAD5i4btK-MJ0bOoBJogSRr47O6A==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"20-22","volume":""},{"id":6529,"author":"郝士宏; 黄德宽","title":"古汉字同源分化研究","abstract":"汉字的孳乳分化是其发展演变的一种重要现象，同源分化又是孳乳分化中的核心部分。因而对古汉字同源分化的深入研究，不仅可以揭示古汉字演化的某些规律，而且对文字学的理论建设有积极意义。本文以殷周到秦汉古文字中的同源分化字为研究对象，详细考辨了大量同源字例，在此基础上分析归纳了同源分化途径、方式，并就相关问题做了深入探讨。论文分上下两篇，其大要如下：第一，通过同源字以及与之经常混用不别的几个概念的辨析，指出同源字的研究应确立字本位的思想，并对同源字做了新的界定：同源字是指汉字在发展过程中孳乳分化来的一组在字义或构形上有意义联系的分化字。第二，深入分析同源字例，归纳出同源分化的三条主要途径：由字义引申而引起的分化、由事物得名的理据导致的分化和由汉字表意特点引起的分化，并对相关的现象做了理论上的分析探讨。第三，对同源分化的方式做了分析总结。归纳出四种分化方式：增加、减省、改易与同取，并对其中的每一类型做","categories":["09_其它"],"year":2002,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIpYINn0lmnAsPUpRglf3drkHsGfnJ2haMgQQVjhU6Im4rasyeNIdWyXNu42YFI-0zz-xPijConNWwpSpxVxrZCYqI68JQ81oQLkG0YgeanG2R9gQzhtIWG7sHk45EaSsrFJrvenbAA61psAqBPCqeSUnjWfvdiIQq8BeQoR4LMGmGDF6MYi87S&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6941,"author":"杨颖; 万业馨","title":"汉字偏旁位置系统的初步研究——兼论影响古汉字偏旁位置的因素","abstract":"与现行汉字的偏旁位置不同，古文字偏旁位置的变动常常并不能改变本字的意羲。因此，古文字的偏旁位置给人的印象多为“变动不居”。汉字偏旁位置由多变到稳定，经历了一个发展变化的过程。但由于研究目的，重多学者对汉字偏旁位置尚未加以系统地研究分析。由此出发，本文考察了不同偏旁在殷墟甲骨文、《金文编》金文、战国文字(睡虎地秦简文字、郭店、包山楚简文字、中山王器文字、侯马盟书文字)合体字(涉及字形8143个)中的位置分布情况，初步分析了汉字偏旁位置系统的形成过程。我们认为，在战国晚期秦系、楚系、中山文字(正体)内部各自形成了偏旁位置系统。汉字偏旁位置系统的形成是与整个古汉字系统的发展变化息息相关的，因此，本文同时对影响古文字偏旁位置的因素作了分析。我们认为，影响古文字偏旁位置的因素主要是：方块格式、偏旁形体、结构方式、生活原型、继承性和從众心理、地域差异以及正俗体等。这些因素互相影响、互相作用，共同决定了","categories":["09_其它"],"year":2002,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iJmXw7Lkm-TNfObjMauPjcbPorBLeedEMaazMWQ6OO9GK5NxOexbppcZ0lnS17YzjxIHh6jZiY7DEgsO3cuHT-iDcD8fHGRRmWP599kv6vE6EnURsUThXe40uJTvPe2y3inUxPfutOzlYzEHqaqEkDQxc9intmK0dblGEHkgldmEww8BK7J5uIe&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6943,"author":"王新宇; 刘守安","title":"阮元与金石学","abstract":"在目前的书法界，人们研究阮元，多将他视为书法理论家，多将关注的焦点锁定在他的《南北书派论》和《北碑南帖论》上，而很少去分析在他的知识结构中，对他能提出崭新理论命题起了决定作用的条件到底是什么，虽也有人注意到他进行尊碑理论阐释，乃是基于渊博的金石学学识这一事实，却语焉不详。长期以来，阮元作为金石学家的面目一直模糊不清。学术意义上的金石学在清代对书法变革起到了不可忽视的影响作用，而阮元则可说是在二者间起连接作用的具体、典型人物。那么，关注玩元、关注他的金石学研究对于更细微、更全面地把握他的书论和清代书法史就变得很有必要。本文试图从金石学角度入手，探讨阮元的金石学成就，进而分析他碑学观念的所以形成。","categories":["09_其它"],"year":2002,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK0bHke0fXdExsEKKfbBkRFwOf7ROK5Ml8-T7JCoNqCu9OPCaVvKGclD31nCaDk4xvj8d7gbYUaQcIPz3EJ2wcmkf7Q0jIp-Lzz-fyRyjbBCG6iJJu11cu1Q5ApktSCmi2tv9LfRw1IGDSSdykyEeYmLSADWOcK9Cfaxcdu4FTh0gwEX4kQmClN&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":6948,"author":"刘玉珺; 胡大雷","title":"先唐铭文研究","abstract":"铭文是常刻写于器物、金石或建筑之上，具有颂赞或戒勉功用的一种文体。从总体而言，铭文是一种介于文学与非文学之间的边缘性应用文体，它的发展演变体现出文学化进程。从文体功能和内容来看，铭文可分为颂赞铭与戒勉铭，其中颂赞铭包括祝颂、记功颂德和题咏礼赞三小类，戒勉铭包括自我戒勉与普遍戒勉两小类；从题刻载体来看，可分为器物铭、居室铭、山川铭和座右铭。依据题刻与文体功能相似的原则，一些学者把碑铭等归入铭文的范畴。从发展的实际情况来看，碑铭应是铭文的衍生体，两者之间有密切的亲缘关系。但碑铭在文体特征和文体形式上均呈现出与铭文明显不同的风貌，已可独立为一体。铭文起源于殷商青铜器铭，它从孕育到正式形成再到革故新变，其中有一个漫长的历史渐进演变过程。在演变过程中铭文从简约发展到复杂，种类从单一衍生为繁多。(一)先秦是铭文的发韧及形成期，青铜器铭从作记事之用的符号演变为一种文体，继而具有了一些共同的文体特征和功能","categories":["09_其它"],"year":2002,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIGBR6hYEsbQXydNFZcgcTwqZFEH8q4oOeJTFBlqTgLYJRubbLeADXDB1E1Rcj1dRIUhONmdPbgZSKRss0Gj89QywdRBZ56LyVBfWgIWWYmXi3eB1KZzvnkmVqP1CAaOaj8ywA4-SjBPvi21PlzNe_UMRxQvoRDdjYPK5_ZcIXcU4tJzTDMW-Qw&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7158,"author":"季旭升","title":"“金文研究与應用纲络计划”的进度与文字处理","abstract":" 铜器自从汉代陆绩出土到现在,总数已经超过万余件,近二千年的研究,在历史、文字等方面,都有很大的贡献。而且,在近代考古学日新月异的进步与发现之下,铜器研究一日千里,因此铜器之学是一门仍在发展中的学问,值得大量投入。铜器之学相当的比重是建立在铭文的释读上,如果铜器铭文的释读不够精确,那么下游的一切解释都成沙上之塔。铭文释读","categories":["09_其它"],"year":2002,"publication":"中国文字研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKzz5jIyCa8k_Q-Ihkc6H9nPRd7yMfHwBEXQjcdcSh0A7sycGPgUqamjtWX7Qedt-Tsyfw3KlheH1bM_f32kqGYY4jg2zcHT9kB1E3P1luIzDWBww5NohF_N235g35Ja1v9guqhpQR65v_-O6qBvylT7jtE1mjFVQw-dI_mxQlQ9Q==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"21-30","volume":""},{"id":7165,"author":"刘德增","title":"《汉书·地理志》所记齐地民俗事象考释","abstract":"《汉书·地理志》把全国划分为13个民俗区,分区表述各地民俗的基本特征,言简意赅。不足之处是行文过于简略,惜墨如金。如淳、颜师古等人的注释也仅是说文解字而已。考释该篇中涉及的齐地民俗的几个主要事象,诸如齐人重商逐利,&quot;奢侈&quot;,&quot;不田作&quot;,&quot;矜功名&quot;,&quot;舒缓阔大而足智&quot;以及&quot;巫儿&quot;现象等等,可以见出与其他地域迥然有别的文化精神。","categories":["09_其它"],"year":2002,"publication":"齐鲁文化研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKI9-0qXayyy5CEh1hFSOLKMTSwWM7pKzJ-rKz6YlPP1I3YWeiuwg8vBoXG20iIxTe3YUt2AGPQz1megWhNB2UtitdYKd-xb_IbfHjotCsVbOmQfVQsHPJNuVBnVMomWOQw2Qx6q5tqEP0l5nJplH8Td1F7WLAgGUIg3B8gzAUhOg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"194-202","volume":"1"},{"id":7166,"author":"梁方健","title":"山东金文的史料价值","abstract":"散见于各家著录的山东先秦时期的各国金文多达300余篇,其国别包括齐、鲁、邾、莒、杞、滕、曹、薛、纪、莱等20余国,其具体内容涉及政治、经济、军事、文化、风俗、等许多方面。它对于研究山东先秦时期的历史、文化具有十分重要的意义。其史料价值可概括为:提供了文献记载所不涉及的史料,提出了研究山东历史、文化的新课题;辨别文献资料之正误,有助于解决某些长期争而未决的问题;印证文献之记载,进一步说明历史事实。另外,内容涉及山东各国的别国金文,对于研究山东历史、文化也有着同样价值。","categories":["09_其它"],"year":2002,"publication":"齐鲁文化研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKI9-0qXayyy5CEh1hFSOLKMTSwWM7pKzJ-rKz6YlPP1I3YWeiuwg8vVb2pJ69ZllmzEgvcInRUBYe5MZdgbzIBDvxtn7QW1a4z1jJNU9Y4oAjONg6KiuZrSkbb76PoxfhXiRiDUjRSwAHaw6nqeIQswiOQ4EwgQYRywJgheue6Nw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"203-208","volume":"1"},{"id":4896,"author":"張懋镕","title":"略談《殷周金文集成》的失誤","abstract":"《殷周金文集成》(下簡稱《集成》)共十八册,收録器銘11983件,是迄今蒐集金文資料最多的書籍,名符其實的集大成者。它充分吸取了已有研究成果,基本上體現了20世紀青銅器銘文的著録水平。工程浩大,難免疏漏訛誤之處。今將其中失誤之例舉示如下,不妥之處,敬請海内外方家批評指正。","categories":["09_其它"],"year":2001,"publication":"考古与文物","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIlvPybDBnvbI6GnO_JNjG0dZczU0fas_en5TrS8up24QlMmIQ44DcVC5MoBF4EI5njT9DRHGviu3tgPCFKXSe3W0BGElsx1IedhC7gNhev7sWyj-2jAl-qPaAOzmTSKoY7CGAN4CWRbITCYilyuW0ctvZ3TgZgHELSqmHjk_J1jmlhH5aHPjGw&amp;uniplatform=NZKPT&amp;language=CHS","pages":"135-142","volume":""},{"id":4900,"author":"张懋镕","title":"关于《早期金文和远古陶器刻绘符号》的补充说明","abstract":" 我向本次会议提交的论文是《早期金文和远古陶器刻绘符号》,其目的是想通过二者的比较研究,证明相当一批刻绘符号是文字,而且可以按它们的功用指认为族氏文字。刚才听了诸位先生的发言很受启发,再作补充说明。","categories":["09_其它"],"year":2001,"publication":"中国书法","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIFu-c9pXUheSAd_YQWTQx04x4l4Idv41AhG6r4fjRq4Gt2PxtuArUTLLZxnCypS3jQ3MpoppR-Tq8MtNdd-w1zITGrHk_f4ox_VlGiYHlIrXDw5gPGVFp_9cx5DcGzg_SlRB4QVzABxtxUkPR66aNl5H9r9J7vK3RfSdJgD7rBr6DscqxQzcg5&amp;uniplatform=NZKPT&amp;language=CHS","pages":"61","volume":""},{"id":6181,"author":"杨天宇","title":"《周礼》的内容、行文特点及其史料价值","abstract":"《周礼》前五篇的内容和职官结构各有其特点，也包含着许多矛盾、错综和不合理处，而导致这种情况的原因，主要因为《周礼》是一部未完成的著作。《考工记》的内容和体例则与前五篇不同，自成一家。《周礼》前五篇的行文有如下特点，一是各篇前皆有一《叙官》，二是以职官联系制度，三是兼记有关的经验、技术或人们对某些问题的认识，四是互文见义，故读《周礼》贵在会通。《周礼》虽出于战国人之手，但其中保留了大量有关西周的珍贵资料，只要善于择别，并参以先秦其他文献和出土资料，即可为我们研究古史、特别是研究西周史所用。","categories":["09_其它"],"year":2001,"publication":"史学月刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLcd6r5hVeadyDVugw1YTsKzXkYDuQpznjt_TAvY09ARuUZNsQzq4E5RqCja73wJfOubOKqf0zZzDR-sorMOqZHKhfUzMHlY6yHYD1X7csT4is2flAti-H9lxbkz87cyu0aDhpxgUS2fmEvHabp61-Q6Pf1ek4PHRlWHKR6t4MPVg==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"44-50, 56","volume":""},{"id":6182,"author":"刘浦江","title":"辽朝国号考释","abstract":"辽朝一代的国号变迁 ,远比人们过去所知道的情况要复杂得多。辽朝建国之初建号大契丹 ;太宗时一度实行双重国号 ,在燕云汉地称大辽 ,在草原地区仍称大契丹 ;圣宗和道宗时又两次改变国号。而在契丹文和女真文中 ,始终称辽朝为哈喇契丹或契丹。辽朝国号的复杂性是辽朝二元政治体制的一种表现","categories":["09_其它"],"year":2001,"publication":"历史研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKb203knnqOxHBaiYIOmauHQS4DFhdg5QYD-9dAdMe0ilbjbVZAIbNR1eCRMXeFd_UYvjzoCeQN3fmbL14h_YK7WcLPV7Ir_dwLkPUe_OKBkTfgdPz755_X3yO9utKxOsVW_LS3dnaYUTwLt7UM5LHX5PdESbNfSJA96R45baegzA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"30-44, 189-190","volume":""},{"id":6189,"author":"王卫平","title":"半个世纪以来围绕“俎侯矢簋”的论争","abstract":"","categories":["09_其它"],"year":2001,"publication":"文博","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIxrFI3zG-KfiRvr7295IB77D_aRBnMDlOpp1CBgkFNBeRiVEa5sZVQMzpJLaeLJjp3EbMvDU-ahLDf7dS0XEbij2cCfNeqkJm7aH25HIsC79d-_UJ1cSrcgFWx15mOoHp3-4iD6DLdloeE8Qtwtqy2RamdbsGTIQWREJg2UIklpA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"51-53","volume":""},{"id":6193,"author":"罗江文","title":"《诗经》与两周金文韵文押韵方式比较","abstract":"一般来说，诗歌与散文的押韵方式应该不同，但《诗经》与两周金文的押韵方式却极为相似，无论是从韵在句中的位置，或是从韵在一章中的位置，以及一章多韵来看，都大致相同。它们共同表现为韵式多种多样、用韵自由灵活，反映出了先秦时期诗文作品用韵的一般情况。","categories":["09_其它"],"year":2001,"publication":"古汉语研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iK9vvwp_-g1EKJ60m3KEI6Q_9R0knqkduzNHUUmH9ElwUGDzB4zZwS36FG1wIbJCVCYcxOGdxgkGmUB8tsL1ONexTn4-6jpdS1lJhMWJL1lQkZitLW3UdDUlJvd2pATYDJUG9Y3pZRKzbx1VZsLDRzik6zMo_9aCrUlxHNeq6YNPw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46058","volume":""},{"id":6211,"author":"罗卫东","title":"汉字的断代测查对汉字史研究的意义","abstract":"汉字的断代测查要整理和描写不同历史层面汉字的构形系统，理清汉字个体字符历史演变。本文以春秋金文为例，探讨汉字断代测查的各个方面及其对汉字史研究的重要意义。","categories":["09_其它"],"year":2001,"publication":"暨南学报（哲学社会科学版）","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iKwwnvYoBdhCPWz3e3WckrCa-PA-6RlLEvVX5PDCZ80CoCzptZvmrjJJp2lQQ9DKe_6zkEVxVJ_DcVEdhxim1GUbkv5Bf2H8rbwahkPbzkS-PztwOZxqL9fnDAR4ZPASfgc407akqxhTKzoeSXNHqK4qkrTnIOpzJ6QQAKSiNV_Yw==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"129-132","volume":""},{"id":6212,"author":"查昌国","title":"论西周孝尊祖敬宗抑制父权——兼论古史研究中经史方法的运用","abstract":"","categories":["09_其它"],"year":2001,"publication":"史学理论研究","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLhoBsStIjferIF9bvwIE73kWR1wYqA2N2x_ulrUGHqnUAN-I2xl_XEqnId0WdVVwm-1M3yIoAfXkCLQpxCVkGPMIrCfvmtofbyGDhJ_UypmqOJIeB--vIzkGmdTWYSbFNp1ZRfGsVzIWZStsPbP_OPEKtOTvIJKLegmD7jRcgu1g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"67-77","volume":""},{"id":6221,"author":"江林昌","title":"夏商周断代工程的研究方法和技术路线","abstract":"备受世人瞩目的夏商周断代工程，以追寻中华古文明源头为最终目标，工程所取得的三代年表，填补了中国年代学史上的空白，而工程所采用的人文社会科学与自然科学相结合、多学科交叉并进的研究方法，和由已知推求未知，由相对晚近推及相对古远的技术路线，在中国学术史上更具有开拓创新意义，对21世纪的学术研究必将产生深远的影响，值得总结和借鉴。","categories":["09_其它"],"year":2001,"publication":"齐鲁学刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLbCq2EbXg1JdtQNL8xXDUhG_RnarhF1CKeUV2mXoRmlO1lTYsraG5gwx9xEkeAhzOnKcJD2PoEzMnAousnprz6lqJDTKgZX4WACtVn9A0tcsmDPFjnxGR6C7ta68IQAhuFCM7dGkpG24KNb3xOkLwy9_X84bByjcXHEb-XxCLSiA==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"46161","volume":""},{"id":6558,"author":"何宏波; 李民","title":"先秦玉礼研究","abstract":"礼制是中国古代社会的根本特征和标志，体现于社会生活的各个方面。而先秦时期是礼制的奠基时期，礼制的许多重要内容都形成于这一时期。玉礼作为礼制中的一个独特而重要的组成，很早就已形成并得到了充分的发展，成为先秦时期礼制的核心内容。对先秦时期玉礼的研究，将有助于更准确更深入的理解和把握中国古代礼制的特质。本文旨在前人研究成果的基础之上，立足于考古学，并依靠出土文字和传世文献，对先秦时期的玉礼作一系统而全面的探讨。本文视玉礼为一个完整的体系，力图通过对玉礼变化发展脉络的把握来全面系统客观地阐述玉礼。同时，本文的研究是从玉、玉礼器、玉礼三个不同的层面进行的，不但探讨玉礼的物质内容和外在表现形式，而且更着重于对玉礼所蕴含的观念意识和精神内容的探讨。本文共分七章。首章绪论对礼和玉礼的内涵、社会功能及其嬗变进行了概要的阐述，并回顾了学术史上有关玉礼的重要研究成果。此章是本文的立论基础。从第二章至第六章，是按","categories":["09_其它"],"year":2001,"publication":"","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iIr-w8uhAjc9BnA-izZFyVOyo92QNU3WEt5v5vCLj9ofEJ37gFZPRZ1LU5eUvueQecAKEvnarMJLYjhuh9AC9HpO3WKZfvPl-rYsqD_upVFTkm1-T_APNKvehwXe32AlEJ3xpnZBOURFBeefbcqwC8KuAdq9VG7n4tZWZ1CsIZ0smzY4yNojEdc&amp;uniplatform=NZKPT&amp;language=CHS","pages":"","volume":""},{"id":7175,"author":"朱思红","title":"一介寒儒铸就的辉煌——读陈直先生的《读金日札》","abstract":"二十一世纪的第一个元旦,周晓陆先生送给我一本刚刚出版的由他自己整理的陈直先生的遗著《读金日札》,并题&quot;以陈直精神治史&quot;七个字相勉励。获此馈赠,百感交集。陈直(1901～1980),原名陈邦直,字进宦,号摹庐,又号弄瓦翁,江苏镇江人,现代著名史学家,生前任西北大学历史系教授。陈直先生治学,师承清代朴学的传统,同时也受到了王国维近代考据学二重证据法的影响,既重文献资料,又重考古资料,提出了&quot;使文献与考古合为一家&quot;、&quot;使考古为历史服务&quot;等学术主张,并大力倡导&quot;搞人民史&quot;、&quot;搞手工业史&quot;。在扩大","categories":["09_其它"],"year":2001,"publication":"碑林集刊","link":"https://kns.cnki.net/kcms2/article/abstract?v=HHZEz91P5iLJePHfWKf5hNjZgWpS6UbsxTA5S8QjVTcEQxKfG2H6luzprSrKcClivzdseQ0F7-16hUhkRCKno2I7uI7QftrMZXyspUAn_cHYH_z6n08OP2JIj33nU2acIhHQ0cN3ORn2act9NaV8rFR434ZJP0fROoj0B9AkcETu7RXx86dh-g==&amp;uniplatform=NZKPT&amp;language=CHS","pages":"305-306, 256","volume":""},{"id":315,"author":"高崇文","title":"先秦两汉都城礼制文明研究","abstract":"中国古代城市文明是一种礼制性的城市文明，它既是物象的行政规划形式，又是政治和意识的体现，构成了中国古代城市礼制文明的显著特色。从史前时代到东汉，都城逐渐成为国家最重要的礼仪中心，都城的礼制建筑不仅体现了当时的建筑水平和规划形式，更重要的是蕴含着丰富的礼制思想，是礼仪制度、政治制度、等级观念、意识形态等多方面的反映。 本书运用考古类型学、聚落考古等方法，结合甲骨文、金文、古代文献及考古发掘资料，对我国古代早期礼制遗存进行系统梳理，研究聚落的形成、聚落的社会形态，都市的形成、都市的社会形态，由聚落到都市的演变，并阐述从新石器时代晚期氏族部落联盟性质神权国家的出现，到夏商周三代强势宗族性质礼制国家的形成，再到秦汉时期统一集权帝国确立的全过程，深入探讨了中国古代文明的形成及其深远影响，揭示了中华文明发展演变的独特轨迹。","categories":["09_其它"],"year":null,"publication":"","link":"","pages":"364","volume":""},{"id":437,"author":"李冬鴿","title":"出土文獻的同源詞族研究","abstract":"同源词即汉语中有同一语源、音义相关的词。本书以出土材料本义与《说文》本义不同的声符为基础，尽可能穷尽地系联同声符同源词，尝试解决声符与同源词、出土材料与同源词系联以及词源意义的相通等问题。全书分为上下两编，上编从声符的《说文》本义、现有考释、出土材料本义、同源词系联、通用情况、词源谱系等几方面，系统地考证了93个同源词族（组）；下编则以上编的材料为基础，探讨了利用出土材料系联同声符同源词族（组）的相关问题。充分利用出土文献对确定词的本义以及同源词系联有着重要的作用，同时也能更好地解释同源词之间的关系，系联到更完整的词族，推动同源词研究进一步发展。","categories":["09_其它"],"year":null,"publication":"","link":"","pages":"445","volume":""},{"id":484,"author":"刘佳君","title":"博物馆里的生僻字","abstract":"本书结合考古学方法，从2013年国务院公布的《通用规范汉字表》二级和三级字表中，选择了日常生活中较为少见、但在博物馆中用于标示文物名称而常出现的十六个字，从每个字的字形、字义出发，结合所示器物的器形、器用，展现汉字所承载的习俗制度、文化传统以及中华文明之瑰丽多彩。希望此书能够帮助读者认识这些所谓“博物馆里的生僻字”，由字及物，循物见史，以史鉴今。见字、见物、见人，见灿若星辰的中华文明，更见历久弥新的民族精神。","categories":["09_其它"],"year":null,"publication":"","link":"","pages":"230","volume":""},{"id":600,"author":"張富海","title":"漢人所謂古文之研究","abstract":"“古文”是汉代出现的一个概念。汉人眼里的古文是五帝三王所用的文字，是圣人孔子所用的文字。汉人所谓古文，今日所见材料大致包括《说文》古文、三体石经古文和汉代经注中的古文，《汗简》和《古文四声韵》所引也有一些不见于《说文》和今存三体石经而可信为传自汉代的古文。《汉人所谓古文之研究》逐字考察了上述材料中的古文，并与出土文献作对比分析，在前人研究的基础上认为汉人所谓古文可以分成两部分，其大部分是六国文字，小部分是非六国文字。属于六国文字的古文的主体是战国齐系文字中的鲁文字，同时含有战国晋系文字和楚文字的成分。非六国文字成分中，有少量西周铜器铭文中的字形，有汉代小学家考定为古文的字形，甚至有编造拼凑的字形。本书共分五章，绪论之外，第二至四章分“《说文》、石经古文”“汉代经注中的古文”“《汗简》《古文四声韵》中的古文”逐字考察古文字形或用法，第五章分析汉人所谓古文的性质。书末并附单字索引。本书材料丰富","categories":["09_其它"],"year":null,"publication":"","link":"","pages":"365","volume":""},{"id":962,"author":"李峰; 施劲松","title":"张长寿、陈公柔先生纪念文集","abstract":"本书中既有聚焦于新发现、对热点问题的新思考，如青铜时代的起源、新发现青铜器和铭文的考订及西周年代、青铜器的产地和地域性青铜文化、新出土简牍文书和历史地理问题等；也有对旧问题的反思，如殷墟的性质和西北冈王陵的序列、青铜器的实际功能、玉器研究的方法、临淄齐故城遗迹的考订、辽代庆陵的规制和象征意义等；更有对新研究领域或议题的探索，如从考古遗存中辨析工匠身份、甲骨卜兆形式的统计研究、西周交通道路、中国古代竞舟与龙舟文化、汉代的武备等等。本书中不乏用力至深的长篇力作，有着重要的学术意义和参考价值。 另外，本书中包括了由仇士华和唐际根、荆志淳先生撰写的两篇追忆，它们记录了张长寿先生在20世纪90年代学术研究，特别是中外合作田野工作中的点点滴滴。本书也包括由李峰和施劲松撰写的三篇纪念文章，它们总结和梳理了张长寿和陈公柔先生的学术思想和成就，表达了对老师的深切怀念。附录收集了张长寿和陈公柔先生各自的著作目","categories":["09_其它"],"year":null,"publication":"","link":"","pages":"704","volume":""},{"id":963,"author":"張玉金; 劉晶","title":"出土文獻語言研究","abstract":"本书为“语言服务书系·出土文献研究”之一，内容包括出土文献与汉语史研究甲骨文及其语言研究，金文及其语言研究，简帛玺印及其语言研究，文字学研究及其他五个部分。本书内容有三个突出特点：一是注重古文字研究与出十文献语言研究相结合；二是注重出土文献与传世文献相结合；三是全面反映了当前学术发展的国际水平，给学界提供参考，注入生机。本书涉及研究内容广，学术前沿性强，研究深入细致，充分展示了当前出土文献语言研究领域的最新成果，对于该领域的研究者具有启发性意义，学术参考价值高。","categories":["09_其它"],"year":null,"publication":"","link":"","pages":"238","volume":""},{"id":3033,"author":"李亚农","title":"李亚农古文字研究四种","abstract":"本书系原上海社会科学院历史研究所所长李亚农的四部古文字学著作的影印汇集，这四部著作分别是《铁云藏龟零拾》《殷契摭佚》《殷契摭佚续编》《金文研究》。作者进行这些古文字研究的目的，乃是想通过古文字构成要素的变化，更进一步而穷其历史的发展。这些书在当时出版后，曾收到学术界的的高度评价，被认为是继郭沫若的古文字研究之后的又一重大成果。由于原书出版距今已有七八十年的时间，图书也极少收藏，故影印出版，以供专业研究者参考。","categories":["09_其它"],"year":null,"publication":"","link":"","pages":"554","volume":""},{"id":3078,"author":"張玉金","title":"出土文獻語言研究","abstract":"本书为首届古文字与出土文献语言研究国际学术研讨会论文结集，内容包括出土文献与汉语史研究、甲骨文及其语言研究、金文及其语言研究、简帛玺印及其语言研究、文字学研究及其他等部分，本书内容有三个突出特点：一注重古文字研究与出土文献语言研究相结合。二注重出土文献与传世文献相结合。三全面反映了当前学术发展的国际水平，给学界提供参考，注入了生机。","categories":["09_其它"],"year":null,"publication":"","link":"","pages":"280","volume":""},{"id":3101,"author":"牛倩","title":"古器图录与商周礼制文化研究","abstract":"本书共分五章，除第一章绪论外，每章探讨一个专题：第一章通过梳理“饕餮”词义形成的历史文献，阐释饕餮纹主要应用于鼎、簋、尊、鬲等重要礼器的根本原因。第二章逐本溯源，发现火纹在上古取象于日，蕴含着“圆道周流”、阴阳相合的哲学意义，最终解释了火纹被刻画为圆形并铸于酒器的原因。第三章北宋古器图录中觥与匜常混称，通过对二者形制与用途的考释，进一步阐释了二者所包蕴的不同礼制内涵。第四章通过梳理古器图录所载乐器，对以下三个问题进行了探索：其一，八音分类法与古人的时空哲学观念密切相关；其二，对錞于形制在文献典籍中存在的诸多异说进行了辨析；其三，对“金錞和鼓”及以虎纹雕饰錞于的文化意义进行了阐释。","categories":["09_其它"],"year":null,"publication":"","link":"","pages":"250","volume":""},{"id":3152,"author":"韦韧","title":"《云龙白曲残本》文字整理与研究","abstract":"方块白文是古代白族在长期使用汉语文的过程中，仿照汉字创制的一种民族文字，是一种既借用汉字又自造拼合字的意音文字。本书以目前已释读方块白文文献中自造拼合字数量最多的《云龙白曲残本》为基本研究材料，采用“结构-功能”分析法和现代系统论，利用Oracle Database数据库，运用语料库语言学知识，对研究材料《云龙白曲残本》进行数字化处理，并构建方块白文数据库系统，详细描写了方块白文的文字属性，细致分析、考释了《云龙白曲残本》中记录的每一个方块白文。","categories":["09_其它"],"year":null,"publication":"","link":"","pages":"372","volume":""},{"id":3156,"author":"王世民","title":"考古学史与商周铜器研究","abstract":"本书汇集了作者关于中国考古学史和商周铜器等方面的论文，考古学史方面，包括概述中国考古学发展的长篇论文、研讨中国考古学前身金石学若干问题的专论，以及对郭沫若、郑振铎、梁思永、夏鼐、陈梦家等多位老一辈专家学术贡献的评述；商周铜器方面，包括商周铜器研究的回顾与展望，西周铜器分期断代研究方法的论述，以及西周诸侯方国铜器、西周金文中的诸侯爵称、两周时期的礼器制度及编钟发展等专论；并附载关于金属铸币与汉代纺织品、南方楚墓与马王堆汉墓、卜天寿写本《论语郑氏注》等专题论文或述评。","categories":["09_其它"],"year":null,"publication":"","link":"","pages":"683","volume":""},{"id":3844,"author":"席晓峰; 席琳","title":"先秦文化研究","abstract":"本书与人民日报出版社出版的《华夏先秦文明史考释断代》是姊妹篇，是21世纪中国学术界的两本奇书。《华夏先秦文明史考释断代》准确考定了先秦十六朝起讫的年代，《先秦文化研究》通过历法学、甲骨学、金文学、历史学、考古学、年代学等多学科、多角度的聚焦研究，进一步证明了先秦十七朝断代的正确，并弄清了以平均主义为基础的原始社会禅让制……","categories":["09_其它"],"year":null,"publication":"","link":"","pages":"300","volume":""},{"id":6590,"author":"张应杰","title":"唐代铭文概论","abstract":"本书从铭文的起源、发展流变和唐代铭文赋存，唐代铭文的思想内容，唐代铭文的艺术成就及唐代的碑铭、墓志铭四个方面进行论述，兼及先唐和唐代之后的铭文，较为全面系统的分析了铭文这种文体的文学价值和社会意义。本书注重原始材料的发掘，通过对《全唐文》《全唐文补遗》《全唐文补编》和《唐代墓志汇编》等几部唐代文章汇编中属于铭文范畴的作品进行提取、统计和分析、研究，注重发掘有重要文学价值和历史意义的铭文篇章，将铭文这一古老的应用性文体在唐代的发展和影响作了详细的论述。本书对古典文学爱好者和研究者都不无裨益，对于山水旅游文学研究和山水文化旅游资源开发也有一定的参考作用。","categories":["09_其它"],"year":null,"publication":"","link":"","pages":"251","volume":""}]};